window.QUESTION_BANK = [
  {"id": 1, "type": "single", "question": "中国共产党和政府历来重视 （　　） 生产管理，把人民群众的生命安全、身体健康放在首位。", "options": ["规范", "平稳", "有序", "安全"], "answer": [3], "explanation": "中国共产党和政府历来重视安全生产管理，把人民群众的生命安全、身体健康放在首位。"},
  {"id": 2, "type": "single", "question": "十八届中央政治局第二十三次集体学习时指出，要切实抓好安全生产，要细化落实各级党委和政府的领导责任、相关部门的监管责任、企业的 （　　） 。", "options": ["主要责任", "主体责任", "生产责任", "安全责任"], "answer": [1], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】正确答案是B。题干对应的是建筑施工安全管理。 A项“主要责任”错误，它说的是“主要责任”，并非题干要找的“主体责任”。 B项“主体责任”正确，它与题干所述“十八届中央政治局第二十三次集体学习时指出，要”相对应。 C项“生产责任”错误，它说的是“生产责任”，并非题干要找的“主体责任”。 D项“安全责任”错误，它说的是“安全责任”，并非题干要找的“主体责任”。"},
  {"id": 3, "type": "single", "question": "以下选项不属于安全生产管理的原理是 （　　） 。", "options": ["人本原理", "预防原理", "系统原理", "强迫原理"], "answer": [3], "explanation": "安全生产管理包括系统原理、人本原理、 强制原理、预防原理、责任原理五个基本原理。"},
  {"id": 4, "type": "single", "question": "属于安全生产管理中系统原理的相关原则有动态相关性原则、整分合原则、反馈原则和 （　　） 。", "options": ["动力原则", "能级原则", "封闭原则", "激励原则"], "answer": [2], "explanation": "系统原理的四大原则：动态相关性（各要素相互作用）、整合合（分工与综合）、反馈（信息回馈）、封闭（管理闭环）。 “能级原则”和“动力原则”属于人本原理，“激励原则”属于行为科学范畴。"},
  {"id": 5, "type": "single", "question": "整分合原则是指现代高效率的管理必须在整体规划下明确分工，并在分工基础上进行 （　　） 。", "options": ["有效整合", "有效合作", "有效组合", "有效综合"], "answer": [3], "explanation": "现代高效率的管理必须在整体规划下明确分工,在分工基础上进行有效的综合,这就是整分合原则。"},
  {"id": 6, "type": "single", "question": "安全生产管理中人本原理的相关原则有动力原则、激励原则和 （　　） 原则。", "options": ["整分合", "反馈", "封闭", "能级"], "answer": [3], "explanation": "人本原理三大原则：动力（内在驱动）、激励（外在鼓励）、能级（人员能力与岗位匹配）。 其他选项属于系统原理。"},
  {"id": 7, "type": "single", "question": "系统原理中的 （　　） 指现代高效率的管理必须在整体规划下明确分工，在分工基础上进行有效的综合。", "options": ["动态相关性原则", "整分合原则", "反馈原则", "封闭原则"], "answer": [1], "explanation": "整分合原理是现代高效率的管理必须在整体规划下明确分工,在分工基础上进行有效的综合。"},
  {"id": 8, "type": "single", "question": "下列选项中，没有贯彻人本原理的措施的是 （　　） 。", "options": ["重视职工职业技能培养", "激励职工行为", "改善领导行为", "强化民主管理"], "answer": [0], "explanation": "贯彻人本原理的措施有:a.重视企业思想教育工作;b.强化民主管理;C.激励职工行为;d.改善领导行为。"},
  {"id": 9, "type": "single", "question": "不管事故是否造成了损失，为了防止事故损失的发生，唯一的办法是防止事故再次发生。这是预防原理中的 （　　）  原则。", "options": ["因果关系", "能级", "3E", "偶然损失"], "answer": [3], "explanation": "1)偶然损失原则：无论事故是否造成了损失，为了防止事故损失的发生，惟一的办法是防止事故再次发生。这个原则强调，在安全管理实践中，一定要重视各类事故，包括未遂事故，只有连未遂事故都控制住，才能真正防止事故损失的发生。"},
  {"id": 10, "type": "single", "question": "从事故的因果关系中认识必然性，发现事故发生的规律性，变不安全条件为安全条件，把事故消灭在 （　　） ，这就是因果关系原则。", "options": ["早期起因阶段", "早期预防阶段", "早期准备阶段", "早期发现阶段"], "answer": [0], "explanation": "因果关系原则强调消除事故的“根源”（起因阶段），而非事后补救。 “预防”“准备”“发现”是后续阶段，非最根本的干预点。"},
  {"id": 11, "type": "single", "question": "采取强制管理的手段控制人的意愿和行为，使个人的活动、行为等受到安全生产管理要求的约束，从而实现有效的安全生产管理，这就是安全生产管理中的 （　　） 。", "options": ["人本原理", "预防原理", "强制原理", "系统原理"], "answer": [2], "explanation": "采取强制管理的手段控制人的意愿和行为，使个人的活动、行为等受到安全生产管理要求的约束，从而实现有效的安全生产管理，这就是强制原理。"},
  {"id": 12, "type": "single", "question": "安全生产管理理论中的事故致因理论有：事故频发倾向理论、海因里希因果连锁理论、系统安全理论和 （　　） 。", "options": ["人本理论", "预防理论", "能量意外释放理论", "本质安全理论"], "answer": [2], "explanation": "四大事故致因理论包括： 事故频发倾向理论（特定人员易引发事故）； 海因里希因果连锁理论（事故链）； 系统安全理论（系统缺陷导致事故）； 能量意外释放理论（能量失控造成伤害）。 “人本理论”和“预防理论”不属于事故致因理论。"},
  {"id": 13, "type": "single", "question": "事故致因理论是探索事故发生、发展规律，研究事故始末本质的理论，下列不属于事故致因理论的是 （　　） 。", "options": ["事故频发倾向理论", "系统安全理论", "本质安全化理论", "能量意外释放理论"], "answer": [2], "explanation": "“本质安全”是设备或系统的固有安全属性，属于安全设计范畴，而非解释事故成因的理论。 其他选项均为经典事故致因理论。"},
  {"id": 14, "type": "single", "question": "根据安全生产管理理论中的事故致因理论， （　　） 阐述了事故的连锁过程：由于管理失误引发的人的不安全行为和物的不安全状态及其相互作用，使不正常的或不希望的危险物质和能量释放，并转移于人体、设施，造成人员伤亡或财产损失，可以通过减少能量和加强屏蔽来预防事故。", "options": ["事故频发倾向理论", "海因里希因果连锁理论", "能量意外释放理论", "系统安全理论"], "answer": [2], "explanation": "能量意外释放理论从事故发生的物理本质出发，阐述了事故的连锁过程：由于管理失误引发的人的不安全行为和物的不安全状态及其相互作用，使不正常的或不希望的危险物质和能量释放，并转移于人体、设施，造成人员伤亡和(或)财产损失，事故可以通过减少能量和加强屏蔽来预防。"},
  {"id": 15, "type": "single", "question": "安全教育对策主要是使人知道哪里存在 （　　） ，如何导致事故，事故的可能性和严重程度如何，对于可能的危险应该怎么做。", "options": ["风险", "危机", "意外", "危险源"], "answer": [3], "explanation": "安全教育的目标是识别“危险源”（可能导致事故的根源），而非泛泛的“风险”或“意外”。 “危险源”是安全管理中的专业术语，符合题目语境。"},
  {"id": 16, "type": "single", "question": "《中华人民共和国安全生产法》是我国有关安全生产的一部 （　　） 法律。", "options": ["专门", "基本", "基础", "相关"], "answer": [2], "explanation": "1） 基础法\n我国有关安全生产的基础法律包括《中华人民共和国安全生产法》以下简称《安全生产法》，以及与它平行的专门法律和相关法律。《安全生产法》是综合规范安全生产法律制度的法律，它适用于所有生产经营单位，是我国安全生产法律体系的核心。"},
  {"id": 17, "type": "single", "question": "下列选项中，不属于行政法规的是 （　　） 。", "options": ["《建设工程安全生产管理条例》", "《安全生产许可证条例》", "《中华人民共和国消防法》", "《生产安全事故报告和调查处理条例》"], "answer": [2], "explanation": "消防法不是行政法规。行政法规是国务院制定的规范性文件，而消防法是全国人大常委会制定的，是法律。"},
  {"id": 18, "type": "single", "question": "由有立法权的地方人民政府制定，在本辖区内有效的安全生产规范性文件是 （　　） 。", "options": ["安全生产法规", "安全生产地方性法规", "安全生产地方性法律", "安全生产地方政府规章"], "answer": [3], "explanation": "地方人民政府根据其立法权，可以制定在本辖区内有效的安全生产规范性文件，这些文件通常被称为“地方政府规章”。"},
  {"id": 19, "type": "single", "question": "在学法用法的实践中，施工企业有时会遇上法规冲突，届时可通过专业咨询服务得到解决，但若能自己通过学习获得解决或理解，则更能提高 （　　） 的效率。", "options": ["企业运营", "生产运营", "生产劳动", "个人能力"], "answer": [0], "explanation": "题目主体是“施工企业”，核心目标是提升“生产经营”效率。 “企业运营”范围过大，“生产劳动”和“个人能力”偏离企业视角。"},
  {"id": 20, "type": "single", "question": "《立法法》第九十四条规定，法律之间对同一事项的新的一般规定与旧的特別规定不一致，不能确定如何适用时，由 （　　） 裁决。", "options": ["国务院", "制定机关", "法院", "全国人民代表大会常务委员会"], "answer": [3], "explanation": "（完整版） 《立法法》第九十四条规定，法律之间对同一事项的新的一般规定与旧的特别规定不一致，不能确定如何适用时，由（ ）裁决。 选项： 国务院 制定机关 法院 全国人民代表大会常务委员会 答案：D. 全国人民代表大会常务委员会 解析：根据《立法法》第九十四条，当新的一般规定与旧的特别规定冲突且无法确定适用时，应由全国人大常委会裁决。这是立法机关的核心职能之一，确保法律体系的统一性。"},
  {"id": 21, "type": "single", "question": "新修订的《安全生产法》提出，生产经营单位要建立健全 （　　） 。", "options": ["单位安全责任制", "负责人安全责任制", "全员安全责任制", "干部安全责任制"], "answer": [2], "explanation": "新修订的《安全生产法》提出,生产经营单位要建立健全“全员安全责任制”。"},
  {"id": 22, "type": "single", "question": "新修订的《安全生产法》将“推进安全生产标准化建设”修改为 （　　） 安全生产标准化建设工作。", "options": ["完善", "提升", "建立", "加强"], "answer": [3], "explanation": "修订后的表述从“推进”改为“加强”，体现了对标准化建设更高层级的重视，强调持续深化和落实。"},
  {"id": 23, "type": "single", "question": "新修订的《安全生产法》针对负有事故责任的生产经营单位主要负责人的处罚，增加 （　　） 的处罚力度。", "options": ["5%-10%", "10%-15%", "10%-20%", "15%-20%"], "answer": [2], "explanation": "一是针对事故罚款翻倍，最高可以处罚一个亿。针对负有事故责任的生产经营单位主要负责人的处罚，增加10％～20％的处罚力度，对发生事故的生产经营单位的罚款金额上限，在原来的基础上翻倍，并提出“发生生产安全事故，情节特别严重、影响特别恶劣的，应急管理部门可以按照前款罚款数额的二倍以上五倍以下对负有责任的生产经营单位处以罚款。”"},
  {"id": 24, "type": "single", "question": "新修订的《安全生产法》第十七条提出“县级以上各级人民政府应当组织负有安全生产监督管理职责的部门依法编制安全生产权力和责任清单，公开并接受 （　　） ”。", "options": ["人民监督", "政府监督", "社会监督", "行业监督"], "answer": [2], "explanation": "清单公开的核心目的是引入“社会监督”，通过公众参与和舆论监督提升透明度和问责效率。"},
  {"id": 25, "type": "single", "question": "新修订的《上海市安全生产条例》规定，生产经营单位应当明确各岗位的安全生产责任人员、 （　　） 和考核要求。", "options": ["责任内容", "安全技术", "责任方案", "安全预案"], "answer": [0], "explanation": "全员安全生产责任制应当涵盖本单位各安全风险点，明确各部门、各岗位的责任人员、责任范围、责任内容和考核要求。"},
  {"id": 26, "type": "single", "question": "根据《建设工程安全生产管理条例》规定，“垂直运输机械作业人员、安装拆卸工、爆破作业人员、起重信号工、登高架设作业人员等特种作业人员，必须按照国家有关规定经过 （　　） ，并取得特种作业操作资格证书后，方可上岗作业。”", "options": ["安全常识培训", "企业培训", "专门的安全作业培训", "自主培训"], "answer": [2], "explanation": "特种作业风险高，需通过“专门培训”掌握专业操作技能和安全规范，持证上岗是法定要求。"},
  {"id": 27, "type": "single", "question": "根据《建设工程安全生产管理条例》规定，“专职安全生产管理人员负责对安全生产进行现场监督检查。发现安全事故隐患，应当及时向 （　　） 报告。”", "options": ["项目负责人和安全生产管理机构", "技术负责人", "监理单位", "质量员"], "answer": [0], "explanation": "专职安全生产管理人员负责对安全生产进行现场监督检查。发现安全事故隐患，应当及时向项目负责人和安全生产管理机构报告；对违章指挥、违章操作的，应当立即制止。"},
  {"id": 28, "type": "single", "question": "根据《建设工程安全生产管理条例》规定，下列选项中，需要编制专项施工方案，但不需要进行专家论证、审查的是 （　　） 。", "options": ["开挖深度超过15m未超过20m的基坑支护工程", "开挖深度超过10m未超过15m的基坑支护工程", "开挖深度超过5m未超过10m的基坑支护工程", "开挖深度超过3m未超过5m的基坑支护工程"], "answer": [3], "explanation": "需要进行专家论证、审查的是：深基坑工程开挖深度超过5m (含 5m) 的基坑(槽)的土方开挖、支护、降水工程或开挖深度虽未超过 5m ，但地质条件、周围环境和地下管线复杂，或影响毗邻建筑(构筑)物安全的基坑(槽)的土方开挖、支护、降水工程。"},
  {"id": 29, "type": "single", "question": "下列选项中，不是政策的特点的是 （　　） 。", "options": ["形式多样", "针对性强", "时效性强", "变动性小"], "answer": [3], "explanation": "政策需随社会需求调整，“变动性小”错误，其特点应是灵活性（如时效性、针对性）。"},
  {"id": 30, "type": "single", "question": "中华人民共和国成立以来第一个以党中央、国务院名义出台的安全生产工作纲领性文件是 （　　） 。", "options": ["《中共中央国务院关于推进安全生产领域改革发展的意见》", "《中共中央国务院关于全面加强危险化学品安全生产工作的意见》", "《中共中央国务院关于进一步加强城市规划建设管理工作的若干意见》", "中共中央办公厅国务院办公厅印发《地方党政领导干部安全生产责任制规定》"], "answer": [0], "explanation": "2016年发布的该文件是首个党中央、国务院联合发布的安全生产顶层设计文件，具有里程碑意义。"},
  {"id": 31, "type": "single", "question": "下列选项中，安全生产的监管主体是 （　　） 。", "options": ["政府", "企业", "政府行政首长", "企业法定代表人"], "answer": [0], "explanation": "政府是监管主体，企业是责任主体，行政首长和企业法定代表人是具体责任人。"},
  {"id": 32, "type": "single", "question": "安全生产主体责任，意为安全生产主体承担的安全生产责任，是指责任主体依照法律、法规规定，应当履行的安全生产法定职责和义务，承担责任，接受 （　　） 的追究。", "options": ["未履职", "失职", "法律", "未尽责"], "answer": [3], "explanation": "企业承担安全生产主体责任是指企业在生产经营活动全过程中必须履行安全生产法定职责和义务，承担责任，接受未尽责的追究。"},
  {"id": 33, "type": "single", "question": "2017年9月颁发的《中共上海市委、上海市人民政府关于本市深化安全生产领域改革发展的实施意见》明确指出，企业主要技术负责人负有安全生产技术决策和 （　　） 。", "options": ["专利权", "实施权", "隐私权", "指挥权"], "answer": [3], "explanation": "2017年9月颁发的《中共上海市委、上海市人民政府关于本市深化安全生产领域改革发展的实施意见》明确指出，企业主要技术负责人负有安全生产技术决策和指挥权。"},
  {"id": 34, "type": "single", "question": "下列选项中，不属于安全生产主体责任的特点是 （　　） 。", "options": ["安全生产法定责任是主体责任的底线", "安全生产主体责任内涵不断与时俱进", "安全生产主体责任地方法规政策概览", "安全生产主体责任因企业不同而各有特点"], "answer": [3], "explanation": "2.1.2.3 安全生产主体责任的特点\n1.安全生产法定责任是主体责任的底线\n2.安全生产主体责任内涵不断与时俱进\n3. 安全生产主体责任因行业不同而各有特点\n4.安全生产主体责任地方法规政策概览"},
  {"id": 35, "type": "single", "question": "在施工总承包模式下，施工现场会出现多个施工企业同时作业。如何来管控和协调多个施工企业的合理作业，以免生产安全事故的发生，法律做出了施工现场的安全管理由 （　　） 的规定。", "options": ["各个施工企业负责", "建设单位负总责", "施工总承包企业负总责", "监理单位负总责"], "answer": [2], "explanation": "《建筑法》第四十五条 施工现场安全由建筑施工企业负责。实行施工总承包的，由总承包单位负责。分包单位向总承包单位负责，服从总承包单位对施工现场的安全生产管理。"},
  {"id": 36, "type": "single", "question": "《上海市建设工程质量和安全管理条例》规定，施工单位应当组建施工现场项目管理机构，并根据合同约定配备相应的项目负责人、技术负责人、专职质量管理和安全管理人员等技术、管理人员。上述人员不得（）。", "options": ["经常更换", "擅自更换", "协商更换", "正常更换"], "answer": [1], "explanation": "第二十八条 施工单位应当组建施工现场项目管理机构 ，并根据合同约定配备相应的项目负责人 、技术负责人 、专职质量管理和安全管理人员等技术 、管理人员 。 上述人员不得擅自更换 ，确需更换的，应当经发包单位同意，并不得降低相应的资格条件。前款规定的人员应当是与施工单位建立劳动关系的人员。"},
  {"id": 37, "type": "single", "question": "根据《建设工程安全生产管理条例》的规定，施工单位应当对管理人员和作业人员每年至少进行 （　　） 次安全生产教育培训，其教育培训情况记入个人工作档案。安全生产教育培训考核不合格的人员，不得上岗。", "options": ["一", "二", "三", "四"], "answer": [0], "explanation": "第三十六条 施工单位的主要负责人、项目负责人、专职安全生产管理人员应当经建设行政主管部门或者其他有关部门考核合格后方可任职。施工单位应当对管理人员和作业人员每年至少进行一次安全生产教育培训，其教育培训情况记入个人工作档案。安全生产教育培训考核不合格的人员，不得上岗。"},
  {"id": 38, "type": "single", "question": "依《安全生产法》规定，建筑施工企业从业人员有权对本单位安全生产工作中存在的问题提出批评、检举、控告；有权拒绝 （　　） 和强令冒险作业。", "options": ["随意指挥", "违章指挥", "危险作业", "违章作业"], "answer": [1], "explanation": "《安全生产法》明确规定从业人员有权拒绝“违章指挥”，其他选项非法律原文表述。"},
  {"id": 39, "type": "single", "question": "根据《建设工程安全生产管理条例》的规定，施工单位应当为施工现场从事危险作业的人员办理意外伤害保险。意外伤害保险费由 （　　） 支付。", "options": ["施工单位", "建设单位", "总包单位", "分包单位"], "answer": [0], "explanation": "第三十八条 施工单位应当为施工现场从事危险作业的人员办理意外伤害保险。意外伤害保险费由施工单位支付。"},
  {"id": 40, "type": "single", "question": "根据《安全生产法》规定，建筑施工企业对重大危险源应当 （　　） 。", "options": ["登记", "建档", "记录登记", "登记建档"], "answer": [3], "explanation": "《安全生产法》要求对重大危险源“登记建档”，其他选项不完整。"},
  {"id": 41, "type": "single", "question": "《上海市建设工程质量和安全管理条例》规定，施工单位应当在建筑起重机械和整体提升脚手架、模板等自升式架设设施使用和拆除前，向 （　　） 或者其他有关部门登记。", "options": ["上级行政管理部门", "建设行政管理部门", "安全管理部门", "质量管理部门"], "answer": [1], "explanation": "施工单位应当在建筑起重机械和整体提升脚手架、模板等自升式架设设施使用和拆除前 ,向建设行政管理部门或者其他有关部门登记。"},
  {"id": 42, "type": "single", "question": "根据《上海市建设工程质量和安全管理条例》规定，施工单位应当按照合同约定的施工工期进行施工，并按照 （　　） 和施工组织设计文件顺序施工，不得违反技术标准压缩工期和交叉作业。", "options": ["国家标准", "行业标准", "企业标准", "技术标准"], "answer": [3], "explanation": "第三十条施工单位应当按照合同约定的施工工期进行施工,并按照技术标准和施工组织设计文件顺序施工,不得违反技术标准压缩工期和交叉作业。"},
  {"id": 43, "type": "single", "question": "《建筑法》规定，施工现场安全由 （　　） 负责。", "options": ["建筑施工企业", "分包单位", "建设单位", "保险公司"], "answer": [0], "explanation": "第四十五条 施工现场安全由建筑施工企业负责。"},
  {"id": 44, "type": "single", "question": "施工项目的安全检查应由 （　　） 组织，定期进行。", "options": ["项目经理", "项目技术负责人", "专职安全员", "企业安全生产部门"], "answer": [0], "explanation": "安全检查由“项目经理”组织，其他人员或部门无此职责。"},
  {"id": 45, "type": "single", "question": "《安全生产法》规定，建筑施工企业应当建立应急救援组织；生产经营规模较小的，可以不建立应急救援组织，但应当指定 （　　） 。", "options": ["现场安全救援人员", "专职安全生产管理人员", "专职的应急救援人员", "兼职的应急救援人员"], "answer": [3], "explanation": "《中华人民共和国安全生产法》第七十九条第一款规定： 危险物品的生产、经营、储存单位以及矿山、金属冶炼、城市轨道交通运营、建筑施工单位应当建立应急救援组织；生产经营规模较小的，可以不建立应急救援组织，但应当指定兼职的应急救援人员。"},
  {"id": 46, "type": "single", "question": "依法设置安全生产管理机构，配齐配强专职安全生产管理人员（包含注册安全工程师）等专业安全管理人员，属于施工企业安全生产责任五落实中的 （　　） 。", "options": ["必须落实“党政同责”要求", "必须落实安全生产组织领导机构", "必须落实安全生产“一岗双责”", "必须落实安全管理力量"], "answer": [3], "explanation": "题目描述属于“落实安全生产组织领导机构”的内容，其他选项重复或无关。"},
  {"id": 47, "type": "single", "question": "建立健全企业全员安全生产责任制， （　　） 要指定专人组织制订并实施本企业全员安全生产教育和培训计划。", "options": ["企业主要负责人", "企业法定代表人", "项目负责人", "专职安全生产管理人员"], "answer": [0], "explanation": "企业主要负责人要指定专人组织制定并实施本企业全员安全生产教育和培训计划。"},
  {"id": 48, "type": "single", "question": "根据《建设工程安全生产管理条例》的规定， （　　） 进入新的岗位或者新的施工现场前，应当接受安全生产教育培训。未经教育培训或者教育培训考核不合格的人员，不得上岗作业。", "options": ["作业人员", "企业负责人", "项目负责人", "专职质量管理人员"], "answer": [0], "explanation": "条例规定“作业人员”需接受岗前安全培训，其他人员无此明确要求。"},
  {"id": 49, "type": "single", "question": "下列施工作业人员的做法中，属于行使紧急避险权的是 （　　） 。", "options": ["甲凭经验判断脚手架可能不稳向现场管理人员提出加固意见", "乙发现基坑四周地表现出大量裂纹并有土石滑落现象，立即报告现场安全管理人员", "丙因为安全帽损坏，回到工人宿舍更换", "丁发现吊装预制构件欲脱落而拒绝继续作业并迅速躲避"], "answer": [3], "explanation": "紧急避险权 是指从业人员在发现直接危及人身安全的紧急情况时，有权停止作业或采取应急措施后撤离。 D选项 中，丁因吊装故障拒绝作业并躲避，符合紧急避险的定义。 A、B选项属于报告行为，C选项属于个人防护措施，均不属于紧急避险。"},
  {"id": 50, "type": "single", "question": "根据《上海市建设工程质量和安全管理条例》的规定，施工单位应当在施工现场建立消防安全责任制度，具体的措施不包括 （　　） 。", "options": ["确定消防安全责任人", "设置消防通道、消防水源", "制定用火、用电、使用易燃易爆材料等各项消防安全管理制度和操作规程", "配备消防设施和灭火器材，施工现场出口处需要设置明显标志"], "answer": [3], "explanation": "第三十一条施工单位应当在施工现场建立消防安全责任制度，确定消防安全责任人，制定用火、用电、使用易燃易爆材料等各项消防安全管理制度和操作规程，设置消防通道、消防水源，配备消防设施和灭火器材，并在施工现场【入口】处设置明显标志。"},
  {"id": 51, "type": "single", "question": "根据《建设工程安全生产管理条例》的规定，发生生产安全事故后，实行施工总承包的建设工程，由 （　　） 单位负责上报事故。", "options": ["分包", "总承包", "总承包和分包", "发包"], "answer": [1], "explanation": "《建设工程安全生产管理条例》规定，总承包单位 对施工现场安全负总责，事故上报由其负责。"},
  {"id": 52, "type": "single", "question": "全面加强企业全员安全生产责任制工作，是推动企业落实安全生产主体责任的重要抓手，有利于减少企业 （　　） 的“三违”现象发生。", "options": ["违章指挥、违章作业、违反劳动纪律", "违章生产、违章指挥、违反劳动纪律", "违章指挥、违章作业、违反治安", "违章指挥、违章作业、违反施工工序"], "answer": [0], "explanation": "“三违”指 违章指挥、违章作业、违反劳动纪律，选项A正确，其他选项重复或表述不准确。"},
  {"id": 53, "type": "single", "question": "根据《建设工程安全生产管理条例》的规定，施工单位应当自施工起重机械和整体提升脚手架、模板等自升式架设设施验收合格之日起 （　　） 日内，向建设行政主管部门或者其他有关部门登记。", "options": ["15", "20", "25", "30"], "answer": [3], "explanation": "法规规定，验收合格后 30日内 需登记，因此选D。"},
  {"id": 54, "type": "single", "question": "安全生产监管部门检查某建设工程项目施工现场，发现了如下行为，①施工现场办公区和生活区混设在一起，毗邻排列；②现场的安全防护用具有生产许可证、产品合格证；③有3名电工没有资格证书；④施工现场脚手架、出入通道口没有安全警示标志。其中不符合安全和文明施工要求的行为有 （　　） 处。", "options": ["1", "2", "3", "4"], "answer": [2], "explanation": "不符合要求的行为： 办公区与生活区混设（违反分区规定）； 无证电工（违反持证上岗规定）； 无安全警示标志（违反安全标识规定）。 ②符合要求（安全防护用具证件齐全）。 共 3处 不符合要求，选C。"},
  {"id": 55, "type": "single", "question": "经过 （　　） 阶段，安全生产许可证制度在建筑施工企业基本确立。", "options": ["动态管理", "常态管理", "全面推进", "部署启动"], "answer": [2], "explanation": "经过全面推进阶段，安全生产许可证制度在建筑施工企业基本确立。"},
  {"id": 56, "type": "single", "question": "我国安全生产许可证的有效期为 （　　） 年。", "options": ["一", "二", "三", "四"], "answer": [2], "explanation": "安全生产许可证有效期为 3年，到期需办理延期。"},
  {"id": 57, "type": "single", "question": "许可证制度要求企业配备专职安全生产管理人员，设立 （　　） ,这样稳定了队伍，也使安全管理人员的素质不断提高。", "options": ["安全部门", "安全领导小组", "兼职机构", "专职机构"], "answer": [3], "explanation": "第十二条 企业应当依法设置安全生产管理机构，配备专职安全生产管理人员。配备的专职安全生产管理人员必须能够满足安全生产的需要。"},
  {"id": 58, "type": "single", "question": "住房城乡建设主管部门应当自受理建筑施工企业的申请之日起 （　　） 日内审查完毕；经审查符合安全生产条件的，颁发安全生产许可证。", "options": ["15", "20", "30", "45"], "answer": [3], "explanation": "法规规定审查期限为 45日，符合条件则颁发许可证。"},
  {"id": 59, "type": "single", "question": "建筑施工企业遗失安全生产许可证，应当立即向原安全生产许可证颁发管理机关报告，并在 （　　） 上声明作废后，方可申请补办。", "options": ["自媒体", "公众媒体", "企业网站", "告示栏"], "answer": [1], "explanation": "第十一条 建筑施工企业遗失安全生产许可证，应当立即向原安全生产许可证颁发管理机关报告，并在公众媒体上声明作废后，方可申请补办。"},
  {"id": 60, "type": "single", "question": "根据《建筑施工企业安全生产许可证管理规定》，企业在安全生产许可证有效期内，严格遵守有关安全生产的法律法规，未发生死亡事故的，安全生产许可证有效期届满时，经原发证管理机关同意，不再审查，安全生产许可证有效期延期 （　　） 年。", "options": ["1", "2", "3", "4"], "answer": [2], "explanation": "符合条件的企业，许可证可 延期3年，无需重新审查。"},
  {"id": 61, "type": "single", "question": "根据《建筑施工企业安全生产许可证管理规定》，建筑施工企业申请安全生产许可证时，应当向住房城乡建设主管部门提供的材料是 （　　） 。", "options": ["企业资质证书", "企业法人营业执照", "设计报告", "安全生产承诺书"], "answer": [1], "explanation": "建筑施工企业申请安全生产许可证时,应当向住房城乡建设主管部门提供下列材料:\n(1)建筑施工企业安全生产许可证申请表;(2)企业法人营业执照;(3)与申请安全生产许可证应当具备的安全生产条件相关的文件、材料。"},
  {"id": 62, "type": "single", "question": "建筑施工企业应当加强对本企业和承建工程安全生产条件的 （　　） 检查，发现不符合法定安全生产条件的，应当立即进行整改，并做好自查和整改记录。", "options": ["日常静态", "日常动态", "定时定点", "随机"], "answer": [1], "explanation": "安全生产检查需 动态进行（即持续、实时监控），而非静态或随机抽查，以确保及时发现并整改隐患。"},
  {"id": 63, "type": "single", "question": "市、县级人民政府建设主管部门或其委托的建筑安全监督机构在日常安全生产监督检查中，应当查验承建工程施工企业的 （　　） 。", "options": ["企业营业执照", "安全技术措施方案", "安全生产许可证", "工程中标通知书"], "answer": [2], "explanation": "根据《建筑施工企业安全生产许可证动态监管暂行办法》，市、县级人民政府建设主管部门或其委托的建筑安全监督机构在日常安全生产监督检查中，应当查验承建工程施工企业的安全生产许可证。"},
  {"id": 64, "type": "single", "question": "工程承建企业跨省施工的，工程所在地省级建设主管部门应当在事故发生之日起 （　　） 日内将事故基本情况书面通报颁发管理机关，同时附具企业及有关项目违法违规事实和证明安全生产条件降低的相关询问笔录或其它证据材料。", "options": ["10", "15", "20", "30"], "answer": [1], "explanation": "跨省施工事故需在 15日内 通报，确保及时跨区域监管协作。"},
  {"id": 65, "type": "single", "question": "暂扣安全生产许可证处罚视事故发生级别和安全生产条件降低情况，按下列标准执行：发生重大事故的，暂扣安全生产许可证 （　　） 。", "options": ["30至60日", "60至90日", "90至120日", "90至150日"], "answer": [2], "explanation": "暂扣安全生产许可证处罚视事故发生级别和安全生产条件降低情况，按下列标准执行：\n（一）发生一般事故的，暂扣安全生产许可证30至60日。\n（二）发生较大事故的，暂扣安全生产许可证60至90日。\n（三）发生重大事故的，暂扣安全生产许可证90至120日。"},
  {"id": 66, "type": "single", "question": "建筑施工企业安全生产许可证被暂扣期间，企业在 （　　） 不得承揽新的工程项目。", "options": ["注册所在地", "全国范围内", "注册地所在省", "注册地所在直辖市"], "answer": [1], "explanation": "暂扣期间，企业 全国范围内 禁止承揽新项目，确保处罚效力。"},
  {"id": 67, "type": "single", "question": "安全生产许可证颁发管理机关作出准予颁发申请人安全生产许可证决定的，应当自决定之日起10个工作日内向申请人颁发、送达安全生产许可证；对作出不予颁发决定的，应当在 （　　） 个工作日内书面通知申请人并说明理由。", "options": ["5", "10", "15", "20"], "answer": [1], "explanation": "安全生产许可证颁发管理机关作出准予颁发申请人安全生产许可证决定的，应当自决定之日起10个工作日内向申请人颁发、送达安全生产许可证；对作出不予颁发决定的，应当在10个工作日内书面通知申请人并说明理由。"},
  {"id": 68, "type": "single", "question": "建筑施工企业应当承担“吊销安全生产许可证”法律责任的违法行为是 （　　） 。", "options": ["取得安全生产许可证后，发生较大安全事故的", "建筑施工企业在安全生产许可证暂扣期内，拒不整改的", "未取得安全生产许可证擅自进行生产的", "安全生产许可证有效期满未办理延期手续，继续从事建筑施工活动的"], "answer": [1], "explanation": "吊销许可证 的严重情形包括 暂扣期内拒不整改（B选项）。其他选项可能面临罚款或暂扣，但未必直接吊销。"},
  {"id": 69, "type": "single", "question": "根据《建筑施工企业安全生产许可证动态监管暂行办法》，对于安全生产工作成效显著、连续 （　　） 年及以上未被暂扣安全生产许可证的企业，在评选各级各类安全生产先进集体和个人、文明工地、优质工程等项目时可以优先考虑，并可根据本地实际情况在监督管理时采取有关优惠政策措施。", "options": ["半", "一", "两", "三"], "answer": [3], "explanation": "对于安全生产工作成效显著、连续三年及以上未被暂扣安全生产许可证的企业，在评选各级各类安全生产先进集体和个人、文明工地、优质工程等时可以优先考虑，并可根据本地实际情况在监督管理时采取有关优惠政策措施。"},
  {"id": 70, "type": "single", "question": "审批后续项目监管是指市、区建设行政管理部门作出安全生产许可证审批决定后， （　　） 内对建筑施工企业新建项目进行安全生产条件的核查。", "options": ["一个月", "两个月", "一年", "二年"], "answer": [1], "explanation": "审批后续项目监管是指市、区建设行政管理部门作出安全生产许可证审批决定后，两个月内对建筑施工企业新建项目进行安全生产条件的核查。"},
  {"id": 71, "type": "single", "question": "关于建筑施工企业安全生产许可证延期的说法，正确的是 （　　） 。", "options": ["企业在安全生产许可证有效期内未发生死亡事故的，安全生产许可证自动续期", "安全生产许可证的有效期为5年", "安全生产许可证有效期满前3个月向原颁发管理机关办理延期手续", "安全生产许可证遗失补办，由申请人告知资质许可机关，由资质许可机关在官网发布信息"], "answer": [2], "explanation": "《安全生产许可证条例》第九条 安全生产许可证的有效期为3年。安全生产许可证有效期满需要延期的，企业应当于期满前3个月向原安全生产许可证颁发管理机关办理延期手续。\n企业在安全生产许可证有效期内，严格遵守有关安全生产的法律法规，未发生死亡事故的，安全生产许可证有效期届满时，经原安全生产许可证颁发管理机关同意，不再审查，安全生产许可证有效期延期3年。\n《建筑施工企业安全生产许可证管理规定》第十一条 建筑施工企业遗失安全生产许可证，应当立即向原安全生产许可证颁发管理机关报告，并在公众媒体上声明作废后，方可申请补办。"},
  {"id": 72, "type": "single", "question": "上海市住房和城乡建设管理委员会下发的《关于本市建筑施工企业安全生产许可证实施告知承诺电子化审批的通知》中指出，市、区建设行政管理部门在作出行政审批决定后，在 （　　） 个月内，对无在建工地的企业的人员配置及社保情况进行核实。", "options": ["一", "二", "三", "四"], "answer": [1], "explanation": "市、区建设行政管理部门在作出行政审批决定后，在二个月内，对无在建工地的企业的人员配置及社保情况进行核实；"},
  {"id": 73, "type": "single", "question": "安全生产许可证针对的对象是 （　　） ，取得该证，反映具备了相关的安全条件。", "options": ["企业", "具体的工程项目", "部门", "岗位"], "answer": [0], "explanation": "企业要进行生产,就必须依法取得安全生产许可证。要取得安全生产许可证,就必须具备相应的安全生产条件。"},
  {"id": 74, "type": "single", "question": "根据《关于本市建筑施工企业安全生产许可证实施告知承诺电子化审批的通知》的规定，本市建筑施工企业安全生产许可证实行 （　　） 行政审批。", "options": ["直接取消", "备案管理", "告知承诺", "精简许可条件"], "answer": [2], "explanation": "为贯彻落实党中央、国务院关于推进政府职能转变和深化“放管服”改革的重大决策，根据《上海市行政审批告知承诺管理办法》（沪府令第4号）要求，本市建筑施工企业安全生产许可证实行告知承诺电子化审批，市住房城乡建设管理委制定了《上海市建筑施工企业安全生产许可证告知承诺电子化审批实施细则》。"},
  {"id": 75, "type": "single", "question": "建筑工程办理安全备案手续需要的材料中，不包括 （　　） 。", "options": ["工程中标通知书", "项目经理安全生产能力考核证书", "安全A类人员证书", "安全技术措施方案"], "answer": [2], "explanation": "建筑工程安全备案需要的材料：工程中标通知书、项目经理安全生产能力考核证书、安全技术措施方案、安全生产许可证、安全C类人员证书等。"},
  {"id": 76, "type": "single", "question": "下列安全生产条件中，属于取得建筑施工企业安全生产许可证首要条件的是 （　　） 。", "options": ["制定完备的安全生产规章制度和操作规程", "配备专职应急救援人员", "针对职业危害制订应急救援预案", "为施工现场全体人员办理意外伤害险"], "answer": [0], "explanation": "首要条件 是建立 安全生产规章制度和操作规程（A选项），其他选项为辅助条件。"},
  {"id": 77, "type": "single", "question": "根据《安全生产法》的规定，下列选项中可以不设置安全生产管理机构或者配备专职安全生产管理人员的是 （　　） 。", "options": ["金属冶炼单位", "建筑施工、运输单位", "危险物品经营单位", "医用过氧化氢消毒液生产单位"], "answer": [3], "explanation": "第二十四条 矿山、金属冶炼、建筑施工、运输单位和危险物品的生产、经营、储存、装卸单位，应当设置安全生产管理机构或者配备专职安全生产管理人员。"},
  {"id": 78, "type": "single", "question": "在部分大型建筑施工企业中，安委会下设 （　　） ，负责安委会的日常工作。", "options": ["安全小组", "专职办公室", "领导小组", "安委会办公室"], "answer": [3], "explanation": "安委会日常工作由 安委会办公室 负责，其他选项非标准名称。"},
  {"id": 79, "type": "single", "question": "工程项目经理部是施工 （　　） 管理机构，必须依据工程特点，建立以项目经理为首的安全生产领导小组。", "options": ["企业", "第一线", "组织", "重要的"], "answer": [1], "explanation": "工程项目经理部是施工第一线的管理机构。"},
  {"id": 80, "type": "single", "question": "项目负责人对本项目安全生产管理 （　　） ，应当建立项目安全生产管理体系，明确项目管理人员安全职责，落实安全生产管理制度，确保项目安全生产费用有效使用。", "options": ["局部负责", "全面负责", "专项负责", "日常负责"], "answer": [1], "explanation": "项目负责人对安全生产 全面负责，需统筹管理体系、职责、费用等。"},
  {"id": 81, "type": "single", "question": "企业安全生产管理机构专职安全生产管理人员应当检查在建项目安全生产管理情况，重点检查项目负责人、项目专职安全生产管理人员履责情况，处理 （　　） ，并记入企业安全管理档案。", "options": ["在建项目安全事故隐患问题", "在建项目违规违章行为", "施工质量安全问题", "监控危险性较大的分项工程"], "answer": [1], "explanation": "《企建筑施工业主要负责人、项目负责人和专职安全生产管理人员安全生产管理规定》第19条 企业安全生产管理机构专职安全生产管理人员应当检查在建项目安全生产管理情况，重点检查项目负责人、项目专职安全生产管理人员履责情况，处理在建项目违规违章行为，并记入企业安全管理档案。"},
  {"id": 82, "type": "single", "question": "根据《建筑施工企业负责人及项目负责人施工现场带班暂行办法》的规定，项目负责人每月带班生产时间不得少于本月施工时间的 （　　） 。", "options": ["60%", "70%", "80%", "90%"], "answer": [2], "explanation": "法规要求项目负责人现场带班时间 ≥80%，确保现场管理有效性。"},
  {"id": 83, "type": "single", "question": "根据《关于进一步贯彻落实建筑施工企业负责人及项目负责人施工现场带班制度的通知》规定，企业法定代表人是落实企业负责人及项目负责人施工现场带班制度的 （　　） ,对落实带班制度全面负责。", "options": ["第一责任人", "主要负责人", "现场责任人", "管理责任人"], "answer": [0], "explanation": "建筑施工企业法定代表人是落实企业负责人及项目负责人施工现场带班制度的第一责任人，对落实带班制度全面负责。"},
  {"id": 84, "type": "single", "question": "根据《关于进一步贯彻落实建筑施工企业负责人及项目负责人施工现场带班制度的通知》要求，项目负责人应当确保每月在现场带班生产的实际时间不少于本月施工时间的 （　　） ，不得擅自脱岗。", "options": ["20%", "25%", "30%", "80%"], "answer": [3], "explanation": "项目负责人必须确保每月在现场带班生产的实际时间不少于本月施工时间的80%,不得擅自离岗。"},
  {"id": 85, "type": "single", "question": "企业安全生产委员会是企业法人建立的安全生产管理 （　　） 机构。", "options": ["决策", "执行", "基层调研", "培训"], "answer": [0], "explanation": "安全生产委员会是企业法人必须依法建立的安全生产决专策机构，一般由企业法人或其委托代理人牵头负责，企业各分管领导、各职能部门负责人为成员，任务是研究、分析和解决企业重大安全生产属问题。安全管理机构负责落实日产工作，遇到重大问题，要及时向安全生产委员会报告，由安委会决策。"},
  {"id": 86, "type": "single", "question": "下列选项中不属于建筑施工企业安全生产管理机构的主要职责的是 （　　） 。", "options": ["宣传和贯彻国家有关安全生产法律法规和标准", "编制并适时更新安全生产管理制度并监督实施", "组织或参与企业生产安全事故应急救援预案的编制及演练", "综合管理施工企业的安全生产工作，分析和预测公司安全生产形势，拟订施工企业安全生产规划，指导、协调和监督施工企业所属各单位做好安全生产管理"], "answer": [3], "explanation": "《建筑施工企业安全生产管理机构设置及专职安全生产管理人员配备办法》\n第六条规定，建筑施工企业安全生产管理机构具有以下职责:\n(一）宣传和贯彻国家有关安全生产法律法规和标准;\n(二）编制并适时更新安全生产管理制度并监督实施;\n(三)组织或参与企业生产安全事故应急救援预案的编制及演练;\n(四）组织开展安全教育培训与交流;\n(五）协调配备项目专职安全生产管理人员;\n(六）制订企业安全生产检查计划并组织实施;\n(七）监督在建项目安全生产费用的使用;\n(八）参与危险性较大工程安全专项施工方案专家论证会;\n(九）通报在建项目违规违章查处情况;\n(十）组织开展安全生产评优评先表彰工作;\n(十一）建立企业在建项目安全生产管理档案;\n(十二)考核评价分包企业安全生产业绩及项目安全生产管理情况;\n(十三）参加生产安全事故的调查和处理工作;\n(十四）企业明确的其他安全生产管理职责。"},
  {"id": 87, "type": "single", "question": "依据工程特点，建立以项目经理为首的安全生产领导小组，称为 （　　） 。", "options": ["工程项目经理部", "安全管理部", "安委会办公室", "安全技术处"], "answer": [0], "explanation": "工程项目经理部是施工第一线的管理机构，必须依据工程特点，建立以项目经理为首的安全生产领导小组。"},
  {"id": 88, "type": "single", "question": "项目负责人，是指取得相应注册执业资格，由 （　　） 授权，负责具体工程项目管理的人员。", "options": ["副总工程师", "副总经理", "企业法定代表人", "总工程师"], "answer": [2], "explanation": "项目负责人，是指取得相应注册执业资格，由企业法定代表人授权，负责具体工程项目管理的人员。"},
  {"id": 89, "type": "single", "question": "根据住建部令（第17号）的规定，安全生产考核合格证书有效期为3年，证书在 （　　） 范围内有效。", "options": ["全国", "户籍所在地", "单位所在地", "考核所在地"], "answer": [0], "explanation": "安全生产考核合格证书 全国有效（A选项），不受地域限制。"},
  {"id": 90, "type": "single", "question": "根据住建部令（第17号）的规定，安全生产考核合格证书有效期届满需要延续的，由本人通过受聘企业向原考核机关申请证书延续。准予证书延续的，证书有效期延续 （　　） 年。", "options": ["3", "4", "5", "6"], "answer": [0], "explanation": "第十条 安全生产考核合格证书有效期届满需要延续的，“安管人员”应当在有效期届满前3个月内，由本人通过受聘企业向原考核机关申请证书延续。准予证书延续的，证书有效期延续3年。"},
  {"id": 91, "type": "single", "question": "根据《建筑施工企业安全生产管理机构设置及专职安全生产管理人员配备办法》的规定，安全生产领导小组的主要职责不包括 （　　） 。", "options": ["贯彻落实国家有关安全生产法律法规和标准", "组织制定项目安全生产管理制度并监督实施", "编制项目生产安全事故应急救援预案并组织演练", "组织编制所有工程安全专项施工方案"], "answer": [3], "explanation": "安全生产领导小组的主要职责：\n（1）贯彻落实国家有关安全生产法律法规和标准；\n（2）组织制定项目安全生产管理制度并监督实施；\n（3）编制项目生产安全事故应急救援预案并组织演练；\n（4）保证项目安全生产费用的有效使用；\n（5）组织编制危险性较大工程安全专项施工方案；\n（6）开展项目安全教育培训；\n（7）组织实施项目安全检查和隐患排查；\n（8）建立项目安全生产管理档案；\n（9）及时、如实报告安全生产事故。"},
  {"id": 92, "type": "single", "question": "根据《建筑施工企业负责人及项目负责人施工现场带班暂行办法》的规定， （　　） 是工程项目质量安全管理的第一责任人，应对工程项目落实带班制度负责。", "options": ["项目负责人", "企业负责人", "专职安全人员", "技术负责人"], "answer": [0], "explanation": "项目负责人（A选项）是现场质量安全管理的 第一责任人，直接负责带班制度的落实。企业负责人负总责，但非一线管理。"},
  {"id": 93, "type": "single", "question": "根据《关于进一步贯彻落实建筑施工企业负责人及项目负责人施工现场带班制度的通知》的规定，项目负责人带班工作主要内容不包括 （　　） 。", "options": ["全面掌握工程项目质量安全生产状况，即人员到岗情况、设备情况、生产（作业环境）安全情况、施工质量情况、生产任务完成情况等", "组织施工管理人员，检查安全质量规章制度、安全质量措施在施工现场的执行和落实情况", "检查企业负责人带班生产情况", "确保安全生产费用的有效使用，组织制定和实施安全质量措施，加强对重点部位、关键环节的控制，及时消除安全质量隐患"], "answer": [2], "explanation": "项目负责人带班工作内容：\n1、全面掌握工程项目质量安全生产状况，即人员到岗情况、设备情况、生产（作业环境）安全情况、施工质量情况、生产任务完成情况等。落实班前安全生产教育等安全生产责任制度和质量责任制、安全生产规章制度和操作规程；\n2、组织施工管理人员，检查安全质量规章制度、安全质量措施在施工现场的执行和落实情况；\n3、确保安全生产费用的有效使用，组织制定和实施安全质量措施，加强对重点部位、关键环节的控制，及时消除安全质量隐患；\n4、督促检查当班生产所涉及的施工方案、安全专项方案、安全质量措施的编制和落实，组织、督促开展技术交底、安全技术交底工作；\n5、危险性较大的分部分项工程及大体积混凝土灌注、桩基灌注、箱梁灌注等重要关键环节施工，项目负责人必须现场带班。"},
  {"id": 94, "type": "single", "question": "下列施工单位人员中不一定经建设主管部门安全教育培训或者经考核合格即可任职的是 （　　） 。", "options": ["企业主要负责人", "项目技术员", "项目经理", "项目安全生产管理人员"], "answer": [1], "explanation": "项目技术员（B选项）主要负责技术工作，法规未强制要求其通过安全教育培训或考核。其他选项（企业负责人、项目经理、安全管理人员）均需经培训考核合格。"},
  {"id": 95, "type": "single", "question": "安全生产标准化是 （　　） 工作一部分。", "options": ["标准化", "企业安全生产标准化", "国家安全生产标准化", "国家标准化"], "answer": [2], "explanation": "建设工程安全生产标准化是全国企业安全生产标准化的一部分。"},
  {"id": 96, "type": "single", "question": "下列选项中不是标准特性的是 （　　） 。", "options": ["权威性", "强制性", "民主性", "实用性"], "answer": [1], "explanation": "标准的特性是：\n一是权威性。\n二是民主性。\n三是实用性。\n四是科学性。"},
  {"id": 97, "type": "single", "question": "标准要由权威机构批准发布，在相关领域有技术权威，为社会所公认。体现了标准的 （　　） 。", "options": ["权威性", "民主性", "实用性", "科学性"], "answer": [0], "explanation": "由权威机构发布并公认的特性体现的是标准的 权威性（A选项）。"},
  {"id": 98, "type": "single", "question": "行业标准由 （　　） 制定。", "options": ["国务院标准化行政主管部门", "国务院有关行政主管部门", "省、自治区、直辖市", "行业协会"], "answer": [1], "explanation": "行业标准由国务院有关行政主管部门制定,并报国务院标准化行政主管部门本案,在公布国家标准之后,该行业标准即行废止。"},
  {"id": 99, "type": "single", "question": "企业安全管理制度的基础是 （　　） 。", "options": ["消防安全制度", "施工设施安全管理制度", "安全生产责任制", "危险作业管理制度"], "answer": [2], "explanation": "安全生产责任制（C选项）是企业安全管理制度的基石，明确各级人员的安全职责。"},
  {"id": 100, "type": "single", "question": "安全生产管理制度是将安全文化从观念文化向 （　　） 转化的保障，是在安全理念要求下需要遵守的一系列办事规程和行动准则。", "options": ["实践文化", "行为文化", "理论文化", "意识文化"], "answer": [1], "explanation": "安全管理制度是将安全文化从观念文化向行为文化转化的保障,其定义了在安全理念的要求下需要遵守的一系列办事规程和行动准则。"},
  {"id": 101, "type": "single", "question": "通过创建安全生产标准化，对危险有害因素进行系统的识别、评估，制订相应的防范措施，使隐患排查工作制度化、规范化和常态化，切实改变运动式的工作方法，对危险源做到 （　　） 。", "options": ["可防可控", "绝对控制", "相对控制", "有效控制"], "answer": [0], "explanation": "安全生产标准化的目标是实现危险源的 可防可控（A选项），而非绝对消除。"},
  {"id": 102, "type": "single", "question": "根据《建筑施工安全生产标准化考评暂行办法》中所称建筑施工安全生产标准化考评包括建筑施工项目安全生产标准化考评和 （　　） 考评。", "options": ["建筑施工分包安全生产标准化", "建筑施工总承包安全生产标准化", "建筑施工质量安全生产标准化", "建筑施工企业安全生产标准化"], "answer": [3], "explanation": "第三条本办法所称建筑施工安全生产标准化考评包括建筑施工项目安全生产标准化考评和建筑施工企业安全生产标准化考评。"},
  {"id": 103, "type": "single", "question": "根据《建筑施工安全生产标准化考评暂行办法》规定，建筑施工企业在办理安全生产许可证延期时，应当向 （　　） 提交企业自评材料。", "options": ["县级及以上住房城乡建设主管部门", "项目所在地安全管理部门", "企业考评主体", "行业考评主体"], "answer": [2], "explanation": "第二十五条 建筑施工企业在办理安全生产许可证延期时，应当向企业考评主体提交企业自评材料。"},
  {"id": 104, "type": "single", "question": "根据《上海市建筑施工安全生产标准化考评规范》的规定，分包竣工后，总包企业在分包退场后 （　　） 工作日内，对分包进行竣工评定，并将评定结果及时在网上填报。", "options": ["3个", "5个", "10个", "15个"], "answer": [1], "explanation": "第十二条 分包竣工后,总包企业在分包退场后5个工作日内,对分包进行竣工评定,并将评定结果及时在网上填报。"},
  {"id": 105, "type": "single", "question": "根据《上海市建筑施工安全生产标准化考评规范》的规定，建筑施工企业应当成立企业安全生产标准化自评机构，每年主要依据 （　　） 开展企业安全生产标准化自评工作。", "options": ["《施工企业安全生产评价标准》", "《现场施工安全生产管理规范》", "《上海市建筑施工安全质量标准化工作实施办法》", "《建筑施工安全生产标准化考评暂行办法》"], "answer": [0], "explanation": "第二十三条 建筑施工企业应当成立企业安全生产标准化自评机构,每年主要依据《施工企业安全生产评价标准》(JGJ/T77-2010)开展企业安全生产标准化自评工作。"},
  {"id": 106, "type": "single", "question": "《关于贯彻落实<上海市建筑施工安全生产标准化考评规范>若干事项的通知》中提出了严格过程管理，施工项目总包项目部均应严格按照《建筑施工安全检查标准》及相关法律、法规、规范、文件等每周对包括危险性较大分部分项工程在内的安全管理和实物状况，以往日、周检查发现的隐患整改情况等进行隐患排查，并将检查情况和整改落实情况如实填至信息系统，每月填报次数不得少于 （　　） 。", "options": ["二次", "三次", "四次", "五次"], "answer": [2], "explanation": "施工项目总包项目部均应严格按照《建筑施工安全检查标准》(JGJ59)及相关法律、法规、规范、文件等每周对包括危险性较大分部分项工程在内的安全管理和实物状况，以往日、周检查发现的隐患整改情况等进行隐患排查，并将检查情况和整改落实情况如实填至信息系统，每月填报次数不得少于四次。"},
  {"id": 107, "type": "single", "question": "《施工企业安全生产评价标准》（JGJ/T77-2010）规定，不属于施工企业安全生产条件考核内容的是 （　　） 。", "options": ["安全生产管理", "安全技术管理", "企业自发性行为", "设备和设施管理"], "answer": [2], "explanation": "安全生产条件考核内容包括 安全生产管理、安全技术管理、设备和设施管理，而 企业自发性行为（C选项）不属于考核内容。"},
  {"id": 108, "type": "single", "question": "《关于开展建筑施工安全生产标准化考评工作的指导意见》指出，建筑施工企业安全生产标准化考评工作应当以 （　　） 为基础，考评主体在对其安全生产许可证延期审查时，同步开展安全生产标准化考评工作。", "options": ["建设单位评定", "监理单位评定", "建筑施工企业自评", "建设主管评定"], "answer": [2], "explanation": "建筑施工企业安全生产标准化考评工作应当以建筑施工企业自评为基础，建筑施工企业应当成立以法定代表人为第一责任人的安全生产标准化工作机构，明确工作目标，制定工作计划，组织开展企业安全生产标准化工作。"},
  {"id": 109, "type": "single", "question": "《建筑施工安全生产标准化考评暂行办法》明确，建筑施工企业应当建立健全以 （　　） 为第一责任人的项目安全生产管理体系，依法履行安全生产职责，实施项目安全生产标准化工作。", "options": ["监理工程师", "项目负责人", "技术负责人", "法定代表人"], "answer": [1], "explanation": "第七条 建筑施工企业应当建立健全以项目负责人为第一责任人的项目安全生产管理体系，依法履行安全生产职责，实施项目安全生产标准化工作。"},
  {"id": 110, "type": "single", "question": "《建筑施工安全生产标准化考评暂行办法》规定，安全生产标准化评定为优良的建筑施工项目数量，原则上不超过所辖区域内本年度拟竣工项目数量的 （　　） 。", "options": ["5%", "8%", "10%", "12%"], "answer": [2], "explanation": "第十七条 各省级住房城乡建设部门可结合本地区实际确定建筑施工项目安全生产标准化优良标准。\n安全生产标准化评定为优良的建筑施工项目数量，原则上不超过所辖区域内本年度拟竣工项目数量的10%。"},
  {"id": 111, "type": "single", "question": "《上海市建筑施工安全生产标准化考评规范》规定，施工项目开工后， （　　） 应在10个工作日内在上海建筑建材业网进行安全生产标准化管理信息申报。", "options": ["总包企业", "分包企业", "建设单位", "监理单位"], "answer": [0], "explanation": "第六条 总包企业以该施工项目建设单位发包的施工合同为单位，生成安全生产标准化管理单元。施工项目开工后10个工作日内， 总包企业在上海建筑建材业网进行安全生产标准化管理信息申报，由受监监督机构审查受理，主要管理信息包括：\n（一）参建各方；\n（二）三类人员；\n（三）专业承包及劳务分包单位；\n（四）危险性较大分部分项工程；\n（五）大型机械；\n（六）文明工地创建预申报。 主要管理信息发生变化时，由相关权限方在网上予以变更。"},
  {"id": 112, "type": "single", "question": "《上海市建筑施工安全生产标准化考评规范》规定， （　　） 负责每周组织各分包，对施工项目及日巡查情况进行全面检查，并督促责任单位落实整改，检查和整改情况及时进行网上填报。", "options": ["专职安全生产管理人员", "总包、分包的项目负责人", "企业负责人", "总包的项目负责人"], "answer": [3], "explanation": "总包的项目负责人负责每周组织各分包，对施工项目及日巡查情况进行全面检查，并督促责任单位落实整改，检查和整改情况及时进行网上填报。"},
  {"id": 113, "type": "single", "question": "《上海市建筑施工安全生产标准化考评规范》规定， （　　） 结合日常现场监理情况，在施工项目总包对分包月度考评、总包企业对施工项目的月度考评等完成后3个工作日内完成复核，并将复核结论及时在网上填报。", "options": ["企业负责人", "施工项目监理", "专职安全员", "项目负责人"], "answer": [1], "explanation": "施工项目监理结合日常现场监理情况,在施工项目总包对分包月度考评、总包企业对施工项目的月度考评等完成3个工作日内完成复核,并将复核结论及时在网上填报。"},
  {"id": 114, "type": "single", "question": "《上海市建筑施工安全生产标准化考评规范》规定，企业于次年 （　　） 前将自评材料报送对应的考评部门。企业未按期提交年度自评材料的，依据《建筑施工安全生产标准化考评暂行办法》，视同企业考评不合格。", "options": ["12月31日", "1月1日", "12月1日", "1月31日"], "answer": [3], "explanation": "企业于次年1月31日前将自评材料报送对应的考评部门。企业未按期提交年度自评材料的，依据《建筑施工安全生产标准化考评暂行办法》，视同企业考评不合格。"},
  {"id": 115, "type": "single", "question": "根据“关于贯彻落实《上海市建筑施工安全生产标准化考评规范》（2016版）若干事项的通知（沪建安质监(2017)57号）”文件精神，安全生产标准化中的“管理的标准化”不包括 （　　） 。", "options": ["建筑行业安全管理", "企业安全管理", "施工现场安全管理", "机械安全管理"], "answer": [3], "explanation": "安全生产标准化工作应当围绕以建筑行业、企业、施工现场、班组各层面安全管理为主的“管理的标准化”、以建筑施工现场人员安全行为为主的“人的标准化”、以建筑施工现场实物状态安全为主的“物的标准化”等三个方面的内容全面开展。"},
  {"id": 116, "type": "single", "question": "根据《危险性较大的分部分项工程安全管理规定》（住建部令第37号），下列不属于危险性较大的分部分项工程的范围的有 （　　） 。", "options": ["开挖深度为3m的基坑支护工程", "滑模工程", "悬挑式脚手架工程", "搭设跨度为8m的砼模板支撑工程"], "answer": [3], "explanation": "混凝土模板支撑工程：搭设高度5m及以上，或搭设跨度10m及以上，或施工总荷载（荷载效应基本组合的设计值，以下简称设计值）10kN/m2及以上，或集中线荷载（设计值）15kN/m及以上，或高度大于支撑水平投影宽度且相对独立无联系构件的混凝土模板支撑工程。"},
  {"id": 117, "type": "single", "question": "根据《危险性较大的分部分项工程安全管理规定》（住建部令第37号），施工总荷载 （　　） kN/㎡及以上，或集中线荷载 （　　） kN/m及以上的混凝土模板支撑工程，属于危险性较大的分部分项工程。", "options": ["8，12", "8，15", "10，12", "10，15"], "answer": [3], "explanation": "施工总荷载（荷载效应基本组合的设计值，以下简称设计值）10kN/m2及以上，或集中线荷载（设计值）15kN/m及以上，或高度大于支撑水平投影宽度且相对独立无联系构件的混凝土模板支撑工程。"},
  {"id": 118, "type": "single", "question": "施工高度 （　　） m及以上的建筑幕墙工程的专项施工方案应组织专家论证。", "options": ["24", "36", "50", "60"], "answer": [2], "explanation": "施工高度50m及以上的建筑幕墙安装工程施工方案需要进行专家论证。"},
  {"id": 119, "type": "single", "question": "危大工程专项施工方案主要内容中的施工计划包括施工进度计划和 （　　） 计划。", "options": ["材料与设备", "作业人员分配", "工艺流程", "应急处置"], "answer": [0], "explanation": "施工计划：包括施工进度计划、材料与设备计划；"},
  {"id": 120, "type": "single", "question": "对于超过一定规模的危险性较大的分部分项工程专项施工方案，下列不属于专家论证的主要内容的有 （　　） 。", "options": ["专项施工方案内容是否完整、可行", "专项施工方案计算书和验算依据是否符合有关标准规范", "专项施工方案施工图是否符合有关标准规范", "专项施工方案施工单位技术负责人、总监理工程师是否审核签字"], "answer": [3], "explanation": "专家论证核心是方案技术内容（A、B、C选项），而 签字审核（D选项）属于程序性要求，非论证重点。"},
  {"id": 121, "type": "single", "question": "对于超过一定规模的危险性较大的分部分项工程，专项施工方案 （　　） 的，施工单位修改后应当重新组织专家论证。", "options": ["暂缓", "通过", "修改后通过", "论证不通过"], "answer": [3], "explanation": "若方案 论证不通过（D选项），需修改后重新论证。"},
  {"id": 122, "type": "single", "question": "危险性较大的分部分项工程专项施工方案实施前，编制人员或者项目技术负责人应当向施工现场管理人员进行 （　　） 。", "options": ["方案交底", "安全技术交底", "设计交底", "质监交底"], "answer": [0], "explanation": "专项施工方案实施前，编制人员或者项目技术负责人应当向施工现场管理人员进行书面的方案交底，并由双方共同签字确认。"},
  {"id": 123, "type": "single", "question": "对未按照专项施工方案施工的，项目专职安全生产管理人应当要求立即整改，并及时报告 （　　） ，其应当及时组织限期整改。", "options": ["项目技术负责人", "企业负责人", "项目负责人", "总监理工程师"], "answer": [2], "explanation": "对未按照专项施工方案施工的,应当要求立即整改，并及时报告项目负责人，项目负责人应当及时组织限期整改。"},
  {"id": 124, "type": "single", "question": "根据《危险性较大的分部分项工程安全管理规定》（住建部令第37号），危大工程发生险情或者事故时，施工单位应当立即采取应急处置措施，并报告 （　　） 。", "options": ["设计单位", "勘察单位", "建设单位", "工程所在地住房城乡建设主管部门"], "answer": [3], "explanation": "危大工程发生险情或者事故时，施工单位应当立即采取应急处置措施，并报告工程所在地区住房城乡建设主管部门。"},
  {"id": 125, "type": "single", "question": "危大工程应急抢险结束后， （　　） 应当组织各单位制定工程恢复方案，并对应急抢险工作进行后评估。", "options": ["建设单位", "设计单位", "施工单位", "监理单位"], "answer": [0], "explanation": "建设单位（A选项）负责组织抢险后评估及恢复方案制定。"},
  {"id": 126, "type": "single", "question": "施工单位应当按照《危险性较大的分部分项工程安全管理规定》对危险性较大的分部分项工程进行施工监测，发现有危及人身安全的紧急情况，下列作业人员应对方法，正确的是 （　　） 。", "options": ["撤离危险区域", "组织抢险", "撤离施工现场", "全员撤离"], "answer": [0], "explanation": "施工单位应当按照规定对危大工程进行施工监测和安全巡视，发现危及人身安全的紧急情况，应当立即组织作业人员撤离危险区域。"},
  {"id": 127, "type": "single", "question": "根据《上海市建筑玻璃幕墙管理办法》，施工单位应当按照国家和本市相关技术标准以及经审查合格的 （　　） 进行玻璃幕墙的施工。", "options": ["施工组织设计文件", "施工图设计文件", "专项施工方案", "合同约定"], "answer": [1], "explanation": "根据《上海市建筑玻璃幕墙管理办法》，施工单位应当按照国家和本市相关技术标准以及经审查合格的施工图设计文件进行玻璃幕墙的施工。"},
  {"id": 128, "type": "single", "question": "根据《装配整体式混凝土结构工程施工安全管理规定》，预制构件安装起吊前，施工、监理单位应对吊装的安全生产措施、条件等进行全面检查，在取得 （　　） 后，方可实施安装。", "options": ["吊装令", "指挥令", "开工令", "动火令"], "answer": [0], "explanation": "（三）吊装令制度。预制构件安装起吊前，施工、监理单位应对吊装的安全生产措施、条件等进行全面检查，在取得《吊装令》后，方可实施安装。"},
  {"id": 129, "type": "single", "question": "根据《关于进一步加强密闭空间施工作业安全管理的紧急通知》，施工单位应对从事密闭空间施工作业的相关人员进行交底培训，下列培训内容不正确的有 （　　） 。", "options": ["有毒有害因素", "安全防范措施", "安全操作规程", "有毒气体浓度监测"], "answer": [3], "explanation": "施工单位应对从事密闭空间施工作业的相关人员进行交底培训，内容应包括密闭空间有毒有害因素、安全防范措施、安全操作规程、紧急处置措施等，并有专门签字、记录、归档。"},
  {"id": 130, "type": "single", "question": "根据《上海市基坑工程管理办法》，施工总承包单位应当对基坑工程的施工质量和安全负总责，分包单位应当接受 （　　） 施工现场的质量和安全管理，按照分包合同的约定对其负责。", "options": ["建设单位", "设计单位", "监理单位", "总承包单位"], "answer": [3], "explanation": "第十七条 施工总承包单位应当对基坑工程的施工质量和安全负总责，分包单位应当接受总承包单位施工现场的质量和安全管理，按照分包合同的约定对总承包单位负责。"},
  {"id": 131, "type": "single", "question": "基坑工程由施工总承包单位实施的，基坑工程施工方案应由该总承包单位编制， （　　） 审核、签字并加盖单位公章。", "options": ["施工单位技术负责人", "总承包单位技术负责人", "分包单位技术负责人", "总监理工程师"], "answer": [0], "explanation": "《上海市基坑工程管理办法》\n第十八条 第二款\n基坑工程由施工总承包单位实施的，基坑工程施工方案应由该总承包单位编制，施工单位技术负责人审核、签字并加盖单位公章；实行分包的，可由专业分包单位编制，但应由总承包单位技术负责人和分包单位技术负责人同时审核、签字，并加盖总包、分包单位公章。"},
  {"id": 132, "type": "single", "question": "根据《上海市基坑工程管理办法》，环境保护等级为一、二级，且开挖深度8m（含8m）以上的基坑工程，以及地质条件比较复杂的其他深基坑工程，其内支撑应不少于 （　　） 道。", "options": ["一", "二", "三", "四"], "answer": [1], "explanation": "环境保护等级为一、二级，且开挖深度8m（含8m）以上的基坑工程，以及地质条件比较复杂的其他深基坑工程，其内支撑应不少于两道。"},
  {"id": 133, "type": "single", "question": "根据《上海市危险性较大的分部分项工程专家论证管理办法》，根据工程规模、特点和风险程度，施工总承包企业不可将危险性较大的分部分项工程自行委托论证机构开展论证活动的是 （　　） 。", "options": ["采用常规、成熟工艺", "对周边环境影响重大", "私营企业自有资金投资", "施工单位为国有企业"], "answer": [1], "explanation": "以下类型的建设工程，施工企业应在市建设管理委科技委办公室指导下开展论证活动：\n（一）政府投资项目以及市重大工程项目中的超过一定规模的危险性较大的分部分项工程；（二）采用新技术、新工艺、新材料、新设备等尚无相关技术标准的危险性较大的分部分项工程；（三）风险特别大或对周边环境影响特别重大的危险性较大的分部分项工程；"},
  {"id": 134, "type": "single", "question": "根据《上海市危险性较大的分部分项工程专家论证管理办法》，危险性较大的分部分项工程专项施工方案论证报告应在论证后的 （　　） 个工作日内反馈给施工企业。", "options": ["5", "7", "10", "15"], "answer": [0], "explanation": "第十八条(论证报告要求)论证报告应符合下列要求:\n（一）论证报告结论应明确为“可行”或“不可行”；\n（二）论证报告意见应分为整改类和建议类。整改类意见必须执行。当结论明确为可行的，整改类意见修改完成，经企业审批后，必须反馈论证机构或论证组组长备案；\n（三）论证报告中对方案提出的意见应明确理由以及修改要求；\n（四）论证报告填写应规范，不得任意涂改；\n（五）论证报告应由所有参与论证的专家签名，每个论证专家的论证意见应附后；由论证机构组织的，论证机构还应加盖论证机构公章。\n（六）论证报告应在论证后的 5 个工作日内反馈给施工企业。"},
  {"id": 135, "type": "single", "question": "根据《上海市危险性较大的分部分项工程专家论证管理办法》，危险性较大的分部分项工程专项施工方案论证工作完成后，相关资料应形成专项方案论证档案，留存备查。下列不属于应归档资料的有 （　　） 。", "options": ["项目的方案文本", "论证会议签到", "论证专家意见和建议", "监督机构报告"], "answer": [3], "explanation": "第二十一条(专项方案论证档案)论证工作完成后，相关资料应形成专项方案论证档案，留存备查。档案至少应包括:项目的方案文本、论证会议签到、论证专家意见和建议、论证报告等资料。\n方案由机构论证的，论证档案由论证机构和施工企业、监理单位分别留存；方案由施工企业自行组织论证的，论证档案由施工企业和监理单位留存备查。"},
  {"id": 136, "type": "single", "question": "根据《上海市建设工程危险性较大的分部分项工程安全管理实施细则》，施工条件验收应由施工单位项目负责人组织企业相关职能部门责任人及分包单位等实施，其中不包括 （　　） 。", "options": ["技术", "施工", "安全", "商务"], "answer": [3], "explanation": "施工条件验收应由施工单位项目负责人依据企业相关规章制度和专项施工方案要求，组织企业技术、施工、安全等职 能部门责任人及分包单位等实施，总监理工程师及相关监理工程师审核。"},
  {"id": 137, "type": "single", "question": "根据《上海市建设工程危险性较大的分部分项工程安全管理实施细则》，安全生产设施设备类危大工程，以及专项施工方案中要求验收的工程，应由 （　　） 组织相关岗位及分包单位进行验收。", "options": ["方案编制人员", "施工单位项目负责人", "总监理工程师", "项目专职安全生产管理人员"], "answer": [0], "explanation": "第二十一条（危大工程验收）模板工程及支撑体系、脚手架工程、起重机械安装拆卸工程等安全生产设施设备类危大工程，以及专项施工方案中要求验收的工程，应由方案编制人员组织相关岗位及分包单位进行验收，经施工单位项目技术负责人及总监理工程师签字确认后，方可进入下一道工序。"},
  {"id": 138, "type": "single", "question": "下列起重机械中，属于特种设备的是 （　　） 。", "options": ["额定起重量0.5t的升降机", "额定起重量2t的起重机", "起重力矩30t ·m的塔式起重机", "生产率200t/h的装卸桥"], "answer": [0], "explanation": "起重机械，是指用于垂直升降或者垂直升降并水平移动重物的机电设备，其范围规定为额定起重量大于或者等于0.5t的升降机；额定起重量大于或者等于3t（或额定起重力矩大于或者等于40t·m的塔式起重机，或生产率大于或者等于300t/h的装卸桥），且提升高度大于或者等于2m的起重机；层数大于或者等于2层的机械式停车设备。"},
  {"id": 139, "type": "single", "question": "使用范围最广、数量最多的起重机械是 （　　） 。", "options": ["施工升降机", "桥式起重机", "流动式起重机", "升降作业平台"], "answer": [1], "explanation": "桥式起重机是横架于车间、仓库和料场上空进行物料吊运的起重设备。由于它的两端坐落在高大的水泥柱或者金属支架上，形状似桥。桥式起重机的桥架沿铺设在两侧高架上的轨道纵向运行，可以充分利用桥架下面的空间吊运物料，不受地面设备的阻碍。它是使用范围最广、数量最多的一种起重机械。"},
  {"id": 140, "type": "single", "question": "下列属于消除危险的工作环境的措施有 （　　） 。", "options": ["请法定检测部门对机械设备进行检测", "检查入场机械设备的出厂合格证", "及时检查塔式起重机的力矩限位", "为搅拌机、物料提升机搭设遮雨棚"], "answer": [3], "explanation": "搭设遮雨棚（D选项）直接改善作业环境，消除天气带来的安全隐患。其他选项属于设备检查或维护。"},
  {"id": 141, "type": "single", "question": "根据《特种设备安全法》的规定，特种设备检验机构接到定期检验要求后，应当按照安全技术规范的要求及时进行 （　　） 检验。", "options": ["使用工况", "安全装置", "运行性能", "安全性能"], "answer": [3], "explanation": "特种设备检验机构接到定期检验要求后，应当按照安全技术规范的要求及时进行安全性能检验。特种设备使用单位应当将定期检验标志置于该特种设备的显著位置。"},
  {"id": 142, "type": "single", "question": "特种设备运行不正常时，特种设备作业人员应当 （　　） 保证安全。", "options": ["按照操作规程采取有效措施", "马上撤离现场", "第一时间报警", "大声呼救通知周边人员"], "answer": [0], "explanation": "特种设备运行不正常时，特种设备作业人员应当按照操作规程采取有效措施保证安全。特种设备出现故障或者发生异常情况，特种设备使用单位应当对其进行全面检查，消除事故隐患，方可继续使用。"},
  {"id": 143, "type": "single", "question": "根据《建筑起重机械安全监督管理规定》，建筑起重机械使用单位和 （　　） 应当在签订的建筑起重机械安装、拆卸合同中明确双方的安全生产责任。", "options": ["总包单位", "分包单位", "安装单位", "出租单位"], "answer": [2], "explanation": "使用单位需与 安装单位（C选项）明确安全责任，确保拆装过程安全。"},
  {"id": 144, "type": "single", "question": "根据《建筑起重机械安全监督管理规定》，使用单位应当自建筑起重机械安装验收合格之日起 （　　） 日内，将建筑起重机械安装验收资料、建筑起重机械安全管理制度、特种作业人员名单等，向工程所在地县级以上地方人民政府建设主管部门办理建筑起重机械使用登记。", "options": ["7", "10", "15", "30"], "answer": [3], "explanation": "建筑起重机械使用单位应当自建筑起重机械安装验收合格之日起30日内，持相关资料向工程所在地县级以上地方人民政府建设主管部门办理建筑起重机械使用登记。"},
  {"id": 145, "type": "single", "question": "根据《建筑起重机械安全监督管理规定》，施工总承包单位应当履行的安全职责不正确的是 （　　） 。", "options": ["向安装单位提供拟安装设备位置的基础施工资料", "审核安装单位、使用单位的资质证书", "审核使用单位制定的生产安全事故应急救援预案", "审核安装单位制定的防止塔吊相互碰撞的方案"], "answer": [3], "explanation": "总包单位审核 安装单位方案（如防碰撞方案），但 应急救援预案 由使用单位制定，非总包审核职责（C选项错误）。"},
  {"id": 146, "type": "single", "question": "根据《建筑起重机械备案登记办法》的规定，设备备案机关应当自收到产权单位提交的备案资料之日起 （　　） 个工作日内，对符合备案条件且资料齐全的建筑起重机械进行编号，向产权单位核发建筑起重机械备案证明。", "options": ["5", "7", "9", "10"], "answer": [1], "explanation": "第七条 设备备案机关应当自收到产权单位提交的备案资料之日起7个工作日内，对符合备案条件且资料齐全的建筑起重机械进行编号，向产权单位核发建筑起重机械备案证明。"},
  {"id": 147, "type": "single", "question": "根据《建筑起重机械备案登记办法》的规定，从事建筑起重机械安装、拆卸活动的单位办理建筑起重机械安装（拆卸）告知手续前，应与 （　　） 签订安全协议书。", "options": ["使用单位", "建设单位", "施工总承包单位", "监理单位"], "answer": [2], "explanation": "安装/拆卸单位需与 施工总承包单位（C选项）签订安全协议，明确双方安全责任，确保作业过程受控。"},
  {"id": 148, "type": "single", "question": "根据《建筑施工特种作业人员管理规定》，用人单位应当履行的职责不包括 （　　） 。", "options": ["与持有效资格证书的特种作业人员订立劳动合同", "向特种作业人员提供齐全、合格的安全防护用品", "按规定组织特种作业人员参加年度安全教育培训", "按规定组织特种作业人员参加继续教育，培训时间不少于32小时"], "answer": [3], "explanation": "继续教育培训时间应 不少于24小时（非32小时），因此D选项错误。其他选项均为用人单位法定职责。"},
  {"id": 149, "type": "single", "question": "根据《建筑施工特种作业人员管理规定》，建筑施工特种作业资格证书有效期为 （　　） 年。有效期满需要延期的，建筑施工特种作业人员应当于期满前3个月内向原考核发证机关申请办理延期复核手续。", "options": ["一", "二", "三", "四"], "answer": [1], "explanation": "特种作业资格证书有效期为 3年（C选项），需提前3个月申请延期。"},
  {"id": 150, "type": "single", "question": "根据《建筑施工特种作业人员管理规定》，建筑施工特种作业人员按规定向原考核发证机关申请办理延期复核合格的，资格证书有效期延期 （　　） 年。", "options": ["1", "2", "3", "5"], "answer": [1], "explanation": "第二十二条 资格证书有效期为两年。有效期满需要延期的，建筑施工特种作业人员应当于期满前3个月内向原考核发证机关申请办理延期复核手续。延期复核合格的，资格证书有效期延期2年。"},
  {"id": 151, "type": "single", "question": "根据《关于进一步加强建设工程起重机械监督管理的通知》的规定， （　　） 应配备专职机械管理人员实施专业管理，负责委托机械检测单位，对施工作业人员相关证书进行查核。", "options": ["建设单位", "使用单位", "总承包单位", "监理单位"], "answer": [2], "explanation": "总承包单位应配备专职机械管理人员实施专业管理,负责委托机械检测单位,对施工作业人员相关证书进行查核。"},
  {"id": 152, "type": "single", "question": "根据《关于进一步加强建设工程起重机械监督管理的通知》的规定，起重机械无设计使用年限规定的，使用满 （　　） 年的，每年开展一次，满 （　　） 年的，每半年开展一次检测评估，合格后方可继续使用。", "options": ["5，10", "10，15", "15，20", "15，30"], "answer": [1], "explanation": "无设计使用年限规定的，使用满10年的，每年度开展一次，满15年的，每半年开展一次检测评估，合格后方可继续使用。检测评估须由法定单位实施。"},
  {"id": 153, "type": "single", "question": "根据《关于进一步加强本市建筑起重机械监督管理的通知》的规定，建筑起重机械设备在进入施工现场安装前，以及准备拆卸前，应当由 （　　） 到工程监督部门办理安装、拆卸告知。", "options": ["出租单位", "分包单位", "使用单位", "施工总包单位"], "answer": [3], "explanation": "建筑起重机械设备在进入施工现场安装前，以及准备拆卸前，应当由施工总包单位到工程监督部门办理安装、拆卸告知。"},
  {"id": 154, "type": "single", "question": "根据《关于进一步加强本市建筑起重机械监督管理的通知》的规定，施工总包单位组织对使用情况、条件、人员及检测整改项目等进行使用验收合格后，应向 （　　） 申请办理使用登记。", "options": ["建设单位", "市建设机械检测机构", "监理单位", "市建设市场监管机构"], "answer": [1], "explanation": "施工总包单位在收到市建设机械检测机构发放的检测报告后，及时组织安装、使用、监理、产权等单位，对使用工况、条件、人员及检测整改项目等进行使用验收;合格后，向市建设机械检测机构申请办理使用登记。"},
  {"id": 155, "type": "single", "question": "根据《关于上海市建筑施工特种作业人员考核和持证上岗管理工作的实施意见》的规定，经核准取得《建筑施工特种作业人员操作资格证书》和备案的特种作业人员，每年必须参加不少于 （　　） 小时的继续教育培训。", "options": ["24", "36", "48", "72"], "answer": [0], "explanation": "五、依据《通知》规定，经核准取得《建筑施工特种作业人员操作资格证书》和备案的特种作业人员，应当认真按照下列要求执行。\n（一）首次取得操作资格证书的特种作业人员，须经过3个月的实习操作后，方可正式独立上岗。\n（二）每年必须参加不少于24小时的继续教育培训。\n（三）有下列情况之一的，必须通过定点强化培训经考试后方可上岗：\n1、连续一年内有2次违章记录的；\n2、因违章操作，导致发生财产损失事故的；\n3、因违章操作，导致发生人员伤亡事故的；"},
  {"id": 156, "type": "single", "question": "根据《关于加强塔式起重机钢结构组合式基础平台安全管理要求的通知》的规定，下列不属于加强灌注桩定位管理的参数有 （　　） 。", "options": ["成孔的中心位置", "孔深、孔径", "垂直度", "充盈系数"], "answer": [3], "explanation": "应加强塔吊基础的桩基施工、格构柱安装的定位管理。按照《塔式起重机混凝土基础工程技术规程》（JGJ/T187）桩基检查验收的要求，控制灌注桩成孔的中心位置、孔深、孔径、垂直度等误差。"},
  {"id": 157, "type": "single", "question": "根据《关于加强塔式起重机钢结构组合式基础平台安全管理要求的通知》的规定， （　　） 应对施工现场塔机钢结构组合式基础平台的设计、制作以及使用加强管理，明确职责，完善相应的管理流程。", "options": ["建设单位", "安质监站", "塔机出租单位", "施工总承包企业"], "answer": [3], "explanation": "总承包施工企业应对施工现场塔机钢结构组合式基础平台的设计、制作以及使用加强管理，明确职责，完善相应的管理流程。施工现场应严格按照图纸、方案、流程组织施工。"},
  {"id": 158, "type": "single", "question": "根据《关于加强塔式起重机钢结构组合式基础平台安全管理要求的通知》的规定，现场机械、施工管理人员，应每月至少 （　　） 次对连接焊缝、连接螺栓预紧情况进行检查且留有记录。", "options": ["1", "2", "3", "5"], "answer": [0], "explanation": "强化钢结构组合式基础平台使用中的日常检查。现场机械、施工管理人员，应每月不少于一次对连接焊缝、连接螺栓预紧情况进行检查且留有记录。使用中一旦出现影响安全使用的问题，应立即停止使用，整改加固。"},
  {"id": 159, "type": "single", "question": "根据《上海市建筑施工机械安全监督管理规定》中关于岗位职责的规定， （　　） 应主要负责现场施工机械安装、加节顶升、升降移位、拆卸及使用过程中的安全防护、文明施工等监督管理。", "options": ["项目技术负责人", "安全员", "项目经理", "总监理工程师"], "answer": [1], "explanation": "第十一条（岗位职责）\n建筑施工机械相关岗位人员应履行下列安全管理职责：\n（一）项目经理应有效落实现场施工机械管理的岗位职 责；\n（二）安全员应主要负责现场施工机械安装、加节顶升、 升降移位、拆卸及使用过程中的安全防护、文明施工等监督管理；\n（三）机械员应主要负责现场施工机械设备及其安装、加 节顶升、升降移位、拆卸、检验检测、维护、保养等作业的管理；\n（四）起重机械司机应做好每日的例行保养工作，作业前 应进行试运行。"},
  {"id": 160, "type": "single", "question": "根据《上海市建筑施工机械安全监督管理规定》，总承包单位、监理单位需对起重机械的 （　　） 信息实施核查。", "options": ["产权登记", "产品铭牌", "外观", "使用说明书"], "answer": [0], "explanation": "建筑施工机械进场前，总承包单位、监理单位应对下列资 料进行核查：\n（一）产品购销合同、合格证、使用说明书，定期维护保 养记录、维修和技术改造记录等；\n（二）安装、拆卸单位的资质证书、安全生产许可证，项 目经理、安全管理人员、特种作业人员证书。\n起重机械需对产权登记信息实施核查。"},
  {"id": 161, "type": "single", "question": "根据《上海市建筑施工机械安全监督管理规定》， （　　） 应当组织安装单位对建筑施工机械安装、拆卸作业条件进行检查验收。", "options": ["安装单位", "施工总包单位", "监理单位", "分包单位"], "answer": [1], "explanation": "第二十一条(作业验收)\n总承包单位应当组织安装单位对建筑施工机械安装、拆卸 作业条件进行检查验收，监理单位对作业验收实行监督管理。 作业条件主要包括以下内容：\n（一）专项施工方案已完成编制、审批、论证；\n（二）基础已通过验收，作业场所已隔离、防护、警戒；\n（三）相关管理、作业人员已到岗；\n（四）安装单位已按照安全技术标准及安装使用说明书等 要求，检查施工机械、安装辅助机械。"},
  {"id": 162, "type": "single", "question": "根据《上海市建筑施工机械安全监督管理规定》，下列选项中不属于起重机械产权登记内容的是 （　　） 。", "options": ["产权单位法人营业执照", "产权单位基本信息", "产权单位的经营情况", "登记设备的基本信息"], "answer": [2], "explanation": "产权登记内容应主要包括：产权单位基本信息，产权单位法人营业执照，登记设备的基本信息。"},
  {"id": 163, "type": "single", "question": "根据《上海市建筑施工机械安全监督管理规定》， （　　） 应当按照安全技术标准及安装使用说明书的有关要求，对所安装的建筑施工机械进行包括调试和试运转等的安装自检，并向总承包单位出具安装自检合格证明。", "options": ["安装单位", "总承包单位", "施工单位", "监理单位"], "answer": [0], "explanation": "安装单位应当按照安全技术标准及安装使用说明书的有关要求,对所安装的建筑施工机械进行包括调试和试运转等的安装自检,并向总承包单位出具安装自检合格证明。"},
  {"id": 164, "type": "single", "question": "根据《上海市建筑施工机械安全监督管理规定》，总承包单位应当每月不少于 （　　） 次组织对建筑机械的日常检查，台风前后、工程停工复工前还需组织专项检查。", "options": ["一", "二", "三", "四"], "answer": [0], "explanation": "总承包单位应当每月不少于一次组织对建筑施工机械的日常检查,台风前后、工程停工复工前还需组织专项检查。"},
  {"id": 165, "type": "single", "question": "根据国务院机构改革方案和新修正的《消防法》规定，建设工程的消防设计审查、竣工后的消防竣工验收以及相应的行政处罚职责，由 （　　） 承担。", "options": ["消防救援机构", "住建部门", "应急管理部门", "公安部门"], "answer": [1], "explanation": "根据国务院机构改革方案和新修正的《消防法》的规定，将建设工程的消防设计审查、建设工程竣工后的消防验收以及相应的行政处罚职责由原来的消防救援机构承担调整为住建部门承担。"},
  {"id": 166, "type": "single", "question": "下列属于动火作业施工企业必须履行的职责是 （　　） 。", "options": ["审查施工作业的安全防范措施", "动火点风险评估与动火条件的复核", "实施动火作业前安全交底", "组织停用消防设施的现场评估和书面审批"], "answer": [2], "explanation": "动火作业施工企业必须履行下列职责：建立企业内部动火审批制度，编制动火作业施工方案；对动火人员特殊工种开展教育培训，并确保持证上岗；开展动火证中涉及动火点风险评估、动火点安全条件检查；实施动火作业前安全交底工作；动火过程监护及突发事故处置；配合开展因动火作业不当发生安全事故后的调查处理。"},
  {"id": 167, "type": "single", "question": "在地下空间、敷设电缆的电缆夹层、电缆沟和其他有电缆的地方，动火作业结束进行检查、清理后，监护人员应到现场复查，每次间隔宜 （　　） 分钟以上。", "options": ["10", "15", "20", "30"], "answer": [3], "explanation": "在地下空间、敷设电缆的电缆夹层、电缆沟和其他有电缆的地方，动火作业结束进行检查、 清理后，监护人员应到现场再复查不少于2 次，每次间隔宜30分钟以上，防止防残留火星持续阴燃致灾。"},
  {"id": 168, "type": "single", "question": "有爆炸和火灾危险的场所，按 （　　） 选用相应的电气设备。", "options": ["易爆品的性质", "易爆品的种类", "危险场所等级", "易燃物的种类"], "answer": [2], "explanation": "有爆炸和火灾危险的场所,按危险场所等级选用相应的电气设备。"},
  {"id": 169, "type": "single", "question": "下列不属于违章使用电气设备行为的是 （　　） 。", "options": ["电气设备超负荷运行", "电气设备带故障使用", "自行改装供用电设施", "自行检查线路运行情况"], "answer": [3], "explanation": "下列不属于违章使用电气设备行为的是：\nD. 自行检查线路运行情况\n选项A、B和C都是违章使用电气设备的行为，而自行检查线路运行情况是一种安全检查行为，不属于违章使用电气设备的行为。"},
  {"id": 170, "type": "single", "question": "关于乙炔等气瓶搬运、存放、使用，下列方法错误的是 （　　） 。", "options": ["保持直立状态防止倾倒", "避免高温", "严禁碰撞、敲打、抛掷、滚动", "与火源距离不小于5m"], "answer": [3], "explanation": "气瓶运输、存放、使用时，应符合下列规定：1) 气瓶应保持直立状态，并采取防倾倒措施，乙炔瓶严禁横躺卧放。2) 严禁碰撞、敲打、抛掷、滚动气瓶。3) 气瓶应远离火源，与火源的距离不应小于10m，并应采取避免高温和防止曝晒的措施。4) 燃气储装瓶罐应设置防静电装置。"},
  {"id": 171, "type": "single", "question": "临时宿舍、办公用房不应与厨房操作间、锅炉房、变配电房等组合建造。厨房排油烟机及油烟管道应清洗油垢 （　　） 不少于一次。", "options": ["每周", "每月", "每季度", "每两周"], "answer": [2], "explanation": "厨房排烟机、管道每季度清洗一次。"},
  {"id": 172, "type": "single", "question": "根据《机关、团体、企业、事业单位消防安全管理规定》，明确建筑工程施工现场的消防安全由 （　　） 负责。", "options": ["建设单位", "设计单位", "施工单位", "监理单位"], "answer": [2], "explanation": "根据《机关、团体、企业、事业单位消防安全管理规定》，明确建筑工程施工现场的消防安全由施工单位负责。实行施工总承包的，由总承包单位负责。"},
  {"id": 173, "type": "single", "question": "不符合施工现场火应要求的是 （　　） 。", "options": ["动火作业应办理动火许可证", "动火操作人员应具有相应资格", "施工现场不应采用明火取暖", "动火作业后，动火操作人员即可离开"], "answer": [3], "explanation": "动火作业结束后,操作人员必须对周围现场进行安全确认,清理现场,在确认无任何火源隐患的情况下,方可离开现场。"},
  {"id": 174, "type": "single", "question": "有爆炸和火灾危险的场所，按 （　　） 选用相应的电气设备。", "options": ["易燃易爆物品种类", "危险品数量", "存在风险的面积", "危险场所等级"], "answer": [3], "explanation": "有爆炸和火灾危险的场所，应按危险场所等级选用相应的电气设备。"},
  {"id": 175, "type": "single", "question": "气瓶应分类储存，库房内通风良好；空瓶和实瓶同库存放时，应分开放置，两者间距不应小于 （　　） m。", "options": ["1", "1.5", "2", "3"], "answer": [1], "explanation": "气瓶应分类储存,库房内通风良好;空瓶和实瓶同库存放时,应分开放置,两者间距不应小于1.5m。"},
  {"id": 176, "type": "single", "question": "施工过程中，施工现场的 （　　） 应定期组织消防安全管理人员对施工现场的消防安全进行检查。", "options": ["施工单位项目负责人", "施工项目技术负责人", "项目专职安全管理人员", "消防安全负责人"], "answer": [3], "explanation": "消防安全负责人（D选项）负责组织定期消防检查，落实防火措施。"},
  {"id": 177, "type": "single", "question": "根据“四不放过”的原则，在火灾事故发生后，施工单位和 （　　） 应共同做好现场保护和会同消防部门进行现场勘察的工作。对火灾事故的处理提出建议，并积极落实防范措施。", "options": ["建设单位", "监理单位", "救援单位", "安质监站"], "answer": [0], "explanation": "根据“四不放过”的原则，在火灾事故发生后，施工单位和建设单位应共同做好现场保护和会同消防部门进行现场勘察的工作。对火灾事故的处理提出建议，并积极落实防范措施。"},
  {"id": 178, "type": "single", "question": " （　　） 应做好施工现场临时消防设施的日常维护工作，对已失效、损坏或丢失的消防设施，应及时更换、修复或补充。", "options": ["消防机构", "监督机构", "建设单位", "施工单位"], "answer": [3], "explanation": "施工单位应做好施工现场临时消防设施的日常维护工作, 对已失效、损坏或丢失的消防设施应及时更换、修复或补充。"},
  {"id": 179, "type": "single", "question": "根据《消防法》规定，消防救援机构统一组织和指挥火灾现场扑救，应当 （　　） 。", "options": ["第一时间掌握现场情况", "抢先疏散人员", "有限撤离机械设备", "优先保障遇险人员的生命安全"], "answer": [3], "explanation": "消防救援机构统一组织和指挥火灾现场扑救,应当优先保障遇险人员的生命安全。"},
  {"id": 180, "type": "single", "question": "根据《上海市消防条例》规定，依法确定的消防安全重点单位自行或者委托符合国家规定条件的消防技术服务机构定期开展消防安全评估后，应自评估完成之日起 （　　） 个工作日内将评估报告报所在地消防救援机构备案。", "options": ["三", "五", "七", "十"], "answer": [1], "explanation": "八、将第十六条改为第十七条，增加一项，作为第五项：\n（五）自行或者委托符合国家规定条件的消防技术服务机构定期开展消防安全评估，并自评估完成之日起五个工作日内将评估报告报所在地消防救援机构备案。"},
  {"id": 181, "type": "single", "question": "根据《上海市消防条例》规定，消防安全重点单位应当至少 （　　） 进行消防演练。", "options": ["每月一次", "每季度一次", "每年一次", "每年二次"], "answer": [3], "explanation": "消防安全重点单位应当每年进行至少两次消防演练。"},
  {"id": 182, "type": "single", "question": "根据《关于进一步加强建筑施工消防安全工作的通知》规定，对不执行政府及有关部门下达的安全隐患整改通知，不认真进行隐患整改以及对隐患整改不力造成事故的，要依法从重追究相关责任人员，尤其是（）的责任。", "options": ["项目负责人", "专职安全管理人员", "企业负责人", "项目技术负责人"], "answer": [2], "explanation": "对不执行政府及有关部门下达的安全隐患整改通知,不认真进行隐患整改以及对隐患整改不力造成事故的,要依法从重追究相关责任人员,尤其是企业负责人的责任。"},
  {"id": 183, "type": "single", "question": "根据《上海市建筑工程施工现场消防安全管理规定》，下列做法符合施工现场搭建临时建筑要求的是（）。", "options": ["办公场所耐火等级四级", "临时建筑之间间距8米", "房间门至疏散楼梯30米", "三层宿舍设三个安全出入口"], "answer": [1], "explanation": "【请注意题目要求：选项B符合临时建筑要求，选项A办公场所为一、二、三级。】\n第十五条 施工现场搭建临时建筑须符合下列要求：\n（一）高压架空线下禁止搭建临时建筑和堆放易燃、可燃材料。\n（二）施工现场办公、住宿工棚的耐火等级不应低于三级，禁止搭建木板房。\n（三）临时建筑之间的防火间距不应小于5m。成组布置的临时建筑，每组不应超过10幢，组与组之间的防火间距不应小于10m。\n（四）施工现场临时建筑不宜超过2层，人员住宿的房间建筑面积大于50m2的应设两个安全出入口；住宿房间的窗不应用硬质材料封堵。每个房门至疏散楼梯的距离不超过25m（位于袋形走道两侧或尽端的房间疏散距离减半）。"},
  {"id": 184, "type": "single", "question": "根据《上海市建筑工程施工现场消防安全管理规定》，临时搭建的办公、住宿场所每100平方米配备 （　　） 个灭火级别不小于3A的灭火器。", "options": ["一", "二", "三", "四"], "answer": [1], "explanation": "临时搭建的办公、住宿场所每100平方米配备两具灭火级别不小于3A的灭火器;临时油漆间、易燃易爆危险物品仓库等每30平方米应配置两具灭火级别不小于4B的灭火器。"},
  {"id": 185, "type": "single", "question": "根据《上海市建筑工程施工现场消防安全管理规定》，临时油漆间、易燃易爆危险品仓库等每 （　　） 平方米应配置两个灭火级别不小于4B的灭火器。", "options": ["30", "50", "60", "100"], "answer": [0], "explanation": "临时油漆间、易燃易爆危险物品仓库等每30平方米应配置两具灭火级别不小于4B的灭火器。"},
  {"id": 186, "type": "single", "question": "根据《关于进一步加强本市建设工程施工现场消防安全管理工作的通知》的规定，施工总承包单位要按照 （　　） 的原则，与分包单位逐一签订消防安全责任书，明确消防安全责任，并对分包单位施工现场的消防安全工作进行管理。", "options": ["谁设计，谁负责", "谁施工，谁负责", "谁验收谁负责", "谁监督谁负责"], "answer": [1], "explanation": "施工总承包单位要按照“谁施工，谁负责”的原则，与分包单位逐一签订消防安全责任书，明确消防安全责任，并对分包单位施工现场的消防安全工作进行管理。"},
  {"id": 187, "type": "single", "question": "根据《关于进一步加强本市建设工程施工现场消防安全管理工作的通知》的规定， （　　） 是施工现场消防安全管理的第一责任人，要全面负责施工现场的消防安全工作，并指定专职消防安全管理人员负责工地日常消防安全管理工作。", "options": ["建设单位主要负责人", "总监理工程师", "施工总承包项目经理", "分包单位项目负责人"], "answer": [2], "explanation": "施工总承包项目经理是施工现场消防安全管理的第一责任人，要全面负责施工现场的消防安全工作，并指定专职消防安全管理人员负责工地日常消防安全管理工作。"},
  {"id": 188, "type": "single", "question": "根据《高处作业分级》(GB/T3608-2008)的规定，凡在坠落高度基准面 （　　） 有可能坠落的高处进行的作业，均称为高处作业。", "options": ["1m以上(含1m）", "2m以上（含2m）", "3m以上(含3m)", "5m以上(含5m)"], "answer": [1], "explanation": "凡在坠落高度基准面 2m以上（含 2m）有可能坠落的高处进行作业，都称为高处作业。"},
  {"id": 189, "type": "single", "question": "物料提升机 （　　） 应装设有联锁装置的安全门，同时采用断绳保护装置或安全停靠装置。", "options": ["安全口", "通道口", "上料口", "下楼口"], "answer": [2], "explanation": "物料提升机上料口应装设有联锁装置的安全门,同时采用断绳保护装置或安全停靠装置。"},
  {"id": 190, "type": "single", "question": "移动式操作平台，立杆底部和平台立面应分别设置扫地杆、剪刀撑或斜撑，平台应用坚实木板满铺，并设置 （　　）  和登高扶梯。", "options": ["安全门", "防护栏杆", "安全棚", "安全网"], "answer": [1], "explanation": "【依据】《建筑施工高处作业安全技术规范》JGJ 80-2016\n【解析】正确答案是B。题干对应的是建筑施工高处作业防护。 A项“安全门”错误，它说的是“安全门”，并非题干要找的“防护栏杆”。 B项“防护栏杆”正确，它与题干所述“移动式操作平台，立杆底部和平台立面应分别设置”相对应。 C项“安全棚”错误，它说的是“安全棚”，并非题干要找的“防护栏杆”。 D项“安全网”错误，它说的是“安全网”，并非题干要找的“防护栏杆”。"},
  {"id": 191, "type": "single", "question": "各类作业平台、卸料平台的架体应保持稳固，不得与施工脚手架连接。作业平台上 （　　） 。", "options": ["严禁堆放", "严禁空载", "严禁踩踏", "严禁超载"], "answer": [3], "explanation": "各类作业平台、卸料平台须按相关规定编制施工方案，经验收合格签字后使用。架体应保持稳固，不得与施工脚手架连接。作业平台上严禁超载。"},
  {"id": 192, "type": "single", "question": "脚手架应按相关规定编制施工方案， （　　） 审批签字， （　　） 组织有关部门验收，经验收合格签字后，方可作业。", "options": ["施工单位技术负责人，项目负责人", "施工单位分管负责人，项目分管负责人", "施工单位分管负责人，项目技术负责人", "施工单位技术负责人，项目技术负责人"], "answer": [1], "explanation": "脚手架应按相关规定编制施工方案,施工单位分管负责人审批签字,项目分管负责人组织有关部门验收,经验收合格签字后,方可作业。"},
  {"id": 193, "type": "single", "question": "使用吊篮作业时，作业人员应按规定佩戴安全带，安全带应挂设在 （　　） 。", "options": ["吊篮栏杆上", "吊篮顶部", "单独设置的安全绳上", "吊篮钢丝绳上"], "answer": [2], "explanation": "安全带应挂设在单独设置的安全绳上，严禁安全绳与吊篮连接。"},
  {"id": 194, "type": "single", "question": "施工单位应作好施工区域内临时排水系统规划，在地形、地质条件复杂，可能发生滑坡、坍塌的地段挖方时，应由 （　　） 确定排水方案。", "options": ["设计单位", "监督机构", "第三方评估单位", "施工总承包单位"], "answer": [0], "explanation": "设计单位（A选项）负责根据地质条件制定排水方案，确保技术可行性。"},
  {"id": 195, "type": "single", "question": "开挖低于地下水位的基坑（槽）、边坡和基础桩时，施工单位应合理选用 （　　） 。", "options": ["开挖顺序", "支护形式", "加固方式", "降水措施"], "answer": [3], "explanation": "开挖低于地下水位的基坑(槽)、边坡和基础桩时,施工单位应合理选用降水措施降低地下水位。"},
  {"id": 196, "type": "single", "question": "模板作业支撑立柱基础为泥土地面时，应采取 （　　） ，对地面平整、夯实，并加设满足支撑承载力要求的垫板后，方可用以支撑立柱。", "options": ["固定措施", "加固措施", "排水措施", "强化措施"], "answer": [2], "explanation": "支撑立柱基础面为泥土地面时，应采取排水措施，对地面平整、夯实，并加设满足支撑承载力要求的垫板后，方可用以支撑立柱。"},
  {"id": 197, "type": "single", "question": "脚手架按施工设计方案规定的要求进行搭设，各种脚手架搭设到一定高度时，按 （　　） 要求，由有关部门或人员分步进行检查、验收，合格后方可投入使用。", "options": ["施工图", "安全管理协议", "应急预案", "安全施工计划"], "answer": [3], "explanation": "脚手架应按施工设计方案规定的要求进行搭设。各种脚手架搭设到一定高度时，按安全保证计划规定的要求，由有关部门或人员分步进行检查、验收，合格后方可投入使用。使用中要落实专人负责维护。"},
  {"id": 198, "type": "single", "question": "某大型工程项目由于脚手架坍塌，造成死亡3人，重伤5人的事故。事故发生后有关部门迅速组成调查组，并对相关人员进行处理和教育，结合该背景，下列说法正确的是 （　　） 。", "options": ["该事故按损失程度划分属于一般事故", "该事故按损失程度划分属于较大事故", "按照我国有关规定该事故逐级上报至市级人民政府安全生产监督管理部门", "该事故应由事故发生单位组成调查组进行调查"], "answer": [1], "explanation": "较大事故，是指造成3人以上10人以下死亡，或者10人以上50人以下重伤，或者1000万元以上5000万元以下直接经济损失的事故；较大事故逐级上报至省、自治区、直辖市人民政府安全生产监督管理部门和负有安全生产监督管理职责的有关部门；未造成人员伤亡的一般事故，县级人民政府也可以委托事故发生单位组织事故调查组进行调查。\n“以上”包括本数,所称的“以下”不包括本数。"},
  {"id": 199, "type": "single", "question": "根据《特种设备安全监察条例》规定，特种设备事故造成 （　　） 人以上死亡，或者100人以上重伤（包括急性工业中毒，下同），或者1亿元以上直接经济损失的，属于特别重大事故。", "options": ["25", "30", "35", "40"], "answer": [1], "explanation": "特别重大事故标准为死亡≥30人（B选项），或重伤≥100人，或损失≥1亿元。"},
  {"id": 200, "type": "single", "question": "根据 （　　） 规定，事故报告应当及时、明确，任何单位对事故不得迟报、漏报、谎报或者瞒报。", "options": ["《生产安全事故应急条例》", "《生产安全事故报告和调查处理条例》", "《建设工程安全生产管理条理》", "《特种设备安全监察条例》"], "answer": [1], "explanation": "《生产安全事故报告和调查处理条例》第四条 事故报告应当及时、准确、完整，任何单位和个人对事故不得迟报、漏报、谎报或者瞒报。"},
  {"id": 201, "type": "single", "question": "根据《生产安全事故报告和调查处理条例》规定，自事故发生之日起 （　　） 日内，事故造成的伤亡人数发生变化的，应当及时补报。", "options": ["10", "15", "20", "30"], "answer": [3], "explanation": "伤亡人数变化需在30日内（D选项）补报。"},
  {"id": 202, "type": "single", "question": "根据《生产安全事故报告和调查处理条例》规定，事故发生单位负责人接到事故报告后，应当立即启动事故相应 （　　） ，或者采取有效措施，组织抢救，防止事故扩大，减少人员伤亡和财产损失。", "options": ["救援方案", "处置方案", "应急预案", "抢救方案"], "answer": [2], "explanation": "第十四条 事故发生单位负责人接到事故报告后，应当立即启动事故相应应急预案，或者采取有效措施，组织抢救，防止事故扩大，减少人员伤亡和财产损失。"},
  {"id": 203, "type": "single", "question": "根据《生产安全事故报告和调查处理条例》规定，重大事故、较大事故、一般事故，负责事故调查的人民政府应当自收到事故调查报告之日起 （　　） 日内做出批复。", "options": ["10", "15", "20", "30"], "answer": [1], "explanation": "政府需在15日内（B选项）批复事故调查报告。"},
  {"id": 204, "type": "single", "question": "根据《生产安全事故报告和调查处理条例》，事故发生单位应当认真吸取事故教训，落实 （　　） ，防止事故再次发生。", "options": ["安全管理制度", "技术管理制度", "防范和整改措施", "事故责任追究制度"], "answer": [2], "explanation": "第三十三条 事故发生单位应当认真吸取事故教训，落实防范和整改措施，防止事故再次发生。防范和整改措施的落实情况应当接受工会和职工的监督。\n安全生产监督管理部门和负有安全生产监督管理职责的有关部门应当对事故发生单位落实防范和整改措施的情况进行监督检查。"},
  {"id": 205, "type": "single", "question": "根据《生产安全事故应急条例》规定，生产经营单位应当针对本单位可能发生的生产安全事故的特点和危害，进行风险辨识和评估，制定相应的生产安全事故应急救援预案，并向 （　　） 公布。", "options": ["社会", "上级主管部门", "在岗职工", "本单位从业人员"], "answer": [3], "explanation": "应急预案需向本单位从业人员（D选项）公布，确保全员知晓。"},
  {"id": 206, "type": "single", "question": "根据《生产安全事故应急条例》规定，生产经营单位应当对从业人员进行 （　　） ，保证从业人员具备必要的应急知识，掌握风险防范技能和事故应急措施。", "options": ["应急教育和培训", "应急救援培训", "应急救援教育", "应急救援培训教育"], "answer": [0], "explanation": "第十五条 生产经营单位应当对从业人员进行应急教育和培训，保证从业人员具备必要的应急知识，掌握风险防范技能和事故应急措施。"},
  {"id": 207, "type": "single", "question": "根据《生产安全事故信息报告和处置办法》规定，事故信息报告后出现新情况的，负责事故报告的单位应当按规定及时续报。重大事故、特别重大事故每日至少续报 （　　） 次。", "options": ["1", "2", "3", "4"], "answer": [1], "explanation": "重大及以上事故需每日至少续报2次（B选项）。"},
  {"id": 208, "type": "single", "question": "根据《上海市建设工程生产安全事故管理规定》，生产安全事故发生后，参建单位应做好应急抢险、事故报告、事故调查、 （　　） 等处置工作。", "options": ["事故尤因", "事故损失", "停工整改", "歇业待查"], "answer": [2], "explanation": "在生产安全事故发生后，参建单位应做好应急抢险、事故报告、事故调查、停工整改、复工准备等处置工作;而建设行政管理部门在接到事故报告后，应启动事故应急程序、事故快报、勘查取证、事故调查、立案查处、复工检查、事故归档等处置工作。制度同时还规定了对日常生产安全事故防范与事故处置的监管要求。"},
  {"id": 209, "type": "single", "question": "根据《上海市建设工程生产安全事故管理规定》，生产安全事故发生后 （　　） 个工作日内，由施工总包单位在“上海市建设市场管理信息平台\"填报事故相关信息。", "options": ["3", "5", "7", "10"], "answer": [1], "explanation": "生产安全事故发生后5个工作日内,由施工总包单位在“上海市建设市场管理信息平台”填报事故相关信息"},
  {"id": 210, "type": "single", "question": "根据《上海市建设工程生产安全事故管理规定》，发生较大事故的施工项目，下列关于停工整改的期限，正确的是 （　　） 。", "options": ["不少于7天", "不少于10天", "不少于15天", "不少于30天"], "answer": [2], "explanation": "《上海市建设工程生产安全事故管理规定》指出，“发生一般事故的施工项目，停工整改不得少于7天；发生较大事故的施工项目，停工整改不得少于15天；发生重大事故的施工项目，停工整改不得少于30天。”"},
  {"id": 211, "type": "single", "question": "根据《上海市建设工程生产安全事故管理规定》，发生生产安全事故的项目责任单位、责任人员，建设行政管理部门应当纳入诚信记录，同时约谈责任单位的 （　　） 。", "options": ["主要负责人", "技术负责人", "法定代表人", "法人代表"], "answer": [3], "explanation": "发生重大事故的，吊销注册建造师、总监理工程师和监理工程师执业资格证书，终身不予注册。发生生产安全事故的项目责任单位、责任人员，建设行政管理部门应当纳入诚信记录，同时约谈责任单位的法人代表。"},
  {"id": 212, "type": "single", "question": "根据《上海市建设工程生产安全事故行业调查办法》（试行）中的个人处理规定，发生较大及以上事故的，一律吊销安全生产考核合格证，并对发生事故的 （　　） 和总监进行信用分扣分，列入不良行为记录。", "options": ["项目经理", "法人代表", "企业负责人", "项目技术负责人"], "answer": [0], "explanation": "对发生一般事故的项目经理和安全员， 暂扣安全生产考核合格证1年； 发生较大及以上事故的， 一律吊销安全生产考核合格证，并对发生事故的项目经理和总监进行信用分扣分，列入不良行为记录。"},
  {"id": 213, "type": "single", "question": "《关于加强建设工程施工现场临建房屋安全管理的通知》规定， （　　） 要对建筑施工现场临建房屋的安全管理负总责。", "options": ["施工总承包企业", "分包企业", "项目部", "建设单位"], "answer": [0], "explanation": "《关于加强建设工程施工现场临建房屋安全管理的通知》规定，施工总承包企业要对建筑施工现场临建房屋的安全管理负总责。"},
  {"id": 214, "type": "single", "question": "《关于加强建设工程施工现场临建房屋安全管理的通知》规定，临建房屋的拆除实施“ （　　） 、谁拆除”的原则。", "options": ["谁生产", "谁安装", "谁施工", "谁使用"], "answer": [1], "explanation": "临建房屋的拆除实施“谁安装、谁拆除”的原则。"},
  {"id": 215, "type": "single", "question": "《关于加强建设工程施工现场临建房屋安全管理的通知》规定，临建房屋安装完成后，应由安装单位进行自检，合格后应由总承包单位组织监理单位、 （　　） 、安装单位进行安装质量验收，合格后方可交付使用。", "options": ["设计单位", "分包单位", "建设单位", "使用单位"], "answer": [3], "explanation": "临建房屋安装完成后,应由安装单位进行自检,合格后应由总承包单位组织监理单位、使用单位、安装单位进行安装质量验收,合格后方可交付使用。"},
  {"id": 216, "type": "single", "question": "《关于加强建设工程施工现场临建房屋安全管理的通知》规定，临建房屋周围消火栓处要设有明显标志，配备足够的消防水泵、消防水带、消防水枪，消防供水要保证足够的 （　　） 。", "options": ["水源和水压", "水源和水量", "水速和水压", "水量和气压"], "answer": [0], "explanation": "上海市城乡建设和交通委员会\n关于加强建设工程施工现场临建房屋安全管理的通知\n沪建交〔2011〕795号\n三、临建房屋消防安全管理要求\n（二）临建房屋周围应合理布置消火栓。消火栓处要设有明显标志，配备足够的消防水带、消防水枪，消防供水要保证足够的水源和水压。消火栓周围3米内不准存放物品，地下消火栓的设置必须符合现行技术规范要求。临建房屋必须配备灭火器材，做到布局、选型合理，并经常检查、维护、保养，保证灭火器材灵敏有效。"},
  {"id": 217, "type": "single", "question": "《建筑施工现场钢管扣件安全管理规定》规定，施工单位应对钢管、扣件产品合格证、带编号的质量保证书、年度检验报告以及扣件生产许可证等资料的真实性、有效性进行审核，并将审核书面材料报 （　　） 进行审查。", "options": ["建设单位", "代建单位", "监理单位", "安质监站"], "answer": [2], "explanation": "施工单位应对钢管、扣件产品合格证、带编号的质量保证书（见附件一）、年度检验报告以及扣件生产许可证等资料的真实性、有效性进行审核，并将审核书面材料报监理单位进行审查。验收记录（见附件二）应存档备查。"},
  {"id": 218, "type": "single", "question": "按经营性质不同，保险可分为政策性保险和 （　　） 。", "options": ["自愿保险", "原保险", "商业性保险", "强制保险"], "answer": [2], "explanation": "按经营性质,保险可分为政策性保险和商业性保险。"},
  {"id": 219, "type": "single", "question": "按 （　　） ，保险可分为过失责任保险和无过失责任保险。", "options": ["经营性质不同", "实施方式不同", "保险人是否承担全部责任", "责任发生原因不同"], "answer": [3], "explanation": "按 责任发生原因（D选项）分为过失责任与无过失责任保险。"},
  {"id": 220, "type": "single", "question": " （　　） 是以第三者对被保险人履约责任为标的的险种。主要有：①忠诚保证保险，承保雇主因雇员的不法行为所致损失；②履约保险，承保合同当事人中一方违约所负的经济责任。", "options": ["信用保险", "财产保险", "人身保险", "责任保险"], "answer": [0], "explanation": "信用保险 以第三者对被保险人履约责任为标的的险种。主要有：①忠诚保证保险，承保雇主因雇员的不法行为所致损失；②履约保险，承保合同当事人中一方违约所负的经济责任。"},
  {"id": 221, "type": "single", "question": "《上海市建设工程安全生产责任保险实施意见》规定， （　　） 应当在办理施工许可手续节点之前投保建设工程安责险，并在施工许可承诺书载明相应的保单号及相应保费支付银行流水证明。", "options": ["新建工程", "扩建工程", "改建工程", "迁建工程"], "answer": [0], "explanation": "新建工程应当在办理施工许可手续节点之前投保建设工程安责险，并在施工许可承诺书载明相应的保单号及相应保费支付银行流水证明。已开工项目应对剩余建设期间内工程投保建设工程安责险。"},
  {"id": 222, "type": "single", "question": "《上海市建设工程安全生产责任保险实施意见》规定，承担本市建设工程安责险的保险机构应当在保险承保限额之上共同提供 （　　） 人民币的共享保障额度，保障本市建设工程生产活动中发生的特别重大事故的救援和赔付。", "options": ["1亿", "2亿", "3亿", "4亿"], "answer": [0], "explanation": "第六条 （保险机构社会责任）\n经招标承担本市建设工程安责险的保险机构应当建立保单承保限额以上的应急赔付机制，在保险承保限额之上共同提供1亿人民币的共享保障额度，保障本市建设工程生产活动中发生的特别重大事故的救援和赔付。"},
  {"id": 223, "type": "single", "question": "《上海市建设工程安全生产责任保险实施意见》规定，建设工程安责险的保险费计算基数为建设工程项目的 （　　） 。", "options": ["人工费", "材料费", "管理费", "合同总造价"], "answer": [3], "explanation": "建设工程安责险的保险费计算基数为建设工程项目的合同总造价。"},
  {"id": 224, "type": "single", "question": "《上海市建设工程安全生产责任保险实施细则》规定，投保建设工程安全生产责任保险的生产经营单位应当在办理施工许可手续时间节点 （　　） ，从具有承保资格的保险机构名单中选择承保公司，承保公司应以报价函形式响应。", "options": ["前", "后", "进行中", "暂停时"], "answer": [0], "explanation": "第五条 （保险合同）投保建设工程安全生产责任保险的生产经营单位应当在办理施工许可手续时间节点前，从具有承保资格的保险机构名单中选择承保公司，承保公司应以报价函形式响应。项目总承包单位应与该承保公司按照《实施意见》第七条相关要求签订《上海市建设工程安全生产责任保险合同》（以下简称“保险合同”）。"},
  {"id": 225, "type": "single", "question": "《工程建设行业标准管理办法》规定，行业标准的某些规定与国家标准不一致时，必须有充分的 （　　） 和理由，并经国家标准的审批部门批准。", "options": ["理论依据", "论证依据", "推论依据", "科学依据"], "answer": [3], "explanation": "行业标准的某些规定与国家标准不一致时,必须有充分的科学依据和理由,并经国家标准的审批部门批准。"},
  {"id": 226, "type": "single", "question": "《企业标准化管理办法》规定，企业标准应定期复审，复审周期一般不超过 （　　） 年。当有相应国家标准、行业标准和地方标准发布实施后，应及时复审，并确定其继续有效、修订或废止。", "options": ["二", "三", "四", "五"], "answer": [1], "explanation": "第十三条 企业标准应定期复审，复审周期一般不超过三年。"},
  {"id": 227, "type": "single", "question": "下列属于安全生产教育档案的是 （　　） 。", "options": ["事故调查报告书及批复", "换岗及复工教育资料", "专项安全检查记录", "隐患整改登记台账"], "answer": [1], "explanation": "2.2安全生产教育档案。保存单位：安全管理部、事业处。\n（1）进厂职工三级教育资料（长期保存）。\n（2）特种作业人员专门培训和定期复审，持证上岗有关资料。\n（3）换岗及复工教育资料。\n（4）每年至少一次对全员进行安全教育资料。\n（5）公司主要负责人和安全生产管理人员安全培训考核资料。\n以上资料均应有培训内容、学员名册、培训时间、考核成绩等。"},
  {"id": 228, "type": "single", "question": "企业安全生产档案中的进企业职工三级教育资料、特种设备档案、有害作业点监测记录的保存期限应为 （　　） 。", "options": ["3年以上", "5年以上", "10年以上", "长期保存"], "answer": [3], "explanation": "进厂职工三级教育资料(长期保存)。"},
  {"id": 229, "type": "single", "question": "根据《生产安全事故档案管理办法》规定，凡是造成人员死亡或重伤，或1000万元以上(含1000万元)直接经济损失的事故档案，列为 （　　） 。", "options": ["10年保管", "20年保管", "30年保管", "永久保管"], "answer": [3], "explanation": "凡是造成人员死亡或重伤,或 1000 万元以上(含 1000 万元)直接经济损失的事故档案,列为永久保管。"},
  {"id": 230, "type": "single", "question": "一般而言，政府对信用信息的管理实行 （　　） 的方式，既有政府部门对行业信用信息实行条线管理，也有地方政府对地方信用信息实行区域管理。", "options": ["一网通办", "一网统管", "条块结合", "大数据管理"], "answer": [2], "explanation": "一般而言，政府对信用信息的管理实行条块结合的方式，既有政府部门对行业信用信息实行条线管理，也有地方政府对地方信用信息实行区域管理。"},
  {"id": 231, "type": "single", "question": "《建筑市场信用管理暂行办法》规定，各级住房城乡建设主管部门应当建立健全信息推送机制，自优良信用信息和不良信用信息产生之日起 （　　） 个工作日内，通过省级工作平台依法对社会公开。", "options": ["5", "7", "10", "15"], "answer": [1], "explanation": "第七条 各级住房城乡建设主管部门应当建立健全信息推送机制，自优良信用信息和不良信用信息产生之日起7个工作日内，通过省级建筑市场监管一体化工作平台依法对社会公开，并推送至全国建筑市场监管公共服务平台。"},
  {"id": 232, "type": "single", "question": "《建筑市场信用管理暂行办法》规定，对被列入建筑市场主体“黑名单”的建筑市场各方主体，地方各级住房城乡建设主管部门应当通过省级建筑市场 （　　） 工作平台向社会公布相关信息。", "options": ["监管一体化", "企业信用", "信用共享", "信息互通"], "answer": [0], "explanation": "第十五条 对被列入建筑市场主体“黑名单”的建筑市场各方主体，地方各级住房城乡建设主管部门应当通过省级建筑市场监管一体化工作平台向社会公布相关信息，包括单位名称、机构代码、个人姓名、证件号码、行政处罚决定、列入部门、管理期限等。"},
  {"id": 233, "type": "single", "question": "根据《上海市建筑市场信用信息管理办法》规定，下列选项中 （　　） 不属于各方主体的信用信息。", "options": ["基本信息", "优良信息", "良好信息", "不良信息"], "answer": [1], "explanation": "第二条（定义）\n本管理办法所称建筑市场信用信息，是指各方主体在建筑市场活动中产生的，可用以识别、分析、判断主体守法、履约状况的客观数据和资料。各方主体的信用信息分为基本信息、良好信用信息、不良信用信息。"},
  {"id": 234, "type": "single", "question": "根据《上海市建筑市场信用信息管理办法》的规定，存在下列 （　　） 情形的，认定为A级不良信用信息。", "options": ["从业单位按照规定在行政审批等事项中作出承诺而未履行承诺的违法行为", "从业单位受到市级及以上建设管理部门书面通报批评的违行为", "超过两年行政处罚追溯期的违法或违规行为", "从业单位在一个自然年度内，被开具5次行政措施单"], "answer": [0], "explanation": "第十条（A级不良信用信息）\n存在下列情形的，认定为A级不良信用信息：\n（一）从业单位或人员被开具行政措施单（整改指令单、局部暂缓施工指令单、停工指令单等）的违法或违规行为；\n（二）从业单位拖欠农民工工资或者工程款但未造成严重不良社会影响的违法或违规行为；\n（三）从业单位或人员按照规定在行政审批等事项中作出承诺而未履行承诺的违法或违规行为；\n（四）在一个评价年度内，被建设行政管理部门、专业建设管理部门或其委托的第三方评定机构评定为成果质量不合格或基本合格的。"},
  {"id": 235, "type": "single", "question": "《上海市建筑市场信用信息管理办法》规定，本市建立建筑市场从业单位和从业人员信用信息档案制度。从业单位和从业人员参与本市建筑活动前，应当通过市建管平台完成基本信息报送与 （　　） 。", "options": ["注册执业人员", "注册专业技术人员", "执业业绩信息", "建立信用信息档案"], "answer": [3], "explanation": "第十三条（信用信息档案制度）\n本市建立建筑市场从业单位和从业人员信用信息档案制度。从业单位和从业人员参与本市建筑活动前，应当通过市建管平台完成基本信息报送，建立信用信息档案。"},
  {"id": 236, "type": "single", "question": "本市规定，水务管理部门、绿化市容管理部门或委行政服务中心应当在收到书面异议申请后 （　　） 工作日内完成核查和处理，并将结果告知申请人。", "options": ["3个", "5个", "7个", "10个"], "answer": [3], "explanation": "水务管理部门、绿化市容管理部门或委行政服务中心应当在收到书面异议申请后 10 个工作日内完成核查和处理，并将结果告知申请人。"},
  {"id": 237, "type": "single", "question": "信用信息通过市政府一网通办等政府网站向社会主动公开。公开时限自 （　　） 起计算。", "options": ["被查处之日", "被列入名单之日", "上网公开之日", "被告知之日"], "answer": [2], "explanation": "以上公开时限自上网公开之日起计算。累计形成的不良信用信息，从累计形成之日起生效起算。"},
  {"id": 238, "type": "single", "question": "上海市建设市场管理信息平台信用信息系统与上海市法人信息库、上海市公共信用信息服务平台等相关信息平台实现信息数据交换和共享，实现跨部门 （　　） 。", "options": ["汇总征信", "联合征信", "分级征信", "条块征信"], "answer": [1], "explanation": "第六条 上海市建设市场管理信息平台信用信息系统与上海市法人信息库、上海市公共信用信息服务平台等相关信息平台实现信息数据交换和共享,实现跨部门联合征信。"},
  {"id": 239, "type": "single", "question": "《上海市在沪建筑业企业信用评价标准》规定，工程业绩以合同履约完成日期为生效日期，自评价基准日起追溯（）。", "options": ["半年", "一年", "一年半", "二年"], "answer": [3], "explanation": "《上海市在沪建筑业企业信用评价标准》规定，工程业绩以合同履约完成日期为生效日期，自评价基准日起追溯二年。"},
  {"id": 240, "type": "single", "question": "《上海市在沪建筑业企业信用评价标准》规定，国家奖项自评价（）起追溯二年。", "options": ["告知日", "发布日", "基准日", "评价日"], "answer": [2], "explanation": "自评价基准日起追溯二年"},
  {"id": 241, "type": "single", "question": "起重伤害指从事各种起重作业时发生的 （　　） 事故。", "options": ["机械伤害", "触电伤害", "坠落伤害", "物体打击伤害"], "answer": [3], "explanation": "起重伤害事故是指在进行各种起重作业（包括吊运、安装、检修、试验）中发生的重物（包括吊具、吊重或吊臂）坠落、夹挤、物体打击、起重机倾翻等事故。"},
  {"id": 242, "type": "single", "question": "在建设工程领域中最常见的职业伤害事故共有7类。下列选项中 （　　） 不属于建设工程领域中最常见的职业伤害事故。", "options": ["灼烫", "物体打击", "中毒", "火灾"], "answer": [0], "explanation": "在建设工程领域中最常见的是高处坠落、物体打击、机械伤害、触电、坍塌、中毒、火灾7类。"},
  {"id": 243, "type": "single", "question": "与社会保险制度一般原则相同，工伤保险首先具有 （　　） 功能。", "options": ["福利", "互助", "补偿", "保障"], "answer": [3], "explanation": "工伤保险的核心功能是 补偿（C选项），为工伤职工提供医疗和经济补偿。"},
  {"id": 244, "type": "single", "question": "《上海市工伤保险实施办法》规定，工伤保险基金用于本办法规定的工伤保险待遇、劳动能力鉴定、 （　　） 、工伤预防的培训、法律、法规规定的用于工伤保险的其他费用的支付。", "options": ["从业人员人身损害或财产损失", "工伤预防的宣传", "事故抢险救援费用", "事故鉴定费用"], "answer": [1], "explanation": "工伤保险基金用于本办法规定的工伤保险待遇，劳动能力鉴定，工伤预防的宣传、培训等费用，以及法律、法规规定的用于工伤保险的其他费用的支付。"},
  {"id": 245, "type": "single", "question": "《上海市工伤保险实施办法》规定，从业人员在工作时间和工作岗位，突发疾病死亡或者在 （　　） 经抢救无效死亡的，视同工伤。", "options": ["48小时之内", "48小时之外", "72小时之内", "72小时之外"], "answer": [0], "explanation": "第十五条（视同工伤范围）从业人员有下列情形之一的，视同工伤：\n（一）在工作时间和工作岗位，突发疾病死亡或者在48小时之内经抢救无效死亡的；\n（二）在抢险救灾等维护国家利益、公共利益活动中受到伤害的；\n（三）从业人员原在军队服役，因战、因公负伤致残，已取得革命伤残军人证，到用人单位后旧伤复发的。\n从业人员有前款第一项、第二项情形的，按照本办法的有关规定享受工伤保险待遇；从业人员有前款第三项情形的，按照本办法的有关规定享受除一次性伤残补助金以外的工伤保险待遇。"},
  {"id": 246, "type": "single", "question": "《关于进一步做好本市建筑业工伤保险工作若干意见的通知》规定，按项目参加本市工伤保险的，工伤保险费按建设工程施工合同载明的合同价的 （　　） 确定，并根据以支定收、收支平衡的原则适时调整。", "options": ["0.5‰", "0.8‰", "1.5‰", "2‰"], "answer": [1], "explanation": "（一）按项目参保的工程建设项目，工伤保险费按照建设工程施工合同或项目标段合同（以下简称项目总承包合同）载明的合同价的0.8‰确定，并根据“以支定收、收支平衡”的原则适时调整。"},
  {"id": 247, "type": "single", "question": "《关于进一步做好本市建筑业工伤保险工作若干意见的通知》规定，未参加本市工伤保险的项目从业人员发生工伤事故，依法由 （　　） 支付工伤保险待遇。", "options": ["施工总承包企业", "建设单位", "所在的用人单位", "工伤保险基金"], "answer": [2], "explanation": "五、未参加本市工伤保险的项目从业人员发生工伤事故，依法由所在的用人单位支付工伤保险待遇，施工总承包企业、建设单位承担连带责任；从业人员所在的用人单位、承担连带责任的施工总承包企业、建设单位不支付的，由工伤保险基金先行支付，从业人员所在的用人单位和承担连带责任的施工总承包企业、建设单位应当偿还；不偿还的，由社会保险经办机构依法追偿。"},
  {"id": 248, "type": "single", "question": "上海市的文明施工从上世纪八十年代起步，发展至今已有四十年的历程。前后共经历 （　　） 阶段。", "options": ["3个", "4个", "5个", "6个"], "answer": [1], "explanation": "改革开放以后，上海市开展文明施工发展过程主要分为四个阶段：一是起步阶段，时间为1980~1992年，这个阶段的文明施工管理尚未有具体的明文规定和法律依据，只是根据市政府提倡的“爱国卫生月”活动和全市文明建设目标的要求，对建筑工地的文明施工只是作了一般的要求；二是摸索阶段，时间从1993~2009年，这一阶段建设部第15号令、沪建施（93）第0989号文、94年《文明施工管理暂行规定》相继出台，文明施工管理有了标准，总共为20条，并制定了具体的检查评分细则；三是发展阶段，时间从2009~2018年，市政府颁布了（2009）第18号文、（2010）第48号令，总共为31条，文明施工的内涵和外延上有了新的拓展和深化；四是逐步完善阶段，时间从2019年~至今，市政府（2019）第23号文，修改并完善了13条，文明施工管理的内容越来越规范化、具体化。"},
  {"id": 249, "type": "single", "question": "建设工程应当优先选用有利于文明施工的施工技术、工艺和建筑材料，并按照本市相关规定，采用 （　　） 建造方式。", "options": ["混合式", "逆作式", "装配式", "敞开式"], "answer": [2], "explanation": "建设工程应当优先选用有利于安全文明施工的施工技术、工艺和建筑材料,并按照省市相关规定,采用装配式建造方式。"},
  {"id": 250, "type": "single", "question": "《上海市建设工程文明施工管理规定》规定，管线工程的围挡高度和其他建设工程的围档高度不得低于 （　　） 。", "options": ["1.6米和1.8米", "1.7米和1.9米", "1.8米和2米", "1.9米和2.2米"], "answer": [2], "explanation": "管线工程的围挡高度不得低于1.8米,其他建设工程的围挡高度不得低于2米。"},
  {"id": 251, "type": "single", "question": "施工单位进行电焊作业或者夜间施工使用灯光照明的，应当采取有效的遮蔽光照措施，避免光照 （　　） 居民住宅。", "options": ["直射", "辐射", "折射", "斜射"], "answer": [0], "explanation": "施工单位进行电焊作业或者夜间施工使用灯光照明的，应当采取有效的遮蔽光照措施，避免光照直射居民住宅。"},
  {"id": 252, "type": "single", "question": "《上海市建设工程文明施工管理规定》规定，施工单位应当对工地泥浆进行三级沉淀后予以排放，禁止直接将工地 （　　） 排入城市排水管网或者河道。", "options": ["污水", "废水", "泥浆", "泥土"], "answer": [2], "explanation": "第十七条（排水设施）\n建设工程施工现场应当设置沉淀池和排水沟（管）网，确保排水畅通。\n施工单位应当对工地泥浆进行三级沉淀后予以排放，禁止直接将工地泥浆排入城市排水管网或者河道。"},
  {"id": 253, "type": "single", "question": "除城市道路工程、管线工程施工以及抢险、抢修工程外，建设工程或者建筑物、构筑物拆除需要在 （　　） 施工的，施工单位应当根据本市有关规定，向区生态环境部门办理夜间施工许可手续。", "options": ["夜间20时至次日凌晨5时", "夜间21时至次日凌晨5时", "夜间21时至次日凌晨6时", "夜间22时至次日凌晨6时"], "answer": [3], "explanation": "除城市道路工程、管线工程施工以及抢险、抢修工程外，建设工程或者建筑物、构筑物拆除需要在夜间 22 时至次日凌晨 6时施工的，施工单位应当根据《上海市环境保护条例》的有关规定，向区生态环境部门办理夜间施工许可手续。"},
  {"id": 254, "type": "single", "question": "《上海市建设工程文明施工管理规定》规定，建设工程项目的外立面紧邻人行道或者车行道的，施工单和位应当在该道路上方搭建坚固的安全天棚，并设置必要的警示和 （　　） 标志。", "options": ["提示标志", "命令标志", "引导标志", "指令标志"], "answer": [2], "explanation": "建设工程项目的外立面紧邻人行道或者车行道的,施工单位应当在该道路上方搭建坚固的安全天棚,并设置必要的警示和引导标志。"},
  {"id": 255, "type": "single", "question": "《建筑工程安全防护、文明施工措施费用及使用管理规定》规定，建设单位与施工单位在施工合同中对安全防护、文明施工措施费用预付、支付计划未作约定的，合同工期在一年以内的，建设单位预付安全防护、文明施工措施项目费用不得低于该费用总额的 （　　） 。", "options": ["30%", "40%", "50%", "55%"], "answer": [2], "explanation": "第七条 （合同内容）建设单位与施工单位应当在施工合同中明确安全防护、文明施工措施项目总费用，以及费用支付计划、使用要求、调整方式等条款。\n合同工期在一年以内的，建设单位预付安全防护、文明施工措施项目费用不得低于该费用总额的50%；合同工期在一年以上的（含一年），预付安全防护、文明施工措施项目费用不得低于该费用总额的30%.其余费用应当按照施工措施进度或合同约定支付。\n实行项目总承包的，总承包单位依法将建筑工程分包给其他单位的，总承包单位与分包单位应当在分包合同中明确安全防护、文明施工措施费用，以及费用支付计划、使用要求、调整方式等条款。"},
  {"id": 256, "type": "single", "question": "《房屋建筑工程文明施工提升标准》规定，施工现场应分别设置车辆与人员出入门，车辆出入门宽度不应小于 （　　） 。", "options": ["3m", "4m", "5m", "6m"], "answer": [2], "explanation": "《房屋建筑工程文明施工提升标准》\n1.施工边界设置\n1.1 施工现场应分别设置车辆与人员出入门，车辆出入门宽度不应小于 5m。"},
  {"id": 257, "type": "single", "question": "《房屋建筑工程文明施工提升标准》规定，施工单位应在围墙上安装喷雾降尘装置，在空气重污染预警启动或易扬尘作业时 （　　） 开启。", "options": ["自动", "手动", "遥控", "控制"], "answer": [0], "explanation": "《房屋建筑工程文明施工提升标准》规定，施工单位应在围墙上安装喷雾降尘装置，在空气重污染预警启动或易扬尘作业时自动开启。"},
  {"id": 258, "type": "single", "question": "《房屋建筑工程文明施工提升标准》规定，PC构件堆放架应使用定型化产品，按预制构件种类及最大重量进行设计和计算，确保架体的整体 （　　） 。", "options": ["固定性", "牢固性", "稳定性", "安全性"], "answer": [2], "explanation": "PC 构件堆放架应使用定型化产品，按预制构件种类及最大重量进行设计和计算，确保架体的整体稳定性。"},
  {"id": 259, "type": "single", "question": "《房屋建筑工程文明施工提升标准》规定，施工单位应在围墙上安装 （　　） 装置，在空气重污染预警启动或易扬尘作业时自动开启。", "options": ["高压喷雾机", "自动喷雾", "喷雾降尘", "水雾除尘"], "answer": [2], "explanation": "《房屋建筑工程文明施工提升标准》规定，施工单位应在围墙上安装喷雾降尘装置，在空气重污染预警启动或易扬尘作业时自动开启。"},
  {"id": 260, "type": "single", "question": "《环境噪声污染防治法》规定，在城市市区范围内，建筑施工过程中使用机械设备，可能产生环境噪声污染的，施工单位必须在工程开工 （　　） 以前向工程所在地的政府生态环境主管部门申报该工程有关环境噪声污染防治措施的情况。", "options": ["7日", "10日", "15日", "30日"], "answer": [2], "explanation": "第二十九条 在城市市区范围内，建筑施工过程中使用机械设备，可能产生环境噪声污染的，施工单位必须在工程开工十五日以前向工程所在地县级以上地方人民政府生态环境主管部门申报该工程的项目名称、施工场所和期限、可能产生的环境噪声值以及所采取的环境噪声污染防治措施的情况。"},
  {"id": 261, "type": "single", "question": "《上海市环境保护条例》规定，禁止在夜间从事产生环境噪声污染的建筑施工作业。但因混凝土连续浇筑等原因，确需在夜间从事建筑施工作业的，施工单位应当在施工作业前，向所在地区环保部门 （　　） 。", "options": ["进行备案", "预告登记", "提出申请", "进行登记"], "answer": [2], "explanation": "禁止在夜间从事产生环境噪声污染的建筑施工作业。但因混凝土连续浇筑等原因，确需在夜间从事建筑施工作业的，施工单位应当在施工作业前，向所在地区生态环境部门提出申请。"},
  {"id": 262, "type": "single", "question": "《上海市建筑垃圾处理管理规定》规定，本市推广装配式建筑、全装修房、建筑信息模型应用、绿色建筑设计标准等新技术、新材料、新工艺、 （　　） ，促进建筑垃圾的源头减量。", "options": ["新规范", "新品质", "新施工", "新标准"], "answer": [3], "explanation": "《上海市建筑垃圾处理管理规定》规定，本市推广装配式建筑、全装修房、建筑信息模型应用、绿色建筑设计标准等新技术、新材料、新工艺、新标准，促进建筑垃圾的源头减量。"},
  {"id": 263, "type": "single", "question": "绿色施工最大限度实现资源节约，工程项目施工目标在保证安全文明、工程质量、施工工期以及成本控制的基础上，增加以资源环境保护为 （　　） 的绿色施工目标.", "options": ["重要", "基本", "前提", "核心"], "answer": [3], "explanation": "绿色施工增加了以资源环境保护为核心内容的绿色工程目标；"},
  {"id": 264, "type": "single", "question": "单位工程绿色施工评价根据三个评价阶段、五个评价要系、三类评价指标，最后按每个批次评价分数的加权平均值，分别确定绿色施工阶段和单位工程的 （　　） 。", "options": ["绿色档次", "绿色等级", "绿色格次", "绿色名次"], "answer": [1], "explanation": "单位工程绿色施工评价通过三个评价阶段、五个评价要素、三类评价指标，最后按每个批次评价分数的加权平均值进行评估，确定的是绿色施工阶段和单位工程的绿色等级。"},
  {"id": 265, "type": "single", "question": "根据《绿色施工导则》要求，对于现场办公和生活用房采用周转式活动房，力争工地临房、临时围挡材料的可重复使用率达到 （　　） 。", "options": ["50%", "60%", "70%", "80%"], "answer": [2], "explanation": "现场办公和生活用房采用周转式活动房。现场围挡应最大限度地利用已有围墙，或采用装配式可重复使用围挡封闭。力争工地临房、临时围挡材料的可重复使用率达到70%。"},
  {"id": 266, "type": "single", "question": "建设工程安全生产监管体制是实行综合监管、行业监管和专业监管相结合的体制。同时综合监管、行业监管和专业监管又是实行 （　　） 。", "options": ["分类管理", "区域管理", "分级管理", "专项管理"], "answer": [2], "explanation": "监管体制结合 分级管理（C选项），明确各级职责分工。"},
  {"id": 267, "type": "single", "question": "《上海市建设工程质量安全监督机构与监督人员管理若干规定》的第二章规定了监督机构具有行政管理部门明确监督工作内容、职责、权限的行政执法 （　　） 。", "options": ["资质证书", "许可证", "工作代码", "委托书"], "answer": [3], "explanation": "第五条 监督机构应当具备以下基本条件：\n（一）机构配置\n1、具有行政管理部门明确监督工作内容、职责、权限的行政执法委托书；\n2、在职责范围内，独立开展建设工程质量安全监督工作，具有独立的对外挂牌和对外监督印章；\n3、有固定的质量安全监督经费来源；\n4、有相对独立的固定办公场所，办公面积应当满足监督工作的需要；\n5、配备满足工程质量安全监督需要的仪器、设备、工具和专用于工程质量安全监督的执法车辆等；\n6、有健全的质量安全监督和内部管理制度；\n7、具备与监督工作相适应的信息化管理条件。"},
  {"id": 268, "type": "single", "question": "《上海市建设工程施工安全监督管理办法》规定，施工单位应当负责本单位承担的施工任务范围内全部的 （　　） 工作。", "options": ["质量安全监督", "全技术管理", "安全管理", "质量安全管理"], "answer": [2], "explanation": "第七条 （施工单位的安全管理责任）\n施工单位应当负责本单位承担的施工任务范围内全部的安全管理工作。但施工承包合同中另有约定的，从其约定。"},
  {"id": 269, "type": "single", "question": "《上海市建设工程施工安全监督管理办法》规定，施工工地管理单位和施工单位应当在施工开始前，确定施工单位在施工现场的 （　　） 为所在施工单位负责施工安全管理的责任人。", "options": ["总监理工程师", "安全员", "项目经理", "技术负责人"], "answer": [2], "explanation": "施工单位在施工现场的项目经理为所在施工单位负责施工安全管理的责任人。"},
  {"id": 270, "type": "single", "question": "《上海市建设工程施工安全监督管理办法》规定，施工单位应当遵守施工现场电气安全保护和防火安全的有关规定，确保 （　　） 作业符合消防技术标准和规范，并保证消防设施的完好、有效。", "options": ["用火", "纵火", "带电", "高空"], "answer": [0], "explanation": "施工单位应当遵守施工现场电气安全保护和防火安全的有关规定，并达到下列要求：（1）保持变配电设施和电气线路处于安全、可靠的可使用状态；（2）确保用火作业符合消防技术标准和规范，并保证消防设施的完好、有效。"},
  {"id": 271, "type": "single", "question": "《上海市建设工程施工安全监督管理办法》规定，安全监督机构应当对施工工地管理单位和施工单位执行本办法有关规定的情况进行 （　　） 检查或者抽查。", "options": ["每月一次", "每月二次", "定期", "不定期"], "answer": [2], "explanation": "安全监督机构应当对施工工地管理单位和施工单位执行本办法有关规定的情况进行定期检查或者抽查。"},
  {"id": 272, "type": "single", "question": "《上海市建设工程质量安全监督管理规定》规定，建设工程安全监督工作一般从工程取得施工许可开始，至监督机构出具终止施工安全监督 （　　） 结束。", "options": ["确认书", "告知书", "评价表", "审核表"], "answer": [1], "explanation": "第六条 建设工程质量监督工作一般从工程取得施工许可开始，至监督机构出具工程质量监督报告结束或从受理工程质量监督手续开始，至出具《终止工程质量监督告知书》结束。"},
  {"id": 273, "type": "single", "question": "《上海市建设工程质量安全监督管理规定》规定，监督机构对每个项目的质量安全监督抽查次数为 （　　） 。", "options": ["每月不应少于一次", "每季度不应少于一次", "每月不应少于两次", "每季度不应少于两次"], "answer": [1], "explanation": "监督机构对每个项目的质量安全监督抽查次数为每季度不应少于一次"},
  {"id": 274, "type": "single", "question": "对符合要求的工地进行安全生产标准化竣工确认，并在确认后 （　　） 工作日内向建设单位发放《终止施工安全监督告知书》。", "options": ["3个", "5个", "7个", "10个"], "answer": [1], "explanation": "竣工确认后 5个工作日内（B选项）发放终止监督告知书。"},
  {"id": 275, "type": "single", "question": "监督机构在完成监督工作后所形成的监督档案，自归档之日起，质量监督档案保管期限统一为 （　　） 。", "options": ["3年", "5年", "7年", "10年"], "answer": [1], "explanation": "根据《上海市建设工程质量安全监督工作规定》第二十四条规定,质量监督档案保管期限自归档之日起为五年。"},
  {"id": 276, "type": "single", "question": "《上海市建设工程质量安全巡查管理办法》规定，市住建委在工程巡查中发现违法违规行为时，应向区建管部门开具 （　　） 。", "options": ["《巡查处置决定书》", "《巡查处置处罚书》", "《巡查处置建议书》", "《巡查处置通知书》"], "answer": [2], "explanation": "市住建委在工程巡查中发现违法违规行为时，应向区建管部门开具《巡查处置建议书》。"},
  {"id": 277, "type": "single", "question": "《关于进一步优化本市建筑工程质量安全监督和综合竣工验收管理工作的通知》规定，风险级别为高风险和超高风险的项目，由建设单位项目负责人组织施工单位技术负责人、 （　　） 和项目总监理工程师实施风险识别。", "options": ["监理单位项目总监", "企业技术负责人", "设计单位项目负责人", "项目安全负责安全人"], "answer": [2], "explanation": "风险级别为高风险和超高风险的项目，由建设单位项目负责人组织施工单位技术负责人、设计单位项目负责人和项目总监理工程师实施风险识别。"},
  {"id": 278, "type": "single", "question": "以下哪个选项不属于我国《民法典》规定的承担民事责任主要方式 （　　） 。", "options": ["罚款", "赔偿损失", "返还财产", "支付违约金"], "answer": [0], "explanation": "罚款属于行政处罚或刑事责任范畴，而《民法典》规定的民事责任方式包括赔偿损失、返还财产、支付违约金等。"},
  {"id": 279, "type": "single", "question": "实践中大部分民事纠纷都是采取非诉讼方式，由当事人双方 （　　） 解决的。", "options": ["协商", "调解", "裁决", "仲裁"], "answer": [0], "explanation": "实践中大部分民事纠纷都是采取非诉讼方式，由当事人双方协商解决的，最终由法院审判解决的仅占一小部分。"},
  {"id": 280, "type": "single", "question": "行政责任主要方式有行政处罚和 （　　） 两种方式。", "options": ["罚款处理", "警告处分", "行政处分", "责令改正"], "answer": [2], "explanation": "题目可能存在排版错误，行政责任的主要方式应为“行政处罚”和“行政处分”，但选项中仅有“行政处罚”重复出现，故选择此选项。"},
  {"id": 281, "type": "single", "question": "我国《行政处罚法》第八条规定的行政处罚中，最为常见的行政处罚是 （　　） 。", "options": ["警告", "罚款", "没收违法所得", "责令停产停业"], "answer": [1], "explanation": "根据我国《行政处罚法》第八条的规定，最为常见的行政处罚是罚款。"},
  {"id": 282, "type": "single", "question": "下列选项中，属于施工安全中常见的刑事责任的是 （　　） 。", "options": ["工程安全责任事故罪", "工程重大安全事故罪", "重大安全事故罪", "安全责任事故罪"], "answer": [1], "explanation": "在施工安全领域，工程重大安全事故罪是最常见的刑事责任形式，涉及因违规操作导致重大事故的情形。"},
  {"id": 283, "type": "single", "question": "依据最高检《关于办理危害生产安全刑事责任案件适用法律若干问题的解释》，以下不被认定为“强令他人违章冒险作业”情形是 （　　） 。", "options": ["采取威逼、胁迫、恐吓等手段，强制他人违章作业的", "故意掩盖事故隐患，组织他人违章作业的", "其他强令他人违章作业的行为", "为偷工减料，伙同他人违章作业"], "answer": [3], "explanation": "第五条 明知存在事故隐患、继续作业存在危险,仍然违反有关安全管理的规定,实施下列行为之一的,应当认定为刑法第一百三十四条第二款规定的“强令他人违章冒险作业”:\n(一)利用组织、指挥、管理职权,强制他人违章作业的;\n(二)采取威逼、胁迫、恐吓等手段,强制他人违章作业的;\n(三)故意掩盖事故隐患,组织他人违章作业的;\n(四)其他强令他人违章作业的行为。"},
  {"id": 284, "type": "single", "question": "依据《安全生产法》规定，生产经营单位的主要负责人受刑事处罚或者撤职处分的，自刑罚执行完毕或者受处分之日起，5年内不得担任任何生产经营单位的（）；对重大、特别重大生产安全事故负有责任的，终身不得担任本行业生产经营单位的主要负责人。", "options": ["项目负责人", "安全负责人", "主要负责人", "生产负责人"], "answer": [2], "explanation": "《安全生产法》明确规定，受处罚的主要负责人在一定期限内不得担任任何单位的主要负责人。"},
  {"id": 285, "type": "single", "question": "依据《安全生产法》规定， （　　） 未按照规定设置安全生产管理机构或者配备安全生产管理人员、注册安全工程师的，责令限期改正，处十万元以下的罚款。", "options": ["产权单位", "建设单位", "安装单位", "生产经营单位"], "answer": [3], "explanation": "第九十七条 生产经营单位有下列行为之一的，责令限期改正，处十万元以下的罚款；逾期未改正的，责令停产停业整顿，并处十万元以上二十万元以下的罚款， 对其直接负责的主管人员和其他直接责任人员处二万元以上五万元以下的罚款：\n（一）未按照规定设置安全生产管理机构或者配备安全生产管理人员、注册安全工程师的；"},
  {"id": 286, "type": "single", "question": "生产经营单位应当在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全 （　　） 标志。", "options": ["警告", "警示", "提示", "指令"], "answer": [1], "explanation": "根据《安全生产法》，危险场所需设置“安全警示标志”以提醒人员注意危险。"},
  {"id": 287, "type": "single", "question": "依据《安全生产法》定，生产经营单位未建立 （　　） 分级管控制度，责令限期改正，处十万元以下的罚款。", "options": ["危险等级", "安全隐患", "安全风险", "安全事故"], "answer": [2], "explanation": "未建立安全风险分级管控制度或者未按照安全风险分级采取相应管控措施的；"},
  {"id": 288, "type": "single", "question": "《安全生产法》规定，高危行业、领域的生产经营单位未按照国家规定投保 （　　） ，责令限期改正，处五万元以上十万元以下的罚款；逾期未改正的，处十万元以上二十万元以下的罚款。", "options": ["工程质量保险", "安全生产责任保险", "工程意外险", "意外伤害险"], "answer": [1], "explanation": "高危行业需投保“安全生产责任保险”，这是《安全生产法》的明确要求。"},
  {"id": 289, "type": "single", "question": "依据《安全生产违法行为行政处罚办法》规定，生产经营单位及其有关人员一年内因同一违法行为受到 （　　） 以上行政处罚的，应当从重处罚。", "options": ["两次", "三次", "四次", "五次"], "answer": [0], "explanation": "根据规定，一年内同一违法行为受到两次以上行政处罚的，应从重处罚。"},
  {"id": 290, "type": "single", "question": "对同一生产经营单位及其有关人员的同一安全生产违法行为， （　　） 给予两次以上罚款的行政处罚。", "options": ["可以", "不得", "报上级机构同意", "如果严重违法"], "answer": [1], "explanation": "第五十三条 对同一生产经营单位及其有关人员的同一安全生产违法行为，不得给予两次以上罚款的行政处罚。"},
  {"id": 291, "type": "single", "question": "《关于加强建筑施工安全事故责任企业人员处罚的意见》规定，对没有履行安全生产职责、造成生产安全事故特别是 （　　） 事故发生的建筑施工企业有关责任人员，住房和城乡建设主管部门要依法暂停或撤销其与安全生产相关执业资格、岗位证书，并依法实施职业禁入；构成犯罪的，依法追究刑事责任。", "options": ["一般及以上", "较大及以上", "重大及以上", "特别重大及以上"], "answer": [1], "explanation": "建筑施工企业主要负责人、项目负责人和专职安全生产管理人员等必须具备相应的安全生产知识和管理能力。对没有履行安全生产职责、造成生产安全事故特别是较大及以上事故发生的建筑施工企业有关责任人员，住房和城乡建设主管部门要依法暂停或撤销其与安全生产相关执业资格、岗位证书，并依法实施职业禁入；构成犯罪的，依法追究刑事责任。对负有事故责任的勘察、设计、监理等单位有关注册执业人员，也要依法责令停止执业直至吊销相关注册证书，不准从事相关建筑活动。"},
  {"id": 292, "type": "single", "question": "根据《上海市建设工程施工安全监督管理办法》第八条第二款规定，施工单位不得安排未接受过安全教育、技术培训并经考核合格的施工人员上岗作业。使用无证人员多于30人或者占施工人员总数25%以上，责令限期改正，并可处以 （　　） 的罚款。", "options": ["3万元以上5万元以下", "1万元以上5万元以下", "5万元以上10万元以下", "2万元以上5万元以下"], "answer": [0], "explanation": "【依据】《上海市建设工程施工安全监督管理办法》\n【解析】正确答案是D。题干对应的是上海市建设工程施工安全监督管理办法。 A项“3万元以上5万元以下”错误，它不符合题干限定的对象、程序或条件。 B项“1万元以上5万元以下”错误，它不符合题干限定的对象、程序或条件。 C项“5万元以上10万元以下”错误，它不符合题干限定的对象、程序或条件。 D项“2万元以上5万元以下”正确，它与题干所述“第八条第二款规定，施工单位不得安排未接受过安”相对应。"},
  {"id": 293, "type": "single", "question": "根据《建筑起重机械安全监督管理规定》，使用单位未制定建筑起重机械生产安全事故应急救援预案，由县级以上地方人民政府建设主管部门责令限期改正，予以警告，并处以 （　　） 罚款。", "options": ["5000元以上1万元以下", "1万元以上3万元以下", "5000元以上3万元以下", "3万元以上5万元以下"], "answer": [2], "explanation": "第十八条 使用单位应当履行下列安全职责：\n（一）根据不同施工阶段、周围环境以及季节、气候的变化，对建筑起重机械采取相应的安全防护措施；\n（二）制定建筑起重机械生产安全事故应急救援预案；【本违反内容】\n（三）在建筑起重机械活动范围内设置明显的安全警示标志，对集中作业区做好安全防护；\n（四）设置相应的设备管理机构或者配备专职的设备管理人员；\n（五）指定专职设备管理人员、专职安全生产管理人员进行现场监督检查；\n（六）建筑起重机械出现故障或者发生异常情况的，立即停止使用，消除故障和事故隐患后，方可重新投入使用。\n第三十条 违反本规定，使用单位有下列行为之一的，由县级以上地方人民政府建设主管部门责令限期改正，予以警告，并处以5000元以上3万元以下罚款：\n（一）未履行第十八条第（一）、（二）、（四）、（六）项安全职责的；\n（二）未指定专职设备管理人员进行现场监督检查的；\n（三）擅自在建筑起重机械上安装非原制造厂制造的标准节和附着装置的。"},
  {"id": 294, "type": "single", "question": "依据《建筑起重机械安全监督管理规定》，施工现场有多台塔式起重机作业时， （　　） 应当组织制定并实施防止塔式起重机相互碰撞的安全措施。", "options": ["建设单位", "监理单位", "施工分包单位", "施工总承包单位"], "answer": [3], "explanation": "第二十一条 施工总承包单位应当履行下列安全职责：\n（一）向安装单位提供拟安装设备位置的基础施工资料，确保建筑起重机械进场安装、拆卸所需的施工条件；\n（二）审核建筑起重机械的特种设备制造许可证、产品合格证、制造监督检验证明、备案证明等文件；\n（三）审核安装单位、使用单位的资质证书、安全生产许可证和特种作业人员的特种作业操作资格证书；\n（四）审核安装单位制定的建筑起重机械安装、拆卸工程专项施工方案和生产安全事故应急救援预案；\n（五）审核使用单位制定的建筑起重机械生产安全事故应急救援预案；\n（六）指定专职安全生产管理人员监督检查建筑起重机械安装、拆卸、使用情况；\n（七）施工现场有多台塔式起重机作业时，应当组织制定并实施防止塔式起重机相互碰撞的安全措施。"},
  {"id": 295, "type": "single", "question": "依据《建筑施工企业安全生产许可证管理规定》，建筑施工企业管理人员和作业人员 （　　） 至少进行一次安全生产教育培训并考核合格。", "options": ["每月", "半年", "每年", "每两年"], "answer": [2], "explanation": "施工单位应当对管理人员和作业人员每年至少进行一次安全生产教育培训。"},
  {"id": 296, "type": "single", "question": "国际劳工组织的执行委员会是 （　　） ，每三年经大会选举产生。", "options": ["理事会", "协调会", "劳工委员会", "管理委员会"], "answer": [0], "explanation": "理事会:国际劳工组织的执行委员会,每三年经大会选举产生,在大会休会期间指导该组织工作,每年3月、6月和11月各召开一次会议。"},
  {"id": 297, "type": "single", "question": "本市规定，为降低建设工地的噪声污染，制定了建设工地施工分贝控制值，即晚21时至23时限 （　　） 分贝。", "options": ["60", "65", "70", "75"], "answer": [2], "explanation": "日间标准（70分贝）"},
  {"id": 298, "type": "single", "question": "《建筑业安全卫生公约》规定，炸药的贮存、搬运、装卸和使用必须由 （　　） 进行，并应采取必要措施使工人和其他人员免受危害。", "options": ["项目经理", "主管人员", "安全员", "材料员"], "answer": [1], "explanation": "第二十七条炸药\n炸药的贮存、搬运、装卸和使用必须：\n（a）符合国家法律或条例规定的条件；\n（b）由主管人员进行，并应采取必要措施使工人和其他人员免受危害。"},
  {"id": 299, "type": "single", "question": "开挖深度 （　　） m及以上的基坑（槽）的土方开挖、支护、降水工程属于Ⅰ类危险等级。", "options": ["3", "5", "15", "24"], "answer": [2], "explanation": "【依据】《建筑基坑支护技术规程》JGJ 120-2012 / 《建筑基坑工程监测技术标准》GB 50497-2019\n【解析】正确答案是B。题干对应的是基坑工程安全与监测。 A项“3”错误，题干对应的控制数值不是3，正确值应为5。 B项“5”正确，规范要求的控制数值或时限就是5。 C项“15”错误，题干对应的控制数值不是15，正确值应为5。 D项“24”错误，题干对应的控制数值不是24，正确值应为5。"},
  {"id": 300, "type": "single", "question": "对建筑施工临时结构应做安全生产技术分析，并应保证在设计规定的使用工况下保持整体稳定性，这一条是 （　　） 条文。", "options": ["指导性", "推荐性", "一般性", "强制性"], "answer": [3], "explanation": "【依据】《建筑施工安全技术统一规范》GB 50870-2013\n【解析】正确答案是D。题干对应的是建筑施工安全技术措施。 A项“指导性”错误，它说的是“指导性”，并非题干要找的“强制性”。 B项“推荐性”错误，它说的是“推荐性”，并非题干要找的“强制性”。 C项“一般性”错误，它说的是“一般性”，并非题干要找的“强制性”。 D项“强制性”正确，它与题干所述“对建筑施工临时结构应做安全生产技术分析，并应”相对应。"},
  {"id": 301, "type": "single", "question": "建筑施工安全生产技术措施应按危险等级分级控制，其分 （　　） 级。", "options": ["2", "3", "4", "5"], "answer": [1], "explanation": "【依据】《建筑施工安全技术统一规范》GB 50870-2013\n【解析】正确答案是B。题干对应的是建筑施工安全技术措施。 A项“2”错误，题干对应的控制数值不是2，正确值应为3。 B项“3”正确，规范要求的控制数值或时限就是3。 C项“4”错误，题干对应的控制数值不是4，正确值应为3。 D项“5”错误，题干对应的控制数值不是5，正确值应为3。"},
  {"id": 302, "type": "single", "question": "建筑施工过程中，对于采用新技术或者新工艺的环节，应按照 （　　） 进行安全生产技术控制。", "options": ["原有危险等级", "提高一个危险等级", "降低一个危险等级", "根据不同工艺选择危险等级"], "answer": [1], "explanation": "对关键环节，特殊环节、采用新技术或新工艺的环节，应提高一个危险等级进行安全技术控制。"},
  {"id": 303, "type": "single", "question": "安全生产技术交底是指交底方向被交底方对预控和控制生产安全事故发生及减少其危害的技术措施、施工方法进行说明的技术活动，用于指导 （　　） 。", "options": ["建筑施工技术", "建筑施工行为", "建筑施工过程", "建筑施工活动"], "answer": [1], "explanation": "交底方向被交底方对预防和控制生产安全事故发生及减少其危害的技术措施、 施工方法进行说明的技术活动，用于指导建筑施工行为。"},
  {"id": 304, "type": "single", "question": "实行施工总承包的单位工程，应由总承包单位组织安全技术措施实施验收，相关专业工程的承包单位 （　　） 和安全负责人应参加相关专业工程的安全技术措施实施验收。", "options": ["项目经理", "安全技术措施编制人", "技术负责人", "专业监理工程师"], "answer": [2], "explanation": "实行施工总承包的单位工程，应由总承包单位组织安全技术措施实施验收，相关专业工程的承包单位技术负责人和安全负责人应参加相关专业工程的安全技术措施实施验收。"},
  {"id": 305, "type": "single", "question": "建设单位、施工单位、监理单位和其他各单位在工程竣工或有关安全生产技术活动结束后 （　　） 天内，应将安全生产技术文件交本单位档案室归档，档案保存期不应少于1年。", "options": ["15", "20", "25", "30"], "answer": [3], "explanation": "建设单位、施工单位、监理单位和其他各单位在工程竣工或有关安全生产技术活动结束后30天内，应将安全生产技术文件交本单位档案室归档，档案保存期不应少于1年。"},
  {"id": 306, "type": "single", "question": "建筑施工安全应急救援预案应对安全事故的 （　　） 进行安全生产技术分析，对可能引发次生灾害的风险，应有预防技术措施。", "options": ["风险等级", "风险特征", "风险程度", "风险因素"], "answer": [1], "explanation": "建筑施工安全应急救援预案应对安全事故的风险特征进行安全生产技术分析，对可能引发次生灾害的风险，应有预防技术措施。"},
  {"id": 307, "type": "single", "question": "基坑工程中，以下关于无支护基坑的特点，说法正确的是 （　　） 。", "options": ["基坑壁土质不稳定，且有地下水的影响", "放坡土方开挖工程量大，不经济", "容易受到施工场地或邻近建筑物限制", "地下水位低于基底或渗透量小，不影响坑壁稳定性"], "answer": [3], "explanation": "工程地质知识：无支护基坑特点和主要形式\n特点：\n1、基础埋置不深，施工期较短，挖基坑时不影响邻近建筑物的安全。\n2、地下水位低于基底，或者渗透量小，不影响坑壁稳定性。\n主要形式：\n无支护基坑的坑壁形式分为垂直坑壁、斜坡和阶梯形坑壁以及变坡度坑壁。"},
  {"id": 308, "type": "single", "question": "以下不属于基坑工程施工安全专项方案中的工程概况内容的是 （　　） 。", "options": ["基坑工程本体安全", "基坑安全等级", "基坑规模", "支护结构形式"], "answer": [0], "explanation": "【依据】《建筑基坑支护技术规程》JGJ 120-2012 / 《建筑基坑工程监测技术标准》GB 50497-2019\n【解析】正确答案是A。这是一道反向设问题，题干要找的是“不符合/不属于/错误”项。 A项“基坑工程本体安全”正确，它与题干所述“以下基坑工程施工安全专项方案中的工程概况内容”相对应。 B项“基坑安全等级”错误，它说的是“基坑安全等级”，并非题干要找的“基坑工程本体安全”。 C项“基坑规模”错误，它说的是“基坑规模”，并非题干要找的“基坑工程本体安全”。 D项“支护结构形式”错误，它说的是“支护结构形式”，并非题干要找的“基坑工程本体安全”。"},
  {"id": 309, "type": "single", "question": "基坑工程中，当 （　　） 的渗流速度超过临界流速或水力坡度超过临界坡度时，就会引起管涌及流砂现象。", "options": ["动水压力", "静水压力", "流水压力", "出水压力"], "answer": [0], "explanation": "当动水压力的渗流速度超过临界流速或水力坡度超过临界坡度时,就会引起管涌及流砂现象。"},
  {"id": 310, "type": "single", "question": "现行《建筑基坑支护技术规程》JGJ120规定，基坑支护结构可划分为 （　　） 个安全等级。", "options": ["一", "二", "三", "四"], "answer": [2], "explanation": "【依据】《建筑基坑支护技术规程》\n【解析】正确答案是C。题干对应的是建筑基坑支护技术规程。 A项“一”错误，它说的是“一”，并非题干要找的“三”。 B项“二”错误，它说的是“二”，并非题干要找的“三”。 C项“三”正确，它与题干所述“现行《建筑基坑支护技术规程》JGJ120规定”相对应。 D项“四”错误，它说的是“四”，并非题干要找的“三”。"},
  {"id": 311, "type": "single", "question": "基坑支护结构中，以下不属于支撑结构作用的是 （　　） 。", "options": ["为深基础施工创造一个安全、良好的作用环境", "控制支护结构的变形区域位移对本工程的影响", "保证基坑开挖时，最大限度地减少对周围建筑的影响，确保其安全", "控制地表隆起或塌陷"], "answer": [3], "explanation": "支护结构的作用：\n（1）为基础施工创造一个安全的，良好的作业环境，保证基础工程施工按期保质完成.\n(2)保证基坑开挖时，最大限度地减小对周围建(构)筑物，道路及管线的影响，确保其安全.\n（3)同时还应控制支护结构的变形对工程桩的影响"},
  {"id": 312, "type": "single", "question": "单一土钉墙适用于地下水位以上或降水的非软土基坑，且基坑深度不宜大于 （　　） m。", "options": ["5", "7", "10", "12"], "answer": [3], "explanation": "【依据】《建筑基坑支护技术规程》JGJ 120-2012 / 《建筑基坑工程监测技术标准》GB 50497-2019\n【解析】正确答案是D。题干对应的是基坑工程安全与监测。 A项“5”错误，题干对应的控制数值不是5，正确值应为12。 B项“7”错误，题干对应的控制数值不是7，正确值应为12。 C项“10”错误，题干对应的控制数值不是10，正确值应为12。 D项“12”正确，规范要求的控制数值或时限就是12。"},
  {"id": 313, "type": "single", "question": "水泥土桩复合土钉墙用于淤泥质土基坑时，基坑深度不宜大于 （　　） m。", "options": ["3", "5", "6", "7"], "answer": [2], "explanation": "用于淤泥质土基坑时，基坑深度不宜大于 6m"},
  {"id": 314, "type": "single", "question": "以下选项中， （　　） 用于非软土基坑时，基坑深度不宜大于12m；用于淤泥质土基坑时，基坑深度不宜大于6m；不宜用在高水位的碎石土、砂土层中。", "options": ["预应力锚杆复合土钉墙", "水泥土桩复合土钉墙", "微型桩复合土钉墙", "单一土钉墙"], "answer": [1], "explanation": "水泥土桩复合土钉墙适用于非软土基坑,且基坑深度不宜大于12m"},
  {"id": 315, "type": "single", "question": "重力式水泥土墙采用格栅形式时，格栅的面积置换率，对一般黏性土、砂土，不宜小于 （　　） 。", "options": ["60%", "70%", "80%", "90%"], "answer": [0], "explanation": "重力式水泥土墙采用格栅形式时,格栅的面积置换率,对淤泥质土,不宜小于0. 7;对淤泥,不宜小于0.8;对一般黏性土、砂土,不宜小于0.6。"},
  {"id": 316, "type": "single", "question": "施工期间土钉墙支护坡顶应按荷载 （　　） 设计要求控制施工荷载。", "options": ["超载值", "标准值", "组合值", "代表值"], "answer": [0], "explanation": "【依据】《建筑基坑支护技术规程》JGJ 120-2012 / 《建筑基坑工程监测技术标准》GB 50497-2019\n【解析】正确答案是D。题干对应的是基坑工程安全与监测。 A项“超载值”错误，它说的是“超载值”，并非题干要找的“代表值”。 B项“标准值”错误，它说的是“标准值”，并非题干要找的“代表值”。 C项“组合值”错误，它说的是“组合值”，并非题干要找的“代表值”。 D项“代表值”正确，它与题干所述“施工期间土钉墙支护坡顶应按荷载设计要求控制施”相对应。"},
  {"id": 317, "type": "single", "question": "重力式水泥土墙的嵌固深度，对淤泥质土，不宜小于 （　　） 。（注：基坑深度用符号h表示)。", "options": ["1.1h", "1.2h", "1.3h", "1.4h"], "answer": [1], "explanation": "重力式水泥土墙的嵌固深度，对淤泥质土，不宜小于1.2h"},
  {"id": 318, "type": "single", "question": "地下连续墙成槽施工前，应沿地下连续墙两侧设置导墙，导墙地面不宜设置在新近填土上，且埋深不宜小于 （　　） m。", "options": ["1.2", "1.5", "1.8", "2.0"], "answer": [1], "explanation": "成槽施工前,应沿地下连续墙两侧设置导墙,导墙宜采用混凝土结构,且混凝土强度等级不宜低于C20。导墙底面不宜设置在新近填土上,且埋深不宜小于1.5m。"},
  {"id": 319, "type": "single", "question": "地下连续墙混凝土浇筑过程中，导管埋入混凝土的深度宜在 （　　） m之间，浇筑液面的上升速度不宜小于3m/h。", "options": ["1-2", "2-4", "4-5", "5-6"], "answer": [1], "explanation": "混凝土浇筑过程中，导管埋入混凝土面的深度宜在2.0m～4.0m，浇筑液面的上升速度不宜小于3m/h。"},
  {"id": 320, "type": "single", "question": "地下连续墙护壁泥浆拌制后应贮放 （　　） h，待泥浆材料充分水化后方可使用。", "options": ["12", "18", "24", "30"], "answer": [2], "explanation": "地下连续墙护壁泥浆拌制后应贮放24h,待泥浆材料充分水化后方可使用。"},
  {"id": 321, "type": "single", "question": "钢筋笼应根据吊装的要求，设置纵横向起吊桁架；桁架主筋宜采用HRB400钢筋，钢筋直径不宜小于 （　　） mm。", "options": ["14", "16", "18", "20"], "answer": [3], "explanation": "钢筋笼应根据吊装的要求，设置纵横向起吊桁架；桁架主筋宜采用HRB335级或HRB400级钢筋，钢筋直径不宜小于20mm，且应满足吊装和沉放过程中钢筋笼的整体性及钢筋笼骨架不产生塑性变形的要求。连接点出现位移、松动或开焊的钢筋笼不得入槽，应重新制作或修整完好。"},
  {"id": 322, "type": "single", "question": "地下连续墙预制墙段运输时叠放层数不宜超过 （　　） 层。", "options": ["2", "3", "4", "5"], "answer": [0], "explanation": "根据《建筑深基坑工程施工安全技术规范JGJ 311》的规定，地下连续墙预制墙段运输叠放层数不宜超过2层。"},
  {"id": 323, "type": "single", "question": "当桩孔净间距过小或采用多台钻机同时施工时，相邻桩应间隔施工，当无特殊措施时，完成浇筑混凝土的桩与邻桩间距不宜小于 （　　） 倍桩径。", "options": ["2.5", "3", "3.5", "4"], "answer": [3], "explanation": "当桩孔净间距过小或采用多台钻机同时施工时，相邻桩应间隔施工，当无特别措施时完成浇筑混凝土的桩与邻桩间距不应小于4倍桩径，或间隔施工时间宜大于36h。"},
  {"id": 324, "type": "single", "question": "钻孔咬合桩施工，钻机就位及吊设第一节钢套管时，应采用两个测斜仪贴附在套管外壁并用经纬仪复核套管垂直度，其垂直度允许偏差应为 （　　） 。", "options": ["0.3%", "0.5%", "0.8%", "1.0%"], "answer": [0], "explanation": "钻机就位及吊设第一节钢套管时,应采用两个测斜仪贴附在套管外壁并用经纬仪复核套管垂直度,其垂直度允许偏差应为0.3%;"},
  {"id": 325, "type": "single", "question": "当采用振动桩锤作业时，悬挂振动桩锤的起重机，其吊钩上必须有 （　　） ，振动桩锤悬挂钢架的耳环上应加装保险钢丝绳。", "options": ["防坠安全绳", "漏电保护装置", "防松脱的保护装置", "自动平衡装置"], "answer": [2], "explanation": "悬挂振动桩锤的起重机,其吊钩上必须有防松脱的保护装置。"},
  {"id": 326, "type": "single", "question": "下列关于钻孔咬合桩施工说法正确的是 （　　） 。", "options": ["桩顶应设导墙，导墙的厚度宜取0.3~0.5m", "桩顶应设置导墙，导墙宽度宜取2m", "钢筋混凝土桩应在素混凝土桩终凝前，通过成孔时切割部分素混凝土桩身形成与素混凝土桩的互相咬合", "抓斗在套管内取土时，套管底部应始终位于抓土面上方，且抓土面与套管低的距离应大于2m"], "answer": [0], "explanation": "钻孔咬合桩施工可采用液压钢套管全长护壁、机械冲抓成孔工艺，其施工应符合下列要求：\n（1）桩顶应设置导墙，导墙宽度宜取3m～4m，导墙厚度宜取0.3m～0.5m；\n（2）咬合桩应按先施工素混凝土桩、后施工钢筋混凝土桩的顺序进行；钢筋混凝土桩应在素混凝土桩初凝前通过在成孔时切割部分素混凝土桩身形成与素混凝土桩的互相咬合搭接；钢筋混凝土桩的施工尚应避免素混凝土桩刚浇筑后被切割；\n（3）钻机就位及吊设第一节套管时，应采用两个测斜仪贴附在套管外壁并用经纬仪复核套管垂直度，其垂直度允许偏差应为3‰。液压套管应正反扭动加压下切。管内抓斗取土时，套管底部应始终位于抓土面下方，抓土面与套管底的距离应大于1.0m；\n（4）孔内虚土和沉渣应清除干净，并用抓斗夯实孔底；灌注混凝土时，套管应随混凝土浇筑逐段拔；套管应垂直提拔，阻力过大时应转动套管同时缓慢提拔。"},
  {"id": 327, "type": "single", "question": "基坑开挖前应进行基坑开挖影响范围内的疏干降水，预抽水时间根据基坑面积、开挖深度决定，且不宜少于 （　　） d。", "options": ["7", "10", "15", "20"], "answer": [2], "explanation": "预抽水时间根据基坑面积、开挖深度决定,不宜少于15天。"},
  {"id": 328, "type": "single", "question": "当坑底下部的 （　　） 影响到基坑安全时，应采取坑底土体加固或降低承压水头等治理措施。", "options": ["淤泥", "支护结构", "承压水", "集水井"], "answer": [2], "explanation": "当坑底下部的承压水影响到基坑安全时，应采取坑底土体加固或降低承压水头等治理措施。"},
  {"id": 329, "type": "single", "question": "降水井施工完成后应进行试抽水，检验 （　　） 和降水效果。", "options": ["成孔垂直度", "成孔工艺", "泥浆配比", "成井质量"], "answer": [3], "explanation": "降水井施工完成后应进行试抽水,检验成井质量和降水效果。"},
  {"id": 330, "type": "single", "question": "降水系统应进行试运行，试运行抽水控制时间为 （　　） ,并应检查出水质量和出水量。", "options": ["1d", "2d", "3d", "4d"], "answer": [0], "explanation": "降水系统应进行试运行，试运行之前应测定各井口和地面标高、静止水位，检查抽水设备、抽水与排水系统；试运行抽水控制时间为1d，并应检查出水质量和出水量；"},
  {"id": 331, "type": "single", "question": "当微承压含水层、承压含水层顶板埋深小于基坑开挖深度，应将微承压含水层和承压含水层的水位降低至基坑开挖面和坑底以下 （　　） 。", "options": ["0.5m", "1m", "1.5m", "2m"], "answer": [0], "explanation": "基坑开挖面和坑底以下0.5m"},
  {"id": 332, "type": "single", "question": "石英砂滤料，其粒径D50代表 （　　） 。", "options": ["有50%(按质量计)滤料能通过规定的筛网达到标准粒径", "滤料平均粒径为0.5mm", "滤料平均粒径为5mm", "有50%(按质量计)滤料标准粒径为5mm"], "answer": [0], "explanation": "d50代表一定质量的石英砂滤料,有50%可以通过规定的筛网达到标准粒径。\n单层或双层滤料滤池的石英砂滤料粒径范围,一般为0.5～1.2mm"},
  {"id": 333, "type": "single", "question": "真空降水管井施工时，孔壁与井管直径的滤料宜采用中粗砂，滤料上方应用黏土封堵，封堵至地面的厚度应 （　　） 。", "options": ["大于0.5m", "大于1m", "小于0.5m", "小于1m"], "answer": [1], "explanation": "孔壁与井管之间的滤料宜采用中粗砂,滤料上方应用黏土封堵,封堵至地面的厚度应大于1.0m"},
  {"id": 334, "type": "single", "question": "在粉性土和砂土中施工水泥土截水帷幕时，宜采用合适的 （　　） ，降低截水帷幕渗透系数。", "options": ["添加剂", "阻锈剂", "泵送剂", "缓凝剂"], "answer": [0], "explanation": "在粉性土及砂土中施工水泥土截水帷幕，宜采用适合的添加剂，降低截水帷幕渗透系数，并应对帷幕渗透系数进行检验，当检验结果不满足设计要求时，应进行设计复核。"},
  {"id": 335, "type": "single", "question": "高压喷射注浆的施工作业顺序应采用隔孔分序方式，相邻孔喷射注浆的间隔时间不宜小于 （　　） 。", "options": ["12h", "24h", "48h", "72h"], "answer": [1], "explanation": "高压喷射注浆的施工作业顺序应采用隔孔分序方式,相邻孔喷射注浆的间隔时间不宜小于24h。"},
  {"id": 336, "type": "single", "question": "当因浆液渗漏而出现孔口不返浆的情况时，应将注浆管停置在不返浆处持续喷射注浆，并宜同时采用从孔口填入中粗砂、注浆液掺入（）等措施，直至出现孔口返浆。", "options": ["泵送剂", "缓凝剂", "速凝剂", "膨胀剂"], "answer": [2], "explanation": "当因浆液渗漏而出现孔口不返浆的情况时，应将注浆管停置在不返浆处持续喷射注浆，并宜同时采用从孔口填入中粗砂、注浆液掺入速凝剂等措施，直至出现孔口返浆。"},
  {"id": 337, "type": "single", "question": "冻结法截水帷幕施工，冻结站安装应进行管路（）试验，并应采取措施保证冻结站的冷却效率。", "options": ["防冻性", "抗压性", "稳定性", "密封性"], "answer": [3], "explanation": "冰冻站安装应进行管路密封性试验,并应采取措施保证冻结站的冷却效率。正式运转后不得无故停止或减少供冷。"},
  {"id": 338, "type": "single", "question": "土方挖掘机、运输车辆等直接进入基坑进行施工作业时，应采取保护坡道稳定的措施，坡道坡度不宜大于 （　　） ,坡道的宽度应满足车辆行驶要求。", "options": ["1：6", "1：8", "1：10", "1：12"], "answer": [1], "explanation": "挖土机械、运输车辆等直接进入基坑进行施工作业时,应采取保证坡道稳定的措施,坡道坡度不宜大于1:8,坡道的宽度应满足车辆行驶的安全要求。"},
  {"id": 339, "type": "single", "question": "挖土机械严禁碰撞工程桩、围护墙、支撑、立柱和立柱桩、降水井管、监测点等，其周边 （　　） mm范围内的土方应采用人工挖除。", "options": ["200～300", "200～500", "300～500", "400～600"], "answer": [0], "explanation": "挖土机械严禁碰撞工程桩、围护墙、支撑、立柱和立柱桩、降水井管、监测点等,其周边 200 ㎜～300mm 范围内的土方应采用人工挖除;"},
  {"id": 340, "type": "single", "question": "当场地条件允许并经验算能保证边坡稳定时，可采用放坡开挖。基坑开挖深度超过 （　　） m时，应采用多级放坡的开挖形式。", "options": ["2", "4", "7", "10"], "answer": [1], "explanation": "基坑开挖深度超过 4.0m 时,应采用多级放坡的开挖方式。"},
  {"id": 341, "type": "single", "question": "采用逆作法、盖挖法进行暗挖施工，基坑暗挖作业应设置足够的照明设施，照明设施应根据 （　　） 配置。", "options": ["作业时长", "挖土过程", "支护类型", "基坑尺寸"], "answer": [1], "explanation": "基坑暗挖作业应设置足够的照明设施,照明设施应根据挖土过程配置。"},
  {"id": 342, "type": "single", "question": "基坑工程施工前， （　　） 编制监测方案。", "options": ["建设单位", "施工单位", "监理单位", "监测单位"], "answer": [3], "explanation": "基坑工程施工前,应由建设方委托具备相应资质第三方对基坑工程实施现场监测。监测单位应编制监测方案,经建设方、设计方、监理方等认可后方可实施。"},
  {"id": 343, "type": "single", "question": "道路沉降监测点的间距不宜大于 （　　） m，且每条道路的监测点不应少于3个。", "options": ["30", "35", "40", "45"], "answer": [0], "explanation": "道路沉降监测点的间距不宜大于30m,且每条道路的监测点不应少于3个。必要时,沿道路宽度方向可布设多个测点。"},
  {"id": 344, "type": "single", "question": "围护墙侧向土压力监测点按土层分布情况布设时，每层应至少布设 （　　） 测点，且宜布置在各层 （　　） 。", "options": ["1个，端部", "2个，两端", "2个，中部", "1个，中间"], "answer": [3], "explanation": "当按土层分布情况布设时，每层应至少布设1个测点，且布置在各层土的中部；"},
  {"id": 345, "type": "single", "question": "采用 （　　） 时，监测前应对经纬仪的垂直轴倾斜误差进行检验，当垂直角超出±3°范围时，应进行垂直轴倾斜修正。", "options": ["前方交汇法", "极坐标法", "视准线法", "小角度法"], "answer": [3], "explanation": "如采用小角度法时,监测前应对经纬仪的垂直轴倾斜误差进行检验,当垂直角超出±3°范围时,应进行垂直轴倾斜修正。"},
  {"id": 346, "type": "single", "question": "下列关于土压力监测说法正确的是 （　　） 。", "options": ["土压力计埋设可采用埋入式或边界式", "受力面与所监测的压力方向平行并紧贴被监测对象", "若在土压力计埋设与围护墙构筑同期进行，土压力计无法紧贴围护墙", "土压力计若在围护墙完成后进行，需解决好土压力计在围护墙迎土面上的安装问题"], "answer": [0], "explanation": "土压力监测。\n土压力宜采用土压力计量测。 土压力计埋设可采用埋入式或边界式（接触式）。埋设时应符合下列要求：\n（1） 受力面与所需监测的压力方向垂直并紧贴被监测对象；\n（2） 埋设过程中应有土压力膜保护措施；\n（3）采用钻孔法埋设时，回填应均匀密实，且回填材料宜与周围岩土体一致。\n（4） 做好完整的埋设记录。 土压力计埋设以后应立即进行检查测试，基坑开挖前至少经过1周时间的监测并取得稳定初始值。"},
  {"id": 347, "type": "single", "question": "地下水位监测时，潜水水位管滤管以上应用膨润土球封至孔口，原因是 （　　） 。", "options": ["防止尘土、杂物落入水位管", "防止水位管损坏", "防止地表水流入水位管", "防止地下水流出水位管"], "answer": [2], "explanation": "潜水水位管滤管以上应用膨润土球封至孔口,防止地表水进入;承压水位管含水层以上部分应用膨润土球或注浆封孔。"},
  {"id": 348, "type": "single", "question": "建筑物对基坑开挖引起的附加变形承受能力宜通过 （　　） 来确定。", "options": ["环境调查", "压力测试", "变形程度", "沉降情况"], "answer": [0], "explanation": "建(构)筑物对基坑开挖引起的附加变形的承受能力宜通过环境调查确定。"},
  {"id": 349, "type": "single", "question": "采用数值方法分析基坑开挖对周围环境的影响，宜建立恰当的有限元模型，采用合理的计算域及符合实际情况的 （　　） ，对基坑开挖进行全过程模拟。", "options": ["连续条件", "变形条件", "约束条件", "边界条件"], "answer": [3], "explanation": "宜建立包括土层分层情况、支护结构、分层开挖工况及周围建(构)筑物在内的有限元模型,采用合理的计算域及符合实际情况的边界条件,对基坑开挖进行全过程模拟;"},
  {"id": 350, "type": "single", "question": "靠近古树名木进行有泥浆污染的围护墙施工时，宜采取 （　　） 等有效隔离措施。", "options": ["安全网", "防护围栏", "钢板桩", "地下连续墙"], "answer": [2], "explanation": "邻近古树名木进行有泥浆污染的围护墙施工时,宜采取钢板桩等有效隔离措施。"},
  {"id": 351, "type": "single", "question": "当基坑底部有 （　　） 并须进行减压降水时，在基坑开挖前应进行抽水试验确定降水参数，并制订合理的降水方案。", "options": ["潜水层", "承压含水层", "上层滞水含水层", "隔水层"], "answer": [1], "explanation": "当基坑底部有承压含水层并须进行减压降水时，在基坑开挖前应进行抽水试验确定降水参数，并制订合理的降水方案。"},
  {"id": 352, "type": "single", "question": "对基坑周围的保护对象，基坑开挖前，在保护对象的侧面和底部设置注浆管，对其土体注浆预加固；建(构)筑物基础底部以下注浆深度不宜小于 （　　） m。", "options": ["2", "3", "4", "5"], "answer": [3], "explanation": "基坑开挖前,在保护对象的侧面和底部设置注浆管,对其土体注浆预加固。建筑物基础底部以下注浆深度不宜小于5m;地下管线底部以下注浆深度不宜小于2m。"},
  {"id": 353, "type": "single", "question": "模板在混凝土浇筑过程中及混凝土强度增长过程中起模板作用，在结构使用过程中与结构连成一个整体，不再拆除，这种模板为 （　　） 。", "options": ["固定式模板", "移动式模板", "永久式模板", "定型模板"], "answer": [2], "explanation": "永久式模板是指模板在混凝土浇筑过程中及混凝土强度增加过程中起模板作用,在结构使用过程中与结构连成一个整体,不再拆除,成为结构组成的一部分。"},
  {"id": 354, "type": "single", "question": "模板工程作业高度在 （　　） 以上操作时，周围应设安全网、防护栏杆。", "options": ["3m及2层", "4m及2层", "5m及2层", "6m及2层"], "answer": [1], "explanation": "模板工程作业高度在2m和2m以上时，应根据高处作业安全技术规范的要求进行操作和防护，要有安全可靠的操作架子；在4m及2层以上操作时周围应设安全网、防护栏杆。在临街及交通要道地区施工应设警示牌，避免伤及行人。"},
  {"id": 355, "type": "single", "question": "照明行灯及机电设备的移动线路应采用 （　　） 电缆线，且不得直接固定在钢模板上。", "options": ["耐高温橡胶套", "屏蔽", "射频", "绝缘橡胶套"], "answer": [3], "explanation": "【依据】《建筑施工模板安全技术规范》JGJ 162-2008\n【解析】正确答案是D。题干对应的是模板工程与支撑体系安全。 A项“耐高温橡胶套”错误，它说的是“耐高温橡胶套”，并非题干要找的“绝缘橡胶套”。 B项“屏蔽”错误，它说的是“屏蔽”，并非题干要找的“绝缘橡胶套”。 C项“射频”错误，它说的是“射频”，并非题干要找的“绝缘橡胶套”。 D项“绝缘橡胶套”正确，它与题干所述“照明行灯及机电设备的移动线路应采用电缆线，且”相对应。"},
  {"id": 356, "type": "single", "question": "现浇多层或高层房屋和构筑物，安装上层模板及其支架，下层楼板应具有承受上层施工荷载的承载能力，否则应加设 （　　） 。", "options": ["垫板", "钢模板", "支撑支架", "U形可调支托"], "answer": [2], "explanation": "现浇多层或高层房屋和构筑物,安装上层模板及其支架应符合下列规定: 1)下层楼板应具有承受上层施工荷载的承载能力,否则应加设支撑支架。"},
  {"id": 357, "type": "single", "question": "根据模板安装构造要求，当层间高度小于或等于 （　　） m时，可采用木柱支模。", "options": ["3", "4", "5", "6"], "answer": [2], "explanation": "根据模板安装构造要求，当层间高度小于或等于5m时，可采用木柱支模。"},
  {"id": 358, "type": "single", "question": "支撑梁、板的支架立柱，钢管立柱底部应设垫木和底座，顶部应设 （　　） ，如果与楞梁两侧间有间隙，必须楔紧，其螺杆伸出钢管顶部不得大于200mm。", "options": ["U形可调支托", "垫木", "隅撑", "剪刀撑"], "answer": [0], "explanation": "木立柱底部应设垫木，顶部应设支撑头。钢管立柱底部应设垫木和底座，顶部应设可调支托，U型支托与楞梁两侧间如有间隙，必须楔紧，其螺杆伸出钢管顶部不得大于200mm，螺杆外径与立柱钢管内径的间隙不得大于3mm，安装时应保证上下同心。"},
  {"id": 359, "type": "single", "question": "在立柱底距地面 （　　） 高处，沿纵横水平方向应按纵下横上的程序设扫地杆。", "options": ["350mm", "300mm", "250mm", "200mm"], "answer": [3], "explanation": "在立柱底距地面200mm高处，沿纵横水平方向应按纵下横上的程序设扫地杆。"},
  {"id": 360, "type": "single", "question": "支撑梁、板的支架立柱，所有水平拉杆的端部均应与四周建(构)筑物顶紧顶牢。无处可顶时，应于水平拉杆端部和中部沿 （　　） 设置连续式剪刀撑。", "options": ["横向", "竖向", "斜向", "双向"], "answer": [1], "explanation": "无处可顶时,应于水平拉杆端部和中部沿竖向设置连续剪刀撑。"},
  {"id": 361, "type": "single", "question": "钢管扫地杆、水平拉杆应采用对接，剪刀撑应采用搭接，其搭接长度按规范要求不得小于 （　　） mm。", "options": ["200", "300", "400", "500"], "answer": [3], "explanation": "钢管扫地杆、水平拉杆应采用对接，剪刀撑应采用搭接，搭接长度不得小于500mm，并应采用2个旋转扣件分别在离杆端不小于100mm处进行固定。"},
  {"id": 362, "type": "single", "question": "关于模板安装构造，下列选项不符合规定的是 （　　） 。", "options": ["模板安装应按设计与施工说明书顺序拼装", "竖向模板和支架立柱支承部分安装在基土上时，应加设垫板", "现浇钢筋混凝土梁、板，当跨度大于3m时，模板应起拱", "模板安装过程中，必须设置有效防倾覆的临时固定设施"], "answer": [2], "explanation": "对跨度不小于4m的现浇钢筋混凝土梁、板，其模板应按设计要求起拱"},
  {"id": 363, "type": "single", "question": "若桁架采用多榀成组排放，在 （　　） 折角处必须加设水平撑。", "options": ["上弦", "下弦", "竖杆", "斜杆"], "answer": [1], "explanation": "若桁架采用多榀成组排放,在下弦折角处必须加设水平撑。"},
  {"id": 364, "type": "single", "question": "所有单立柱支撑应位于底垫木和梁底模板的中心，并应与底部垫木和顶部梁底模板紧密接触，且不得承受 （　　） 荷载。", "options": ["弯曲", "对称", "轴心", "偏心"], "answer": [3], "explanation": "所有单立柱支撑应在底垫木和梁底模板的中心,并应与底部垫木和顶部梁底模板紧密接触,且不得承受偏心荷载。"},
  {"id": 365, "type": "single", "question": "当仅为单排立柱时，应于单排立柱的两边每隔3m加设斜支撑，且每边不得少于2根，斜支撑与地面的夹角应为 （　　） 。", "options": ["30°", "45°", "60°", "75°"], "answer": [2], "explanation": "当仅为单排立柱时,应于单排立柱的两边每隔3m 加设斜支撑,且每边不得少于两根,斜支撑与地面的夹角应为60°。"},
  {"id": 366, "type": "single", "question": "安装基础及地下工程模板时，以下说法正确的是 （　　） 。", "options": ["当深度超过1m时，操作人员应设梯上下", "斜支撑与侧模的夹角不应小于60°", "运下的模板可临时立放于基槽土壁上", "距基槽上口边缘1m内不得堆放模板"], "answer": [3], "explanation": "(1) 基础及地下工程模板：\n1) 地面以下支模应先检查土壁的稳定情况，当有裂纹及塌方迹象时，应采取安全防范措施后，方可下人作业。当深度超过2m时，操作人员应扶梯上下；\n2) 距基槽（坑）上口边缘1m内不得堆放模板。向基槽（坑）内运料应使用起重机、溜槽或绳索；运下的模板严禁立放在基槽（坑）土壁上；\n3) 斜支撑与侧模的夹角不应小于45°，支在土壁上的斜支撑应加设垫板，底部的对角楔木应与斜支撑连牢。高大长脖基础若采用分层支模时，其上下模板应经就位校正并支撑稳固后，方可进行上一层模板的安装；\n4) 在有斜支撑的位置，应在两侧模间采用水平撑连成整体。"},
  {"id": 367, "type": "single", "question": "墙模板构造中，当钢楞长度需接长时，搭接长度不得小于墙模板宽或高的 （　　） 。", "options": ["5%-10%", "10%-15%", "15%-20%", "20%-25%"], "answer": [2], "explanation": "当钢楞长度需接长时,接头处应增加相同数量和不小于原规格的钢楞,搭接长度不得小于墙模板宽或高的15～20%。"},
  {"id": 368, "type": "single", "question": "混凝土浇筑过程应分层进行，采用表面振动器时，分层振捣厚度不宜超过 （　　） mm。", "options": ["250", "300", "100", "200"], "answer": [3], "explanation": "浇筑混凝土时应分段分层进行,每层浇筑高度应根据结构特点、钢筋疏密决定。一般分层高度为插入式振动器作用部分长度的1.25倍,大不超过500mm,平板振动器的分层厚度为200mm。"},
  {"id": 369, "type": "single", "question": "承受混凝土重量的模板，应在混凝土达到设计强度的 （　　） %后方可拆除承重模板。", "options": ["10", "15", "20", "25"], "answer": [3], "explanation": "在承重焊接钢筋骨架作配筋的结构中,承受混凝土重量的模板,应在混凝土达到设计强度的25%后方可拆除承重模板。"},
  {"id": 370, "type": "single", "question": "拆除条形基础、杯形基础、独立基础或设备基础的钢模板时，正确的拆除顺序为： （　　） 。", "options": ["先拆U型卡和L型插销，后拆面板", "先拆钩头螺栓和内外钢楞，后拆拉杆和斜撑", "先拆钩头螺栓和内外钢楞，后拆U型卡和L型插销", "先拆U型卡和L型插销，后拆钩头螺栓和内外钢楞"], "answer": [2], "explanation": "拆除条形基础、杯形基础、独立基础或设备基础的模板时，应遵守下列规定：\n①拆除前应先检查基槽(坑)土壁的安全状况，发现有松软、龟裂等不安全因素时，应在采取安全防范措施后，方可进行作业。\n②模板和支撑杆件等应随拆随运，不得在离槽(坑)上口边缘1000mm 以内堆放。\n③拆除模板时，施工人员必须站在安全地方。应先拆内外木楞、再拆木面板；钢模板应先拆钩头螺栓和内外钢楞，后拆U型卡和L型插销，拆下的钢模板应妥善传递或用绳钩放置地面，不得抛掷。拆下的小垄零配件应装入工具袋内或小型箱内，不得随处乱扔。"},
  {"id": 371, "type": "single", "question": "扣件式脚手架，是靠拧紧扣件螺栓所产生的 （　　） 承担连接作用的脚手架。", "options": ["作用力", "剪切力", "挤压力", "摩擦力"], "answer": [3], "explanation": "扣件式脚手架是指使用扣件箍紧连接的脚手架,即靠拧紧扣件螺栓所产生的摩擦力承担连接作用的脚手架。"},
  {"id": 372, "type": "single", "question": "作业脚手架外侧和支撑脚手架作业层栏杆应采用 （　　） 或其他措施全封闭防护。", "options": ["绞索网", "尼龙网", "主动防护网", "密目式安全网"], "answer": [3], "explanation": "【依据】《建筑施工高处作业安全技术规范》JGJ 80-2016\n【解析】正确答案是D。题干对应的是建筑施工高处作业防护。 A项“绞索网”错误，它说的是“绞索网”，并非题干要找的“密目式安全网”。 B项“尼龙网”错误，它说的是“尼龙网”，并非题干要找的“密目式安全网”。 C项“主动防护网”错误，它说的是“主动防护网”，并非题干要找的“密目式安全网”。 D项“密目式安全网”正确，它与题干所述“作业脚手架外侧和支撑脚手架作业层栏杆应采用或”相对应。"},
  {"id": 373, "type": "single", "question": "在搭设和拆除脚手架作业时，应设置安全警戒线和 （　　） ,并应设专人监护，严禁非作业人员进入作业范围。", "options": ["保持安全距离", "安全区域", "警戒标志", "安全限位装置"], "answer": [2], "explanation": "在搭设和拆除脚手架作业时,应设置安全警戒线、警戒标志,并应由专人监护,严禁非作业人员入内。"},
  {"id": 374, "type": "single", "question": "悬挑钢梁悬挑长度应按设计确定，固定段长度不应小于悬挑段长度的 （　　） 倍。", "options": ["1", "1.25", "1.5", "2"], "answer": [1], "explanation": "悬挑钢梁悬挑长度应按设计确定，固定段长度不应小于悬挑段长度的1.25倍。"},
  {"id": 375, "type": "single", "question": "悬挑架的外立面 （　　） 应自下而上连续设置。", "options": ["斜撑", "抛撑", "剪刀撑", "水平横撑"], "answer": [2], "explanation": "悬挑架的外立面剪刀撑应自下而上连续设置。"},
  {"id": 376, "type": "single", "question": "设在脚手架外侧面、与墙面平行的十字交叉斜杆，可增强脚手架的纵向刚度的构件是 （　　） 。", "options": ["连墙件", "剪刀撑", "立杆", "脚手板"], "answer": [1], "explanation": "剪刀撑∶设在脚手架外侧面、与墙面平行的十字交叉斜杆，可增强脚手架的纵向刚度"},
  {"id": 377, "type": "single", "question": "依据《建筑施工扣件式钢管脚手架安全技术规范》JGJ130，常用密目式安全立网全封闭式单、双排脚手架的设计尺寸表格适用于地面粗糙度为 （　　） 类地区。", "options": ["A", "B", "C", "D"], "answer": [2], "explanation": "地面粗糙度可分为A、B、C、D四类：\n一A类指近海海面和海岛、海岸、湖岸及沙漠地区；\n一B类指田野、乡村、丛林、丘陵以及房屋比较稀疏的乡镇和城市郊区；\n一C类指有密集建筑群的城市市区；\n—D类指有密集建筑群且房屋较高的城市市区。"},
  {"id": 378, "type": "single", "question": "常用密目式安全立网全封闭式双排脚手架的设计，三步三跨连墙件设置不适用于立杆横距 （　　） m的架子。", "options": ["1.05", "1.20", "1.30", "1.55"], "answer": [3], "explanation": "两步三跨适用于立杆间距为1.05、1.30、1.55M的架子，三步三跨不适用于立杆间距为1.55M的架子。"},
  {"id": 379, "type": "single", "question": "纵向水平杆采用对接扣件连接或搭接时，各接头中心至最近主节点的距离不应大于 （　　） 的1/3。", "options": ["纵距", "横距", "步距", "层高"], "answer": [0], "explanation": "对接时纵向水平杆的对接扣件应交错布置,两根相邻纵向水平杆的接头不宜设置在同步或同跨内，不同步或不同跨两个相邻接头在水平方向错开的距离不应小于500mm；各接头中心至最近主节点的距离不宜大于纵距的1/3。"},
  {"id": 380, "type": "single", "question": "扣件式钢管脚手架，当使用冲压钢脚手板、木脚手板、竹串片脚手板时，纵向水平杆应作为横向水平杆的支座，用 （　　） 固定在立杆上。", "options": ["直角扣件", "对接扣件", "旋转扣件", "转角扣件"], "answer": [0], "explanation": "当使用冲压钢脚手板、木脚手板、竹串片脚手板时,纵向水平杆应作为横向水平杆的支座,用直角扣件固定在立杆上"},
  {"id": 381, "type": "single", "question": "扣件式钢管脚手架，单排、双排与满堂脚手架立杆接长除 （　　） 外，其余各层各步接头必须采用对接扣件连接。", "options": ["底层底步", "顶层顶步", "底层顶步", "顶层底步"], "answer": [1], "explanation": "单排、双排与满堂脚手架立杆接长除顶层顶步外，其余各层各步接头必须采用对接扣件连接。"},
  {"id": 382, "type": "single", "question": "扣件式钢管脚手架，连墙件应靠近主节点设置，偏离主节点的距离不应大于 （　　） mm。", "options": ["300", "400", "500", "600"], "answer": [0], "explanation": "连墙件的布置应靠近主节点设置，偏离主节点的距离不应大于300mm；"},
  {"id": 383, "type": "single", "question": "扣件式钢管脚手架，单、双排脚手架门洞桁架的斜腹杆宜采用 （　　） 固定在与之相交的横向水平杆的伸出端上。", "options": ["直角扣件", "对接扣件", "旋转扣件", "转角扣件"], "answer": [2], "explanation": "扣件式钢管脚手架，单、双排脚手架门洞桁架的斜腹杆宜采用旋转扣件固定在与之相交的横向水平杆的伸出端上。"},
  {"id": 384, "type": "single", "question": "扣件式钢管脚手架，单排脚手架过窗洞时应增设立杆或增设一根 （　　） 。", "options": ["连墙杆", "斜腹杆", "横向水平杆", "纵向水平杆"], "answer": [3], "explanation": "单排脚手架过窗洞时应增设立杆或增设 1 根纵向水平杆。"},
  {"id": 385, "type": "single", "question": "扣件式钢管脚手架，门洞桁架中伸出上下弦杆的杆件端头，均应增设一个 （　　） 扣件。", "options": ["对接", "旋转", "防滑", "直角"], "answer": [2], "explanation": "依据《建筑施工扣件式钢管脚手架安全技术规范》(JGJ130-2011)，门洞桁架中伸出上下弦杆的杆件端头，均应增设一个防滑扣件，该扣件宜紧靠主节点处的扣件。"},
  {"id": 386, "type": "single", "question": "高度在24m以下的封闭型双排脚手架可不设 （　　） 。", "options": ["横向扫地杆", "纵向扫地杆", "横向斜撑", "连墙杆"], "answer": [2], "explanation": "高度在 24m 以下的封闭型双排脚手架可不设横向斜撑。"},
  {"id": 387, "type": "single", "question": "斜道脚手板顺铺时，接头应采用搭接，下面的板头应压住上面的板头，板头的凸棱应采用 （　　） 填顺。", "options": ["模板条", "塑料胶条", "三角木", "方木"], "answer": [2], "explanation": "脚手板顺铺时，接头应采用搭接，下面的板头应压住上面的板头，板头的凸棱处应采用三角木填顺。"},
  {"id": 388, "type": "single", "question": "扣件式钢管满堂脚手架立杆接长接头必须采用 （　　） 连接。", "options": ["直角扣件", "对接扣件", "旋转扣件", "转角扣件"], "answer": [1], "explanation": "【依据】《建筑施工扣件式钢管脚手架安全技术规范》JGJ 130-2011\n【解析】正确答案是B。题干对应的是扣件式钢管脚手架安全技术。 A项“直角扣件”错误，它说的是“直角扣件”，并非题干要找的“对接扣件”。 B项“对接扣件”正确，它与题干所述“扣件式钢管满堂脚手架立杆接长接头必须采用连接”相对应。 C项“旋转扣件”错误，它说的是“旋转扣件”，并非题干要找的“对接扣件”。 D项“转角扣件”错误，它说的是“转角扣件”，并非题干要找的“对接扣件”。"},
  {"id": 389, "type": "single", "question": "扣件式钢管，当架体搭设高度在8m以下时，应在架体 （　　） 设置连续水平剪刀撑。", "options": ["顶部", "底部", "中间", "竖向间隔不超过8m的位置"], "answer": [0], "explanation": "当架体搭设高度在8m以下时,在架体顶部设置连续水平剪刀撑;"},
  {"id": 390, "type": "single", "question": "下列关于加强型满堂支撑架说法错误的是 （　　） 。", "options": ["在竖向剪刀撑顶部交点平面应设置水平剪刀撑", "水平剪刀撑至架体底平面距离与水平剪刀撑间距不宜超过8m", "剪刀撑宽度应为3m~5m", "竖向剪刀撑斜杆与地面的倾角应为45°~60°"], "answer": [1], "explanation": "剪刀撑设置\na）剪刀撑的构造：剪刀撑斜杆的接长宜采用搭接；剪刀撑斜杆应用旋转扣件固定在与之相交的横向水平杆的伸出端或立杆上，旋转扣件中心线至主节点的距离不宜大于150mm。\nb）在竖向剪刀撑顶部交点平面应设置水平剪刀撑，水平剪刀撑至架体底平面距离与水平剪刀撑间距不宜超过6m，剪刀撑宽度应为3～5m。\nc)竖向剪刀撑斜杆与地面的倾角应为45～60,水平剪刀撑与支架纵（或横）向夹角应为45～60°。\nd)满堂支架的可调底座、可调托撑螺杆伸出长度不宜超过300mm，插入立杆内的长度不得小于150mm。"},
  {"id": 391, "type": "single", "question": "关于扣件式钢管脚手架的搭设，下列说法错误的是 （　　） 。", "options": ["纵向水平杆应随立杆按步搭设，并应采用直角扣件与立杆固定", "应先安装脚手架，随后安装连墙件", "剪刀撑与双排脚手架同步搭设，不得滞后安装", "脚手板应铺满、铺稳，离墙面的距离不应大于150mm"], "answer": [1], "explanation": "连墙件的安装应随架体升高及时在规定位置处设置,不得滞后安装;"},
  {"id": 392, "type": "single", "question": "当脚手架拆至下部最后一根长立杆的高度（约6.5m）时，应先在适当位置搭设 （　　） 加固后，再拆除连墙件。", "options": ["水平杆", "临时抛撑", "剪刀撑", "扫地杆"], "answer": [1], "explanation": "当脚手架拆至下部最后一根长立杆的高度(约6.5m)时,应先在适当位置搭设临时抛撑加固后,再拆除连墙件;"},
  {"id": 393, "type": "single", "question": "承插型盘扣式钢管支撑架立杆盘扣节点间距宜按 （　　） 模数设置，横杆长度宜按 （　　） 模数设置。", "options": ["0.3m，0.5m", "0.3m，0.6m", "0.5m，0.3m", "0.6m，0.3m"], "answer": [2], "explanation": "立杆盘扣节点间距宜按0.5m模数设置;横杆长度宜按0.3m模数设置。"},
  {"id": 394, "type": "single", "question": "用承插型盘扣式钢管支架搭设双排脚手架时，脚手架首层立杆宜采用不同长度的立杆交错布置，错开立杆竖向距离不应小于 （　　） 。", "options": ["300mm", "400mm", "500mm", "600mm"], "answer": [2], "explanation": "脚手架首层立杆宜采用不同长度的立杆交错布置，错开立杆竖向距离不应小于500mm，当需设置人行通道时，立杆底部应配置可调底座。"},
  {"id": 395, "type": "single", "question": "对于承插型盘扣式钢管脚手架，立杆的垂直偏差不应大于模板支架总高度的 （　　） ，且不得大于50mm。", "options": ["1/200", "1/300", "1/400", "1/500"], "answer": [3], "explanation": "立杆的垂直偏差不应大于模板支架总高度的 1/500,且不得大于 50mm。"},
  {"id": 396, "type": "single", "question": "脚手架可分段搭设分段使用，应由工程 （　　） 组织相关人员进行验收，符合专项施工方案后方可使用。", "options": ["项目总监理工程师", "项目经理", "项目技术负责人", "项目安全负责人"], "answer": [2], "explanation": "脚手架可分段搭设分段使用，应由工程项目技术负责人组织相关人员进行验收，符合专项施工方案后方可使用。"},
  {"id": 397, "type": "single", "question": "对于承插型轮扣式模板支架，可调托撑上的主楞梁应居中，其间隙每边不大于 （　　） mm。", "options": ["1", "2", "3", "4"], "answer": [1], "explanation": "可调托撑上的主楞梁应居中,其间隙每边不大于2mm。"},
  {"id": 398, "type": "single", "question": "门式钢管脚手架的门架高度不宜小于 （　　） 。", "options": ["1600mm", "1700mm", "1800mm", "1900mm"], "answer": [1], "explanation": "门架高度不宜小于1700mm,且不宜大于2000mm。"},
  {"id": 399, "type": "single", "question": "门式脚手架应设置剪刀撑，剪刀撑斜杆的倾角应为 （　　） 。", "options": ["20°-30°", "30°-40°", "45°-60°", "65°-70°"], "answer": [2], "explanation": "门式脚手架剪刀撑斜杆的倾角应为45°-60°之间。"},
  {"id": 400, "type": "single", "question": "当架上总荷载 （　　） 3kN/㎡时，门式支撑架可通过门架橫杆承担和传递荷载。", "options": [">", "≥", "<", "≤"], "answer": [3], "explanation": "《建筑施工门式钢管脚手架安全技术标准》6.1.13当架上总荷载小于或等于3kN/m²时，门式支撑架可通过门架横杆承担和传递荷载。"},
  {"id": 401, "type": "single", "question": "门式脚手架采用落地、密目式安全立网全封闭，其最大的搭设高度不可能超过 （　　） m。", "options": ["24", "30", "45", "60"], "answer": [3], "explanation": "钢管脚手架中扣件式单排架不宜超过24m，扣件式双排架不宜超过50m。门式架不宜超过60m。"},
  {"id": 402, "type": "single", "question": "采用悬挑、密目式安全网全封闭搭设的门式脚手架，搭设高度>60米，则每根连墙件覆盖面积≤ （　　） ㎡。", "options": ["15", "22", "33", "40"], "answer": [1], "explanation": "【依据】《建筑施工高处作业安全技术规范》JGJ 80-2016\n【解析】正确答案是C。题干对应的是建筑施工高处作业防护。 A项“15”错误，题干对应的控制数值不是15，正确值应为33。 B项“22”错误，题干对应的控制数值不是22，正确值应为33。 C项“33”正确，规范要求的控制数值或时限就是33。 D项“40”错误，题干对应的控制数值不是40，正确值应为33。"},
  {"id": 403, "type": "single", "question": "门式脚手架通道口宽度为一个门架跨距时，在通道口上方的内外侧应设置水平加固杆，水平加固杆应延伸至通道口两侧各 （　　） 个门架跨距。", "options": ["0.5", "1", "2", "3"], "answer": [1], "explanation": "当通道口宽度为一个门架跨距时，在通道口上方的内外侧应设置水平加固杆，水平加固杆应延伸至通道口两侧各一个门架跨距，并在两个上角内外侧应加设斜撑杆（见图5—11a)。"},
  {"id": 404, "type": "single", "question": "门式满堂作业架的搭设高度应 （　　） 。", "options": ["≤36m", "≤30m", "≥30m", "≥36m"], "answer": [0], "explanation": "《建筑施工门式钢管脚手架安全技术标准》"},
  {"id": 405, "type": "single", "question": "混凝土梁板类结构的模板满堂支撑架，应按梁板结构分别设计，其中梁下横向水平加固杆应伸入板支撑架内不少于 （　　） 根门架立杆，并应与板下门架立杆扣紧。", "options": ["1", "2", "3", "4"], "answer": [1], "explanation": "梁下横向水平加固杆应伸入板支架内不少于2根门架立杆,并应与板下门架立杆扣紧。"},
  {"id": 406, "type": "single", "question": "移动门式作业架的高宽比大于2时，在移动就位后使用前应设 （　　） 。", "options": ["水平加固杆", "横向扫地杆", "连墙件", "抛撑"], "answer": [3], "explanation": "《建筑施工门式钢管脚手架安全技术标准》第6.5.5当架体的高宽比大于2时,在移动就位后使用前应设置拋撑。"},
  {"id": 407, "type": "single", "question": "碗扣式脚手架立杆碗扣节点间距，对于Q235级材质钢管立杆宜按 （　　） m模数设置。", "options": ["0.3", "0.5", "0.6", "0.8"], "answer": [2], "explanation": "碗扣式脚手架立杆碗扣节点间距,对Q235级材质钢管立杆宜按0.6m模数设置;对Q345级材质钢管立杆宜按0.5m模数设置。"},
  {"id": 408, "type": "single", "question": "作业层脚手板下应采用安全平网兜底，以下每隔 （　　） m应采用安全平网封闭。", "options": ["3", "5", "8", "10"], "answer": [3], "explanation": "作业层脚手板下应采用安全平网兜底,以下每隔 10 米应采用安全平网封闭。"},
  {"id": 409, "type": "single", "question": "当碗扣式钢管双排脚手架拐角为非直角时，可采用 （　　） 组架。", "options": ["竖向斜撑杆", "水平杆", "钢管扣件", "立杆"], "answer": [2], "explanation": "当双排脚手架拐角为非直角时,可采用钢管扣件组架。"},
  {"id": 410, "type": "single", "question": "碗扣式钢管双排脚手架内立杆与建筑物距离不宜大于 （　　）  mm。", "options": ["250", "200", "150", "100"], "answer": [2], "explanation": "建筑施工碗扣式钢管脚手架安全技术规范(JGJ166-2008)规定,碗扣式脚手架内立杆与建筑物距离应小于或等于150mm。"},
  {"id": 411, "type": "single", "question": "碗扣式钢管模板支撑架应设置水平斜撑杆，水平斜撑杆应在相邻立杆间呈 （　　） 连续设置。", "options": ["八字形", "条带状", "之字形", "V字形"], "answer": [1], "explanation": "水平斜撑杆应在相邻立杆间呈条带状连续设置。"},
  {"id": 412, "type": "single", "question": "碗扣式钢管模板支撑架应按 （　　） 的顺序搭设形成基本架体单元。", "options": ["先水平杆、后立杆、再斜杆", "先立杆、后斜杆、再水平杆", "先立杆、后水平杆、再斜杆", "先水平杆、后斜杆、再立杆"], "answer": [2], "explanation": "顺序搭设安装搭设盘扣式支撑架时,应先安装立杆,再安装水平杆,最后安装斜杆,形成了基本的架体单元后,再以此扩展搭设成整体的支架体系。"},
  {"id": 413, "type": "single", "question": "附着式升降作业安全防护平台结构的 （　　） ，其垂直于建筑结构外立面，并与导轨连接，将平台所承受的水平和竖向荷载传递给建筑结构。", "options": ["水平支承结构", "竖向主框架", "提升机构", "架体防护结构"], "answer": [1], "explanation": "竖向主框架垂直于建筑结构外立面，并与导轨连接，主要承受和传递平台的竖向和水平荷载，由钢管或封钢制做，分为平面桁架，空间桁架，刚架三种结构形式。"},
  {"id": 414, "type": "single", "question": "附着式防护平台的导轨，当采用型钢时，导轨可兼做主框架 （　　） 。", "options": ["内立杆", "拉结杆", "支撑杆", "加固杆"], "answer": [0], "explanation": "当采用型钢制作时,导轨可兼做主框架内立杆;"},
  {"id": 415, "type": "single", "question": "以下不属于格构式防坠装置的类别是 （　　） 。", "options": ["摆块式", "转轮式", "摩擦式", "顶撑式"], "answer": [2], "explanation": "防坠装置分为格构式和摩擦式,格构式分为摆块式、转轮式和顶撑式。"},
  {"id": 416, "type": "single", "question": "附着式防护平台升降时，水平高差同步控制系统在相邻两机位高差达到 （　　） mm时，应能自动停机。", "options": ["10", "20", "30", "40"], "answer": [2], "explanation": "水平高差同步控制系统应具有下列功能：\n1）当水平支承桁架两端高差达到30mm时，应能自动停机；\n2）应具有显示各提升点的实际升高和超高的数据，并应有记忆和储存的功能；\n3）不得采用附加重量的措施控制同步。"},
  {"id": 417, "type": "single", "question": "当附着式防护平台停用超过 （　　） 个月时，应提前采取加固措施。", "options": ["6", "2", "1", "3"], "answer": [3], "explanation": "当附着式防护平台停用超过3个月时,应提前采取加固措施。"},
  {"id": 418, "type": "single", "question": "超高层钢结构工程安全要点中，对当天作业内容、部位、 （　　） 等进行交代。", "options": ["空间", "工艺", "顺序", "吊点"], "answer": [2], "explanation": "其他零星类钢结构工程安全要点中，对当天作业内容、部位、顺序等进行交代。"},
  {"id": 419, "type": "single", "question": "超高层钢结构工程安全要点中，对当天作业内容、部位、顺序等进行交代，包括 （　　） 、塔吊位置、土建施工部位、核心筒及外框施工高度等。", "options": ["作业面面积", "作业面层数", "作业面标高", "作业面宽度"], "answer": [1], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】正确答案是B。题干对应的是建筑施工安全管理。 A项“作业面面积”错误，它说的是“作业面面积”，并非题干要找的“作业面层数”。 B项“作业面层数”正确，它与题干所述“超高层钢结构工程安全要点中，对当天作业内容、”相对应。 C项“作业面标高”错误，它说的是“作业面标高”，并非题干要找的“作业面层数”。 D项“作业面宽度”错误，它说的是“作业面宽度”，并非题干要找的“作业面层数”。"},
  {"id": 420, "type": "single", "question": "超高层钢结构工程安全要点中，对当天作业内容、部位、顺序等进行交代，包括作业面层数、塔吊位置、土建施工部位、 （　　） 等。", "options": ["结构施工高度", "核心筒及外框施工高度", "主体施工高度", "柱子施工高度"], "answer": [1], "explanation": "超高层钢结构工程安全要点中，对当天作业内容、部位、顺序等进行交代，包括作业面层数、塔吊位置、土建施工部位、核心筒及外框施工高度等。"},
  {"id": 421, "type": "single", "question": "大跨度及厂房钢结构工程安全要点中，对当天作业的技术措施和 （　　） 进行交代，包括防高空坠落措施、防火星坠落等。", "options": ["组织措施", "安全措施", "经济措施", "管理措施"], "answer": [1], "explanation": "【依据】《建设工程施工现场消防安全技术规范》GB 50720-2011 / 《中华人民共和国消防法》\n【解析】正确答案是B。题干对应的是施工现场消防安全。 A项“组织措施”错误，它说的是“组织措施”，并非题干要找的“安全措施”。 B项“安全措施”正确，它与题干所述“大跨度及厂房钢结构工程安全要点中，对当天作业”相对应。 C项“经济措施”错误，它说的是“经济措施”，并非题干要找的“安全措施”。 D项“管理措施”错误，它说的是“管理措施”，并非题干要找的“安全措施”。"},
  {"id": 422, "type": "single", "question": "其他零星类钢结构工程安全要点中，对当天 （　　） 、部位、顺序等进行交代。", "options": ["作业内容", "作业点动火", "作业高度", "作业宽度"], "answer": [0], "explanation": "【依据】《建设工程施工现场消防安全技术规范》GB 50720-2011 / 《中华人民共和国消防法》\n【解析】正确答案是A。题干对应的是施工现场消防安全。 A项“作业内容”正确，它与题干所述“其他零星类钢结构工程安全要点中，对当天、部位”相对应。 B项“作业点动火”错误，它说的是“作业点动火”，并非题干要找的“作业内容”。 C项“作业高度”错误，它说的是“作业高度”，并非题干要找的“作业内容”。 D项“作业宽度”错误，它说的是“作业宽度”，并非题干要找的“作业内容”。"},
  {"id": 423, "type": "single", "question": "钢结构安装的安全生产目标是保证作业人员的 （　　） 安全，保证施工机械和设备能够安全运行。还保证不发生火灾事故，以及涂装作业人员的人身安全。", "options": ["财产", "人身", "施工", "登高"], "answer": [1], "explanation": "【依据】《建设工程施工现场消防安全技术规范》GB 50720-2011 / 《中华人民共和国消防法》\n【解析】正确答案是B。题干对应的是施工现场消防安全。 A项“财产”错误，它说的是“财产”，并非题干要找的“人身”。 B项“人身”正确，它与题干所述“钢结构安装的安全生产目标是保证作业人员的安全”相对应。 C项“施工”错误，它说的是“施工”，并非题干要找的“人身”。 D项“登高”错误，它说的是“登高”，并非题干要找的“人身”。"},
  {"id": 424, "type": "single", "question": "钢柱吊装松钩时，施工人员宜通过 （　　） 登高，并应采用防坠器进行人身保护。", "options": ["安全绳梯", "钢挂梯", "木梯", "升降机"], "answer": [1], "explanation": "【依据】《建筑施工起重吊装工程安全技术规范》JGJ 276-2012\n【解析】正确答案是B。题干对应的是起重吊装作业安全。 A项“安全绳梯”错误，它说的是“安全绳梯”，并非题干要找的“钢挂梯”。 B项“钢挂梯”正确，它与题干所述“钢柱吊装松钩时，施工人员宜通过登高，并应采用”相对应。 C项“木梯”错误，它说的是“木梯”，并非题干要找的“钢挂梯”。 D项“升降机”错误，它说的是“升降机”，并非题干要找的“钢挂梯”。"},
  {"id": 425, "type": "single", "question": "钢结构安装工程中的安全爬梯的承载必须经过 （　　） 计算。", "options": ["结构", "安全", "受力", "内力"], "answer": [1], "explanation": "安全爬梯的承载必须经过安全计算。"},
  {"id": 426, "type": "single", "question": "钢结构安装施工中，边长或直径为 （　　） cm的洞口应采用刚性盖板固定防护。", "options": ["35", "45", "50", "60"], "answer": [0], "explanation": "边长或直径为20cm~40cm的洞口应采用刚性盖板固定防护。"},
  {"id": 427, "type": "single", "question": "钢结构安装施工中，边长或直径为40-150cm的洞口应架设钢管脚手架、 （　　） 等。", "options": ["满铺钢丝网片", "满铺脚手板", "满铺竹片筏", "满铺塑料板"], "answer": [1], "explanation": "边长或直径为40cm~150cm的洞口应架设钢管脚手架、满铺脚手板等"},
  {"id": 428, "type": "single", "question": "钢结构安装施工中，楼层周边钢梁吊装完成后，应在每层临边设置防护栏，且防护栏高度不应低于 （　　） m。", "options": ["1.2", "1.25", "1.3", "1.35"], "answer": [0], "explanation": "【依据】《建筑施工高处作业安全技术规范》JGJ 80-2016\n【解析】正确答案是A。题干对应的是建筑施工高处作业防护。 A项“1.2”正确，它与题干所述“钢结构安装施工中，楼层周边钢梁吊装完成后，应”相对应。 B项“1.25”错误，它说的是“1.25”，并非题干要找的“1.2”。 C项“1.3”错误，它说的是“1.3”，并非题干要找的“1.2”。 D项“1.35”错误，它说的是“1.35”，并非题干要找的“1.2”。"},
  {"id": 429, "type": "single", "question": "钢结构安装施工中，楼层周边钢梁吊装完成后，应在 （　　） 临边设置防护栏，且防护栏高度不应低于1.2m。", "options": ["底层", "每层", "单层", "双层"], "answer": [1], "explanation": "楼层周边钢梁吊装完成后,应在每层临边设置防护栏,且防护栏高度不应低于1.2m。"},
  {"id": 430, "type": "single", "question": "高空作业使用的小型手持工具和小型零部件应采取 （　　） 措施。", "options": ["防止坠落", "防火", "防滑", "防盗"], "answer": [0], "explanation": "【依据】《建设工程施工现场消防安全技术规范》GB 50720-2011 / 《中华人民共和国消防法》\n【解析】正确答案是A。题干对应的是施工现场消防安全。 A项“防止坠落”正确，它与题干所述“高空作业使用的小型手持工具和小型零部件应采取”相对应。 B项“防火”错误，它说的是“防火”，并非题干要找的“防止坠落”。 C项“防滑”错误，它说的是“防滑”，并非题干要找的“防止坠落”。 D项“防盗”错误，它说的是“防盗”，并非题干要找的“防止坠落”。"},
  {"id": 431, "type": "single", "question": "高空作业使用的小型 （　　） 和小型零部件应采取防止坠落措施。", "options": ["手持工具", "设备", "机械", "工具"], "answer": [0], "explanation": "高空作业使用的小型手持工具和小型零部件应采取防止坠落措施。"},
  {"id": 432, "type": "single", "question": "密闭空间涂装作业应使用 （　　） ，安装防爆报警装置；作业完成后油漆在空气中的挥发物消散前，严禁电焊修补作业。", "options": ["防爆灯具", "防火灯具", "防水灯具", "报警灯具"], "answer": [0], "explanation": "【依据】《建设工程施工现场消防安全技术规范》GB 50720-2011 / 《中华人民共和国消防法》\n【解析】正确答案是A。题干对应的是施工现场消防安全。 A项“防爆灯具”正确，它与题干所述“密闭空间涂装作业应使用，安装防爆报警装置；作”相对应。 B项“防火灯具”错误，它说的是“防火灯具”，并非题干要找的“防爆灯具”。 C项“防水灯具”错误，它说的是“防水灯具”，并非题干要找的“防爆灯具”。 D项“报警灯具”错误，它说的是“报警灯具”，并非题干要找的“防爆灯具”。"},
  {"id": 433, "type": "single", "question": "现场施工人员均应带安全帽，高空作业人员应佩带安全带，并要 （　　） ，并系在安全可靠的地方，现场作业人员穿好防滑鞋。", "options": ["高挂低用", "低挂高用", "挂栏杆", "挂中间"], "answer": [0], "explanation": "现场施工人员均应带安全帽,高空作业人员应佩带安全带,并要高挂低用,并系在安全可靠的地方,现场作业人员穿好防滑鞋。"},
  {"id": 434, "type": "single", "question": "钢结构安装工程施工时，高空操作必须配戴安全带，穿 （　　） ,并作好安全措施。", "options": ["皮鞋", "绝缘软底鞋", "运动鞋", "工装鞋"], "answer": [1], "explanation": "《建筑施工高处作业安全技术规范》（JGJ 80）要求高空作业人员 “穿防滑鞋”。\n钢结构施工涉及电气焊作业时，《施工现场临时用电安全技术规范》（JGJ 46）强调 “绝缘防护”。\n绝缘软底鞋是同时满足防滑、绝缘双重要求的典型防护装备，常见于带电作业或金属结构施工场景。"},
  {"id": 435, "type": "single", "question": "钢结构安装工程施工时，高空作业人员所携带各种工具、螺栓等应在 （　　） 中放好，在高空传递物品时，应挂好安全绳，不得随便抛掷，以防伤人。", "options": ["专用工具袋", "专用工具箱", "自己口袋", "工具包"], "answer": [0], "explanation": "高空作业人员所携带各种工具、螺栓等应在专用工具袋中放好，在高空传递物品时，应挂好安全绳，不得随便抛掷，以防伤人。"},
  {"id": 436, "type": "single", "question": "钢结构安装工程施工时，对于钢梁的吊装，由于钢梁为不规则工字钢，绑扎点容易滑动，故特制一吊装悬挂点用的专用钢板 （　　） 厚钢连接板，并用螺栓与钢梁上弦紧固。", "options": ["δ=6mm", "δ=8mm", "δ=10mm", "δ=14mm"], "answer": [3], "explanation": "对于钢梁的吊装，由于钢梁为不规则工字钢，绑扎点容易滑动，故特制一吊装悬挂点用的专用钢板δ=14mm厚钢连接板，并用螺栓与钢梁上弦紧固。"},
  {"id": 437, "type": "single", "question": "钢结构安装工程施工时，构件吊装就位后，应经初校和临时固定或连接可靠后方可 （　　） ，稳定后方可拆除固定工具或其他稳定装置。", "options": ["松钩", "卸钩", "脱钩", "卸索"], "answer": [1], "explanation": "构件吊装就位后，应经初校和临时固定或连接可靠后方可以卸钩，最后稳定后方可拆除固定工具或其他稳定装置。"},
  {"id": 438, "type": "single", "question": "钢结构安装工程施工时，长袖比较大的构件，未经就位临时固定组成 （　　） 前，应设溜绳加地锚固定。", "options": ["结构稳定体系", "一稳定单元体系", "排架体系", "空间体系"], "answer": [1], "explanation": "钢结构安装工程施工时，长袖比较大的构件，未经就位临时固定组成一稳定单元体系前，应设溜绳加地锚固定。"},
  {"id": 439, "type": "single", "question": "钢结构安装工程施工时，对于现场手持电动工具，必须有 （　　） ，其操作者必须戴绝缘手套、穿绝缘鞋。", "options": ["单独开关箱", "漏电保护器", "接地", "接零"], "answer": [1], "explanation": "各种用电设备必须有良好的接地、接零,对于现场用手持电动工具,必须有漏电保护器,其操作者必须戴绝缘手套,穿绝缘鞋."},
  {"id": 440, "type": "single", "question": "钢结构安装工程施工时，现场有乙炔、氧气瓶搬运要有防震措施，绝对禁止向地上抛掷，猛摔，同时避免在阳光下爆晒，并与火源保持 （　　） 米以上距离。", "options": ["1", "5", "10", "15"], "answer": [2], "explanation": "一、钢结构工程施工中的安全防护要点\n(六)对现场防火防爆问题的预防\n防火防爆措施要配备灭火器，并由专人监护。高空焊割必须设接火花斗，接火花斗内使用阻燃材料接熔珠，防止熔珠再次溅出。\n电、气焊火花严禁落到氧气瓶和乙炔瓶上。不能用油手接触氧气瓶，要防止起重机或其他机械油落到氧气瓶上。\n现场有乙炔、氧气瓶搬运要有防震措施，绝对禁止向地上抛掷，猛摔，同时避免在阳光下爆晒，并与火源保持10米以上距离。\n施工时还应注意防火，乙炔、氧气按规定摆放，保证安全距离，现场易燃物品不得随意堆放、抛弃，应集中堆放于安全位置。\n现场备好消防器材、工具，并有专门消防保卫人员。"},
  {"id": 441, "type": "single", "question": "索膜吊装时注意膜面的应力分布均匀，必要时可在膜上焊接连续的 （　　） ，用两片钢板夹紧搭扣来吊装。", "options": ["安装搭扣", "安装吊环", "吊装搭扣", "吊装吊环"], "answer": [2], "explanation": "吊装时要注意膜面的应力分布均匀,必要时可在膜上焊接连续的\"吊装搭扣\",用两片钢板夹紧搭扣来吊装"},
  {"id": 442, "type": "single", "question": "大面积膜面的吊装应选择晴朗无风的天气进行，风力大于3级或气温低于 （　　） ℃时不宜进行安装。", "options": ["3", "4", "5", "6"], "answer": [1], "explanation": "大面积膜面的吊装应选择晴朗无风的天气进行，风力大于三级或气温低于 4°C 时不宜进行安装。"},
  {"id": 443, "type": "single", "question": "点支撑幕墙是由玻璃面板、 （　　） 和支撑结构构成的建筑幕墙。", "options": ["立杆", "点支撑装置", "横杆", "龙骨"], "answer": [1], "explanation": "点支撑:点支撑玻璃幕墙由玻璃面板、点支承装置和支承结构构成的建筑幕墙。"},
  {"id": 444, "type": "single", "question": "幕墙工程项目部成立以项目经理为 （　　） 的安全生产领导小组，确定安全目标，落实安全生产责任制，保证安全措施费提取和合理使用。", "options": ["责任人", "第一责任人", "负责人", "组长"], "answer": [1], "explanation": "项目部成立以项目经理为第一责任人的安全生产领导小组,确定安全目标,落实安全生 产责任制,保证安全技术措施费提取和合理使用。"},
  {"id": 445, "type": "single", "question": "幕墙安装工程属于危险性较大的分部分项工程，应编制专项施工方案，对于超过一定规模的应由施工单位组织 （　　） 论证、审查。", "options": ["监理", "设计", "业主", "专家"], "answer": [3], "explanation": "幕墙安装工程属于危险性较大的分部分项工程，应编制专项施工方案，对于超过一定规模的应由施工单位组织专家论证、审查。"},
  {"id": 446, "type": "single", "question": "幕墙安装工程，项目部根据项目特点和现场环境编制《安全事故应急救援及施工现场安全急救方案》，并组织演练，一旦发生事故按已审批的 （　　） 开展救援工作，防止事故扩大，减少人员伤亡。", "options": ["专项施工方案", "救援方案", "应急处置方案", "施工现场安全急救方案"], "answer": [1], "explanation": "安全事故应急救援及施工现场安全急救处理练,一旦发生事故按已审批的救援方案开展求援工作,防止事故扩大,减少人员伤亡。"},
  {"id": 447, "type": "single", "question": "幕墙工程施工作业准备阶段，应建立由项目经理和技术负责人、质检员、安全员、施工员等参与组成的 （　　） ,领导和组织施工质量、生产、进度的管理。", "options": ["项目领导小组", "项目管理小组", "生产管理小组", "质量管理小组"], "answer": [1], "explanation": "幕墙工程施工作业准备阶段，应建立由项目经理和技术负责人、质检员、安全员、施工员等参与组成的项目管理小组，领导和组织施工质量、生产、进度的管理。"},
  {"id": 448, "type": "single", "question": "玻璃幕墙工程施工工艺流程正确的是 （　　） 。", "options": ["安装立柱→放样定位→安装横梁→安装玻璃→打胶→清理", "放样定位→安装横梁→安装立柱→安装玻璃→打胶→清理", "放样定位→安装立柱→安装横梁→安装玻璃→打胶→清理", "放样定位→安装立柱→安装横梁→打胶→安装玻璃→清理"], "answer": [2], "explanation": "工艺流程：放样定位→安装立柱→安装横梁→安装玻璃→打胶→清理"},
  {"id": 449, "type": "single", "question": "玻璃幕墙施工中立柱在加长时，应用配套的专用芯管连接，上下柱之间应留有空隙，空隙宽度不宜小于 （　　） mm，其接头应为活动接头，从而满足立柱在热胀冷缩时发生的变形需求。", "options": ["5", "15", "10", "8"], "answer": [2], "explanation": "加长立柱连接时须用配套的专用芯管,上下柱之间应留有空隙,空隙宽度不宜小于10mm,其接头应为活动接头,以适应立柱在热胀冷缩时发生的变形。"},
  {"id": 450, "type": "single", "question": "玻璃幕墙施工中，同层横梁的标高偏差，当幕墙宽度大于35m时，不应大于 （　　） mm，同一层横梁在安装时应由上而下进行。", "options": ["4", "5", "6", "7"], "answer": [3], "explanation": "对于一幅玻璃幕墙的宽度小于或等于35m时,同层横梁的标高允许偏差,不应大于5mm;当一幅幕墙宽度大于35m时,不应大于7mm。"},
  {"id": 451, "type": "single", "question": "明框幕墙的玻璃安装应根据幕墙的具体种类来定，在横梁上设置定位垫块，垫块的搁置点离玻璃垂直边缘的距离宜为玻璃宽度的1/4，且不宜小于150mm，垫块的宽度应不大于所支撑玻璃的厚度，长度不宜小于 （　　） mm，并符合有关要求。", "options": ["15", "20", "25", "30"], "answer": [2], "explanation": "在横梁上设置定位垫块,垫块的搁置点离玻璃垂直边缘的距离宜为玻璃宽度的1/4,且不宜小于150mm,垫块的宽度应不大于所支撑玻璃的厚度,长度不宜小于25mm,并符合有关要求。"},
  {"id": 452, "type": "single", "question": "玻璃幕墙的玻璃安装完后，应用 （　　） 清洁剂和水对有污染的玻璃和铝型材进行清洗。", "options": ["酸性", "中性", "碱性", "强碱性"], "answer": [1], "explanation": "清理:玻璃幕墙的玻璃安装完后,应用中性清洁剂和水对有污染的玻璃和铝型材进行清洗。"},
  {"id": 453, "type": "single", "question": "石材幕墙施工预埋件安装时如有预埋件位置超差而无法使用或漏放时，应根据实际情况提出选用膨胀螺栓的方案，并必须报 （　　） 审核批准，且应在现场做拉拔试验，做好记录。", "options": ["设计单位", "建设单位", "总承包单位", "监理单位"], "answer": [0], "explanation": "如有预埋件位置超差而无法使用或漏放时，应根据实际情况提出选用膨胀螺栓的方案，并必须报设计单位审核批准，且应在现场做拉拔试验，做好记录。"},
  {"id": 454, "type": "single", "question": "石材幕墙金属骨架安装，如有焊接时，应对下方和邻近的已完工装饰面进行成品保护。焊接时要采用 （　　） ，以减少因焊接产生的变形。", "options": ["跳焊", "交替焊", "对称焊", "分段退焊"], "answer": [2], "explanation": "焊接时要采用对称焊,以减少因焊接产生的变形。"},
  {"id": 455, "type": "single", "question": "将运至工地的石材饰面板按编号分类，检查 （　　） 是否准确和有无破损、缺棱、掉角。", "options": ["厚度", "长度", "尺寸", "角度"], "answer": [2], "explanation": "将运至工地的石材饰面板按编号分类,检查尺寸是否准确和有无破损、缺楞、掉角,按施工要求分层次将 石材饰面板运至施工面附近,并注意摆放可靠。"},
  {"id": 456, "type": "single", "question": "石材幕墙的工石材饰面板安装时，宜先完成窗洞口 （　　） 的石材板镶边，以免安装发生困难。", "options": ["底边", "四周", "左边", "右边"], "answer": [1], "explanation": "安装时,宜先完成窗洞口四周的石材板镶边,以免安装发生困难。"},
  {"id": 457, "type": "single", "question": "嵌胶封缝石材板间的胶缝是石板幕墙的第一道防水措施，同时也使石板幕墙形成一个 （　　） 。", "options": ["板面", "整体", "整面", "板体"], "answer": [1], "explanation": "嵌胶封缝石材板间的胶缝是石板幕墙的第一道防水措施，同时也使石板幕墙形成一个整体。"},
  {"id": 458, "type": "single", "question": "石材幕墙嵌胶封缝施工中要注意不能有漏胶污染墙面，如墙面上沾有胶液应立即擦去，并用 （　　） 及时擦净余胶。", "options": ["清洁剂", "草酸", "清水", "玻璃水"], "answer": [0], "explanation": "施工中要注意不能有漏胶污染墙面,如墙面上沾有胶液应立即擦去,并用清洁剂及时擦净余胶。"},
  {"id": 459, "type": "single", "question": "金属幕墙嵌缝打胶时，硅酮结构密封胶应打注饱满，并应在温度15~30℃,相对湿度 （　　） 以上的洁净室内进行。", "options": ["20%", "30%", "40%", "50%"], "answer": [3], "explanation": "硅酮结构密封胶应打注饱满，并应在温度15—30℃、相对湿度50％以上、洁净的室内进行；不得在现场墙上打注。"},
  {"id": 460, "type": "single", "question": "幕墙玻璃的反射比不应大于 （　　） 。", "options": ["30%", "20%", "10%", "50%"], "answer": [0], "explanation": "玻璃幕墙应采用反射比不大于 0.30 的幕墙玻璃,对有采光功能要求的玻璃幕墙,其采光折减系数不宜低于 0.20。"},
  {"id": 461, "type": "single", "question": "人造板材幕墙专项要求中对纤维水泥板连接的规定，穿透连接的基板厚度不应小于 （　　） mm，背栓连接的基板厚度不应小于12mm，通长挂件连接的基板厚度不应小于15mm 。", "options": ["5", "6", "7", "8"], "answer": [3], "explanation": "纤维水泥板应采用符合现行标准规定厚度不应小于 8mm。"},
  {"id": 462, "type": "single", "question": "人造板材幕墙专项要求，木纤维板宜采用末端型式为刮削式（SC）的螺钉连接或背栓连接，也可采用 （　　） 连接。", "options": ["正向", "横向", "穿透", "异向"], "answer": [2], "explanation": "木纤维板宜采用末端形式为刮削式(SC)的螺钉连接或背栓连接,也可采用穿透连接。"},
  {"id": 463, "type": "single", "question": "人造板材幕墙专项要求，面板挂件与支承构件之间应采用不锈钢螺栓或不锈钢自钻自攻螺钉连接。螺栓的螺纹规格不应小于M6，自钻自攻螺钉的螺纹规格不应小于 （　　） ,并采取放松脱和滑移措施。", "options": ["ST5.0", "ST5.5", "ST6.0", "ST6.5"], "answer": [1], "explanation": "螺栓的螺纹规格不应小于M6,自钻自攻螺钉的螺纹规格不应小于ST5.5，并采取防松脱和滑移措施。"},
  {"id": 464, "type": "single", "question": "人造板材幕墙专项要求，瓷板短挂件的长度不宜小于 （　　）  mm。", "options": ["45", "50", "55", "60"], "answer": [1], "explanation": "瓷板短挂件用不锈钢材料和铝合金型材的截面厚度均不宜小于2.0mm；通长挂件用不锈钢材料和铝合金型材的截面厚度均不宜小于1.5mm。短挂件的长度不宜小于50mm。"},
  {"id": 465, "type": "single", "question": "人造板材幕墙专项要求，微晶玻璃板通长挂件用不锈钢材料的截面厚度不宜小于 （　　） mm。", "options": ["1.5", "2.0", "2.5", "3.0"], "answer": [1], "explanation": "微晶玻璃板短挂件用不锈钢材料的截面厚度不宜小于3．0mm，铝合金型材的截面厚度不宜小于4．0mm；通长挂件用不锈钢材料的截面厚度不宜小于【2．0mm】，铝合金型材的截面厚度不宜小于3．0mm。短挂件的长度不宜小于40mm。"},
  {"id": 466, "type": "single", "question": "人造板材幕墙专项要求，陶板短挂件用铝合金型材的截面厚度不宜小于 （　　） mm。", "options": ["1.0", "2.0", "2.5", "3.0"], "answer": [1], "explanation": "陶板短挂件用不锈钢材料的截面厚度不宜小于1．5mm，铝合金型材的截面厚度不宜小于2．0mm；通长挂件用铝合金型材的截面厚度不宜小于1．5mm。定位弹簧片的截面厚度不宜小于0．5mm。"},
  {"id": 467, "type": "single", "question": "人造板材幕墙瓷板挂件插入槽口的深度不宜小于8mm，也不宜大于12mm；微晶玻璃板、纤维水泥板挂件插入槽口的深度不宜小于10mm，也不宜大于 （　　） mm。", "options": ["10", "20", "15", "18"], "answer": [2], "explanation": "瓷板挂件插入槽口的深度不宜小于8mm,也不宜大于12mm;微晶玻璃板、纤维水泥板挂件插入槽口的深度不宜小于10mm,也不宜大于15mm;"},
  {"id": 468, "type": "single", "question": "人造板材幕墙面板设计时， （　　） 正面平整时，其面板截面的计算厚度，按公称厚度（总厚度）减去挂槽和挂钩宽度采用；正面有装饰条纹时，还应减去装饰条纹的凸起高度或凹下深度。", "options": ["瓷板", "微晶玻璃板", "实心陶板", "纤维水泥板"], "answer": [2], "explanation": "实心陶板：正面平整时，按公称厚度(总厚度)减去挂槽和挂钩宽度采用；正面有装饰条纹时，还应减去装饰条纹的凸起高度或凹下深度；"},
  {"id": 469, "type": "single", "question": "拆除工程施工中，对生产、使用、储存危险品的拟拆除物，拆除施工前应先进行 （　　） ，合格后方可进行施工。", "options": ["加固", "保护", "环境评估", "残留物的检测和处理"], "answer": [3], "explanation": "对生产、使用、储存危险品的拟拆除物,拆除施工前应先进行残留物的检测和处理,合格后方可进行施工。"},
  {"id": 470, "type": "single", "question": "当拟拆除物与毗邻建筑及道路的 （　　） 不能满足要求时，必须采取相应的安全防护措施。", "options": ["直线距离", "垂直距离", "安全距离", "施工距离"], "answer": [2], "explanation": "当拟拆除物与毗邻建筑及道路的安全距离不能满足要求时,必须采取相应的安全防护措施。"},
  {"id": 471, "type": "single", "question": "拆除作业中必须由专人负责监测被拆除建筑的结构状态，并应做好记录。当发现有不稳定状态的趋势时，必须 （　　） 。", "options": ["组织抢修", "加强监测", "停止作业", "加紧作业"], "answer": [2], "explanation": "拆除作业中必须由专人负责监测被拆除建筑的结构状态，并应做好记录。当发现有不稳定状态的趋势时，必须停止作业。"},
  {"id": 472, "type": "single", "question": "当拆除屋架等大型构件时，必须采用 （　　） 将构件锁定牢固，待起重机吊稳后进行切割作业。", "options": ["吊索具", "铁扁担", "钢丝绳", "吊钩"], "answer": [0], "explanation": "拆除屋架等大型构件时,必须采用吊索具将构件锁定牢固,待起重机吊稳后,方可进行切割作业。"},
  {"id": 473, "type": "single", "question": "机械拆除作业开始前，应对地下的各类管线，施工单位应在 （　　） 设置明显标识。", "options": ["地面下", "地面上", "管线面", "管线端"], "answer": [1], "explanation": "对地下的各类管线,施工单位应在地面上设置明显标识。对水、电、气的检查井、污水井应采取相应的保护措施。"},
  {"id": 474, "type": "single", "question": "高处作业是指在坠落高度基准面 （　　） 有可能坠落的高处进行的作业。", "options": ["2m", "2m或2m以上", "5m", "5m以上（含5m）"], "answer": [1], "explanation": "高处作业是指在距坠落高度基准面高处作业指凡在坠落高度基准面 2m 以上(含 2m)有可能坠落的高处进行的作业。"},
  {"id": 475, "type": "single", "question": "高处作业高度是指作业区各作业位置至相应坠落高度基准面的垂直距离中的 （　　） 。", "options": ["最小值", "平均值", "最大值", "任意值"], "answer": [2], "explanation": "作业区各作业位置至相应坠落高度基准面之间的垂直距离中的最大值，称为该作业区的高处作业高度。"},
  {"id": 476, "type": "single", "question": "高处作业高度分为 （　　） 个区段。", "options": ["三", "四", "五", "六"], "answer": [1], "explanation": "高处作业高度分为2m至5m、5m以上至15m、15m以上至30m、30m以上4个区段。"},
  {"id": 477, "type": "single", "question": "高处作业活动范围与220v带电体的距离应小于 （　　） 。", "options": ["1.7m", "2.5m", "4m", "5m"], "answer": [2], "explanation": "【依据】《建筑施工高处作业安全技术规范》JGJ 80-2016\n【解析】正确答案是A。题干对应的是建筑施工高处作业防护。 A项“1.7m”正确，它与题干所述“高处作业活动范围与220v带电体的距离应小于”相对应。 B项“2.5m”错误，它说的是“2.5m”，并非题干要找的“1.7m”。 C项“4m”错误，题干对应的控制数值不是4m，正确值应为1.7m。 D项“5m”错误，题干对应的控制数值不是5m，正确值应为1.7m。"},
  {"id": 478, "type": "single", "question": "Ⅰ级高处作业的高处作业高度为 （　　） 。", "options": ["2m至5m", "2m至6m", "3m至5m", "3m至8m"], "answer": [0], "explanation": "作业高度在2米至5米时,称为一级高处作业。"},
  {"id": 479, "type": "single", "question": "无客观危险因素的高处作业可分为 （　　） 个级别。", "options": ["三", "四", "五", "六"], "answer": [1], "explanation": "高处作业高度分为2m至5m、5m以上至15m、15m以上至30m、30m以上4个区段。"},
  {"id": 480, "type": "single", "question": "高处作业高度为40m的作业属于 （　　） 高处作业。", "options": ["Ⅰ级", "Ⅱ级", "Ⅲ级", "Ⅳ级"], "answer": [3], "explanation": "1.高处作业高度在2-5ｍ时，称为一级高处作业。\n2.高处作业高度在5ｍ以上至15ｍ时，称为二级高处作业。\n3.高处作业高度在15ｍ以上至30ｍ时，称为三级高处作业。\n4.高处作业高度在30ｍ以上时，称为特级高处作业。"},
  {"id": 481, "type": "single", "question": "临边与洞口作业、攀登与悬空作业、操作平台、交叉作业及安全网搭设的安全防护技术措施等内容应制定高处作业 （　　） 。", "options": ["管理条例", "实施办法", "施工方案", "安全生产技术措施"], "answer": [3], "explanation": "临边与洞口作业、攀登与悬空作业、操作平台、交叉作业及安全网搭设的安全防护技术措施等内容应制定高处作业安全生产技术措施。"},
  {"id": 482, "type": "single", "question": "高处作业施工前，应对作业人员进行安全技术教育及交底，并应配备相应 （　　） 。", "options": ["学习资料", "生产工具", "防护用品", "生活用品"], "answer": [2], "explanation": "高处作业施工前,应对作业人员进行安全技术教育及交底,并应配备相应防护用品。"},
  {"id": 483, "type": "single", "question": "高处作业施工前，应对作业人员进行 （　　） 及交底，并应配备相应防护用品。", "options": ["安全生产技术教育", "消防安全教育", "专业技术教育", "质量把控教育"], "answer": [0], "explanation": "高处作业施工前，应对作业人员进行安全生产技术教育及交底，并应配备相应防护用品。"},
  {"id": 484, "type": "single", "question": "高处作业时，当遇有 （　　） 以上强风、浓雾、沙尘暴等恶劣气候，不得进行露天攀登与悬空高处作业。", "options": ["4级", "5级", "6级", "7级"], "answer": [2], "explanation": "高处作业时，当遇有六级以上强风、浓雾、沙尘暴等恶劣气候，不得进行露天攀登与悬空高处作业。"},
  {"id": 485, "type": "single", "question": "在工作面边沿无围护或围护设施高度低于800mm的高处作业称为 （　　） 。", "options": ["临边作业", "洞口作业", "攀登作业", "悬空作业"], "answer": [0], "explanation": "临边高处作业是指施工现场中,工作面边沿无围护设施或围护设施高度低于80cm时的高处作业。"},
  {"id": 486, "type": "single", "question": "坠落高度基准面 （　　） 及以上进行临边作业时，应在临空一侧设置防护栏杆，并应采用密目式安全立网或工具式栏板封闭。", "options": ["1.8m", "2m", "2.2m", "2.5m"], "answer": [1], "explanation": "在坠落高度基准面2m及以上进行临边作业时，应在临空一侧设置防护栏杆，并应采用密目式安全立网或工具式栏板封闭。"},
  {"id": 487, "type": "single", "question": "临边作业防护要求各类垂直运输接料平台口应设置高度不低于 （　　） 的楼层防护门，并应设置防外开装置。", "options": ["1.50m", "1.80m", "2.50m", "2.60m"], "answer": [1], "explanation": "各类垂直运输接料平台口应设置高度不低于1.8m的楼层防护门，并应设置防外开装置；"},
  {"id": 488, "type": "single", "question": "临边作业防护要求各类垂直运输接料平台口应设置高度不低于1.8m的楼层 （　　） ，并应设置防外开装置。", "options": ["消防门", "防护门", "逃生门", "防火门"], "answer": [1], "explanation": "各类垂直运输接料平台口应设置高度不低于1.8m的楼层防护门，并应设置防外开装置；"},
  {"id": 489, "type": "single", "question": "洞口高处作业是指洞与孔、边口旁的高处作业，包括施工作业及通道旁深度在 （　　） 的桩孔、沟槽与管道、孔洞等边沿上的作业。", "options": ["1.5m以下", "1.5m至1.8m上", "2m及2m以上", "1.6m至1.9m"], "answer": [2], "explanation": "洞口作业是指孔、洞口旁边的高处作业,包括施工现场及通道旁深度在2m及2m以上的桩孔、沟槽与管道孔洞等边沿作业。"},
  {"id": 490, "type": "single", "question": "洞与孔、边口旁的高处作业称为 （　　） 。", "options": ["临边作业", "洞口作业", "攀登作业", "悬空作业"], "answer": [1], "explanation": "洞口作业的含义: 洞与孔边口旁的高处作业,包括施工现场及通道旁深度在2m以上的桩孔、人孔、沟槽与管道,孔洞等边沿上的作业称为洞口作业。"},
  {"id": 491, "type": "single", "question": "当垂直洞口短边边长小于 （　　） 时，应采取封堵措施。", "options": ["300m", "400m", "500m", "600m"], "answer": [2], "explanation": "当垂直洞口短边边长小于500mm时,应采取封堵措施。"},
  {"id": 492, "type": "single", "question": "当垂直洞口短边边长大于或等于500m时，应在临空一侧设置高度不小于 （　　） 的防护栏杆。", "options": ["1.2m", "1.3m", "1.4m", "1.5m"], "answer": [0], "explanation": "垂直洞口短边边长大于或等于500㎜时,应在临空一侧设置高度不小于1.2m的防护栏杆"},
  {"id": 493, "type": "single", "question": "当非垂直洞口短边尺寸为 （　　） 时，应采用承载力满足使用要求的盖板覆盖，盖板四周搁置应均衡，且应防止盖板移位。", "options": ["50~500mm", "25~250mm", "50~250mm", "25~500mm"], "answer": [3], "explanation": "根据《建筑施工高处作业安全技术规范》（JGJ80-2016）规定，当非垂直洞口短边尺寸为25mm～500㎜时，应采用承载力满足使用要求的盖板覆盖，盖板四周搁置应均衡，且应防止盖板移位。"},
  {"id": 494, "type": "single", "question": "当非垂直洞口短边边长为 （　　） 时，应采用专项设计盖板覆盖，并应采取固定措施。", "options": ["300~500mm", "500~800mm", "500~1500mm", "800~1500mm"], "answer": [2], "explanation": "当非垂直洞口短边边长为0.5m-1.5m时,应采用专项设计盖板覆盖,并应采取固定措施;"},
  {"id": 495, "type": "single", "question": "当非垂直洞口短边边长大于或等于 （　　） 时，应在洞口作业侧设置高度不小于1.2m的防护栏杆，并应采用密目式安全立网或工具式栏板封闭；洞口应采用安全平网封闭。", "options": ["1000mm", "1200mm", "1500mm", "1800mm"], "answer": [2], "explanation": "当非垂直洞口短边边长大于或等于1500mm时，应在洞口作业侧设置高度不小于1.2m的防护栏杆，下设180mm高的踢脚板，防护栏杆距离洞口不得小于200mm，并应采用密目式安全立网或工具式栏板封闭，栏杆表面刷黄黑相间警示漆，洞口应采用安全平网封闭。"},
  {"id": 496, "type": "single", "question": "当非垂直洞口短边边长大于或等于1500mm时，应在洞口作业侧设置高度不小于 （　　） 的防护栏杆，并应采用密目式安全立网或工具式栏板封闭；洞口应采用安全平网封闭。", "options": ["1.0m", "1.2m", "1.5m", "1.8m"], "answer": [1], "explanation": "当非垂直洞口短边边长大于或等于1500mm时，应在洞口作业侧设置高度不小于1.2m的防护栏杆，下设180mm高的踢脚板，防护栏杆距离洞口不得小于200mm，并应采用密目式安全立网或工具式栏板封闭，栏杆表面刷黄黑相间警示漆，洞口应采用安全平网封闭。"},
  {"id": 497, "type": "single", "question": "电梯井口应设置防护门，其高度不应小于1.5m，防护门底端距地面高度不应大于 （　　） ，并应设置挡脚板。", "options": ["30mm", "40mm", "50mm", "60mm"], "answer": [2], "explanation": "电梯井口应设置防护门，其高度不应小于1.5m，防护门底端距地面高度不应大于50mm，并应设置高度不小于180mm的挡脚板。"},
  {"id": 498, "type": "single", "question": "电梯井口应设置防护门，其高度不应小于 （　　） ，防护门底端距地面高度不应大于50mm，并应设置挡脚板。", "options": ["1.2m", "1.5m", "1.6m", "1.8m"], "answer": [1], "explanation": "电梯井口应设置防护门，其高度不应小于1.5m，防护门底端距地面高度不应大于50mm，并应设置高度不小于180mm的挡脚板。"},
  {"id": 499, "type": "single", "question": "在进入电梯安装施工工序之前，同时井道内应每隔 （　　） ,且不大于2层加设一道水平安全网。", "options": ["8m", "10m", "12m", "14m"], "answer": [1], "explanation": "在进入电梯安装施工工序之前,同时井道内应每隔10m且不大于2层加设一道水平安全网。"},
  {"id": 500, "type": "single", "question": "在进入电梯安装施工工序之前，同时井道内应每隔10m，且不大于 （　　） 加设一道水平安全网。", "options": ["1层", "2层", "3层", "4层"], "answer": [1], "explanation": "在进入电梯安装施工工序之前，同时井道内应每隔10m且不大于2层加设一道水平安全网。电梯井内的施工层上部，应设置隔离防护设施。"},
  {"id": 501, "type": "single", "question": "施工现场通道附近的洞口、坑、沟、槽、高处临边等危险作业处，应悬挂安全警示标志外，夜间 （　　） 。", "options": ["应有人巡查", "应设灯光警示", "应设警戒线", "应设硬隔离"], "answer": [1], "explanation": "施工现场通道附近的洞口、坑、沟、槽、高处临边等危险作业处,应悬挂安全警示标志外,夜间应设灯光警示。"},
  {"id": 502, "type": "single", "question": "边长不大于500m洞口所加盖板，应能承受不小于 （　　） 的荷载。", "options": ["1.0kN/m", "1.1kN/m", "1.2kN/m", "1.5kN/m"], "answer": [1], "explanation": "【依据】《建筑施工高处作业安全技术规范》JGJ 80-2016\n【解析】正确答案是B。题干对应的是建筑施工高处作业防护。 A项“1.0kN/m”错误，它说的是“1.0kN/m”，并非题干要找的“1.1kN/m”。 B项“1.1kN/m”正确，它与题干所述“边长不大于500m洞口所加盖板，应能承受不小”相对应。 C项“1.2kN/m”错误，它说的是“1.2kN/m”，并非题干要找的“1.1kN/m”。 D项“1.5kN/m”错误，它说的是“1.5kN/m”，并非题干要找的“1.1kN/m”。"},
  {"id": 503, "type": "single", "question": "当防护栏杆高度大于 （　　） 时，应增设横杆，横杆间距不应大于600mm.", "options": ["1.1m", "1.2m", "1.3m", "1.4m"], "answer": [1], "explanation": "当防护栏杆高度大于1.2m时，应增设横杆，横杆间距不应大于600mm"},
  {"id": 504, "type": "single", "question": "当防护栏杆高度大于1.2m时，应增设横杆，横杆间距不应大于 （　　） 。", "options": ["500mm", "550mm", "600mm", "650mm"], "answer": [2], "explanation": "【依据】《建筑施工高处作业安全技术规范》JGJ 80-2016\n【解析】正确答案是C。题干对应的是建筑施工高处作业防护。 A项“500mm”错误，题干对应的控制数值不是500mm，正确值应为600mm。 B项“550mm”错误，题干对应的控制数值不是550mm，正确值应为600mm。 C项“600mm”正确，规范要求的控制数值或时限就是600mm。 D项“650mm”错误，题干对应的控制数值不是650mm，正确值应为600mm。"},
  {"id": 505, "type": "single", "question": "防护栏杆应为 （　　） 横杆。", "options": ["一道", "两道", "三道", "四道"], "answer": [1], "explanation": "防护栏杆应为两道横杆，上杆距地面高度应为1.2m,下杆应在上杆和挡脚板中间设置。当防护栏杆高度大于1.2m时，应增设横杆，横杆间距不应大于600m."},
  {"id": 506, "type": "single", "question": "防护栏杆立杆间距不应大于 （　　） m。", "options": ["2", "3", "4", "5"], "answer": [0], "explanation": "临边作业的防护栏杆应由横杆、立杆及挡脚板组成，防护栏杆应符合下列规定：防护栏杆立杆间距不应大于2m。"},
  {"id": 507, "type": "single", "question": "挡脚板高度不应小于 （　　） mm。", "options": ["160", "180", "280", "3600"], "answer": [1], "explanation": "挡脚板高度不应小于180mm。"},
  {"id": 508, "type": "single", "question": "应确保防护栏杆在上下横杆和立杆任何处，均能承受任何方向的最小 （　　） kN外力作用。", "options": ["4", "3", "2", "1"], "answer": [3], "explanation": "栏杆立杆和横杆的设置、固定及连接，应确保防护栏杆在上下横杆和立杆任何处,均能承受任何方向的最小1kN外力作用，当栏杆所处位置有发生人群拥挤、车辆冲击和物件碰撞等可能时，应加大横杆截面或加密立杆间距。"},
  {"id": 509, "type": "single", "question": "当采用钢管作为防护栏杆件时，横杆及栏杆立杆应采用 （　　） ,并应采用扣件、焊接、定型套管等方式连接固定。", "options": ["木方", "脚手钢管", "方钢", "钢筋"], "answer": [1], "explanation": "当采用钢管作为防护栏杆杆件时,横杆及栏杆立杆应采用脚手钢管,并应采用扣件、定型套管等方式进行连接固定;"},
  {"id": 510, "type": "single", "question": "在施工现场，凡借助于登高用具或登高设施，在攀登条件下进行的高处作业，称为 （　　） 。", "options": ["临边作业", "洞口作业", "攀登作业", "悬空作业"], "answer": [2], "explanation": "在施工现场，借助于登高用具或登高设施，在攀登条件下进行的高处作业，叫攀登作业。"},
  {"id": 511, "type": "single", "question": "攀登作业所用设施和用具的结构构造应牢固可靠，作用在踏步上的荷载在踏板上的荷载不应大于 （　　） ，当梯面上有特殊作业，重量超过上述荷载时，应按实际情况验算。", "options": ["1.0KN", "1.1KN", "1.2KN", "1.3KN"], "answer": [1], "explanation": "攀登的用具、设施、建筑结构构造必须牢固可靠,供人上下的梯踏板其使用荷载不应大于1100N。当梯面上有特殊作业,重量超过上述荷载时,应按实际情况加以验算。"},
  {"id": 512, "type": "single", "question": "单梯不得垫高使用，使用时应与水平面成75°夹角，踏步不得缺失，其间距宜为 （　　） 。", "options": ["150mm", "200mm", "250mm", "300mm"], "answer": [3], "explanation": "防控措施:单梯不得垫高使用,使用时应与水平面成75°夹角,踏步不得缺失,其间距宜为30cm。"},
  {"id": 513, "type": "single", "question": "单梯不得垫高使用，使用时应与水平面成 （　　） 夹角，踏步不得缺失，其间距宜为300mm。", "options": ["35°", "55°", "75°", "95°"], "answer": [2], "explanation": "防控措施:单梯不得垫高使用,使用时应与水平面成75°夹角,踏步不得缺失,其间距宜为30cm。"},
  {"id": 514, "type": "single", "question": "当梯子需接长使用时，应有可靠的连接措施，接头不得超过 （　　） 处。", "options": ["1", "2", "3", "4"], "answer": [0], "explanation": "当梯子需接长使用时，应有可靠的连接措施，接头不得超过1处。连接后梯梁的强度，不应低于单梯梯梁的强度。"},
  {"id": 515, "type": "single", "question": "使用固定式直梯进行攀登作业时，攀登高度宜为 （　　） ,且不超过10m。", "options": ["2m", "3m", "4m", "5m"], "answer": [3], "explanation": "使用固定式直梯进行攀登作业时,攀登高度宜为5m,且不超过10m。超过3m时,宜加护笼,超过8m时必须设置梯间平台。"},
  {"id": 516, "type": "single", "question": "使用固定式直梯进行攀登作业时，攀登高度宜为5m，且不超过10m。当攀登高度超过 （　　） 时，宜加设护笼；超过8m时，应设置梯间平台。", "options": ["2m", "3m", "4m", "5m"], "answer": [1], "explanation": "使用固定式直梯进行攀登作业时,攀登高度宜为5m,且不超过10m。超过3m时,宜加护笼,超过8m时必须设置梯间平台。"},
  {"id": 517, "type": "single", "question": "使用固定式直梯进行攀登作业时，攀登高度宜为5m，且不超过10m。当攀登高度超过3m时，宜加设护笼；超过 （　　） 时，应设置梯间平台。", "options": ["5m", "6m", "7m", "8m"], "answer": [3], "explanation": "使用固定式直梯进行攀登作业时,攀登高度宜为5m,且不超过10m。超过3m时,宜加护笼,超过8m时必须设置梯间平台。"},
  {"id": 518, "type": "single", "question": "当无电焊防风要求时，高处作业操作平台的防护栏杆高度不应小于 （　　） m。", "options": ["1.0", "1.1", "1.2", "1.3"], "answer": [2], "explanation": "当无电焊防风要求时,操作平台的防护栏杆高度不应小于1.2m;有电焊防风要求时,操作平台的防护栏杆高度不应小于1.8m。"},
  {"id": 519, "type": "single", "question": "当有电焊防风要求时，高处作业操作平台的防护栏杆高度不应小于 （　　） m。", "options": ["1.7", "1.8", "1.9", "2.0"], "answer": [1], "explanation": "当有电焊防风要求时，操作平台的防护栏杆高度不小于1.8m。"},
  {"id": 520, "type": "single", "question": "使用固定式直梯进行攀登作业时，攀登高度宜为5m，且不超过 （　　） 。", "options": ["6m", "8m", "10m", "12m"], "answer": [2], "explanation": "使用固定式直梯进行攀登作业时,攀登高度宜为5m,且不超过10m。超过3m时,宜加护笼,超过8m时必须设置梯间平台。"},
  {"id": 521, "type": "single", "question": "悬空高处作业是指无立足点或无牢靠立足点的条件下进行的高处作业，简称为 （　　） 。", "options": ["临边作业", "洞口作业", "攀登作业", "悬空作业"], "answer": [3], "explanation": "因此,在悬空高处作业时,需要建立有牢固的立足点,如设置防护栏网、栏杆或其它安全设 在周边临空状态下,无立足点或无牢靠立足点的条件下进行的高处作业,称为悬空作业。"},
  {"id": 522, "type": "single", "question": "在 （　　） 以上高处搭设和拆除柱模板及悬挑式模板时，应设置操作平台。", "options": ["1.8m", "2.0m", "2.1m", "2.2m"], "answer": [1], "explanation": "在坠落基准面2m及以上高处搭设与拆除柱模板及悬挑结构的模板时,应设置操作平台"},
  {"id": 523, "type": "single", "question": "在坡度大于 （　　） 的屋面上作业，当无外脚手架时，应在屋檐边设置不低于1.5m高的防护栏杆，并应采用密目式安全网全封闭。", "options": ["1：2.0", "1：2.1", "1：2.2", "1：2.3"], "answer": [2], "explanation": "在坡度大于1:2.2的屋面上作业,当无外脚手架时,应在屋檐边设置不低于1.5m高的防护栏杆,并应采用密目式安全立网全封闭。"},
  {"id": 524, "type": "single", "question": "单独设置的高处作业操作平台应设置供人上下、踏步间距不大于 （　　） mm的扶梯。", "options": ["250", "300", "350", "400"], "answer": [3], "explanation": "操作平台的临边应设置防护栏杆,单独设置的操作平台应设置供人上下、踏步间距不大于400mm的扶梯。"},
  {"id": 525, "type": "single", "question": "高处作业的操作平台投入使用时，应在平台的 （　　） 设置标明允许荷载值的限载牌。", "options": ["外侧", "内侧", "底部", "顶部"], "answer": [1], "explanation": "操作平台投入使用时,应在平台的内侧设置标明允许负载值的限载牌,物料应及时转运,不得超重与超高堆放。"},
  {"id": 526, "type": "single", "question": "高处作业的操作平台投入使用时，应在平台的内侧设置标明允许荷载值的 （　　） 。", "options": ["警示牌", "限载牌", "说明书", "安全标牌"], "answer": [1], "explanation": "操作平台投入使用时,应在平台的内侧设置标明允许负载值的限载牌,物料应及时转运,不得超重与超高堆放。"},
  {"id": 527, "type": "single", "question": "高处作业的移动式操作平台的面积不应超过 （　　） 平方米。", "options": ["5", "10", "15", "20"], "answer": [1], "explanation": "《建筑施工高处作业安全技术规范》JGJ 80-2016\n6.2.1 移动式操作平台面积不宜大于10㎡，高度不宜大于 5m，高宽比不应大于2:1，施工荷载不应大于1.5kN/㎡。"},
  {"id": 528, "type": "single", "question": "高处作业的移动式操作平台的高度不应超过 （　　） m。", "options": ["2", "3", "4", "5"], "answer": [3], "explanation": "《建筑施工高处作业安全技术规范》JGJ 80-2016\n6.2.1 移动式操作平台面积不宜大于10㎡，高度不宜大于 5m，高宽比不应大于2:1，施工荷载不应大于1.5kN/㎡。"},
  {"id": 529, "type": "single", "question": "高处作业的移动式操作平台的高宽比不应大于 （　　） 。", "options": ["2∶1", "1∶2", "3∶1", "1∶3"], "answer": [0], "explanation": "《建筑施工高处作业安全技术规范》JGJ 80-2016\n6.2.1 移动式操作平台面积不宜大于10㎡，高度不宜大于 5m，高宽比不应大于2:1，施工荷载不应大于1.5kN/㎡。"},
  {"id": 530, "type": "single", "question": "高处作业的移动式操作平台的施工荷载每平方米不应超过 （　　） kN。", "options": ["1.0", "1.5", "1.8", "2.0"], "answer": [1], "explanation": "《建筑施工高处作业安全技术规范》JGJ 80-2016\n6.2.1 移动式操作平台面积不宜大于10㎡，高度不宜大于 5m，高宽比不应大于2:1，施工荷载不应大于1.5kN/㎡。"},
  {"id": 531, "type": "single", "question": "高处作业的落地式操作平台高度不应大于 （　　） m，高宽比不应大于3∶1。", "options": ["10", "15", "20", "25"], "answer": [1], "explanation": "落地式操作平台的搭设高度不应大于15m,高宽比不应大于3:1。"},
  {"id": 532, "type": "single", "question": "高处作业的落地式操作平台高度不应大于15m，高宽比不应大于 （　　） 。", "options": ["2：1", "3∶1", "4：1", "5：1"], "answer": [1], "explanation": "落地式操作平台的搭设高度不应大于15m,高宽比不应大于3:1。"},
  {"id": 533, "type": "single", "question": "高处作业的落地式操作平台中，当接料平台的施工荷载大于 （　　） KN/㎡时，应进行专项设计。", "options": ["1.0", "1.5", "2.0", "2.5"], "answer": [2], "explanation": "施工平台的施工荷载不应大于2.0kN/m2;当接料平台的施工荷载大于2.0kN/m2时,应进行专项设计;"},
  {"id": 534, "type": "single", "question": "落地式操作平台应从底层第一步水平杆起遂层设置连墙件，且连墙件间隔不应大于 （　　） m，并设置水平剪刀撑。", "options": ["2.5", "3.0", "3.5", "4.0"], "answer": [3], "explanation": "操作平台应从底层第一步水平杆起逐层设置连墙件，且连墙件间隔不应大于4m，并应设置水平剪刀撑。"},
  {"id": 535, "type": "single", "question": "落地式操作平台应从底层第一步水平杆起遂层设置连墙件，且连墙件间隔不应大于4m，并设置 （　　） 。", "options": ["斜撑", "水平剪刀撑", "顶撑", "竖向剪刀撑"], "answer": [1], "explanation": "操作平台应从底层第一步水平杆起逐层设置连墙件，且连墙件间隔不应大于4m，并应设置水平剪刀撑。"},
  {"id": 536, "type": "single", "question": "高处作业的落地式操作平台一次搭设高度不应超过相邻连墙件以上 （　　） 。", "options": ["半步", "一步", "两步", "三步"], "answer": [2], "explanation": "操作平台一次搭设高度不应超过相邻连墙件以上两步，操作平台拆除应由上而下逐层进行，严禁上下同时作业，连墙件应随施工进度逐层拆除。"},
  {"id": 537, "type": "single", "question": "高处作业的悬挑式操作平台的搁置点、拉结点、支撑点应设置在 （　　） 上，且应可靠连接。", "options": ["砖混结构", "主体结构", "框架结构", "框筒结构"], "answer": [1], "explanation": "根据《建筑施工高处作业安全技术规范》规定，悬挑式操作平台的搁置点、拉结点、支撑点应设置在稳定的主体结构上，且应可靠连接。"},
  {"id": 538, "type": "single", "question": "高处作业的悬挑式操作平台的悬挑长度不宜大于 （　　） ,承载力需经设计验收。", "options": ["3m", "5m", "8m", "10m"], "answer": [1], "explanation": "悬挑式操作平台的悬挑长度不宜大于5m，承载力需经设计验收。"},
  {"id": 539, "type": "single", "question": "采用斜拉式的高处作业悬挑式操作平台在平台两边各设置前后 （　　） 斜拉钢丝绳，每一道均应做单独受力计算和设置。", "options": ["两道", "三道", "四道", "五道"], "answer": [0], "explanation": "采用斜拉方式的悬挑式操作平台应在平台两边各设置前后两道斜拉钢丝绳,每一道均应作单独受力计算和设置。"},
  {"id": 540, "type": "single", "question": "交叉作业时，安全防护棚和警戒隔离区范围的设置应视上层作业高度确定，并应大于 （　　） 。", "options": ["坠落直径", "坠落半径", "基础高度", "高处作业高度"], "answer": [1], "explanation": "施工现场立体交叉作业时，下层作业的位置应处于坠落半径之外，安全防护棚和警戒隔离区范围的设置应视上层作业高度确定，并应大于坠落半径，当尚未设置安全隔离措施时，应设置警戒隔离区，人员严禁进入隔离区；"},
  {"id": 541, "type": "single", "question": "交叉作业时，安全防护棚和警戒隔离区范围的设置应视 （　　） 确定，并应大于坠落半径。", "options": ["楼层作业高度", "上层作业高度", "通道宽度", "通道高度"], "answer": [1], "explanation": "施工现场立体交叉作业时，下层作业的位置应处于坠落半径之外，安全防护棚和警戒隔离区范围的设置应视上层作业高度确定，并应大于坠落半径，当尚未设置安全隔离措施时，应设置警戒隔离区，人员严禁进入隔离区；"},
  {"id": 542, "type": "single", "question": "当在多层、高层建筑外立面施工时应在二层及每隔 （　　） 层设一道固定的安全防护网，同时设一道随施工高度提升的安全防护网。", "options": ["三", "四", "五", "六"], "answer": [1], "explanation": "对不搭设脚手架和设置安全防护棚时的交叉作业，应设置安全防护网,当在多层、高层建筑外立面施工时,应在二层及每隔四层设一道固定的安全防护网,同时设一道随施工高度提升的安全防护网。安全防护网应外高里低,水平夹角不宜小于45°，网与网之间应拼接严密。"},
  {"id": 543, "type": "single", "question": "当安全防护棚为非机动车辆通行时，棚底至地面高度不应小于 （　　） m。", "options": ["2", "3", "4", "5"], "answer": [1], "explanation": "当安全防护棚为非机动车辆通行时,棚底至地面高度不应小于3m;当安全防护棚为机动车辆通行时,棚底至地面高度不应小于4m。"},
  {"id": 544, "type": "single", "question": "当安全防护棚为机动车辆通行时，棚底至地面高度不应小于 （　　） m。", "options": ["3", "4", "5", "6"], "answer": [1], "explanation": "【依据】《建筑施工高处作业安全技术规范》JGJ 80-2016\n【解析】正确答案是B。题干对应的是建筑施工高处作业防护。 A项“3”错误，题干对应的控制数值不是3，正确值应为4。 B项“4”正确，规范要求的控制数值或时限就是4。 C项“5”错误，题干对应的控制数值不是5，正确值应为4。 D项“6”错误，题干对应的控制数值不是6，正确值应为4。"},
  {"id": 545, "type": "single", "question": "安全防护棚的顶棚采用竹笆或木质板搭设时，应采用双层搭设，间距不应小于 （　　） mm。", "options": ["500", "600", "700", "800"], "answer": [2], "explanation": "当安全防护棚的顶棚采用竹笆或木质板搭设时，应采用双层搭设，间距不应小于700mm。"},
  {"id": 546, "type": "single", "question": "当安全防护棚的顶棚采用木质板或与其等强度的其他材料搭设时，应采用单层搭设，木板厚度不应小于 （　　） mm。", "options": ["20", "30", "40", "50"], "answer": [3], "explanation": "当安全防护棚的顶棚采用竹笆或木质板搭设时，应采用双层搭设，间距不应小于700mm;当采用木质板或与其等强度的其他材料搭设时，可采用单层搭设，木板厚度不应小于50mm。防护棚的长度应根据建筑物高度与可能坠落半径确定。"},
  {"id": 547, "type": "single", "question": "密目式安全立网的网目密度应为10cmX10cm，面积上大于或等于 （　　） 目。", "options": ["500", "1000", "1500", "2000"], "answer": [3], "explanation": "密目式安全立网的网目密度应为10cm×10cm面积上大于或等于2000目。"},
  {"id": 548, "type": "single", "question": "密目式安全立网搭设时，每个开眼环扣应穿入系绳，系绳应绑扎在支撑架上，间距不得大于 （　　） 。", "options": ["350", "400", "450", "500"], "answer": [2], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】正确答案是C。题干对应的是建筑施工安全管理。 A项“350”错误，题干对应的控制数值不是350，正确值应为450。 B项“400”错误，题干对应的控制数值不是400，正确值应为450。 C项“450”正确，规范要求的控制数值或时限就是450。 D项“500”错误，题干对应的控制数值不是500，正确值应为450。"},
  {"id": 549, "type": "single", "question": "当立网用于龙门物料提升架及井架的封闭防护时，四周边绳应与支撑架紧贴，边绳的断裂张力不得小于 （　　） KN，系绳应绑扎在支撑架上，间距不得大于750mm。", "options": ["1.5", "2.0", "2.5", "3.0"], "answer": [3], "explanation": "当立网用于龙门架、物料提升架及井架的封闭防护时,四周边绳应与支撑架贴紧,边绳的断裂张力不得小于3kN,系绳应绑在支撑架上,间距不得大于750mm。"},
  {"id": 550, "type": "single", "question": "当立网用于龙门物料提升架及井架的封闭防护时，四周边绳应与支撑架紧贴，边绳的断裂张力不得小于3kN，系绳应绑扎在支撑架上，间距不得大于 （　　） mm。", "options": ["600", "650", "700", "750"], "answer": [3], "explanation": "当立网用于龙门架、物料提升架及井架的封闭防护时,四周边绳应与支撑架贴紧,边绳的断裂张力不得小于3kN,系绳应绑在支撑架上,间距不得大于750mm。"},
  {"id": 551, "type": "single", "question": "电梯井内平网网体与井壁的空隙不得大于 （　　） mm，安全网拉结应牢固。", "options": ["20", "25", "30", "35"], "answer": [1], "explanation": "电梯井内平网网体与井壁的空隙不得大于25mm，安全网拉结应牢固。"},
  {"id": 552, "type": "single", "question": "装配式混凝土建筑施工，施工单位应根据工程施工特点对 （　　） 进行分析并予以公示，并制定相对应的安全生产应急预案。", "options": ["危大工程", "重大危险源", "危险源", "特种工程"], "answer": [1], "explanation": "装配式混凝土建筑施工，施工单位应根据工程施工特点对重大危险源进行分析并予以公示，并制定相对应的安全生产应急预案。"},
  {"id": 553, "type": "single", "question": "装配整体式混凝土结构工程施工，堆场加固、构件堆放架体、构件吊点、施工设施设备附墙，附着设施等涉及工程结构安全的方案应由 （　　） 核定。", "options": ["施工单位", "设计单位", "监理单位", "建设单位"], "answer": [1], "explanation": "深化施工设计制度。堆场加固、构件堆放架体、构件吊点、施工设施设备附墙，附着设施等涉及工程结构安全的方案应由设计单位核定。"},
  {"id": 554, "type": "single", "question": "装配整体式混凝土结构工程施工，当涉及尚无规范依据的新技术、新工艺、新材料、新设备， （　　） 应编制专项施工方案，组织专家进行系统论证。", "options": ["施工单位", "设计单位", "监理单位", "建设单位"], "answer": [0], "explanation": "专项施工方案论证制度.施工专用操作平台、高处临边作业防护设施等涉及尚无规范依据的新技术、新工艺、新材料、新设备，施工单位应编制专项施工方案,组织专家进行系统论证."},
  {"id": 555, "type": "single", "question": "装配整体式混凝土结构工程施工，吊装机械选型及平面布置由 （　　） 编制专项施工方案。", "options": ["施工单位", "设计单位", "监理单位", "建设单位"], "answer": [0], "explanation": "第五条 施工单位应当在危险性较大的分部分项工程施工前编制专项方案；对于超过一定规模的危险性较大的分部分项工程，施工单位应当组织专家对专项方案进行论证。"},
  {"id": 556, "type": "single", "question": "装配整体式混凝土结构工程预制构件安装起吊前， （　　） 单位应对吊装的安全生产措施、条件等进行全面检查，在取得《吊装令》后，方可实施安装。", "options": ["施工、设计", "施工、地勘", "施工、监理", "设计、监理"], "answer": [2], "explanation": "吊装令制度。预制构件安装起吊前,施工、监理单位应对吊装的安全生产措施、条件等进行全面检查,在取得《吊装令》后,方可实施安装。"},
  {"id": 557, "type": "single", "question": "装配整体式混凝土结构工程施工，自制堆放架、操作平台、脚手架、反挂吊篮和爬梯的设计属于 （　　） 。", "options": ["安全防护", "支撑体系", "辅助设施", "机械选型"], "answer": [2], "explanation": "自制堆放架、操作平台、脚手架、反挂吊篮和爬梯等辅助设施设计;"},
  {"id": 558, "type": "single", "question": "装配式混凝土建筑应根据预制构件的类型选择合适的堆放方式，规定堆放层数，构件之间应设置可靠的（）；若使用货架堆置，货架应进行力学计算。", "options": ["垫块", "支撑", "堆场", "围挡"], "answer": [0], "explanation": "应根据预制构件的类型选择合适的堆放方式及规定堆放层数,同时构件之间应设置可靠的垫块;若使用货架堆置,货架应进行力学计算满足承载力要求。"},
  {"id": 559, "type": "single", "question": "装配式混凝土建筑预制构件堆场的选址尽可能设置在 （　　） ,避免交叉作业。", "options": ["建筑场地附近", "任意建筑单体的周边", "相应建筑单体的周边", "办公区域附近"], "answer": [2], "explanation": "预制构件堆场的选址应结合垂直运输设备起吊半径、施工便道布置及卸货车辆停靠位置等因素综合考虑,尽可能设置在相应建筑单体的周边,避免交叉作业。"},
  {"id": 560, "type": "single", "question": "装配式混凝土建筑的堆场、货架、高处作业专用操作平台、脚手架及吊篮等辅助设施、预制构件安装的临时支撑体系等应经 （　　） 方可投入使用。", "options": ["验收通过", "检查合格", "力学计算", "验收通过并挂牌"], "answer": [3], "explanation": "（五）堆场、货架、高处作业专用操作平台、脚手架及吊篮等辅助设施、预制构件安装的临时支撑体系等应经验收通过并挂牌方可投入使用。"},
  {"id": 561, "type": "single", "question": "装配式混凝土建筑预制构件起吊使用的钢丝绳、手拉葫芦等起重工具应根据 （　　） ，增加检查频次，根据检查结果定期更换。", "options": ["使用频率", "起吊重量", "起吊的构件种类", "使用次数"], "answer": [0], "explanation": "起吊使用的钢丝绳、手拉葫芦等起重工具应根据使用频率,增加检查频次,根据检查结果定期更换。严禁使用自编的钢丝绳接头;严禁使用无设计依据的自制吊索具。"},
  {"id": 562, "type": "single", "question": "装配式混凝土建筑预制构件安装施工前，应核对预制构件的混凝土 （　　） 及预制构件和配件的型号、规格、数量等符合设计要求。", "options": ["强度", "刚度", "承载力", "标号"], "answer": [0], "explanation": "预制构件安装前的准备工作应符合下列规定：\n1） 应核对已施工完成结构的混凝土强度、外观、尺寸等符合设计文件要求；\n2） 应核对预制构件混凝土强度及预制构件和配件的型号、规格、数量等符合设计文件要求；\n3） 应在已施工完成结构及预制构件上进行测量放线，并应设置安装定位标志；\n4） 应确认吊装设备及吊具处于安全操作状态；\n5） 应核实现场环境、天气、道路状况满足吊装施工要求。"},
  {"id": 563, "type": "single", "question": "装配式混凝土建筑预制构件安装施工前，应进行测量放线、设置构件安装 （　　） 标识。", "options": ["型号", "规格", "定位", "尺寸"], "answer": [2], "explanation": "安装施工前,应进行测量放线、设置构件安装定位标识。"},
  {"id": 564, "type": "single", "question": "装配式结构施工前，宜选择 （　　） 单元进行预制构件试安装，并应根据试安装结果及时调整完善施工方案和施工工艺。", "options": ["随机的", "任意1个", "有代表性的", "任意3个"], "answer": [2], "explanation": "装配式建筑施工前,宜选择有代表性的单元进行预制构件试安装,并应根据试安装结果及时调整完善施工方案和施工工艺。"},
  {"id": 565, "type": "single", "question": "装配式混凝土建筑预制构件吊装作业施工前， （　　） 对所用的各类设施设备、吊索具、构配件定期检查、更换。", "options": ["施工单位、监理", "施工单位、设计单位", "设计单位、监理", "施工单位、建设单位"], "answer": [0], "explanation": "定期检查：施工单位、监理对上述各类设施设备、吊索具、构配件定期检查、更换。"},
  {"id": 566, "type": "single", "question": "装配式混凝土建筑预制构件安装作业开始前，应对安装作业区进行围护并做出 （　　） ，拉警戒线，根据危险源级别安排旁站，严禁与安装作业无关的人员进入。", "options": ["标识", "明显的标识", "标记", "通知"], "answer": [1], "explanation": "安装作业开始前,应对安装作业区进行围护并做出明显的标识,拉警戒线, 根据危险源级别安排旁站,严禁与安装作业无关的人员进入。"},
  {"id": 567, "type": "single", "question": "装配式混凝土建筑预制板叠放按照规定不得超过 （　　） 层。", "options": ["3", "4", "5", "6"], "answer": [3], "explanation": "装配式混凝土建筑预制构件堆放按规定堆放不超限，板叠放不大于6层，柱、梁叠放不大于2层。"},
  {"id": 568, "type": "single", "question": "装配式混凝土建筑预制柱、梁叠放按照规定不得超过 （　　） 层。", "options": ["2", "3", "4", "5"], "answer": [0], "explanation": "装配式混凝土建筑预制构件堆放按规定堆放不超限，板叠放不大于6层，柱、梁叠放不大于2层。"},
  {"id": 569, "type": "single", "question": "装配式混凝土建筑预制构件堆放按规定堆放不超限，板叠放不大于 （　　） 层，柱、梁叠放不大于2层。", "options": ["4", "5", "6", "7"], "answer": [2], "explanation": "按规定堆放不超限 ; (板叠放不大于 6 层,柱、梁叠放不大于 2 层) 堆放架验收挂牌有限载"},
  {"id": 570, "type": "single", "question": "装装配式混凝土建筑预制构件堆放按规定堆放不超限，板叠放不大于6层，柱、梁叠放不大于 （　　） 层。", "options": ["2", "3", "4", "5"], "answer": [0], "explanation": "按规定堆放不超限 ; (板叠放不大于 6 层,柱、梁叠放不大于 2 层) 堆放架验收挂牌有限载"},
  {"id": 571, "type": "single", "question": "装配式混凝土建筑预制构件吊装应按作业面配备 （　　） 指挥。", "options": ["上", "下", "1名", "上下"], "answer": [3], "explanation": "吊装按作业面配备上下指挥"},
  {"id": 572, "type": "single", "question": "装配式混凝土建筑预制构件吊装作业，临时固定措施按照 （　　） 设置，安全可靠。", "options": ["设计方案", "施工方案", "初步方案", "应急预案"], "answer": [1], "explanation": "临时固定措施按施工方案设置,安全可靠。"},
  {"id": 573, "type": "single", "question": "装配式混凝土建筑预制构件安装作业，安装点的安全防护措施或安全警示标志按 （　　） 和方案要求设置。", "options": ["规范", "设计", "现场要求", "指示"], "answer": [0], "explanation": "安装点的安全防护措施或安全标志\n（1）按规范和方案要求设置；\n（2）危险部位设置安全警示标志；"},
  {"id": 574, "type": "single", "question": "装配式混凝土建筑安装作业登高及平台须有 （　　） 挂牌。", "options": ["安全", "验收", "设计", "使用许可"], "answer": [1], "explanation": "作业登高及平台有验收挂牌; 安全可靠;"},
  {"id": 575, "type": "single", "question": "装配式混凝土建筑施工，安全防护采用操作架时，操作架应与结构有可靠的连接体系，操作架 （　　） 应满足计算要求。", "options": ["构造", "受力", "强度", "刚度"], "answer": [1], "explanation": "装配式混凝土建筑施工，安全防护采用操作架时，操作架应与结构有可靠的连接体系，操作架受力应满足计算要求。"},
  {"id": 576, "type": "single", "question": "装配式混凝土建筑安装作业安全防护采用围挡式安全隔离时，楼层围挡高度应不低于 （　　） m。", "options": ["1", "1.5", "1.8", "2"], "answer": [1], "explanation": "安全防护采用围挡式安全隔离时, 楼层围挡高度应不低于1.50m, 阳台围挡不应低于1.2m, 楼梯临边应加设高度不小于0.9m 的临时栏杆。"},
  {"id": 577, "type": "single", "question": "装配式混凝土建筑安装作业安全防护采用围挡式安全隔离时，阳台围挡不应低于 （　　） m。", "options": ["1.0", "1.05", "1.1", "1.2"], "answer": [2], "explanation": "上海市工程建设规范《装配整体式混凝土结构施工及质量验收规范》\n7.2.3 安全防护采用围挡式安全隔离时,楼层围挡高度应不低于1.50m,阳台围挡不应低于1.10m,楼梯临边应加设高度不小于 0.9m 的临时栏杆。"},
  {"id": 578, "type": "single", "question": "装配式混凝土建筑安装作业安全防护采用围挡式安全隔离时，楼梯临边应加设高度不小于 （　　） m的临时栏杆。", "options": ["0.9", "1.0", "1.05", "1.1"], "answer": [0], "explanation": "安全防护采用围挡式安全隔离时, 楼层围挡高度应不低于1.50m, 阳台围挡不应低于1.2m, 楼梯临边应加设高度不小于0.9m 的临时栏杆。"},
  {"id": 579, "type": "single", "question": "装配整体式混凝土结构施工在绑扎柱、墙钢筋，应采用专用登高设施，当高于围挡时，必须佩戴 （　　） 保险带。", "options": ["攀登固定式", "双背带式", "悬挂单腰带式", "穿芯自锁"], "answer": [3], "explanation": "装配整体式混凝土结构施工在绑扎柱、墙钢筋,应采用专用登高设施,当高于围挡时必须佩戴穿芯自锁保险带。"},
  {"id": 580, "type": "single", "question": "装配整体式混凝土结构中特殊结构或必要的外墙板构件安装可选用 （　　） 作为安全防护。", "options": ["围挡", "全防护操作架", "落地脚手架", "局部脚手架"], "answer": [2], "explanation": "装配整体式混凝土结构施工宜采用围挡或外防护架，特殊结构或必要的外墙板构件安装可选用落地式脚手架。"},
  {"id": 581, "type": "single", "question": "装配式混凝土建筑施工现场，建筑内危险部位须设置 （　　） 。", "options": ["警示标志", "安全标志", "安全警示标志", "小心坠物标识"], "answer": [2], "explanation": "【依据】《装配整体式混凝土结构工程施工安全管理规定》 / 《装配式混凝土结构技术规程》JGJ 1-2014\n【解析】正确答案是C。题干对应的是装配式混凝土结构施工安全。 A项“警示标志”错误，它说的是“警示标志”，并非题干要找的“安全警示标志”。 B项“安全标志”错误，它说的是“安全标志”，并非题干要找的“安全警示标志”。 C项“安全警示标志”正确，它与题干所述“装配式混凝土建筑施工现场，建筑内危险部位须设”相对应。 D项“小心坠物标识”错误，它说的是“小心坠物标识”，并非题干要找的“安全警示标志”。"},
  {"id": 582, "type": "single", "question": "装配式混凝土建筑施工现场，坠落区域应按规范规定的坠落 （　　） 设定。", "options": ["坠落高度", "坠落半径", "坠落直径", "作业高度"], "answer": [1], "explanation": "装配式混凝土建筑施工现场，坠落区域应按规范规定的坠落半径设定。"},
  {"id": 583, "type": "single", "question": "装配式混凝土建筑施工现场，注浆机等机具验收使用，须有 （　　） 挂牌或允许使用的识别标志，安全可靠。", "options": ["验收", "安全", "设计", "检查"], "answer": [0], "explanation": "装配式混凝土建筑施工现场，注浆机等机具验收使用，须有验收挂牌或允许使用的识别标志，安全可靠。"},
  {"id": 584, "type": "single", "question": "塔机在施工中主要作用是重物的 （　　） 运输和施工现场内的 （　　） 距离水平运输。", "options": ["垂直，长", "垂直，短", "水平，长", "水平，短"], "answer": [1], "explanation": "塔机在施工中主要用于建筑结构和工业设备的安装,吊运建筑材料和建筑构件。它的主要作用是重物的垂直运输和施工现场内的短距离水平运输。"},
  {"id": 585, "type": "single", "question": "额定起重力矩为50吨米的塔式起重机，最大幅度为30米时，相应额定起重量为 （　　） t。", "options": ["1", "1.26", "1.34", "1.67"], "answer": [3], "explanation": "【依据】《建筑起重机械安全监督管理规定》 / 《塔式起重机安全规程》GB 5144-2006\n【解析】正确答案是D。题干对应的是塔式起重机安全管理。 A项“1”错误，题干对应的控制数值不是1，正确值应为1.67。 B项“1.26”错误，它说的是“1.26”，并非题干要找的“1.67”。 C项“1.34”错误，它说的是“1.34”，并非题干要找的“1.67”。 D项“1.67”正确，它与题干所述“额定起重力矩为50吨米的塔式起重机，最大幅度”相对应。"},
  {"id": 586, "type": "single", "question": "轮胎塔式起重机的特性代号是 （　　） 。", "options": ["QTL", "QTV", "QTU", "QTD"], "answer": [0], "explanation": "轮胎式塔式起重机:QTL"},
  {"id": 587, "type": "single", "question": "履带塔式起重机的特性代号是 （　　） 。", "options": ["QTL", "QTV", "QTU", "QTD"], "answer": [2], "explanation": "履带式塔式起重机:QTU"},
  {"id": 588, "type": "single", "question": "塔式起重机最高附着点以上的最大可安装高度是指 （　　） 。", "options": ["固定高度", "自由高度", "起升高度", "工作高度"], "answer": [1], "explanation": "塔吊自由高度要区别于独立高度，塔吊独立高度指的是不扶墙的最大可安装高度；自由高度，指的是扶墙后，扶墙以上最高可安装（不进行下一道扶墙）高度。"},
  {"id": 589, "type": "single", "question": "塔式起重机的型号QTZ80C中，QTZ是指 （　　） 。", "options": ["上回转自升塔式起重机", "下回转塔式起重机", "内爬升式塔式起重机", "固定式塔式起重机"], "answer": [0], "explanation": "QTZ系列自升式塔式起重机"},
  {"id": 590, "type": "single", "question": "塔式起重机和220kV输电线路之间的安全距离，垂直方向需达到至少 （　　） m。", "options": ["3", "4", "5", "6"], "answer": [3], "explanation": "【依据】《建筑起重机械安全监督管理规定》 / 《塔式起重机安全规程》GB 5144-2006\n【解析】正确答案是D。题干对应的是塔式起重机安全管理。 A项“3”错误，题干对应的控制数值不是3，正确值应为6。 B项“4”错误，题干对应的控制数值不是4，正确值应为6。 C项“5”错误，题干对应的控制数值不是5，正确值应为6。 D项“6”正确，规范要求的控制数值或时限就是6。"},
  {"id": 591, "type": "single", "question": "一般自升塔式起重机的安装程序中，安装平衡臂后，应当 （　　） 。", "options": ["安装起重臂和变幅小车，穿绕起升钢丝绳", "组拼安装转台、回转支承装置", "顶升接高标准节到需要高度", "安装塔帽和驾驶室"], "answer": [0], "explanation": "铺设轨道基础或固定基础→安装行走台车及底架→安装塔身基础节和两个标准节→安装斜撑杆→放置压重→安装顶升套架和液压顶升装置→组拼安装转台、回转支承装置。承座及过渡节→安装塔帽和驾驶室→装平衡臂→安装起重臂和变幅小车，穿绕起升钢丝绳→顶升接高标准节到需要高度。"},
  {"id": 592, "type": "single", "question": "安装附着框架和附着杆件时，应用经纬仪测量塔身垂直度，并应利用附着杆件进行调整，在最高锚固点以下垂直度允许偏差为 （　　） 。", "options": ["1%", "2%", "1‰", "2‰"], "answer": [3], "explanation": "安装附着框架和附着杆件时,应用经纬仪测量塔身垂直度,并应利用附着杆件进行调整,在最高锚固点以下垂直度允许偏差为2/1000。"},
  {"id": 593, "type": "single", "question": "塔机司机每年需进行体检，患有 （　　） ，仍能做塔机司机。", "options": ["色盲", "心脏病", "高血压", "贫血"], "answer": [3], "explanation": "每年须对塔吊司机进行一次身体检查，患有色盲、矫正视力低于1.0、听觉障碍、心脏病等妨碍起重作业的其他疾病者，不能做司机工作。"},
  {"id": 594, "type": "single", "question": "塔机若回转部分不设集电器，应安装回转限位器，在作业时，不得顺一个方向连续回转 （　　） 圈。", "options": ["1.5", "2", "2.5", "3"], "answer": [0], "explanation": "回转部分不设集电器的塔式起重机,应按照回转限位器,在作业时,不得顺一个方向连续回转1.5圈。"},
  {"id": 595, "type": "single", "question": "雨天后，对 （　　） 塔式起重机应检查混凝土基础不均匀沉降。", "options": ["行走式", "车载式", "内爬式", "固定式"], "answer": [3], "explanation": "雨天后,对行走式塔式起重机,应检查轨距偏差、钢轨顶面的倾斜度、轨道基础的沉降、钢轨的平直度及轨道的通过性能等;对固定式塔式起重机,应检查混凝土基础不均匀沉降。"},
  {"id": 596, "type": "single", "question": "配电箱应设置在距塔机 （　　） m范围内或轨道中部，且明显可见。", "options": ["2", "3", "4", "5"], "answer": [1], "explanation": "施工现场塔机配电箱应设置在距塔机3m范围内或轨道中部，且明显可见。"},
  {"id": 597, "type": "single", "question": "两台塔机之间的最小架设水平安全距离和垂直安全距离不应小于 （　　） m。", "options": ["2", "3", "4", "5"], "answer": [0], "explanation": "两台塔机之间的最小架设距离应保证2米。"},
  {"id": 598, "type": "single", "question": "塔式起重机安装、拆卸单位必须建立健全 （　　） ，明确塔式起重机安装、拆卸的主管领导、工程技术人员、机械管理员、安全员和塔机装卸工在拆装起重机中的岗位职责。", "options": ["技术交底制", "事故责任制", "技术培训制", "岗位责任制"], "answer": [3], "explanation": "第十二条 塔式起重机拆装单位必须建立健全岗位责任制,明确现场指挥和司机、钳工、 电工、起重工、信号工等作业人员的职责。拆装作业人员实行持证上岗。"},
  {"id": 599, "type": "single", "question": "内爬升作业应在白天进行。风力超过 （　　） 级时，应停止作业。", "options": ["2", "3", "4", "5"], "answer": [3], "explanation": "内爬升作业应在白天进行。风力在五级及以上时,应停止作业。"},
  {"id": 600, "type": "single", "question": "地基加固工程，应在正式施工前进行试验段施工，论施工参数及加固效果进行论证。验证加固效果的载荷试验最大加载压力不应小于设计要求压力值的 （　　） 倍。", "options": ["2", "3", "4", "5"], "answer": [0], "explanation": "最大加载压力不应小于设计要求压力值的2倍。"},
  {"id": 601, "type": "single", "question": "运载装置不可进人的倾斜式货用升降机，最大额定载荷为 （　　） kg。", "options": ["200", "250", "300", "350"], "answer": [2], "explanation": "运载装置不可进人的倾斜式货用升降机的运载装置由钢丝绳卷筒(卷扬机)驱动,运载装置最大额定载荷为300 kg。"},
  {"id": 602, "type": "single", "question": "防坠安全器只能在有效的标定期限内使用，有效标定期限 （　　） 。", "options": ["一年", "不应超过一年", "两年", "不应超过两年"], "answer": [1], "explanation": "防坠安全器:防坠安全器只能在有效的标定期限内使用,有效标定期限不应超过一年。"},
  {"id": 603, "type": "single", "question": "对于额定提升速度不超过 （　　） m/s的施工升降机，可采用瞬时式安全器。", "options": ["0.6", "0.63", "0.65", "0.68"], "answer": [1], "explanation": "对于额定提升速度不超过0.63m/s的施工升降机,可采用瞬时式安全器,否则应采用渐进式安全器;"},
  {"id": 604, "type": "single", "question": "防坠安全器钢丝绳的张紧力应为安全装置起作用所需力的两倍，但不应小于 （　　） N。", "options": ["200", "300", "400", "500"], "answer": [1], "explanation": "防坠安全器钢丝绳的张紧力应为安全装置起作用所需力的两倍,但不应小于300N;"},
  {"id": 605, "type": "single", "question": "作缆风绳用钢丝绳的安全系数为 （　　） 。", "options": ["2.5", "3.0", "3.5", "4.0"], "answer": [2], "explanation": "在起重吊装中,用作缆风绳的安全系数不小于3.5"},
  {"id": 606, "type": "single", "question": "用于载人的升降机的钢丝绳的安全系数为 （　　） 。", "options": ["10", "12", "14", "16"], "answer": [2], "explanation": "用于载人的升降机钢丝绳的安全系数是14。"},
  {"id": 607, "type": "single", "question": "钢丝绳按绳芯的类别分为纤维芯钢丝绳和 （　　） 钢丝绳。", "options": ["铜芯", "铁芯", "钢芯", "空芯"], "answer": [2], "explanation": "钢丝绳按绳芯的不同分为纤维芯和钢芯。"},
  {"id": 608, "type": "single", "question": "钢丝绳其断丝数在一个节距内超过总丝数的 （　　） 应报废。", "options": ["5%", "8%", "10%", "12%"], "answer": [2], "explanation": "钢丝绳报废标准：钢丝绳在一个捻节距内断丝数达钢丝绳总丝数的 10%。"},
  {"id": 609, "type": "single", "question": "为了保证吊装的安全，钢丝绳根据使用时的受力情况，规定出所能允许承受的最大拉力，叫钢丝绳的 （　　） 拉力。", "options": ["弹性", "阈限", "安全", "强度"], "answer": [2], "explanation": "钢丝绳安全系数为了保证吊装的安全,钢丝绳根据使用时的受力情况,规定出所能允许承受的最大拉力,叫钢丝绳的安全拉力。"},
  {"id": 610, "type": "single", "question": "起重机械不得使用 （　　） 的吊钩。", "options": ["片式", "锻造", "铸造", "单钩"], "answer": [2], "explanation": "起重机械不得使用铸造的吊钩。"},
  {"id": 611, "type": "single", "question": "高空作业车是指 （　　） m以上，其是指采用液压传动的载人高空作业车。", "options": ["2", "3", "4", "5"], "answer": [1], "explanation": "高空车是指3米以上，由液压或电动系统支配多支液压油缸，能够上下举升进行作业的一种车辆。采用液压传动的载人高空车，是当代先进的特种机械设备。施工人员借助高空车升空工作，只要正确使用，安全得到保证。"},
  {"id": 612, "type": "single", "question": "当建筑物高度超过 （　　） m时，应设置双层防护棚。", "options": ["16", "20", "24", "32"], "answer": [2], "explanation": "施工升降机地面通道上方应搭设防护棚。当建筑物高度超过【24】m时，应设置双层防护棚。"},
  {"id": 613, "type": "single", "question": "当建筑物超过 （　　） 层时，施工升降机地面通道上方应搭设防护棚。", "options": ["2", "3", "4", "5"], "answer": [0], "explanation": "【依据】《建筑施工高处作业安全技术规范》JGJ 80-2016\n【解析】正确答案是A。题干对应的是建筑施工高处作业防护。 A项“2”正确，规范要求的控制数值或时限就是2。 B项“3”错误，题干对应的控制数值不是3，正确值应为2。 C项“4”错误，题干对应的控制数值不是4，正确值应为2。 D项“5”错误，题干对应的控制数值不是5，正确值应为2。"},
  {"id": 614, "type": "single", "question": "施工升降机每3个月应进行1次 （　　） 倍额定重量的超载试验，确保制动器性能安全可靠。", "options": ["1.1", "1.15", "1.2", "1.25"], "answer": [3], "explanation": "施工升降机每3个月进行1次1.25倍额定重量的超载试验,确保制动器性能安全可靠。"},
  {"id": 615, "type": "single", "question": "最大作业高度大于 （　　） m的作业车，工作平台上应设风速测量仪。", "options": ["10", "20", "30", "40"], "answer": [2], "explanation": "《高空作业车》大于30m的高空作业车应配备风速仪、支腿与伸展结构互锁、作业车额定载荷的安全保护等安全要求；"},
  {"id": 616, "type": "single", "question": "高空作业车的专用车用途特征代号是 （　　） 。", "options": ["HK", "GC", "GH", "GK"], "answer": [3], "explanation": "高空作业车规格型号\n作业车规格型号由代号、产品参数等组成。下面以XZ5040JGKZ14A型高空作业车为例对产品型号的编制方法加以说明。\n（1）企业代号。国家对国内每个汽车生产企业给定唯一的企业代号。如：XHZ是徐州海伦哲专用车辆有限公司的企业代号。\n（2）车辆类别代号。专用汽车类别代号为：5。\n（3）产品主参数。专用汽车的产品主参数为车辆的总重，该产品总重为3.5t≤G≤4.5t，因此该车主参数为04。\n（4）产品序号。第一次设计序号为0，第一次改型，序号为1，依此类推。\n（5）专用汽车分类代号。J表示起重举升类汽车。\n（6）用途特征代号。GK表示高空。\n（7）企业自定代号。由企业根据自身情况确定。"},
  {"id": 617, "type": "single", "question": "作业车安装荷载保护装置时，在达到额定载重量后，超过额定载重量的 （　　） 时，应停止工作平台从静止工作位置上移动。", "options": ["90%", "100%", "110%", "120%"], "answer": [2], "explanation": "施工升降机应安装超载保护装置。超载保护装置在荷载达到额定载重量的110%前应能中止吊笼启动，在齿轮齿条式载人施工升降机荷载达到额定载重量的90%时应能给出报警信号。"},
  {"id": 618, "type": "single", "question": "高空作业车的调平机构应保证工作平台在任一工作位置均处于水平状态，工作平台底面与水平面的夹角应不大于 （　　） 。", "options": ["5°", "7°", "10°", "15°"], "answer": [0], "explanation": "作业车的调平机构应保证工作平台在任一工作位置均处于水平状态，工作平台底面与水平面的夹角应不大于5°，调平过程必须平稳、可靠，不得出现振颤、冲击、打滑等现象。"},
  {"id": 619, "type": "single", "question": "使用作业高度 （　　） m以上作业车，除设置好安全标志及护栏外，地面监护人除司机外，还要设1-2人专责加强监护。", "options": ["10", "15", "20", "25"], "answer": [3], "explanation": "使用作业高度 25 米以上作业车,除设置好安全标示及护栏外,地 面监护人除司机外,还要设 1-2 人专职加强监护。"},
  {"id": 620, "type": "single", "question": "封闭或部分封闭，进出口较为狭窄有限，未被设计为固定工作场所，自然通风不良，易造成有毒有害、易燃易爆物质积聚或氧含量不足的空间，称 （　　） 。", "options": ["建筑有限空间", "建筑密闭空间", "施工封闭空间", "施工狭窄空间"], "answer": [0], "explanation": "有限空间是指封闭或部分封闭，进出口较为狭窄有限，未被设计为固定工作场所，自然通风不良，易造成有毒有害、易燃易爆物质积聚或氧含量不足的空间。"},
  {"id": 621, "type": "single", "question": "有限空间是指与外界相对隔离，进出口受限，自然通风不良，足够容纳一人进入并从事非常规、非连续性作业的有限空间。下列各组场所中，均属于密闭空间的是 （　　）  。", "options": ["炉、塔、釜、罐、储藏室", "沟、坑、井、池、锅炉房", "炉、塔、沟、坑、配电间", "釜、罐、井、池、仪表间"], "answer": [0], "explanation": "有限空间分类三类：一是密闭设备，如贮罐、车载槽罐、反应塔（釜）、冷藏箱、压力容器、管道、烟道、锅炉等；二是地下有限空间，如地下管道、地下室、地下仓库、地下工程、暗沟、隧道、涵洞、地坑、废井、地窖、污水池（井）、沼气池、化粪池、下水道等；三是地上有限空间，如储藏室、酒糟池、发酵池、垃圾站、温室、冷库、粮仓、料仓等。"},
  {"id": 622, "type": "single", "question": "在有限空间内由于通风不良、生物的呼吸作用或物质的氧化作用会使有限空间形成缺氧状态。单纯性窒息气体也会引发窒息事故，其本身无毒，但排挤氧空间，造成作业人员缺氧窒息。下列不是导致单纯性窒息的气体是 （　　） 。", "options": ["一氧化碳", "二氧化碳", "甲烧", "六氟化氯"], "answer": [0], "explanation": "一氧化碳为中毒窒息气体。"},
  {"id": 623, "type": "single", "question": "实施有限空间作业前，作业单位应对作业环境及作业过程进行风险评估，分析可能存在的危险有害因素，提出消除、控制危害的措施，制订作业方案，并经本单位 （　　） 人员审核，负责人批准。", "options": ["安全生产管理", "技术", "施工管理", "质量管理"], "answer": [0], "explanation": "实施有限空间作业前，作业单位应对作业环境及作业过程进行风险评估，分析可能存在的危险有害因素，提出消除、控制危害的措施，制定作业方案，并经本单位安全生产管理人员审核，负责人批准。"},
  {"id": 624, "type": "single", "question": "有限空间作业监护者的职责不包括 （　　） 。", "options": ["接受本单位职业卫生培训，持证上岗", "检查、验证应急救援服务、呼叫方法的效果", "在作业者作业期间保证在密闭空间外持续监护", "与作业者进行必要有效的安全、报警、撤离等信息沟通"], "answer": [0], "explanation": "【依据】《生产安全事故应急条例》 / 《生产经营单位生产安全事故应急预案编制导则》GB/T 29639-2020\n【解析】正确答案是B。这是一道反向设问题，题干要找的是“不符合/不属于/错误”项。 A项“接受本单位职业卫生培训，持证上岗”错误，它不符合题干限定的对象、程序或条件。 B项“检查、验证应急救援服务、呼叫方法的效果”正确，它与题干所述“有限空间作业监护者的职责不包括”相对应。 C项“在作业者作业期间保证在密闭空间外持续监护”错误，它不符合题干限定的对象、程序或条件。 D项“与作业者进行必要有效的安全、报警、撤离等信息沟通”错误，它不符合题干限定的对象、程序或条件。"},
  {"id": 625, "type": "single", "question": "有限空间气体检测报警仪应由法定计量检定机构 （　　） 至少检定1次，检定合格后方可使用，日常使用时应确保零值准确。", "options": ["每季度", "每半年", "每月", "每年"], "answer": [3], "explanation": "气体检测报警仪应由法定计量检定机构每年至少检定1次,检定合格后方可使用。 日常使用时应确保零值准确。"},
  {"id": 626, "type": "single", "question": "可燃性气体、 （　　） 和蒸气应设定预警值和报警值两级检测报警值。", "options": ["氧气", "温度", "有毒有害气体", "湿度"], "answer": [2], "explanation": "可燃性和有毒有害气体、蒸气应设定预警值和报警值两级检测报警值"},
  {"id": 627, "type": "single", "question": "有限空间内宜设置 （　　） 气体检测报警仪，并在作业过程中全程运行。", "options": ["固定式", "便携式", "移动式", "防爆式"], "answer": [0], "explanation": "有限空间内宜设置固定式气体检测报警仪,并在作业过程中全程运行。"},
  {"id": 628, "type": "single", "question": "有限空间应急救援预案 （　　） 至少进行1次应急培训与演练。", "options": ["每两年", "每年", "每季度", "每半年"], "answer": [1], "explanation": "有限空间作业事故专项应急预案应每年至少组织1次演练,现场处置方案应至少每半年组织1次演练。"},
  {"id": 629, "type": "single", "question": "存在有限空间的单位应对相关人员每年至少组织 （　　） 次有限空间作业安全专项培训。", "options": ["1", "2", "3", "4"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】正确答案是A。题干对应的是建筑施工安全管理。 A项“1”正确，规范要求的控制数值或时限就是1。 B项“2”错误，题干对应的控制数值不是2，正确值应为1。 C项“3”错误，题干对应的控制数值不是3，正确值应为1。 D项“4”错误，题干对应的控制数值不是4，正确值应为1。"},
  {"id": 630, "type": "single", "question": "进入密闭空间作业，应严格执行作业审批制度和 （　　） 的规定。", "options": ["“先通风、后作业”", "“先通风、作业后再检测”", "“先作业、再通风、后检测”", "“先通风、再检测、后作业”"], "answer": [3], "explanation": "严格执行“先通风、再检测、后作业”的原则 未经通风和检测,严禁作业人员进入有限空间作业。"},
  {"id": 631, "type": "single", "question": "有限空间作业时应保证足够照明，照明灯采用带胶罩的工作灯，照明电压应小于 （　　） V。", "options": ["48", "36", "24", "12"], "answer": [1], "explanation": "进入有限空间作业应有足够的照明，设备内照明电压应不大于36V。在潮湿或狭小容器内作业应小于12V，所有灯具及电动工具必须符合防潮、防爆等安全要求；"},
  {"id": 632, "type": "single", "question": "对有限空间内照明及安全用电的说法，正确的是 （　　） 。", "options": ["有限空间照明电压应小于或等于220V", "有限空间照明电压应小于或等于48V", "潮湿、狭小容器内作业电压应小于或等于24V", "潮湿、狭小容器内作业电压应小于或等于12V"], "answer": [3], "explanation": "受限空间照明电压应小于或等于 36V,在潮湿容器、狭小容器内作业电压应小于或等于 12V;"},
  {"id": 633, "type": "single", "question": "有限空间作业时，当需要使用电动工具或照明电压大于24V时，应按规定安装漏电保护器，其接线箱（板）必须放置在 （　　） 。", "options": ["内部", "外部", "顶部", "底部"], "answer": [1], "explanation": "【依据】《施工现场临时用电安全技术规范》JGJ 46-2005\n【解析】正确答案是B。题干对应的是施工现场临时用电。 A项“内部”错误，它说的是“内部”，并非题干要找的“外部”。 B项“外部”正确，它与题干所述“有限空间作业时，当需要使用电动工具或照明电压”相对应。 C项“顶部”错误，它说的是“顶部”，并非题干要找的“外部”。 D项“底部”错误，它说的是“底部”，并非题干要找的“外部”。"},
  {"id": 634, "type": "single", "question": "在有限空间使用超过安全电压的手持电动工具作业或进行电焊作业时，应配备 （　　） 。", "options": ["熔断器", "热继电器", "漏电保护器", "控制器"], "answer": [2], "explanation": "使用超过安全电压的手持电动工具作业或进行电焊作业时,应配备漏电保护器。在潮湿容器中,作业人员应站在绝缘 板上,同时保证金属容器接地可靠。"},
  {"id": 635, "type": "single", "question": "有限空间作业气体检测是保证作业安全的重要手段之一，有限空间作业必须坚持“先通风，再检测，后作业”的原则。下列关于气体通风检测的说法中，错误的是 （　　）  。", "options": ["在作业人员进入有限空前，应对作业场内的所有气体进行检测以判断其内部环境是否适合人员进入", "在作业过程中，还应通过实时检测，及时了解气体浓度变化", "气体检测合格后，对有限空间作业可以停止通风换气", "使用风机强制通风时，若检测结果显示处于易燃易爆环境中必须使用防爆型风机"], "answer": [2], "explanation": "本题考查的是有限空间作业安全管理。无论气体检测合格与否，对有限空间作业都必须进行通风换气。"},
  {"id": 636, "type": "single", "question": "有限空间作业时，应对气体浓度进行严格监测，作业前 （　　） 分钟内，进行气体分析，分析合格后方可入内。", "options": ["45", "60", "90", "30"], "answer": [3], "explanation": "受限空间作业前（30）分钟内，应对受限空间进行气体采样分析，分析合格后方可进入。"},
  {"id": 637, "type": "single", "question": "进入自然通风换气效果不良的有限空间，应采用机械通风，通风换气次数每小时不能少于 （　　） 次。", "options": ["1", "2", "3", "4"], "answer": [2], "explanation": "进入自然通风换气效果不良的有限空间，应采用机械通风，通风换气次数每小时不能少于3次.对不能采用通风换气措施或受作业环境限制不易充分通风换气的场所，作业人员必须配备并使用空气呼吸器或软管面具等隔离式呼吸保护器具。严禁使用过滤式面具。"},
  {"id": 638, "type": "single", "question": "生产经营单位在 （　　） 应针对施工方案，对从事有限空间危险作业的人员进行作业内容、职业危害等教育；进行紧急情况下的个人避险常识、中毒窒息和其他伤害的应急救援措施教育。", "options": ["发生事故后", "作业前", "作业后", "作业时"], "answer": [1], "explanation": "生产经营单位在作业前应针对施工方案,对从事有限空间危险作业的人员进行作业内容、职业危害等教育;"},
  {"id": 639, "type": "single", "question": "对不能采用通风换气措施或受作业环境限制不易充分通风换气的场所，作业人员必须配备并使用 （　　） 呼吸保护器具。", "options": ["隔离式", "过滤式", "半闭式", "闭式内循环"], "answer": [0], "explanation": "对不能采用通风换气措施或受作业环境限制不易充分通风换气的场所，作业人员必须配备并使用空气呼吸器或软管面具等隔离式呼吸保护器具。严禁使用过滤式面具。"},
  {"id": 640, "type": "single", "question": "下列关于有限空间作业要求说法中，错误的是 （　　） 。", "options": ["未经作业负责人审批，任何人不得进入有限空间作业", "有限空间内部应设置醒目的警示标志，并告知作业者存在的危险有害因素和防控措施", "有限空间作业现场应明确作业负责人、监护人员和作业人员，不得在没有监护人的情况下作业", "生产经营单位委托承包单位进行有限空间作业时，不得将工程发包给不具备生产条件的单位和个人"], "answer": [1], "explanation": "有限空间出入口附近应设置醒目的警示标志，并告知作业者存在的危险有害因素和防控措施，防止未经许可人员进入作业现场。"},
  {"id": 641, "type": "single", "question": "有限空间作业涉及的行业领域多，不确定危险因素多，今年以来，有关行业领域连续发生多起有限空间较大生产安全事故。下列关于有限空间作业说法错误的是 （　　） 。", "options": ["遵守\"先通风、再检测、后作业\"的原则", "保持有限空间出人口畅通", "监护人员离开作业现场时，应与作业人员保持联系", "作业过程中，应当采取通风措施，保持空气流通"], "answer": [2], "explanation": "监护人员不得离开作业现场，并与作业人员保持联系"},
  {"id": 642, "type": "single", "question": "下列关于有限空间作业说法中，正确的是 （　　） 。", "options": ["有限空间作业许可证由作业单位负责办理并审批", ".作业前对有限空间进行清洗或置换，使含氧量为17%-21%", "若作业中断时间超过30min，应重新进行分析", "最早可以在作业前60min对有限空间进行气体分析"], "answer": [2], "explanation": "作业中断超过 30 min 应重新进行监测分析，对可能释放有害物质的受限空间，应连续监测。"},
  {"id": 643, "type": "single", "question": "下列关于有限空间作业安全措施的说法中，错误的是 （　　） 。", "options": ["有限空间作业中应定时监测，至少每2h监测一次", "在潮湿容器、狭小容器内作业电压应小于或等于36V", "在有限空间外应设有专人监护，作业期间监护人员不应离开", "易燃易爆的有限空间经清洗或置换仍达不到安全要求的应穿防静电工作服及防静电工作鞋，使用防爆型低压灯具及防爆工具"], "answer": [1], "explanation": "在潮湿容器、狭小容器内作业，电压应小于等于12伏。"},
  {"id": 644, "type": "single", "question": "施工现场用电设备在5台及以上或设备总容量在 （　　） kW及以上者，应编制用电组织设计。", "options": ["50", "45", "40", "35"], "answer": [0], "explanation": "施工现场用电设备在5台及以上或设备总容量在50kW及以上者，应编制用电组织设计，并且应由电气工程技术人员组织编写，经相关部门审核及具有法人资格企业的技术负责人批准后实施。"},
  {"id": 645, "type": "single", "question": "编制 （　　） 的目的是用以指导建造一个安全可靠、经济合理、方便适用、适应施工现场特点和用电特性的用电工程，并且用以指导所建用电工程的正确使用。", "options": ["用电计划", "临时用电计划", "电路图", "用电组织设计"], "answer": [3], "explanation": "编制用电组织设计的目的是用以指导建造一个安全可靠、经济合理、方便适用,适应施工现场特点和用电特性的用电工程,并且用以指导所建用电工程的正确使用。"},
  {"id": 646, "type": "single", "question": "临时用电负荷是电力负荷的简称，是指电气设备(例如电力变压器)中的 （　　） 。", "options": ["功率", "能耗", "电压", "电流"], "answer": [0], "explanation": "临时用电负荷作为电力负荷的简称，是指电气设备（如电力变压器）运行时涉及的电流、电压和功率的统称。但结合选项分析：\nA（功率）：包括有功功率、无功功率、视在功率，是负荷的核心参数之一，反映设备的能量消耗或容量。\nB（能耗）：指一段时间内消耗的总电量（如千瓦时），属于功率与时间的累积，非负荷的直接定义。\nC（电压）：是推动电荷流动的动力，与负荷相关但非负荷本身。\nD（电流）：是负荷的直观表现，负荷大小直接影响电流强度，但仅为负荷的一部分。\n题干中 “电力负荷” 的定义更侧重于设备运行时的能量参数，而功率（尤其是有功功率）是衡量负荷大小的核心指标（如变压器容量用视在功率表示，设备负荷用有功功率表示）。因此，最符合题意的选项为 A（功率）。"},
  {"id": 647, "type": "single", "question": "临时用电负荷计算的结果是配电系统设计中选择电气、导线、 （　　） ，以及供电变压器和发电机容量的重要依据。", "options": ["电线规格", "导线规格", "电缆规格", "电箱规格"], "answer": [2], "explanation": "负荷计算的结果是配电系统设计中选择电器、导线、电缆规格,以及供电变压器和发电机容量的重要依据。"},
  {"id": 648, "type": "single", "question": "变压器的选择主要是指为施工现场用电提供电力的 （　　） kV级电力变压器形式和容量的选择，选择的主要依据是现场总计算负荷。", "options": ["12/0.4", "10/0.4", "12/0.3", "10/0.3"], "answer": [1], "explanation": "选择变压器：施工现场电力变压器的选择主要是指为施工现场用电提供电力的10／0.4kV级电力变压器的形式和容量的选择。"},
  {"id": 649, "type": "single", "question": "配电系统的三部分中， （　　） 是整个配电系统的枢纽。", "options": ["配电装置", "配电线路", "接地装置", "安全装置"], "answer": [1], "explanation": "配电系统主要由配电线路、配电装置和接地装置三部分组成。其中配电线路是整个配电系统的枢纽。"},
  {"id": 650, "type": "single", "question": "按照《施工现场临时用电安全技术规范》JGJ46—2005的规定，所有防雷冲击接地电阻值均不得大于 （　　） Ω。", "options": ["20", "25", "30", "40"], "answer": [2], "explanation": "按照《施工现场临时用电安全技术规范》JGJ46一2005的规定,所有防雷冲击接地电阻值均不得大于30Ω。"},
  {"id": 651, "type": "single", "question": "保护零线PE必须采用 （　　） 双色线，严格与相线、工作零线相区别，不得混用。", "options": ["红／黄", "蓝／黄", "绿／红", "绿／黄"], "answer": [3], "explanation": "保护线PE必须采用绿/黄双色线,严格与相线、工作零线相区别,不得混用。"},
  {"id": 652, "type": "single", "question": "重复接地体符合要求，二根之间距离不小于 （　　） m，接地体不得采用螺纹钢。", "options": ["2", "2.5", "3", "5"], "answer": [1], "explanation": "严禁地零混接,接地体符合要求,二根之间距离不小于 2.5m,工作接地阻值 ≤4 欧姆,重复接地电阻≤10 欧姆接地,不得使用螺纹钢;"},
  {"id": 653, "type": "single", "question": "重复接地体符合要求，重复接地电阻值小于 （　　） Ω,接地体不得采用螺纹钢。", "options": ["5", "10", "15", "20"], "answer": [1], "explanation": "严禁地零混接,接地体符合要求,二根之间距离不小于 2.5m,工作接地阻值 ≤4 欧姆,重复接地电阻≤10 欧姆接地,不得使用螺纹钢;"},
  {"id": 654, "type": "single", "question": "电动机的绝缘电阻值不小于 （　　） MΩ。", "options": ["0.5", "1", "2", "7"], "answer": [0], "explanation": "电动机的绝缘一般只要大于0.5MΩ（兆欧）就可以使用,如果电机功率大于20千瓦绝缘就要大于5MΩ了.不管怎么说绝缘是越大越好."},
  {"id": 655, "type": "single", "question": "Ⅱ类工具的绝缘电阻值不小于 （　　） MΩ。", "options": ["0.5", "1", "2", "7"], "answer": [3], "explanation": "电动机的绝缘电阻值不小于0.5MΩ;Ⅰ类工具的绝缘电阻值不小于2MΩ;Ⅱ类工具的绝缘电阻值不小于7MΩ;Ⅲ类工具的绝缘电阻值不小于1MΩ"},
  {"id": 656, "type": "single", "question": "合理配置施工现场的临时供配电线路， （　　） 包括变压器、总配电箱（配电柜）、分配电箱、开关箱、无功补偿等，确保配电系统安全可靠。", "options": ["供配电装置", "接地装置", "用电设备", "电源进线线路"], "answer": [0], "explanation": "配电装置,包括总配电箱和分配电箱,如无特指,总配电箱、分配电箱合称配电箱。"},
  {"id": 657, "type": "single", "question": "三级配电是指施工现场从 （　　） 开始至用电设备之间，应经过三级配电装置配送电力。", "options": ["电源进线", "开关箱", "分配电箱", "总配电箱"], "answer": [0], "explanation": "三级配电是指施工现场从电源进线开始至用电设备之间，应经过三级配电装置配送电力。"},
  {"id": 658, "type": "single", "question": "级配电应经过三级配电装置配送电力，其中二级箱是指 （　　） 。", "options": ["变压器", "开关箱", "分配电箱", "总配电箱"], "answer": [2], "explanation": "总配电箱(一级箱)或配电室的配电柜开始，依次经由分配电箱(二级箱)、开关箱(三级箱)到用电设备，这种分三个层次逐级配送电力的系统就是三级配电系统。"},
  {"id": 659, "type": "single", "question": "按照三级配电系统应遵守的 （　　） 规则的要求，在三级配电系统中，任何用电设备均不得越级配电，即其电源线不得直接连接于分配电箱或总配电箱。", "options": ["分级分路", "动、照分设", "压缩配电间距", "环境安全"], "answer": [0], "explanation": "教材P221页：\n按照分级分路规则的要求，在三级配电系统中，任何用电设备均不得越级配电，即其电源线不得直接连接于分配电箱或总配电箱；任何配电装置不得挂接其他临时用电设备。否则，三级配电系统的结构形式和分级分路规则将被破坏。"},
  {"id": 660, "type": "single", "question": "若动力与照明合置于同一配电箱内共箱配电，则动力与照明应 （　　） 。", "options": ["分路配电", "分级分路", "压缩配电间距", "分箱设置"], "answer": [0], "explanation": "动力和照明分设规则：1）动力配电箱与照明配电箱宜分别设置；若动力与照明合置于同一配电箱内共箱配电，则动力与照明应分路配电。2）动力开关箱与照明开关箱必须分箱设置，不存在共箱分路设置问题。"},
  {"id": 661, "type": "single", "question": "压缩配电间距规则中规定分配电箱与开关箱的距离不得超过 （　　） m。", "options": ["20", "30", "40", "50"], "answer": [1], "explanation": "分配电箱与开关箱的距离不得超过30m。"},
  {"id": 662, "type": "single", "question": "压缩配电间距规则中规定关箱与其供电的固定式用电设备的水平距离不宜超过 （　　） m。", "options": ["3", "4", "5", "6"], "answer": [0], "explanation": "开关箱与其供电的固定式用电设备的水平距离不宜超过3m。"},
  {"id": 663, "type": "single", "question": "环境安全规则是指 （　　） 对其设置和运行环境安全因素的要求。主要是指对易燃易爆物、腐蚀介质、机械损伤、电磁感应、静电等因素的防护要求，防止由其引发设备损坏、触电和电气火灾事故。", "options": ["配电线路", "配电装置", "接地装置", "配电系统"], "answer": [3], "explanation": "环境安全规则是指配电系统对其设置和运行环境安全因素的要求。主要是指对易燃易爆物、腐蚀介质、机械损伤、电磁感应、静电等因素的防护要求，防止由其引发设备损坏、触电和电气火灾事故。"},
  {"id": 664, "type": "single", "question": "根据现行行业标准《建筑施工安全检查标准》JGJ59规定，配电室建筑耐火等级应不低于 （　　） 级并配备合格的消防器材。", "options": ["1", "2", "3", "4"], "answer": [2], "explanation": "配电室建筑耐火等级不低于3级并配备合格的消防器材;"},
  {"id": 665, "type": "single", "question": "配电室天棚的高度应当距离地面不低于 （　　） m。", "options": ["1", "2", "3", "3.5"], "answer": [2], "explanation": "配电室天棚的高度应当距离地面不低于3m。"},
  {"id": 666, "type": "single", "question": "配电柜正面的操作通道宽度，单列布置或双列背对背布置时不应小于 （　　） m。", "options": ["0.5", "1", "1.5", "2"], "answer": [2], "explanation": "配电柜正面的操作通道宽度,单列布置或双列背对背布置不小于1.5m,双列面对面布置不小于2m;"},
  {"id": 667, "type": "single", "question": "配电柜侧面的维护通道宽度不应小于 （　　） m。", "options": ["1", "2", "3", "3.5"], "answer": [0], "explanation": "配电柜侧面的维护通道宽度不小于1m,配电室的棚顶与地面的距离不低于3m;"},
  {"id": 668, "type": "single", "question": "配电室的照明包括两个彼此独立的照明系统：一是正常照明，二是事故照明。事故照明不受配电室 （　　） 控制。", "options": ["总配电箱", "分配电箱", "开关箱", "电源进线"], "answer": [0], "explanation": "配电室的照明应包括两个彼此独立的照明系统。一是正常照明，二是事故照明，事故照明应不受配电室总配电箱控制。"},
  {"id": 669, "type": "single", "question": "配电装置上端(含配电柜顶部与配电母线排)距天棚不应小于 （　　） m。", "options": ["0.5", "1", "1.5", "2"], "answer": [0], "explanation": "配电装置上端(含配电柜顶部与配电母线排)距天棚不小于0.5m。"},
  {"id": 670, "type": "single", "question": "施工现场设置的自备电源，即是指自备的 （　　） 发电机组。", "options": ["110/400V", "220/400V", "230/400V", "380/400V"], "answer": [2], "explanation": "自备电源的设置:施工现场设置的自备电源,即是指自行设置的230/400V发电机组。"},
  {"id": 671, "type": "single", "question": "配电室内设值班室或检修室时，该室边缘距配电柜的水平距离应大于 （　　） m，并采取屏障隔离。", "options": ["0.5", "1", "1.5", "2"], "answer": [1], "explanation": "配电室内设置值班或检修室时,该室边缘距配电柜的水平距离大于 1m, 并采取屏障隔离;"},
  {"id": 672, "type": "single", "question": "配电箱、开关箱的箱体采用冷轧钢板制作时，钢板厚度应为1.2-2.0mm，配电箱的箱体厚度不得小于 （　　） mm。", "options": ["0.8", "1.0", "1.2", "1.5"], "answer": [3], "explanation": "配电箱、开关箱应采用冷轧钢板制作，钢板厚度为1.2~2.0mm，其中开关箱箱体钢板厚度不得小于1.2mm，配电箱箱体钢板厚度不得小于1.5mm，箱门均应设加强筋，箱体表面应做防腐处理。固定式配电箱、开关箱的中心点与地面的垂直距离应为1.4~1.6m。移动式配电箱、开关箱应装设在坚固、稳定的支架上。其中心点与地面的垂直距离宜为0.8~1.6m。"},
  {"id": 673, "type": "single", "question": "配电箱、开关箱内电器安装，电器至板边最小净距为 （　　）  mm。", "options": ["20", "30", "40", "50"], "answer": [2], "explanation": "【依据】《施工现场临时用电安全技术规范》JGJ 46-2005\n【解析】正确答案是B。题干对应的是施工现场临时用电。 A项“20”错误，题干对应的控制数值不是20，正确值应为30。 B项“30”正确，规范要求的控制数值或时限就是30。 C项“40”错误，题干对应的控制数值不是40，正确值应为30。 D项“50”错误，题干对应的控制数值不是50，正确值应为30。"},
  {"id": 674, "type": "single", "question": "电源隔离功能是指所选配的电器分断时具有可见分断点，并能同时断开电源所有极，因此这类电器称为 （　　） 。", "options": ["隔离开关", "断路器", "漏电保护器的组合", "漏电断路器"], "answer": [0], "explanation": "隔离开关应设置于电源进线端，应采用分断时具有可见分断点，并能同时断开电源所有极的隔离电器。如采用分断时具有可见分断点的断路器，可不另设隔离开关。"},
  {"id": 675, "type": "single", "question": "所选配的电器能够在配电系统空载或正常负载情况下可靠、有效地分断电路（非频繁操作），即 （　　） 功能。", "options": ["电源隔离", "正常接通与分断电路", "过载、短路、漏电保护", "空载接通与分断电路"], "answer": [1], "explanation": "正常接通与分断电路功能:所谓正常接通与分断电路功能是指所选配的电器能够在配电系统空载或正常负载情况下可靠、有效地 接通与分断电路(非频繁操作)。"},
  {"id": 676, "type": "single", "question": "总配电箱应设置的设备不包括 （　　） 。", "options": ["电源隔离开关", "断路器", "漏电保护器", "开关箱"], "answer": [3], "explanation": "总配电箱应设置电源隔离开关、断路器或熔断器、漏电保护器。功能；1 接收电源，分路分配电源电路。2 隔离的功能，3 短路和过载的保护功能，4 漏电的保护功能，5 TN-s接零接地保护系统。"},
  {"id": 677, "type": "single", "question": "当分路所设漏电保护器是同时具备短路、过载、漏电保护功能的漏电断路器时，可不设 （　　） 。", "options": ["总隔离开关", "分路隔离开关", "分路熔断器", "总断熔器"], "answer": [2], "explanation": "当分路所设漏电保护器是同时具备短路、过载、漏电保护功能的漏电断路器时,可不设分路断路器或分路熔断器。"},
  {"id": 678, "type": "single", "question": "总电源隔离开关的缩写为 （　　） 。", "options": ["DK", "RCD", "KK", "PE"], "answer": [0], "explanation": "DK-总电源隔离开关"},
  {"id": 679, "type": "single", "question": "在采用二级漏电保护的配电系统中，分配电箱中不要求设置 （　　） 装置。", "options": ["电源隔离开关", "过载与短路保护器", "漏电保护器", "分路熔断器"], "answer": [2], "explanation": "在采用二级漏电保护的配电系统中,分配电箱中不要求设置漏电保护器。"},
  {"id": 680, "type": "single", "question": "①开关箱②总配电箱③分配电箱，送电操作顺序应为 （　　） 。", "options": ["①②③", "③②①", "②①③", "②③①"], "answer": [3], "explanation": "送电操作顺序为：总配电箱(配电柜) — 分配电箱 — 开关箱；"},
  {"id": 681, "type": "single", "question": "施工现场下班停止工作时，必须将班后不用的配电装置分闸断电并上锁。班中停止作业 （　　） 小时及以上时，相关动力开关箱应断电上锁。", "options": ["0.5", "1", "2", "3"], "answer": [1], "explanation": "6) 施工现场下班停止工作时，必须将班后不用的配电装置分闸断电并上锁。班中停止作业1h及以上时，相关动力开关箱应断电上锁。暂时不用的配电装置也应断电上锁。"},
  {"id": 682, "type": "single", "question": "配电装置的漏电保护器应于每次使用时首先用试验按钮试跳 （　　） 次，只有试跳正常才可继续使用。", "options": ["1", "2", "3", "4"], "answer": [0], "explanation": "配电装置的漏电保护器应于每次使用时用试验按钮试跳一次,只有试跳正常才可继续使用。"},
  {"id": 683, "type": "single", "question": "在供配电系统中，除了有配电装置作为配电枢纽以外，还必须有连结配电装置和用电设备，传输、分配电能的电力路线，这就是 （　　） 。", "options": ["配电线路", "输电线路", "架空线路", "电缆线路"], "answer": [0], "explanation": "在供配电系统中,除了有配电装置作为配电枢纽以外,还必须有联结配电装置和用电设备、传输、分配电能的电力线路,这就是配电线路。"},
  {"id": 684, "type": "single", "question": "架空导线截面积的选择不仅要通过负荷计算，使其满足导线中的负荷电流不大于其允许截流量，还必须考虑其 （　　）  。", "options": ["电缆结构", "机械强度", "绝缘强度", "环境温度"], "answer": [1], "explanation": "架空导线的截面积的选择不仅要通过负荷计算,使其满足导线中的负荷电流不大于其允许载流量,还必须考虑其机械强度。"},
  {"id": 685, "type": "single", "question": "架空线路必须采用绝缘铜线或绝缘铝线，为保证机械强度；铜线的截面积不得小于 （　　） m㎡。", "options": ["10", "12", "14", "16"], "answer": [0], "explanation": "室外架空线路必须采用绝缘铜线或绝缘铝线,铝线的截面积大于16m㎡,铜线的截面积大于10m㎡."},
  {"id": 686, "type": "single", "question": "架空线的绝缘色标准为：当考虑相序排列时：L1(A相)一 （　　） ；L2(B相)一 （　　） ；L3(C相)一 （　　） 。", "options": ["红；绿；黄", "红；黄；绿", "黄；红；绿", "黄；绿；红"], "answer": [3], "explanation": "架空线的绝缘色标准为:为考虑相序排列时:L1(A 相)—黄色;L2(B 相)—绿色;L3(C 相)—红色。"},
  {"id": 687, "type": "single", "question": "空线的绝缘色标准为：PE线一 （　　） /双色。", "options": ["黄/红", "黄/绿", "绿/黄", "绿/红"], "answer": [2], "explanation": "N 线—淡蓝色;PE 线—绿/黄双色"},
  {"id": 688, "type": "single", "question": "根据架空线的敷设要求，动力、照明线在同一横担上架设时，导线相序排列顺序是：面向负荷从左侧起依次为: （　　） 。", "options": ["L1、L2、L3、N、PE", "L1、N、L2、L3、PE", "L1、L2、N、L3、PE", "N、L1、L2、L3、PE"], "answer": [1], "explanation": "动力、照明线在同一横担上架设时，导线相序排列是：面向负荷从左侧起依次为 L1、N、L2、L3、PE。"},
  {"id": 689, "type": "single", "question": "电缆埋地宜采用直埋方式，埋设深度不应小于 （　　） m。", "options": ["0.5", "0.6", "0.7", "0.8"], "answer": [2], "explanation": "电缆埋地宜采用直埋方式,埋设深度不应小于0.7m,埋设方法应符合《规范》的规定。"},
  {"id": 690, "type": "single", "question": "直埋电缆在穿越建筑物、构筑物、道路、易受机械损伤、介质腐蚀场所及引出地面从 （　　） m高到地下 （　　） m处必须加设防护套管。", "options": ["1，0.2", "1，1", "2，0.2", "2，1"], "answer": [2], "explanation": "直埋电缆在穿越建筑物、构筑物、道路,易受机械损伤、腐蚀介质场所及引出地面2.0m高至地下0.2m处,应加设防护套管。"},
  {"id": 691, "type": "single", "question": "直埋电缆在穿越建筑物、构筑物、道路、易受机械损伤、介质腐蚀场所及引出地面从2m高到地下0.2m处必须加设防护套管，防护套管内径不应小于电缆外径的 （　　） 倍。", "options": ["1", "1.5", "2", "2.5"], "answer": [1], "explanation": "埋地电缆在穿越建筑物、构筑物、道路、易受机械损伤、介质腐蚀场所及引出地面从2.0m高到地下0.2m处,必须加设防护套管,防护套管内径不应小于电缆外径的1.5倍。"},
  {"id": 692, "type": "single", "question": "室内配线采用瓷瓶、瓷（塑料）夹等敷设，距地高度不得小于 （　　） m。", "options": ["1.5", "2", "2.5", "3"], "answer": [2], "explanation": "采用瓷瓶、瓷(塑料)夹等敷设,距地面高度不得小于2.5m。"},
  {"id": 693, "type": "single", "question": "室内配线所用导线截面，应根据用电设备的负荷计算确定，但铝线截面应不小于 （　　） m㎡。", "options": ["1", "1.5", "2", "2.5"], "answer": [3], "explanation": "室内配线所用导线截面,应根据用电设备的计算负荷确定,但铝线截面应不小于2.5MM2,铜线截面应不小于1.5MM2。"},
  {"id": 694, "type": "single", "question": "下列关于室内配线安全要求，正确的是 （　　） 。", "options": ["采用瓷瓶、瓷（塑料）夹敷设，距地高度不得大于2.5m", "采用瓷夹固定导线时，导线间距应不小于50mm，瓷夹间距应不大于800mm", "采用瓷瓶固定导线时，导线间距应不小于100mm，瓷瓶间距应不大于1.5m", "钢索配线的架吊间距不宜大于12m"], "answer": [2], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】正确答案是C。题干对应的是建筑施工安全管理。 A项“采用瓷瓶、瓷（塑料）夹敷设，距地高度不得大于2.5m”错误，它不符合题干限定的对象、程序或条件。 B项“采用瓷夹固定导线时，导线间距应不小于50mm，瓷夹间距应不大于800mm”错误，它不符合题干限定的对象、程序或条件。 C项“采用瓷瓶固定导线时，导线间距应不小于100mm，瓷瓶间距应不大于1.5m”正确，它与题干所述“室内配线安全要求”相对应。 D项“钢索配线的架吊间距不宜大于12m”错误，它不符合题干限定的对象、程序或条件。"},
  {"id": 695, "type": "single", "question": "根据架空线的敷设要求，进户线过墙应穿管保护，距地面不得小于 （　　） ，并应采取防雨措施。", "options": ["2", "2.5", "3", "3.5"], "answer": [1], "explanation": "架空进户线的室外端应采用绝缘子固定,过墙处应穿管保护,距地面高度不得小于2.5m并应采取防雨措施。"},
  {"id": 696, "type": "single", "question": "暗敷设金属穿管应作等电位连接，并与 （　　） 线相连接。", "options": ["DK", "RCD", "KK", "PE"], "answer": [3], "explanation": "暗敷设金属穿管应作等电位 连接,并与 PE 线相连接。"},
  {"id": 697, "type": "single", "question": "与变压器直接接地的中性点连接的导线，称为 （　　） 。", "options": ["零线", "保护线", "NPE线", "总线"], "answer": [0], "explanation": "与变压器直接接地的中性点连接的导线,称为零线。"},
  {"id": 698, "type": "single", "question": "电气设备因运行需要而与工作零线连接，称为 （　　） 。", "options": ["工作接零", "保护接零", "专用保护零线", "接地零线"], "answer": [0], "explanation": "电气设备因运行需要而与工作零线连接,称为工作接零。"},
  {"id": 699, "type": "single", "question": "临时用电时，N表示 （　　） 。", "options": ["工作零线", "保护零线", "导线", "中性线"], "answer": [0], "explanation": "TN-S——保护零线 PE 与工作零线 N 分开的系统"},
  {"id": 700, "type": "single", "question": "在施工现场用电工程专用的电源中性点直接接地的220/380V三相四线制低压电力系统中，必须采用 （　　） 接零保护系统。", "options": ["TN-S", "TN-C", "TN-C-S", "N-S"], "answer": [0], "explanation": "在施工现场用电工程专用的电源中性点直接接地的220/380V三相四线制低压电力系统中，必须采线TN-S（三相五线）接零保护系统，严禁采用TN-C（三相四线）接零保护系统或TT接地保护系统。"},
  {"id": 701, "type": "single", "question": "采用TN系统做保护接零时，（）必须通过总漏电保护器，保护零线必须由电源进线零线重复接地处或总漏电保护器电源侧零线处，引出形成局部TN-S接零保护系统。", "options": ["A相", "工作零线", "B相", "C相"], "answer": [1], "explanation": "采用TN系统做保护接零时，工作零线(N线)必须通过总漏电保护器，保护零线(PE线)必须由电源进线零线重复接地处或总漏电保护器电源侧零线处，引出形成局部TN-S接零保护系统。"},
  {"id": 702, "type": "single", "question": "PE线是（），只用于连接电气设备外露可导电部分，在正常工作情况下无电流通过，被视为不带电部分，且与大地保持等电位。", "options": ["工作零线", "保护零线", "导线", "中性线"], "answer": [1], "explanation": "PE线是保护零线，只用于连接电气设备外露可导电部分，在正常工作情况下无电流通过。"},
  {"id": 703, "type": "single", "question": "重复接地必须与 （　　） 线相连接，严禁与 （　　） 线相连接。", "options": ["保护零线，工作零线", "工作零线，保护零线", "导线，保护零线", "工作零线，中性线"], "answer": [0], "explanation": "重复接地线必须与PE线相连接，严禁与N线相连接。\nPE线是保护零线,N线是工作零线。"},
  {"id": 704, "type": "single", "question": "二级漏电保护系统中漏电保护器的设置位置必须在基本供配电系统的 （　　） 和开关箱首、末二级配电装置中。", "options": ["总配电箱", "分配电箱", "开关箱", "总断熔器"], "answer": [0], "explanation": "二级漏电保护系统中漏电保护器的设置必须在基本供配电系统的总配电箱(配电柜)和开关箱 、 二级配电装置中。"},
  {"id": 705, "type": "single", "question": "PE线的重复接地不应少于三处，应分别设置于供配电系统的首端、中间、末端处，每处重复接地电阻值(指工频接地电阻值)不应大于 （　　） Ω。", "options": ["20", "15", "10", "5"], "answer": [2], "explanation": "保护线PE每处重复接地电阻值不得大于10Ω"},
  {"id": 706, "type": "single", "question": "漏电保护器的 （　　） 按实行分级、分段漏电保护原则和可靠防止人体触电伤害原则确定。", "options": ["动作参数", "额定频率", "额定电压", "额定电流"], "answer": [0], "explanation": "漏电保护器的动作参数应实行分级、分段漏电保护原则和可靠防止人体触电伤害原则确定。"},
  {"id": 707, "type": "single", "question": "文明施工包括了一般项目和保证项目，以下属于保证项目的是 （　　） 。", "options": ["社区服务", "综合治理", "材料管理", "生活设施"], "answer": [2], "explanation": "文明施工检查评定保证项目应包括:现场围挡、封闭管理、施工场地、材料管理、现场办公与住宿、现场防火。"},
  {"id": 708, "type": "single", "question": "以下关于上海市重点区域内建设工程的施工围挡说法正确的是 （　　） 。", "options": ["管线工程的围挡高度不得低于1.5m", "其他建设工程的围挡高度不得低于1.8m", "线形水利工程、非全封闭的城市道路工程和公路工程，施工工期小于30天，可使用路栏式围挡", "距离医院、住宅、学校等建筑物不足15m 的施工现场，应设置具有降噪功能的围挡"], "answer": [3], "explanation": "施工单位应当在施工现场四周设置连续、封闭的围挡。施工现场围挡的设置应当符合下列要求：\n（一）采用符合规定强度的硬质材料，基础牢固，表面整洁和美观。\n（二）管线工程的围挡高度不得低于1.8米，其他建设工程的围挡高度不得低于2米。\n（三）施工现场主要出入口的围挡大门符合有关规定。\n（四）距离住宅、医院、学校等建筑物不足5米的施工现场，设置具有降噪功能的围挡。\n线性水利工程、非全封闭的城市道路工程和公路工程、施工工期小于7日或者仅在夜间施工的管线工程的施工现场，可以使用路拦式围挡。\n施工单位应当定期对围挡进行养护、维修，保持完好、整洁和美观。"},
  {"id": 709, "type": "single", "question": "上海市文明施工的重点区域是指 （　　） 区域和市人民政府确定的其他重点区域。", "options": ["内环以内", "外环以内", "外环以内", "郊环以内"], "answer": [1], "explanation": "本市文明施工重点区域是指外环线以内区域和市人民政府确定的其他重点区域。市建设行政管理部门应当根据人口密度、居住环境、景观要求等提出其他重点区域划分方案，报市人民政府批准。"},
  {"id": 710, "type": "single", "question": "施工现场的围挡的稳固度，应满足抗 （　　） 级以上大风。", "options": ["6", "7", "8", "9"], "answer": [2], "explanation": "施工现场的围挡应稳固、整洁，并能抗8级以上大风。\n这个要求出自《上海市建设工程文明施工管理规定》等地方性管理办法，确保在恶劣天气下围挡不会倾倒，保障行人和施工安全。"},
  {"id": 711, "type": "single", "question": "占用道路施工的围挡应在道路交叉路口视距5m范围内，设置具有 （　　） 围挡，做到不遮挡车辆驾驶员和行人的视线，保证交通通行安全。", "options": ["折弯的彩钢", "喷漆的绿色", "底面镂空的PVC", "挺直刚度的金属网"], "answer": [3], "explanation": "占用道路施工的围挡应在道路交叉路口视距5米范围内设置具有挺直刚度的金属网板围挡,确保路口围挡不遮挡车辆驾驶员和行人的视线,以保证交通通行安全；产生扬尘污染的工程必须使用封闭式围挡。"},
  {"id": 712, "type": "single", "question": "围挡距离住宅不大于 （　　） m或施工作业点距离住宅、医院、学校等敏感建筑物不大于 （　　） m的，应采取增高围挡或设置声屏障等降音措施。", "options": ["3，5", "5，10", "5，15", "10，15"], "answer": [2], "explanation": "围挡距离住宅≤5米或施工作业点距离住宅、医院、学校等敏感建筑物≤15米的，应采取增高围挡或设置声屏障等降音措施，声屏障设置应符合相关规范和标准规定。"},
  {"id": 713, "type": "single", "question": "围挡内测 （　　） m范围内禁止堆放料具、土石方等物料。", "options": ["1", "3", "5", "7"], "answer": [0], "explanation": "围挡外侧5米范围内应保持清洁。围挡内侧1米范围内禁止堆放料具、土石方等物料。禁止将围挡用作挡土墙或其他设施设备的支撑。"},
  {"id": 714, "type": "single", "question": "拆除工程围挡宜采用 （　　） 等材料做围挡。", "options": ["轻型硬质的彩钢板", "底面镂空的PVC", "挺直刚度的金属网", "黏土砖"], "answer": [0], "explanation": "拆除工程围挡宜采用轻型硬质的彩钢板等材料做围挡。"},
  {"id": 715, "type": "single", "question": "采用砖墙作围挡的，墙体厚度不应小于 （　　） m。", "options": ["0.12", "0.24", "0.36", "0.48"], "answer": [1], "explanation": "第十二条 围挡应采用彩钢夹芯板、砌体或其他能满足强度要求的硬质材料，同时应满足耐燃性要求。用板材作围挡时，宜使用双层夹心彩钢板或具有相应硬度的板材。采用砖墙作围挡的，墙体厚度不应小于0.24m，严禁使用粘土砖砌筑(陈旧粘土砖利用除外)，其墙柱和基础砌筑应符合相关技术规范和标准的规定。砖砌墙体或裙基所用砌筑和表面应抹平砂浆。"},
  {"id": 716, "type": "single", "question": "线形水利工程、非全封闭的城市道路工程和公路工程，施工工期小于 （　　） 天，可使用路栏式围挡。", "options": ["7", "15", "20", "30"], "answer": [0], "explanation": "线形水利工程、非全封闭的城市道路工程和公路工程，施工工期小于7天，可使用路栏式围挡。\n这一规定旨在兼顾施工便捷性与交通安全，适用于短期、临时性的施工场景。"},
  {"id": 717, "type": "single", "question": "上海市重点区域内，围挡高度不得低于 （　　） m。", "options": ["1.8", "2.0", "2.5", "2.8"], "answer": [2], "explanation": "根据《上海市建设工程文明施工管理规定》：\n在上海市重点区域内，施工现场设置的围挡高度不得低于2.5米。\n此规定适用于如城市核心区域、重要道路沿线、景观控制区域等重点区域，以确保施工现场的封闭性、美观性和安全性。"},
  {"id": 718, "type": "single", "question": "根据上海市重点区域内施工工地的文明施工要求，重点区域内的施工现场设置宿舍的，每间宿舍人均面积不得低于 （　　） ㎡，并按照标准配备生活实施。", "options": ["4", "5", "6", "7"], "answer": [1], "explanation": "本市重点区域内施工工地的文明施工要求，还应当符合下列规定：\n（五）施工现场设置宿舍的，每间宿舍人均居住面积不得低于5平方米，并按照标准配备生活设施。"},
  {"id": 719, "type": "single", "question": "根据上海市重点区域内施工工地的文明施工要求，重点区域内的围挡内侧 （　　） m范围内禁止堆放料具、土石方等物料。", "options": ["1.0", "1.2", "1.5", "1.6"], "answer": [0], "explanation": "根据《上海市建设工程文明施工管理规定》，在上海市重点区域内，施工现场的围挡内侧1米范围内禁止堆放料具、土石方等物料。此外，围挡外侧5米范围内应保持清洁。禁止将围挡用作挡土墙或其他设施设备的支撑。这些规定旨在确保施工现场的整洁和安全，防止物料堆放对围挡结构稳定性和周边环境造成影响。"},
  {"id": 720, "type": "single", "question": "采用砖墙作围挡的，墙体厚度不应小于 （　　） mm，其墙柱和基础砌筑应符合相关技术规范和标准的规定。", "options": ["120", "180", "240", "370"], "answer": [2], "explanation": "采用砖墙作围挡的,墙体厚度不应小于0.24m,严禁使用粘土砖砌筑(陈旧粘土砖利用除外),其墙柱和基础砌筑应符合相关技术规范和标准的规定。"},
  {"id": 721, "type": "single", "question": "使用围挡的施工工地应设置 （　　） 出入门。", "options": ["1个", "2个", "不少于2个", "不少于3个"], "answer": [2], "explanation": "根据《上海市建设工程文明施工管理规定》等相关规范：\n使用围挡的施工工地应设置不少于2个出入门，以满足施工期间人员和车辆的通行、安全疏散等需求。"},
  {"id": 722, "type": "single", "question": "施工现场出入口应设置出入门，出入门总宽度不应小于 （　　） m，总高度应小于围挡高度 （　　） m，其上边沿应和围挡顶部保持平齐。", "options": ["5，0.2", "2，0.2", "5，0.5", "2，0.5"], "answer": [0], "explanation": "1.1 施工现场应分别设置车辆与人员出入门，车辆出入门宽度不应小于5m。\n1.2 施工现场应设置全封闭、轻质结构、可拆卸周转的围墙，材料宜选用金属材料，围墙基础色调为白色，底部设置0.2米的踢脚线，基础色调为深蓝色，总高度不应低于2.0m。"},
  {"id": 723, "type": "single", "question": "施工现场出入口门与围挡结合处应砌筑 （　　） 其高度应高出围挡不小于0.2m，并与围挡紧密连接。", "options": ["安全网", "施工标牌", "洗车池", "门墩"], "answer": [3], "explanation": "出入门与围挡结合处应砌筑门墩,其高度应高出围挡不小于0.2m,并与围挡紧密连接;门墩应使用商品预拌砂浆进行砌筑和粉刷。"},
  {"id": 724, "type": "single", "question": "施工现场出入门或内侧设置旗杆时，应设置 （　　） 的防锈蚀性金属旗杆。 （　　） 的旗杆设为中华人民共和国国旗专用旗杆，并高于其他旗杆。", "options": ["不少于2根，左起第一杆", "不少于2根，右起第一杆", "不少于3根的奇数，居中", "不少于5根的奇数，居中"], "answer": [2], "explanation": "出入门前或内侧需要设置旗杆的，应设置≥3根并为奇数的防锈蚀性金属旗杆。居中的旗杆为中华人民共和国国旗专用旗杆，并应高于其他旗杆0.5米。旗杆基础设置应结实、坚固，并应设置旗杆防护设施。"},
  {"id": 725, "type": "single", "question": "施工现场出入门或内侧设置旗杆时，应设置不少于3根的奇数的防锈蚀性金属旗杆。居中的旗杆设为中华人民共和国国旗专用旗杆，并高于其他旗杆 （　　） m。", "options": ["0.2", "0.5", "0.8", "1"], "answer": [1], "explanation": "出入门前或内侧需要设置旗杆的，应设置≥3根并为奇数的防锈蚀性金属旗杆。居中的旗杆为中华人民共和国国旗专用旗杆，并应高于其他旗杆0.5米。旗杆基础设置应结实、坚固，并应设置旗杆防护设施。"},
  {"id": 726, "type": "single", "question": "施工现场应有防止扬尘措施。道路管线工程实施一体化施工的，每 （　　） 应做到工完场清。", "options": ["日", "周", "旬", "期"], "answer": [0], "explanation": "建筑垃圾应集中、分类堆放,及时清运。道路管线工程施工,应每日做到工完场清。"},
  {"id": 727, "type": "single", "question": "在生活区设置宿舍的，应当安装可开启式窗户，每间宿舍人均居住面积不得低于 （　　） ㎡。", "options": ["2.5", "3", "3.5", "4"], "answer": [3], "explanation": "《上海市建设工程文明施工管理规定》\n施工现场设置生活区的，应当符合下列规定：\n（一）生活区和作业区分隔设置；\n（二）设置饮用水设施；\n（三）设置盥洗池和淋浴间；\n（四）设置水冲式或者移动式厕所，并由专人负责冲洗和消毒；\n（五）设置符合分类要求的密闭式垃圾容器，生活垃圾应当分类放置于垃圾容器内并做到日产日清。\n在生活区设置食堂的，应当依法办理餐饮服务许可手续，并遵守食品卫生管理的有关规定。\n在生活区设置宿舍的，应当安装可开启式窗户，每间宿舍人均居住面积不得低于4平方米。"},
  {"id": 728, "type": "single", "question": "施工现场使用的水泥筒仓、砂浆干粉筒仓在材料进、出环节应采取有效 （　　） 措施。", "options": ["扬尘控制", "防噪音", "防光污染", "防霉"], "answer": [0], "explanation": "现场使用的水泥筒仓、砂浆干粉筒仓在材料进、出时,应采取有效控制扬尘措施。"},
  {"id": 729, "type": "single", "question": "当风力大于等于 （　　） 级时，应停止室外建（构）筑物拆除和清除作业。", "options": ["4", "5", "6", "7"], "answer": [1], "explanation": "风力大于5级时,应停止室外建(构)筑物拆除和清除作业。"},
  {"id": 730, "type": "single", "question": "强光照明灯应配有防眩光罩，照明光束应 （　　） 施工作业面。", "options": ["散射", "直射", "俯射", "仰射"], "answer": [2], "explanation": "强光照明灯应配有防眩光罩,照明光束应俯射施工作业面。进行电焊作业时,应采取有效的弧光遮蔽措施。禁止施工工地夜间照明灯光、电焊弧光直射敏感建筑物。"},
  {"id": 731, "type": "single", "question": "安全资料分为A、B、C三类，其中B类属于 （　　） 。", "options": ["基本要求", "基本条件", "核心要求", "核心条件"], "answer": [2], "explanation": "安全资料分为A、B、C三类：A类为基本条件类，B类为核心要求类，这两类属于相对静态，以开工前和开工初期为主；C类为基本要求类，属于相对动态，以开工后为主。"},
  {"id": 732, "type": "single", "question": "以下属于安全资料中各类方案的是 （　　） 。", "options": ["安全生产、文明施工、环境保护计划", "各级安全生产责任制", "施工方案、操作规程交底", "安全检查记录"], "answer": [0], "explanation": "【依据】《建筑施工安全检查标准》JGJ 59-2011\n【解析】正确答案是A。题干对应的是建筑施工安全检查评定。 A项“安全生产、文明施工、环境保护计划”正确，它与题干所述“以下安全资料中各类方案的是”相对应。 B项“各级安全生产责任制”错误，它不符合题干限定的对象、程序或条件。 C项“施工方案、操作规程交底”错误，它不符合题干限定的对象、程序或条件。 D项“安全检查记录”错误，它不符合题干限定的对象、程序或条件。"},
  {"id": 733, "type": "single", "question": "项目经理带班记录要求每月不少于工作日的 （　　） ，并实名签字。", "options": ["30%", "50%", "60%", "80%"], "answer": [3], "explanation": "项目负责人每月带班生产时间不得少于本月施工时间的80%。"},
  {"id": 734, "type": "single", "question": "下列选项中不是每年编制的安全资料是 （　　） 。", "options": ["总分包协议综合交底", "交底", "三级教育卡", "施工安全生产管理制度"], "answer": [1], "explanation": "每年：总分包协议综合交底、施工管理人员安全生产岗位责任制（人员调动及时换）、三级教育卡、施工安全生产管理制度、职工家属安全责任状、防火安全、行车安全责任状协议。\n项目部安全教育培训按计划表执行，保持每月2-3次 落地式脚手架验收以单位工程（每栋楼）验收，基础验收1次，每达到6-8米时验收1次，搭设完成整体验收1次。悬挑式脚手架验收，槽钢层（悬挑基础）验收1次，每三层（不超过10米）一次，搭设到规定高度整体验收1次（一般18米，基本上每一悬挑需要验收3次，以单位工程验收，如果作业面较大以单位工程分段验收） 临边、洞口安全防护设施验收一层一次（以单位工程验收，如果作业面较大以单位工程分段验收）验收记录必须有项 目经理签字。模板工程及支撑体系安全验收记录每层一次（以单位工程验收，如果作业面较大以单位工程分段验收）"},
  {"id": 735, "type": "single", "question": "施工现场的（）式脚手架验收，槽钢层验收1次，每三层一次，搭设到规定高度整体验收一次（一般18m，以单位工程验收，如果作业面较大以单位工程分段验收）。", "options": ["落地", "悬挑", "盘扣", "碗扣"], "answer": [1], "explanation": "悬挑式脚手架验收，槽钢层（悬挑基础）验收1次，每三层（不超过10米）一次，搭设到规定高度整体验收1次（一般18米，基本上每一悬挑需要验收3次，以单位工程验收，如果作业面较大以单位工程分段验收） 临边、洞口安全防护设施验收一层一次（以单位工程验收，如果作业面较大以单位工程分段验收）验收记录必须有项 目经理签字。"},
  {"id": 736, "type": "single", "question": "下列选项中是开工前要求技术员编制完成的的专项施工方案的是（）。", "options": ["降水", "临时用电平面布置图", "卸料平台", "脚手架搭设"], "answer": [3], "explanation": "脚手架搭设前，应按专项施工方案向施工人员进行交底。"},
  {"id": 737, "type": "single", "question": "施工现场的消防安全由 （　　） 负责。", "options": ["建设单位", "施工单位", "监理单位", "消防部门"], "answer": [1], "explanation": "建筑工程施工现场的消防安全由施工单位负责。"},
  {"id": 738, "type": "single", "question": "施工现场必须配备足够的消防器材，其中要害部位应配备 （　　） 灭火器。", "options": ["3具", "不少于3具", "4具", "不少于4具"], "answer": [3], "explanation": "施工现场必须配备足够的消防器材，做到布局合理。要害部位应配备不少于4具的灭火器，要有明显的防火标志，指定专人经常查、维护、保养、定期更新，保证灭火器材灵敏有效。"},
  {"id": 739, "type": "single", "question": "施工现场必须设置临时消防车道，其宽度不得小于 （　　） m。", "options": ["3", "4", "5", "6"], "answer": [1], "explanation": "第十二、施工现场必须设置临时消防车道。其宽度不得小于4m，并保证临时消防车道的畅通，禁止在临时消防车道上堆物、堆料或挤占临时消防车道。"},
  {"id": 740, "type": "single", "question": "施工现场的重点防火部位或区域，应设置 （　　） 。", "options": ["消防车道", "临时疏散通道", "防火警示标识", "疏散指示标识"], "answer": [2], "explanation": "施工现场的重点防火部位或区域，应设置防火警示标识。"},
  {"id": 741, "type": "single", "question": "重要文物单位动火作业属于 （　　） 级动火作业。", "options": ["一", "二", "三", "四"], "answer": [0], "explanation": "在古建筑和重要文物单位等场所动火作业也属于一级动火。"},
  {"id": 742, "type": "single", "question": "距配电屏 （　　） m范围内不应设置可能产生较多易燃、易爆气体、粉尘的作业区。", "options": ["2", "3", "4", "5"], "answer": [3], "explanation": "《建设工程施工现场消防安全技术规范》，6.3.2.5"},
  {"id": 743, "type": "single", "question": "地下工程施工的防火要求包括：安全出入口、疏散走道和楼梯的最小净宽不应小于 （　　） m。", "options": ["0.5", "0.8", "1", "1.5"], "answer": [2], "explanation": "安全出入口、疏散走道以及楼梯的最小净宽不应小于 1m。"},
  {"id": 744, "type": "single", "question": "地下工程施工的防火要求包括：每个出入口的疏散人数不宜超过 （　　） 人。", "options": ["200", "250", "300", "350"], "answer": [1], "explanation": "每个出入口的疏散人数不宜超过 250 人。"},
  {"id": 745, "type": "single", "question": "标志灯正前方0.5m处的地面照度不应低于 （　　） lx。", "options": ["1", "2", "3", "4"], "answer": [0], "explanation": "标志灯正前方0.5m处的地面照度不应低于1lx。"},
  {"id": 746, "type": "single", "question": "火灾事故照明灯和疏散指示灯工作电源断电后，应能自动 （　　） 。", "options": ["报警", "强启", "洒水", "投合"], "answer": [3], "explanation": "灾事故照明灯和疏散指示灯工作电源断电后,应能自动投合。"},
  {"id": 747, "type": "single", "question": "地下工程施工的防火要求，禁止 （　　） 式乙炔发生器在地下工程内部使用及存放。", "options": ["沉浮", "排水", "中压", "联合"], "answer": [2], "explanation": "禁止中压式乙炔发生器在地下工程内部使用及存放。"},
  {"id": 748, "type": "single", "question": "锅炉房应达到 （　　） 的耐火等级。", "options": ["二级", "不低于二级", "三级", "不低于三级"], "answer": [1], "explanation": "锅炉房的耐火等级不应低于二级。"},
  {"id": 749, "type": "single", "question": "锅炉烟道和烟囱与可燃物应保持一定的距离，金属烟囱距可燃结构不小于 （　　） cm。", "options": ["10", "50", "70", "100"], "answer": [3], "explanation": "锅炉烟道和烟囱与可燃构件应保持一定的距离,金属烟囱距离可燃结构不小于 100cm.,已做好防火保护层的可燃结构不小于 70cm,"},
  {"id": 750, "type": "single", "question": "各种火炉的炉身、烟囱和烟囱出口等部分与电源线和电气设备应保持 （　　） cm以上的距离。", "options": ["5", "15", "30", "50"], "answer": [3], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】正确答案是D。题干对应的是建筑施工安全管理。 A项“5”错误，题干对应的控制数值不是5，正确值应为50。 B项“15”错误，题干对应的控制数值不是15，正确值应为50。 C项“30”错误，题干对应的控制数值不是30，正确值应为50。 D项“50”正确，规范要求的控制数值或时限就是50。"},
  {"id": 751, "type": "single", "question": "某地块施工现场，施工人员杜某在四楼楼面清理浇筑混凝土的钢筋笼时，不慎坠落。此次事故属于高处坠落事故，根据相关国家标准的规定，凡在坠落高度基准面 （　　） 有可能坠落的高处进行的作业，均称为高处作业。", "options": ["1m以上", "1m以上（含1m）", "2m以上", "2m以上（含2m）"], "answer": [3], "explanation": "凡在坠落高度基准面2M以上（含2M）有可能坠落的高处进行的作业，均称为高处作业。"},
  {"id": 752, "type": "single", "question": "某地块施工现场，施工人员杜某在四楼楼面清理浇筑混凝土的钢筋笼时，不慎坠落。已知该施工项目有超200名施工人员，应配备不少于 （　　） 专职安全管理人员。", "options": ["1名", "2名", "3名", "4名"], "answer": [2], "explanation": "根据《建筑施工企业安全生产管理机构设置及专职安全生产管理人员配备标准》（建质〔2004〕84号）规定：\n施工现场施工人员超过200人时，应配备不少于3名专职安全管理人员。"},
  {"id": 753, "type": "single", "question": "某项目在吊运作业中，工人钟某强行越过警戒线，信号工郭某拉拽劝阻无果，钢丝绳突然断裂，方钢滑脱坠地，反弹后导致钟某当场死亡。在施工作业前，要对钢丝绳作全长检查，特别注意 （　　） 。", "options": ["腐蚀及疲劳的内部检验", "钢丝绳的种类", "钢丝绳的数量", "处于冷环境绳段"], "answer": [0], "explanation": "钢丝绳在检验时,应对钢丝绳全长进行检验,但应特别留意下列部位: (1)钢丝绳固定和运动始末端部位; (2)通过滑轮组或绕过滑轮的绳段;\n(3)在在机构进行重复作业情况下,应特别注意机构吊载期间绕过滑轮的任何部位: (4)由于塔机上的其他部件可能引起磨损绳段; (5)腐蚀及疲劳的内部检验;\n(6)对从固定端引出的钢丝绳进行检验,这个部位容易发生疲劳断丝和腐蚀: (7)对固定装置本身的变形或磨损进行检验;\n(8)对采用压制或锻造的绳端固定装置进行检验,并检验绳箍材料是否有裂纹以及绳箍与钢丝绳间是否产生滑动;\n(9)对可拆卸装置(楔形接头、绳夹、压板等)应检验其内部和绳端内的断丝及腐蚀情况,并确保楔形接头和钢丝绳夹的紧固性,检验还应确保绳端装置符合相应标准的要求;\n(10)对编织的环状插扣式绳头应只使用在接头的尾部,以防止绳端突出的钢丝伤手。而接头的其余部"},
  {"id": 754, "type": "single", "question": "某项目在吊运作业中，工人钟某强行越过警戒线，信号工郭某拉拽劝阻无果，钢丝绳突然断裂，方钢滑脱坠地，反弹后导致钟某当场死亡。判断钢丝绳疲劳的一种方法是记录 （　　） 的规律。", "options": ["变形大小", "腐蚀程度", "断丝增加率", "磨损程度"], "answer": [2], "explanation": "逐项分析：\nA. 变形大小\n→ 变形可能是使用不当或受力异常造成，但不是疲劳判断的主要依据。\nB. 腐蚀程度\n→ 腐蚀是导致疲劳的因素之一，但“记录腐蚀”不是判断疲劳的直接方法。\nC. 断丝增加率 √\n→ 正确答案。随着钢丝绳使用时间增加，疲劳会导致断丝逐渐增多，观察和记录断丝数量的增长趋势，是判断钢丝绳疲劳的重要手段。\nD. 磨损程度\n→ 磨损反映使用状况，但不能单独用来准确判断疲劳程度。\n正确答案：C. 断丝增加率"},
  {"id": 755, "type": "single", "question": "某项目在进行塔式起重机拆卸作业过程中，3名作业人员坠落死亡，直接经济损失约四百万余元。请问根据《生产安全事故报告和调查处理条例》的规定，该事故按照造成的人员伤亡或者直接经济损失分类属于 （　　） 。", "options": ["特别重大事故", "重大事故", "较大事故", "一般事故"], "answer": [2], "explanation": "根据《生产安全事故报告和调查处理条例》（国务院令第 493 号）第三条规定，生产安全事故按造成的人员伤亡或直接经济损失分为以下等级：\n特别重大事故：造成 30 人以上死亡，或 100 人以上重伤（包括急性工业中毒，下同），或 1 亿元以上直接经济损失。\n重大事故：造成 10 人以上 30 人以下死亡，或 50 人以上 100 人以下重伤，或 5000 万元以上 1 亿元以下直接经济损失。\n较大事故：造成 3 人以上 10 人以下死亡，或 10 人以上 50 人以下重伤，或 1000 万元以上 5000 万元以下直接经济损失。\n一般事故：造成 3 人以下死亡，或 10 人以下重伤，或 1000 万元以下直接经济损失。"},
  {"id": 756, "type": "single", "question": "某项目在进行塔式起重机拆卸作业过程中，3名作业人员坠落死亡，直接经济损失约四百万余元。该起事故中，项目部经理安全生产履职不力，对事故发生负有责任。项目经理在施工过程中有着重要的作用，他是 （　　） 的第一责任人。", "options": ["企业安全生产工作", "落实企业负责人施工现场带班制度", "落实项目负责人施工现场带班制度", "工程项目质量安全管理"], "answer": [3], "explanation": "项目经理是在建筑施工总承包单位负责人授权委托下全面负责项目工程建设管理的工作岗位；是项目施工质量安全第一责任人。"},
  {"id": 757, "type": "single", "question": "某项目在进行塔式起重机拆卸作业过程中，3名作业人员坠落死亡，直接经济损失约四百万余元。该起事故中，项目部经理安全生产履职不力，对事故发生负有责任。该项目经理按照《生产安全事故罚款处罚规定》应当处罚上一年年收入 （　　） 的罚款。", "options": ["20%-30%", "30%-40%", "40%-50%", "50%"], "answer": [1], "explanation": "该事故造成 3 人死亡，属于 较大事故（根据《生产安全事故报告和调查处理条例》，较大事故指造成 3 人以上 10 人以下死亡）。\n第二十条 事故发生单位其他负责人和安全生产管理人员未依法履行安全生产管理职责，导致事故发生的，依照下列规定处以罚款：\n（一）发生一般事故的，处上一年年收入20％至30%的罚款；\n（二）发生较大事故的，处上一年年收入30％至40%的罚款；\n（三）发生重大事故的，处上一年年收入40％至50%的罚款；\n（四）发生特别重大事故的，处上一年年收入50％的罚款。"},
  {"id": 758, "type": "single", "question": "某项目作业人员在进行混凝土泵车维修后测试时，从现场预留孔洞坠落身亡。洞口作业是指在地面、楼面、屋面和墙面等有可能使人和物料坠落,其坠落高度大于或等于 （　　） 的开口处的高处作业。", "options": ["1米", "1.5米", "2米", "2.5米"], "answer": [2], "explanation": "根据《建筑施工高处作业安全技术规范》（JGJ 80-2016）等相关安全标准规定，坠落高度基准面 2 米及以上的开口处作业，需按高处作业要求采取防护措施（如设置防护栏杆、加盖件、张设安全网等），以防止人员或物料坠落。"},
  {"id": 759, "type": "single", "question": "某项目作业人员在进行混凝土泵车维修后测试时，从现场预留孔洞坠落身亡。当洞口作业时，垂直洞口短边边长小于 （　　） 时，应采取封堵措施。", "options": ["200毫米", "300毫米", "400毫米", "500毫米"], "answer": [3], "explanation": "根据《建筑施工高处作业安全技术规范》（JGJ 80-2016）规定：\n短边边长小于 500mm 的垂直洞口：应采用坚实的盖板覆盖，并固定牢固，防止挪动移位。\n短边边长≥500mm 的垂直洞口：应设置防护栏杆（如加装安全立网）或采用贯穿于混凝土板内的钢筋构成防护网，钢筋网格间距不得大于 200mm。"},
  {"id": 760, "type": "single", "question": "某项目作业人员在进行混凝土泵车维修后测试时，从现场预留孔洞坠落身亡。施工现场通道附近的洞口、坑、沟、槽、高处临边等危险作业处，应悬挂 （　　） 外，夜间应设灯光警示。", "options": ["安全警示标志", "安全护栏", "安全照明灯", "安全操作指南"], "answer": [0], "explanation": "施工现场通道附近的洞口、坑、沟、槽、高处临边等危险作业处，除应悬挂明显的安全警示标志外，夜间应设灯光警示。"},
  {"id": 761, "type": "single", "question": "某扩建工程工地内，1名作业人员在配合汽车吊进行钢质楼承板卸车作业时坠落身亡。此次事故是由于施工人员未使用安全带导致。作为施工企业，有着 （　　） 。", "options": ["保护拒绝违章指挥、强令冒险作业的责任", "保护紧急避险权的责任", "提供劳动安全防护用品的责任", "参加工伤保险的责任"], "answer": [2], "explanation": "根据题目描述，事故直接原因是施工人员未使用安全带，而安全带属于施工企业应为作业人员提供的劳动安全防护用品。分析各选项如下：\nA. 保护拒绝违章指挥、强令冒险作业的责任\n该责任针对员工拒绝管理层违规指令的情形，与本题 “未提供 / 使用安全带” 无直接关联，排除。\nB. 保护紧急避险权的责任\n紧急避险权指员工在危险情况下停止作业或撤离的权利，本题未涉及此类场景，排除。\nC. 提供劳动安全防护用品的责任\n根据《安全生产法》第四十五条，生产经营单位必须为从业人员提供符合国家标准或行业标准的劳动防护用品（如安全带），并监督、教育其正确佩戴使用。本题中企业若未提供安全带或未监督使用，则直接违反此责任，与事故原因高度相关，为正确选项。\nD. 参加工伤保险的责任\n参加工伤保险是企业的法定义务，但属于事故善后范畴，与事故直接原因（未使用安全带）无因果关系，排除。\n答案：C"},
  {"id": 762, "type": "single", "question": "某扩建工程工地内，1名作业人员在配合汽车吊进行钢质楼承板卸车作业时坠落身亡。施工总承包单位在起重机械作业时， （　　） 应当监督检查建筑起重机械的安装、拆卸和使用情况。", "options": ["项目负责人", "特种作业人员", "专职安全生产管理人员", "专职机械管理人员"], "answer": [2], "explanation": "根据《建筑起重机械安全监督管理规定》\n第二十一条，施工总承包单位有多项安全职责，其中包括指定专职安全生产管理人员监督检查建筑起重机械安装、拆卸、使用情况。这是为了确保起重机械作业的安全，及时发现和纠正可能存在的安全隐患，防止类似事故的发生。"},
  {"id": 763, "type": "single", "question": "某热泵机组施工现场，由于现场构配件堆放混乱，1名作业人员在行走过程中摔倒，头部撞在地面钢制构件上致其身亡。针对现场检查中发现的隐患， （　　） 应当立即处理；不能处理的，及时报告项目负责人和企业安全生产管理机构。", "options": ["项目专职安全生产管理人员", "企业专职安全生产管理人员", "企业负责人", "施工班组长"], "answer": [0], "explanation": "根据《建设工程安全生产管理条例》第二十三条规定：\n专职安全生产管理人员的主要职责包括对安全生产进行现场监督检查。\n发现安全事故隐患，应当立即要求整改（如本题中构配件堆放混乱问题）；\n若隐患当场无法处理（如需要停工整改、调用设备等），应及时向项目负责人和企业安全生产管理机构报告，确保隐患得到闭环管理。\n企业专职安全生产管理人员- 主要负责企业层面安全管理（如制度制定、定期检查），非现场即时处置主体。"},
  {"id": 764, "type": "single", "question": "某地块项目工地内，1名作业人员擅自翻越护栏进行现场查看时坠落身亡。该事故中作业人员安全意识薄弱，从业人员从事施工作业，应当 （　　） 。", "options": ["边培训边作业", "先培训再上岗", "先上岗再培训", "不需要培训"], "answer": [1], "explanation": "根据《建设工程安全生产管理条例》第三十七条及《安全生产法》相关规定，从业人员必须经安全生产教育和培训合格后，方可上岗作业。"},
  {"id": 765, "type": "single", "question": "某项目装饰装修施工工程中，1名作业人员在吊顶区域进行接线作业时触电身亡。电工作为特种作业人员，需要取得 （　　） 方可从事相应的特种作业。", "options": ["建筑施工特种作业人员操作资格证书", "安全生产考核合格证书", "注册建造师证书", "职业技能等级证书"], "answer": [0], "explanation": "电工作为特种作业人员，需要取得 特种作业操作证 方可从事相应的特种作业。"},
  {"id": 766, "type": "single", "question": "某项目装饰装修施工工程中，1名作业人员在吊顶区域进行接线作业时触电身亡。该单位还存在违法发包行为，按规定，施工单位按照国家和本市有关规定实行劳务分包的，劳务分包单位应当 （　　） 。", "options": ["具备相应的资质", "必须有更高的资质", "有较低的资质", "隶属于总包单位"], "answer": [0], "explanation": "根据《建筑法》《建设工程质量管理条例》及《房屋建筑和市政基础设施工程施工分包管理办法》等规定，施工单位实行劳务分包的，劳务分包单位必须具备相应的资质条件。"},
  {"id": 767, "type": "single", "question": "某施工现场拆除闲置阁楼时，1名作业人员被掉落楼板砸中身亡。该事故是墙体拆除过多，建筑垃圾未及时清运，致使超载坍塌，根据法律规定，被拆除的构件应 （　　）  。", "options": ["用叉车移至施工现场外", "静力销毁", "集中堆放在拆除平台上", "有安全的放置场所"], "answer": [3], "explanation": "根据法律规定，被拆除的构件应有安全的放置场所。\n具体要求如下：\n人工拆除作业时：楼板上严禁人员聚集或堆放材料，作业人员应站在稳定的结构或脚手架上操作，被拆除的构件应有安全的放置场所。\n机械拆除作业时：进行高处拆除作业时，对较大尺寸的构件或沉重的材料，必须采用起重机具及时吊下，拆卸下来的各种材料应及时清理，分类堆放在指定的场所，严禁向下抛掷。"},
  {"id": 768, "type": "single", "question": "某项目装修现场，2名作业人员安装光纤线，其中1人从房间的检修口爬入吊顶夹层内拉拽光纤线接触夹层内的裸露电源致触电身亡。配电TN-S系统中，相导体L1（A）、L2（B）、L3（C）相序的绝缘层颜色依次为 （　　） 。", "options": ["黄、红、绿", "黄、蓝、红", "黄、绿、红", "绿、黄、红"], "answer": [2], "explanation": "在配电 TN-S 系统中，相导体 L1（A）、L2（B）、L3（C）相序的绝缘层颜色依次为 黄、绿、红。\n三相交流电的相序颜色标准：\nL1（A 相）：黄色\nL2（B 相）：绿色\nL3（C 相）：红色\n其他导体颜色规定：\n中性线（N 线）：淡蓝色\n保护接地线（PE 线）：黄绿双色"},
  {"id": 769, "type": "single", "question": "某项目旧房改造施工过程中，西面墙体发生坍塌，作业人员被压身亡。本次事故，施工单位未尽到 （　　） 。", "options": ["安全生产监管责任", "安全生产主体责任", "安全生产技术责任", "安全生产决策责任"], "answer": [1], "explanation": "主体责任是指企业作为安全生产的直接实施者，需对本单位的安全生产全面负责，包括：\n- 建立安全管理制度、制定施工方案、落实隐患排查、培训人员、配备安全设施等。\n- 本题中施工单位未制定合理方案、未落实安全检查、未有效管理现场，均属于未履行主体责任。"},
  {"id": 770, "type": "single", "question": "某项目旧房改造施工过程中，西面墙体发生坍塌，作业人员被压身亡。该项目使用了机械拆除，拆除工程施工中，应对拟拆除物的 （　　） 进行监测；当发生事故隐患时，必须停止作业。", "options": ["力学状态", "稳定状态", "与毗邻结构的影响", "实际状况"], "answer": [1], "explanation": "根据《建筑拆除工程安全技术规范》（JGJ 147）及相关标准，拆除工程施工中应对拟拆除物的 稳定状态 进行监测。"},
  {"id": 771, "type": "single", "question": "某项目旧房改造施工过程中，西面墙体发生坍塌，作业人员被压身亡。该项目西面墙体本身稳定性差，且拆除其他墙体后未做加固，在拆除作业中，对局部拆除影响结构安全的，应 （　　） 。", "options": ["同步拆除", "边加固边拆除", "先加固再拆除", "避免拆除"], "answer": [2], "explanation": "根据《建筑拆除工程安全技术规范》（JGJ 147）及相关标准，当拟拆除物的结构稳定性不足时，必须采取 先加固再拆除 的措施。"},
  {"id": 772, "type": "single", "question": "某项目劳务公司施工人员在屋面上施工时不慎从临边坠落，身上穿戴安全带所悬挂的生命线发生断裂，导致其坠落死亡。安全带旧产品应进行静态负荷测试，当主带或安全绳的破坏负荷低于 （　　） 时，该批安全带应报废或更换相应部件。", "options": ["10千牛", "15千牛", "20千牛", "25千牛"], "answer": [1], "explanation": "根据《安全带》（GB 6095-2009）及相关标准，安全带旧产品进行静态负荷测试时，若主带或安全绳的破坏负荷低于 15 kN（千牛），该批安全带应报废或更换相应部件。"},
  {"id": 773, "type": "single", "question": "某工地A公司建筑工人在施工作业区域午休。B公司作业人员进入现场在作业时，大玻璃倾覆，带倒木梯，砸在正在午休的建筑工人头上。面对多家生产经营单位，建设工程实行总承包的， （　　） 对施工现场的安全生产负总责。", "options": ["总承包单位", "建设单位", "监理单位", "分包单位"], "answer": [0], "explanation": "《建设工程安全生产管理条例》第二十四条规定，建设工程实行施工总承包的，由总承包单位对施工现场的安全生产负总责。总承包单位应当自行完成建设工程主体结构的施工。总承包单位依法将建设工程分包给其他单位的，分包合同中应当明确各自在安全生产方面的权利、义务。总承包单位和分包单位对分包工程的安全生产承担连带责任。分包单位应当服从总承包单位的安全生产管理，分包单位不服从管理导致生产安全事故的，由分包单位承担主要责任。"},
  {"id": 774, "type": "single", "question": "某工地A公司建筑工人在施工作业区域午休。B公司作业人员进入现场在作业时，大玻璃倾覆，带倒木梯，砸在正在午休的建筑工人头上。两个以上生产经营单位在同一作业区域内进行生产经营活动，可能危及对方生产安全的，应当签订 （　　） 。", "options": ["安全生产责任协议", "安全生产管理协议", "安全生产职责协议", "安全生产协调协议"], "answer": [1], "explanation": "《中华人民共和国安全生产法》第四十八条规定，两个以上生产经营单位在同一作业区域内进行生产经营活动，可能危及对方生产安全的，应当签订安全生产管理协议，明确各自的安全生产管理职责和应当采取的安全措施，并指定专职安全生产管理人员进行安全检查与协调。"},
  {"id": 775, "type": "single", "question": "某工地A公司建筑工人在施工作业区域午休。B公司作业人员进入现场在作业时，大玻璃倾覆，带倒木梯，砸在正在午休的建筑工人头上。两个以上生产经营单位在同一作业区域内进行生产经营活动，要指定 （　　） 进行安全检查与协调。", "options": ["企业负责人", "项目负责人", "专职安全生产管理人员", "班组长"], "answer": [2], "explanation": "《中华人民共和国安全生产法》第四十八条规定，两个以上生产经营单位在同一作业区域内进行生产经营活动，可能危及对方生产安全的，应当签订安全生产管理协议，明确各自的安全生产管理职责和应当采取的安全措施，并指定专职安全生产管理人员进行安全检查与协调。"},
  {"id": 776, "type": "single", "question": "某工地泥工班组进行塔吊吊运混凝土浇筑屋面施工。塔吊吊运吊斗移动时，吊斗未停稳发生自转，站在吊斗东侧的一人被挤压在吊斗和花架门框之间，抢救无效死亡。施工作业人员安全意识淡薄，施工单位应对管理人员和作业人员每年进行至少 （　　） 安全生产教育培训。", "options": ["一次", "两次", "三次", "四次"], "answer": [0], "explanation": "《建设工程安全生产管理条例》规定，施工单位应当对管理人员和作业人员每年至少进行一次安全生产教育培训，其教育培训情况记入个人工作档案。安全生产教育培训考核不合格的人员，不得上岗。"},
  {"id": 777, "type": "single", "question": "某工地泥工班组进行塔吊吊运混凝土浇筑屋面施工。塔吊吊运吊斗移动时，吊斗未停稳发生自转，站在吊斗东侧的一人被挤压在吊斗和花架门框之间，抢救无效死亡。施工现场应当指定专职设备管理人员、 （　　） 进行现场监督检查。", "options": ["企业负责人", "项目负责人", "班组长", "专职安全生产管理人员"], "answer": [3], "explanation": "《建设工程安全生产管理条例》第二十三条规定，施工单位应当设立安全生产管理机构，配备专职安全生产管理人员。专职安全生产管理人员负责对安全生产进行现场监督检查。对于垂直运输机械作业等危险作业，需有专职安全生产管理人员进行现场监督，确保操作规程的遵守和安全措施的落实。"},
  {"id": 778, "type": "single", "question": "某工地泥工班组进行塔吊吊运混凝土浇筑屋面施工。塔吊吊运吊斗移动时，吊斗未停稳发生自转，站在吊斗东侧的一人被挤压在吊斗和花架门框之间，抢救无效死亡。塔吊司机作为特种作业人员，应当参加年度安全教育培训或继续教育，培训时间不少于 （　　） 。", "options": ["12小时", "24小时", "32小时", "48小时"], "answer": [1], "explanation": "根据《建筑施工特种作业人员管理规定》，建筑施工特种作业人员应当参加年度安全教育培训或者继续教育，每年不得少于 24 小时。塔吊司机属于建筑施工特种作业人员，因此其年度安全教育培训或继续教育时间不少于 24 小时。"},
  {"id": 779, "type": "single", "question": "某工地泥工班组进行塔吊吊运混凝土浇筑屋面施工。塔吊吊运吊斗移动时，吊斗未停稳发生自转，站在吊斗东侧的一人被挤压在吊斗和花架门框之间，抢救无效死亡。起重机械施工作业，必须编制施工组织设计和针对性的 （　　） 。", "options": ["机械装拆方案", "专项施工方案", "设计图方案", "安全生产管理方案"], "answer": [1], "explanation": "根据《危险性较大的分部分项工程安全管理规定》（住建部令第 37 号）及《建筑施工起重机械安全监督管理规定》，起重机械的 安装、拆卸、顶升、吊装作业 属于危险性较大的分部分项工程，必须编制 安全专项施工方案，明确施工工艺、安全技术措施和应急处置方案等内容。"},
  {"id": 780, "type": "single", "question": "某在建工地，挖掘机驾驶员将现场管理人员的手势误解为作业指令，操作挖掘机挖斗推倒上部围墙，击中在围墙内侧3名作业人员。司机必须听从指挥人员的指挥，当指挥信号不明时，司机应发出 （　　） 信号询问，明确指挥意图后，方可开车。", "options": ["重复", "前进", "继续", "下车"], "answer": [0], "explanation": "当指挥信号不明时，司机应发出 重复 信号询问，明确指挥意图后，方可开车。"},
  {"id": 781, "type": "single", "question": "某在建工地，挖掘机驾驶员将现场管理人员的手势误解为作业指令，操作挖掘机挖斗推倒上部围墙，击中在围墙内侧3名作业人员。司机必须熟练掌握标准规定的通用（）和有关的各种指挥信号，并与指挥人员密切配合。", "options": ["后退信号", "手势信号", "操作信号", "前进信号"], "answer": [1], "explanation": "根据《起重机械安全规程》（GB 6067.1）及建筑机械操作规范，起重机械（含挖掘机）作业的指挥信号体系通常包括 手势信号、音响信号和灯光信号，其中 手势信号 是最直接、最常用的沟通方式，也是避免误解的核心基础。"},
  {"id": 782, "type": "single", "question": "某在建工地，挖掘机驾驶员将现场管理人员的手势误解为作业指令，操作挖掘机挖斗推倒上部围墙，击中在围墙内侧3名作业人员。挖掘机平整作业场地时，不得用铲斗进行（）或者对地面进行夯实。", "options": ["挖掘", "回转", "砸击", "横扫"], "answer": [3], "explanation": "《建筑机械使用安全技术规程》第5.2.7条规定,平整场地时,不得用铲斗进行横扫或用铲斗对地面进行夯实。"},
  {"id": 783, "type": "single", "question": "某施工现场的作业人员在切割作业时没有对钢结构件进行支护，导致钢结构件切割开后失稳倾倒压在其身上，导致事故发生。在切割拆除部分结构后，要确保剩余结构的稳定，必要时应进行 （　　） 。", "options": ["永久支护", "临时支护", "拆除", "运输"], "answer": [1], "explanation": "在切割拆除部分结构后，为确保剩余结构的稳定，必要时应进行临时支护。"},
  {"id": 784, "type": "single", "question": "某施工现场的作业人员在切割作业时没有对钢结构件进行支护，导致钢结构件切割开后失稳倾倒压在其身上，导致事故发生。该类物体打击事故有相应的防范措施，钢模板部件拆除后，临时堆放处离楼层边沿不应小于 （　　） 米，堆放高度不得超过 （　　） 米。", "options": ["1，1", "1，2", "2，1", "2，2"], "answer": [0], "explanation": "钢模板部件拆除后，临时堆放处离楼层边沿不应小于1 米，堆放高度不得超过1 米。\n这一规定是为了防止模板堆放过于靠近边沿或过高导致失稳坠落，引发物体打击事故，属于施工现场高处作业及物料堆放的安全基本要求。"},
  {"id": 785, "type": "single", "question": "某施工现场的作业人员在切割作业时没有对钢结构件进行支护，导致钢结构件切割开后失稳倾倒压在其身上，导致事故发生。钢模板部件拆除后，要防止拆除的钢模板等物件掉落造成 （　　） 。", "options": ["高处坠落", "物体打击", "机械伤害", "起重伤害"], "answer": [1], "explanation": "钢模板部件拆除后，要防止拆除的钢模板等物件掉落造成 物体打击事故。\n这类事故通常是由于物件堆放不当、未固定或违规抛掷等原因，导致重物从高处坠落并击打下方人员，可能造成头部损伤、骨折、内脏破裂甚至死亡等严重后果。因此，施工现场需严格遵守物料堆放安全规范（如离楼层边沿不小于 1 米、堆放高度不超过 1 米等），并设置警戒区域、佩戴防护装备，避免此类风险。"},
  {"id": 786, "type": "single", "question": "据悉，某排水管线迁移工程在建工地，因降雨沟槽一侧土体松动下滑，致沟内作业工人被困。雨季施工时，应加强 （　　） 的防护，防止因雨水冲刷导致边坡失稳。", "options": ["基坑监测点", "基坑边坡", "排水设施", "降水井点"], "answer": [1], "explanation": "在雨季施工时，因雨水冲刷易导致土体松动、边坡失稳，因此需重点加强对边坡本身的防护。"},
  {"id": 787, "type": "single", "question": "据悉，某排水管线迁移工程在建工地，因降雨沟槽一侧土体松动下滑，致沟内作业工人被困。基坑边坡的顶部应设排水措施，在边坡顶部挖纵向坡度不小于 （　　） 的排水沟。", "options": ["1‰", "2‰", "3‰", "4‰"], "answer": [2], "explanation": "排水沟设置坡度的目的是确保雨水能顺畅排出，避免积水回流渗入边坡土体。根据《建筑施工土石方工程安全技术规范》（JGJ 180）等相关标准，施工现场排水沟的纵向坡度通常不应小于 0.3%（即 3‰），以保证排水流畅，减少雨水滞留对边坡稳定性的影响。"},
  {"id": 788, "type": "single", "question": "据悉，某排水管线迁移工程在建工地，因降雨沟槽一侧土体松动下滑，致沟内作业工人被困。边坡工程施工应做好临时排水系统，临时排水系统宜与永久性排水系统 （　　） 。", "options": ["相结合", "相分离", "串联合作", "分开使用"], "answer": [0], "explanation": "临时排水系统（如施工期间的截水沟、排水沟）与永久性排水系统（如工程设计的排水管网、边坡防护中的排水孔等）相结合，可实现以下目标：\n提高排水效率：避免重复建设，利用永久性设施提前介入施工期排水，减少雨水对边坡的冲刷。\n降低成本：减少临时设施的投入和拆除工作，实现资源优化。\n保障连续性：施工期临时排水设施可作为永久性系统的组成部分，确保工程全周期排水功能的稳定性，尤其在雨季或高水位地区，能有效预防边坡失稳。\n这一原则符合《建筑边坡工程技术规范》（GB 50330）等相关标准对排水系统设计的要求。"},
  {"id": 789, "type": "single", "question": "据悉，某排水管线迁移工程在建工地，因降雨沟槽一侧土体松动下滑，致沟内作业工人被困。在下雨等特殊天气可能增加风险的情况下，需有 （　　） ，其中应包含对可能导致土方坍塌等风险的防控措施。", "options": ["机械装拆方案", "设计图方案", "专项施工方案", "安全生产管理方案"], "answer": [2], "explanation": "《建筑施工安全检查标准》（JGJ 59）及《建筑边坡工程技术规范》（GB 50330）要求，施工单位需针对恶劣天气制定专项方案和应急预案，强化风险防控，确保施工安全。"},
  {"id": 790, "type": "single", "question": "某一在建工地上有施工设备遭到雷击，导致现场4名施工人员受伤。施工现场内的金属机械设备，当在相关装置的保护范围以外时，应按相关规定安装 （　　） 。", "options": ["放电装置", "防雷装置", "避雷针", "避雷装置"], "answer": [1], "explanation": "施工现场内的金属机械设备，当在相关装置（如防雷接地装置、接闪器）的保护范围以外时，应按相关规定安装 防雷装置。"},
  {"id": 791, "type": "single", "question": "某施工现场，由于暴雨天形成流沙冲袭致工地路面松软，一正在施工的打桩机发生倒塌。生产经营单位应当建立健全生产安全事故 （　　） ，采取技术、管理措施，及时发现并消除事故隐患。", "options": ["隐患整治排查制度", "隐患排查治理制度", "隐患分类排查制度", "安全生产管理制度"], "answer": [1], "explanation": "生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。\n事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。其中，重大事故隐患排查治理情况应当及时向负有安全生产监督管理职责的部门和职工大会或者职工代表大会报告。"},
  {"id": 792, "type": "single", "question": "某施工现场，由于暴雨天形成流沙冲袭致工地路面松软，一正在施工的打桩机发生倒塌。在雨季施工时，应采取有效的（），防止地基受水浸泡，影响地基承载力。", "options": ["降水措施", "抽水措施", "排水措施", "减水措施"], "answer": [2], "explanation": "题干中 “暴雨天形成流沙冲袭”“防止地基受水浸泡” 的核心矛盾是地表雨水积聚，而非地下水水位过高。因此，需通过排水措施（如沟渠、集水井、抽排等）快速排除地表积水，避免地基被浸泡。降水措施（A）适用于地下水控制，抽水措施（B）是排水的具体步骤，均不如排水措施（C）全面精准。"},
  {"id": 793, "type": "single", "question": "某地下污水管网施工路段，在拆除堵水气囊过程中，发生中毒窒息事故。生产经营单位必须遵守本法和其他有关安全生产的法律、法规，加强安全生产管理，其中生产经营单位的（）是本单位安全生产第一责任人。", "options": ["主要负责人", "项目负责人", "企业专职安全管理人员", "项目专职安全管理人员"], "answer": [0], "explanation": "根据《中华人民共和国安全生产法》第五条规定：生产经营单位的主要负责人是本单位安全生产第一责任人，对本单位的安全生产工作全面负责。其他负责人对职责范围内的安全生产工作负责。"},
  {"id": 794, "type": "single", "question": "某地下污水管网施工路段，在拆除堵水气囊过程中，发生中毒窒息事故，造成3人死亡、1人受伤，直接经济损失约516万元。该事故按照造成的人员伤亡或者直接经济损失分类属于 （　　） 。", "options": ["特重大事故", "重大事故", "较大事故", "一般事故"], "answer": [2], "explanation": "相关法规内容为《生产安全事故报告和调查处理条例》第三条的规定，根据生产安全事故造成的人员伤亡或者直接经济损失，事故分为以下等级：\n特别重大事故：造成 30 人以上死亡，或者 100 人以上重伤（包括急性工业中毒，下同），或者 1 亿元以上直接经济损失的事故。\n重大事故：造成 10 人以上 30 人以下死亡，或者 50 人以上 100 人以下重伤，或者 5000 万元以上 1 亿元以下直接经济损失的事故。\n较大事故：造成 3 人以上 10 人以下死亡，或者 10 人以上 50 人以下重伤，或者 1000 万元以上 5000 万元以下直接经济损失的事故。\n一般事故：造成 3 人以下死亡，或者 10 人以下重伤，或者 1000 万元以下直接经济损失的事故。\n本条第一款所称的 “以上” 包括本数，所称的 “以下” 不包括本数。"},
  {"id": 795, "type": "single", "question": "某地下污水管网施工路段，在拆除堵水气囊过程中，发生中毒窒息事故，本次事故是作业人员擅自在硫化氢气体浓度严重超标的环境下违规作业。作业前 （　　） 分钟，应再次对有限空间操作位置附近有害物质浓度采样，分析合格后方可进入有限空间。", "options": ["15", "20", "25", "30"], "answer": [3], "explanation": "作业前30分钟，应再次对有限空间操作位置附近有害物质浓度采样，分析合格后方可进入有限空间。\n在有限空间作业时，为保障作业人员安全，需严格遵循相关规定。作业前 30 分钟内进行采样分析，能较为准确地反映作业时有限空间内的气体状况，因为时间过长，空间内的气体成分可能因各种因素发生变化，无法保证作业时的安全性。"},
  {"id": 796, "type": "single", "question": "某施工现场吊装作业过程中，在前后分别吊装2个配电箱时，放置2号配电箱时压到1号配电箱所垫的槽钢，致使1号配电箱失稳倾倒，压到突然返回作业现场的程某。在吊装作业过程中， （　　） 前，必须对吊运物进行前的安全状态确认，无误后方可继续。", "options": ["吊装", "松钩", "抓取", "绑扎"], "answer": [0], "explanation": "根据《起重机械安全规程》（GB 6067.1），起吊前必须对吊运物的捆绑状态、吊具连接、作业环境（如周边物件稳定性）等进行全面确认，确保起吊过程中无碰撞、倾倒风险。本例中，若在起吊 2 号配电箱前确认其放置位置与 1 号箱的安全距离，可避免事故发生。"},
  {"id": 797, "type": "single", "question": "某施工现场吊装作业过程中，在前后分别吊装2个配电箱时，放置2号配电箱时压到1号配电箱所垫的槽钢，致使1号配电箱失稳倾倒，压到突然返回作业现场的程某。吊装作业人员应对吊装作业现场采取有效的 （　　） 措施，防止无关人员进入危险区域。", "options": ["警戒围蔽", "宣传教育", "专人阻挡", "警戒线"], "answer": [0], "explanation": "根据《建筑施工起重吊装安全技术规范》（JGJ 276），吊装作业前应 “设置警戒区域，明确警示标志，并设专人监护”。其中，“警戒围蔽” 是物理隔离措施的统称，涵盖警戒线、围栏等多种形式，而 “专人监护” 是辅助措施，二者需结合使用。"},
  {"id": 798, "type": "single", "question": "某施工现场吊装作业过程中，在前后分别吊装2个配电箱时，放置2号配电箱时压到1号配电箱所垫的槽钢，致使1号配电箱失稳倾倒，压到突然返回作业现场的程某。吊运过程中在吊运区域范围拉设 （　　） 警戒旗，无关人员不得入内。", "options": ["红蓝", "黑白", "红白", "红绿"], "answer": [2], "explanation": "吊装作业中，红白相间的警戒旗、警戒带 是最常见的隔离标识，其高对比度颜色能显著提醒人员 “禁止进入危险区域”，符合案例中防止无关人员误入的需求。"},
  {"id": 799, "type": "single", "question": "督导检查组在某施工现场督查时，发现多个乙炔瓶和氧气瓶混放在临时仓库内，存在重大安全隐患。施工现场氧气瓶、乙炔瓶应分开存放，间距不得小于 （　　） 。", "options": ["5米", "10米", "15米", "20米"], "answer": [0], "explanation": "这一规定出自《危险化学品企业特殊作业安全规范》（GB 30871 - 2022），该标准明确要求氧气瓶与乙炔瓶的间距不得小于 5 米，两者与动火点的距离均需保持 10 米以上，并需采取防晒、防倾倒措施。"},
  {"id": 800, "type": "single", "question": "督导检查组在某施工现场督查时，发现多个乙炔瓶和氧气瓶混放在临时仓库内，存在重大安全隐患。不同气瓶在仓库放置时，要注意气瓶角度，应保持 （　　） 状态。", "options": ["倾斜45度角", "直立", "卧倒", "静止"], "answer": [1], "explanation": "不同气瓶在仓库放置时，应保持 直立稳固 状态，禁止横躺卧放。这一要求的核心目的是防止气瓶滚动、碰撞引发安全隐患，同时避免气体泄漏或压力异常。"},
  {"id": 801, "type": "multiple", "question": "下列选项中，属于安全生产主体责任的特点是 （　　） 。", "options": ["安全生产法定责任是主体责任的底线", "安全生产主体责任内涵不断与时俱进", "安全生产主体责任因行业不同而各有特点", "安全生产主体责任地方法规政策概览", "安全生产主体责任因企业不同而各有特点"], "answer": [0, 1, 2, 3], "explanation": "2.1.2.3 安全生产主体责任的特点\n1.安全生产法定责任是主体责任的底线\n2.安全生产主体责任内涵不断与时俱进\n3. 安全生产主体责任因行业不同而各有特点\n4.安全生产主体责任地方法规政策概览"},
  {"id": 802, "type": "multiple", "question": "《建设工程安全生产管理条例》规定，施工单位从事建设工程的新建、扩建、改建和拆除等活动，应当具备国家规定的 （　　） 等条件，依法取得相应等级的资质证书，并在其资质等级许可的范围内承揽工程。", "options": ["营业执照", "注册资本", "专业技术人员", "技术装备", "安全生产"], "answer": [1, 2, 3, 4], "explanation": "施工单位从事建设工程的新建、扩建、改建和拆除等活动，应当具备国家规定的注册资本、专业技术人员、技术装备和安全生产等条件，依法取得相应等级的资质证书，并在其资质等级许可的范围内承揽工程。"},
  {"id": 803, "type": "multiple", "question": "根据《安全生产法》规定，建筑施工的 （　　） 单位，应当设置安全生产管理机构或者配备专职安全生产管理人员。", "options": ["生产", "经营", "服务", "储存", "装卸"], "answer": [0, 1, 3, 4], "explanation": "第二十四条 矿山、金属冶炼、建筑施工、运输单位和危险物品的生产、经营、储存、装卸单位，应当设置安全生产管理机构或者配备专职安全生产管理人员。"},
  {"id": 804, "type": "multiple", "question": "根据《建设工程安全生产管理条例》的规定， （　　） 应当经建设行政主管部门或者其他有关部门考核合格后方可任职。", "options": ["施工单位的主要负责人", "企业法人代表", "项目负责人", "企业质量监理", "专职安全生产管理人员"], "answer": [0, 2, 4], "explanation": "【依据】《建设工程安全生产管理条例》\n【解析】正确答案是A、C、E。题干对应的是建设工程安全生产管理条例。 A项“施工单位的主要负责人”正确，题干对应职责主体就是施工单位的主要负责人。 B项“企业法人代表”错误，它不符合题干限定的对象、程序或条件。 C项“项目负责人”正确，该事项的责任主体不是项目负责人，而是施工单位的主要负责人。 D项“企业质量监理”错误，它不符合题干限定的对象、程序或条件。 E项“专职安全生产管理人员”正确，该事项的责任主体不是专职安全生产管理人员，而是施工单位的主要负责人。"},
  {"id": 805, "type": "multiple", "question": "根据《建设工程安全生产管理条例》的规定，施工单位在采用 （　　） 时，应当对作业人员进行相应的安全生产教育培训。", "options": ["新技术", "新产品", "新工艺", "新设备", "新材料"], "answer": [0, 2, 3, 4], "explanation": "第三十七条 作业人员进入新的岗位或者新的施工现场前，应当接受安全生产教育培训。未经教育培训或者教育培训考核不合格的人员，不得上岗作业。施工单位在采用新技术、新工艺、新设备、新材料时，应当对作业人员进行相应的安全生产教育培训。"},
  {"id": 806, "type": "multiple", "question": "依《安全生产法》规定，建筑施工企业与从业人员订立的劳动合同，应当载明有关保障从业人员 （　　） 的事项，以及依法为从业人员办理工伤保险的事项。", "options": ["劳动安全", "安全保险", "社会保险", "防止职业危害", "失业保险"], "answer": [0, 3], "explanation": "【依据】《中华人民共和国安全生产法》\n【解析】正确答案是A、D。题干对应的是中华人民共和国安全生产法。 A项“劳动安全”正确，它与题干所述“依《安全生产法》规定，建筑施工企业与从业人员”相对应。 B项“安全保险”错误，它不符合题干限定的对象、程序或条件。 C项“社会保险”错误，它不符合题干限定的对象、程序或条件。 D项“防止职业危害”正确，它与题干所述“依《安全生产法》规定，建筑施工企业与从业人员”相对应。 E项“失业保险”错误，它不符合题干限定的对象、程序或条件。"},
  {"id": 807, "type": "multiple", "question": "《上海市建设工程质量和安全管理条例》规定，施工现场的 （　　） 必须由专人管理，定期进行检查、维修和保养。", "options": ["安全防护用具", "一般工具", "机械设备", "施工机具", "施工机具配件"], "answer": [0, 2, 3, 4], "explanation": "施工现场的安全防护用具、机械设备、施工机具及配件必须由专人管理，定期进行检查、维修和保养，建立相应的资料档案，并按照国家有关规定及时报废。"},
  {"id": 808, "type": "multiple", "question": "根据《安全生产法》规定，生产经营项目分包给其他单位的，建筑施工企业对承包单位的安全生产工作 （　　） 、定期进行安全检查，发现安全问题的，应当及时督促整改。", "options": ["统一协调", "统一管理", "统一布置", "设定标准", "落实到位"], "answer": [0, 1], "explanation": "【依据】《中华人民共和国安全生产法》\n【解析】正确答案是A、B。题干对应的是中华人民共和国安全生产法。 A项“统一协调”正确，它与题干所述“规定，生产经营项目分包给其他单位的，建筑施工”相对应。 B项“统一管理”正确，它与题干所述“规定，生产经营项目分包给其他单位的，建筑施工”相对应。 C项“统一布置”错误，它不符合题干限定的对象、程序或条件。 D项“设定标准”错误，它不符合题干限定的对象、程序或条件。 E项“落实到位”错误，它不符合题干限定的对象、程序或条件。"},
  {"id": 809, "type": "multiple", "question": "根据《建设工程安全生产管理条例》的规定，施工单位对因建设工程施工可能造成损害的毗邻 （　　） 等，应当采取专项防护措施。", "options": ["建筑物", "构筑物", "地下管线", "设施设备", "建筑材料"], "answer": [0, 1, 2], "explanation": "第三十条 施工单位对因建设工程施工可能造成损害的毗邻建筑物、构筑物和地下管线等，应当采取专项防护措施。"},
  {"id": 810, "type": "multiple", "question": "根据《建设工程安全生产管理条例》的规定，施工单位应当制定本单位生产安全事故应急救援预案，建立应急救援组织或者配备应急救援人员，配备必要的 （　　） ，并定期组织演练。", "options": ["应急救援器材", "设备", "材料", "安全工具", "消防工具"], "answer": [0, 1], "explanation": "【依据】《建设工程安全生产管理条例》\n【解析】正确答案是A、B。题干对应的是建设工程安全生产管理条例。 A项“应急救援器材”正确，它与题干所述“的规定，施工单位应当制定本单位生产安全事故应”相对应。 B项“设备”正确，它与题干所述“的规定，施工单位应当制定本单位生产安全事故应”相对应。 C项“材料”错误，它不符合题干限定的对象、程序或条件。 D项“安全工具”错误，它不符合题干限定的对象、程序或条件。 E项“消防工具”错误，它不符合题干限定的对象、程序或条件。"},
  {"id": 811, "type": "multiple", "question": "下列选项中，属于施工企业安全生产责任五到位的是 （　　） 。", "options": ["安全投入到位", "安全管理到位", "安全培训到位", "应急救援到位", "安全理赔到位"], "answer": [0, 1, 2, 3], "explanation": "安全五到位指的是;必须做到安全责任到位、安全投入到位、安全培训到位、安全管理到位、应急救援到位。"},
  {"id": 812, "type": "multiple", "question": "全国安全生产专项整治三年行动计划》，在专题实施方案中，把企业落实主体责任的要求概括为四个体系，即 （　　） ,体现“齐抓共管”的思路。", "options": ["企业主体责任体系", "规范化安全管理体系", "安全管理体系", "社会化服务体系", "安全预防控制体系"], "answer": [0, 1, 3, 4], "explanation": "在该专题实施方案中，把企业落实主体责任的要求概括为以下四个体系，即企业主体责任体系、规范化安全管理体系、安全预防控制体系、社会化服务体系，充分体现了一直强调的“齐抓共管”思路。"},
  {"id": 813, "type": "multiple", "question": "根据《安全生产法》的规定，建筑施工企业采用 （　　） ,必须了解、掌握其安全技术特性，采取有效的安全防护措施，并对从业人员进行专门的安全生产教育和培训。", "options": ["新企业负责人", "新工艺", "新技术", "新材料", "新设备"], "answer": [1, 2, 3, 4], "explanation": "【依据】《中华人民共和国安全生产法》\n【解析】正确答案是B、C、D、E。题干对应的是中华人民共和国安全生产法。 A项“新企业负责人”错误，它不符合题干限定的对象、程序或条件。 B项“新工艺”正确，它与题干所述“的规定，建筑施工企业采用,必须了解、掌握其安”相对应。 C项“新技术”正确，它与题干所述“的规定，建筑施工企业采用,必须了解、掌握其安”相对应。 D项“新材料”正确，它与题干所述“的规定，建筑施工企业采用,必须了解、掌握其安”相对应。 E项“新设备”正确，它与题干所述“的规定，建筑施工企业采用,必须了解、掌握其安”相对应。"},
  {"id": 814, "type": "multiple", "question": "根据《建设工程安全生产管理条例》的规定，关于意外伤害保险的说法，不正确的有 （　　） 。", "options": ["意外伤害保险费由施工企业支付，不得向职工摊派", "保险期间应涵盖工程项目开工之日到工程竣工验收合格日", "已在企业所在地参加工伤保险的人员，从事现场施工时不得参加意外伤害保险", "实行施工总承包的，由总承包单位支付意外伤害保险费", "施工单位应当为全体员工办理意外伤害保险"], "answer": [2, 4], "explanation": "第三十八条 施工单位应当为施工现场从事危险作业的人员办理意外伤害保险。\n意外伤害保险费由施工单位支付。实行施工总承包的，由总承包单位支付意外伤害保险费。意外伤害保险期限自建设工程开工之日起至竣工验收合格止。"},
  {"id": 815, "type": "multiple", "question": "根据《建设工程安全生产管理条例》的规定，施工单位采购、租赁的安全防护用具、机械设备、施工机具及配件，应当具有 （　　） ，并在进入施工现场前进行查验。", "options": ["产品说明书", "生产(制造)许可证", "产品合格证", "使用说明书", "质量检验报告"], "answer": [1, 2], "explanation": "第三十四条 施工单位采购、租赁的安全防护用具、机械设备、施工机具及配件，应当具有生产(制造)许可证、产品合格证，并在进入施工现场前进行查验。"},
  {"id": 816, "type": "multiple", "question": "根据《建设工程安全生产管理条例》的规定，对达到一定规模的危险性较大的分部分项工程，如 （　　） 等，编制专项施工方案，并附具安全验算结果，经施工单位技术负责人、总监理工程师签字后实施，由专职安全生产管理人员进行现场监督。", "options": ["基坑支护与降水工程", "脚手架工程", "土方开挖工程", "模板工程", "临时用水工程"], "answer": [0, 1, 2, 3], "explanation": "【依据】《建设工程安全生产管理条例》\n【解析】正确答案是A、B、C、D。题干对应的是建设工程安全生产管理条例。 A项“基坑支护与降水工程”正确，它与题干所述“的规定，对达到一定规模的危险性较大的分部分项”相对应。 B项“脚手架工程”正确，它与题干所述“的规定，对达到一定规模的危险性较大的分部分项”相对应。 C项“土方开挖工程”正确，它与题干所述“的规定，对达到一定规模的危险性较大的分部分项”相对应。 D项“模板工程”正确，它与题干所述“的规定，对达到一定规模的危险性较大的分部分项”相对应。 E项“临时用水工程”错误，它不符合题干限定的对象、程序或条件。"},
  {"id": 817, "type": "multiple", "question": "根据《上海市建设工程质量和安全管理条例》的规定，施工单位应当在施工现场建立消防安全责任制度，具体的措施有 （　　） 。", "options": ["确定消防安全责任人", "设置消防通道、消防水源", "制定用火、用电、使用易燃易爆材料等各项消防安全管理制度和操作规程", "配备消防设施和灭火器材，施工现场入口处不需要设置明显标志", "建设工程材料和设备，以及施工脚手架(包括支架和脚踏板)、安全网应当符合防火要求"], "answer": [0, 1, 2, 4], "explanation": "施工单位应当在施工现场建立消防安全责任制度，确定消防安全责任人，制定用火、用电、使用易燃易爆材料等各项消防安全管理制度和操作规程，设置消防通道、消防水源，配备消防设施和灭火器材，并在施工现场入口处设置明显标志。\n建设工程材料和设备，以及施工脚手架（包括支架和脚踏板）、安全网应当符合防火要求。"},
  {"id": 818, "type": "multiple", "question": "企业要在适当位置对全员安全生产责任制进行长期公示。公示的内容主要包括 （　　） 。", "options": ["所有层级安全生产责任", "所有岗位安全生产责任", "所有层级安全生产责任范围", "所有岗位安全生产责任范围", "所有岗位安全生产责任考核标准"], "answer": [0, 1, 2, 3, 4], "explanation": "加强企业全员安全生产责任制公示。企业要在适当位置对全员安全生产责任制进行长期公示。公示的内容主要包括：所有层级、所有岗位的安全生产责任、安全生产责任范围、安全生产责任考核标准等。"},
  {"id": 819, "type": "multiple", "question": "建筑施工企业相比于矿山企业、危险化学品、烟花爆竹、民用爆炸物品生产企业，其危险特点有所不同，主要在于 （　　） 等。", "options": ["突发性", "不可控性", "频率高", "范围不定", "劳动者的素质较低"], "answer": [2, 3, 4], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】正确答案是A、C、D。题干对应的是建筑施工安全管理。 A项“突发性”正确，它与题干所述“建筑施工企业相比于矿山企业、危险化学品、烟花”相对应。 B项“不可控性”错误，它不符合题干限定的对象、程序或条件。 C项“频率高”正确，它与题干所述“建筑施工企业相比于矿山企业、危险化学品、烟花”相对应。 D项“范围不定”正确，它与题干所述“建筑施工企业相比于矿山企业、危险化学品、烟花”相对应。 E项“劳动者的素质较低”错误，它不符合题干限定的对象、程序或条件。"},
  {"id": 820, "type": "multiple", "question": "根据《行政许可法》规定，直接涉及 （　　） 以及直接关系人身健康、生命财产安全等特定活动，需要按照法定条件予以批准的事项，可以设定行政许可。", "options": ["国家安全", "公共安全", "经济宏观调控", "生态环境保护", "社会发展"], "answer": [0, 1, 2, 3], "explanation": "【依据】《行政许可法》\n【解析】正确答案是A、B、C、D。题干对应的是行政许可法。 A项“国家安全”正确，它与题干所述“规定，直接涉及以及直接关系人身健康、生命财产”相对应。 B项“公共安全”正确，它与题干所述“规定，直接涉及以及直接关系人身健康、生命财产”相对应。 C项“经济宏观调控”正确，它与题干所述“规定，直接涉及以及直接关系人身健康、生命财产”相对应。 D项“生态环境保护”正确，它与题干所述“规定，直接涉及以及直接关系人身健康、生命财产”相对应。 E项“社会发展”错误，它不符合题干限定的对象、程序或条件。"},
  {"id": 821, "type": "multiple", "question": "安全生产许可和生产许可的主要区别体现在 （　　） 不同。", "options": ["适用对象", "许可目的", "适用的法律", "审批的部门", "适用的行业"], "answer": [0, 1, 2, 3], "explanation": "生产许可证，是针对“产品”的结果，对可能造成公共安全影响的产品的生产（担心产品对社会造成危害），实行许可证制度。比如米面、食用油、通信设备，劳动保障产品、爆炸物等等。审批部门一般是质量技术监督局，或其它主管工业的部门；\n安全生产许可证，是针对“生产”的过程，对可能在生产制造过程中产生安全影响的制造（担心生产过程产生社会危害），实行许可证制度。比如采矿、危险化学物品、烟花鞭炮等等。审批部门一般是安监局。建设项目可能是建设部门审批。"},
  {"id": 822, "type": "multiple", "question": "我国涉及施工企业安全生产许可证的法规有 （　　） 。", "options": ["《建筑施工企业安全生产许可证管理规定实施意见》", "《中华人民共和国行政许可法》", "《上海市建筑施工企业安全生产许可批后监督管理办法》", "《安全生产许可证条例》", "《建筑施工企业安全生产许可证管理规定》"], "answer": [1, 3, 4], "explanation": "资料：\n根据《行政许可法》、《安全生产许可证条例》（国务院令第397号）、《建设工程安全生产管理条例》（国务院令第393号）和《建筑施工企业安全生产许可证管理规定》（部令第128号）等法规及有关规定，现将我厅审核的2025年第21批建筑施工企业安全生产许可证结果予以公告。"},
  {"id": 823, "type": "multiple", "question": "建筑施工企业取得安全生产许可证，应当具备下列 （　　） 安全生产条件。", "options": ["管理人员和作业人员每年至少进行一次安全生产教育培训并考核合格", "主要负责人经建设主管部门或者其他有关部门考核合格", "项目负责人经建设主管部门或者其他有关部门考核合格", "专职安全生产管理人员经建设主管部门或者其他有关部门考核合格", "依法参加工伤保险，依法为施工现场从事危险作业的人员办理意外伤害保险，为从业人员交纳保险费"], "answer": [0, 1, 2, 3, 4], "explanation": "第四条建筑施工企业取得安全生产许可证，应当具备下列安全生产条件：\n（一）建立、健全安全生产责任制，制定完备的安全生产规章制度和操作规程；\n（二）保证本单位安全生产条件所需资金的投入；\n（三）设置安全生产管理机构，按照国家有关规定配备专职安全生产管理人员；\n（四）主要负责人、项目负责人、专职安全生产管理人员经建设主管部门或者其他有关部门考核合格；\n（五）特种作业人员经有关业务主管部门考核合格，取得特种作业操作资格证书；\n（六）管理人员和作业人员每年至少进行一次安全生产教育培训并考核合格；\n（七）依法参加工伤保险，依法为施工现场从事危险作业的人员办理意外伤害保险，为从业人员交纳保险费；\n（八）施工现场的办公、生活区及作业场所和安全防护用具、机械设备、施工机具及配件符合有关安全生产法律、法规、标准和规程的要求；\n（九）有职业危害防治措施，并为作业人员配备符合国家标准或者行业标准的安全防护用具和安全防护服装；\n（十）有对危险性较大的分部分项工程及施工现场易发生重大事故的部位、环节的预防、监控措施和应急预案；\n（十一）有生产安全事故应急救援预案、应急救援组织或者应急救援人员，配备必要的应急救援器材、设备；\n（十二）法律、法规规定的其他条件。"},
  {"id": 824, "type": "multiple", "question": "中央管理的建筑施工企业（集团公司、总公司）下属的建筑施工企业，以及其他建筑施工企业的安全生产许可证加盖 （　　） 公章有效。", "options": ["省人民政府建设主管部门", "自治区人民政府建设主管部门", "直辖市人民政府建设主管部门", "建设部", "技监局"], "answer": [0, 1, 2], "explanation": "(十四)中央管理的建筑施工企业(集团公司、总公司)的安全生产许可证加盖建设部公章有效。中央管理的建筑施工企业(集团公司、总公司)下属的建筑施工企业，以及其他建筑施工企业的安全生产许可证加盖省、自治区、直辖市人民政府建设主管部门公章有效。由建设部以及各省、自治区、直辖市人民政府建设主管部门颁发的安全生产许可证均在全国范围内有效。"},
  {"id": 825, "type": "multiple", "question": "关于安全生产许可证有效期的说法，不正确的有 （　　） 。", "options": ["安全生产许可证的有效期为3年", "施工企业应当向原安全生产许可证颁发管理机关办理延期手续", "安全生产许可证有效期满需要延期的，施工企业应当于期满前1个月办理延期手续", "施工企业在安全生产许可证有效期内，严格遵守有关安全生产的法律法规，未发生死亡事故的，安全生产许可证有效期届满时，自动延期", "安全生产许可证有效期延期3年"], "answer": [2, 3], "explanation": "第九条 安全生产许可证的有效期为3年。安全生产许可证有效期满需要延期的，企业应当于期满前3个月向原安全生产许可证颁发管理机关办理延期手续。"},
  {"id": 826, "type": "multiple", "question": "建设单位或其委托的工程招标代理机构在编制资格预审文件和招标文件时，应当明确要求建筑施工企业提供安全生产许可证，以及（）相应的安全生产考核合格证书。", "options": ["企业法定代表人", "企业主要负责人", "总工程师", "拟担任该项目负责人", "专职安全生产管理人员"], "answer": [1, 3, 4], "explanation": "第二条 建设单位或其委托的工程招标代理机构在编制资格预审文件和招标文件时，应当明确要求建筑施工企业提供安全生产许可证，以及企业主要负责人、拟担任该项目负责人和专职安全生产管理人员（以下简称“三类人员”）相应的安全生产考核合格证书。"},
  {"id": 827, "type": "multiple", "question": "根据《建筑施工企业安全生产许可证管理规定》，关于安全生产许可证的说法不正确的有（）。", "options": ["施工企业未取得安全生产许可证的不得从事建筑施工活动", "施工企业变更法定代表人的不必办理安全生产许可证变更手续", "对没有取得安全生产许可证的施工企业所承包的项目不得颁发施工许可", "施工企业取得安全生产许可证后不得降低安全生产条件", "未发生死亡事故的，安全生产许可证有效期届满时自动延期"], "answer": [1, 4], "explanation": "企业在安全生产许可证有效期内，严格遵守有关安全生产的法律法规，未发生死亡事故的，安全生产许可证有效期届满时，经原安全生产许可证颁发管理机关同意，不再审查，安全生产许可证有效期延期3年。"},
  {"id": 828, "type": "multiple", "question": "企业收到《上海市住房和城乡建设管理委员会行政审批告知承诺书》， （　　） 后，在网上进行建筑施工企业安全生产许可证申请填报。", "options": ["签收", "确认", "核对", "作出承诺", "回复响应"], "answer": [1, 3], "explanation": "【依据】《上海市住房和城乡建设管理委员会行政审批告知承诺书》\n【解析】正确答案是A、D。题干对应的是上海市住房和城乡建设管理委员会行政审批告知承诺书。 A项“签收”正确，它与题干所述“企业收到《上海市住房和城乡建设管理委员会行政”相对应。 B项“确认”错误，它不符合题干限定的对象、程序或条件。 C项“核对”错误，它不符合题干限定的对象、程序或条件。 D项“作出承诺”正确，它与题干所述“企业收到《上海市住房和城乡建设管理委员会行政”相对应。 E项“回复响应”错误，它不符合题干限定的对象、程序或条件。"},
  {"id": 829, "type": "multiple", "question": "在施工企业安全生产管理实践中，应渐进形成建立安全生产管理机构，并形成了 （　　） 三级安全管理的格局。", "options": ["企业法定代表人", "企业负责人", "项目负责人", "专职安全人员", "项目技术负责人"], "answer": [1, 2, 3], "explanation": "【依据】《建筑施工企业安全生产管理机构设置及专职安全生产管理人员配备办法》 / 《建筑施工企业主要负责人、项目负责人和专职安全生产管理人员安全生产管理规定》\n【解析】正确答案是B、C、D。题干对应的是企业和项目安全生产组织管理。 A项“企业法定代表人”错误，它不符合题干限定的对象、程序或条件。 B项“企业负责人”正确，它与题干所述“在施工企业安全生产管理实践中，应渐进形成建立”相对应。 C项“项目负责人”正确，该事项的责任主体不是项目负责人，而是企业负责人。 D项“专职安全人员”正确，它与题干所述“在施工企业安全生产管理实践中，应渐进形成建立”相对应。 E项“项目技术负责人”错误，它不符合题干限定的对象、程序或条件。"},
  {"id": 830, "type": "multiple", "question": "根据《建筑施工企业安全生产许可证管理规定》，建筑施工企业取得安全生产许可证应具备 （　　） 安全生产条件。", "options": ["建立、健全安全生产责任制，制定完备的安全生产规章制度和操作规程", "管理人员和作业人员每年至少进行二次安全生产教育培训并考核合格", "依法参加工伤保险，依法为施工现场从事危险作业的人员办理意外伤害保险，为从业人员交纳保险费", "设置安全生产管理机构，按照国家有关规定配备专职安全生产管理人员", "保证本单位安全生产条件所需资金的投入"], "answer": [0, 2, 3, 4], "explanation": "（六）管理人员和作业人员每年至少进行一次安全生产教育培训并考核合格；"},
  {"id": 831, "type": "multiple", "question": "某施工单位申领建筑施工企业安全生产许可证时，根据我国《建筑施工企业安全生产许可证管理规定》，应具备经建设行政主管或其他有关部门考核合格的人员包括 （　　） 。", "options": ["应急救援人员", "单位主要负责人", "从业人员", "专职安全生产管理人员", "特种作业人员"], "answer": [1, 3, 4], "explanation": "第四条 建筑施工企业取得安全生产许可证，应当具备下列安全生产条件：\n（一）建立、健全安全生产责任制，制定完备的安全生产规章制度和操作规程；\n（二）保证本单位安全生产条件所需资金的投入；\n（三）设置安全生产管理机构，按照国家有关规定配备专职安全生产管理人员；\n（四）主要负责人、项目负责人、专职安全生产管理人员经建设主管部门或者其他有关部门考核合格；\n（五）特种作业人员经有关业务主管部门考核合格，取得特种作业操作资格证书；\n（六）管理人员和作业人员每年至少进行一次安全生产教育培训并考核合格；\n（七）依法参加工伤保险，依法为施工现场从事危险作业的人员办理意外伤害保险，为从业人员交纳保险费；\n（八）施工现场的办公、生活区及作业场所和安全防护用具、机械设备、施工机具及配件符合有关安全生产法律、法规、标准和规程的要求；\n（九）有职业危害防治措施，并为作业人员配备符合国家标准或者行业标准的安全防护用具和安全防护服装；\n（十）有对危险性较大的分部分项工程及施工现场易发生重大事故的部位、环节的预防、监控措施和应急预案；\n（十一）有生产安全事故应急救援预案、应急救援组织或者应急救援人员，配备必要的应急救援器材、设备；\n（十二）法律、法规规定的其他条件。"},
  {"id": 832, "type": "multiple", "question": "安委会一般包含主要负责人（最高管理者，党政同责），企业各分管领导、各职能部门负责人、工会代表组成，任务是 （　　） 企业重大安全生产问题。", "options": ["调查", "研究", "分析", "讨论", "解决"], "answer": [1, 2, 4], "explanation": "【依据】习近平总书记关于安全生产重要论述\n【解析】正确答案是B、C、D、E。题干对应的是安全生产方针和责任体系。 A项“调查”错误，它不符合题干限定的对象、程序或条件。 B项“研究”正确，它与题干所述“安委会一般包含主要负责人（最高管理者，党政同”相对应。 C项“分析”正确，它与题干所述“安委会一般包含主要负责人（最高管理者，党政同”相对应。 D项“讨论”正确，它与题干所述“安委会一般包含主要负责人（最高管理者，党政同”相对应。 E项“解决”正确，它与题干所述“安委会一般包含主要负责人（最高管理者，党政同”相对应。"},
  {"id": 833, "type": "multiple", "question": "建筑施工企业主要负责人、项目负责人、专职安全生产管理人员安全教育内容，依履职要求不同而有所差别。下列选项中，属于他们都应掌握的安全教育培训的内容是 （　　） 。", "options": ["建筑施工安全生产的方针政策、法律法规和标准规范", "工程建设各方主体的安全生产法律义务与法律责任", "企业安全生产责任制和安全生产管理制度", "安全检查、隐患排查与安全生产标准化", "地管理与文明施工"], "answer": [0, 1, 2, 3, 4], "explanation": "安全生产知识考核要点\n建筑施工安全生产的方针政策、法律法规、规章制度和标准规范。\n建筑施工安全生产管理、工程项目施工安全生产管理的基本理论和基础知识。\n工程建设各方主体的安全生产法律义务与法律责任。\n企业、工程项目安全生产责任制和安全生产管理制度。\n安全生产保证体系、资质资格、费用保险、教育培训、机械设备、防护用品、评价考核等管理。\n危险性较大的分部分项工程、危险源辨识、安全技术交底和安全技术资料等安全技术管理。\n施工现场安全检查、隐患排查与安全生产标准化。\n场地管理与文明施工。\n事故应急救援和事故报告、调查与处理。\n起重吊装、土方与筑路机械、建筑起重与升降机械设备等安全技术要点。\n国内外安全生产管理经验与典型事故案例分析。"},
  {"id": 834, "type": "multiple", "question": "申请参加安全生产考核的“安管人员”，应当具备 （　　） ,与企业确立劳动关系，并经企业年度安全生产教育培训合格。", "options": ["相应文化程度", "专业工作年限", "专业技术职称", "一定安全生产工作经历", "专业工作职位"], "answer": [0, 2, 3], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】正确答案是A、B、D。题干对应的是建筑施工安全管理。 A项“相应文化程度”正确，它与题干所述“申请参加安全生产考核的“安管人员”，应当具备”相对应。 B项“专业工作年限”正确，它与题干所述“申请参加安全生产考核的“安管人员”，应当具备”相对应。 C项“专业技术职称”错误，它不符合题干限定的对象、程序或条件。 D项“一定安全生产工作经历”正确，它与题干所述“申请参加安全生产考核的“安管人员”，应当具备”相对应。 E项“专业工作职位”错误，它不符合题干限定的对象、程序或条件。"},
  {"id": 835, "type": "multiple", "question": "《建筑施工企业主要负责人、项目负责人和专职安全生产管理人员安全生产管理规定》中阐述：安全生产管理能力考核的内容有 （　　） 。", "options": ["建筑施工安全管理基本理论", "建立和落实安全生产管理制度", "辨识和监控危险性较大的分部分项工程", "发现和消除安全事故隐患", "报告和处置生产安全事故"], "answer": [1, 2, 3, 4], "explanation": "第七条 安全生产考核包括安全生产知识考核和管理能力考核。\n安全生产知识考核内容包括：建筑施工安全的法律法规、规章制度、标准规范，建筑施工安全管理基本理论等。\n安全生产管理能力考核内容包括：建立和落实安全生产管理制度、辨识和监控危险性较大的分部分项工程、发现和消除安全事故隐患、报告和处置生产安全事故等方面的能力。"},
  {"id": 836, "type": "multiple", "question": "根据《安全生产法》的规定，生产经营单位的安全生产管理机构以及安全生产管理人员履行职责 （　　） 职责。", "options": ["组织拟定本单位安全生产规章制度", "参与拟定本单位操作规程", "组织开展危险源辨识和评估", "组织本单位应急救援演练", "督促落实本单位安全生产整改措施"], "answer": [0, 1, 2, 3, 4], "explanation": "第二十五条 生产经营单位的安全生产管理机构以及安全生产管理人员履行下列职责：\n（一）组织或者参与拟订本单位安全生产规章制度、操作规程和生产安全事故应急救援预案；\n（二）组织或者参与本单位安全生产教育和培训，如实记录安全生产教育和培训情况；\n（三）组织开展危险源辨识和评估，督促落实本单位重大危险源的安全管理措施；\n（四）组织或者参与本单位应急救援演练；\n（五）检查本单位的安全生产状况，及时排查生产安全事故隐患，提出改进安全生产管理的建议；\n（六）制止和纠正违章指挥、强令冒险作业、违反操作规程的行为；\n（七）督促落实本单位安全生产整改措施。\n生产经营单位可以设置专职安全生产分管负责人，协助本单位主要负责人履行安全生产管理职责。"},
  {"id": 837, "type": "multiple", "question": "根据《建筑施工项目经理质量安全责任十项规定》的要求，项目经理必须组织对进入现场的 （　　） 等进行检验，未经检验或检验不合格，不得使用。", "options": ["办公用品", "建筑材料", "构配件", "设备", "预拌混凝土"], "answer": [1, 2, 3, 4], "explanation": "四、项目经理必须组织对进入现场的建筑材料、构配件、设备、预拌混凝土等进行检验，未经检验或检验不合格，不得使用；必须组织对涉及结构安全的试块、试件以及有关材料进行取样检测，送检试样不得弄虚作假，不得篡改或者伪造检测报告，不得明示或暗示检测机构出具虚假检测报告。"},
  {"id": 838, "type": "multiple", "question": "根据《上海市建设工程项目经理质量安全管理履职规定》，建立建设工程项目质量和安全管理体系并组织实施，采取有效措施，确保项目管理机构按照相关规定配置 （　　） 、施工员、材料员、资料员、标准员、劳务员等相关技术和管理人员，明确其相应的岗位职责并签订责任书，做好相关人员的日常考勤工作。", "options": ["项目技术负责人", "质量员", "安全员", "机械员", "财务员"], "answer": [0, 1, 2, 3], "explanation": "一）建立建设工程项目质量和安全管理体系并组织实施,采取有效措施,确保项目管理机构按照相关规定配置项目技术负责人、质量员、安全员、施工员、材料员、资料员、标准员、机械员、劳务员等相关技术和管理人员，明确其相应的岗位职责并签订责任书，做好相关人员的日常考勤工作。"},
  {"id": 839, "type": "multiple", "question": "根据《上海市建筑施工企业主要负责人、项目负责人和专职安全生产管理人员安全生产考核发证管理办法》的规定，申请建筑施工企业专职安全生产管理人员（C类）安全生产知识初证考试，应当具备 （　　） 条件。", "options": ["取得相应注册执业资格", "具有中专（含高中、中技、职高）及以上文化程度或初级及以上专业技术职称，且从事施工管理工作两年以上", "与所在企业确立劳动关系", "经所在企业年度安全生产教育培训合格", "年龄已满18周岁未满60周岁，身体健康"], "answer": [1, 2, 3, 4], "explanation": "申请建筑施工企业专职安全生产管理人员（C 类）安全生产知识初证考试，应当具备下列条件：\n(一)年龄已满18周岁未满60周岁，身体健康。\n(二)具有中专（含高中、中技、职高）及以上文化程度或初级及以上专业技术职称，且从事施工管理工作两年以上。\n(三)与所在企业确立劳动关系。\n(四)经所在企业年度安全生产教育培训合格。"},
  {"id": 840, "type": "multiple", "question": "下列选项中属于企业安委会组成的是 （　　） 。", "options": ["企业主要负责人", "企业各分管领导", "各职能部门负责人", "工会代表", "一线工人代表"], "answer": [0, 1, 2, 3, 4], "explanation": "【依据】《建筑施工企业安全生产管理机构设置及专职安全生产管理人员配备办法》 / 《建筑施工企业主要负责人、项目负责人和专职安全生产管理人员安全生产管理规定》\n【解析】正确答案是A、B、C、D。题干对应的是企业和项目安全生产组织管理。 A项“企业主要负责人”正确，题干对应职责主体就是企业主要负责人。 B项“企业各分管领导”正确，它与题干所述“企业安委会组成的是”相对应。 C项“各职能部门负责人”正确，它与题干所述“企业安委会组成的是”相对应。 D项“工会代表”正确，它与题干所述“企业安委会组成的是”相对应。 E项“一线工人代表”错误，它不符合题干限定的对象、程序或条件。"},
  {"id": 841, "type": "multiple", "question": "建设工程项目安全生产领导小组的主要职责有 （　　） 。", "options": ["贯彻落实国家有关安全生产法律法规和标准", "组织制定项目安全生产管理制度并监督实施", "编制项目生产安全事故应急救援预案并组织演练", "保证项目安全生产费用的有效使用", "组织编制危险性较大工程安全专项施工方案"], "answer": [0, 1, 2, 3, 4], "explanation": "安全生产领导小组的主要职责：\n（1）贯彻落实国家有关安全生产法律法规和标准；\n（2）组织制定项目安全生产管理制度并监督实施；\n（3）编制项目生产安全事故应急救援预案并组织演练；\n（4）保证项目安全生产费用的有效使用；\n（5）组织编制危险性较大工程安全专项施工方案；\n（6）开展项目安全教育培训；\n（7）组织实施项目安全检查和隐患排查；\n（8）建立项目安全生产管理档案；\n（9）及时、如实报告安全生产事故。"},
  {"id": 842, "type": "multiple", "question": "建筑施工企业项目负责人安全教育培训内容主要包括 （　　） 。", "options": ["建筑施工安全生产的方针政策、法律法规和标准规范", "建筑施工安全生产管理、工程项目施工安全生产管理的基本理论和基础知识", "企业、工程项目安全生产责任制和安全生产管理制度", "危险性较大的分部分项工程、危险源辨识、安全技术交底和安全技术资料等安全技术管理", "场地管理与文明施工"], "answer": [0, 1, 2, 3, 4], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材\n【解析】正确答案是A、B、C、D、E。题干对应的是安全生产管理基础知识。 A项“建筑施工安全生产的方针政策、法律法规和标准规范”正确，它与题干所述“建筑施工企业项目负责人安全教育培训内容主要包”相对应。 B项“建筑施工安全生产管理、工程项目施工安全生产管理的基本理论和基础知识”正确，它与题干所述“建筑施工企业项目负责人安全教育培训内容主要包”相对应。 C项“企业、工程项目安全生产责任制和安全生产管理制度”正确，它与题干所述“建筑施工企业项目负责人安全教育培训内容主要包”相对应。 D项“危险性较大的分部分项工程、危险源辨识、安全技术交底和安全技术资料等安全技术管理”正确，它与题干所述“建筑施工企业项目负责人安全教育培训内容主要包”相对应。 E项“场地管理与文明施工”正确，它与题干所述“建筑施工企业项目负责人安全教育培训内容主要包”相对应。"},
  {"id": 843, "type": "multiple", "question": "根据《建筑施工企业主要负责人、项目负责人和专职安全生产管理人员安全管理规定》，关于“安管人员”安全生产考核的说法，不正确的有 （　　） 。", "options": ["“安管人员”应当自行申请安全生产考核", "“安管人员”的安全生产考核由国务院住房城乡建设行政主管部门统一颁发合格证书", "安全生产考核证书的有效期无限制", "应当向省级人民政府住房城乡建设主管部门申请安全生产考核", "安全生产考核证书在全国范围内有效"], "answer": [0, 1, 2], "explanation": "【注意题目是不正确的】安管人员”应当通过其受聘企业，向企业工商注册地的省、自治区、直辖市人民政府住房城乡建设主管部门（以下简称考核机关）申请安全生产考核，并取得安全生产考核合格证书。安全生产考核不得收费。\n第九条 安全生产考核合格证书有效期为3年，证书在全国范围内有效。\n证书式样由国务院住房城乡建设主管部门统一规定。"},
  {"id": 844, "type": "multiple", "question": "根据《建筑施工企业安全生产管理机构设置及专职安全生管理人员配备办法》的规定，关于建筑施工企业安全生产管理机构专职安全生产管理人员配备的说法，不正确的有 （　　） 。", "options": ["建筑施工总承包资质特级资质专职安全生产管理人员不少于6人", "建筑施工企业安全生产管理机构专职安全生产管理员的配备与企业经营规模和生产需要有关，与企业设备管理无关", "建筑施工专业承包资质二级和二级以下资质企业的专职安全生产管理人员不少于2人", "建筑施工企业的分公司、区域公司等较大的分支机构不需要具备专职安全生产管理人员", "建筑施工劳务分包资质序列企业的专职安全生产管理人员不少于2人"], "answer": [1, 3], "explanation": "【依据】《建筑施工企业安全生产管理机构设置及专职安全生管理人员配备办法》\n【解析】正确答案是B、D。这是一道反向设问题，题干要找的是“不符合/不属于/错误”项。 A项“建筑施工总承包资质特级资质专职安全生产管理人员不少于6人”错误，该事项的责任主体不是建筑施工总承包资质特级资质专职安全生产管理人员不少于6人，而是建筑施工企业安全生产管理机构专职安全生产管理员的配备与企业经营规模和生产需要有关，与企业设备管理无关。 B项“建筑施工企业安全生产管理机构专职安全生产管理员的配备与企业经营规模和生产需要有关，与企业设备管理无关”正确，它与题干所述“的规定，建筑施工企业安全生产管理机构专职安全”相对应。 C项“建筑施工专业承包资质二级和二级以下资质企业的专职安全生产管理人员不少于2人”错误，该事项的责任主体不是建筑施工专业承包资质二级和二级以下资质企业的专职安全生产管理人员不少于2人，而是建筑施工企业安全生产管理机构专职安全生产管理员的配备与企业经营规模和生产需要有关，与企业设备管理无关。 D项“建筑施工企业的分公司、区域公司等较大的分支机构不需要具备专职安全生产管理人员”正确，该事项的责任主体不是建筑施工企业的分公司、区域公司等较大的分支机构不需要具备专职安全生产管理人员，而是建筑施工企业安全生产管理机构专职安全生产管理员的配备与企业经营规模和生产需要有关，与企业设备管理无关。 E项“建筑施工劳务分包资质序列企业的专职安全生产管理人员不少于2人”错误，该事项的责任主体不是建筑施工劳务分包资质序列企业的专职安全生产管理人员不少于2人，而是建筑施工企业安全生产管理机构专职安全生产管理员的配备与企业经营规模和生产需要有关，与企业设备管理无关。"},
  {"id": 845, "type": "multiple", "question": "依据《建筑施工企业安全生产管理机构设置及专职安全生产管理人员配备办法》的规定，分包单位配备项目专职安全生产管理人员应当满足的要求，下列说法不正确的有 （　　） 。", "options": ["劳务分包单位施工人员在50人以下的，应当配备1名专职安全生产管理人员", "劳务分包单位施工人员在50人以下的，不需要配备专职安全生产管理人员", "劳务分包单位施工人员200人及以上的，应当配备3名及以上专职安全生产管理人员，并根据所承担的分部分项工程施工危险实际情况增加，不得少于工程施工人员总人数的5‰。", "劳务分包单位施工人员50人-200人的，应当配备1名专职安全生产管理人员", "劳务分包单位施工人员50人-200人的，应当配备2名专职安全生产管理人员"], "answer": [1, 3], "explanation": "【依据】《建筑施工企业安全生产管理机构设置及专职安全生产管理人员配备办法》\n【解析】正确答案是B、E。这是一道反向设问题，题干要找的是“不符合/不属于/错误”项。 A项“劳务分包单位施工人员在50人以下的，应当配备1名专职安全生产管理人员”错误，该事项的责任主体不是劳务分包单位施工人员在50人以下的，应当配备1名专职安全生产管理人员，而是劳务分包单位施工人员在50人以下的，不需要配备专职安全生产管理人员。 B项“劳务分包单位施工人员在50人以下的，不需要配备专职安全生产管理人员”正确，题干对应职责主体就是劳务分包单位施工人员在50人以下的，不需要配备专职安全生产管理人员。 C项“劳务分包单位施工人员200人及以上的，应当配备3名及以上专职安全生产管理人员，并根据所承担的分部分项工程施工危险实际情况增加，不得少于工程施工人员总人数的5‰。”错误，该事项的责任主体不是劳务分包单位施工人员200人及以上的，应当配备3名及以上专职安全生产管理人员，并根据所承担的分部分项工程施工危险实际情况增加，不得少于工程施工人员总人数的5‰。，而是劳务分包单位施工人员在50人以下的，不需要配备专职安全生产管理人员。 D项“劳务分包单位施工人员50人-200人的，应当配备1名专职安全生产管理人员”错误，该事项的责任主体不是劳务分包单位施工人员50人-200人的，应当配备1名专职安全生产管理人员，而是劳务分包单位施工人员在50人以下的，不需要配备专职安全生产管理人员。 E项“劳务分包单位施工人员50人-200人的，应当配备2名专职安全生产管理人员”正确，该事项的责任主体不是劳务分包单位施工人员50人-200人的，应当配备2名专职安全生产管理人员，而是劳务分包单位施工人员在50人以下的，不需要配备专职安全生产管理人员。"},
  {"id": 846, "type": "multiple", "question": "根据《建筑施工项目经理质量安全责任十项规定》，建筑施工项目经理质量安全责任包括 （　　） 。", "options": ["项目经理必须组织对进入现场的建筑材料、构配件、设备、预拌混凝土等进行检验，未经检验或检验不合格，不得使用", "项目经理必须组织做好隐蔽工程的验收工作，参加地基基础、主体结构等分部工程的验收，参加单位工程和工程竣工验收", "项目经理必须将安全生产费用足额用于安全防护和安全措施，不得挪作他用", "项目经理必须组织对施工现场作业人员进行岗前质量安全教育，组织审核建筑施工特种作业人员操作资格证书，未经质量安全教育和无证人员不得上岗", "项目经理必须按规定报告质量安全事故，立即启动应急预案，保护事故现场，开展应急救援"], "answer": [0, 1, 2, 3, 4], "explanation": "一、建筑施工项目经理（以下简称项目经理）必须按规定取得相应执业资格和安全生产考核合格证书；合同约定的项目经理必须在岗履职，不得违反规定同时在两个及两个以上的工程项目担任项目经理。\n二、项目经理必须对工程项目施工质量安全负全责，负责建立质量安全管理体系，负责配备专职质量、安全等施工现场管理人员，负责落实质量安全责任制、质量安全管理规章制度和操作规程。\n三、项目经理必须按照工程设计图纸和技术标准组织施工，不得偷工减料；负责组织编制施工组织设计，负责组织制定质量安全技术措施，负责组织编制、论证和实施危险性较大分部分项工程专项施工方案；负责组织质量安全技术交底。\n四、项目经理必须组织对进入现场的建筑材料、构配件、设备、预拌混凝土等进行检验，未经检验或检验不合格，不得使用；必须组织对涉及结构安全的试块、试件以及有关材料进行取样检测，送检试样不得弄虚作假，不得篡改或者伪造检测报告，不得明示或暗示检测机构出具虚假检测报告。\n五、项目经理必须组织做好隐蔽工程的验收工作，参加地基基础、主体结构等分部工程的验收，参加单位工程和工程竣工验收；必须在验收文件上签字，不得签署虚假文件。\n六、项目经理必须在起重机械安装、拆卸，模板支架搭设等危险性较大分部分项工程施工期间现场带班；必须组织起重机械、模板支架等使用前验收，未经验收或验收不合格，不得使用；必须组织起重机械使用过程日常检查，不得使用安全保护装置失效的起重机械。\n七、项目经理必须将安全生产费用足额用于安全防护和安全措施，不得挪作他用；作业人员未配备安全防护用具，不得上岗；严禁使用国家明令淘汰、禁止使用的危及施工质量安全的工艺、设备、材料。\n八、项目经理必须定期组织质量安全隐患排查，及时消除质量安全隐患；必须落实住房城乡建设主管部门和工程建设相关单位提出的质量安全隐患整改要求，在隐患整改报告上签字。\n九、项目经理必须组织对施工现场作业人员进行岗前质量安全教育，组织审核建筑施工特种作业人员操作资格证书，未经质量安全教育和无证人员不得上岗。\n十、项目经理必须按规定报告质量安全事故，立即启动应急预案，保护事故现场，开展应急救援。"},
  {"id": 847, "type": "multiple", "question": "建设工程安全生产标准化是从 （　　） 发展和引申而来的。", "options": ["标准", "标准化", "安全标准化", "企业安全生产标准化", "国家安全生产标准化"], "answer": [0, 1, 2, 3], "explanation": "【依据】《企业安全生产标准化基本规范》 / 《中华人民共和国标准化法》\n【解析】正确答案是B、C。题干对应的是安全生产标准化与标准基础。 A项“标准”错误，它不符合题干限定的对象、程序或条件。 B项“标准化”正确，它与题干所述“建设工程安全生产标准化是从发展和引申而来的”相对应。 C项“安全标准化”正确，它与题干所述“建设工程安全生产标准化是从发展和引申而来的”相对应。 D项“企业安全生产标准化”错误，它不符合题干限定的对象、程序或条件。 E项“国家安全生产标准化”错误，它不符合题干限定的对象、程序或条件。"},
  {"id": 848, "type": "multiple", "question": "标准样品是具有一种或多种良好特性值的材料或物质，主要用于 （　　） 。", "options": ["实验验证", "科技成果", "校准仪器", "评价测量方法", "给材料赋值"], "answer": [2, 3, 4], "explanation": "标准样品是具有一种或多种足够均匀的和很好确定了的特性值的材料或物质,可以用来校准仪器、评价测量方法和给材料赋值。"},
  {"id": 849, "type": "multiple", "question": "安全生产标准化体现了 （　　） 的方针和“以人为本”的科学发展观，强调企业安全生产工作的规范化、科学化、系统化和法制化。", "options": ["安全第一", "科学第一", "预防为主", "系统预防", "综合治理"], "answer": [0, 2, 4], "explanation": "【依据】《企业安全生产标准化基本规范》 / 《中华人民共和国标准化法》\n【解析】正确答案是A、C、E。题干对应的是安全生产标准化与标准基础。 A项“安全第一”正确，它与题干所述“安全生产标准化体现了的方针和“以人为本”的科”相对应。 B项“科学第一”错误，它不符合题干限定的对象、程序或条件。 C项“预防为主”正确，它与题干所述“安全生产标准化体现了的方针和“以人为本”的科”相对应。 D项“系统预防”错误，它不符合题干限定的对象、程序或条件。 E项“综合治理”正确，它与题干所述“安全生产标准化体现了的方针和“以人为本”的科”相对应。"},
  {"id": 850, "type": "multiple", "question": "下列选项中，属于安全生产标准化作用的是 （　　） 。", "options": ["消灭事故发生的有效办法", "落实企业主体责任的基本手段", "提升企业安全管理的重要方法", "提高企业安全水平的有效途径", "树立企业形象的重要措施"], "answer": [1, 2, 3], "explanation": "【依据】《企业安全生产标准化基本规范》 / 《中华人民共和国标准化法》\n【解析】正确答案是B、C、D。题干对应的是安全生产标准化与标准基础。 A项“消灭事故发生的有效办法”错误，它不符合题干限定的对象、程序或条件。 B项“落实企业主体责任的基本手段”正确，它与题干所述“安全生产标准化作用的是”相对应。 C项“提升企业安全管理的重要方法”正确，它与题干所述“安全生产标准化作用的是”相对应。 D项“提高企业安全水平的有效途径”正确，它与题干所述“安全生产标准化作用的是”相对应。 E项“树立企业形象的重要措施”错误，它不符合题干限定的对象、程序或条件。"},
  {"id": 851, "type": "multiple", "question": "安全生产标准化强调过程控制和系统管理，将贯彻国家有关法律法规、标准规程的行为过程及结果定量化或定性化，使安全生产工作处于可控状态，并通过 （　　） 等方式、方法和手段的结合，形成了有效的安全生产激励约束机制。", "options": ["内部评审", "外部评审", "建模考核", "绩效考核", "评分考核"], "answer": [0, 3], "explanation": "【依据】《企业安全生产标准化基本规范》 / 《中华人民共和国标准化法》\n【解析】正确答案是A、B、D、E。题干对应的是安全生产标准化与标准基础。 A项“内部评审”正确，它与题干所述“安全生产标准化强调过程控制和系统管理，将贯彻”相对应。 B项“外部评审”正确，它与题干所述“安全生产标准化强调过程控制和系统管理，将贯彻”相对应。 C项“建模考核”错误，它不符合题干限定的对象、程序或条件。 D项“绩效考核”正确，它与题干所述“安全生产标准化强调过程控制和系统管理，将贯彻”相对应。 E项“评分考核”正确，它与题干所述“安全生产标准化强调过程控制和系统管理，将贯彻”相对应。"},
  {"id": 852, "type": "multiple", "question": "根据《上海市建筑施工安全生产标准化考评规范》的规定，受监监督机构收到 （　　） 共同签署确认的工地完工报告，以及施工总包单位填报的施工项目安全生产标准化竣工考核评审表后，经查验符合完工要求的，在网上进行施工项目安全生产标准化竣工确认。", "options": ["施工单位", "建设单位", "项目负责人", "监理单位", "施工总包单位"], "answer": [1, 3, 4], "explanation": "第十七条 受监监督机构收到建设单位、监理单位、施工总包单位共同签署确认的工地完工报告，以及施工总包单位填 报的施工项目安全生产标准化竣工考核评审表后，经查验符合完工要求的，在网上进行施工项目安全生产标准化竣工确认。"},
  {"id": 853, "type": "multiple", "question": "《施工企业安全生产评价标准》（JGJ/T77-2010）规定，施工企业安全生产条件按 （　　） 等内容进行考核。", "options": ["安全生产管理", "安全技术管理", "企业自发性行为", "设备和设施管理", "施工现场安全管理"], "answer": [0, 1, 3, 4], "explanation": "【依据】《施工企业安全生产评价标准》\n【解析】正确答案是A、B、D、E。题干对应的是施工企业安全生产评价标准。 A项“安全生产管理”正确，它与题干所述“《施工企业安全生产评价标准》（JGJ/T77”相对应。 B项“安全技术管理”正确，它与题干所述“《施工企业安全生产评价标准》（JGJ/T77”相对应。 C项“企业自发性行为”错误，它不符合题干限定的对象、程序或条件。 D项“设备和设施管理”正确，它与题干所述“《施工企业安全生产评价标准》（JGJ/T77”相对应。 E项“施工现场安全管理”正确，它与题干所述“《施工企业安全生产评价标准》（JGJ/T77”相对应。"},
  {"id": 854, "type": "multiple", "question": "《建筑施工安全生产标准化考评暂行办法》明确，建筑施工安全生产标准化考评工作应坚持 （　　） 的原则。", "options": ["公平", "公开", "公正", "客观", "主观"], "answer": [1, 2, 3], "explanation": "建筑施工安全生产标准化考评工作应坚持客观、公正、公开的原则"},
  {"id": 855, "type": "multiple", "question": "《建筑施工安全生产标准化考评暂行办法》明确，建筑施工企业具有 （　　） 之一的，安全生产标准化评定为不合格。", "options": ["未按规定开展企业自评工作的", "企业近三年所承建的项目发生较大及以上生产安全责任事故的", "企业近三年所承建已竣工项目不合格率超过5%的", "省级及以上住房城乡建设主管部门规定的其他情形", "企业近三年所承建的项目发生一般及以上生产安全责任事故的"], "answer": [0, 1, 2, 3], "explanation": "【依据】《建筑施工安全生产标准化考评暂行办法》\n【解析】正确答案是A、B、D。题干对应的是建筑施工安全生产标准化考评暂行办法。 A项“未按规定开展企业自评工作的”正确，它与题干所述“《建筑施工安全生产标准化考评暂行办法》明确，”相对应。 B项“企业近三年所承建的项目发生较大及以上生产安全责任事故的”正确，它与题干所述“《建筑施工安全生产标准化考评暂行办法》明确，”相对应。 C项“企业近三年所承建已竣工项目不合格率超过5%的”错误，它不符合题干限定的对象、程序或条件。 D项“省级及以上住房城乡建设主管部门规定的其他情形”正确，它与题干所述“《建筑施工安全生产标准化考评暂行办法》明确，”相对应。 E项“企业近三年所承建的项目发生一般及以上生产安全责任事故的”错误，它不符合题干限定的对象、程序或条件。"},
  {"id": 856, "type": "multiple", "question": "根据《上海市建筑施工安全生产标准化考评规范》规定，有 （　　） 之一的，季度确认等级为“不合格”。", "options": ["《上海市建设工程安全生产标准化评分表》60分以下", "当季月度考评及复核有2次及以上“不合格”等级", "当季月度考评及复核与工地实际情况不相符", "当季度发生较大及以上生产安全事故", "当季度漏报、谎报、瞒报生产安全事故"], "answer": [1, 2, 3, 4], "explanation": "（二）有下列情形之一的，季度确认为“不合格”。\n1.《上海市建设工程安全生产标准化评分表》70 分以下；\n2.当季月度考评及复核有2次及以上“不合格”等级；\n3.当季月度考评及复核与工地实际情况不相符；\n4.当季度发生较大及以上生产安全事故；\n5.当季度漏报、谎报、瞒报生产安全事故；\n6.近期安全管理性文件未有效推进落实。"},
  {"id": 857, "type": "multiple", "question": "根据《上海市建筑施工安全生产标准化考评规范》规定，具有 （　　） 之一的，企业年度安全生产标准化评定为“不合格”。", "options": ["未按规定开展企业自评工作的", "企业本年度所承建的项目发生三起及以上较大及以上生产安全责任事故", "企业本年度所承建的项目发生两起及以上一般生产安全责任事故", "企业本年度已竣工项目不合格率超过5%", "企业本年度受到非事故原因暂扣安全生产许可证处理"], "answer": [0, 3, 4], "explanation": "（二）具有下列情形之一的，企业年度安全生产标准化评定为“不合格”。\n1.未按规定开展企业自评工作；\n2.企业本年度所承建的项目发生较大及以上生产安全责任事故；\n3.企业本年度所承建的项目发生三起及以上一般生产安全责任事故；\n4.企业本年度已竣工项目不合格率超过5%；\n5.企业本年度受到非事故原因暂扣安全生产许可证处理。"},
  {"id": 858, "type": "multiple", "question": "根据“关于贯彻落实《上海市建筑施工安全生产标准化考评规范》（2016版）若干事项的通知（沪建安质监(2017)57号）”指出，安全生产标准化工作应当围绕 （　　） 等内容全面开展。", "options": ["班组的标准化", "文件资料的标准化", "物的标准化", "人的标准化", "管理的标准化"], "answer": [2, 3, 4], "explanation": "安全生产标准化工作应当围绕以建筑行业、企业、施工现场、班组各层面安全管理为主的“管理的标准化”、以建筑施工现场人员安全行为为主的“人的标准化”、以建筑施工现场实物状态安全为主的“物的标准化”等三个方面的内容全面开展。"},
  {"id": 859, "type": "multiple", "question": "满足下列 （　　） 条件的土方开挖、支护、降水工程属于危险性较大的分部分项工程。", "options": ["开挖深度≥3m", "地质条件、周围环境、地下管线复杂", "采用放坡开挖", "重大工程", "影响毗邻建、构筑物安全"], "answer": [0, 1, 4], "explanation": "【依据】《建筑基坑支护技术规程》JGJ 120-2012 / 《建筑基坑工程监测技术标准》GB 50497-2019\n【解析】正确答案是A、B、E。题干对应的是基坑工程安全与监测。 A项“开挖深度≥3m”正确，它与题干所述“满足下列条件的土方开挖、支护、降水工程危险性”相对应。 B项“地质条件、周围环境、地下管线复杂”正确，它与题干所述“满足下列条件的土方开挖、支护、降水工程危险性”相对应。 C项“采用放坡开挖”错误，它不符合题干限定的对象、程序或条件。 D项“重大工程”错误，它不符合题干限定的对象、程序或条件。 E项“影响毗邻建、构筑物安全”正确，它与题干所述“满足下列条件的土方开挖、支护、降水工程危险性”相对应。"},
  {"id": 860, "type": "multiple", "question": "根据《上海市建设工程危险性较大的分部分项工程安全管理实施细则》规定，将 （　　） 增设入危大工程的定义范围。", "options": ["包含有限空间作业的施工工程", "多台多机种作业工程", "改扩建工程中承重结构拆除工程", "地下隧道注浆帷幕工程", "冻结法工程"], "answer": [0, 2], "explanation": "危大工程的定义范围详见附件1，并增设：1、包含有限空间作业的施工工程；2、改扩建工程中承重结构拆除工程。其中，基坑工程的管理按照《上海市基坑工程管理办法》实施。"},
  {"id": 861, "type": "multiple", "question": "下列关于超过一定规模的危险性较大的分部分项工程范围，正确的有 （　　） 。", "options": ["搭设高度50m 及以上的落地式钢管脚手架工程", "提升高度在150m及以上的附着式升降脚手架工程", "分段架体搭设高度20m 及以上的悬挑式脚手架工程", "高处作业吊篮", "异型脚手架工程"], "answer": [0, 1, 2], "explanation": "脚手架工程\n（一）搭设高度50m及以上的落地式钢管脚手架工程。\n（二）提升高度在150m及以上的附着式升降脚手架工程或附着式升降操作平台工程。\n（三）分段架体搭设高度20m及以上的悬挑式脚手架工程。"},
  {"id": 862, "type": "multiple", "question": "下列关于危险性较大的分部分项工程专项施工方案的主要内容，正确的有 （　　） 。", "options": ["工程概况", "编制依据", "施工工艺技术", "施工安全保证措施", "资金计划"], "answer": [0, 1, 2, 3], "explanation": "三、建筑工程项目施工相关法规与标准专项方案编制应当包括以下内容：\n（1）工程概况：危险性较大的分部分项工程概况、施工平面布置、施工要求和技术保证条件。\n（2）编制依据：相关法律、法规、规范性文件、标准、规范及图纸（国标图集）、施工组织设计等。\n（3）施工计划：包括施工进度计划、材料与设备计划。\n（4）施工工艺技术：技术参数、工艺流程、施工方法、检查验收等。\n（5）施工安全保证措施：组织保障、技术措施、应急预案、监测监控等。\n（6）劳动力计划：专职安全生产管理人员、特种作业人员等。\n（7）计算书及相关图纸。\n工程造价虽然重要，但是不属于编制施工方案的必要内容。"},
  {"id": 863, "type": "multiple", "question": "危大工程专项施工方案主要内容中的验收要求包括 （　　） 等内容。", "options": ["验收标准", "验收程序", "验收内容", "验收人员", "验收作业"], "answer": [0, 1, 2, 3], "explanation": "【依据】《危险性较大的分部分项工程安全管理规定》\n【解析】正确答案是A、B、C、D。题干对应的是危大工程专项施工方案管理。 A项“验收标准”正确，它与题干所述“危大工程专项施工方案主要内容中的验收要求包括”相对应。 B项“验收程序”正确，它与题干所述“危大工程专项施工方案主要内容中的验收要求包括”相对应。 C项“验收内容”正确，它与题干所述“危大工程专项施工方案主要内容中的验收要求包括”相对应。 D项“验收人员”正确，它与题干所述“危大工程专项施工方案主要内容中的验收要求包括”相对应。 E项“验收作业”错误，它不符合题干限定的对象、程序或条件。"},
  {"id": 864, "type": "multiple", "question": "对于危险性较大的分部分项工程现场安全管理，下列关于现场公告内容，正确的有 （　　） 。", "options": ["危大工程名称", "施工时间", "具体责任人员", "监理单位名称", "危险区域安全警示标志"], "answer": [0, 1, 2, 4], "explanation": "《危险性较大的分部分项工程安全管理规定》第四章 现场安全管理\n第十四条 施工单位应当在施工现场显著位置公告危大工程名称、施工时间和具体责任人员，并在危险区域设置安全警示标志。"},
  {"id": 865, "type": "multiple", "question": "根据《危险性较大的分部分项工程安全管理规定》，施工单位未按照专项施工方案施工的，监理单位可采取的措施有 （　　） 。", "options": ["要求立即整改", "要求暂停施工", "报告建设单位", "开具罚款单", "报告住房城乡建设主管部门"], "answer": [0, 1, 2, 4], "explanation": "【依据】《危险性较大的分部分项工程安全管理规定》\n【解析】正确答案是A、B、C、E。题干对应的是危险性较大的分部分项工程安全管理规定。 A项“要求立即整改”正确，它与题干所述“施工单位未按照专项施工方案施工的，监理单位可”相对应。 B项“要求暂停施工”正确，它与题干所述“施工单位未按照专项施工方案施工的，监理单位可”相对应。 C项“报告建设单位”正确，该事项的责任主体不是报告建设单位，而是要求立即整改。 D项“开具罚款单”错误，它不符合题干限定的对象、程序或条件。 E项“报告住房城乡建设主管部门”正确，它与题干所述“施工单位未按照专项施工方案施工的，监理单位可”相对应。"},
  {"id": 866, "type": "multiple", "question": "监理单位应当建立危大工程安全管理档案，将 （　　） 等相关资料纳入档案管理。", "options": ["专项施工方案审查", "监理大纲", "监理实施细则", "专项巡视检查", "验收及整改"], "answer": [0, 2, 3, 4], "explanation": "第二十四条 监理单位应当建立危大工程安全管理档案。\n监理单位应当将监理实施细则、专项施工方案审查、专项巡视检查、验收及整改等相关资料纳入档案管理。"},
  {"id": 867, "type": "multiple", "question": "根据《上海市建筑玻璃幕墙管理办法》，施工单位应当按照国家和本市 （　　） 进行玻璃幕墙的施工。", "options": ["相关技术标准", "审查合格的施工图设计文件", "施工组织设计文件", "工程设计要求", "合同约定"], "answer": [0, 1], "explanation": "第十四条（施工要求）\n施工单位应当按照国家和本市相关技术标准以及经审查合格的施工图设计文件进行玻璃幕墙的施工。\n施工单位应当在施工前编制玻璃幕墙专项施工方案。"},
  {"id": 868, "type": "multiple", "question": "根据《装配整体式混凝土结构工程施工安全管理规定》，下列关于其专项施工方案的主要内容，下列说法正确的有 （　　） 。", "options": ["预制构件堆放、驳运及吊装", "高处作业的安全防护", "专用操作平台、脚手架等设施及其附着设施", "垂直爬梯及吊篮等设施及其附着设施", "构件安装的临时支撑体系"], "answer": [0, 1, 2, 3, 4], "explanation": "专项施工方案应包括以下主要内容：\n（一）预制构件堆放、驳运及吊装，包括：现场装卸、堆放及驳运、吊装方式和路线；构件堆场的地基承载力计算；吊装设备选型，吊具设计；构件吊点、塔吊施工升降机附墙点等设计；\n（二）高处作业的安全防护，包括：因临边安装构件、连接节点现浇混凝土及成品保护修补所采取的防护措施以及交叉作业安全防护等；\n(三）专用操作平台、脚手架、垂直爬梯及吊篮等设施，及其附着设施；\n(四）构件安装的临时支撑体系等。"},
  {"id": 869, "type": "multiple", "question": "根据《关于进一步加强密闭空间施工作业安全管理的紧急通知》，在密闭空间场所内进行施工作业，活动范围有限，工作场地狭窄，并且通风条件差，极易发生 （　　） 造成人员伤亡事故。", "options": ["贫血", "中毒", "缺氧", "低血糖", "发热"], "answer": [1, 2], "explanation": "在密闭空间场所内进行施工作业，活动范围有限，工作场地狭窄，并且通风条件差，极易发生窒息缺氧或者因硫化氢、一氧化碳、甲烷、氰化氢等有毒有害气体引发中毒窒息等人员伤亡事故。"},
  {"id": 870, "type": "multiple", "question": "根据《上海市基坑工程管理办法》，基坑工程应当采用信息化施工和动态控制方法。对特别重要的基坑工程，施工单位应当采用 （　　） ，加强质量安全风险管控。", "options": ["信息化施工技术", "数字化施工技术", "远程监控", "报警系统", "应急预案"], "answer": [0, 1, 2, 3], "explanation": "第二十一条 基坑工程施工应当采用信息化施工和动态控制方法。对特别重要的基坑工程,施工单位应当采用信息化、数字化施工技术,运用远程监控及报警系统,加强质量安全风险管控。"},
  {"id": 871, "type": "multiple", "question": "在确定基坑围护结构（包括隔水帷幕等）与用地红线间的距离时，需要考虑围护结构施工对周边环境的影响和施工机械设备或发生险情后抢险所需的 （　　） 。", "options": ["抢险成本", "救援时间", "安全距离", "操作场地", "操作空间"], "answer": [2, 3, 4], "explanation": "对设计单位也提出了明确要求，如要求其在确定基坑围护结构（包括隔水帷幕等）与用地红线间的距离时，需要考虑围护结构施工对周边环境的影响和施工机械设备或发生险情后抢险所需的安全距离、操作场地和空间等，对基坑开挖、围护体施工、桩基施工采取严格措施，对抽取地下水等，要求采取回灌措施；对开挖深度7m以上的基坑工程，其设计方案应当根据地面沉降危险性评估结果，明确地面沉降监测和防治要求等。"},
  {"id": 872, "type": "multiple", "question": "根据《上海市危险性较大的分部分项工程专家论证管理办法》，对参加危险性较大的分部分项工程专项方案论证会议的对象有明确规定，下列选项正确的有 （　　） 。", "options": ["论证组成员", "建设单位项目负责人或技术负责人", "监理单位项目总监理工程师及专业监理工程师", "勘察、设计单位项目技术负责人及相关人员", "监督机构必须派员参加"], "answer": [0, 1, 3], "explanation": "第⼗六条（论证会议对象）下列⼈员应当参加专项⽅案论证会议：\n（⼀）论证组成员；\n（⼆）建设单位项⽬负责⼈或技术负责⼈；\n（三）监理单位项⽬总监理⼯程师及相关⼈员；\n（四）施⼯企业技术负责⼈、项⽬负责⼈、专项⽅案编制⼈员、项⽬专职安全⽣产管理⼈员；\n（五）勘察、设计单位项⽬技术负责⼈及相关⼈员；\n（六）监督机构视需要派员参加。"},
  {"id": 873, "type": "multiple", "question": "根据《上海市危险性较大的分部分项工程专家论证管理办法》，方案由施工企业自行组织论证的，论证档案由 （　　） 留存备查。", "options": ["设计单位", "建设单位", "施工单位", "监理单位", "监督机构"], "answer": [2, 3], "explanation": "方案由机构论证的，论证档案由论证机构和施工企业、监理单位分别留存；方案由施工企业自行组织论证的，论证档案由施工企业和监理单位留存备查。"},
  {"id": 874, "type": "multiple", "question": "根据《上海市建设工程危险性较大的分部分项工程安全管理实施细则》，下列关于危大工程验收人员的说法，正确的有 （　　） 。", "options": ["总承包单位和分包单位技术负责人或授权委派的专业技术人员", "施工单位项目负责人、项目技术负责人", "专项施工方案编制人员、项目专职安全生产管理人员", "监理单位项目总监理工程师及专业监理工程师", "有关勘察、设计和监测单位项目技术负责人"], "answer": [0, 1, 2, 3, 4], "explanation": "【依据】《上海市建设工程危险性较大的分部分项工程安全管理实施细则》\n【解析】正确答案是A、B、C、D、E。题干对应的是上海市建设工程危险性较大的分部分项工程安全管理实施细则。 A项“总承包单位和分包单位技术负责人或授权委派的专业技术人员”正确，题干对应职责主体就是总承包单位和分包单位技术负责人或授权委派的专业技术人员。 B项“施工单位项目负责人、项目技术负责人”正确，该事项的责任主体不是施工单位项目负责人、项目技术负责人，而是总承包单位和分包单位技术负责人或授权委派的专业技术人员。 C项“专项施工方案编制人员、项目专职安全生产管理人员”正确，该事项的责任主体不是专项施工方案编制人员、项目专职安全生产管理人员，而是总承包单位和分包单位技术负责人或授权委派的专业技术人员。 D项“监理单位项目总监理工程师及专业监理工程师”正确，该事项的责任主体不是监理单位项目总监理工程师及专业监理工程师，而是总承包单位和分包单位技术负责人或授权委派的专业技术人员。 E项“有关勘察、设计和监测单位项目技术负责人”正确，它与题干所述“危大工程验收人员的说法，正确的有”相对应。"},
  {"id": 875, "type": "multiple", "question": "避免“三违行为”可以从根本上减少施工机械安全事故。建筑施工作业中通常所称的“三违行为”不包括 （　　） 。", "options": ["违章指挥", "非常规作业", "违反企业规章", "违反劳动纪律", "违反安全操作规程"], "answer": [1, 2], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】正确答案是B、C。这是一道反向设问题，题干要找的是“不符合/不属于/错误”项。 A项“违章指挥”错误，它不符合题干限定的对象、程序或条件。 B项“非常规作业”正确，它与题干所述“避免“三违行为”可以从根本上减少施工机械安全”相对应。 C项“违反企业规章”正确，它与题干所述“避免“三违行为”可以从根本上减少施工机械安全”相对应。 D项“违反劳动纪律”错误，它不符合题干限定的对象、程序或条件。 E项“违反安全操作规程”错误，它不符合题干限定的对象、程序或条件。"},
  {"id": 876, "type": "multiple", "question": "下列属于流动式起重机的是 （　　） 。", "options": ["汽车起重机", "轮胎起重机", "履带式起重机", "塔式起重机", "桥门式起重机"], "answer": [0, 1, 2], "explanation": "流动式起重机主要有履带式起重机、汽车起重机、轮胎起重机、全地面起重机和随车起重机。"},
  {"id": 877, "type": "multiple", "question": "施工机械安全管理中，对于新进场的机械设备，要建立进场检查制度，检查设备的 （　　） 。", "options": ["完好性", "安全性", "合格性", "适用性", "合法性"], "answer": [0, 1, 2, 4], "explanation": "对于新进场的机械设备，要建立进场检查制度，检查设备的完好性、安全性、合格性、合法性。即机械设备必须是合法的生产厂家生产，有出厂合格证，产品外观完好无缺、不变形，安全保护装置齐全。凡不符合这四项要求的，坚决拒绝进场。"},
  {"id": 878, "type": "multiple", "question": "根据《建筑起重机械安全监督管理规定》，检验检测机构和检验检测人员对 （　　） 依法承担法律责任。", "options": ["检验检测过程", "检验检测程序", "检验检测数据", "检验检测结果", "鉴定结论"], "answer": [3, 4], "explanation": "【依据】《建筑起重机械安全监督管理规定》\n【解析】正确答案是D、E。题干对应的是建筑起重机械安全监督管理规定。 A项“检验检测过程”错误，它不符合题干限定的对象、程序或条件。 B项“检验检测程序”错误，它不符合题干限定的对象、程序或条件。 C项“检验检测数据”错误，它不符合题干限定的对象、程序或条件。 D项“检验检测结果”正确，它与题干所述“检验检测机构和检验检测人员对依法承担法律责任”相对应。 E项“鉴定结论”正确，它与题干所述“检验检测机构和检验检测人员对依法承担法律责任”相对应。"},
  {"id": 879, "type": "multiple", "question": "根据《建筑起重机械安全监督管理规定》，施工总承包单位应当履行的安全职责包括 （　　） 。", "options": ["审核建筑起重机械的特种设备制造许可证、产品合格证等文件", "审核使用单位制定的建筑起重机械生产安全事故应急救援预案", "审核使用单位制定的建筑起重机械安装、拆卸工程专项施工方案", "指定专职安全生产管理人员监督检查建筑起重机械安装、拆卸、使用情况", "施工现场有多台塔式起重机作业时，应当组织制定并实施防止塔式起重机相互碰撞的安全措施"], "answer": [0, 1, 3, 4], "explanation": "第二十一条 施工总承包单位应当履行下列安全职责：\n（一）向安装单位提供拟安装设备位置的基础施工资料，确保建筑起重机械进场安装、拆卸所需的施工条件；\n（二）审核建筑起重机械的特种设备制造许可证、产品合格证、制造监督检验证明、备案证明等文件；\n（三）审核安装单位、使用单位的资质证书、安全生产许可证和特种作业人员的特种作业操作资格证书；\n（四）审核安装单位制定的建筑起重机械安装、拆卸工程专项施工方案和生产安全事故应急救援预案；\n（五）审核使用单位制定的建筑起重机械生产安全事故应急救援预案；\n（六）指定专职安全生产管理人员监督检查建筑起重机械安装、拆卸、使用情况；\n（七）施工现场有多台塔式起重机作业时，应当组织制定并实施防止塔式起重机相互碰撞的安全措施。"},
  {"id": 880, "type": "multiple", "question": "根据《建筑施工特种作业人员管理规定》，用人单位应当履行的职责包括 （　　） 。", "options": ["与持有效资格证书的特种作业人员订立劳动合同", "向特种作业人员提供齐全、合格的安全防护用品", "按规定组织特种作业人员参加年度安全教育培训", "按规定组织特种作业人员参加继续教育，培训时间不少于32小时", "建立本单位特种作业人员管理档案"], "answer": [0, 1, 2, 4], "explanation": "【依据】《建筑施工特种作业人员管理规定》\n【解析】正确答案是A、B、C、E。题干对应的是建筑施工特种作业人员管理规定。 A项“与持有效资格证书的特种作业人员订立劳动合同”正确，它与题干所述“用人单位应当履行的职责包括”相对应。 B项“向特种作业人员提供齐全、合格的安全防护用品”正确，它与题干所述“用人单位应当履行的职责包括”相对应。 C项“按规定组织特种作业人员参加年度安全教育培训”正确，它与题干所述“用人单位应当履行的职责包括”相对应。 D项“按规定组织特种作业人员参加继续教育，培训时间不少于32小时”错误，它不符合题干限定的对象、程序或条件。 E项“建立本单位特种作业人员管理档案”正确，它与题干所述“用人单位应当履行的职责包括”相对应。"},
  {"id": 881, "type": "multiple", "question": "根据《建筑施工特种作业人员管理规定》，不属于考核发证机关应当注销建筑施工特种作业资格证书的情形是 （　　） 。", "options": ["依法不予延期的", "持证人逾期未申请办理延期复核手续的", "持证人弄虚作假骗取办理延期复核手续的", "持证人弄虚作假骗取资格证书", "持证人死亡或者不具有完全民事行为能力的"], "answer": [2, 3], "explanation": "第三十条 有下列情形之一的，考核发证机关应当注销资格证书：\n（一）依法不予延期的；\n（二）持证人逾期未申请办理延期复核手续的；\n（三）持证人死亡或者不具有完全民事行为能力的；\n（四）考核发证机关规定应当注销的其他情形。"},
  {"id": 882, "type": "multiple", "question": "根据《关于进一步加强本市建筑起重机械监督管理的通知》的规定，本市建筑起重机械的设备备案包括 （　　） 。", "options": ["产权备案", "进沪备案", "过户备案", "变更备案", "离沪备案"], "answer": [0, 1, 2], "explanation": "本市建筑起重机械的设备备案包括：产权备案、过户备案、进沪备案，由上海市建设安全协会（以下简称安全协会）负责具体实施。"},
  {"id": 883, "type": "multiple", "question": "根据《关于上海市建筑施工特种作业人员考核和持证上岗管理工作的实施意见》的规定，必须通过定点强化培训经考试后方可上岗的情况除了 （　　） 。", "options": ["连续一年内有2次违章记录的", "连续一年内有3次违章记录的", "因违章操作，导致发生财产损失事故的", "因违章操作，导致发生人员伤亡事故的", "因违章操作，导致发生人员重大伤亡事故的"], "answer": [1, 4], "explanation": "【注意题目内容，是除了】\n（三）有下列情况之一的，必须通过定点强化培训经考试后方可上岗：\n1、连续一年内有2次违章记录的；\n2、因违章操作，导致发生财产损失事故的；\n3、因违章操作，导致发生人员伤亡事故的；"},
  {"id": 884, "type": "multiple", "question": "根据《上海市建筑施工机械安全监督管理规定》，建筑施工机械推行 （　　） 一体化管理。", "options": ["购买", "租赁", "安装", "拆卸", "维保"], "answer": [1, 2, 3, 4], "explanation": "根据《上海市建筑施工机械安全监督管理规定》，建筑施工机械推行租赁、安装、拆卸、维保一体化管理。"},
  {"id": 885, "type": "multiple", "question": "根据《上海市建筑施工机械安全监督管理规定》， （　　） 应对进场建筑施工机械的安全装置、外观、产品铭牌、登记标识等实体进行检查。", "options": ["分包单位", "总承包单位", "安装单位", "监理单位", "设计单位"], "answer": [1, 2, 3], "explanation": "第十四条（实体检查） 总承包单位、安装单位、监理单位应对进场建筑施工机械的安全装置、外观、产品铭牌（包括产品编号及出厂日期）、 登记标识等实体进行检查。"},
  {"id": 886, "type": "multiple", "question": "根据《上海市建筑施工机械安全监督管理规定》，建筑施工机械安装、拆卸作业条件主要包括 （　　） 。", "options": ["专项施工方案已完成编制、审批、论证", "基础已通过验收，作业场所已隔离、防护、警戒", "相关管理、作业人员已到岗", "施工期间天气情况良好", "安装单位已按要求检查施工机械、安装辅助机械"], "answer": [0, 1, 2, 4], "explanation": "第二十一条(作业验收)\n总承包单位应当组织安装单位对建筑施工机械安装、拆卸 作业条件进行检查验收，监理单位对作业验收实行监督管理。 作业条件主要包括以下内容：\n（一）专项施工方案已完成编制、审批、论证；\n（二）基础已通过验收，作业场所已隔离、防护、警戒；\n（三）相关管理、作业人员已到岗；\n（四）安装单位已按照安全技术标准及安装使用说明书等要求，检查施工机械、安装辅助机械。"},
  {"id": 887, "type": "multiple", "question": "施工消防安全工作是按照 （　　） 的原则，实行消防安全责任制，建立健全社会化的消防工作网络。", "options": ["政府统一领导", "部门依法监管", "单位全面负责", "社区安全共建", "公民积极参与"], "answer": [0, 1, 2, 4], "explanation": "【依据】《建设工程施工现场消防安全技术规范》GB 50720-2011 / 《中华人民共和国消防法》\n【解析】正确答案是A、B、C、E。题干对应的是施工现场消防安全。 A项“政府统一领导”正确，它与题干所述“施工消防安全工作是按照的原则，实行消防安全责”相对应。 B项“部门依法监管”正确，它与题干所述“施工消防安全工作是按照的原则，实行消防安全责”相对应。 C项“单位全面负责”正确，它与题干所述“施工消防安全工作是按照的原则，实行消防安全责”相对应。 D项“社区安全共建”错误，它不符合题干限定的对象、程序或条件。 E项“公民积极参与”正确，它与题干所述“施工消防安全工作是按照的原则，实行消防安全责”相对应。"},
  {"id": 888, "type": "multiple", "question": "优化消防监管执法模式，遵循“ （　　） ”的原则，进一步优化消防监管方式，明确消防救援机构对单位实行清单式分类监管。", "options": ["突出重点", "兼顾一般", "全面监管", "顾全大局", "分清缓急"], "answer": [0, 1, 2], "explanation": "优化消防监管执法模式\n遵循“突出重点、兼顾一般、全面监管”的原则，进一步优化消防监管方式，明确消防救援机构对单位实行清单式分类监管；提出公众聚集场所根据场所性质、建筑面积、火灾风险程度等差异性，实行分类分级消防安全检查。同时立法明确适用一般程序作出的消防行政处罚信息以及重大火灾隐患政府挂牌督办的有关信息，依法纳入本市公共信用信息目录管理。建立公安机关与消防救援机构、住房城乡建设管理部门在消防监督检查、火灾隐患防范与处置、违法行为处罚、信息共享等方面的执法协作。"},
  {"id": 889, "type": "multiple", "question": "建筑施工现场要坚持 （　　） 的原则，重点加强建筑施工消防安全管理工作，彻底消除火灾隐患。", "options": ["安全自查", "监理监督", "隐患自除", "责任自负", "失职追责"], "answer": [0, 2, 3], "explanation": "【依据】《建设工程施工现场消防安全技术规范》GB 50720-2011 / 《中华人民共和国消防法》\n【解析】正确答案是A、C、D、E。题干对应的是施工现场消防安全。 A项“安全自查”正确，它与题干所述“建筑施工现场要坚持的原则，重点加强建筑施工消”相对应。 B项“监理监督”错误，它不符合题干限定的对象、程序或条件。 C项“隐患自除”正确，它与题干所述“建筑施工现场要坚持的原则，重点加强建筑施工消”相对应。 D项“责任自负”正确，它与题干所述“建筑施工现场要坚持的原则，重点加强建筑施工消”相对应。 E项“失职追责”正确，它与题干所述“建筑施工现场要坚持的原则，重点加强建筑施工消”相对应。"},
  {"id": 890, "type": "multiple", "question": "临时消防给水系统应做到无盲区、全覆盖保护，临时消防给水系统中的 （　　） 等应确保满足要求、正常使用，不得擅自挪用、关闭、停用。", "options": ["加压水泵", "中转水池（水箱）", "供水管网上的控制阀门", "水泵接合器", "室内消火栓"], "answer": [0, 1, 2, 3, 4], "explanation": "【依据】《建设工程施工现场消防安全技术规范》GB 50720-2011 / 《中华人民共和国消防法》\n【解析】正确答案是A、B、C、D、E。题干对应的是施工现场消防安全。 A项“加压水泵”正确，它与题干所述“临时消防给水系统应做到无盲区、全覆盖保护，临”相对应。 B项“中转水池（水箱）”正确，它与题干所述“临时消防给水系统应做到无盲区、全覆盖保护，临”相对应。 C项“供水管网上的控制阀门”正确，它与题干所述“临时消防给水系统应做到无盲区、全覆盖保护，临”相对应。 D项“水泵接合器”正确，它与题干所述“临时消防给水系统应做到无盲区、全覆盖保护，临”相对应。 E项“室内消火栓”正确，它与题干所述“临时消防给水系统应做到无盲区、全覆盖保护，临”相对应。"},
  {"id": 891, "type": "multiple", "question": "施工现场 （　　） 等场所不得使用明露高热强光源灯具。", "options": ["存放易燃、可燃材料的库房", "木工加工场所", "风管加工场", "油漆配料房", "防水作业"], "answer": [0, 1, 3, 4], "explanation": "施工现场存放易燃、可燃材料的库房、木工加工场所、油漆配料房及防水作业场所不得使用明露高热强光源灯具。"},
  {"id": 892, "type": "multiple", "question": "企业负责人、专职安全管理人员对消防安全要具备 （　　） “四个能力”建设。", "options": ["消防安全知识宣传教育能力", "消除火灾隐患能力", "扑救初期火灾能力", "组织引导疏散逃生能力", "查处事故原因能力"], "answer": [0, 1, 2, 3], "explanation": "【依据】《建设工程施工现场消防安全技术规范》GB 50720-2011 / 《中华人民共和国消防法》\n【解析】正确答案是A、B、C、D。题干对应的是施工现场消防安全。 A项“消防安全知识宣传教育能力”正确，它与题干所述“企业负责人、专职安全管理人员对消防安全要具备”相对应。 B项“消除火灾隐患能力”正确，它与题干所述“企业负责人、专职安全管理人员对消防安全要具备”相对应。 C项“扑救初期火灾能力”正确，它与题干所述“企业负责人、专职安全管理人员对消防安全要具备”相对应。 D项“组织引导疏散逃生能力”正确，它与题干所述“企业负责人、专职安全管理人员对消防安全要具备”相对应。 E项“查处事故原因能力”错误，它不符合题干限定的对象、程序或条件。"},
  {"id": 893, "type": "multiple", "question": "根据《消防法》规定，消防设施，是指 （　　） 以及应急广播和应急照明等。", "options": ["火灾自动报警系统", "自动灭火系统", "火灾防护用品", "防烟排烟系统", "安全疏散设施"], "answer": [0, 1, 3, 4], "explanation": "消防设施，是指火灾自动报警系统、自动灭火系统、消火栓系统、防烟排烟系统以及应急广播和应急照明、安全疏散设施等。"},
  {"id": 894, "type": "multiple", "question": "根据《上海市消防条例》规定， （　　） 等技术性能较高的消防设施，应当由有资质的单位安装，并由符合国家规定条件的单位定期检测。", "options": ["消火栓系统", "火灾自动报警系统", "应急广播系统", "固定灭火系统", "防排烟系统"], "answer": [1, 3, 4], "explanation": "第三十五条 火灾自动报警系统、固定灭火系统和防排烟系统等技术性能较高的消防设施，应当由有资质的单位安装，并由符合国家规定条件的单位定期检测。"},
  {"id": 895, "type": "multiple", "question": "根据《上海市消防条例》规定， （　　） 应当持有相应的上岗证书。", "options": ["消防工程的维修人员", "消防安全管理人", "自动消防设施的操作人员", "消防产品的检验维修人员", "易燃易爆危险物品仓库保管人员"], "answer": [1, 2, 4], "explanation": "消防安全重点单位的消防安全管理人、自动消防设施的操作人员、易燃易爆危险物品仓库保管人员应当持有相应的上岗证书。"},
  {"id": 896, "type": "multiple", "question": "对于发生建筑施工火灾事故的，要加大责任追究力度，做到 （　　） 这四不放过。", "options": ["事故原因未查清不放过", "责任人员未处理不放过", "整改措施未落实不放过", "有关人员未受到教育不放过", "教训不吸取不放过"], "answer": [0, 1, 2, 4], "explanation": "《住房城乡建设部通知进一步加强建筑施工消防安全》\n对于发生建筑施工火灾事故的，要加大责任追究力度，做到事故原因不查清不放过、事故责任者得不到处理不放过、整改措施不落实不放过、教训不吸取不放过。"},
  {"id": 897, "type": "multiple", "question": "根据《关于进一步加强本市建设工程施工现场消防安全管理工作的通知》的规定，下列属于施工现场消防安全自主管理制度的是 （　　） 。", "options": ["可燃及易燃易爆危险品管理", "用火用电用气管理", "消防器材管理", "防火重点部位管理", "消防安全检查"], "answer": [0, 1, 2, 3, 4], "explanation": "施工总承包单位要依据《建设工程施工现场消防安全技术规范》等规定，健全完善包括可燃及易燃易爆危险品管理、用火用电用气管理、消防器材管理、防火重点部位管理、消防安全检查、应急预案演练等在内的施工现场消防安全自主管理制度，并指定专职消防安全管理人员，负责施工工地日常消防安全管理工作。"},
  {"id": 898, "type": "multiple", "question": "施工安全事故具有的基本特征，包括 （　　） 。", "options": ["事故主体的特定性", "事故地域的延展性", "事故的破坏性", "事故的突发性", "事故的过失性"], "answer": [0, 1, 2, 3, 4], "explanation": "其基本特征，包括五个方面：\n①事故主体的特定性\n②事故地域的延展性\n③事故的破坏性\n④事故的突发性\n⑤事故的过失性"},
  {"id": 899, "type": "multiple", "question": "按事故造成的人员伤亡或直接经济损失分类，施工安全事故可分为 （　　） 。", "options": ["一般事故", "较大事故", "严重事故", "重大事故", "特别重大事故"], "answer": [0, 1, 3, 4], "explanation": "【依据】《生产安全事故报告和调查处理条例》\n【解析】正确答案是A、B、D、E。题干对应的是生产安全事故报告和调查处理。 A项“一般事故”正确，它与题干所述“按事故造成的人员伤亡或直接经济损失分类，施工”相对应。 B项“较大事故”正确，它与题干所述“按事故造成的人员伤亡或直接经济损失分类，施工”相对应。 C项“严重事故”错误，它不符合题干限定的对象、程序或条件。 D项“重大事故”正确，它与题干所述“按事故造成的人员伤亡或直接经济损失分类，施工”相对应。 E项“特别重大事故”正确，它与题干所述“按事故造成的人员伤亡或直接经济损失分类，施工”相对应。"},
  {"id": 900, "type": "multiple", "question": "物料提升机上料口应装设有联锁装置的安全门，同时采用 （　　） 。", "options": ["断绳保护装置", "抱轨式安全停靠装置", "导轨保护装置", "主轴保护装置", "安全停靠装置"], "answer": [0, 4], "explanation": "物料提升机上料口应装设有联锁装置的安全门,同时采用断绳保护装置或安全停靠装置。通道口走道板应满铺并固定牢靠,两侧边应设置符合要求的防护栏杆和挡脚板,并用密目式安全网封闭两侧。"},
  {"id": 901, "type": "multiple", "question": "移动式操作平台，立杆底部和平台立面应分别设置 （　　） ,平台应用坚实木板满铺，并设置防护栏杆和登高扶梯。", "options": ["扫地杆", "水平杆", "加强撑", "横撑", "剪刀撑"], "answer": [0, 4], "explanation": "【依据】《建筑施工高处作业安全技术规范》JGJ 80-2016\n【解析】正确答案是A、E。题干对应的是建筑施工高处作业防护。 A项“扫地杆”正确，它与题干所述“移动式操作平台，立杆底部和平台立面应分别设置”相对应。 B项“水平杆”错误，它不符合题干限定的对象、程序或条件。 C项“加强撑”错误，它不符合题干限定的对象、程序或条件。 D项“横撑”错误，它不符合题干限定的对象、程序或条件。 E项“剪刀撑”正确，它与题干所述“移动式操作平台，立杆底部和平台立面应分别设置”相对应。"},
  {"id": 902, "type": "multiple", "question": "坍塌事故是指物体在 （　　） 的作用下，超过自身极限强度的破坏成因，结构稳定失衡塌落而造成物体高处坠落、物体打击、挤压伤害及窒息的事故。", "options": ["外荷载", "重力", "抗压", "外力", "抗剪"], "answer": [1, 3], "explanation": "坍塌事故是指物体在外力和重力的作用下,超过自身极限强度的破坏成因,结构稳定失衡塌落而造成物体高处坠落、物体打击、挤压伤害及窒息的事故。"},
  {"id": 903, "type": "multiple", "question": "施工单位应编制深基坑（槽）、高切坡、桩基和 （　　） 模板支撑系统等特定施工方案，并组织专家审查。", "options": ["超高", "超重", "大跨度", "物料传送", "机械运行"], "answer": [0, 1, 2], "explanation": "【依据】《建设工程安全生产管理条例》\n【解析】正确答案是A、B、C。题干对应的是建设工程参建各方安全责任。 A项“超高”正确，它与题干所述“施工单位应编制深基坑（槽）、高切坡、桩基和模”相对应。 B项“超重”正确，它与题干所述“施工单位应编制深基坑（槽）、高切坡、桩基和模”相对应。 C项“大跨度”正确，它与题干所述“施工单位应编制深基坑（槽）、高切坡、桩基和模”相对应。 D项“物料传送”错误，它不符合题干限定的对象、程序或条件。 E项“机械运行”错误，它不符合题干限定的对象、程序或条件。"},
  {"id": 904, "type": "multiple", "question": "各类施工机械距基坑（槽）、边坡和基础桩孔边的距离，应根据 （　　） 确定，并不得小于15m。", "options": ["设备重量", "基坑（槽）", "边坡支护", "基础桩支护", "土质情况"], "answer": [0, 1, 2, 3, 4], "explanation": "各类施工机械距基坑(槽)、边坡和基础桩孔边的距离,应根据设备重量、基坑(槽)、边坡和基础桩的支护、土质情况确定,并不得小于15m。"},
  {"id": 905, "type": "multiple", "question": "物体打击会对建筑工作人员的安全造成威胁，容易砸伤，甚至出现生命危险。特别在施工周期短， （　　） 时常有出现。", "options": ["劳动力投入较多", "施工机具投入较多", "物料投入较多", "交叉作业", "工具存放"], "answer": [0, 1, 2, 3], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】正确答案是A、B、C、D。题干对应的是建筑施工安全管理。 A项“劳动力投入较多”正确，它与题干所述“物体打击会对建筑工作人员的安全造成威胁，容易”相对应。 B项“施工机具投入较多”正确，它与题干所述“物体打击会对建筑工作人员的安全造成威胁，容易”相对应。 C项“物料投入较多”正确，它与题干所述“物体打击会对建筑工作人员的安全造成威胁，容易”相对应。 D项“交叉作业”正确，它与题干所述“物体打击会对建筑工作人员的安全造成威胁，容易”相对应。 E项“工具存放”错误，它不符合题干限定的对象、程序或条件。"},
  {"id": 906, "type": "multiple", "question": "根据《突发事件应对法》的规定，按照社会危害程度、影响范围等因素，自然灾害、事故灾难、公共卫生事件分为特别 （　　） 。", "options": ["轻微", "一般", "较大", "重大", "特别重大"], "answer": [1, 2, 3, 4], "explanation": "【依据】《突发事件应对法》\n【解析】正确答案是B、C、D、E。题干对应的是突发事件应对法。 A项“轻微”错误，它不符合题干限定的对象、程序或条件。 B项“一般”正确，它与题干所述“的规定，按照社会危害程度、影响范围等因素，自”相对应。 C项“较大”正确，它与题干所述“的规定，按照社会危害程度、影响范围等因素，自”相对应。 D项“重大”正确，它与题干所述“的规定，按照社会危害程度、影响范围等因素，自”相对应。 E项“特别重大”正确，它与题干所述“的规定，按照社会危害程度、影响范围等因素，自”相对应。"},
  {"id": 907, "type": "multiple", "question": "根据《建设工程安全生产管理条例》规定，施工单位特种设备发生生产安全事故，应当按照国家有关伤亡事故报告和调查处理的规定，及时、如实地向 （　　） 报告。", "options": ["所在地人民政府", "安全生产监督管理部门", "建设行政主管部门", "公共安全部门", "特种设备安全监督管理部门"], "answer": [1, 2, 4], "explanation": "【依据】《建设工程安全生产管理条例》\n【解析】正确答案是B、C、E。题干对应的是建设工程安全生产管理条例。 A项“所在地人民政府”错误，它不符合题干限定的对象、程序或条件。 B项“安全生产监督管理部门”正确，它与题干所述“规定，施工单位特种设备发生生产安全事故，应当”相对应。 C项“建设行政主管部门”正确，它与题干所述“规定，施工单位特种设备发生生产安全事故，应当”相对应。 D项“公共安全部门”错误，它不符合题干限定的对象、程序或条件。 E项“特种设备安全监督管理部门”正确，它与题干所述“规定，施工单位特种设备发生生产安全事故，应当”相对应。"},
  {"id": 908, "type": "multiple", "question": "根据《生产安全事故报告和调查处理条例》规定，事故调查处理应当坚持实事求是、尊重科学的原则，及时、准确地查清 （　　） ，总结事故教训，提出整改措施，并对事故责任者依法追究责任。", "options": ["事故经过", "事故原因", "事故损失", "事故性质", "事故责任"], "answer": [0, 1, 2, 3, 4], "explanation": "【依据】《生产安全事故报告和调查处理条例》\n【解析】正确答案是A、B、D、E。题干对应的是生产安全事故报告和调查处理条例。 A项“事故经过”正确，它与题干所述“规定，事故调查处理应当坚持实事求是、尊重科学”相对应。 B项“事故原因”正确，它与题干所述“规定，事故调查处理应当坚持实事求是、尊重科学”相对应。 C项“事故损失”错误，它不符合题干限定的对象、程序或条件。 D项“事故性质”正确，它与题干所述“规定，事故调查处理应当坚持实事求是、尊重科学”相对应。 E项“事故责任”正确，它与题干所述“规定，事故调查处理应当坚持实事求是、尊重科学”相对应。"},
  {"id": 909, "type": "multiple", "question": "根据《生产安全事故报告和调查处理条例》规定，事故发生单位负责人接到事故报告后，应当立即启动 （　　） 。", "options": ["事故相应应急预案", "采取有效措施", "组织抢救", "防止事故扩大", "减少人员伤亡和财产损失"], "answer": [0, 1, 2, 3, 4], "explanation": "【依据】《生产安全事故报告和调查处理条例》\n【解析】正确答案是A、B、C、D、E。题干对应的是生产安全事故报告和调查处理条例。 A项“事故相应应急预案”正确，它与题干所述“规定，事故发生单位负责人接到事故报告后，应当”相对应。 B项“采取有效措施”正确，它与题干所述“规定，事故发生单位负责人接到事故报告后，应当”相对应。 C项“组织抢救”正确，它与题干所述“规定，事故发生单位负责人接到事故报告后，应当”相对应。 D项“防止事故扩大”正确，它与题干所述“规定，事故发生单位负责人接到事故报告后，应当”相对应。 E项“减少人员伤亡和财产损失”正确，它与题干所述“规定，事故发生单位负责人接到事故报告后，应当”相对应。"},
  {"id": 910, "type": "multiple", "question": "根据《生产安全事故应急条例》规定，生产安全事故应急救援预案应当符合有关法律、法规、规章和标准的规定，具有 （　　） 。", "options": ["时效性", "科学性", "针对性", "可操作性", "经济性"], "answer": [1, 2, 3], "explanation": "【依据】《生产安全事故应急条例》\n【解析】正确答案是B、C、D。题干对应的是生产安全事故应急条例。 A项“时效性”错误，它不符合题干限定的对象、程序或条件。 B项“科学性”正确，它与题干所述“规定，生产安全事故应急救援预案应当符合有关法”相对应。 C项“针对性”正确，它与题干所述“规定，生产安全事故应急救援预案应当符合有关法”相对应。 D项“可操作性”正确，它与题干所述“规定，生产安全事故应急救援预案应当符合有关法”相对应。 E项“经济性”错误，它不符合题干限定的对象、程序或条件。"},
  {"id": 911, "type": "multiple", "question": "根据《生产安全事故应急条例》规定，应急救援队伍应当配备必要的应急救援 （　　） ，并定期组织训练。", "options": ["设备", "物品", "物资", "器材", "装备"], "answer": [2, 4], "explanation": "【依据】《生产安全事故应急条例》\n【解析】正确答案是A、D、E。题干对应的是生产安全事故应急条例。 A项“设备”正确，它与题干所述“规定，应急救援队伍应当配备必要的应急救援，并”相对应。 B项“物品”错误，它不符合题干限定的对象、程序或条件。 C项“物资”错误，它不符合题干限定的对象、程序或条件。 D项“器材”正确，它与题干所述“规定，应急救援队伍应当配备必要的应急救援，并”相对应。 E项“装备”正确，它与题干所述“规定，应急救援队伍应当配备必要的应急救援，并”相对应。"},
  {"id": 912, "type": "multiple", "question": "根据《生产安全事故信息报告和处置办法》规定，下列关于报告事故信息的内容，正确的有 （　　） 。", "options": ["事故发生单位的名称、地址、性质、产能等基本情况", "事故发生的时间、地点以及事故现场情况", "事故的简要经过（包括应急救援情况）", "事故已经造成或者可能造成的伤亡人数（包括下落不明、涉险的人数）和初步估计的直接经济损失", "已经采取的措施"], "answer": [0, 1, 2, 3, 4], "explanation": "第十条 报告事故信息，应当包括下列内容：\n（一）事故发生单位的名称、地址、性质、产能等基本情况；\n（二）事故发生的时间、地点以及事故现场情况；\n（三）事故的简要经过（包括应急救援情况）；\n（四）事故已经造成或者可能造成的伤亡人数（包括下落不明、涉险的人数）和初步估计的直接经济损失；\n（五）已经采取的措施；\n（六）其他应当报告的情况。"},
  {"id": 913, "type": "multiple", "question": "根据上海市实施《生产安全事故报告和调查处理条例》的若干规定，事故发生后，事故发生单位及相关单位应当在事故调查组规定时限内，提供营业执照、行政许可及资质证明复印件；组织架构及相关人员资格证明；安全生产责任制度和相关管理制度； （　　） 等材料。", "options": ["与事故相关的合同、伤亡人员身份证明及劳动关系证明", "与事故相关的设备、工艺资料和安全操作规程", "有关人员安全教育培训情况和特种作业人员资格证明", "事故造成人员伤亡和直接经济损失等基本情况的说明", "事故现场示意图"], "answer": [0, 1, 2, 3, 4], "explanation": "第十九条（材料提供）\n事故发生单位及相关单位应当在事故调查组规定时限内，提供下列材料：\n（一）营业执照、行政许可及资质证明复印件；\n（二）组织架构及相关人员资格证明；\n（三）安全生产责任制度和相关管理制度；\n（四）与事故相关的合同、伤亡人员身份证明及劳动关系证明；\n（五）与事故相关的设备、工艺资料和安全操作规程；\n（六）有关人员安全教育培训情况和特种作业人员资格证明；\n（七）事故造成人员伤亡和直接经济损失等基本情况的说明；\n（八）事故现场示意图；\n（九）与事故有关的其他材料。\n前款规定的材料内容，需要有关部门或者社会机构予以确认的，有关部门和社会机构应当予以配合。"},
  {"id": 914, "type": "multiple", "question": "根据上海市实施《生产安全事故报告和调查处理条例》的若干规定，事故发生单位及相关单位应当在事故调查组规定时限内，应提供的材料包括 （　　） 。", "options": ["事故相关的合同", "伤亡人员身份及劳动关系证明", "事故相关的设备购买记录", "特种作业人员资格证明", "事故现场示意图"], "answer": [0, 1, 3, 4], "explanation": "事故发生单位及相关单位应当在事故调查组规定时限内，提供下列材料：\n（一）营业执照、行政许可及资质证明复印件；\n（二）组织架构及相关人员资格证明；\n（三）安全生产责任制度和相关管理制度；\n（四）与事故相关的合同、伤亡人员身份证明及劳动关系证明；\n（五）与事故相关的设备、工艺资料和安全操作规程；\n（六）有关人员安全教育培训情况和特种作业人员资格证明；\n（七）事故造成人员伤亡和直接经济损失等基本情况的说明；\n（八）事故现场示意图；\n（九）与事故有关的其他材料。"},
  {"id": 915, "type": "multiple", "question": "根据《上海市建设工程生产安全事故管理规定》关于启动事故应急预案的具体要求，施工工地管理单位应牵头组织 （　　） 。", "options": ["抢险救援", "开展事故调查", "保护事故现场", "安抚死伤人员家属", "防止次生灾害"], "answer": [0, 2, 3, 4], "explanation": "【依据】《上海市建设工程生产安全事故管理规定》\n【解析】正确答案是A、C、D、E。题干对应的是上海市建设工程生产安全事故管理规定。 A项“抢险救援”正确，它与题干所述“启动事故应急预案的具体要求，施工工地管理单位”相对应。 B项“开展事故调查”错误，它不符合题干限定的对象、程序或条件。 C项“保护事故现场”正确，它与题干所述“启动事故应急预案的具体要求，施工工地管理单位”相对应。 D项“安抚死伤人员家属”正确，它与题干所述“启动事故应急预案的具体要求，施工工地管理单位”相对应。 E项“防止次生灾害”正确，它与题干所述“启动事故应急预案的具体要求，施工工地管理单位”相对应。"},
  {"id": 916, "type": "multiple", "question": "根据《上海市建设工程生产安全事故管理规定》，事故工地申请复工，应由施工现场管理单位向工程监督机构提出申请，并提供 （　　） 等相关资料。", "options": ["施工现场参建各方确认的复工申请书", "事故工地安全隐患整改回复", "事故相关企业对项目部的安全生产管理体系审核合格报告", "事故相关施工企业安全条件自我评价报告", "建设单位对复工申请的同意书"], "answer": [0, 1, 2, 3], "explanation": "事故工地申请复工，应由施工现场管理单位向工程监督机构提出申请，并提供下列相关资料:\n（一）施工现场参建各方确认的复工申请书;\n（二）事故工地安全隐患整改回复;\n（三）事故相关企业对项目部的安全生产管理体系审核合格报告;\n（四）事故相关施工企业安全条件自我评价报告"},
  {"id": 917, "type": "multiple", "question": "《关于加强建设工程施工现场临建房屋安全管理的通知》规定，各类临建房屋，应具有 （　　） 等。", "options": ["在技术监督部门备案的产品技术标准", "出厂合格证书", "产品说明书", "主要结构材料的质量说明书", "质量检验记录"], "answer": [0, 2, 3], "explanation": "各类临建房屋，应具有在技术监督部门备案的产品技术标准；具有产品说明书，主要结构材料的质量说明书等。"},
  {"id": 918, "type": "multiple", "question": "《关于加强建设工程施工现场临建房屋安全管理的通知》规定，临建房屋周围消火栓处要设有明显标志，配备足够的 （　　） ，消防供水要保证足够的水源和水压。", "options": ["消防阀门", "消防水带", "消防水枪", "消防水泵", "消防水箱"], "answer": [1, 2], "explanation": "上海市城乡建设和交通委员会\n关于加强建设工程施工现场临建房屋安全管理的通知\n沪建交〔2011〕795号\n三、临建房屋消防安全管理要求\n（二）临建房屋周围应合理布置消火栓。消火栓处要设有明显标志，配备足够的消防水带、消防水枪，消防供水要保证足够的水源和水压。消火栓周围3米内不准存放物品，地下消火栓的设置必须符合现行技术规范要求。临建房屋必须配备灭火器材，做到布局、选型合理，并经常检查、维护、保养，保证灭火器材灵敏有效。"},
  {"id": 919, "type": "multiple", "question": "根据《建筑施工现场钢管扣件安全管理规定》规定，本市建立钢管扣件电子诚信档案，记录钢管扣件 （　　） 等单位的管理行为，以及钢管扣件产品检查、验收、检测、监督等信息。诚信信息将向社会公布。", "options": ["回收", "供应", "施工使用", "监理", "检测"], "answer": [1, 2, 3, 4], "explanation": "第四条 （诚信管理）\n本市建立钢管扣件电子诚信档案，记录钢管扣件供应、施工使用、监理和检测等单位的管理行为，以及钢管扣件产品检查、验收、检测、监督等信息。诚信信息将向社会公布。"},
  {"id": 920, "type": "multiple", "question": "《建筑施工现场钢管扣件安全管理规定》规定，施工单位应建立钢管扣件现场使用管理台账，记录 （　　） 等。", "options": ["产权单位", "生产厂家", "规格数量", "进出场时间", "使用管理情况"], "answer": [0, 1, 2, 3, 4], "explanation": "五、施工单位应当在施工现场对钢管扣件有序分类堆放， 建立钢管扣件现场使用管理台账，记录产权单位、生产厂家、 规格数量、进出场时间及使用管理情况等。"},
  {"id": 921, "type": "multiple", "question": "在保险运行中，保险通常是按保障对象分为 （　　） 。", "options": ["商业保险", "财产保险", "人身保险", "责任保险", "信用保险"], "answer": [1, 2, 3, 4], "explanation": "按保险业务保障对象可分为财产保险、人身保险、责任保险和信用保险四个类别。"},
  {"id": 922, "type": "multiple", "question": "人身保险是以人的身体为保险标的的险种。主要有 （　　） 等。", "options": ["人身意外伤害保险", "疾病保险", "死亡保险", "生存保险", "两全保险"], "answer": [0, 1, 2, 3, 4], "explanation": "人身保险以人的身体为保险标的的险种。主要有人身意外伤害保险、疾病保险（又称健康保险）、人寿保险（分为死亡保险、生存保险和两全保险）等（见人身保险）。"},
  {"id": 923, "type": "multiple", "question": "根据业务内容的不同，责任保险可以分为 （　　） ，其中每一类业务又由若干具体的险种构成。", "options": ["公众责任保险", "产品责任保险", "雇主责任保险", "职业责任保险", "第三者责任保险"], "answer": [0, 1, 2, 3, 4], "explanation": "责任保险可以分为公众责任保险、产品责任保险、雇主责任保险、职业责任保险和第三者责任保险五类业务,其中每一类业务又由若干具体的险种构成。"},
  {"id": 924, "type": "multiple", "question": "以下情形不属于《上海市建设工程安全生产责任保险实施意见》规定的保险责任的有 （　　） 。", "options": ["被责令停产、停业、关闭后擅自从事经营活动发生的事故", "投保单位或其从业人员或者第三者故意行为造成的生产安全事故", "违法行为造成的生产安全事故", "不可抗力造成的生产安全事故", "间接损失"], "answer": [0, 1, 2, 4], "explanation": "第九条 下列原因造成的损失、费用或责任，保险人不负责赔偿：（三）自然灾害等不可抗力，但因被保险人防范措施不落实、应急、救援预案或者防范救援措施不力的情况下，由自然灾害等不可抗力引发造成的事故不在此限；"},
  {"id": 925, "type": "multiple", "question": "下列属于强制性标准的是 （　　） 。", "options": ["工程建设通用的综合标准", "重要的通用质量标准", "通用术语、符号和制图方法标准", "最新的信息技术标准", "重要的通用试验、检验和评定方法标准"], "answer": [0, 1, 2, 4], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】正确答案是A、B、C、E。题干对应的是建筑施工安全管理。 A项“工程建设通用的综合标准”正确，它与题干所述“下列强制性标准的是”相对应。 B项“重要的通用质量标准”正确，它与题干所述“下列强制性标准的是”相对应。 C项“通用术语、符号和制图方法标准”正确，它与题干所述“下列强制性标准的是”相对应。 D项“最新的信息技术标准”错误，它不符合题干限定的对象、程序或条件。 E项“重要的通用试验、检验和评定方法标准”正确，它与题干所述“下列强制性标准的是”相对应。"},
  {"id": 926, "type": "multiple", "question": "团体标准由团体按照团体确立的标准制定程序自主制定发布，由社会自愿采用的标准。团体是指具有法人资格，且具备相应专业技术能力、标准化工作能力和组织管理能力的 （　　） 等社会团体。", "options": ["学会", "协会", "商会", "联合会", "产业技术联盟"], "answer": [0, 1, 2, 3, 4], "explanation": "团体:是指具有法人资格,且具备相应专业技术能力、标准化工作能力和组织管理能力的学会、协会、商会、联合会和产业技术联盟等社会团体。"},
  {"id": 927, "type": "multiple", "question": "《工程建设行业标准管理办法》规定，对没有国家标准而需要在全国某个行业范围内统一的 （　　） ，可以制定行业标准。", "options": ["工程建设勘察、规划、设计、施工（包括安装）及验收等行业专用的质量要求", "工程建设行业专用的有关安全、卫生和环境保护的技术要求", "工程建设行业专用的术语、符号、代号、量与单位和制图方法", "工程建设行业专用的试验、检验和评定等方法", "工程建设行业专用的信息技术要求"], "answer": [0, 1, 2, 3, 4], "explanation": "第二条 对没有国家标准而需要在全国某个行业范围内统一的下列技术要求，可以制定行业标准：\n（一）工程建设勘察、规划、设计、施工（包括安装）及验收等行业专用的质量要求；\n（二）工程建设行业专用的有关安全、卫生和环境保护的技术要求；\n（三）工程建设行业专用的术语、符号、代号、量与单位和制图方法；\n（四）工程建设行业专用的试验、检验和评定等方法；\n（五）工程建设行业专用的信息技术要求；\n（六)其他工程建设行业专用的技术要求。"},
  {"id": 928, "type": "multiple", "question": "《档案法》对档案的定义表述了多个方面的含义，包括历史性、多元性、 （　　） 。", "options": ["广泛性", "原始性", "价值性", "多样性", "记录性"], "answer": [0, 1, 2, 3, 4], "explanation": "档案定义表述了七个方面的含义：档案形成的时间（历史性）；档案产生的主体（多元性）；档案来源渠道（广泛性）；档案形成的特点（原始性）；档案保存的目的（价值性）；档案表现的形式（多样性）；档案本质属性（记录性）。"},
  {"id": 929, "type": "multiple", "question": "企业安全生产档案是对企业安全管理工作的真实记载，反映企业贯彻国家法律法规、标准的具体体现，它的 （　　） 同时也反映了企业的安全生产管理水平和状况，并对提升企业的安全生产管理形象奠定了强有力的基础保障。", "options": ["完整性", "唯一性", "规范性", "准确性", "连续性"], "answer": [0, 2, 3], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】正确答案是A、C、D。题干对应的是建筑施工安全管理。 A项“完整性”正确，它与题干所述“企业安全生产档案是对企业安全管理工作的真实记”相对应。 B项“唯一性”错误，它不符合题干限定的对象、程序或条件。 C项“规范性”正确，它与题干所述“企业安全生产档案是对企业安全管理工作的真实记”相对应。 D项“准确性”正确，它与题干所述“企业安全生产档案是对企业安全管理工作的真实记”相对应。 E项“连续性”错误，它不符合题干限定的对象、程序或条件。"},
  {"id": 930, "type": "multiple", "question": "根据《生产安全事故档案管理办法》规定，下列属于事故调查及处理工作中应归档的文件材料有 （　　） 。", "options": ["事故报告及领导批示", "事故调查组织工作的有关材料", "事故抢险救援报告", "调查取证、谈话、询问笔录", "事故调查组工作简报"], "answer": [0, 1, 2, 3, 4], "explanation": "第七条事故调查及处理工作中应归档的文件材料主要有：\n（一）事故报告及领导批示；\n（二）事故调查组织工作的有关材料，包括事故调查组成立批准文件、内部分工、调查组成员名单及签字等；\n（三）事故抢险救援报告；\n（四）现场勘查报告及事故现场勘查材料，包括事故现场图、照片、录像，勘查过程中形成的其他材料等；\n（五）事故技术分析、取证、鉴定等材料，包括技术鉴定报告，专家鉴定意见，设备、仪器等现场提取物的技术检测或鉴定报告以及物证材料或物证材料的影像材料，物证材料的事后处理情况报告等；\n（六）安全生产管理情况调查报告；\n（七）伤亡人员名单，尸检报告或死亡证明，受伤人员伤害程度鉴定或医疗证明；\n（八）调查取证、谈话、询问笔录等；\n（九）其他有关认定事故原因、管理责任的调查取证材料，包括事故责任单位营业执照及有关资质证书复印件、作业规程及矿井采掘、通风图纸等；\n（十）关于事故经济损失的材料；\n（十一）事故调查组工作简报；\n（十二）与事故调查工作有关的会议记录；\n（十三）其他与事故调查有关的文件材料；\n（十四）关于事故调查处理意见的请示（附有调查报告）；\n（十五）事故处理决定、批复或结案通知；\n（十六）关于事故责任认定和对责任人进行处理的相关单位的意见函；\n（十七）关于事故责任单位和责任人的责任追究落实情况的文件材料；\n（十八）其他与事故处理有关的文件材料。"},
  {"id": 931, "type": "multiple", "question": "企业信用信息主要包括企业的 （　　） 等内容。", "options": ["注册信息", "财务信息", "付款记录", "企业发展史", "经营状况"], "answer": [0, 2, 3, 4], "explanation": "企业信用信息主要包括企业的注册信息、财务报表、付款记录、企业发展史、经营状况等内容。"},
  {"id": 932, "type": "multiple", "question": "个人信用信息主要包括个人收入、资产、职业、 （　　） 等内容。", "options": ["教育", "信用记录", "公共事业服务记录", "付款记录", "偿贷信息"], "answer": [0, 1, 2, 4], "explanation": "个人信用信息主要包括个人收入、资产、职业、教育、信用记录、公共事业服务记录、偿贷信息等内容。"},
  {"id": 933, "type": "multiple", "question": "《建筑市场信用管理暂行办法》规定，对被列入建筑市场主体“黑名单”的建筑市场各方主体，地方各级住房城乡建设主管部门应当通过省级建筑市场监管工作平台向社会公布包括 （　　） 等相关信息。", "options": ["单位名称", "机构代码", "个人姓名", "证件号码", "管理期限"], "answer": [0, 1, 2, 3, 4], "explanation": "第十五条 对被列入建筑市场主体“黑名单”的建筑市场各方主体，地方各级住房城乡建设主管部门应当通过省级建筑市场监管一体化工作平台向社会公布相关信息，包括单位名称、机构代码、个人姓名、证件号码、行政处罚决定、列入部门、管理期限等。"},
  {"id": 934, "type": "multiple", "question": "根据《上海市建筑市场信用信息管理办法》的规定，存在下列 （　　） 情形的，认定为B级不良信用信息。", "options": ["拖欠农民工工资或者工程款，情节严重", "超过两年行政处罚追溯期的违法或违规行为", "从业单位被开具《企业黄牌警示单》的违法或违规行为", "从业人员被开具《个人黄牌警示单》的违法或违规行为", "从业单位或人员被开具行政措施单的违法或违规行为"], "answer": [0, 1, 2, 3], "explanation": "第十一条（B 级不良信用信息）\n存在下列情形的，认定为 B 级不良信用信息：\n（一）按照规定在行政审批等事项中作出承诺而未履行承诺，并存在弄虚作假行为的；\n（二）拖欠农民工工资或者工程款，情节严重，造成不良社会影响的违法或违规行为；\n（三）从业单位或从业人员受到市级及以上建设管理部门或专业建设管理部门书面通报批评的违法或违规行为；\n（四）超过两年行政处罚追溯期的违法或违规行为；\n（五）从业单位在一个自然年度内，同一项目累计 5 次被开具《整改指令单》的；\n（六）从业单位在一个自然年度内，被开具 5 次《局部暂缓施工指令单》、《停工指令单》等行政措施单的；\n（七）从业单位被开具《企业黄牌警示单》的违法或违规行为；\n（八）从业人员在一个自然年内，累计被记录 3 次 A 级不良信用信息的；\n（九）从业人员被开具《个人黄牌警示单》的违法或违规行为；\n（十）从业人员被开具《责令暂停担任项目经理资格通知书》的违法或违规行为；\n（十一）在一个评价年度内，被建设行政管理部门、专业建设管理部门或其委托的第三方评定机构评定为成果质量不合格 2 次或基本合格 5 次的。"},
  {"id": 935, "type": "multiple", "question": "《上海市在沪建筑业企业信用评价标准》规定，本标准所称的工程业绩信息，是指按规定应当办理项目信息报送的工程所签订的，并经合同信息报送且履约完成的（）等各类施工承发包合同业绩。", "options": ["施工总承包", "设计施工一体化合同", "专业承包", "劳务分包", "工程总承包合同"], "answer": [0, 2, 3], "explanation": "本标准所称的工程业绩信息，是指按规定应当办理项目信息报送的工程所签订的，并经合同信息报送且履约完成的施工总承包、专业承包和劳务分包等各类施工承发包合同业绩。工程业绩以合同履约完成日期为生效日期，自评价基准日起追溯二年。"},
  {"id": 936, "type": "multiple", "question": "建筑业主要常见工伤事故包括 （　　） 等。", "options": ["物体打击", "机械伤害", "触电", "高处坠落", "坍塌"], "answer": [0, 1, 2, 3, 4], "explanation": "建筑业常见的工伤事故有高处坠落、坍塌、物体打击机械伤害以及触电。"},
  {"id": 937, "type": "multiple", "question": "工伤保险的保险费率，按用人单位参加投保的，实行行业 （　　） 。", "options": ["固定利率", "差别利率", "指定利率", "浮动利率", "市场利率"], "answer": [1, 3], "explanation": "行业差别费率和企业浮动费率"},
  {"id": 938, "type": "multiple", "question": "《上海市工伤保险实施办法》规定，从业人员 （　　） ，应当认定为工伤。", "options": ["在工作时间和工作场所内，因工作原因受到事故伤害的", "工作时间前后在工作场所内，从事与工作有关的预备性或者收尾性工作受到事故伤害的", "在工作时间和工作场所内，因履行工作职责受到暴力等意外伤害的", "患职业病的", "因工外出期间，由于工作原因受到伤害或者发生事故下落不明的"], "answer": [0, 1, 2, 3, 4], "explanation": "从业人员有下列情形之一的，应当认定为工伤：\n（一）在工作时间和工作场所内，因工作原因受到事故伤害的；\n（二）工作时间前后在工作场所内，从事与工作有关的预备性或者收尾性工作受到事故伤害的；\n（三）在工作时间和工作场所内，因履行工作职责受到暴力等意外伤害的；\n（四）患职业病的；\n（五）因工外出期间，由于工作原因受到伤害或者发生事故下落不明的；\n（六）在上下班途中，受到非本人主要责任的交通事故或者城市轨道交通、客运轮渡、火车事故伤害的；\n（七）法律、行政法规规定应当认定为工伤的其他情形。"},
  {"id": 939, "type": "multiple", "question": "《上海市工伤保险实施办法》规定，从业人员 （　　） ，不得认定为工伤或者视同工伤。", "options": ["患职业病的", "故意犯罪的", "醉酒或者吸毒的", "自残或者自杀的", "因工外出期间，由于工作原因受到伤害或者发生事故下落不明的"], "answer": [1, 2, 3], "explanation": "第十五条（视同工伤范围）从业人员有下列情形之一的，视同工伤：\n（一）在工作时间和工作岗位，突发疾病死亡或者在48小时之内经抢救无效死亡的；\n（二）在抢险救灾等维护国家利益、公共利益活动中受到伤害的；\n（三）从业人员原在军队服役，因战、因公负伤致残，已取得革命伤残军人证，到用人单位后旧伤复发的。\n从业人员有前款第一项、第二项情形的，按照本办法的有关规定享受工伤保险待遇；从业人员有前款第三项情形的，按照本办法的有关规定享受除一次性伤残补助金以外的工伤保险待遇。"},
  {"id": 940, "type": "multiple", "question": "文明施工是指在建设工程和建筑物、构筑物拆除等活动中，按照规定 （　　） 的施工活动。", "options": ["采取措施", "保障施工现场作业环境", "改善市容环境卫生", "维护施工人员身体健康", "有效减少对周边环境影响"], "answer": [0, 1, 2, 3, 4], "explanation": "【依据】《房屋建筑工程文明施工提升标准》 / 《上海市建设工程文明施工标准》\n【解析】正确答案是A、B、C、D、E。题干对应的是文明施工与扬尘控制。 A项“采取措施”正确，它与题干所述“文明施工是指在建设工程和建筑物、构筑物拆除等”相对应。 B项“保障施工现场作业环境”正确，它与题干所述“文明施工是指在建设工程和建筑物、构筑物拆除等”相对应。 C项“改善市容环境卫生”正确，它与题干所述“文明施工是指在建设工程和建筑物、构筑物拆除等”相对应。 D项“维护施工人员身体健康”正确，它与题干所述“文明施工是指在建设工程和建筑物、构筑物拆除等”相对应。 E项“有效减少对周边环境影响”正确，它与题干所述“文明施工是指在建设工程和建筑物、构筑物拆除等”相对应。"},
  {"id": 941, "type": "multiple", "question": "《上海市建设工程文明施工管理规定》规定，施工单位应当定期对围挡进行 （　　） ，保持完好、整洁和美观。", "options": ["养护", "维修", "管理", "服务", "维护"], "answer": [0, 1], "explanation": "施工单位应当定期对围挡进行养护、维修,保持完好、整洁和美观。"},
  {"id": 942, "type": "multiple", "question": "《上海市建设工程文明施工管理规定》规定，施工现场设置生活区的，应当符合 （　　） 规定。", "options": ["生活区和作业区分隔设置", "设置饮用水设施", "设置盥洗池和淋浴间", "设置水冲式或者移动式厕所，并由专人负责冲洗和消毒", "设置符合分类要求的密闭式垃圾容器，生活垃圾应当分类放置于垃圾容器内并做到日产日清"], "answer": [0, 1, 2, 3, 4], "explanation": "第二十一条（施工现场生活区设置）\n施工现场设置生活区的，应当符合下列规定：\n（一）生活区和作业区分隔设置；\n（二）设置饮用水设施；\n（三）设置盥洗池和淋浴间；\n（四）设置水冲式或者移动式厕所，并由专人负责冲洗和消毒；\n（五）设置符合分类要求的密闭式垃圾容器，生活垃圾应当分类放置于垃圾容器内并做到日产日清。\n在生活区设置食堂的，应当依法办理餐饮服务许可手续，并遵守食品卫生管理的有关规定。\n在生活区设置宿舍的，应当安装可开启式窗户，每间宿舍人均居住面积不得低于4平方米。"},
  {"id": 943, "type": "multiple", "question": "《建筑工程安全防护、文明施工措施费用及使用管理规定》规定，建筑工程安全防护、文明施工措施费用是由《建筑安装工程费用项目组成》中措施费所含的 （　　） 组成。", "options": ["文明施工费", "环境保护费", "临时设施费", "安全施工费", "安全人员培训费"], "answer": [0, 1, 2, 3], "explanation": "建筑工程安全防护、文明施工措施费用是由《建筑安装工程费用项目组成》中措施费所含的环境保护费、文明施工费、安全施工费用、临时设施费等组成的。"},
  {"id": 944, "type": "multiple", "question": "《房屋建筑工程文明施工提升标准》要求，企业LOGO标识及各类宣传，应采用喷绘、涂刷等方式，严禁在 （　　） 悬挂广告、标语。", "options": ["结构顶部", "塔吊机身", "平衡臂", "外脚手架", "围墙"], "answer": [0, 1, 2, 3, 4], "explanation": "企业LOGO标识及各类宣传,应采用喷绘、涂刷等方式,严禁在结构顶部、塔吊机身和平衡臂、外脚手架、围墙悬挂广告、标语。"},
  {"id": 945, "type": "multiple", "question": "《房屋建筑工程文明施工提升标准》规定，施工防护设施要求 （　　） 。", "options": ["工具化", "定型化", "指标化", "固定化", "标准化"], "answer": [0, 1, 4], "explanation": "施工防护设施工具化、定型化、标准化"},
  {"id": 946, "type": "multiple", "question": "施工单位应当在施工工地设置硬质围挡，并采取覆盖、 （　　） 等有效防尘降尘措施。", "options": ["清运", "分段作业", "择时施工", "洒水抑尘", "冲洗地面和车辆"], "answer": [1, 2, 3, 4], "explanation": "【依据】《建设工程安全生产管理条例》\n【解析】正确答案是B、C、D、E。题干对应的是建设工程参建各方安全责任。 A项“清运”错误，它不符合题干限定的对象、程序或条件。 B项“分段作业”正确，它与题干所述“施工单位应当在施工工地设置硬质围挡，并采取覆”相对应。 C项“择时施工”正确，它与题干所述“施工单位应当在施工工地设置硬质围挡，并采取覆”相对应。 D项“洒水抑尘”正确，它与题干所述“施工单位应当在施工工地设置硬质围挡，并采取覆”相对应。 E项“冲洗地面和车辆”正确，它与题干所述“施工单位应当在施工工地设置硬质围挡，并采取覆”相对应。"},
  {"id": 947, "type": "multiple", "question": "下列选项中符合《上海市建筑垃圾处理管理规定》规定是 （　　） 。", "options": ["工程渣土，进入消纳场所进行消纳", "泥浆，进入泥浆预处理设施进行预处理后，进入消纳场所进行消纳", "装修垃圾经分拣后进入消纳场所和资源化利用设施进行消纳、利用", "建筑废弃混凝土，进入资源化利用设施进行利用", "拆除工程中产生的废弃物，经分拣后进入消纳场所和资源化利用设施进行消纳、利用"], "answer": [0, 1, 2, 3, 4], "explanation": "建筑垃圾应当按照下列要求，进行分类处理：\n（一）工程渣土，进入消纳场所进行消纳；\n（二）泥浆，进入泥浆预处理设施进行预处理后，进入消纳场所进行消纳；\n（三）装修垃圾和拆除工程中产生的废弃物，经分拣后进入消纳场所和资源化利用设施进行消纳、利用；\n（四）建筑废弃混凝土，进入资源化利用设施进行利用。"},
  {"id": 948, "type": "multiple", "question": "《建筑工程绿色施工评价标准》规范了绿色施工评价的方法，实施评价的基本思路是： （　　） 。", "options": ["实用", "简便", "经济", "节约", "有效"], "answer": [0, 1, 3], "explanation": "【依据】《建筑工程绿色施工评价标准》\n【解析】正确答案是A、B、E。题干对应的是建筑工程绿色施工评价标准。 A项“实用”正确，它与题干所述“《建筑工程绿色施工评价标准》规范了绿色施工评”相对应。 B项“简便”正确，它与题干所述“《建筑工程绿色施工评价标准》规范了绿色施工评”相对应。 C项“经济”错误，它不符合题干限定的对象、程序或条件。 D项“节约”错误，它不符合题干限定的对象、程序或条件。 E项“有效”正确，它与题干所述“《建筑工程绿色施工评价标准》规范了绿色施工评”相对应。"},
  {"id": 949, "type": "multiple", "question": "根据《绿色施工导则》要求，必须优化钢结构制作和安装方法，大型钢结构宜采用 （　　） 等安装方法，减少方案的措施用材量。", "options": ["工厂制作，现场拼装", "分段吊装", "整体提升", "滑移", "顶升"], "answer": [0, 1, 2, 3, 4], "explanation": "优化钢结构制作和安装方法。大型钢结构宜采用工厂制作，现场拼装；宜采用分段吊装、整体提升、滑移、顶升等安装方法，减少方案的措施用材量。"},
  {"id": 950, "type": "multiple", "question": "施工安全监管体制是国家安全生产监管体制的一个子系统，实行 （　　） 管理相结合的体制。", "options": ["综合监督", "行业监督", "专业监督", "总包监管", "分包监管"], "answer": [0, 1], "explanation": "我国目前安全生产管理体制是：综合监管与行业监管相结合、国家监察与地方监管相结合、政府监督与其他监督 相结合的格局。国务院安全生产监督管理部门依照 《安全生产法》，对全国安全生产工作实施综合监督管理。"},
  {"id": 951, "type": "multiple", "question": "建设行政管理部门在履行建设工程安全监督管理职责时，有权要求被检查单位提供有关建设工程的 （　　） 资料。", "options": ["消防", "生产", "质量", "施工", "安全"], "answer": [2, 4], "explanation": "第五十五条建设行政管理部门和其他有关部门在履行建设工程质量和安全监督管理职责时，有权采取下列措施：\n（一）要求被检查单位提供有关建设工程质量和安全的资料；\n（二）进入被检查单位的施工现场进行检查，并将检查的时间、地点、内容、发现的问题及其处理情况，作出书面记录；\n（三）发现有影响建设工程质量的问题或者安全事故隐患时，责令改正或者立即排除；重大安全事故隐患排除前或者排除过程中无法保证安全的，责令从危险区域内撤出作业人员或者暂停施工；\n（四）法律、法规规定采取的其他措施。"},
  {"id": 952, "type": "multiple", "question": "《上海市建设工程质量安全监督机构与监督人员管理若干规定》的第二章规定了监督机构 （　　） 基本条件等。", "options": ["在职责范围内，独立开展建设工程质量安全监督工作，具有独立的对外挂牌和对外监督印章", "有固定的质量安全监督经费来源", "有相对独立的固定办公场所", "有一定在职的工作人员", "有健全的质量安全监督和内部管理制度"], "answer": [0, 1, 2, 4], "explanation": "（一）机构配置\n1、具有行政管理部门明确监督工作内容、职责、权限的行政执法委托书；\n2、在职责范围内，独立开展建设工程质量安全监督工作，具有独立的对外挂牌和对外监督印章；\n3、有固定的质量安全监督经费来源；\n4、有相对独立的固定办公场所，办公面积应当满足监督工作的需要；\n5、配备满足工程质量安全监督需要的仪器、设备、工具和专用于工程质量安全监督的执法车辆等；\n6、有健全的质量安全监督和内部管理制度；\n7、具备与监督工作相适应的信息化管理条件。"},
  {"id": 953, "type": "multiple", "question": "《上海市建设工程施工安全监督管理办法》规定，施工单位在编制施工组织设计时，应当根据建设工程的 （　　） ,制定和组织落实专项的施工安全技术措施，并向所有施工人员进行安全技术交底。", "options": ["人员配备", "性质", "规模", "特点", "施工现场的环境条件"], "answer": [1, 2, 3, 4], "explanation": "施工单位在编制施工组织设计时，应当根据建设工程的性质、规模、特点以及施工现场的环境条件，制定和组织落实专项的施工安全技术措施，并向所有施工人员（包括按照有关规定使用的其他建筑劳务人员，下同）进行安全技术交底。"},
  {"id": 954, "type": "multiple", "question": "《上海市建设工程施工安全监督管理办法》规定，施工单位应当遵守施工现场 （　　） 的有关规定，确保用火作业符合消防技术标准和规范，并保证消防设施的完好、有效。", "options": ["高空作业安全", "电气安全保护", "特种工种操作安全", "纵火安全", "防火安全"], "answer": [1, 4], "explanation": "第十六条 （电气安全保护和防火安全）\n施工单位应当遵守施工现场电气安全保护和防火安全的有关规定，并达到下列要求：\n（一）保持变配电设施和输配电线路处于安全、可靠的可使用状态；\n（二）确保用火作业符合消防技术标准和规范，并保证消防设施的完好、有效。"},
  {"id": 955, "type": "multiple", "question": "《房屋建筑和市政基础设施工程施工安全监督规定》规定，施工安全监督主要包括 （　　） 。", "options": ["抽查工程建设责任主体履行安全生产职责情况", "抽查建筑施工安全生产标准化开展情况", "组织或参与工程项目施工安全事故的调查处理", "依法对工程建设责任主体违法违规行为实施行政处罚", "依法处理与工程项目施工安全相关的投诉、举报"], "answer": [0, 1, 2, 3, 4], "explanation": "第八条 施工安全监督主要包括以下内容：\n（一）抽查工程建设责任主体履行安全生产职责情况；\n（二）抽查工程建设责任主体执行法律、法规、规章、制度及工程建设强制性标准情况；\n（三）抽查建筑施工安全生产标准化开展情况；\n（四）组织或参与工程项目施工安全事故的调查处理；\n（五）依法对工程建设责任主体违法违规行为实施行政处罚；\n（六）依法处理与工程项目施工安全相关的投诉、举报。"},
  {"id": 956, "type": "multiple", "question": "《房屋建筑和市政基础设施工程施工安全监督规定》规定，监督机构实施工程项目的施工安全监督，有权采取以下 （　　） 措施。", "options": ["要求工程建设责任主体提供有关工程项目安全管理的文件和资料", "进入工程项目施工现场进行安全监督抽查", "发现安全隐患，责令整改或暂时停止施工", "发现违法违规行为，按权限实施行政处罚或移交有关部门处理", "向社会公布工程建设责任主体安全生产不良信息"], "answer": [0, 1, 2, 3, 4], "explanation": "第十条 监督机构实施工程项目的施工安全监督，有权采取下列措施：\n（一）要求工程建设责任主体提供有关工程项目安全管理的文件和资料；\n（二）进入工程项目施工现场进行安全监督抽查；\n（三）发现安全隐患，责令整改或暂时停止施工；\n（四）发现违法违规行为，按权限实施行政处罚或移交有关部门处理。\n（五）向社会公布工程建设责任主体安全生产不良信息。"},
  {"id": 957, "type": "multiple", "question": "《上海市建设工程质量安全监督管理规定》规定，建设工程施工过程中，监督机构在接到工程质量安全险情、质量安全事故报告后，应当采取以下哪些处理方式 （　　） 。", "options": ["依据国家及本市有关规定上报险情和事故情况", "应当迅速采取有效措施，组织抢救.防止事故扩大，减少人员伤亡和财产损失", "按照职责分工，组织或参与应急处置、事故调查处理", "负责人应当按照国家有关规定立即如实报告当地负有安全生产监督管理职责的部门", "安排人员赶赴现场，采集现场信息"], "answer": [0, 2, 4], "explanation": "四、建设工程施工过程中，监督机构在接到工程质量安全险情、质量安全事故报告后，应当依据国家及本市有关规定上报险情和事故情况，安排人员赶赴现场，采集现场信息，按照职责分工，组织或参与应急处置、事故调查处理。"},
  {"id": 958, "type": "multiple", "question": "《上海市建设工程质量安全监督管理规定》规定，监督机构应当按照有关规定，将工程质量安全监督中发现的涉及（）的工程质量问题及整改情况，及时向社会公布。", "options": ["主体基础部分", "结构搭建部分", "主体结构安全", "安全措施", "主要使用功能"], "answer": [2, 4], "explanation": "工程质量监督中发现的涉及主体结构安全和主要使用功能的工程质量问题及整改情况，及时向社会公布。"},
  {"id": 959, "type": "multiple", "question": "《上海市建设工程质量安全巡查管理办法》规定，市住建委、区建管部门应将巡查中发现的违法违规行为，记入相关责任单位、责任人员的信用信息档案，按照有关规定，对责任单位、责任人员实施信用评价扣分或诚信记分工作，并在（）等活动中使用。", "options": ["工程招投标", "资质资格准入", "评标报告", "复核审查", "事中事后监管"], "answer": [0, 1, 4], "explanation": "第十四条（信用管理）\n巡查工作实行“市场与现场联动”。市住建委、区建管部门应将巡查中发现的违法违规行为，记入相关责任单位、责任人员的信用信息档案，按照有关规定，对责任单位、责任人员实施信用评价扣分或诚信记分工作，并在工程招投标、资质资格准入、事中事后监管等活动中使用。"},
  {"id": 960, "type": "multiple", "question": "以下属于我国《民法典》规定的承担民事责任主要方式有 （　　） 。", "options": ["赔偿损失", "恢复原状", "支付补偿金", "消除危害", "更换"], "answer": [0, 1, 4], "explanation": "《民法典》第一百七十九条第一款规定，承担民事责任的方式主要有：（一）停止侵害；（二）排除妨碍；（三）消除危险；（四）返还财产；（五）恢复原状；（六）修理、重作、更换；（七）继续履行；（八）赔偿损失；（九）支付违约金；（十）消除影响、恢复名誉；（十一）赔礼道歉。罚款属于行政处罚的种类。"},
  {"id": 961, "type": "multiple", "question": "我国《行政处罚法》规定的行政处罚有 （　　） 。", "options": ["警告", "罚款", "撤职", "没收违法所得", "行政拘留"], "answer": [0, 1, 3, 4], "explanation": "第九条 行政处罚的种类：\n（一）警告、通报批评；\n（二）罚款、没收违法所得、没收非法财物；\n（三）暂扣许可证件、降低资质等级、吊销许可证件；\n（四）限制开展生产经营活动、责令停产停业、责令关闭、限制从业；\n（五）行政拘留；\n（六）法律、行政法规规定的其他行政处罚。"},
  {"id": 962, "type": "multiple", "question": "我国《刑法》规定了刑罚分为主刑和附加刑。下列选项中属于主刑的是 （　　） 和死刑。", "options": ["劳动教养", "管制", "拘役", "有期徒刑", "无期徒刑"], "answer": [1, 2, 3, 4], "explanation": "第三十二条 刑罚分为主刑和附加刑。\n第三十三条 主刑的种类如下：\n(一)管制;\n(二)拘役;\n(三)有期徒刑;\n(四)无期徒刑;\n(五)死刑。"},
  {"id": 963, "type": "multiple", "question": "施工安全中常见的刑事责任有 （　　） 。", "options": ["工程重大安全事故罪", "工程安全责任事故罪", "重大责任事故罪", "重大安全事故罪", "重大劳动安全事故罪"], "answer": [0, 2, 4], "explanation": "在建设工程领域，常见的刑事法律责任有：工程重大安全事故罪、重大责任事故罪、重大劳动安全事故罪、串通投标罪。"},
  {"id": 964, "type": "multiple", "question": "《安全生产法》规定，生产经营单位有下列 （　　） 行为的，责令限期改正，处十万元以下的罚款。", "options": ["未按照规定配备安全生产管理人员、注册安全工程师的", "未按照规定对实习学生进行安全生产教育和培训的", "未如实记录安全生产教育和培训情况的", "未将事故隐患排查治理情况如实记录的", "未按照规定制定生产安全事故应急救援预案的"], "answer": [0, 1, 2, 3, 4], "explanation": "第九十七条 生产经营单位有下列行为之一的，责令限期改正，处十万元以下的罚款；逾期未改正的，责令停产停业整顿，并处十万元以上二十万元以下的罚款， 对其直接负责的主管人员和其他直接责任人员处二万元以上五万元以下的罚款：\n（一）未按照规定设置安全生产管理机构或者配备安全生产管理人员、注册安全工程师的；\n（二）危险物品的生产、经营、储存、装卸单位以及矿山、金属冶炼、建筑施工、运输单位的主要负责人和安全生产管理人员未按照规定经考核合格的；\n（三）未按照规定对从业人员、被派遣劳动者、实习学生进行安全生产教育和培训，或者未按照规定如实告知有关的安全生产事项的；\n（四）未如实记录安全生产教育和培训情况的；\n（五）未将事故隐患排查治理情况如实记录或者未向从业人员通报的；\n（六）未按照规定制定生产安全事故应急救援预案或者未定期组织演练的；\n（七）特种作业人员未按照规定经专门的安全作业培训并取得相应资格，上岗作业的。"},
  {"id": 965, "type": "multiple", "question": "依据《安全生产法》规定，生产经营单位未按照规定设置 （　　） ，责令限期改正，处十万元以下的罚款。", "options": ["安全生产管理机构", "配备安全生产管理人员", "注册安全工程师", "配备安全生产知识培训人员", "安全生产知识培训机构"], "answer": [0, 1, 2], "explanation": "第九十七条 生产经营单位有下列行为之一的，责令限期改正，处十万元以下的罚款；逾期未改正的，责令停产停业整顿，并处十万元以上二十万元以下的罚款， 对其直接负责的主管人员和其他直接责任人员处二万元以上五万元以下的罚款：\n（一）未按照规定设置安全生产管理机构或者配备安全生产管理人员、注册安全工程师的；\n（二）危险物品的生产、经营、储存、装卸单位以及矿山、金属冶炼、建筑施工、运输单位的主要负责人和安全生产管理人员未按照规定经考核合格的；\n（三）未按照规定对从业人员、被派遣劳动者、实习学生进行安全生产教育和培训，或者未按照规定如实告知有关的安全生产事项的；\n（四）未如实记录安全生产教育和培训情况的；\n（五）未将事故隐患排查治理情况如实记录或者未向从业人员通报的；\n（六）未按照规定制定生产安全事故应急救援预案或者未定期组织演练的；\n（七）特种作业人员未按照规定经专门的安全作业培训并取得相应资格，上岗作业的。"},
  {"id": 966, "type": "multiple", "question": "生产经营单位应当为从业人员提供符合 （　　） 的劳动防护用品。", "options": ["国家标准", "地方标准", "行业标准", "企业标准", "国际标准"], "answer": [0, 2], "explanation": "【依据】《中华人民共和国安全生产法》\n【解析】正确答案是A、C。题干对应的是安全生产法定职责。 A项“国家标准”正确，它与题干所述“生产经营单位应当为从业人员提供符合的劳动防护”相对应。 B项“地方标准”错误，它不符合题干限定的对象、程序或条件。 C项“行业标准”正确，它与题干所述“生产经营单位应当为从业人员提供符合的劳动防护”相对应。 D项“企业标准”错误，它不符合题干限定的对象、程序或条件。 E项“国际标准”错误，它不符合题干限定的对象、程序或条件。"},
  {"id": 967, "type": "multiple", "question": "依据《安全生产违法行为行政处罚办法》规定，生产经营单位及其有关人员 （　　） 行政审批工作人员取得安全生产许可证书及其他批准文件的，撤销许可及批准文件，该生产经营单位及其有关人员在3年内不得再次申请该行政许可。", "options": ["弄虚作假", "骗取", "伪造", "勾结", "串通"], "answer": [0, 1, 3, 4], "explanation": "第五十一条 生产经营单位及其有关人员弄虚作假，骗取或者勾结、串通行政审批工作人员取得安全生产许可证书及其他批准文件的，撤销许可及批准文件，并按照下列规定处以罚款：\n（一）生产经营单位有违法所得的，没收违法所得，并处违法所得1倍以上3倍以下的罚款，但是最高不得超过3万元；没有违法所得的，并处5000元以上1万元以下的罚款；\n（二）对有关人员处1000元以上1万元以下的罚款。\n有前款规定违法行为的生产经营单位及其有关人员在3年内不得再次申请该行政许可。\n生产经营单位及其有关人员未依法办理安全生产许可证书变更手续的，责令限期改正，并对生产经营单位处1万元以上3万元以下的罚款，对有关人员处1000元以上5000元以下的罚款。"},
  {"id": 968, "type": "multiple", "question": "依据《安全生产违法行为行政处罚办法》规定，生产经营单位及其有关人员有 （　　） 之一的，应当从轻或者减轻行政处罚。", "options": ["主动消除安全生产违法行为危害后果的", "减轻安全生产违法行为危害后果的", "受他人胁迫实施安全生产违法行为的", "配合安全监管监察部门查处安全生产违法行为有立功表现的", "其他依法应予从轻或者减轻行政处罚的"], "answer": [0, 1, 2, 3, 4], "explanation": "第五十六条 生产经营单位及其有关人员有下列情形之一的，应当依法从轻或者减轻行政处罚：\n（一）已满14周岁不满18周岁的公民实施安全生产违法行为的；\n（二）主动消除或者减轻安全生产违法行为危害后果的；\n（三）受他人胁迫实施安全生产违法行为的；\n（四）配合安全监管监察部门查处安全生产违法行为，有立功表现的；\n（五）主动投案，向安全监管监察部门如实交待自己的违法行为的；\n（六）具有法律、行政法规规定的其他从轻或者减轻处罚情形的。"},
  {"id": 969, "type": "multiple", "question": "根据《上海市建设工程施工安全监督管理办法》第十四条第一款施工单位应当按照有关的国家标准、行业标准或者地方标准，在施工现场设置安全防护设施，应满足 （　　） 等要求。", "options": ["根据建设工程的施工进度，及时调整和完善安全防护设施", "在施工现场的事故易发区域，设置专项的安全防护设施，并设立醒目的警示标志", "根据季节，设置或者调整专项的安全防护设施，并进行相关的安全检查", "根据天气特点，设置或者调整专项的安全防护设施，并进行相关的安全检查", "根据人员的变化，设置或者调整专项的安全防护设施，并进行相关的安全检查"], "answer": [0, 1, 2, 3], "explanation": "第十四条（施工安全防护设施的设置）\n施工单位应当按照有关的国家标准、行业标准或者地方标准，在施工现场设置安全防护设施，并达到下列要求：\n（一）根据建设工程的施工进度，及时调整和完善安全防护设施；\n（二）在施工现场的事故易发区域，设置专项的安全防护设施，并设立醒目的警示标志；\n（三）根据季节或者天气特点，设置或者调整专项的安全防护设施，并进行相关的安全检查。\n建设工程涉及公共安全的，施工单位应当按照有关规定，在施工现场周围设置专项的公共安全防护设施。公共安全防护设施的有关费用应当在施工承包合同中约定；施工承包合同中未作约定的，应当由建设单位负担。"},
  {"id": 970, "type": "multiple", "question": "依据《建筑起重机械安全监督管理规定》，施工总承包单位应当履行安全职责，其中包括 （　　） 。", "options": ["审核安装单位制定的建筑起重机械安装、拆卸工程方案", "审核安装单位制定的生产安全事故应急救援预案", "审核安装单位的资质证书", "审核特种作业人员的特种作业操作资格证书", "审核使用单位的资质证书"], "answer": [0, 1, 2, 3, 4], "explanation": "第二十一条 施工总承包单位应当履行下列安全职责：\n（一）向安装单位提供拟安装设备位置的基础施工资料，确保建筑起重机械进场安装、拆卸所需的施工条件；\n（二）审核建筑起重机械的特种设备制造许可证、产品合格证、制造监督检验证明、备案证明等文件；\n（三）审核安装单位、使用单位的资质证书、安全生产许可证和特种作业人员的特种作业操作资格证书；\n（四）审核安装单位制定的建筑起重机械安装、拆卸工程专项施工方案和生产安全事故应急救援预案；\n（五）审核使用单位制定的建筑起重机械生产安全事故应急救援预案；\n（六）指定专职安全生产管理人员监督检查建筑起重机械安装、拆卸、使用情况；\n（七）施工现场有多台塔式起重机作业时，应当组织制定并实施防止塔式起重机相互碰撞的安全措施。"},
  {"id": 971, "type": "multiple", "question": "国际劳工局是国际劳工组织常设秘书处。主要活动有从事 （　　） ，设在瑞士日内瓦国际劳工局总部。", "options": ["国际劳工立法", "制定公约和建议书", "协调各成员国之间纠纷", "技术援助", "技术合作"], "answer": [0, 1, 3, 4], "explanation": "国际劳工大会：最高权利机构，每年召开一次会议；闭会期间理事会指导该组织工作，国际劳工局是其常设秘书处。主要活动有从事国际劳工立法，制定公约和建议书以及技术援助和技术合作。"},
  {"id": 972, "type": "multiple", "question": "《建筑业安全卫生公约》所指的雇主是 （　　） 在建筑工地雇佣一名以上工人的任何自然人或法人和视具体情况而定。", "options": ["发包方", "主承包商", "承包商", "转包商", "投标方"], "answer": [1, 2, 3], "explanation": "“雇主”一词指：\n(1)在建筑工地雇佣一名或数名工人的任何自然人或法人；和\n(2)视具体情况而定的主承包商、承包商或转包商；"},
  {"id": 973, "type": "multiple", "question": "建筑施工安全生产技术规划编制应依据 （　　） 和周边环境、与工程有关的资源供应情况、施工技术、施工工艺、材料、设备等。", "options": ["与工程建设有关的法律法规", "国家现行有关标准", "工程设计文件", "工程施工合同或者招标投标文件", "工程场地条件"], "answer": [0, 1, 2, 3, 4], "explanation": "安全技术规划编制应依据与工程建设有关的法律法规、国家现行相关标准、工程设计文件、工程施工合同或招标投标文件、工程场地条件和周边环境、与工程有关的资源供应情况、施工技术、施工工艺、材料、设备等。"},
  {"id": 974, "type": "multiple", "question": "危险源辨识是指识别危险源的 （　　） ，并确定其特性的过程。", "options": ["存在", "根源", "状态", "方位", "程度"], "answer": [0, 4], "explanation": "危险源辨识是指识别危险源的存在并确定其特性的过程，危险源辨识是安全管理的基础工作，主要目的是要找出每项工作有关的所有危险源，并考虑这些危险源可能会对什么人造成什么样的损害或导致什么设备设施损坏。"},
  {"id": 975, "type": "multiple", "question": "下列属于Ⅰ级危险等级的分部分项工程有 （　　） 。", "options": ["开挖深度16m 及以上的人工挖孔桩工程", "各类工具式模板工程：包括滑模、爬模、飞模、隧道模等工程", "文物保护建筑、优秀历史建筑或历史文化风貌区影响范围内的拆除工程", "高处作业吊篮", "悬挑式脚手架工程"], "answer": [0, 1, 2], "explanation": "【依据】《建筑施工高处作业安全技术规范》JGJ 80-2016\n【解析】正确答案是A、B、C。题干对应的是建筑施工高处作业防护。 A项“开挖深度16m 及以上的人工挖孔桩工程”正确，它与题干所述“下列Ⅰ级危险等级的分部分项工程有”相对应。 B项“各类工具式模板工程：包括滑模、爬模、飞模、隧道模等工程”正确，它与题干所述“下列Ⅰ级危险等级的分部分项工程有”相对应。 C项“文物保护建筑、优秀历史建筑或历史文化风貌区影响范围内的拆除工程”正确，它与题干所述“下列Ⅰ级危险等级的分部分项工程有”相对应。 D项“高处作业吊篮”错误，它不符合题干限定的对象、程序或条件。 E项“悬挑式脚手架工程”错误，它不符合题干限定的对象、程序或条件。"},
  {"id": 976, "type": "multiple", "question": "人的危险和有害因素，其包括的内容有 （　　） 。", "options": ["负荷超限", "健康情况异常", "辨识功能缺陷", "指挥失误", "操作失误"], "answer": [0, 1, 2, 3, 4], "explanation": "1.人的因素\n1）心理、生理性危险和有害因素\n⑴负荷超限（体力负荷超限、听力负荷超限、视力负荷超限、其他负荷超限）。\n⑵健康状况异常。\n（3）从事禁忌作业。\n（4）心理异常（情绪异常、冒险心理、过度紧张、其他心理异常）。\n（5）辨识功能缺陷（感知延迟、辨识错误、其他辨识功能缺陷）。\n（6）其他心理、生理性危险和有害因素。\n2）行为性危险和有害因素\n⑴指挥错误（指挥失误、违章指挥、其他指挥错误）。\n⑵操作错误（误操作、违章作业、其他操作失误）。\n（3）监护失误。（4）其他错误。（5）其他行为性危险和危害因素。"},
  {"id": 977, "type": "multiple", "question": "风险准则是企业开展 （　　） 工作的重要依据。", "options": ["风险评估", "风险模拟", "风险管控", "风险预测", "风险防控"], "answer": [0, 2], "explanation": "确定风险准则 风险准则是企业开展风险评估和风险管控工作的重要依据。"},
  {"id": 978, "type": "multiple", "question": "对于脚手架工程中可能发生的事故类型主要有 （　　） 。", "options": ["坍塌", "沉陷", "高处坠落", "物体打击", "中毒"], "answer": [0, 2, 3], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】正确答案是A、C、D。题干对应的是建筑施工安全管理。 A项“坍塌”正确，它与题干所述“对于脚手架工程中可能发生的事故类型主要有”相对应。 B项“沉陷”错误，它不符合题干限定的对象、程序或条件。 C项“高处坠落”正确，它与题干所述“对于脚手架工程中可能发生的事故类型主要有”相对应。 D项“物体打击”正确，它与题干所述“对于脚手架工程中可能发生的事故类型主要有”相对应。 E项“中毒”错误，它不符合题干限定的对象、程序或条件。"},
  {"id": 979, "type": "multiple", "question": "安全生产技术措施实施前应审核作业过程的指导文件，实施过程中应进行 （　　） ，并应使人员、机械、材料、方法、环境等因素均处于受控状态。", "options": ["检查", "分析", "评价", "计算", "计划"], "answer": [0, 1, 2], "explanation": "安全技术措施实施前应审核作业过程的指导文件,实施过程中应进行检查、分析和评价,并应使人员、机械、材料、方法、环境等因素均处于受控状态。"},
  {"id": 980, "type": "multiple", "question": "建筑施工过程中， （　　） 应按相应专业技术标准进行安全生产技术控制。", "options": ["各分部分项工程", "各工序", "各单体工程", "各单位工程", "各工艺流程"], "answer": [0, 1], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】正确答案是A、B。题干对应的是建筑施工安全管理。 A项“各分部分项工程”正确，它与题干所述“建筑施工过程中，应按相应专业技术标准进行安全”相对应。 B项“各工序”正确，它与题干所述“建筑施工过程中，应按相应专业技术标准进行安全”相对应。 C项“各单体工程”错误，它不符合题干限定的对象、程序或条件。 D项“各单位工程”错误，它不符合题干限定的对象、程序或条件。 E项“各工艺流程”错误，它不符合题干限定的对象、程序或条件。"},
  {"id": 981, "type": "multiple", "question": "安全生产技术交底是指交底方向被交底方对预控和控制生产安全事故发生及减少其危害的 （　　） 进行说明的技术活动，用于指导建筑施工行为。", "options": ["技术措施", "施工方法", "施工措施", "施工工艺", "施工过程"], "answer": [0, 1], "explanation": "安全技术交底 交底方向被交底方对预防和控制生产安全事故发生及减少其危害的技术措施、施工方法进行说明的技术活动，用于指导建筑施工行为。"},
  {"id": 982, "type": "multiple", "question": "安全生产技术交底活动需要对将要开工的工程施工项目通过 （　　） 的排查，找出现实中存在的不安全因素，制定相应的对策，防止作业中的危害。", "options": ["施工机械", "施工现场", "危险源", "施工人员", "施工风险"], "answer": [2, 4], "explanation": "【依据】《建筑施工安全技术统一规范》GB 50870-2013\n【解析】正确答案是A、B、C。题干对应的是建筑施工安全技术措施。 A项“施工机械”正确，它与题干所述“安全生产技术交底活动需要对将要开工的工程施工”相对应。 B项“施工现场”正确，它与题干所述“安全生产技术交底活动需要对将要开工的工程施工”相对应。 C项“危险源”正确，它与题干所述“安全生产技术交底活动需要对将要开工的工程施工”相对应。 D项“施工人员”错误，它不符合题干限定的对象、程序或条件。 E项“施工风险”错误，它不符合题干限定的对象、程序或条件。"},
  {"id": 983, "type": "multiple", "question": "建筑施工安全生产技术监测的监测报警值宜以监测项目的 （　　） 进行控制。", "options": ["累计变化量", "时间变化率", "变化速率值", "瞬时变化量", "位移变化值"], "answer": [0, 2], "explanation": "建筑施工安全技术监测预警应依据事前设置的限值确定；监测报警值宜以监测项目的累计变化量和变化速率值进行控制。"},
  {"id": 984, "type": "multiple", "question": "建筑施工安全生产技术监测现场测点布置中，在监测对象 （　　） 部位，监测点的数量和观测频度应适当加密。", "options": ["内力变化大", "变形变化大", "高度大", "建筑角部", "周边重点监护"], "answer": [0, 1, 4], "explanation": "在监测对象内力和变形变化大的代表性部位及周边重点监护部位,监测点的数量和观测频度应适当加密;"},
  {"id": 985, "type": "multiple", "question": "建筑施工安全生产技术预警是指在建筑施工中，通过仪器监测分析、数据计算等技术手段，针对可能引发生产安全事故的征兆所采取 （　　） 的技术措施。", "options": ["预先报警", "事前控制", "事前分析", "过程管理", "事后处理"], "answer": [0, 1], "explanation": "建筑施工安全技术预警 在建筑施工中，通过仪器监测分析、数据计算等技术手段，针对可能引发生产安全事故的征兆所采取的预先报警和事前控制的技术措施。"},
  {"id": 986, "type": "multiple", "question": "无支护基坑的坑壁形式分为 （　　） 。", "options": ["垂直坑壁", "斜坡", "阶梯型坑壁", "变坡度坑壁", "变坡度阶梯形坑壁"], "answer": [0, 1, 2, 3], "explanation": "无支护基坑的坑壁形式分为垂直坑壁，斜坡，阶梯型坑壁以及变坡度坑壁。"},
  {"id": 987, "type": "multiple", "question": "基坑工程施工安全专项方案中安全管理措施包括 （　　） 内容。", "options": ["安全控制技术措施", "安全处理预案", "安全管理组织", "安全管理应急启动", "人员教育培训"], "answer": [2, 4], "explanation": "安全管理措施，包含安全管理组织及人员教育培训等措施；"},
  {"id": 988, "type": "multiple", "question": "编制专项施工方案，更好地指导基坑支护开挖作业，确保 （　　） 的安全。", "options": ["基坑", "支护", "作业人员", "支撑", "机械设备"], "answer": [0, 1, 2, 3, 4], "explanation": "【依据】《危险性较大的分部分项工程安全管理规定》\n【解析】正确答案是A、B、C。题干对应的是危大工程专项施工方案管理。 A项“基坑”正确，它与题干所述“编制专项施工方案，更好地指导基坑支护开挖作业”相对应。 B项“支护”正确，它与题干所述“编制专项施工方案，更好地指导基坑支护开挖作业”相对应。 C项“作业人员”正确，它与题干所述“编制专项施工方案，更好地指导基坑支护开挖作业”相对应。 D项“支撑”错误，它不符合题干限定的对象、程序或条件。 E项“机械设备”错误，它不符合题干限定的对象、程序或条件。"},
  {"id": 989, "type": "multiple", "question": "基坑支护结构中，支撑结构的作用有 （　　） 。", "options": ["为深基础施工创造一个安全、良好的作业环境", "保证基础工程能按期保质施工", "保证基坑开挖时，最大限度地减少对周围建筑物、道路及管线的影响", "控制支护结构的变形区域位移对本工程的影响", "施工方便，确保安全"], "answer": [0, 1, 2, 3], "explanation": "支护结构的作用：\n（1）为基础施工创造一个安全的，良好的作业环境，保证基础工程施工按期保质完成.\n(2)保证基坑开挖时，最大限度地减小对周围建(构)筑物，道路及管线的影响，确保其安全.\n（3)同时还应控制支护结构的变形对工程桩的影响"},
  {"id": 990, "type": "multiple", "question": "基坑各类支护结构的使用条件有 （　　） 。", "options": ["基坑深度", "环境条件", "土类条件", "地下水条件", "基坑面积"], "answer": [0, 1, 2, 3], "explanation": "【依据】《建筑基坑支护技术规程》JGJ 120-2012 / 《建筑基坑工程监测技术标准》GB 50497-2019\n【解析】正确答案是A、B、C、D。题干对应的是基坑工程安全与监测。 A项“基坑深度”正确，它与题干所述“基坑各类支护结构的使用条件有”相对应。 B项“环境条件”正确，它与题干所述“基坑各类支护结构的使用条件有”相对应。 C项“土类条件”正确，它与题干所述“基坑各类支护结构的使用条件有”相对应。 D项“地下水条件”正确，它与题干所述“基坑各类支护结构的使用条件有”相对应。 E项“基坑面积”错误，它不符合题干限定的对象、程序或条件。"},
  {"id": 991, "type": "multiple", "question": "基坑工程中，以下关于支挡式结构说法正确的是 （　　） 。", "options": ["悬臂式结构的支挡适用于较深的基坑", "排桩适用于可采用降水或截水帷幕的基坑", "支护结构与主体结构结合的逆作法适用于较深的基坑", "拉锚式结构适用于较深的基坑", "锚杆适用于软土层和高水位的碎石土、砂土层中"], "answer": [1, 2, 3], "explanation": "悬臂式围护结构适用于土质较好、开挖深度较浅的基坑工程。\n支护结构与主体结构结合的逆作法 适用于基坑周边环境条件很复杂的深基坑。\n锚杆不宜用在软土层和高水位的碎石土、砂土层中。"},
  {"id": 992, "type": "multiple", "question": "地下连续墙的转角处或有特殊要求时，单元槽段的平面形状可采用 （　　） 。", "options": ["L形", "T形", "Z形", "I形", "H形"], "answer": [0, 1], "explanation": "地下连续墙的转角处或有特殊要求时，单元槽段的平面形状可采用L形、T形等。"},
  {"id": 993, "type": "multiple", "question": "下列关于地下连续墙的说法错误的有 （　　） 。", "options": ["当成槽施工可能对周边环境产生不利影响或成槽壁稳定性较差时，应取较小的槽段长度", "必要时，宜采用搅拌桩对槽壁进行加固", "地下连续墙的混凝土设计强度等级宜取C20~C30", "地下连续墙用于截水时，墙体混凝土抗渗等级不宜小于P4", "水平钢筋及构造钢筋宜选用HPB300或HRB400钢筋，直径不宜小于12mm，水平钢筋间距宜取200mm~400mm"], "answer": [2, 3], "explanation": "地下连续墙的混凝土设计强度等级宜取C30～C40。地下连续墙用于截水时，墙体混凝土抗渗等级不宜小于P6。"},
  {"id": 994, "type": "multiple", "question": "地下连续墙槽段接头类型有 （　　） 。", "options": ["圆形锁口管接头", "波纹管接头", "楔形接头", "工字形钢接头", "混凝土预制接头"], "answer": [0, 1, 2, 3, 4], "explanation": "根据受力特性地下连续墙施工接头可分为柔性接头和刚性接头。\n地下连续墙宜采用圆形锁口管接头、波纹管接头、楔形接头、工字形钢接头或混凝土预制接头等柔性接头；"},
  {"id": 995, "type": "multiple", "question": "下列关于地下连续墙钢筋笼吊装施工说法错误的是 （　　） 。", "options": ["吊装所选用的起重机应满足吊装高度及起重量的要求，主吊和副吊应根据经验确定", "采用双机抬吊作业时，应统一指挥，动作应配合协调，载荷应分配合理", "起重机械在吊钢筋笼行走时，载荷不得超过允许起重量的75%", "钢筋笼离地不得大于500mm，并应栓好拉绳，缓慢行驶", "钢筋笼应设置定位垫块，垫块在水平方向上的间距宜取3m～5m，在垂直方向上宜每层设置2块～3块"], "answer": [0, 2, 4], "explanation": "吊装所选用的吊车应满足吊装高度及起重量的要求，主吊和副吊应根据计算确定。\n起重机械在吊钢筋笼行走时，载荷不得超过允许起重量的70％，钢筋笼离地不得大于500mm，并应拴好拉绳，缓慢行驶。\n钢筋笼应设置定位垫块,垫块在垂直方向上的间距宜取 3～5m,在水平方向上宜每层设置 2～3 块。"},
  {"id": 996, "type": "multiple", "question": "下列关于排桩围护墙的说法正确的是 （　　） 。", "options": ["干作业挖孔时孔口周边必须设置护栏，护栏高度不应小于0.5m", "采用混凝土灌注桩时，单桩的纵向受力钢筋不宜少于5根", "钻机施工时，当桩孔净间距过小或采用多台钻机同时施工时，相邻桩应间隔施工，当无特别措施时完成浇筑混凝土的桩与邻桩间距不宜小于4倍桩径，或间隔施工时间宜大于36h", "采用混凝土灌注桩时，对锚拉式排桩或支撑式排桩，支护桩的桩径宜大于或等于300mm；排桩的中心距不宜大于桩直径的3.0倍", "排桩桩间土应采取防护措施。喷射混凝土面层的厚度不宜小于50mm，混凝土强度等级不宜低于C20，混凝土面层内配置的钢筋网的纵横向间距不宜大于200mm"], "answer": [2, 4], "explanation": "孔口周边必须设置护栏，护栏高度不应小于0.8m。\n纵向受力钢筋宜选用HRB400、HRB500钢筋，单桩的纵向受力钢筋不宜少于8根。\n当桩孔净间距过小或采用多台钻机同时施工时，相邻桩应间隔施工，当无特别措施时完成浇筑混凝土的桩与邻桩间距不应小于4倍桩径，或间隔施工时间宜大于36h。\n采用混凝土灌注桩时，对悬臂式排桩，支护桩的桩径宜大于或等于600mm；对锚拉式排桩或支撑式排桩，支护桩的桩径宜大于或等于400mm；排桩的中心距不宜大于桩直径的2.0倍。\n排桩桩间土应采取防护措施。桩间土防护措施宜采用内置钢筋网或钢丝网的喷射混凝土面层。喷射混凝土面层的厚度不宜小于50mm，混凝土强度等级不宜低于C20，混凝土面层内配置的钢筋网的纵横向间距不宜大于200mm。"},
  {"id": 997, "type": "multiple", "question": "对于排桩，根据 （　　） 的不同，可考虑选择混凝土灌注桩、型钢桩、钢管桩、钢板桩、型钢水泥土搅拌桩等桩型。", "options": ["土层的性质", "安全等级", "地下水条件", "施工机械", "基坑周边环境要求"], "answer": [0, 2, 4], "explanation": "应根据土层的性质、地下水条件及基坑周边环境要求等选择混凝土灌注桩、型钢桩、钢管桩、钢板桩、型钢水泥土搅拌桩等桩型；"},
  {"id": 998, "type": "multiple", "question": "基坑降排水的安全生产目标包括 （　　） 。", "options": ["防止地表水流入基坑而浸泡地基，影响地基承载力", "保障施工机械正常工作", "防止基坑坑底被水浸泡后造成基坑安全性的降低", "防止边坡土方坍塌，影响施工进度", "对基坑施工范围内的地下水进行控制"], "answer": [0, 2, 3, 4], "explanation": "【依据】《建筑基坑支护技术规程》JGJ 120-2012 / 《建筑基坑工程监测技术标准》GB 50497-2019\n【解析】正确答案是A、C、E。题干对应的是基坑工程安全与监测。 A项“防止地表水流入基坑而浸泡地基，影响地基承载力”正确，它与题干所述“基坑降排水的安全生产目标包括”相对应。 B项“保障施工机械正常工作”错误，它不符合题干限定的对象、程序或条件。 C项“防止基坑坑底被水浸泡后造成基坑安全性的降低”正确，它与题干所述“基坑降排水的安全生产目标包括”相对应。 D项“防止边坡土方坍塌，影响施工进度”错误，它不符合题干限定的对象、程序或条件。 E项“对基坑施工范围内的地下水进行控制”正确，它与题干所述“基坑降排水的安全生产目标包括”相对应。"},
  {"id": 999, "type": "multiple", "question": "下列关于排水沟、集水井设计符合规定的是 （　　） 。", "options": ["排水沟深度、宽度、坡度应根据基坑涌水量集水确定", "排水沟底宽不宜小于250mm", "集水井壁应有防护结构，并应设置碎石滤水层、泵端滤网", "排水沟与集水井的深度应随开挖深度加深", "排水沟、集水井与坑边距离不宜小于0.3m"], "answer": [0, 2, 3], "explanation": "排水沟、集水井设计应符合下列规定：\n（1）排水沟深度、宽度、坡度应根据基坑涌水量计算确定，排水沟底宽不宜小于300mm；\n（2）集水井大小和数量应根据基坑涌水量和渗漏水量、积水水量确定，且直径（或宽度）不宜小于0.6m，底面应比排水沟沟底深0.5m，间距不宜大于30m.集水井壁应有防护结构，并应设置碎石滤水层、泵端纱网；\n（3）当基坑开挖深度超过地下水位后，排水沟与集水井的深度应随开挖深度加深，并应及时将集水井中的水排出基坑。\n排水沟、盲沟和集水井与坑边的距离不宜小于0.5m。"},
  {"id": 1000, "type": "multiple", "question": "基坑降水应根据场地的 （　　） 等，选择合理降水井类型、设备和方法。", "options": ["水文地质条件", "基坑面积", "开挖深度", "各土层的渗透性", "周边环境"], "answer": [0, 1, 2, 3], "explanation": "【依据】《建筑基坑支护技术规程》JGJ 120-2012 / 《建筑基坑工程监测技术标准》GB 50497-2019\n【解析】正确答案是A、B、C、D、E。题干对应的是基坑工程安全与监测。 A项“水文地质条件”正确，它与题干所述“基坑降水应场地的等，选择合理降水井类型、设备”相对应。 B项“基坑面积”正确，它与题干所述“基坑降水应场地的等，选择合理降水井类型、设备”相对应。 C项“开挖深度”正确，它与题干所述“基坑降水应场地的等，选择合理降水井类型、设备”相对应。 D项“各土层的渗透性”正确，它与题干所述“基坑降水应场地的等，选择合理降水井类型、设备”相对应。 E项“周边环境”正确，它与题干所述“基坑降水应场地的等，选择合理降水井类型、设备”相对应。"},
  {"id": 1001, "type": "multiple", "question": "下列关于轻型井点降水系统说法正确的是 （　　） 。", "options": ["真空泵的真空度应达到0.08Mpa及以上", "正式抽水宜在预抽水3d后进行", "坑内降水井宜在基坑开挖20d前进行", "总管与真空泵接好后应开动真空泵开始试抽水，检查泵的工作状态", "应及时做好降水记录"], "answer": [0, 3, 4], "explanation": "轻型井点降水系统运行应符合下列规定：\n1）总管与真空泵接好后应开动真空泵开始试抽水，检查泵的工作状态；\n2）真空泵的真空度应达到0.08MPa及以上；\n3）正式抽水宜在预抽水15d后进行；\n4）应及时做好降水记录。"},
  {"id": 1002, "type": "multiple", "question": "以下关于喷射井点施工说法错误的是 （　　） 。", "options": ["井管采用金属管，管壁上渗水孔宜按梅花状布置", "井点管水平间距一般为2~3m", "井点管直径宜为100~150mm", "成孔孔径不应小于300mm，成孔深度应大于过滤器底端埋深1.0m。", "每根喷射井点沉设完毕后，必须及时进行单井试抽，试抽持续到水由浊变清为止"], "answer": [1, 2, 3], "explanation": "喷射井点施工\n（1）井点管直径宜为75mm～100mm，井点管水平间距宜为2.0～4.0m。\n（2）成孔孔径不应小于400mm，成孔深度应大于过滤器底端埋深1.0m。\n（3）回填滤料应符合规定。\n（4）每套喷射井点的井点数不宜超过30根，总管直径不宜小于为150mm，总长不宜超过60.0m。如果多套井点呈环圈布置，各套进水总管之间宜用阀门隔开，每套井点自成系统。\n（5）每根喷射井点沉设完毕后，必须及时进行单井试抽，排出的浑浊水不得回入循环管路系统，试抽时间持续到水由浊变清为止。\n（6）喷射井点系统安装完毕，亦需进行试抽，不应有漏气或翻砂冒水现象。工作水应保持清洁，在降水过程中应视水质浑浊程度及时更换。\n补充：\n3.10 真空井点的构造应符合下列要求：\n1）井管宜采用金属管，管壁上渗水孔宜按梅花状布置，渗水孔直径宜取12mm～18mm，渗水孔的孔隙率应大于15%，渗水段长度应大于1.0m；管壁外应根据土层的粒径设置滤网；"},
  {"id": 1003, "type": "multiple", "question": "截水措施失效时，可考虑采用 （　　） 处理措施。", "options": ["设置导流水管", "采用遇水膨胀材料或压密注浆、聚氨酯注浆等方法堵漏", "采用快硬早强混凝土浇筑护墙", "在基坑外壁增设高压旋喷或水泥土搅拌桩截水帷幕", "增设坑内降水和排水设施"], "answer": [0, 1, 2, 3, 4], "explanation": "截水措施失效时，可采用下列处理措施：\n1 设置导流水管。\n2 采用遇水膨胀材料或压密注浆、聚氨酯注浆等方法堵漏。\n3 快硬早强混凝土浇筑护墙。\n4 在基坑外壁增设高压旋喷或水泥土搅拌桩截水帷幕。\n5 增设坑内降水和排水设施。"},
  {"id": 1004, "type": "multiple", "question": "基坑开挖施工方案应综合考虑工程地质与水文地质条件、环境保护要求、 （　　） 等因素，临水基坑尚应考虑最高水位、潮位等因素。", "options": ["场地条件", "基坑平面尺寸", "开挖深度", "支护形式", "施工方法"], "answer": [0, 1, 2, 3, 4], "explanation": "16.1.1 基坑开挖施工方案应综合考虑工程地质与水文地质条件、环境保护要求、场地条件、基坑平面尺寸、开挖深度、支护形式、施工方法等因素，临水基坑尚应考虑最高水位、潮位等因素。"},
  {"id": 1005, "type": "multiple", "question": "土石方开挖顺序、方法必须与设计工况和施工方案相一致，并遵循 （　　） 的原则。", "options": ["槽支撑", "先撑后挖", "分层开挖", "严禁超挖", "对称开挖"], "answer": [0, 1, 2, 3], "explanation": "土方开挖的顺序、方法必须与设计工况相一致,并遵循“开槽支撑,先撑后挖,分层开挖,严禁超挖\"的原则。"},
  {"id": 1006, "type": "multiple", "question": "以下关于锚杆支护的基坑开挖施工说法正确的是 （　　） 。", "options": ["基坑开挖应与锚杆施工分层交替进行，并应缩短无支护暴露时间", "锚杆承载力、龄期达到设计要求后方可进行下一层土方开挖", "面积较大的基坑宜采用盆式开挖方式，盆边留土平台宽度不宜小于8m", "土方开挖至坑底后应及时浇筑垫层，暴露长度不宜大于25m", "预应力锚杆达到强度后即进行下一层土方开挖，并应对预应力进行监测"], "answer": [0, 1], "explanation": "8.2.4 采用锚杆支护的基坑开挖施工应符合下列规定：\n1 面层或排桩、微型桩、截水帷幕的强度和龄期应达到设计要求后方可进行土方开挖。\n2 基坑开挖应与锚杆施工分层交替进行，并应缩短无支护暴露时间。\n3 锚杆承载力、龄期达到设计要求后方可进行下一层土方开挖。\n4 预应力锚杆应经试验检测合格后方可进行下一层土方开挖，并应对预应力进行监测。"},
  {"id": 1007, "type": "multiple", "question": "基坑监测方案应包括以下内容 （　　） 。", "options": ["工程概况", "监测依据、项目、测点布置和监测方法", "监测元件和仪器", "监测频率和报警值", "资料整理方法及监测成果形成"], "answer": [0, 1, 2, 3], "explanation": "【依据】《建筑基坑支护技术规程》JGJ 120-2012 / 《建筑基坑工程监测技术标准》GB 50497-2019\n【解析】正确答案是A、B、C、D、E。题干对应的是基坑工程安全与监测。 A项“工程概况”正确，它与题干所述“基坑监测方案应包括以下内容”相对应。 B项“监测依据、项目、测点布置和监测方法”正确，它与题干所述“基坑监测方案应包括以下内容”相对应。 C项“监测元件和仪器”正确，它与题干所述“基坑监测方案应包括以下内容”相对应。 D项“监测频率和报警值”正确，它与题干所述“基坑监测方案应包括以下内容”相对应。 E项“资料整理方法及监测成果形成”正确，它与题干所述“基坑监测方案应包括以下内容”相对应。"},
  {"id": 1008, "type": "multiple", "question": "在支护结构施工、基坑开挖期间以及支护结构使用期内，应对支护结构和周边环境的状况随时进行巡查，现场巡查应检查内容包括 （　　） 等。", "options": ["基坑外地面和道路开裂、沉陷", "基坑周边水管漏水、破裂，燃气管漏气", "基坑排水是否通畅", "支撑构件变形，开裂", "道路监测点测量精度"], "answer": [0, 1, 2, 3], "explanation": "支护结构或基坑周边环境出现报警情况或其他险情时，应立即停止开挖，并应根据危险产生的原因和可能进一步发展的破坏形式，采取控制或加固措施。危险消除后，方可继续开挖。必要时，应对危险部位采取基坑回填、地面卸土、临时支撑等应急措施。当危险由地下水管道渗漏、坑体渗水造成时，应及时采取截断渗漏水源、疏排渗水等措施。（JGJ120：8.1.7）\n（报警情况包括：\n1基坑外地面和道路开裂、沉陷；\n2基坑周边建(构)筑物、围墙开裂、倾斜；\n3基坑周边水管漏水、破裂，燃气管漏气；\n4挡土构件表面开裂；\n5锚杆锚头松动，锚具夹片滑动，腰梁及支座变形，连接破损等；\n6支撑构件变形、开裂；\n7土钉墙土钉滑脱，土钉墙面层开裂和错动；\n8基坑侧壁和截水帷幕渗水、漏水、流砂等；\n9降水井抽水异常，基坑排水不通畅。）（JGJ120：8.1.7）"},
  {"id": 1009, "type": "multiple", "question": "建筑倾斜观测，当被测建筑具有明显的外部特征点和宽敞的观测场地时，宜选用 （　　） 。", "options": ["前方交汇法", "极坐标法", "视准线法", "小角度法", "投点法"], "answer": [0, 4], "explanation": "当被测建筑物具有明显的外部特征点和宽敞的观测场地时，宜选用投点法、测水平角法或前方交会法。"},
  {"id": 1010, "type": "multiple", "question": "基坑进行孔隙水压力监测时，下列选项中，说法正确的是 （　　） 。", "options": ["孔隙水压力计的主要类型为钢弦式和应变式孔隙水压力计", "孔隙水压力计的量程应满足被测压力范围的要求，可取静水压力与超孔隙水压力之和的2倍", "孔隙水压力计应事前埋设，埋设前应浸泡饱和，排除透水石中的气泡", "采用钻孔法埋设孔隙水压力计时钻孔直径不应大于110mm", "宜使用泥浆护壁成孔"], "answer": [0, 1, 2], "explanation": "采用钻孔法埋设孔隙水压力计时，钻孔直径宜为110mm～130mm，不宜使用泥浆护壁成孔，钻孔应圆直、干净；封口材料宜采用直径10mm～20mm的干燥膨润土球。"},
  {"id": 1011, "type": "multiple", "question": "基坑工程监测必须确定监测报警值，监测报警值应满足 （　　） 要求。", "options": ["基坑工程设计", "地下结构设计", "上部结构设计", "施工组织设计", "周边环境中被保护对象的控制"], "answer": [0, 1, 4], "explanation": "“基坑工程监测必须确定监测报警值,监测报警值应满足基坑工程设计、地下结构设计以及周边环境中被保护对象的控制要求”。"},
  {"id": 1012, "type": "multiple", "question": "基坑环境保护等级分为 （　　） 。", "options": ["一级", "二级", "三级", "四级", "五级"], "answer": [0, 1, 2], "explanation": "【依据】《建筑基坑支护技术规程》JGJ 120-2012 / 《建筑基坑工程监测技术标准》GB 50497-2019\n【解析】正确答案是A、B、C。题干对应的是基坑工程安全与监测。 A项“一级”正确，它与题干所述“基坑环境保护等级分为”相对应。 B项“二级”正确，它与题干所述“基坑环境保护等级分为”相对应。 C项“三级”正确，它与题干所述“基坑环境保护等级分为”相对应。 D项“四级”错误，它不符合题干限定的对象、程序或条件。 E项“五级”错误，它不符合题干限定的对象、程序或条件。"},
  {"id": 1013, "type": "multiple", "question": "地下管线对附加变形的承受能力应考虑管线的材料、管节长度、接头构造、新旧状况、埋深、内压等因素，并宜与管线管理单位协商综合确定管线的 （　　） 。", "options": ["强度", "容许变形量", "监控实施方案", "材料", "铺设方案"], "answer": [1, 2], "explanation": "地下管线对附加变形的承受能力应考虑管线的材料、管节长度、接头构造、新旧状况、埋深、内压等因素，并宜与管线管理单位协商综合确定管线容许变形量及监控实施方案。"},
  {"id": 1014, "type": "multiple", "question": "灌注排桩施工可选用在搅拌桩中套打、提高泥浆比重、采用优质泥浆护壁等措施提高灌注桩 （　　） 。", "options": ["桩身强度", "桩侧摩阻力", "成孔质量", "承载力", "控制孔壁坍塌"], "answer": [2, 4], "explanation": "灌注排桩施工可选用在搅拌桩中套打、提高泥浆比重、采用优质泥浆护壁等措施提高灌注桩成孔质量以及控制孔壁坍塌。"},
  {"id": 1015, "type": "multiple", "question": "模板按照结构类型不同，可分为 （　　） 等。", "options": ["基础模板", "柱模板", "墙模板", "梁模板", "楼板模板"], "answer": [0, 1, 2, 3, 4], "explanation": "模板按照结构类型不同，可分为基础模板、柱模板、墙模板、梁和楼板模板等。"},
  {"id": 1016, "type": "multiple", "question": "模板应具有足够的 （　　） ，应能可靠承受新浇混凝土的自重和侧压力以及施工过程中所产生的荷载。", "options": ["承载能力", "硬度", "刚度", "整体性", "稳定性"], "answer": [0, 2, 4], "explanation": "模板应具有足够的承载力、刚度和稳定性，应能可靠承受新浇混凝土的自重和侧压力以及施工过程中所产生的荷载。"},
  {"id": 1017, "type": "multiple", "question": "安装上层模板时，当层间高度大于5m时，应选用 （　　） 。", "options": ["木立柱支模", "桁架支模", "竹立柱支模", "钢管立柱支模", "钢木组合立柱支模"], "answer": [1, 3], "explanation": "当层间高度大于5m时，应选用桁(heng)架支模或钢管立柱支模。"},
  {"id": 1018, "type": "multiple", "question": "关于爬模作业，下列说法正确的是 （　　） 。", "options": ["爬升时，作业人员应站在爬升件上，防止模板爬升过程中晃动与扭转", "爬升前，应检查确认各个爬升模板单元已彻底分开", "爬架底部亦应满铺脚手板和设置安全网。", "支架爬升时的附墙架穿墙螺栓受力处的新浇混凝土强度应达到10N/m㎡", "每单元爬升完毕应及时固定"], "answer": [1, 2, 3, 4], "explanation": "爬升时，应先收紧千斤钢丝绳，吊住大模板或支架，然后拆卸穿墙螺栓，并检查再无任何连接，卡环和安全钩无问题，调整好大模板或支架的重心，保持垂直，开始爬升。爬升时，作业人员应站在固定件上，不得站在爬升件上爬升，爬升过程中应防止晃动与扭转。"},
  {"id": 1019, "type": "multiple", "question": "设计无规定时，模板拆除顺序，下列说法正确的是 （　　） 。", "options": ["先支的后拆、后支的先拆", "先拆非承重模板、后拆承重模板", "后支的后拆、先支的先拆", "从上而下进行", "先拆承重模板、后拆非承重模板"], "answer": [0, 1, 3], "explanation": "模板拆除时，拆模的顺序和方法应按模板的设计规定进行。当设计无规定时，可采取先支的后拆、后支的先拆，先拆非承重模板、后拆承重模板的顺序，并应从上而下进行拆除。"},
  {"id": 1020, "type": "multiple", "question": "脚手架按支固方式可分为 （　　） 。", "options": ["落地式脚手架", "悬挑脚手架", "爬架", "附墙悬挂脚手架", "悬吊脚手架"], "answer": [0, 1, 2, 3, 4], "explanation": "按照支固方式对脚手架进行分类的话，可以分为落地式脚手架、悬挑脚手架、悬挂脚手架、悬吊脚手架和附着升降脚手架。\n①落地式脚手架是一种搭设在地面、露面、屋面或者是其他平台结构之上的脚手架。\n②悬挑脚手架，也可称之为挑脚手架，它是采用悬挑的方式来支固脚手架，比如架设于专用的悬挑梁、专用的悬挑三角桁架上和架设于由支撑杆件组合的支挑结构上三种。\n③悬挂脚手架，也可称为挂脚手架，是一种附墙而搭，在上部和中部挂设于墙体挑挂件上的定型脚手架。\n④悬吊脚手架，也可称之为吊脚手架，是一种悬吊于悬挑梁或工程结构之下的脚手架。\n⑤附着升降脚手架，简称为“爬架”，也可称之为“整体提升脚手架”，其附着于工程结构、依靠自身提升设备实现升降的悬空脚手架，其中实现整体提升的脚手架。"},
  {"id": 1021, "type": "multiple", "question": "脚手架在使用过程中，应定期进行检查， （　　） 应无缺失、无松动，架体应无明显变形。", "options": ["警戒标志", "主要受力杆件", "剪刀撑等加固杆件", "外墙板", "连墙件"], "answer": [1, 2, 4], "explanation": "脚手架在使用过程中，应定期进行检查，检查项目应符合下列规定：\n（1）主要受力杆件、剪刀撑等加固杆件、连墙件应无缺失、无松动，架体应无明显变形；\n（2）场地应无积水，立杆底端应无松动、无悬空；\n（3）安全防护设施应齐全、有效，应无损坏缺失；\n（4）附着式升降脚手架支座应牢固，防倾、防坠装置应处于良好工作状态，架体升降应正常平稳；\n（5）悬挑脚手架的悬挑支承结构应固定牢固。"},
  {"id": 1022, "type": "multiple", "question": "搭拆脚手架时，操作人员必须戴 （　　） 。", "options": ["安全帽", "系安全带", "穿防滑鞋", "穿防手套", "防护服"], "answer": [0, 1, 2], "explanation": "搭拆脚手架时，操作人员必须戴安全帽、系安全带，穿防滑鞋。"},
  {"id": 1023, "type": "multiple", "question": "扣件式脚手架中扣件基本形式有 （　　） 。", "options": ["直角扣件", "对接扣件", "旋转扣件", "转角扣件", "回转扣件"], "answer": [0, 1, 2], "explanation": "扣件式钢管脚手架的扣件的基本形式有：\n1、旋转扣件：是指旋转扣件安装在脚手架架管上的中心位置，主节点是指脚手架管件横杆与竖杆的连接点。\n2、直角扣件：符合按规定程序批准的图样进行生产。扣件的材料应符合GB9440中KTH330-08牌号规定的力学性能。\n3、对接扣件：是用于两根钢管对接接长的连接。对接扣件一般用编织袋包装，每包25个，国标对接扣件重量应为1.1kg/个。"},
  {"id": 1024, "type": "multiple", "question": "脚手架斜道的构造应符合下列规定 （　　） 。", "options": ["斜道宜附着外脚手架设置", "拐弯处应设置平台", "平台宽度不应小于斜道宽度", "人行斜道宽度不宜小于1m，坡度宜采用1：3", "斜道两侧及平台外围均应设置栏杆及挡脚板"], "answer": [0, 1, 2, 3, 4], "explanation": "6.7.2斜道的构造应符合下列规定：\n（1）斜道宜附着外脚手架或建筑物设置。\n（2）运料斜道宽度不宜小于1.5米，坡度宜采用1：6，人行斜道宽度不宜小于1米，坡度宜采用1：3。\n（3）拐弯处应设置平台，其宽度不应小于斜道宽度。\n（4）斜道两侧及平台外围均应设置栏杆及挡脚板。栏杆高度应为1.2米，挡脚板高度不应小于180毫米。\n（5）运料斜道两侧、平台外围和端部均应按本规范第6.4.1～6.4.6条的规定设置连墙件。每两步应加设水平斜杆。应按本规范第6.6.2和6.6.3条的规定设置剪刀撑和横向斜撑。"},
  {"id": 1025, "type": "multiple", "question": "每搭完一步扣件式钢管脚手架后，应按规范规定校正 （　　） 。", "options": ["步距", "纵距", "横距", "立杆的垂直度", "脚手板的水平度"], "answer": [0, 1, 2, 3], "explanation": "每搭完一步脚手架后,应按规定校正步距、纵距、横距及立杆的垂直度。"},
  {"id": 1026, "type": "multiple", "question": "承插型盘扣式钢管支架由 （　　） 等构配件构成。", "options": ["立杆", "水平杆", "斜杆", "可调托座", "可调底座"], "answer": [0, 1, 2, 3, 4], "explanation": "承插型盘扣式钢管支架由立杆、水平杆、斜杆、可调底座及可调托座等配件构成。"},
  {"id": 1027, "type": "multiple", "question": "承插型盘扣式支架，当搭设高度不超过8m的满堂模板支架时，竖向斜杆应 （　　） 。", "options": ["满布设置", "架体整体底层以及顶层设置", "支架架体四周外立面向内的第一跨每层设置", "支架架体四周外立面向外的第一跨每层设置", "在架体内部区域每隔5跨由底至顶纵、横向设置"], "answer": [1, 2, 4], "explanation": "当搭设高度不超过8m的满堂模板支架时，支架架体四周外立面向内的第一跨每层均应设置竖向斜杆，架体整体底层以及顶层均应设置竖向斜杆，并应在架体内部区域每隔5跨由底至顶纵、横向均设置竖向斜杆（图2-1）或采用扣件钢管搭设的大剪刀撑（图2-2）。当满堂模板支架的架体高度不超过4节段立杆时，可不设置顶层水平斜杆；当架体高度超过4节段立杆时，应设置顶层水平斜杆或扣件钢管水平剪刀撑。"},
  {"id": 1028, "type": "multiple", "question": "脚手架在通行机动车的洞口，必须设置 （　　） 。", "options": ["安全警示", "安民告示", "门卫", "机动车检测设备", "防撞设施"], "answer": [0, 4], "explanation": "通行机动车的洞口,必须设置安全警示和防撞设施。"},
  {"id": 1029, "type": "multiple", "question": "每搭完一步支模架后，应及时校正 （　　） 。", "options": ["水平杆步距", "立杆的纵距", "立杆的横距", "立杆的垂直偏差", "水平杆的水平偏差"], "answer": [0, 1, 2, 3, 4], "explanation": "【依据】《建筑施工模板安全技术规范》JGJ 162-2008\n【解析】正确答案是A、B、C、D。题干对应的是模板工程与支撑体系安全。 A项“水平杆步距”正确，它与题干所述“每搭完一步支模架后，应及时校正”相对应。 B项“立杆的纵距”正确，它与题干所述“每搭完一步支模架后，应及时校正”相对应。 C项“立杆的横距”正确，它与题干所述“每搭完一步支模架后，应及时校正”相对应。 D项“立杆的垂直偏差”正确，它与题干所述“每搭完一步支模架后，应及时校正”相对应。 E项“水平杆的水平偏差”错误，它不符合题干限定的对象、程序或条件。"},
  {"id": 1030, "type": "multiple", "question": "承插型轮扣式模板支架，当同时满足 （　　） 条件时，可采用无剪刀撑框架式支撑结构。", "options": ["木垫板厚度大于50mm", "模板支架支撑高度(H)不大于3m", "楼板厚度(D) 不大于200mm", "梁截面面积(SL)不大于0.2㎡", "立杆的垂直偏差不大于50mm"], "answer": [1, 2, 3], "explanation": "模板支架支撑高度(H)不大于3m且楼板厚度(D)不大于200mm且梁截面面积(S L)不大于0.2m2时,可采用无剪刀撑框架式支撑结构;"},
  {"id": 1031, "type": "multiple", "question": "搭设门式脚手架，当 （　　） 等配件与门架相连时，应有防止退出松脱的构造。", "options": ["交叉支撑", "锁臂", "立杆加强杆", "连接棒", "脚手板"], "answer": [0, 1, 3], "explanation": "交叉支撑、锁臂、连接棒等配件与门架相连时,应有防止退出松脱的构造, 当连接棒与锁臂一起应用时,连接棒可不受此限。"},
  {"id": 1032, "type": "multiple", "question": "门式作业脚手架应在门架的横杆上扣挂水平架，水平架设置应在作业脚手架的 （　　） 设置。", "options": ["底层", "顶层", "连墙件设置层", "脚手架转角处", "洞口处顶部"], "answer": [1, 2], "explanation": "水平架设置应符合以下规定: 在脚手架的顶层门架上部、连墙件设置层、防护棚设置处必须设置。"},
  {"id": 1033, "type": "multiple", "question": "在建(构)筑物的转角处，门式作业脚手架内外两侧立杆上应按步设置 （　　） ，应将转角处的两榀门架连成一体。", "options": ["水平架", "水平连接杆", "水平斜撑杆", "连墙件", "水平加固杆"], "answer": [1, 2], "explanation": "在建筑物的转角处,门式脚手架内、外两侧立杆上应按步设置水平连接杆、斜撑杆,将转角处的两榀门架连成一体。"},
  {"id": 1034, "type": "multiple", "question": "悬挑脚手架搭设前应检查 （　　） 。", "options": ["连墙件", "锚固件", "预埋件", "支撑型钢悬挑梁的混凝土强度", "型钢悬挑梁强度"], "answer": [2, 3], "explanation": "悬挑脚手架搭设前应检查预埋件和支承型钢悬挑梁的混凝土强度。"},
  {"id": 1035, "type": "multiple", "question": "碗扣式钢管脚手架的碗扣节点处除立杆和横杆外，还应有 （　　） 。", "options": ["上碗扣", "下碗扣", "限位销", "横杆接头", "立杆接头"], "answer": [0, 1, 2, 3], "explanation": "碗扣式脚手架碗扣式脚手架由上下碗扣,横杆接头、上碗口的限位销等组成。"},
  {"id": 1036, "type": "multiple", "question": "当碗扣式钢管模板支撑架同时满足下列条件时，可不设置竖向及水平向的斜撑杆和剪刀撑 （　　） 。", "options": ["被支撑结构自重面荷载标准值不大于8kN/㎡", "搭设高度小于5m，架体高宽比小于1.5", "被支撑结构自重线荷载标准值不大于8kN/m", "架体按要求与既有建筑结构进行了可靠连接", "场地满足承载力要求"], "answer": [1, 2, 3, 4], "explanation": "当模板支撑同时满足下列条件时，可不设置竖向及水平向的斜撑杆和剪刀撑：\n（1）搭设高度小于5m，架体高宽比小于1.5；\n（2）被支撑结构自重面荷载标准值不大于5kN/m2，线荷载标准值不大于8kN/m；\n（3）架体按规范要求与既有建筑结构进行了可靠边连接；\n（4）场地地基坚实、均匀，满足承载力要求。"},
  {"id": 1037, "type": "multiple", "question": "竖向主框架与水平支承结构采用铰接点连接时，各杆件轴线应交汇于一点，可采用 （　　） 的形式。", "options": ["侧面连接", "上下连接", "焊接", "扣件连接", "穿套式连接"], "answer": [0, 1, 4], "explanation": "【依据】《建筑施工扣件式钢管脚手架安全技术规范》JGJ 130-2011\n【解析】正确答案是C、D。题干对应的是扣件式钢管脚手架安全技术。 A项“侧面连接”错误，它不符合题干限定的对象、程序或条件。 B项“上下连接”错误，它不符合题干限定的对象、程序或条件。 C项“焊接”正确，它与题干所述“竖向主框架与水平支承结构采用铰接点连接时，各”相对应。 D项“扣件连接”正确，它与题干所述“竖向主框架与水平支承结构采用铰接点连接时，各”相对应。 E项“穿套式连接”错误，它不符合题干限定的对象、程序或条件。"},
  {"id": 1038, "type": "multiple", "question": "当水平支承结构不能连续设置时，局部可采用脚手架杆件进行连接，但其长度不得大于2.0m，且应采取加强措施，确保其 （　　） 不低于原有的结构。", "options": ["强度", "刚度", "水平位移", "变形", "挠度"], "answer": [0, 1], "explanation": "当水平支承不能连续设置时，局部可采用脚手架杆件进行连接，但其长度不得大于2.0m，且必须采取加强措施，其强度和刚度不得低于原有的水平支承。"},
  {"id": 1039, "type": "multiple", "question": "附着式升降脚手架同步控制装置，总控制箱应有急停，单机手动和多机手动控制功能；应能实时显示和记录各机位的 （　　） ，并应能自动下达指令。", "options": ["编号", "荷载值", "最大量程", "故障信息", "运行状态"], "answer": [1, 3, 4], "explanation": "总控箱应有急停、单机手动和多机手动控制功能；应能实时显示和记录各机位的荷载值、故障信息和运行状态，并能自动下达指令。"},
  {"id": 1040, "type": "multiple", "question": "超高层钢结构工程安全要点中，须对当天作业内容、部位、顺序等进行交代，包括 （　　） 。", "options": ["作业面层数", "塔吊位置", "土建施工部位", "施工面积", "核心筒及外框施工高度"], "answer": [0, 1, 2, 4], "explanation": "超高层钢结构工程安全要点中，对当天作业内容、部位、顺序等进行交代，包括作业面层数、塔吊位置、土建施工部位、核心筒及外框施工高度等。"},
  {"id": 1041, "type": "multiple", "question": "大跨度及厂房钢结构工程安全要点中，对当天作业存在的 （　　） 进行交代。", "options": ["危险源", "危险点", "框架桁架的动火点监控", "土建施工路线对吊车的影响", "下方行人路线的注意避让"], "answer": [0, 1, 2, 3, 4], "explanation": "大跨度及厂房钢结构工程的安全要点包括对当天作业存在的危险源和危险点进行交代；对框架桁架的动火点进行监控；考虑土建施工路线对吊车的影响；以及注意下方行人路线的避让。"},
  {"id": 1042, "type": "multiple", "question": "市政类钢结构工程安全要点中，对当天作业内容、部位、顺序等进行交代，包括 （　　） 。", "options": ["作业面平面区域的施工内容", "本方施工区域临边防护", "汽车吊及履带吊的位置及可能涉及的影响", "施工当天天气情况", "钢箱梁的施工高度"], "answer": [0, 2, 4], "explanation": "【依据】《建筑施工高处作业安全技术规范》JGJ 80-2016\n【解析】正确答案是A、B、C。题干对应的是建筑施工高处作业防护。 A项“作业面平面区域的施工内容”正确，它与题干所述“市政类钢结构工程安全要点中，对当天作业内容、”相对应。 B项“本方施工区域临边防护”正确，它与题干所述“市政类钢结构工程安全要点中，对当天作业内容、”相对应。 C项“汽车吊及履带吊的位置及可能涉及的影响”正确，它与题干所述“市政类钢结构工程安全要点中，对当天作业内容、”相对应。 D项“施工当天天气情况”错误，它不符合题干限定的对象、程序或条件。 E项“钢箱梁的施工高度”错误，它不符合题干限定的对象、程序或条件。"},
  {"id": 1043, "type": "multiple", "question": "钢结构工程的安全生产技术要点中对下列 （　　） 类型的工程，对当天作业的危险源、危险点进行交代。", "options": ["超高层", "大跨度及厂房", "电梯井", "幕墙", "劲性结构"], "answer": [0, 1, 2, 3, 4], "explanation": "在钢结构工程的安全生产技术要点中，对当天作业的危险源、危险点进行交代的工程类型通常包括以下几种：\nA. 超高层：超高层建筑由于高度原因，存在较高的高空坠落风险、风荷载影响等危险源，需要特别关注。\nB. 大跨度及厂房：大跨度结构和厂房在安装和施工过程中，涉及到大型构件的吊装、拼装等作业，危险点较多。\nC. 电梯井：电梯井施工涉及到垂直空间的高空作业和狭小空间作业，有坠落和物体打击等危险。\nD. 幕墙：幕墙施工同样涉及高空作业，同时还需要关注玻璃或其他幕墙材料的安装安全。\nE. 劲性结构：劲性结构通常用于高层或超高层建筑中，施工过程复杂，存在较多危险源和危险点。\n因此，答案是：A、B、C、D、E。"},
  {"id": 1044, "type": "multiple", "question": "钢结构施工的平面安全通道两侧应设置 （　　） 。", "options": ["安全标志", "安全护栏", "防护钢丝绳", "安全带", "爬梯"], "answer": [1, 2], "explanation": "钢结构施工的平面安全通道宽度不宜小于600mm，且两侧应设置安全护栏或防护钢丝绳。"},
  {"id": 1045, "type": "multiple", "question": "钢结构安装施工中，边长或直径为 （　　） cm的洞口应架设钢管脚手架、满铺脚手板等。", "options": ["40", "50", "60", "150", "160"], "answer": [0, 1, 2, 3], "explanation": "边长或直径为40cm~150cm的洞口应架设钢管脚手架、满铺脚手板等"},
  {"id": 1046, "type": "multiple", "question": "吊装物吊离地面 （　　） - （　　） mm时，应进行全面检查，并应确认无误后再正式起吊。", "options": ["150", "200", "300", "350", "400"], "answer": [1, 2], "explanation": "吊装物吊离地面200mm～300mm时,应进行全面检查,并应确认无误后再正式起吊。"},
  {"id": 1047, "type": "multiple", "question": "钢结构安装施工， （　　） 作业时，应清除作业区危险品易燃物，并应采取防火措施。", "options": ["机械切割", "气体切割", "高空焊接", "高空铆接", "高空拼装"], "answer": [1, 2], "explanation": "气体切割和高空焊接作业时,应清除作业区危险易燃物,并应采取防火措施。"},
  {"id": 1048, "type": "multiple", "question": "吊装工作区应有明显标志，并 （　　） 。", "options": ["设专人警戒", "非吊装现场作业人员严禁入内", "起重机工作时起重臂下严禁站人", "避免人员在吊车起重臂回转半径内停留", "设专人指挥"], "answer": [0, 1, 2, 3], "explanation": "吊装工作区应有明显标志,并设专人警戒,非吊装现场作业 人员严禁入内,起重机工作时,起重臂下严禁站人,同时避免人员在 吊车起重臂回转半径内停留。"},
  {"id": 1049, "type": "multiple", "question": "钢结构安装工程施工，以下属于防止高空坠物伤人的措施有 （　　） 。", "options": ["高空作业人员所携带各种工具、螺栓等应在专用工具袋中放好", "吊装时可以在构件上堆放或是悬挂零星物件，零星物品应用专用袋子上、下传递", "吊装高空对接构件时需绑好溜绳，控制其方向", "起吊构件时，速度不能太快，不能在高空停留太久，严禁猛升、降，以防构件脱落", "吊开时应平稳，避免振动或摆动，在构件就拉或固定前，不得解开吊装索具，以防构件坠落伤人"], "answer": [0, 2, 3, 4], "explanation": "吊装时不得在构件上堆放或是悬挂零星物件，零星物品应装在专用袋子上、下传递。"},
  {"id": 1050, "type": "multiple", "question": "钢结构安装工程施工时，现场用电要有专门人员负责 （　　） 严禁非电工人员随意拆改。", "options": ["安装", "管理", "维护", "看守", "举报"], "answer": [0, 1, 2], "explanation": "现场用电要有专门人员负责安装、维护、管理、严禁非电工人员随意拆改。"},
  {"id": 1051, "type": "multiple", "question": "钢结构安装工程施工时，以下 （　　） 措施属于防止触电事故。", "options": ["构件吊装时，应防止碰撞，临时拉线以防触电", "经常检查各种电线，有问题及时处理", "现场各种电线插头、开关均设在开关箱内，停电后必须拉下电闸", "不要站在潮湿的地方使用电动工具或设备", "对于现场用手持电动工具，必须有漏电保护器"], "answer": [0, 1, 2, 3, 4], "explanation": "防止触电事故\n（1）现场用电要有专门人员负责安装、维护、管理、严禁非电工人随意拆除。\n（2）不要站在潮湿的地方使用电动工具或设备。\n（3）现场各种电线插头、开关均设在开关箱内,停电后必须拉下电闸.\n（4)各种用电设备必须有良好的接地、接零,对于现场用手持电动工具,必须有漏电保护器，其操作者必须戴绝缘手套，穿绝缘鞋.\n（5）构件吊装时，应防止碰撞，临时拉线应防触电.\n（6）各种电线要经常检查，有问题及时处理。\n(7）现场临时电源按国家有关安全规程和公司有关规定架设，电源装漏电保护装置,用电施工机械做好接地接零。\n（8）施工用的电动机和设备均须接地，绝对不允许破损的电线和电缆，电源应设触电保护器."},
  {"id": 1052, "type": "multiple", "question": "幕墙工程施工分类按密闭形式分可分为 （　　） 幕墙。", "options": ["封闭式", "开放式", "半封闭式", "半开放式", "密封式"], "answer": [0, 1], "explanation": "按密闭形式分：封闭式和开放式"},
  {"id": 1053, "type": "multiple", "question": "现场在主体结构上安装 （　　） 的建筑幕墙称构件式幕墙。", "options": ["立柱", "横梁", "龙骨", "保温材料", "各种面板"], "answer": [0, 1, 4], "explanation": "现场在主体结构上安装立柱、横梁和各种面板的建筑幕墙称构件式幕墙。"},
  {"id": 1054, "type": "multiple", "question": "幕墙工程施工按面板材料，可分为 （　　） 幕墙。", "options": ["玻璃", "石材", "人造板材", "组合面板", "天然木材"], "answer": [0, 1, 2, 3], "explanation": "按建筑幕墙的面板材料分类可分为：\n1．玻璃幕墙\n2．金属幕墙面板为金属板材的建筑幕墙，主要包括：单层铝板幕墙、铝塑复合板墙、蜂窝铝板幕墙、不锈钢板幕墙、搪瓷板幕墙等。\n3．石材幕墙面板为建筑石材板的建筑幕墙。\n4．人造板材幕墙面板由瓷板、陶板、微晶玻璃板等。\n5．组合幕墙面板由玻璃、金属、石籍、人造板材等不同面板组成的建筑幕墙。"},
  {"id": 1055, "type": "multiple", "question": "幕墙工程项目部成立以项目经理为第一责任人的安全生产领导小组， （　　） 。", "options": ["确定安全目标", "落实安全生产责任制", "落实进度目标", "保证安全措施费提取和合理使用", "落实质量目标"], "answer": [0, 1, 3], "explanation": "项目部成立以项目经理为第一责任人的安全生产领导小组,确定安全目标,落实安全生产责任制,保证安全技术措施费提取和合理使用。"},
  {"id": 1056, "type": "multiple", "question": "幕墙工程施工作业准备阶段，应建立由 （　　） 等参与组成的项目管理小组，领导和组织施工质量、生产、进度的管理。", "options": ["项目经理", "技术负责人", "质检员", "安全员", "施工员"], "answer": [0, 1, 2, 3, 4], "explanation": "幕墙工程施工作业准备阶段，应建立由项目经理和技术负责人、质检员、安全员、施工员等参与组成的项目管理小组，领导和组织施工质量、生产、进度的管理。"},
  {"id": 1057, "type": "multiple", "question": "幕墙工程施工作业准备阶段，项目经理应组织项目部管理人员制订施工必需的技术文件和管理文件，用于指导施工全过程的设计、 （　　） 、安全和环境管理。", "options": ["采购", "加工制作", "施工安装", "服务", "质量控制"], "answer": [0, 1, 2, 3, 4], "explanation": "幕墙工程施工作业准备阶段，项目经理应组织项目部管理人员制订施工必需的技术文件和管理文件，用于指导施工全过程的设计、采购、加工制作、施工安装、服务、质量控制、安全和环境管理。"},
  {"id": 1058, "type": "multiple", "question": "幕墙工程施工技术负责人在施工前应向施工人员做好技术交底工作，交代清楚 （　　） 。", "options": ["预埋固定支座", "铝合金骨架体系的划分尺寸及形式", "玻璃与骨架间的连接的方法及连接要求", "预埋件固定支座", "龙骨位置"], "answer": [0, 1, 2], "explanation": "施工技术负责人在施工前应向施工人员做好技术交底工作，交待清楚预埋固定支座、铝合金骨架体系的划分尺寸及形式，玻璃与骨架间的连接的方法及连接要求等。"},
  {"id": 1059, "type": "multiple", "question": "玻璃幕墙工程主要机具包括电锤、电钻、 （　　） 等。", "options": ["电焊机", "铝合金切割机", "无齿锯", "经纬仪", "水平仪"], "answer": [0, 1, 2, 3], "explanation": "玻璃幕墙工程主要机具(工具):\n3.1.1主要机具：电锤、电钻、电焊机、铝合金切割机、无齿锯和经纬仪等。"},
  {"id": 1060, "type": "multiple", "question": "石材幕墙施工，将运至工地的石材饰面板按编号分类， （　　） ,按施工要求分层次将石材饰面板运至施工面附件，并注意摆放可靠。", "options": ["检查尺寸有无准确", "有无破损", "有无缺楞", "有无掉角", "有无色差"], "answer": [0, 1, 2, 3], "explanation": "石材幕墙施工，将运至工地的石材饰面板按编号分类，检查尺寸有无准确和有无破损、缺楞、掉角，按施工要求分层次将石材饰面板运至施工面附件，并注意摆放可靠。"},
  {"id": 1061, "type": "multiple", "question": "金属幕墙施工工艺流程测量放线 （　　） 嵌缝打胶、清洗保洁。", "options": ["锚固件制作、安装", "竖杆制作安装", "横杆制作安装", "骨架制作安装", "面板安装"], "answer": [0, 3, 4], "explanation": "金属幕墙的工艺流程：\n测量放线→锚固件制作、安装→骨架制作安装→面板安装→嵌缝打胶→清洗保洁。"},
  {"id": 1062, "type": "multiple", "question": "金属幕墙锚固件安装，角码位置确定后，将角码按此位置焊到埋板上，焊缝 （　　） 要符合设计要求。", "options": ["厚度", "宽度", "长度", "强度", "饱满度"], "answer": [1, 2], "explanation": "角码位置确定后,将角码按此位置焊到埋板上,焊缝宽度和长度要符合设计要求,焊完后焊口要重新做防锈处理,一般涂刷防锈漆两遍。"},
  {"id": 1063, "type": "multiple", "question": "对于玻璃幕墙专项要求，中空玻璃气体层厚度不应小于9mm，宜采双单道密封，其中明框玻璃幕墙的中空玻璃可采用 （　　） 。", "options": ["玻璃胶", "丁基密封胶", "聚硫密封胶", "硅酮结构胶", "耐候胶"], "answer": [2, 3], "explanation": "明框玻璃幕墙用中空玻璃的二道密封宜采用聚硫类中空玻璃密封胶，也可采用硅酮密封胶。"},
  {"id": 1064, "type": "multiple", "question": "幕墙选用的石材的放射性应符合现行国家标准《建筑材料放射性核素限量》GB6566中 （　　） 的要求。", "options": ["A级", "B级", "C级", "D级", "E级"], "answer": [0, 1], "explanation": "用于幕墙的石材,其放射性应符合《建筑材料放射性核素限量》GB6566中A级、B级石材的要求。"},
  {"id": 1065, "type": "multiple", "question": "人造板材幕墙专项要求，以下 （　　） 面板与幕墙构件的连接可以采用通长挂件连接。", "options": ["瓷板", "微晶玻璃板", "陶板", "纤维水泥板", "石材蜂窝板"], "answer": [0, 1, 2, 3], "explanation": "人造板材幕墙面板的连接方式：\n（1）瓷板、微晶玻璃板宜采用短挂件连接、通长挂件连接和背栓连接；\n（2）陶板宜采用短挂件连接，也可采用通长挂件连接；\n（3）纤维水泥板宜采用穿透支承连接或背栓支承连接，也可采用通长挂件连接；\n（4）石材蜂窝板宜通过板材背面预置螺母连接；\n（5）木纤维板宜采用末端形式为刮削式（SC）的螺钉连接或背栓连接，也可采用穿透连接。"},
  {"id": 1066, "type": "multiple", "question": "拆除工程施工的安全生产目标，以下说法正确的有 （　　） 。", "options": ["确保拆除过程无重大人身伤亡事故发生", "无重大交通责任事故发生", "无火灾事故发生", "职工重伤率0.03%以下以及轻伤率3%以下", "保证拆除工程中的人民生命和财产安全"], "answer": [0, 1, 2, 3, 4], "explanation": "【依据】《建筑拆除工程安全技术规范》JGJ 147-2016\n【解析】正确答案是A、B、C、E。题干对应的是拆除工程施工安全。 A项“确保拆除过程无重大人身伤亡事故发生”正确，它与题干所述“拆除工程施工的安全生产目标，以下说法正确的有”相对应。 B项“无重大交通责任事故发生”正确，它与题干所述“拆除工程施工的安全生产目标，以下说法正确的有”相对应。 C项“无火灾事故发生”正确，它与题干所述“拆除工程施工的安全生产目标，以下说法正确的有”相对应。 D项“职工重伤率0.03%以下以及轻伤率3%以下”错误，它不符合题干限定的对象、程序或条件。 E项“保证拆除工程中的人民生命和财产安全”正确，它与题干所述“拆除工程施工的安全生产目标，以下说法正确的有”相对应。"},
  {"id": 1067, "type": "multiple", "question": "拆除工程施工前应对使用的 （　　） 进行进场验收和检查，合格后方可作业。", "options": ["机械设备", "建筑垃圾清运车辆", "防护用具", "消防设施", "用电设施"], "answer": [0, 2], "explanation": "拆除工程施工前,应对所使用的机械设备和防护用具进行进场验收和检查,合格后方可作业。"},
  {"id": 1068, "type": "multiple", "question": "当人工拆除建（构）筑物墙体，按规定应符合的操作有 （　　） 。", "options": ["从下至上逐层拆", "从上至下逐层拆", "不得垂直交叉作", "严禁采用底部掏掘或推倒的方法", "先行拆除的栏杆、楼梯、楼板等构件"], "answer": [1, 2, 3], "explanation": "【依据】《建筑拆除工程安全技术规范》JGJ 147-2016\n【解析】正确答案是B、C、D。题干对应的是拆除工程施工安全。 A项“从下至上逐层拆”错误，它不符合题干限定的对象、程序或条件。 B项“从上至下逐层拆”正确，它与题干所述“当人工拆除建（构）筑物墙体，按规定应符合的操”相对应。 C项“不得垂直交叉作”正确，它与题干所述“当人工拆除建（构）筑物墙体，按规定应符合的操”相对应。 D项“严禁采用底部掏掘或推倒的方法”正确，它与题干所述“当人工拆除建（构）筑物墙体，按规定应符合的操”相对应。 E项“先行拆除的栏杆、楼梯、楼板等构件”错误，它不符合题干限定的对象、程序或条件。"},
  {"id": 1069, "type": "multiple", "question": "爆破拆除是指对废弃的旧建（构）筑物进行拆除的控制爆破技术。爆破拆除要严格控制爆破可能产生的损害因素，如 （　　） 保护周围建（构）筑物和设备的安全。", "options": ["振动", "冲击波", "飞石", "粉尘", "噪声"], "answer": [0, 1, 2, 3, 4], "explanation": "在爆破工程施工中，采取相应的准备工作和保护措施将爆破作业产生的爆破飞石、爆破振动、爆破冲击波、爆破有害气体、爆破粉尘、爆破噪声等有害效应降至最低，以确保爆区周边环境和人民群众的生命财产处于安全状态。"},
  {"id": 1070, "type": "multiple", "question": "爆破器材必须向工程所在地法定部门申请《爆炸物品购买许可证》，到指定的供应点购买，爆破器材严禁 （　　） 。", "options": ["赠送", "转让", "转卖", "转借", "购买"], "answer": [0, 1, 2, 3], "explanation": "【依据】《爆炸物品购买许可证》\n【解析】正确答案是A、B、C、D。题干对应的是爆炸物品购买许可证。 A项“赠送”正确，它与题干所述“爆破器材必须向工程所在地法定部门申请《爆炸物”相对应。 B项“转让”正确，它与题干所述“爆破器材必须向工程所在地法定部门申请《爆炸物”相对应。 C项“转卖”正确，它与题干所述“爆破器材必须向工程所在地法定部门申请《爆炸物”相对应。 D项“转借”正确，它与题干所述“爆破器材必须向工程所在地法定部门申请《爆炸物”相对应。 E项“购买”错误，它不符合题干限定的对象、程序或条件。"},
  {"id": 1071, "type": "multiple", "question": "爆破后应对 （　　） 等进行检查，发现问题应及时处理。", "options": ["盲炮", "爆堆", "爆破拆除效果", "对周围环境的影响", "爆破质量"], "answer": [0, 1, 2, 3], "explanation": "爆破后应检查的内容有：\n-确认有无盲炮；\n-露天爆破爆堆是否稳定，有无危坡、危石、危墙、危房及未炸倒建（构）筑物；\n-地下爆破有无瓦斯及地下水突出、有无冒顶、危岩，支撑是否破坏，有害气体是否排除；\n-在爆破警戒区内公用设施及重点保护建（构）筑物安全情况。"},
  {"id": 1072, "type": "multiple", "question": "高处作业高度分为 （　　） 区段。", "options": ["2m至5m", "5m以上至15m", "15m以上至30m", "30米以上", "3m至6m"], "answer": [0, 1, 2, 3], "explanation": "高处作业高度分为2m至5m、5m以上至15m、15m以上至30m、30m以上4个区段。"},
  {"id": 1073, "type": "multiple", "question": "客观危险因素的高处作业的分级方法有 （　　） 。", "options": ["A类法", "B类法", "C类法", "D类法", "E类法"], "answer": [0, 1], "explanation": "【依据】《建筑施工高处作业安全技术规范》JGJ 80-2016\n【解析】正确答案是A、B。题干对应的是建筑施工高处作业防护。 A项“A类法”正确，它与题干所述“客观危险因素的高处作业的分级方法有”相对应。 B项“B类法”正确，它与题干所述“客观危险因素的高处作业的分级方法有”相对应。 C项“C类法”错误，它不符合题干限定的对象、程序或条件。 D项“D类法”错误，它不符合题干限定的对象、程序或条件。 E项“E类法”错误，它不符合题干限定的对象、程序或条件。"},
  {"id": 1074, "type": "multiple", "question": "高处作业施工前，应检查高处作业的 （　　） ，确认其完好，方可进行施工。", "options": ["安全标志", "安全设施", "工具、仪表", "防火设施", "电气设施和设备"], "answer": [0, 1, 2, 3, 4], "explanation": "高处作业施工前,应检查高处作业的安全标志、安全设施、工具、仪表、防火设施、电气设施和设备,确认其完好,方可进行施工。"},
  {"id": 1075, "type": "multiple", "question": "高处作业时，安全防护设施验收资料应包括的主要内容有 （　　） 。", "options": ["施工组织设计中的安全技术措施或专项方案", "安全防护用品用具产品合格证明", "安全防护设施验收记录", "预埋件隐蔽验收记录", "安全防护设施变更记录及签证"], "answer": [0, 1, 2, 3, 4], "explanation": "(一)安全防护设施验收资料应包括下列主要内容:\n1.施工组织设计中的安全技术措施或专项方案;\n2.安全防护用品用具产品合格证明;\n3.安全防护设施验收记录;\n4.预埋件隐蔽验收记录;\n5.安全防护设施变更记录及签证。"},
  {"id": 1076, "type": "multiple", "question": "建筑工地常称的“五临边”是指 （　　） 。", "options": ["基坑周边", "二层以上楼层周边", "分层施工的楼梯口和梯段边", "各种垂直运输接料平台边", "井架与施工用电梯和脚手架等与建（构）筑物通道的两侧边"], "answer": [0, 1, 2, 3, 4], "explanation": "“五临边”防护是指在建工程的楼面临边、屋面临边、阳台临边、升降口临边、基坑临边。"},
  {"id": 1077, "type": "multiple", "question": "施工现场及通道旁深度在2m及2m以上的 （　　） 等边沿上的作业，简称洞口作业。", "options": ["桩孔", "沟槽", "管道", "孔洞", "基坑"], "answer": [0, 1, 2, 3], "explanation": "洞口作业。孔、洞口旁边的高处作业，包括施工现场及通道旁深度在2m及2m以上的桩孔、沟槽与管道孔洞等边沿作业。"},
  {"id": 1078, "type": "multiple", "question": "当采用钢管作为防护栏杆件时，横杆及栏杆立杆应采用脚手钢管，并应采用 （　　） 等方式连接固定。", "options": ["螺栓", "扣件", "焊接", "定型套管", "销轴"], "answer": [1, 2, 3], "explanation": "当采用钢管作为防护栏杆件时，横杆及栏杆立杆应采用脚手钢管，并应采用扣件、焊接、定型套管等方式连接固定。"},
  {"id": 1079, "type": "multiple", "question": "建筑施工现场的悬空作业，一般包括 （　　） 等。", "options": ["梁柱安装", "预应力现场张拉", "屋架安装", "门窗安装作业", "设备安装"], "answer": [1, 3], "explanation": "建筑施工现场悬高作业主要分为六类： (1) 构件吊装与管道安装； (2) 模板支撑和拆卸； (3) 钢筋绑扎和安装钢骨架； (4) 混凝土浇注； (5) 预应力现场张拉； (6) 门窗安装作业。"},
  {"id": 1080, "type": "multiple", "question": "绑扎钢筋和预应力张拉时的悬空作业应符合 （　　） 规定。", "options": ["在2m以上的高处绑扎柱钢筋时，在操作平台可以不挂安全带", "绑扎立柱和墙体钢筋，不得站在钢筋骨架上或攀登骨架", "在2m以上的高处绑扎柱钢筋时，应搭设操作平台", "在高处进行预应力张拉时，应搭设有防护挡板的操作平台", "在2m以上的高处绑扎墙体钢筋时，应搭设操作平台"], "answer": [1, 2, 3], "explanation": "绑扎钢筋和预应力张拉时的悬空作业应符合下列规定：\n1.绑扎立柱和墙体钢筋，不得站在钢筋骨架上或攀登骨架；\n2.在2m以上的高处绑扎柱钢筋时，应搭设操作平台；\n3.在高处进行预应力张拉时，应搭设有防护挡板的操作平台。（JGJ80—2016）"},
  {"id": 1081, "type": "multiple", "question": "高处作业的落地式操作平台应按国家现行脚手架标准规定，计算 （　　） 等。", "options": ["受弯构件强度", "连接扣件抗滑承载力", "立杆稳定性", "连墙杆件强度与稳定性及连接强度", "立杆地基承载力"], "answer": [0, 1, 2, 3, 4], "explanation": "落地式操作平台应按相关脚手架规范的规定计算受弯构件强度、连接扣件抗滑承载力、立杆稳定性、连墙杆件强度与稳定性及连接强度、立杆地基承载力等。"},
  {"id": 1082, "type": "multiple", "question": "当建（构）筑物高度大于24m，并采用木质板搭设安全防护棚时，应 （　　） 。", "options": ["搭设单层安全防护棚", "搭设双层安全防护棚", "两层防护的间距不应小于700mm", "两层防护的间距不应小于500mm", "安全防护棚的高度不应小于4m"], "answer": [1, 2, 4], "explanation": "当建筑物高度大于24m并采用木质板搭设时，应搭设双层安全防护棚。两层防护的间距不应小于700mm，安全防护棚的高度不应小于4m。"},
  {"id": 1083, "type": "multiple", "question": "当立网用于龙门架、物料提升架及井架的封闭防护时，要求 （　　） 。", "options": ["四周边绳应与支撑架贴紧", "边绳的断裂张力不得小于3kN", "边绳的断裂张力不得小于5kN", "系绳应绑在支撑架上", "间距不得大于750mm"], "answer": [0, 1, 3, 4], "explanation": "当立网用于龙门架、物料提升架及井架的封闭防护时,四周边绳应与支撑架贴紧,边绳的断裂张力不得小于3KN,系绳应绑在支撑架上,间距不得大于750㎜。"},
  {"id": 1084, "type": "multiple", "question": "装配整体式混凝土结构工程施工的专项施工方案应包括 （　　） 。", "options": ["预制构件堆放、堆场加固、驳运及吊装", "吊装机械选型及平面布置", "高处作业、交叉作业的安全防护", "构件安装临时支撑体系", "可能发生的危害和突发事件应急预案"], "answer": [0, 1, 2, 3], "explanation": "专项施工方案应包括以下主要内容：\n（一）预制构件堆放、驳运及吊装，包括：现场装卸、堆放及驳运、吊装方式和路线；构件堆场的地基承载力计算；吊装设备选型，吊具设计；构件吊点、塔吊施工升降机附墙点等设计；\n（二）高处作业的安全防护，包括：因临边安装构件、连接节点现浇混凝土及成品保护修补所采取的防护措施以及交叉作业安全防护等；\n（三）专用操作平台、脚手架、垂直爬梯及吊篮等设施，及其附着设施；\n（四）构件安装的临时支撑体系及基础承载力等。"},
  {"id": 1085, "type": "multiple", "question": "装配式混凝土建筑预制构件吊装作业前，须进行安全交底，包括 （　　） 。", "options": ["总包对交叉作业的分包单位专项交底", "对塔吊作业人员进行交底", "对塔吊施工操作人员进行交底", "对可能发生的危害和应急预案进行交底。", "对预制构件试安装安装情况进行交底"], "answer": [0, 1, 2, 3], "explanation": "【依据】《建筑施工起重吊装工程安全技术规范》JGJ 276-2012\n【解析】正确答案是A、B、C、D。题干对应的是起重吊装作业安全。 A项“总包对交叉作业的分包单位专项交底”正确，题干对应职责主体就是总包对交叉作业的分包单位专项交底。 B项“对塔吊作业人员进行交底”正确，它与题干所述“装配式混凝土建筑预制构件吊装作业前，须进行安”相对应。 C项“对塔吊施工操作人员进行交底”正确，它与题干所述“装配式混凝土建筑预制构件吊装作业前，须进行安”相对应。 D项“对可能发生的危害和应急预案进行交底。”正确，它与题干所述“装配式混凝土建筑预制构件吊装作业前，须进行安”相对应。 E项“对预制构件试安装安装情况进行交底”错误，它不符合题干限定的对象、程序或条件。"},
  {"id": 1086, "type": "multiple", "question": "装配式混凝土建筑安装前按设计要求检查预制构件、预埋件以及配件的 （　　） 。", "options": ["型号", "规格", "数量", "名称", "隐蔽工程验收单"], "answer": [0, 1, 2], "explanation": "应核对预制构件混凝土强度及预制构件和配件的型号、规格、数量等符合设计文件要求；"},
  {"id": 1087, "type": "multiple", "question": "以下属于装配式混凝土建筑吊装作业安全措施的有 （　　） 。", "options": ["作业时封闭设置，专人监护", "临时固定措施按施工方案设置，安全可靠", "吊装按作业面配备上下指挥", "安装点的安全防护措施或安全警示标志按规范和方案要求设置", "建筑起重机械信号司索及司机、高处作业等持证上岗"], "answer": [0, 1, 2, 3, 4], "explanation": "安全措施：\n吊索具和牵引绳有允许使用的识别标志;\n作业时封闭设置,专人监护;\n临时固定措施按施工方案设置,安全可靠;\n吊装按作业面配备上下指挥;\n安装点的安全防护措施或安全警示标志按规范和方案要求设置;\n建筑起重机械信号司索及司机、高处作业等持证上岗：\n安装作业人员按规定佩带使用安全带、防坠器等劳防用品;\n生命绳和安全带固定点设置，有验收挂牌或允许使用的识别标志;"},
  {"id": 1088, "type": "multiple", "question": "装配整体式结构施工现场应设置 （　　） 。", "options": ["消防疏散通道", "专用通道", "安全通道", "消防车通道", "专用出口"], "answer": [0, 2, 3], "explanation": "装配整体式结构施工现场应设置消防疏散通道、安全通道以及消防车通道,防火防烟应分区。"},
  {"id": 1089, "type": "multiple", "question": "建筑施工现场主要使用主要使用的起重机械类型有 （　　） 。", "options": ["桥式起重机", "塔式起重机", "门式起重机", "流动式起重机", "升降机"], "answer": [0, 1, 2, 3, 4], "explanation": "建筑起重机械具体包括桥式起重机、塔式起重机、门式起重机、流动式起重机、升降机等。"},
  {"id": 1090, "type": "multiple", "question": "塔式起重机型号分类代号有 （　　） 。", "options": ["QTZ", "QTA", "QTG", "QTP", "QTQ"], "answer": [0, 2, 3, 4], "explanation": "目前中国使用的塔机型号主要有以下十大类型号：\n1、上回转式塔式起重机：QT;\n2、上回转自升式塔式起重机：QTZ;\n3、下回转式塔式起重机：QTX;\n4、下回转自升式塔式起重机：QTS;\n5、快速安装式塔式起重机：QTK;\n6、固定式塔式起重机：QTG;\n7、爬升式塔式起重机：QTP;\n8、轮胎式塔式起重机：QTL;\n9、汽车式塔式起重机：QTQ;\n10、履带式塔式起重机：QTU."},
  {"id": 1091, "type": "multiple", "question": "轨道式塔机作业前，应检查 （　　） 等内容。", "options": ["轨道基础平直无沉陷", "鱼尾板不松动", "连接螺栓不松动", "道钉不松动", "轨道上有无无障碍物"], "answer": [0, 1, 2, 3, 4], "explanation": "应检查轨道基础平直无沉陷，鱼尾板连接螺栓及道钉无松动，并应清除轨道上的障碍物，松开夹轨器并向上固定好。"},
  {"id": 1092, "type": "multiple", "question": "根据使用说明书的要去，应定期对塔机 （　　） 等部位进行检查。", "options": ["工作机构", "安全装置", "制动器", "润滑系统", "液压系统"], "answer": [0, 1, 2, 3, 4], "explanation": "根据使用说明书的要求，应定期对塔式起重机各工作机构、所有安全装置、制动器的性能及磨损情况、钢丝绳的磨损及绳端固定、液压系统、润滑系统、螺栓销轴等连接处等进行检查。"},
  {"id": 1093, "type": "multiple", "question": "塔式起重机装拆作业时，编制拆装方案主要依据是 （　　） 。", "options": ["装拆工人的工作经验", "国家有关塔式起重机的技术标准和规范，规程", "随机的使用、拆装说明书、整机、部件的装配图、电气原理及接线图等", "已有的拆装方案及过去拆装作业中积累的技术资料", "其他单位的拆装方案或有关资料"], "answer": [1, 2, 3, 4], "explanation": "编制拆装方案主要依据是：\n（1）国家有关塔式起重机的技术标准和规范，规程；\n（2）随机的使用、拆装说明书、整机、部件的装配图、电气原理及接线图等；\n（3）已有的拆装方案及过去拆装作业中积累的技术资料；\n（4）其他单位的拆装方案或有关资料"},
  {"id": 1094, "type": "multiple", "question": "塔机的拆装方案一般包括 （　　） 等内容。", "options": ["整机及部件的安装程序与方法", "整机及部件的拆卸程序与方法", "作业工位的布置、人员配备及承担工序分工", "安全生产技术措施和注意事项", "关键部位的调整工艺应达到的技术条件"], "answer": [0, 1, 2, 3, 4], "explanation": "安装、拆卸专项施工方案一般应包括以下内容：\n1）工程概况、塔式起重机作业周围环境；\n2）装、拆过程中进出场路线（应有施工平面图）\n3）整机及部件的安装或拆卸的程序与方法，其中必须列有整机及零部件重量及吊点位置；\n4）装、拆作业所需的辅助设备的型号、规格、性能表及对地基的要求；5）安装过程中应检测的项目以及应达到的技术要求；\n6）关键部位的调整工艺应达到的技术条件；\n7）装、拆作业所需的工具、量具、索具等的名称、规格、数量、及使用注意事项；\n8）作业工位的布置、人员配备（分工种、等级）以及承担的工序分工；9）安全技术措施和注意事项；\n10）应急预案。"},
  {"id": 1095, "type": "multiple", "question": "塔机的拆装作业必须在白天进行，不得在 （　　） 情况下进行。", "options": ["夜间", "大风", "浓雾", "雨雪天", "高温"], "answer": [0, 1, 2, 3], "explanation": "塔机的拆装作业应在白天进行。当遇大风、浓雾和雨雪等恶劣天气时,应停止作业。"},
  {"id": 1096, "type": "multiple", "question": "当遇 （　　） 时，不得使用施工升降机。", "options": ["大雨", "大雪", "大雾", "施工升降机顶部风速大于10m/s", "电缆表面有水珠"], "answer": [0, 1, 2], "explanation": "《施工升降机安装、使用、拆卸安全技术规程》第5.2.9条规定,当遇大雨、大雪、大雾、施工升降机顶部风速大于20m/s或导轨架、电缆表面结有冰层时,不得使用施工升降机。"},
  {"id": 1097, "type": "multiple", "question": "施工升降机安装完毕后，安装单位应验收的技术数据包括 （　　） 等。", "options": ["接地电阻", "绝缘电阻", "垂直度数据", "水平度数据", "钢丝绳规格直径"], "answer": [0, 1, 2, 4], "explanation": "【依据】《建筑施工升降机安装、使用、拆卸安全技术规程》JGJ 215-2010\n【解析】正确答案是A、B、C。题干对应的是施工升降机安全管理。 A项“接地电阻”正确，它与题干所述“施工升降机安装完毕后，安装单位应验收的技术数”相对应。 B项“绝缘电阻”正确，它与题干所述“施工升降机安装完毕后，安装单位应验收的技术数”相对应。 C项“垂直度数据”正确，它与题干所述“施工升降机安装完毕后，安装单位应验收的技术数”相对应。 D项“水平度数据”错误，它不符合题干限定的对象、程序或条件。 E项“钢丝绳规格直径”错误，它不符合题干限定的对象、程序或条件。"},
  {"id": 1098, "type": "multiple", "question": "起重吊装常用索具吊具钢丝绳，按绳芯的不同分为 （　　） 。", "options": ["麻芯", "纤维芯", "金属芯", "石棉芯", "钢芯"], "answer": [0, 2, 3], "explanation": "钢丝绳按绳芯不同可分为麻芯(棉芯)、石棉芯和金属芯三种。"},
  {"id": 1099, "type": "multiple", "question": "单斗挖掘机的工作装置是可更换的，可进行 （　　） 多种作业。", "options": ["破碎", "打桩", "夯土", "起重", "吊装"], "answer": [0, 1, 2, 3], "explanation": "单斗挖掘机的工作装置是可更换的，可进行破碎、打桩、夯土、起重等多种作业。"},
  {"id": 1100, "type": "multiple", "question": "有 （　　） 情形之一的施工升降机，不得出租、安装、使用。", "options": ["属国家明令淘汰或者禁止使用的", "超过安全技术标准或者制造厂家规定的使用年限的", "经检验达不到安全技术标准规定的", "没有完整安全技术档案的", "没有齐全有效的安全保护装置的"], "answer": [0, 1, 2, 3, 4], "explanation": "4.1.6 有下列情况之一的施工升降机不得安装使用:\n1 属国家明令淘汰或禁止使用的；\n2 超过由安全技术标准或制造厂家规定使用年限的；\n3 经检验达不到安全技术标准规定的；\n4 无完整安全技术档案的；\n5 无齐全有效的安全保护装置的。"},
  {"id": 1101, "type": "multiple", "question": "建筑有限空间是指 （　　） 的空间。", "options": ["封闭或部分封闭", "进出口较为狭窄有限", "未被设计为固定工作场所", "自然通风不良", "易造成有毒有害、易燃易爆物质积聚或氧含量不足"], "answer": [0, 1, 2, 3, 4], "explanation": "有限空间是指封闭或部分封闭，进出口较为狭窄有限，未被设计为固定工作场所，自然通风不良，易造成有毒有害、易燃易爆物质积聚或氧含量不足的空间。本项目施工区域内从事有限空间作业和具有有限空间作业行为的生产经营单位、班组均适用本方案。"},
  {"id": 1102, "type": "multiple", "question": "在建筑有限空间场所内进行施工作业时，引发中毒窒息的原因有 （　　） 。", "options": ["设备设施与设备设施之间、设备设施内外之间空气通道相互隔断，导致作业空间通风不畅，照明不良，通信不畅", "空气中有害物质的浓度高于职业接触限值", "活动空间较小，工作场地狭窄，易导致工作人员出入困难，相互联系不便，不利于工作监护和实施救援", "湿度和热度等物理危害因素较高，作业人员能量消耗大，易于疲劳", "存在可燃性气体、蒸气和气溶胶的浓度低于爆炸下限（LEL）的10%"], "answer": [0, 1, 2, 3], "explanation": "4.2有限空间危险、有害因素包括：\na)设备设施与设备设施之间、设备设施内外之间空气通道相互隔断，导致作业空间通风不畅，照\n明不良，通讯不畅；\nb)活动空间较小，工作场地狭窄，易导致工作人员出入困难，相互联系不便，不利于工作监护和\n实施救援；\nc)湿度和热度等物理危害因素较高，作业人员能量消耗大，易于疲劳；\nd)存在可燃性气体、蒸气和气溶胶的浓度高于爆炸下限(LEL)的10%；空气中爆炸性粉尘浓度达\n到或高于爆炸下限；空气中存在缺氧或富氧环境；空气中有害物质的浓度高于职业接触限值，引发中毒和窒息、火灾和爆炸事故；\ne)存在触电、高处坠落、物体打击、机械伤害等危险有害因素。"},
  {"id": 1103, "type": "multiple", "question": "有限空间作业者的职责包括 （　　） 。", "options": ["接受本单位职业卫生培训，持证上岗", "遵守密闭空间作业安全操作规程", "正确使用密闭空间作业安全设施与个体防护用品", "确认作业环境、作业程序和防范设施及用品符合进入要求", "应与监护者进行有效的安全、报警、撤离等双向信息沟通"], "answer": [0, 1, 2, 4], "explanation": "作业者的职责。\n作业者应接受本单位职业卫生培训，持证上岗；\n遵守密闭空间作业安全操作规程；\n正确使用密闭空间作业安全设施与个体防护用品；\n应与监护者进行有效的安全、报警、撤离等双向信息沟通。\n选项D属于：作业负责人的职责。\n作业负责人应确认作业者、监护者的职业卫生培训及上岗条件，确认作业环境、作业程序和防范设施及用品符合进入要求；同时检查、验证应急救援服务、呼叫方法的效果；在作业完成后，要确认作业者及所携带的设备和物品均已撤离。"},
  {"id": 1104, "type": "multiple", "question": "作业单位应对有限空间作业的 （　　） 进行培训。", "options": ["安全管理人员", "作业负责人", "监护者", "作业者", "应急救援人员"], "answer": [0, 1, 2, 3, 4], "explanation": "应对有限空间作业分管负责人、安全管理人员、作业现场负责人、监护人员、作业人员、应急救援人员进行专项安全培训。"},
  {"id": 1105, "type": "multiple", "question": "进入密闭空间施工作业前，应拟定和掌握紧急情况时的撤离 （　　） 。", "options": ["线路", "方法", "时间", "人员", "范围"], "answer": [0, 1], "explanation": "进入密闭空间施工作业前，应拟定和掌握紧急情况时的撤离线路和方法。"},
  {"id": 1106, "type": "multiple", "question": "某施工项目存在污水池等危险性较高场所的作业，下列企业的做法中，正确的有 （　　） 。", "options": ["严格实行作业审批程度，严禁擅自进入污水池内作业", "先通风、后作业，严禁通风次数不够就作业", "对作业人员进行安全培训，严禁教育培训不合格人员上岗作业", "制定应急措施，严禁盲目施救", "将应急装备存放在专用仓库，避免遭到损坏"], "answer": [0, 2, 3], "explanation": "《有限空间安全作业五条规定》已废止。\n有限空间安全作业五条规定：\n⑴必须严格实行作业审批制度，严禁擅自进入有限空间作业。\n⑵必须做到“先通风、再检测、后作业”，严禁通风、检测不合格作业。\n⑶必须配备个人防中毒窒息等防护装备，设置安全警示标识，严禁无防护监护措施作业。\n⑷必须对作业人员进行安全培训，严禁教育培训不合格上岗作业。\n⑸必须制定应急措施，现场配备应急装备，严禁盲目施救。"},
  {"id": 1107, "type": "multiple", "question": "临时用电施工组织设计的基本内容包括 （　　） 等部分。", "options": ["现场勘测", "负荷计算", "设计配电系统", "确定防护措施", "选择变流器"], "answer": [0, 1, 2, 3], "explanation": "临时用电施工组织设计的主要内容应包括：现场勘测；确定电源进线、变电所、配电室、配电装置、用电设备位置及线路走向；进行负荷计算；选择变压器；设计配电系统；设计配电线路、选择导线或电缆，设计配电装置、选择电器，设计接地装置，绘制临时用电工程图纸，包括用电工程总平面图、配电装置布置图、配电系统接线图、接地装置设计图；设计防雷装置；确定防护措施；制定安全用电措施和电气防火措施。"},
  {"id": 1108, "type": "multiple", "question": "临时用电现场勘测主要确定 （　　） 。", "options": ["电源进线", "线路走向", "配电装置", "用电设备位置", "变电所"], "answer": [0, 1, 2, 3, 4], "explanation": "确定电源进线、变电所或配电室、配电装置、用电设备位置及线路走向。"},
  {"id": 1109, "type": "multiple", "question": "施工现场用电工程配电系统设计和绘制临时用电图纸的主要内容有 （　　） 。", "options": ["用电工程总平面图", "导线布置图", "配电装置布置图", "配电系统接线图", "接地装置设计图"], "answer": [0, 2, 3, 4], "explanation": "绘制临时用电工程图纸,主要包括用电工程总平面图、配电装置布置图、配电系统接线图、接地装置设计图。"},
  {"id": 1110, "type": "multiple", "question": "安全用电措施和电气防火措施是指为了正确使用现场用电工程，并保证其安全运行，防止各种触电事故和电气火灾事故而制定的 （　　） 规定。", "options": ["技术性", "管理性", "系统性", "稳定性", "全面性"], "answer": [0, 1], "explanation": "安全用电措施和电气防火措施是指为了正确使用现场用电工程,并保证其安全运行,防止各种触电事故和电气火灾事故而制定的技术性和管理性规定。"},
  {"id": 1111, "type": "multiple", "question": "施工现场临时用电是指 （　　） 。", "options": ["临时电力线路", "安装的各种电气", "保护零线", "配电箱提供的机械设备动力源", "照明"], "answer": [0, 1, 3, 4], "explanation": "施工现场临时用电是指临时电力线路、安装的各种电气、配电箱提供的机械设备动力源和照明,必须执行JGJ46-2005《施工现场临时用电安全技术规范》。"},
  {"id": 1112, "type": "multiple", "question": "施工现场用电安全技术档案包括 （　　） 等内容。", "options": ["用电技术交底记录", "临时用电工程检查验收记录表", "接地电阻测验记录表", "施工现场用电组织设计的全部资料", "绝缘电阻测验记录表"], "answer": [0, 2, 3, 4], "explanation": "按照《规范》的规定，施工现场用电安全技术档案应包括以下八个方面的内容：\n① 施工现场用电组织设计的全部资料；\n② 修改施工现场用电组织设计资料；\n③ 用电技术交底资料；\n④ 施工现场用电工程检查验收表；\n⑤ 电气设备试、检验凭单和调试记录；\n⑥ 接地电阻、绝缘电阻、漏电保护器漏电动作参数测定记录表；\n⑦ 定期检(复)查表；\n⑧ 电工安装、巡检、维修、拆除工作记录。"},
  {"id": 1113, "type": "multiple", "question": "合理配置施工现场的临时供配电装置，包括 （　　） 等，确保配电系统安全可靠。", "options": ["变压器", "总配电箱", "分配电箱", "照明", "开关箱"], "answer": [0, 1, 2, 4], "explanation": "合理配置施工现场的临时供配电线路，供配电装置包括变压器、总配电箱（配电柜）、分配电箱、开关箱、无功补偿等，确保配电系统安全可靠。"},
  {"id": 1114, "type": "multiple", "question": "三级配电系统的设置应遵守 （　　） 规则。", "options": ["多机一闸", "分级分路", "动、照分设", "压缩配电间距", "环境安全"], "answer": [1, 2, 3, 4], "explanation": "三级配电系统应遵守四项基本原则：即分级分路原则，动照分设原则，压缩配电间距原则，环境安全原则。"},
  {"id": 1115, "type": "multiple", "question": "下列关于压缩配电间距规则的选项，正确的包括 （　　） 。", "options": ["压缩配电间距规则中规定关箱与其供电的固定式用电设备的水平距离不宜超过3m", "压缩配电间距规则中规定分配电箱与开关箱的距离不得超过30m", "分配电箱应设在用电设备或负荷相对分散的场所", "压缩配电间距规则是指除总配电箱，配电室(配电柜)外，分配电箱与开关箱之间，开关箱与用电设备之间的空间间距应尽量伸长", "实行一机一闸"], "answer": [0, 1, 4], "explanation": "压缩配电间距\n压缩配电间距原则是指各配电箱、 开关箱之间的距离应尽量缩短。 总配电箱应设在靠近电源的区域， 分配电箱应设在用电设备或负荷相对集中的区域， 分配电箱与开关箱的距离不得超过 30m ，开关箱与其控制的固定式用电设备的水平距离不宜超过3m 。"},
  {"id": 1116, "type": "multiple", "question": "环境安全规则是指配电系统对其设置和运行环境安全因素的要求。主要是指对 （　　） 等因素的防护要求，防止由其引发设备损坏、触电和电气火灾事故。", "options": ["易燃易爆物", "腐蚀介质", "机械损伤", "电磁辐射", "静电"], "answer": [0, 1, 2, 4], "explanation": "环境安全规则是指配电系统对其设置和运行环境安全因素的要求。主要是指对易燃易爆物、腐蚀介质、机械损伤、电磁感应、静电等因素的防护要求，防止由其引发设备损坏、触电和电气火灾事故。"},
  {"id": 1117, "type": "multiple", "question": "根据现行行业标准《建筑施工安全检查标准》JGJ59规定，施工用电一般项目的检查评定包括 （　　） 等内容。", "options": ["配电室建筑耐火等级应不低于3级并配备合格的消防器材", "配电室的布设应符合规范", "配电装置的电器元件设置应符合规范", "配电箱应设置警示标志", "备用发电机组必须与外电线路连锁"], "answer": [0, 1, 2, 3, 4], "explanation": "施工用电,5 配电室与配电装置 1）配电室建筑耐火等级不低于3级并配备合格的消防器材； 2）配电室、配电装置的布设应符合规范； 3）配电装置中的仪表、电器元件设置应符合规范； 4）备用发电机组必须与外电线路进行连锁； 5）配电室应设置警示标志、工地平面图和系统图 。"},
  {"id": 1118, "type": "multiple", "question": "配电室的位置应符合周围环境无 （　　） 的要求。", "options": ["灰层", "积水", "振动", "腐蚀介质", "易燃易爆无"], "answer": [0, 1, 2, 3, 4], "explanation": "配电室的位置周围环境无灰层、无潮气、无振动、无腐蚀介质、无易燃易爆物、无积水。"},
  {"id": 1119, "type": "multiple", "question": "下列配电室的布置规则，正确的有 （　　） 。", "options": ["配电柜正面的操作通道宽度，双列面对面布置时不应小于2.5m", "配电柜正面的操作通道宽度，单列布置或双列背对背布置时不应小于2m", "配电装置上端(含配电柜顶部与配电母线排)距天棚不应小于0.5m", "配电柜侧面的维护通道宽度不应小于1m", "配电室围栏上端与其正上方带电部分的净距不应小于1m"], "answer": [2, 3], "explanation": "配电柜正面的操作通道宽度，单列布置或双列背对背布置不小于1.5m，双列面对面布置不小于2m；\n配电室围栏上端与其正上方带电部分的净距不小于75mm。"},
  {"id": 1120, "type": "multiple", "question": "施工现场临时用电工程中的自备发电机供电系统的设置必须遵守的原则包括 （　　） 。", "options": ["自备发电机组电源应与外电线电源相互联锁，严禁并列运行", "自备发电机组电源的供配电系统应采用具有专用保护零线的三相四线制中性点直接接地系统", "自备发电机组电源的接地系统应与外电线路联锁", "自备发电机组电源的接零系统应与电气连接", "施工现场设置的自备电源，即是指自备的220/400V发电机组"], "answer": [0, 1], "explanation": "施工现场临时用自备发电机组的供配电系统应采用三相四线制中性点直接接地系统，并须独立设置，与外电线路隔离，不得有电气连接；自备发电机组电源应与外电线路电源联锁，严禁并列运行；发电机组应设置短路保护和过负荷保护。\n自备电源的设置:施工现场设置的自备电源,即是指自行设置的230/400V发电机组。"},
  {"id": 1121, "type": "multiple", "question": "施工现场的配电装置是指施工现场用电工程配电系统中设置的 （　　） 。", "options": ["总配电箱(配电柜)", "分配电箱", "开关箱", "用电设备", "变压器"], "answer": [0, 1, 2], "explanation": "配电装置是指施工现场用电工程配电系统中设置的总配电箱(配电柜)、分配电箱和开关箱。"},
  {"id": 1122, "type": "multiple", "question": "下列关于配电箱、开关箱中N线与PE线接线端子板的设置规则中，正确的是 （　　） 。", "options": ["N端子板与钢质电器安装板之间必须保持电气连接", "PE端子板与钢质电器安装板之间必须保持绝缘", "N、PE端子板应采用紫铜板制作", "配电箱、开关箱应设门配锁，箱门与箱内PE端子板间应跨接编织软铜线", "配电箱、开关箱的外形结构应能防雨、防尘"], "answer": [2, 3, 4], "explanation": "N、PE端子板必须分别设置，固定安装在电器安装板上，并分别作(N、PE)符号标记，严禁合设在一起。其中，N端子板与钢质电器安装板之间必须保持绝缘，而PE端子板应与钢质电器安装板之间必须保持电气连接。当钢板箱配装绝缘电器安装板时，PE端子板应与钢板箱体作电气连接。"},
  {"id": 1123, "type": "multiple", "question": "配电装置配置的电器必须具备的基本功能有 （　　） 。", "options": ["电源隔离功能", "空载连接", "正常接通与分断电路功能", "短路保护功能", "过载、漏电保护功能"], "answer": [0, 2, 3, 4], "explanation": "配电装置配置的电器必须具备三种基本功能：即电源隔离功能，正常接通与分断电路功能，以及短路、过载、漏电保护功能。"},
  {"id": 1124, "type": "multiple", "question": "总配电箱应设置 （　　） 。", "options": ["电源隔离开关", "断路器", "漏电保护器", "开关箱", "配电柜"], "answer": [0, 1, 2], "explanation": "总配电箱应设置电源隔离开关、断路器或熔断器、漏电保护器。功能；1 接收电源，分路分配电源电路。2 隔离的功能，3 短路和过载的保护功能，4 漏电的保护功能，5 TN-s接零接地保护系统。"},
  {"id": 1125, "type": "multiple", "question": "当所设总漏电保护器是同时具备短路、过载、漏电保护功能的漏电断路器时，可不设 （　　） 。", "options": ["总断路器", "总隔离开关", "总熔断器", "分路熔断器", "分路断路器"], "answer": [0, 2], "explanation": "当所设总漏电保护器是同时具备短路、过载、漏电保护功能的漏电断路器时,可不设总断路器或总熔断器。"},
  {"id": 1126, "type": "multiple", "question": "当总路设置总漏电保护器时，应装设 （　　） 等装置。", "options": ["总隔离开关", "分路隔离开关", "总断路器", "分路断路器", "电源进线"], "answer": [0, 1, 2, 3], "explanation": "①当总路设置总漏电保护器时，还应装设总隔离开关、分路隔离开关以及总断路器、分路断路器或总烙断器、分路熔电器。"},
  {"id": 1127, "type": "multiple", "question": "当分路设置分路漏电保护器时，应装设 （　　） 等装置。", "options": ["总隔离开关", "分路隔离开关", "总断路器", "分路断路器", "电源进线"], "answer": [0, 1, 2, 3], "explanation": "当各分路设置分路漏电保护器时，还应装设总隔离开关、分路隔离开关以及总断路器、分路断路器或总熔断器、分路熔断器。当分路所设漏电保护器是同时具备短路、过载、漏电保护功能的漏电断路器时，可不设分路断路器或分路熔断器。（JGJ46－2005第8.2.2条）"},
  {"id": 1128, "type": "multiple", "question": "在采用二级漏电保护的配电系统中，分配电箱的电器配置与接线原则包括 （　　） 。", "options": ["总路应设置总隔离开关，以及总断路器或总熔断器", "分路应设置分路隔离开关，以及分路断路器分路熔断器", "熔断器应设置于电源进线端", "总电源开关应设置于隔离开关的负荷侧", "隔离开关应设置于电源进线端"], "answer": [0, 1, 4], "explanation": "在采用二级漏电保护的配电系统中，分配电箱中不要求设置漏电保护器，但电源隔离开关、过载与短路保护电器必须设置。此时分配电箱的电器配置与接线原则如下：\n(1)总路应设置总隔离开关，以及总断路器或总熔断器。\n(2)分路应设置分路隔离开关，以及分路断路器或分路熔断器。\n(3)隔离开关应设置于电源进线端。并选用分断时具有可见分断点的电器，如刀型开关等。\n(4)断路器或熔断器应设置于隔离开关的负荷侧。断路器和熔断器应具有可靠的过载与短路保护功能。"},
  {"id": 1129, "type": "multiple", "question": "配电装置的箱（柜）门处均应有 （　　） 等内容，以防误操作。", "options": ["名称", "规格", "用途", "分路标记", "内部电气系统接线图"], "answer": [0, 2, 3, 4], "explanation": "配电装置的箱(柜)门处均应有名称、用途、分路标记，及内部电气系统接线图，以防误操作。"},
  {"id": 1130, "type": "multiple", "question": "配电装置应定期检查、维修，检查、维修时应遵循的事项包括 （　　） 等内容。", "options": ["检查、维修人员必须是持证专业电工", "检查、维修时必须先将需本级配电装置的相应隔离开关分闸断电", "严禁带电作业", "检查、维修人员必须按规定穿戴绝缘、防护用品", "检查、维修前应悬挂“禁止合闸有人工作”的停电标志牌"], "answer": [0, 2, 3, 4], "explanation": "配电装置应定期检查、维修。检查、维修人员必须是专业电工。检查、维修时，必须首先将其前一级配电装置的相应隔离开关分闸断电，并悬挂“禁土合闸有人工作\"停电标志牌，严禁带电作业检查、维修人员必须按规定穿戴绝缘、防护用品，使用绝缘工具。"},
  {"id": 1131, "type": "multiple", "question": "固定式配电箱、开关箱的中心点与地面的垂直距离应为 （　　） m。", "options": ["1.3", "1.4", "1.5", "1.6", "1.7"], "answer": [1, 2, 3], "explanation": "固定式配电箱、开关箱的中心点与地面的垂直距离应为【1.4～1.6】m。"},
  {"id": 1132, "type": "multiple", "question": "根据现行行业标准《建筑施工安全检查标准》JGJ59规定，施工用电一保证项目的检查评定包括 （　　） 等内容。", "options": ["线路及接头应保证机械强度和绝缘强度", "线路应设短过载保护", "导线应满足线路负荷电流", "线路架设应符合规范", "线路埋设应符合规范"], "answer": [0, 1, 3, 4], "explanation": "施工用电保证项目的检查评定应符合下列规定：\n配电线路\n1)线路及接头应保证机械强度和绝缘强度;\n2线路应设短路、过载保护，导线截面应满足线路负荷电流;\n3)线路架设或埋设应符合规范。"},
  {"id": 1133, "type": "multiple", "question": "施工现场的配电线路，按其敷设方式和场所不同，主要有 （　　） 。", "options": ["架空线路", "电缆线路", "室外配线", "室内配线", "配电母线"], "answer": [0, 1, 3], "explanation": "施工现场的配电线路,按其敷设方式和场所不同,主要有架空线路、电缆线路、室内配线三种。"},
  {"id": 1134, "type": "multiple", "question": "施工现场内的低压架空线路不得直接捆绑在 （　　） 上，不得拖在地面上。", "options": ["电杆", "专用电杆", "木杆", "树木", "脚手架"], "answer": [0, 3, 4], "explanation": "施工现场内的低压架空线路不得直接捆绑在电杆、树木、脚手架上，不得拖在地面上。"},
  {"id": 1135, "type": "multiple", "question": "架空线中各导线截面与线路工作制的关系为：三相四线制工作时， （　　） 。", "options": ["N线和PE线截面不小于相线（L线）截面的50%", "N线和PE线截面与相线（L线）截面相同", "相线线路的零线截面不小于相线截面的50%", "相线线路的零线截面与相线截面相同", "相线截面最大"], "answer": [0, 3], "explanation": "架空线中各导线截面与线路工作制的关系为:三相四线制工作时,N线和PE线截面不小于相线(L线)截面的50%;单相线路的零线截面与相线截面相同。"},
  {"id": 1136, "type": "multiple", "question": "下列关于架空线的绝缘色标准中，正确的是 （　　） 。", "options": ["L1(A相)一黄色", "L2(B相)一红色", "L3(C相)一绿色", "N线一蓝色", "PE线一绿/黄双色"], "answer": [0, 3, 4], "explanation": "根据中国电力系统的相关标准（如《低压配电设计规范》GB 50054等），架空线的绝缘色标准通常如下：\n• L1（A相）：黄色\n• L2（B相）：绿色\n• L3（C相）：红色\n• N线（中性线）：蓝色或浅蓝色\n• PE线（保护接地线）：绿/黄双色\n我们逐一分析选项：\n• A. L1(A相)一黄色：正确，A相通常使用黄色。\n• B. L2(B相)一红色：错误，B相应为绿色，红色通常用于C相。\n• C. L3(C相)一绿色：错误，C相应为红色，绿色通常用于B相。\n• D. N线一蓝色：正确，N线（中性线）通常使用蓝色或浅蓝色。\n• E. PE线一绿/黄双色：正确，PE线（保护接地线）使用绿/黄双色。"},
  {"id": 1137, "type": "multiple", "question": "五芯电缆中相线的绝缘色则一般由 （　　） 中的二种搭配。", "options": ["黑", "棕", "白", "灰", "红"], "answer": [1, 3], "explanation": "五芯电缆必须包含淡蓝、绿/黄二种颜色绝缘芯线。"},
  {"id": 1138, "type": "multiple", "question": "架空线路的组成一般包括 （　　） 。", "options": ["导线", "绝缘导线", "绝缘子", "横担", "电杆"], "answer": [1, 2, 3, 4], "explanation": "架空线路一般包括四部分，即电杆、横担、绝缘子和绝缘导线。如采纳绝缘横担，则架空线路可由电杆、绝缘横担、绝缘线三部分组成。"},
  {"id": 1139, "type": "multiple", "question": "下列关于架空线相序排列顺序，正确的是 （　　） 。", "options": ["动力、照明线在同一横担上架设时，面向负荷从左侧起依次为L1、L2、L3、N、PE", "动力、照明线在同一横担上架设时，面向负荷从左侧起依次为L1、N、L2、L3、PE", "动力、照明线在同一横担上架设时，面向负荷从左侧起依次为L1、L2、N、L3、PE", "动力、照明线在二层横担上分别架设时，上层横担面向负荷从左侧起依次为：L（L1或L2或L3）、N、PE", "动力、照明线在二层横担上分别架设时，下层横担面向负荷从左侧起依次为：L（L1或L2或L3）、N、PE"], "answer": [1, 4], "explanation": "1、动力、照明线在同一横担上架设时，导线相序排列是：面向负荷从左侧起依次为L1、N、L2、L3、PE；\n2、动力、照明线在二层横担上分别架设时，导线相序排列是：上层横担面向负荷从左侧起依次为L1、L2、L3；下层横担面向负荷从左侧起依次为L1（L2、L3）、N、PE。"},
  {"id": 1140, "type": "multiple", "question": "室内配线的明敷设可采用 （　　） 方式，不得悬空乱拉线。", "options": ["瓷瓶、瓷（塑料）夹配线", "直埋墙方式配线", "嵌绝缘槽配线", "铝线截面配线", "钢索配线"], "answer": [0, 2, 4], "explanation": "室内配线分为明敷设和暗敷设两种。（1）明敷设可采用瓷瓶、瓷（塑料）夹配线，嵌绝缘槽配线和钢索配线三种方式，不得悬空乱拉。明敷主干线的距地高度不得小于2.5m。（2）暗敷设可采用绝缘导线穿管埋墙或埋地方式和电缆直埋墙或直埋地方式。1）暗敷设线路部分不得有接头。2）暗敷设金属穿管应作等电位连接，并与PE线相连接。3）潮湿场所或埋地非电缆（绝缘导线）配线必须穿管敷设，管口和管接头应密封。严禁将绝缘导线直埋地下。"},
  {"id": 1141, "type": "multiple", "question": "下列属于室内配线暗敷设的要求的有 （　　） 。", "options": ["暗敷设可采用绝缘导线穿管埋墙或埋地方式", "暗敷设可采用瓷瓶、瓷(塑料)夹配线", "暗敷设可采用钢索配线", "暗敷设可采用电缆直埋地方式", "暗敷设可采用绝缘导线直埋墙内方式"], "answer": [0, 3], "explanation": "室内配线分为明敷设和暗敷设两种。（1）明敷设可采用瓷瓶、瓷（塑料）夹配线，嵌绝缘槽配线和钢索配线三种方式，不得悬空乱拉。明敷主干线的距地高度不得小于2.5m。（2）暗敷设可采用绝缘导线穿管埋墙或埋地方式和电缆直埋墙或直埋地方式。1）暗敷设线路部分不得有接头。2）暗敷设金属穿管应作等电位连接，并与PE线相连接。3）潮湿场所或埋地非电缆（绝缘导线）配线必须穿管敷设，管口和管接头应密封。严禁将绝缘导线直埋地下。"},
  {"id": 1142, "type": "multiple", "question": "为了保证用电过程中系统能够安全、可靠地运行，并对系统本身在运行过程中可能出现的诸如 （　　） 等故障进行自我保护，在系统结构配置中必须设置一些与保护要求相适应的子系统。而这些子系统的组合就是用电系统的基本保护系统。", "options": ["接地", "短路", "过载", "漏电", "腐蚀"], "answer": [0, 1, 2, 3], "explanation": "施工现场的用电系统，不论其供电方式如何，都属于电源中性点直接接地的220/380三相四线制低压电力系统。为了保证用电过程中系统能够安全、可靠地运行，并对系统本身在运行过程中可能出现的诸如接地、短路、过载、漏电等故障进行自我保护，在系统结构配置中必须设置一些与保护要求相适应的子系统，即接地保护系统、过载与短路保护系统、漏电保护系统，它们的组合就是用电系统的基本保护系统。"},
  {"id": 1143, "type": "multiple", "question": "过载、短路保护系统可通过在 （　　） 中设置过载、短路保护电器实现。", "options": ["总配电箱", "分配电箱", "总断熔器", "分断熔器", "开关箱"], "answer": [0, 1, 4], "explanation": "过载、短路保护系统可通过在总配电箱、分配电箱、开关箱中设置过载、短路保护电器中实现。"},
  {"id": 1144, "type": "multiple", "question": "文明施工包括了一般项目和保证项目，以下属于保证项目的有 （　　） 。", "options": ["现场围挡", "封闭管理", "公示标牌", "生活设施", "材料管理"], "answer": [0, 1, 4], "explanation": "文明施工\n一般项目:综合治理、公示标牌、生活设施、社区服务。\n保证项目:现场围挡、封闭管理、施工场地、材料管理、现场办公与住宿、现场防火。"},
  {"id": 1145, "type": "multiple", "question": "距离 （　　） 等建筑物不足5m的施工现场，应设置具有降噪功能的围挡。", "options": ["医院", "厂房", "学校", "住宅", "体育馆"], "answer": [0, 2, 3], "explanation": "距离住宅、医院、学校等建筑物不足5米的施工现场，设置具有降噪功能的围档。"},
  {"id": 1146, "type": "multiple", "question": "上海市重点区域内施工工地的文明施工要求包括 （　　） 等规定。", "options": ["采用爆破方式拆除基坑支撑", "施工现场设置宿舍的，每间宿舍人均居住面积不得低于5㎡", "任何情况下，禁止夜间施工", "禁止采用钢筋、模板成型加工作业", "设置的连续、封闭围挡图案简洁、美观且与周边环境相协调"], "answer": [1, 3, 4], "explanation": "本市重点区域内施工工地的文明施工要求，还应当符合下列\n规定：\n（一）设置的连续、封闭围挡图案简洁、美观且与周边环境相协调，除管线工程外，围挡高度不得低于2.5米。\n（二）安全网采用不透尘、符合安全要求的材料。\n（三）禁止采用爆破方式拆除基坑支撑。\n（四）禁止使用不符合标准的高噪声作业设备。\n（五）施工现场设置宿舍的，每间宿舍人均居住面积不得低于5平方米，并按照标准配备生活设施。\n（六）禁止夜间施工，但抢险、抢修工程及有特殊工序要求的工程除外；因特殊工序要求确需夜间施工的，应当向交通行政管理部门或者区生态环境部门办理夜间施工有关手续，并提前在周边区域予以公告。\n（七）禁止采用钢筋、模板成型加工作业。\n（八）轨道交通站点、隧道工程工作井施工，采用覆罩法作业方式，但施工现场安全或者空间条件无法达到要求的除外。"},
  {"id": 1147, "type": "multiple", "question": "上海市重点区域内施工工地的文明施工要求，重点区域临街围挡应结合环境，宜选用 （　　） 等点缀措施。", "options": ["灯光", "仿古", "墙面绘画", "防风围挡", "园林造型"], "answer": [0, 1, 2, 4], "explanation": "重点区域临街围挡应结合环境,宜选用仿古、园林造型、灯光、墙面绘画等点缀措施。"},
  {"id": 1148, "type": "multiple", "question": "施工现场出入门内侧应设置门卫室，门卫室应满足（）等要求。", "options": ["总面积不宜小于5平方", "配备必需的办公桌椅", "悬挂管理制度", "建立车辆进出登记台账", "建立来客登记台账"], "answer": [1, 2, 3, 4], "explanation": "出入门内侧应设置门卫室,总面积不宜小于4㎡,配备必需的办公桌椅,悬挂管理制度,建立来(访)客登记台帐和车辆进出登记台账。"},
  {"id": 1149, "type": "multiple", "question": "按照封闭管理的要求，施工现场的出入门内侧应规范设置 （　　） 和施工现场平面图。", "options": ["工程概况牌", "消防保卫牌", "安全生产牌", "文明施工牌", "管理人员名单及监督电话牌"], "answer": [0, 1, 2, 3, 4], "explanation": "《建筑施工安全检查标准》第3.2.4条规定，大门口处应设置公示标牌，主要内容应包括：工程概况牌、消防保卫牌、安全生产牌、文明施工牌、管理人员名单及监督电话牌、施工现场总平面图；标牌应规范、整齐、统一；施工现场有安全标语；应有宣传栏、读报栏、黑板报。"},
  {"id": 1150, "type": "multiple", "question": "施工现场堆放物品应按物品的种类整齐有序的堆放，下列关于物品堆放的要求正确的是 （　　） 。", "options": ["每垛建材间的距离不应小于1m", "每垛建材与梁、柱的距离不应小于1m", "每垛建材与墙的距离不应小于1m", "每垛建材堆叠高度不应大于1m", "主要通道的宽度不应小于1m"], "answer": [0, 2], "explanation": "上海市工程建设规范文明施工规范\n堆放物品的方式应按物品的种类分别堆放,堆放应整齐有序,稳定牢固,物品堆叠高度不应大于1.6m。圆形物品塔型堆叠时,不应大于四层,最底层外围应加垫块垫稳。\n各类建材物品每垛堆放的占地面积不宜大于100m2。垛与垛的距离不应小于1m,垛与墙的距离不应小于1m,垛与梁、柱的距离不应小于0.5m。主要通道的宽度不应小于2m。"},
  {"id": 1151, "type": "multiple", "question": "施工现场材料码放应采取 （　　） 等措施。", "options": ["防火", "防潮", "防尘", "防锈蚀", "防震"], "answer": [0, 1, 3], "explanation": "《建筑施工安全检查标准》JGJ 59-2011，3.2.3 文明施工保证项目的检查评定应符合下列规定：4 材料管理 3）施工现场材料码放应采取防火、防锈蚀、防雨等措施；"},
  {"id": 1152, "type": "multiple", "question": "施工现场的 （　　） 等堆放，需砌筑不低于0.5m高度的围挡，表面采用苫布覆盖。", "options": ["土", "石", "灰", "沙", "砂"], "answer": [0, 1, 2, 4], "explanation": "施工现场的土、灰、砂、石堆放,需砌筑不低于0.5m高度的围挡,表面采用苫布覆盖。"},
  {"id": 1153, "type": "multiple", "question": "施工现场应设置有 （　　） 等公示标牌。", "options": ["安全标语", "宣传栏", "工程概况牌", "黑板报", "施工现场总平面图"], "answer": [2, 4], "explanation": "《建筑施工安全检查标准》JGJ 59-2011，3.2.4 文明施工一般项目的检查评定应符合下列规定：2 公示标牌 1）大门口处应设置公示标牌，主要内容应包括：工程概况牌、消防保卫牌、安全生产牌、文明施工牌、管理人员名单及监督电话牌、施工现场总平面图；"},
  {"id": 1154, "type": "multiple", "question": "施工现场设置生活区的，应当符合 （　　） 等规定。", "options": ["设置饮用水设施", "设置盥洗池或淋浴间", "设置水冲式或移动式厕所", "生活区和作业区分隔设置", "厕所由专人负责冲洗和消毒"], "answer": [0, 2, 3, 4], "explanation": "选项B是【和】而不是【或】\n第二十一条（施工现场生活区设置）\n施工现场设置生活区的，应当符合下列规定：\n（一）生活区和作业区分隔设置；\n（二）设置饮用水设施；\n（三）设置盥洗池和淋浴间；\n（四）设置水冲式或者移动式厕所，并由专人负责冲洗和消毒；\n（五）设置符合分类要求的密闭式垃圾容器，生活垃圾应当分类放置于垃圾容器内并做到日产日清。\n在生活区设置食堂的，应当依法办理餐饮服务许可手续，并遵守食品卫生管理的有关规定。\n在生活区设置宿舍的，应当安装可开启式窗户，每间宿舍人均居住面积不得低于4平方米。"},
  {"id": 1155, "type": "multiple", "question": "施工现场的安全管理资料是 （　　） 的基础。", "options": ["编写安全生产工作意见", "制定安全目标责任书", "编写各类安全生产总结和报告", "事故处理", "事故报告"], "answer": [0, 1, 2], "explanation": "安全管理资料是编写安全生产工作意见、制定安全目标责任书、编写各类安全生产总结和报告的基础。"},
  {"id": 1156, "type": "multiple", "question": "项目部应按职责分工落实安全生产管理资料和记录编制 （　　） 的责任。", "options": ["填写", "审核", "审批", "收集", "报告"], "answer": [0, 1, 2, 3], "explanation": "项目部应按职责分工落实安全生产管理资料和记录编制、填写、审核、审批、收集、保管的责任。"},
  {"id": 1157, "type": "multiple", "question": "安全生产管理资料和记录的填写与制作应符合 （　　） 等要求。", "options": ["应真实、完整，字迹清晰，签章规范", "不得随意涂改，具有一致性和可追溯性", "应采用信息化管理技术", "应至工程完工后处理或归档", "应随工程施工同步形成，分类归集保管"], "answer": [0, 1, 2, 4], "explanation": "（4）安全生产管理资料和记录的填写与制作应当符合以下条件：\n1）真实完整，字迹清楚，签章规范，不得随意涂改，并具有一致性和可追溯性；\n2）随工程施工同步形成，分类归集保管，直至工程竣工交付后处理或归档；\n3）采用信息化管理技术。"},
  {"id": 1158, "type": "multiple", "question": "以下不属于安全资料中教育交底资料的是 （　　） 。", "options": ["方案需论证的专家意见书及完善措施", "三级动火证开具", "底总包对分包的安全交底", "隐患整改记录及回复单", "常规安全教育记录"], "answer": [0, 2, 3], "explanation": "【依据】《建设工程施工现场消防安全技术规范》GB 50720-2011 / 《中华人民共和国消防法》\n【解析】正确答案是A、B、D。这是一道反向设问题，题干要找的是“不符合/不属于/错误”项。 A项“方案需论证的专家意见书及完善措施”正确，它与题干所述“以下安全资料中教育交底资料的是”相对应。 B项“三级动火证开具”正确，它与题干所述“以下安全资料中教育交底资料的是”相对应。 C项“底总包对分包的安全交底”错误，它不符合题干限定的对象、程序或条件。 D项“隐患整改记录及回复单”正确，它与题干所述“以下安全资料中教育交底资料的是”相对应。 E项“常规安全教育记录”错误，它不符合题干限定的对象、程序或条件。"},
  {"id": 1159, "type": "multiple", "question": "安全管理资料中关于安全验收的资料应包括 （　　） 等内容。", "options": ["活动房、围挡验收记录", "安全设施设备验收记录", "塔吊和施工电梯安装告知书", "塔吊和施工电梯隐蔽验收记录及基础砼强度报告", "基坑沉降和位移监测、土方开挖等验收资料"], "answer": [0, 1, 2, 3, 4], "explanation": "【依据】《建筑基坑支护技术规程》JGJ 120-2012 / 《建筑基坑工程监测技术标准》GB 50497-2019\n【解析】正确答案是A、B、D、E。题干对应的是基坑工程安全与监测。 A项“活动房、围挡验收记录”正确，它与题干所述“安全管理资料中安全验收的资料应包括等内容”相对应。 B项“安全设施设备验收记录”正确，它与题干所述“安全管理资料中安全验收的资料应包括等内容”相对应。 C项“塔吊和施工电梯安装告知书”错误，它不符合题干限定的对象、程序或条件。 D项“塔吊和施工电梯隐蔽验收记录及基础砼强度报告”正确，它与题干所述“安全管理资料中安全验收的资料应包括等内容”相对应。 E项“基坑沉降和位移监测、土方开挖等验收资料”正确，它与题干所述“安全管理资料中安全验收的资料应包括等内容”相对应。"},
  {"id": 1160, "type": "multiple", "question": "安全管理资料中关于分包资料应包括 （　　） 等内容。", "options": ["分包单位企业证照、安全生产许可证等", "总包对分包的安全交底", "总包对分包的检查记录", "总包对分包的安全生产协议书", "进场人员花名册及保险"], "answer": [0, 1, 2, 3, 4], "explanation": "【依据】《安全生产许可证条例》 / 《建筑施工企业安全生产许可证管理规定》\n【解析】正确答案是A、B、C、D、E。题干对应的是安全生产许可制度。 A项“分包单位企业证照、安全生产许可证等”正确，题干对应职责主体就是分包单位企业证照、安全生产许可证等。 B项“总包对分包的安全交底”正确，它与题干所述“安全管理资料中分包资料应包括等内容”相对应。 C项“总包对分包的检查记录”正确，它与题干所述“安全管理资料中分包资料应包括等内容”相对应。 D项“总包对分包的安全生产协议书”正确，它与题干所述“安全管理资料中分包资料应包括等内容”相对应。 E项“进场人员花名册及保险”正确，它与题干所述“安全管理资料中分包资料应包括等内容”相对应。"},
  {"id": 1161, "type": "multiple", "question": "安全检查验收方面， （　　） 等进场或初次施工完成后还需每月及复工验收。", "options": ["脚手架", "临边洞口防护", "防护棚", "机械", "施工电梯"], "answer": [0, 1, 2, 3], "explanation": "【依据】《建筑施工安全检查标准》JGJ 59-2011\n【解析】正确答案是A、B、D。题干对应的是建筑施工安全检查评定。 A项“脚手架”正确，它与题干所述“安全检查验收方面，等进场或初次施工完成后还需”相对应。 B项“临边洞口防护”正确，它与题干所述“安全检查验收方面，等进场或初次施工完成后还需”相对应。 C项“防护棚”错误，它不符合题干限定的对象、程序或条件。 D项“机械”正确，它与题干所述“安全检查验收方面，等进场或初次施工完成后还需”相对应。 E项“施工电梯”错误，它不符合题干限定的对象、程序或条件。"},
  {"id": 1162, "type": "multiple", "question": "每月应编制的安全资料包括 （　　） 等内容。", "options": ["工地食堂卫生食品安全检查表", "消防设施检查验收", "应急救援演练资料", "施工管理人员安全生产岗位责任制", "临时用电验收"], "answer": [0, 1, 4], "explanation": "每 月：大型机械定期检查（每月两次）、项目管理人员安全生产责任制考核、环境卫生检查评分表（每月两次）、施工现场环境卫生检查记录表、工地食堂卫生食品安全检查表、消防设施检查验收、临时用电验收、劳动保护自查、劳动保护工作会议记录、职工代表劳动保护巡视检查表、施工现场场容场貌验收表收表、施工电梯坠落实验（三个月一次）。\n选项C是每周、选项D是每年。"},
  {"id": 1163, "type": "multiple", "question": "下列关于落地式脚手架的验收，正确的包括 （　　） 。", "options": ["以单位工程（每栋楼）验收", "基础验收1次", "每达到6-8m时验收1次", "每三层验收1次", "搭设完成整体验收1次"], "answer": [0, 1, 2, 4], "explanation": "落地式脚手架验收以单位工程（每栋楼）验收，基础验收1次，每达到6-8米时验收1次，搭设完成整体验收1次。"},
  {"id": 1164, "type": "multiple", "question": "下列验收方式正确的包括 （　　） 。", "options": ["洞口安全防护设施验收一层一次", "悬挑式脚手架验收一层层一次", "落地式脚手架验收一层层一次", "模板工程及支撑体系安全验收记录每层一次", "临边安全防护施验收一层一次"], "answer": [0, 3, 4], "explanation": "资料：\n项目部安全教育培训按计划表执行，保持每月2-3次\n落地式脚手架验收以单位工程（每栋楼）验收，基础验收1次，每达到6-8米时验收1次，搭设完成整体验收1次。\n悬挑式脚手架验收，槽钢层（悬挑基础）验收1次，每三层（不超过10米）一次，搭设到规定高度整体验收1次（一般 18米，基本上每一悬挑需要验收3次，以单位工程验收，如果作业面较大以单位工程分段验收）\n临边、洞口安全防护设施验收一层一次（以单位工程验收，如果作业面较大以单位工程分段验收）验收记录必须有项 目经理签字。\n模板工程及支撑体系安全验收记录每层一次（以单位工程验收，如果作业面较大以单位工程分段验收）\n专项施工方案：基坑支护、降水、土方开挖、模板工程及支撑、脚手架搭设（悬挑、落地）、起重设备安装拆卸方案、 卸料平台（悬挑式钢平台）、起重吊装、拆除施工、以上以单位工程编制，施工临时用电可以单项工程编制、现场平 面布置图、安全警示标志平面布置图、消防平面布置图、临时用电平面布置图及其他，开工前要求技术员编制完成。"},
  {"id": 1165, "type": "multiple", "question": "专项施工方案中以单位工程编制的包括 （　　） 等内容。", "options": ["基坑支护", "消防平面布置图", "起重吊装", "拆除施工", "模板工程及支撑"], "answer": [0, 2, 3, 4], "explanation": "专项施工方案：基坑支护、降水、土方开挖、模板工程及支撑、脚手架搭设（悬挑、落地）、起重设备安装拆卸方案、 卸料平台（悬挑式钢平台）、起重吊装、拆除施工、以上以单位工程编制，施工临时用电可以单项工程编制、现场平面布置图、安全警示标志平面布置图、消防平面布置图、临时用电平面布置图及其他，开工前要求技术员编制完成。"},
  {"id": 1166, "type": "multiple", "question": "施工现场都要建立健全防火检查制度，发现火险隐患，必须立即消除，一时难以消除的隐患，要 （　　） 限期整改。", "options": ["定人员", "定责任", "定项目", "定措施", "定处罚"], "answer": [0, 3], "explanation": "施工现场都要建立、健全防火检查制度,发现火险隐患,必须立即消除,一时难以消除的隐患,要定人员、定时间、定措施限期整改。"},
  {"id": 1167, "type": "multiple", "question": "根据“四不放过”原则，在火灾事故发生后，施工单位和建设单位应共同做好现场保护和会同消防部门进行现场勘察的工作，以下属于“四不放过”原则的是 （　　） 。", "options": ["事故原因分析不清不放过", "事故责任者和群众没受到教育不放过", "事故隐患不整改不放过", "事故责任者未受到处理不放过", "事故未调查处理不放过"], "answer": [0, 1, 2, 3], "explanation": "安全生产的“四不放过”原则是：原因未查明不放过、责任人未处理不放过、有关人员未受到教育不放过、整改措施未落实不放过\"。"},
  {"id": 1168, "type": "multiple", "question": "施工材料的堆放使用应符合防火要求。其中，易燃易爆物品必须有严格的防火措施，包括 （　　） 等内容，确保施工安全。", "options": ["专库储存", "保持通风", "指定防火负责人", "分类单独存放", "配备灭火器材"], "answer": [0, 1, 2, 3, 4], "explanation": "第十六、施工材料的存放、使用应符合防火要求。库房应采用非燃材料支搭。易燃易爆物品必须有严格的防火措施，应专库储存，分类单独存放，保持通风，配备灭火器材，指定防火负责人，确保施工安全。不准在工程内、库房内调配油漆、稀料。"},
  {"id": 1169, "type": "multiple", "question": "根据施工现场消防安全管理要求，在建工程内严禁 （　　） 。", "options": ["作为仓库使用", "存放易燃物品", "存放可燃材料", "设置宿舍", "吸烟"], "answer": [0, 1, 2, 3], "explanation": "第十八、在建工程内不准作为仓库使用，不准存放易燃、可燃材料，不得设置宿含。"},
  {"id": 1170, "type": "multiple", "question": "施工单位应制定消防安全管理制度，包括 （　　） 等内容。", "options": ["消防安全教育与培训制度", "可燃及易燃易爆危险品管理制度", "用火用电用气管理制度", "消防安全检查制度", "应急预案演练制度"], "answer": [0, 1, 2, 3, 4], "explanation": "消防安全管理制度应包括下列主要内容：\n（1）消防安全教育与培训制度。\n（2）可燃及易燃易爆危险品管理制度。\n（3）用火、用电、用气管理制度。\n（4）消防安全检查制度。\n（5）应急预案演练制度。"},
  {"id": 1171, "type": "multiple", "question": "消防安全管理制度的消防安全教育与培训制度包括 （　　） 等内容。", "options": ["施工现场消防安全管理制度", "报火警、接警的程序和方法", "可燃及易燃易爆危险品管理制度", "用火用电用气管理制度", "应急预案演练制度"], "answer": [0, 1, 4], "explanation": "消防安全教育和培训应包括下列内容：\n1 施工现场消防安全管理制度、防火技术方案、灭火及应急疏散预案的主要内容。\n2 施工现场临时消防设施的性能及使用、维护方法。\n3 扑灭初起火灾及自救逃生的知识和技能。\n4 报警、接警的程序和方法。"},
  {"id": 1172, "type": "multiple", "question": "施工单位编制的施工现场防火技术方案应包括 （　　） 等主要内容。", "options": ["施工现场重大火灾危险源辨识", "施工现场防火技术措施", "用火管理制度", "临时疏散设施设备", "临时消防设施和消防警示标识布置图"], "answer": [0, 1, 3, 4], "explanation": "根据《建设工程施工现场消防安全技术规范》GB50720-20116.1.5施工单位应编制施工现场防火技术方案，并应根据现场情况变化及时对其修改、完善。\n防火技术方案应包括下列主要内容：\n1）施工现场重大火灾危险源辨识。\n2）施工现场防火技术措施。\n3）临时消防设施、临时疏散设施配备。\n4）临时消防设施和消防警示标识布置图。"},
  {"id": 1173, "type": "multiple", "question": "施工作业前，施工现场的施工管理人员应向作业人员进行消防安全生产技术交底，包括 （　　） 等主要内容。", "options": ["施工过程中可能发生火灾的部位或环节", "逃生方法及路线", "施工过程应采取的防火措施", "动火作业审批流程", "初起火灾的扑救方法及注意事项"], "answer": [0, 1, 2, 4], "explanation": "6.1.8 施工作业前，施工现场的施工管理人员应向作业人员进行消防安全技术交底。消防安全技术交底应包括下列主要内容：\n1 施工过程中可能发生火灾的部位或环节。\n2 施工过程应采取的防火措施及应配备的临时消防设施。\n3 初起火灾的扑救方法及注意事项。\n4 逃生方法及路线。"},
  {"id": 1174, "type": "multiple", "question": "用于在建工程的 （　　） 等材料的燃烧性能等级，应符合设计要求。可燃材料及易燃易爆危险品应按计划限量进场。", "options": ["保温", "隔热", "防水", "防腐", "装饰"], "answer": [0, 2, 3, 4], "explanation": "6.2.1 用于在建工程的保温、防水、装饰及防腐等材料的燃烧性能等级应符合设计要求。"},
  {"id": 1175, "type": "multiple", "question": "用于在建工程的材料进场后，可燃材料宜存放于库房内，如露天存放时，应分类成垛堆放，并要求 （　　） 。", "options": ["垛高不应超过2m", "单垛体积不应超过50立方米", "单垛体积不应超过100 立方米", "垛与垛之间的最小间距不应小于1m", "垛与垛之间的最小间距不应小于2m"], "answer": [0, 1, 4], "explanation": "6.2.2 可燃材料及易燃易爆危险品应按计划限量进场。进场后，可燃材料宜存放于库房内，露天存放时，应分类成垛堆放，垛高不应超过 2m，单垛体积不应超过 50m3，垛与垛之间的最小间距不应小于 2m，且应采用不燃或难燃材料覆盖；易燃易爆危险品应分类专库储存，库房内应通风良好，并应设置严禁明火标志。"},
  {"id": 1176, "type": "multiple", "question": "室内使用油漆及其有机溶剂、乙二胺、冷底子油或其他可燃、易燃易爆危险品的物资作业时，应 （　　） 。", "options": ["保持良好通风", "作业场所严禁明火", "配备监护者，确保作业安全", "进行气体检测评估", "避免产生静电"], "answer": [0, 1, 4], "explanation": "6.2.3 室内使用油漆及其有机溶剂、乙二胺、冷底子油等易挥发产生易燃气体的物资作业时，应保持良好通风，作业场所严禁明火，并应避免产生静电。"},
  {"id": 1177, "type": "multiple", "question": "施工现场存放易燃、可燃材料的库房、木工加工场所、油漆配料房及防水作业场所不得使用 （　　） 灯具。", "options": ["明露", "高热", "热辐射光源", "强光源", "高压钠"], "answer": [0, 1, 3], "explanation": "施工现场用电，应严格执行有关“施工现场电气安全管理规定”，加强电源管理，防止发生电气火灾。施工现场存放易燃、可燃材料的库房、木工加工场所、油漆配料房及防水作业场所不得使用明露高热强光源灯具。"},
  {"id": 1178, "type": "multiple", "question": "调料间的防火要求包括 （　　） 等内容。", "options": ["有良好的通风", "采用防爆电气设备", "与油漆料库分开设置", "室内禁止一切火源", "不兼做休息室"], "answer": [0, 1, 2, 3, 4], "explanation": "油漆料库和调料间的防火要求\n（1）油漆料库与调料间应当分开设置，油漆料库和调料间与散发火花的场所应当保持一定的防火间距。\n（2）性质相抵触、灭火方法不同的品种，应当分库存放。\n（3）涂料和稀释剂的存放和管理应当符合《仓库防火安全管理规则》的要求。\n（4）调料间应当有良好的通风，并采用防爆型电器设备。室内杜绝一切火源。调料间不能兼做更衣室和休息室。\n（5）调料人员应当穿着不易产生静电的工作服、不带钉子的鞋。使用开启涂料和稀释剂包装的工具，应当采用不易产生火花型的工具。\n（6）调料人员应当严格遵守操作规程，调料间内不应存放超过当日加工所用的原料。"},
  {"id": 1179, "type": "multiple", "question": "地下工程施工的防火要求包括：安全出入口、疏散走道和楼梯的宽度应按 （　　） 的净宽计算。", "options": ["不小于1m", "不小于2m", "其通过人数每100人不小于1m", "其通过人数每100人不小于2m", "每个出入口的疏散人数不宜超过200人"], "answer": [0, 2], "explanation": "安全出口、疏散通道和楼梯的宽度应按其通过人数每100人不小于1m的净宽计算。"},
  {"id": 1180, "type": "multiple", "question": "下列关于地下工程施工的防火要求，正确的是 （　　） 。", "options": ["施工现场应有不少于2个出入口或坡道", "每个出入口的疏散人数不宜超过250人", "安全出入口、疏散走道和楼梯的最小净宽不应小于2m", "疏散指示标志灯距地面高度应为2m", "火灾事故灯在疏散通道的最低照度应不低于2lx"], "answer": [0, 1], "explanation": "地下工程施工中除遵守正常施工中的各项防火安全管理制度和要求，还应遵守以下防火安全要求：\n1.施工现场的临时电源线不宜直接敷设在墙壁或土墙上，须用绝缘材料架空安装。配电箱应采取防水措施，潮湿地段或渗水部位照明灯具应采取相应措施或安装防潮灯具。\n2.施工现场应有不少于两个出入口或坡道，施工距离长时，应适当增加出入口的数量。施工区面积不超过50㎡，且施工人员超过20人时，可只设一个直通地上的安全出口。\n3.安全出口、疏散通道和楼梯的宽度应按其通过人数每100人不小于1m的净宽计算。每个出入口的疏散人员不宜超过250人。安全出入口、疏散通道、楼梯的最小净宽不应小于1m。\n4.疏散通道、楼梯及坡道内，不宜设置突出物或堆放施工材料和机具。\n5.疏散通道、安全出入口、疏散马道（楼梯）、操作区域等部位，应设置火灾事故照明灯。火灾事故照明灯在上述部位的最低照度应不低于5lx（勒克斯）。\n6.疏散通道及其交叉口、拐弯处、安全出口处应设置疏散指示标志灯。疏散指示标志灯的间距不宜过大，距地面高度应为1-1.2m标志灯正前方0.5m的地面照度不应低于11x。\n7.火灾事故照明灯和疏散指示灯工作电源断电后，应能自动投合。\n8.地下室工程施工区域应设置消防给水管道和消火栓，消防给水管道可以与施工用水管道合用。特殊地下工程不能设置消防用水时，应配备足够数量的轻便消防器材。\n9.大面积油漆粉刷和喷漆应在地面施工，局部的粉刷可在地下工程内部进行，但一次粉刷的量不宜过多，同时在粉刷区域内禁止一切火源，加强通风。\n10.禁止中压式乙炔发生器在地下工程内部使用及存放。\n11.指定应急的疏散预案。"},
  {"id": 1181, "type": "multiple", "question": "应该设置疏散指示标志灯的地方包括 （　　） 等。", "options": ["疏散走道", "疏散走道的交叉口", "疏散走道的拐弯处", "楼梯", "安全出口"], "answer": [0, 1, 2, 4], "explanation": "疏散通道及其交叉口、拐弯处、安全出口处应设置疏散指示标志灯。"},
  {"id": 1182, "type": "multiple", "question": "地下工程施工区域应设置 （　　） 。", "options": ["消防给水管道", "消防水箱", "消防水池", "灭火栓", "稳压泵"], "answer": [0, 3], "explanation": "地下室工程施工区域应设置消防给水管道和消火栓，消防给水管道可以与施工用水管道合用。特殊地下工程不能设置消防用水时，应配备足够数量的轻便消防器材。"},
  {"id": 1183, "type": "multiple", "question": "锅炉房应远离 （　　） 等处。", "options": ["在建工程", "易燃可燃建筑", "生活区", "露天可燃材料堆场", "料库"], "answer": [0, 1, 3, 4], "explanation": "锅炉房宜建造在施工现场的下风方向,远离在建工程、易燃、可燃建筑、露天可燃材料堆场、料库等。"},
  {"id": 1184, "type": "multiple", "question": "下列关于锅炉房应符合的要求包括 （　　） 。", "options": ["锅炉房的门应向外开启", "锅炉正面与墙的距离不小于1m", "锅炉正面与墙的距离不小于2m", "锅炉与锅炉的距离不小于1m", "锅炉与锅炉之间的距离不小于2m"], "answer": [0, 3], "explanation": "锅炉房的门应向外开启，锅炉正面与墙的距离应不小于3m，锅炉与锅炉之间应保持不小于1m 的距离。"},
  {"id": 1185, "type": "multiple", "question": "锅炉烟道和烟囱与可燃物应保持一定的距离，下列说法正确的是 （　　） 。", "options": ["金属烟囱距可燃结构不小于100cm", "金属烟囱距已做防火保护层的可燃结构不小于100cm", "未采取消烟除尘措施的锅炉，其烟囱应设防火星帽", "砖砌的烟囱和烟道其内表面距可燃结构不小于10cm", "砖砌的烟囱和烟道其外表面距可燃结构不小于10cm"], "answer": [0, 2, 4], "explanation": "锅炉烟道和烟囱与可燃构件应保持一定的距离。金属烟囱距可燃结构不小于100cm;已做防火保护层的可燃结构不小于 70cm;砖砌的烟肉和烟道其内表面距可燃结构不小于50cm，其外表面不小于 10cm。\n未采取消烟除尘措施的锅炉，其烟肉应设防火星帽。"},
  {"id": 1186, "type": "multiple", "question": "冬季施工的防火要求中，对司炉工的要求包括 （　　） 等内容。", "options": ["严格值班检查制度", "工作时间决不允许离开工作岗位", "炉灰倒在指定地点", "禁止使用易燃液体点火", "下班时须做好交接班，并记录锅炉运行情况"], "answer": [0, 2, 3, 4], "explanation": "(7)严格值班检查制度。锅炉开着火以后，司炉人员不准离开工作岗位，值班时间绝不允许睡觉或做无关的事。\n(8)司炉人员下班时，须向下一班作好交接班，并记录锅炉运行情况。\n(9)炉灰倒在指定地点(不能带余火倒灰)，随时观察水温及水位，禁止使用易燃、可燃液体点火。\n选项B：司炉工不得随便离开工作岗位，如果要离开时，应有合格司炉工代替。"},
  {"id": 1187, "type": "multiple", "question": "禁止使用火炉的地方包括 （　　） 。", "options": ["木工房", "木工操作间", "料库", "使用高分子装修材料的房间", "油漆调料间"], "answer": [0, 1, 2, 3, 4], "explanation": "木工棚、材料库、清洗车间、喷漆车间、油漆配料间内不准生火或使用电炉取暖,周围15m内,严禁明火作业和吸烟。\n但在油漆、喷漆、油漆调料间、料库、使用高分子装修材料的装修阶段，禁止用火炉采暖。"},
  {"id": 1188, "type": "multiple", "question": "在木地板上安装火炉，必须设置炉盘。下列关于炉盘的要求，正确的是 （　　） 。", "options": ["有脚的火炉炉盘厚度不得小于12cm", "无脚的炉盘厚度不得小于15cm", "炉盘前应伸出炉门前50cm", "炉盘前应伸出炉后50cm", "火炉应根据需要设置高出炉身的火挡"], "answer": [0, 2, 4], "explanation": "在木地板上安装火炉，必须设置炉盘，有脚的火炉炉盘厚度不得小于12cm，无脚的火炉炉盘厚度不得小于1 8cm。炉盘应伸出炉门前50cm，伸出炉后左右各15cm。各种火炉应根据需要设置高出炉身的火档。"},
  {"id": 1189, "type": "multiple", "question": "各种小型加热火炉的金属烟囱穿过 （　　） 等必须设铁板，从烟囱周边到铁板的尺寸不得小于5cm。", "options": ["板壁", "挡风墙", "窗户", "门斗", "暖棚"], "answer": [0, 1, 2, 4], "explanation": "各种小型加热火炉的金属烟囱穿过板壁、窗户、挡风墙、暖棚等必须 设铁板,从烟囱周边到铁板的尺寸,不得小于 5cm。"},
  {"id": 1190, "type": "multiple", "question": "冬季施工中，高层建筑工程应采用 （　　） 材料进行保温。", "options": ["不燃", "难燃", "可燃", "易燃", "极易燃"], "answer": [0, 1], "explanation": "《建筑设计防火规范》（GB50016） 明确规定：\n高层建筑外保温材料的燃烧性能不应低于 B1 级（难燃），且外墙内保温材料宜采用不燃材料（A 级）；\n对于人员密集场所或特殊部位（如避难层、疏散通道等），必须使用不燃材料（A 级）。"},
  {"id": 1191, "type": "multiple", "question": "某一在建工地上有施工设备遭到雷击，导致现场4名施工人员受伤。建筑物顶部的 （　　） 等必须与顶部外露的其他金属物体连成一个整体的电气通路，且与避雷引下线连接可靠。", "options": ["避雷针", "避雷环", "避雷带", "绝缘带", "绝缘环"], "answer": [0, 2], "explanation": "建筑物顶部的避雷针、避雷带等必须与顶部外露的其他金属物体连成一个整体的电气通路,且与避雷引下线连接可靠。"},
  {"id": 1192, "type": "multiple", "question": "某地块施工现场，施工人员杜某在四楼楼面清理浇筑混凝土的钢筋笼时，不慎坠落。该事故由于临边防护设置不当导致人员从护栏空档处坠落，关于临边防护的要求说法正确的是 （　　） 。", "options": ["高处作业时，防护栏杆要采用密目式安全立网或工具式栏板封闭", "当防护栏杆高度大于1.5m时，应增设横杆，横杆间距不应大于600mm", "防护栏杆立杆底端当在土体上固定时，应采用预埋或打入方式固定", "防护栏杆立杆间距不应大于2m", "施工的楼梯口、楼梯平台和梯段边，应安装防护栏杆；外设楼梯口、楼梯平台和梯段边还应采用密目式安全立网封闭"], "answer": [2, 3, 4], "explanation": "防护栏杆应张挂密目式安全立网或其他材料封闭。\n当防护栏杆高度大于1.2m时，应增设横杆，横杆间距不应大于600mm；"},
  {"id": 1193, "type": "multiple", "question": "某项目在吊运作业中，工人钟某强行越过警戒线，信号工郭某拉拽劝阻无果，钢丝绳突然断裂，方钢滑脱坠地，反弹后导致钟某当场死亡。本次事故与钢丝绳有关，请问钢丝绳按钢丝表面状态分为 （　　） 。", "options": ["光面钢丝绳", "圆股钢丝绳", "镀锌钢丝绳", "钢芯钢丝绳", "三角股钢丝绳"], "answer": [0, 2], "explanation": "钢丝绳按表面状态主要分为光面钢丝绳、镀锌钢丝绳、涂塑钢丝绳等。"},
  {"id": 1194, "type": "multiple", "question": "某项目在吊运作业中，工人钟某强行越过警戒线，信号工郭某拉拽劝阻无果，钢丝绳突然断裂，方钢滑脱坠地，反弹后导致钟某当场死亡。以下关于钢丝绳报废标准，其安全程度决定因素有 （　　） 。", "options": ["绳股断裂", "暂时伸长的增加率", "弹性减小", "外部及内部腐蚀", "变形"], "answer": [0, 2, 3, 4], "explanation": "选项B. 暂时伸长的增加率\n非直接决定因素：暂时伸长（弹性伸长）是钢丝绳受力后的正常现象，其增加率通常不作为报废标准。但若出现异常快速伸长（如超过弹性极限的永久变形），可能反映内部断丝或结构损伤，需结合其他指标综合判断。"},
  {"id": 1195, "type": "multiple", "question": "某项目在吊运作业中，工人钟某强行越过警戒线，信号工郭某拉拽劝阻无果，钢丝绳突然断裂，方钢滑脱坠地，反弹后导致钟某当场死亡。起重机械作业时，应在作业区域周围设置明显的 （　　） ，禁止无关人员进入。", "options": ["警戒线", "警戒标志", "警戒栏杆", "警戒围墙", "负责人"], "answer": [0, 1, 2], "explanation": "【依据】《建筑施工起重吊装工程安全技术规范》JGJ 276-2012\n【解析】正确答案是A、B。题干对应的是起重吊装作业安全。 A项“警戒线”正确，它与题干所述“某项目在吊运作业中，工人钟某强行越过警戒线，”相对应。 B项“警戒标志”正确，它与题干所述“某项目在吊运作业中，工人钟某强行越过警戒线，”相对应。 C项“警戒栏杆”错误，它不符合题干限定的对象、程序或条件。 D项“警戒围墙”错误，它不符合题干限定的对象、程序或条件。 E项“负责人”错误，它不符合题干限定的对象、程序或条件。"},
  {"id": 1196, "type": "multiple", "question": "某项目在进行塔式起重机拆卸作业过程中，3名作业人员坠落死亡，直接经济损失约四百万余元。该起事故中，项目部经理安全生产履职不力，对事故发生负有责任。项目负责人对本项目安全生产管理全面负责，应当 （　　） 。", "options": ["监控危险性较大分部分项工程", "及时排查处理施工现场安全事故隐患", "发生事故时，应当按规定及时报告并开展现场救援", "设置安全生产管理机构", "保证安全生产投入"], "answer": [0, 1, 2], "explanation": "第十八条 项目负责人应当按规定实施项目安全生产管理，监控危险性较大分部分项工程，及时排查处理施工现场安全事故隐患，隐患排查处理情况应当记入项目安全管理档案；发生事故时，应当按规定及时报告并开展现场救援。\n工程项目实行总承包的，总承包企业项目负责人应当定期考核分包企业安全生产管理情况。"},
  {"id": 1197, "type": "multiple", "question": "某项目作业人员在进行混凝土泵车维修后测试时，从现场预留孔洞坠落身亡。当非垂直洞口短边长大于或等于1500毫米时，应 （　　） 。", "options": ["在洞口作业侧设置高度不小于1.2m的防护栏杆", "在洞口作业侧设置高度不小于1.5m的防护栏杆", "采用密目式安全立网或工具式栏板封闭", "洞口应采用安全平网封闭", "洞口应采用安全立网封闭"], "answer": [0, 2, 3], "explanation": "当非垂直洞口短边长≥1500mm时，应在洞口作业侧设置高度≥1.2m的防护栏杆，并应采用密目式安全立网或工具式栏板封闭；洞口应采用安全平网封闭。"},
  {"id": 1198, "type": "multiple", "question": "某热泵机组施工现场，由于现场构配件堆放混乱，1名作业人员在行走过程中摔倒，头部撞在地面钢制工件上致其身亡。生产经营单位必须遵守本法和其他有关安全生产的法律、法规，加强安全生产管理，构建 （　　） 双重预防机制。", "options": ["安全风险分级管控", "隐患排查治理", "风险防范化解", "安全风险评估与论证机制", "安全隐患排查管控"], "answer": [0, 1], "explanation": "新修订的《安全生产法》规定,生产经营单位必须遵守本法和其他有关安全生产的法律、法规,加强安全生产管理,构建安全风险分级管控和隐患排查治理双重预防机制。"},
  {"id": 1199, "type": "multiple", "question": "某地块项目工地内，1名作业人员擅自翻越护栏进行现场查看时坠落身亡。强调了作业人员未经 （　　） ，都不得上岗作业。", "options": ["教育培训", "教育培训考核不合格", "师徒带教", "登记", "应急演练"], "answer": [0, 1], "explanation": "根据《建设工程安全生产管理条例》，作业人员进入新的岗位或者新的施工现场前，应当接受安全生产教育培训。未经教育培训或者教育培训考核不合格的人员，不得上岗作业。"},
  {"id": 1200, "type": "multiple", "question": "某施工现场拆除闲置阁楼时，1名作业人员被掉落楼板砸中身亡。该项目是建筑拆除工程，人工拆除施工应该 （　　）  。", "options": ["从上至下", "逐层拆除", "不得垂直交叉作业", "分段进行", "由下至上"], "answer": [0, 1, 2, 3], "explanation": "人工拆除施工应从上至下逐层拆除，并应分段进行，不得垂直交叉作业。"},
  {"id": 1201, "type": "judge", "question": "安全生产管理一般包括四个部分，再往外延伸还会涉及安全生产管理的甲方服务等。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1202, "type": "judge", "question": "习总书记在2020年4月11日全国统筹推进新冠肺炎疫情防控和复工复产的关键时期作出指示，要针对安全生产事故主要特点和突出问题，层层压实责任，狠抓整改落实，强化风险防控，从根本上消除事故隐患，有效遏制重特大事故发生。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】习近平总书记关于安全生产重要论述\n【解析】该说法正确。题干中的主体、程序或控制数值与现行规定一致，属于直接记忆点。"},
  {"id": 1203, "type": "judge", "question": "安全生产管理主要是指人类社会在安全生产领域经长期研究和实践所形成的安全生产管理理论和实践经验。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1204, "type": "judge", "question": "党的十八大以来，以习近平同志为核心的党中央坚持以人民为中心的发展思想，顺应人民群众对美好生活的向往的需求，把增进人民福祉、促进人的全面发展作为一切工作的出发点和落脚点，在经济发展和生命安全、身体健康的关系上，坚持以人为本、生命至上。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】习近平总书记关于安全生产重要论述\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1205, "type": "judge", "question": "要始终把人民生命安全放在首位，以对党和人民高度负责的精神，完善制度、强化责任、加强管理、严格监管，把安全生产责任制落到实处，切实防范重特大安全生产事故的发生。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】习近平总书记关于安全生产重要论述\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1206, "type": "judge", "question": "总书记对安全生产工作作出指示，有事都是从没事中来的，各级领导干部要防患于未然，宁防十次空，不放一次松。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1207, "type": "judge", "question": "安全生产管理的原理包括系统原理、人本原理、预防原理和强制原理等。", "options": ["正确", "错误"], "answer": [0], "explanation": "安全生产管理包括系统原理、人本原理、 强制原理、预防原理、责任原理五个基本原理。"},
  {"id": 1208, "type": "judge", "question": "动态相关性原则是指现代高效率的管理必须在整体规划下明确分工，在分工基础上进行有效的综合。", "options": ["正确", "错误"], "answer": [1], "explanation": "【依据】安全管理学—系统原理、人本原理、预防原理、强制原理 / 建筑施工企业安全生产管理人员考核教材\n【解析】该说法错误。题干中的主体、程序、禁止性要求或控制数值与现行规定不一致。"},
  {"id": 1209, "type": "judge", "question": "在管理中必须把人的因素放在首位，体现以人为本的指导思想，这就是人本原理。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】安全管理学—系统原理、人本原理、预防原理、强制原理 / 建筑施工企业安全生产管理人员考核教材\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1210, "type": "judge", "question": "管理中的激励就是利用某种外部诱因的刺激调动人的积极性和创造性。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1211, "type": "judge", "question": "封闭原则指的是在任何一个管理系统内部，管理手段、管理过程等必须构成一个连续封闭的回路，才能形成有效的管理活动。", "options": ["正确", "错误"], "answer": [0], "explanation": "封闭原则定义:在任何一个管理系统内部,管理手段、管理过程等必须构成一个连续封闭的回路,才能形成有效的管理活动。"},
  {"id": 1212, "type": "judge", "question": "安全生产事故所产生的后果是随机的，反复发生同类事故，不一定产生相同的后果，这是事故损失的偶然性。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1213, "type": "judge", "question": "本质安全化原则来源于本质安全化理论，该原则的含义是指从一开始和从本质上实现了安全化，就从根本上消除事故发生的可能性，从而达到预防事故发生的目的。", "options": ["正确", "错误"], "answer": [0], "explanation": "本质安全化原则来源于本质安全化理论。该原则的含义是指从一开始和从本质上实现了安全化，就可以从根本上消除事故发生的可能，从而达到预防事故发生的目的。"},
  {"id": 1214, "type": "judge", "question": "系统安全理论是安全生产管理理论中事故致因理论中的一种。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】安全管理学—系统原理、人本原理、预防原理、强制原理 / 建筑施工企业安全生产管理人员考核教材\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1215, "type": "judge", "question": "能量意外释放理论认为，工业事故及其造成的伤害或损坏，通常都是生产过程中失去控制的能量转化和(或)能量消失的过程中发生的。", "options": ["正确", "错误"], "answer": [1], "explanation": "能量意外释放理论认为，工业事故及其造成的伤害或损坏，通常都是生产过程中失去控制的能量转化和【能量做功】的过程中发生的。"},
  {"id": 1216, "type": "judge", "question": "系统安全理论区别于传统安全理论的创新概念，其中认为：不可能根除一切危险源，但可以降低现有危险源的危险性。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1217, "type": "judge", "question": "在事故致因理论方面，改变了人们只注重操作人员的安全行为，而忽略硬件故障在事故致因中作用的传统观念，开始考虑如何通过改善物的系统可靠性来提高复杂系统的安全性，从而避免事故。", "options": ["正确", "错误"], "answer": [1], "explanation": "在事故致因理论方面，改变了人们只注重操作人员的【不安全行为】而忽略硬件的故障在事故致因中作用的传统观念，开始考虑如何通过改善物的系统的可靠性来提高复杂系统的安全性，从而避免事故。"},
  {"id": 1218, "type": "judge", "question": "安全教育对策和安全管理对策主要着眼于人的不安全行为问题。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1219, "type": "judge", "question": "安全生产法律，是特指中华人民共和国全国人民代表大会或中华人民共和国全国人民代表大会常务委员会制定的法律。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《中华人民共和国安全生产法》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1220, "type": "judge", "question": "根据《中华人民共和国立法法》的规定，部门规章之间、部门规章与地方政府规章之间具有同等效力，在各自权限范围内施行。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《中华人民共和国立法法》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1221, "type": "judge", "question": "《立法法》规定，同一机关制定的新的一般规定与旧的特别规定不一致时，由制定机关裁决。", "options": ["正确", "错误"], "answer": [0], "explanation": "第九十五条 地方性法规、规章之间不一致时，由有关机关依照下列规定的权限作出裁决：\n（一）同一机关制定的新的一般规定与旧的特别规定不一致时，由制定机关裁决；\n（二）地方性法规与部门规章之间对同一事项的规定不一致，不能确定如何适用时，由国务院提出意见，国务院认为应当适用地方性法规的，应当决定在该地方适用地方性法规的规定；认为应当适用部门规章的，应当提请全国人民代表大会常务委员会裁决；\n（三）部门规章之间、部门规章与地方政府规章之间对同一事项的规定不一致时，由国务院裁决。\n根据授权制定的法规与法律规定不一致，不能确定如何适用时，由全国人民代表大会常务委员会裁决。"},
  {"id": 1222, "type": "judge", "question": "特别法就是法规的某项特别规定、个性规定，一般法就是法规的普通规定、共性规定。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1223, "type": "judge", "question": "新修订的《安全生产法》新增了全员安全责任制的规定，就是要把全体员工的积极性和创造性调动起来，形成人人关心安全生产、人人提升安全素质、人人做好安全生产的局面。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《中华人民共和国安全生产法》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1224, "type": "judge", "question": "新修订的《安全生产法》增加了高危行业领域生产经营单位投保必须投保的规定。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《中华人民共和国安全生产法》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1225, "type": "judge", "question": "新修订的《安全生产法》规定，生产经营单位的主要负责人是本单位安全生产第一责任人，对本单位的安全生产工作全面负责。其他负责人对职责范围内的安全生产工作负责。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《中华人民共和国安全生产法》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1226, "type": "judge", "question": "新修改的《安全生产法》突出预防为主，提出建立安全风险评估与论证机制。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《中华人民共和国安全生产法》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1227, "type": "judge", "question": "新修订的《安全生产法》突出预防为主，增加了关注从业人员心理和行为分析的规定。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《中华人民共和国安全生产法》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1228, "type": "judge", "question": "新修订《安全生产法》加大了对中介服务机构失信行为的惩戒力度。增加“对违法行为情节严重的直接责任人员，吊销其相应资格和资质，十年内不得从事相关工作”。", "options": ["正确", "错误"], "answer": [1], "explanation": "【依据】《中华人民共和国安全生产法》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1229, "type": "judge", "question": "《建设工程安全生产条例》规定，建设单位、勘察单位、设计单位、施工单位、工程监理单位及其他与建设工程安全生产有关的单位，必须遵守安全生产法律、法规的规定，保证建设工程安全生产，依法承担建设工程安全生产责任。", "options": ["正确", "错误"], "answer": [0], "explanation": "第四条 建设单位、勘察单位、设计单位、施工单位、工程监理单位及其他与建设工程安全生产有关的单位，必须遵守安全生产法律、法规的规定，保证建设工程安全生产，依法承担建设工程安全生产责任。"},
  {"id": 1230, "type": "judge", "question": "《建设工程安全生产管理条例》规定“施工单位可以在尚未竣工的建筑物内设置员工集体宿舍。”", "options": ["正确", "错误"], "answer": [1], "explanation": "【依据】《建设工程安全生产管理条例》\n【解析】该说法错误。题干中的主体、程序、禁止性要求或控制数值与现行规定不一致。"},
  {"id": 1231, "type": "judge", "question": "国家鼓励施工单位为施工现场从事危险作业的人员办理意外伤害保险。意外伤害保险费由施工单位支付。", "options": ["正确", "错误"], "answer": [1], "explanation": "【应当】而不是鼓励\n第三十八条 施工单位应当为施工现场从事危险作业的人员办理意外伤害保险。\n意外伤害保险费由施工单位支付。实行施工总承包的，由总承包单位支付意外伤害保险费。意外伤害保险期限自建设工程开工之日起至竣工验收合格止。"},
  {"id": 1232, "type": "judge", "question": "《建设工程安全生产管理条例》规定“施工单位应当设立安全生产管理机构，配备专职和兼职安全生产管理人员。”", "options": ["正确", "错误"], "answer": [1], "explanation": "【依据】《建设工程安全生产管理条例》\n【解析】该说法错误。题干中的主体、程序、禁止性要求或控制数值与现行规定不一致。"},
  {"id": 1233, "type": "judge", "question": "《建设工程安全生产管理条例》规定“施工单位应当在施工组织设计中编制安全技术措施和施工现场临时用电方案，对达到一定规模的危险性较大的分部分项工程编制专项施工方案，并附具安全验算结果。”", "options": ["正确", "错误"], "answer": [0], "explanation": "第二十六条 施工单位应当在施工组织设计中编制安全技术措施和施工现场临时用电方案，对下列达到一定规模的危险性较大的分部分项工程编制专项施工方案，并附具安全验算结果，经施工单位技术负责人、总监理工程师签字后实施，由专职安全生产管理人员进行现场监督："},
  {"id": 1234, "type": "judge", "question": "《上海市建设工程质量和安全管理条例》明确施工企业在组织施工中应当按照施工组织设计文件和施工技术标准顺序施工，在危险性较大的分部工程、分项工程施工时，项目负责人、兼职安全管理人员必须在现场监督。", "options": ["正确", "错误"], "answer": [1], "explanation": "国家和本市规定的危险性较大的分部工程、分项工程施工时，项目负责人、专职安全管理人员应当进行现场监督。"},
  {"id": 1235, "type": "judge", "question": "《上海市建设工程质量和安全管理条例》明确首次上岗的施工作业人员，必须在进行不少于六个月的实习操作后方可正式上岗。", "options": ["正确", "错误"], "answer": [1], "explanation": "对于首次上岗的施工作业人员，施工单位或者劳务分包单位应当在其正式上岗前安排不少于三个月的实习操作。"},
  {"id": 1236, "type": "judge", "question": "《上海市建设工程质量和安全管理条例》规定，建设工程使用商品混凝土、钢筋等结构性建设工程材料的，建设单位应当在分部工程、分项工程验收和竣工验收时，要求供应单位对供应数量进行确认。", "options": ["正确", "错误"], "answer": [1], "explanation": "建设工程使用商品混凝土、钢筋等结构性建设工程材料的，【施工单位】应当在分部工程、分项工程验收和竣工验收时，要求供应单位对供应数量进行确认。"},
  {"id": 1237, "type": "judge", "question": "在法规和政策的关系中，法规的特点决定了政策的必要性。", "options": ["正确", "错误"], "answer": [1], "explanation": "法规和政策各有其特点和职能，在社会治理中发挥着不同的作用。它们相辅相成，共同构成了一个完整的法律体系和治理框架。"},
  {"id": 1238, "type": "judge", "question": "至2030年，安全生产工作总体方向可概括为：一条红线，十二字方针，三个着力点和五项基本原则。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干中的主体、程序或控制数值与现行规定一致，属于直接记忆点。"},
  {"id": 1239, "type": "judge", "question": "企业是生产经营活动的主体，是安全生产工作责任的间接承担主体。", "options": ["正确", "错误"], "answer": [1], "explanation": "企业是生产经营活动的主体,是安全生产工作责任的直接承担主体。"},
  {"id": 1240, "type": "judge", "question": "安全生产责任面对企业时，强调企业是安全生产的责任主体；面对政府及职能部门时，强调政府是安全生产的监管主体。", "options": ["正确", "错误"], "answer": [0], "explanation": "安全上有两个责任主体：\n①生产经营单位以及学校、医院、幼儿园、事业单位、人民团体、社会团体是安全生产的责任主体。必须履行安全生产责任主体义务，承担安全生产主体责任，预防生产安全事故、职业危害，并对发生生产安全事故、职业危害的后果承担全部责任。\n②政府及其职能部门是安全生产的监管主体，负责对本行政区域，本行业的安全生产工作实行全面领导和监督管理，并承担领导责任和监督管理责任。"},
  {"id": 1241, "type": "judge", "question": "《中共上海市委、上海市人民政府关于本市深化安全生产领域改革发展的实施意见》明确指出，企业法定代表人和实际控制人同为安全生产第一责任人。", "options": ["正确", "错误"], "answer": [0], "explanation": "企业实行安全生产责任制度，法定代表人和实际控制人同为安全生产第一责任人，主要技术负责人负有安全生产技术决策和指挥权，强化部门安全生产职责，落实一岗双责。"},
  {"id": 1242, "type": "judge", "question": "我国施工企业安全生产主体有一特点，它是通过一系列法律法规设定的，是一种国家意志。作为法定责任，无需企业认可就具备强制效力，不管企业知道与否都是适用的。", "options": ["正确", "错误"], "answer": [0], "explanation": "我国施工企业的安全生产主体责任是由一系列法律法规设定的，具有法定的强制效力。企业无需认可即可适用，且适用于所有在中国境内从事生产经营活动的企业。"},
  {"id": 1243, "type": "judge", "question": "一个施工项目现场会有若干个平行关系的承包商在同时作业，也存在施工总承包企业和建设单位直接发包的施工单位并存施工现场的局面，按照法律规定，这些企业之间应当签订安全生产管理协议的规定，企业各方依据安全生产管理协议的约定，承担安全生产责任。", "options": ["正确", "错误"], "answer": [0], "explanation": "《安全生产法》第四十五条“两个以上生产经营单位在同一作业区域内进行生产经营活动，可能危及对方生产安全的，应当签订安全生产管理协议，明确各自的安全生产管理职责和应当采取的安全措施，并指定专职安全生产管理人员进行安全检查与协调。”"},
  {"id": 1244, "type": "judge", "question": "根据《上海市建设工程质量和安全管理条例》的规定，施工单位按照国家和本市有关规定实行劳务分包的，劳务分包单位可以不具备相应的资质。", "options": ["正确", "错误"], "answer": [1], "explanation": "第三十二条施工单位按照国家和本市有关规定实行劳务分包的 ， 劳务分包单位应当具备相应的资质。"},
  {"id": 1245, "type": "judge", "question": "根据《安全生产法》的规定，建筑施工企业应当安排用于配备劳动防护用品、进行安全生产培训的经费。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《中华人民共和国安全生产法》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1246, "type": "judge", "question": "根据《建设工程安全生产管理条例》的规定，施工单位应当对管理人员和作业人员每年至少进行三次安全生产教育培训，其教育培训情况记入个人工作档案。安全生产教育培训考核不合格的人员，不得上岗。", "options": ["正确", "错误"], "answer": [1], "explanation": "施工单位应当对管理人员和作业人员每年至少进行一次安全生产教育培训，其教育培训情况记入个人工作档案。安全生产教育培训考核不合格的人员，不得上岗。"},
  {"id": 1247, "type": "judge", "question": "《安全生产法》规定，建筑施工企业应当关注从业人员的身体、心理状况和行为习惯，加强对从业人员的心理疏导、精神慰藉，严格落实岗位安全生产责任，防范从业人员行为异常导致事故发生。", "options": ["正确", "错误"], "answer": [0], "explanation": "生产经营单位应当关注从业人员的身体、心理状况和行为习惯，加强对从业人员的心理疏导、精神慰藉，严格落实岗位安全生产责任，防范从业人员行为异常导致事故发生。"},
  {"id": 1248, "type": "judge", "question": "《建筑法》规定，涉及建筑主体和承重结构变动的装修工程，建设单位应当在施工前委托原设计单位或者具有相应资质条件的设计单位提出设计方案；没有设计方案的，不得施工。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《中华人民共和国建筑法》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1249, "type": "judge", "question": "《建筑法》规定，房屋拆除应当由具备保证安全条件的建筑施工单位承担，由建筑施工单位专职安全生产管理人员对安全负责。", "options": ["正确", "错误"], "answer": [1], "explanation": "第五十条 房屋拆除应当由具备保证安全条件的建筑施工单位承担，由建筑施工单位负责人对安全负责。"},
  {"id": 1250, "type": "judge", "question": "根据《上海市建设工程质量和安全管理条例》规定，施工单位应当在建筑起重机械和整体提升脚手架、模板等自升式架设设施使用和拆除后，向建设行政管理部门或者其他有关部门登记。", "options": ["正确", "错误"], "answer": [1], "explanation": "施工单位应当在建筑起重机械和整体提升脚手架、模板等自升式架设设施使用和拆除【前】,向建设行政管理部门或者其他有关部门登记。"},
  {"id": 1251, "type": "judge", "question": "根据《建设工程安全生产管理条例》的规定，施工单位不得在尚未竣工的建筑物内设置员工集体宿舍。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建设工程安全生产管理条例》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1252, "type": "judge", "question": "根据《上海市建设工程质量和安全管理条例》规定，施工单位应当按照国家和本市有关规定，根据季节和天气特点，采取预警和安全防护措施；出现高温天气或者异常天气时，应当限制或者禁止室外露天作业。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《上海市建设工程质量和安全管理条例》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1253, "type": "judge", "question": "根据《建设工程安全生产管理条例》的规定，总承包单位和分包单位对分包工程的安全生产承担连带责任。", "options": ["正确", "错误"], "answer": [0], "explanation": "总承包单位和分包单位对分包工程的安全生产承担连带责任。分包单位应当服从总承包单位的安全生产管理，分包单位不服从管理导致生产安全事故的，由分包单位承担主要责任。"},
  {"id": 1254, "type": "judge", "question": "根据《建设工程安全生产管理条例》的规定，施工单位对因建设工程施工可能造成损害的毗邻建筑物、构筑物和地下管线等，应当采取一般防护措施。", "options": ["正确", "错误"], "answer": [1], "explanation": "根据《建设工程安全生产管理条例》的规定，施工单位对因建设工程施工可能造成损害的毗邻建筑物、构筑物和地下管线等，应当采取专项防护措施。"},
  {"id": 1255, "type": "judge", "question": "各类企业必须要落实\"党政同责\"的要求，党组织书记要和董事长、总经理共同对本企业的安全生产工作承担领导责任，也要抓安全、管安全，发生事故要依法依规一并追责。", "options": ["正确", "错误"], "answer": [0], "explanation": "各类企业必须要落实“党政同责”的要求,党组织书记要和董事长、总经理共同对本企业的安全生产工作承担领导责任,也要抓安全、管安全,发生事故要依法依规一并追责。"},
  {"id": 1256, "type": "judge", "question": "《安全生产法》规定，生产经营单位应当建立相应的机制，加强对安全生产责任制落实情况的监督考核，保证安全生产责任制的落实。", "options": ["正确", "错误"], "answer": [0], "explanation": "《安全生产法》第十九条规定:生产经营单位应当建立相应的机制,加强对安全生产责任制落实情况的监督考核,保证安全生产责任制的落实。"},
  {"id": 1257, "type": "judge", "question": "根据《安全生产法》的规定，建筑施工企业使用被派遣劳动者的，被派遣劳动者不需纳入本单位从业人员统一管理。", "options": ["正确", "错误"], "answer": [1], "explanation": "生产经营单位使用被派遣劳动者的，应当将被派遣劳动者纳入本单位从业人员统一管理，对被派遣劳动者进行岗位安全操作规程和安全操作技能的教育和培训。劳务派遣单位应当对被派遣劳动者进行必要的安全生产教育和培训。"},
  {"id": 1258, "type": "judge", "question": "某建筑施工企业使用了新设备，根据《安全生产法》的规定，必须了解、掌握其安全技术特性，采取有效的安全防护措施，并对从业人员进行专门的安全生产教育和培训。", "options": ["正确", "错误"], "answer": [0], "explanation": "①必须了解、掌握其安全技术特性;②必须采取有效的安全防护措施;③必须对从业人员进行专门的安全生产教育和培训。"},
  {"id": 1259, "type": "judge", "question": "根据《建设工程安全生产管理条例》的规定，登高架设作业人员，不需要按照国家有关规定经过专门的安全作业培训，也不需要取得特种作业操作资格证书，即可上岗作业。", "options": ["正确", "错误"], "answer": [1], "explanation": "第二十五条 垂直运输机械作业人员、安装拆卸工、爆破作业人员、起重信号工、登高架设作业人员等特种作业人员，必须按照国家有关规定经过专门的安全作业培训，并取得特种作业操作资格证书后，方可上岗作业。"},
  {"id": 1260, "type": "judge", "question": "根据《建设工程安全生产管理条例》的规定，施工单位应当向作业人员提供安全防护用具和安全防护服装，并书面告知危险岗位的操作规程和违章操作的危害。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建设工程安全生产管理条例》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1261, "type": "judge", "question": "根据《建筑法》的规定，建筑施工企业无需要为职工参加工伤保险并缴纳工伤保险费。", "options": ["正确", "错误"], "answer": [1], "explanation": "第四十八条 建筑施工企业应当依法为职工参加工伤保险缴纳工伤保险费。鼓励企业为从事危险作业的职工办理意外伤害保险，支付保险费。"},
  {"id": 1262, "type": "judge", "question": "根据《建设工程安全生产管理条例》的规定，施工单位应当鼓励全体员工自行办理意外伤害保险。意外伤害保险费由员工自行承担。", "options": ["正确", "错误"], "answer": [1], "explanation": "第三十八条 施工单位应当为施工现场从事危险作业的人员办理意外伤害保险。意外伤害保险费由施工单位支付。"},
  {"id": 1263, "type": "judge", "question": "根据《安全生产法》的规定，建筑施工企业应当按照国家有关规定将本单位重大危险源及有关安全措施、应急措施报有关地方人民政府应急管理部门和有关部门备案。", "options": ["正确", "错误"], "answer": [0], "explanation": "第四十条 第二款\n生产经营单位应当按照国家有关规定将本单位重大危险源及有关安全措施、应急措施报有关地方人民政府应急管理部门和有关部门备案。有关地方人民政府应急管理部门和有关部门应当通过相关信息系统实现信息共享。"},
  {"id": 1264, "type": "judge", "question": "根据《建设工程安全生产管理条例》的规定，对进入施工现场的建筑起重机械，施工单位只需核验其生产(制造)许可证、产品合格证。", "options": ["正确", "错误"], "answer": [1], "explanation": "第三十五条 施工单位在使用施工起重机械和整体提升脚手架、模板等自升式架设设施前，应当组织有关单位进行验收，也可以委托具有相应资质的检验检测机构进行验收；使用承租的机械设备和施工机具及配件的，由施工总承包单位、分包单位、出租单位和安装单位共同进行验收。验收合格的方可使用。\n《特种设备安全监察条例》规定的施工起重机械，在验收前应当经有相应资质的检验检测机构监督检验合格。\n施工单位应当自施工起重机械和整体提升脚手架、模板等自升式架设设施验收合格之日起30日内，向建设行政主管部门或者其他有关部门登记。登记标志应当置于或者附着于该设备的显著位置。"},
  {"id": 1265, "type": "judge", "question": "根据《建筑法》的规定，建筑施工企业针对专业性较强的工程项目，应当编制专项安全施工组织设计，并采取安全技术措施。", "options": ["正确", "错误"], "answer": [0], "explanation": "第三十八条 建筑施工企业在编制施工组织设计时，应当根据建筑工程的特点制定相应的安全技术措施；对专业性较强的工程项目，应当编制专项安全施工组织设计，并采取安全技术措施。"},
  {"id": 1266, "type": "judge", "question": "根据《建设工程安全生产管理条例》的规定，建设工程施工前，施工单位负责项目管理的技术人员应当对有关安全施工的技术要求向施工作业班组、作业人员作出详细说明，并由双方签字确认。", "options": ["正确", "错误"], "answer": [0], "explanation": "第二十七条 建设工程施工前，施工单位负责项目管理的技术人员应当对有关安全施工的技术要求向施工作业班组、作业人员作出详细说明，并由双方签字确认。"},
  {"id": 1267, "type": "judge", "question": "根据《建设工程安全生产管理条例》的规定，施工单位应当将施工现场的办公、生活区与作业区分开设置，并保持安全距离。", "options": ["正确", "错误"], "answer": [0], "explanation": "第二十九条 施工单位应当将施工现场的办公、生活区与作业区分开设置，并保持安全距离；办公、生活区的选址应当符合安全性要求。职工的膳食、饮水、休息场所等应当符合卫生标准。施工单位不得在尚未竣工的建筑物内设置员工集体宿舍。"},
  {"id": 1268, "type": "judge", "question": "根据《上海市建设工程质量和安全管理条例》的规定，出现高温天气或者异常天气时，应当限制或禁止室外露天作业。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《上海市建设工程质量和安全管理条例》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1269, "type": "judge", "question": "根据《建设工程安全生产管理条例》的规定，总承包单位和分包单位对分包工程的安全生产承担连带责任。分包单位应当服从总承包单位的安全生产管理，分包单位不服从管理导致生产安全事故的，由总包单位承担主要责任。", "options": ["正确", "错误"], "answer": [1], "explanation": "总承包单位和分包单位对分包工程的安全生产承担连带责任。分包单位应当服从总承包单位的安全生产管理，分包单位不服从管理导致生产安全事故的，由分包单位承担主要责任。"},
  {"id": 1270, "type": "judge", "question": "根据《建设工程安全生产管理条例》的规定，施工单位对因建设工程施工可能造成损害的毗邻建筑物、构筑物和地下管线等，应当采取专项防护措施。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建设工程安全生产管理条例》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1271, "type": "judge", "question": "根据《安全生产法》的规定，建筑施工企业应当建立应急救援组织；生产经营规模较小的，可以不建立应急救援组织，但应当指定专职的应急救援人员。", "options": ["正确", "错误"], "answer": [1], "explanation": "第八十二条 危险物品的生产、经营、储存单位以及矿山、金属冶炼、城市轨道交通运营、建筑施工单位应当建立应急救援组织；生产经营规模较小的，可以不建立应急救援组织，但应当指定兼职的应急救援人员。"},
  {"id": 1272, "type": "judge", "question": "根据《安全生产法》的规定，建筑施工企业安全生产管理人员在检查中发现重大事故隐患，向本单位有关负责人报告，有关负责人不及时处理的，安全生产管理人员可以向主管的负有安全生产监督管理职责的部门报告，接到报告的部门应当依法及时处理。", "options": ["正确", "错误"], "answer": [0], "explanation": "生产经营单位的安全生产管理人员在检查中发现重大事故隐患，依照前款规定向本单位有关负责人报告，有关负责人不及时处理的，安全生产管理人员可以向主管的负有安全生产监督管理职责的部门报告，接到报告的部门应当依法及时处理。"},
  {"id": 1273, "type": "judge", "question": "全面加强企业全员安全生产责任制工作，是推动企业落实安全生产主体责任的重要抓手，有利于减少企业违章指挥、违章作业、违反施工工序的“三违”现象发生。", "options": ["正确", "错误"], "answer": [1], "explanation": "（二）充分认识企业全员安全生产责任制的重要意义。全面加强企业全员安全生产责任制工作，是推动企业落实安全生产主体责任的重要抓手，有利于减少企业“三违”现象（违章指挥、违章作业、【违反劳动纪律】）的发生，有利于降低因人的不安全行为造成的生产安全事故，对解决企业安全生产责任传导不力问题，维护广大从业人员的生命安全和职业健康具有重要意义。"},
  {"id": 1274, "type": "judge", "question": "根据《建设工程安全生产管理条例》的规定，施工单位应当自施工起重机械和整体提升脚手架、模板等自升式架设设施验收合格之日起15日内，向建设行政主管部门或者其他有关部门登记。", "options": ["正确", "错误"], "answer": [1], "explanation": "《建设工程安全生产管理条例》（国务院令第393号） 第三十五条第三款 施工单位应当自施工起重机械和整体提升脚手架、模板等自升式架设设施验收合格之日起30日内，向建设行政主管部门或者其他有关部门登记。登记标志应当置于或者附着该设备的显著位置。"},
  {"id": 1275, "type": "judge", "question": "根据《建设工程安全生产管理条例》的规定，施工现场暂时停止施工的，施工单位应当做好现场防护，所需费用由施工方承担，或者按照合同约定执行。", "options": ["正确", "错误"], "answer": [1], "explanation": "施工现场暂时停止施工的，施工单位应当做好现场防护，所需费用由责任方承担，或者按照合同约定执行。"},
  {"id": 1276, "type": "judge", "question": "安全生产许可证是建筑施工企业实行安全生产许可证制度后，所必备的一个证件，它和企业资质联系在一起。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《安全生产许可证条例》 / 《建筑施工企业安全生产许可证管理规定》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1277, "type": "judge", "question": "根据《行政许可法》规定，直接涉及国家安全、公共安全、经济宏观调控、生态环境保护以及间接关系人身健康、生命财产安全等特定活动，需要按照法定条件予以批准的事项，可以设定行政许可。", "options": ["正确", "错误"], "answer": [1], "explanation": "根据《行政许可法》规定，直接涉及国家安全、公共安全、经济宏观调控、生态环境保护以及【直接】关系人身健康、生命财产安全等特定活动，需要按照法定条件予以批准的事项，可以设定行政许可。"},
  {"id": 1278, "type": "judge", "question": "2008年6月30日，中华人民共和国住房和城乡建设部关于印发《建筑施工企业安全生产许可证动态监管暂行办法》的通知，这是许可证进入动态阶段的重要标志。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑施工企业安全生产许可证动态监管暂行办法》\n【解析】该说法正确。题干中的主体、程序或控制数值与现行规定一致，属于直接记忆点。"},
  {"id": 1279, "type": "judge", "question": "建筑施工企业未取得安全生产许可证的，可以从事生产活动。", "options": ["正确", "错误"], "answer": [1], "explanation": "【依据】《安全生产许可证条例》 / 《建筑施工企业安全生产许可证管理规定》\n【解析】该说法错误。题干中的主体、程序、禁止性要求或控制数值与现行规定不一致。"},
  {"id": 1280, "type": "judge", "question": "国家对建筑施工企业实行安全生产许可制度，从严管控施工企业的安全生产。没有安全生产许可证的施工企业，不得从事生产经营。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《安全生产许可证条例》 / 《建筑施工企业安全生产许可证管理规定》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1281, "type": "judge", "question": "建设工程安全生产许可证由政府建设主管部门负责，生产许可证一般是质量技术监督局，或其它主管工业的部门。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《安全生产许可证条例》 / 《建筑施工企业安全生产许可证管理规定》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1282, "type": "judge", "question": "建筑施工企业破产、倒闭、撤销的，应当将安全生产许可证交回原安全生产许可证颁发管理机关予以注销。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《安全生产许可证条例》 / 《建筑施工企业安全生产许可证管理规定》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1283, "type": "judge", "question": "由建设部以及各省、自治区、直辖市人民政府建设主管部门颁发的安全生产许可证只可在企业注册地有效。", "options": ["正确", "错误"], "answer": [1], "explanation": "【依据】《安全生产许可证条例》 / 《建筑施工企业安全生产许可证管理规定》\n【解析】该说法错误。题干中的主体、程序、禁止性要求或控制数值与现行规定不一致。"},
  {"id": 1284, "type": "judge", "question": "建设主管部门在审核发放施工许可证时，对未取得安全生产许可证及安全生产许可证处于暂扣期内的，不得颁发施工许可证。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《安全生产许可证条例》 / 《建筑施工企业安全生产许可证管理规定》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1285, "type": "judge", "question": "建筑施工企业在12个月内第二次发生生产安全事故的，发生较大事故的，暂扣时限为在上一次暂扣时限的基础上再增加30日。", "options": ["正确", "错误"], "answer": [1], "explanation": "【依据】《生产安全事故报告和调查处理条例》\n【解析】该说法正确。题干中的主体、程序或控制数值与现行规定一致，属于直接记忆点。"},
  {"id": 1286, "type": "judge", "question": "安全生产许可证颁发管理机关作出准予颁发申请人安全生产许可证决定的，应当自决定之日起10个工作日内向申请人颁发、送达安全生产许可证；对作出不予颁发决定的，应当在10个工作日内书面通知申请人并说明理由。", "options": ["正确", "错误"], "answer": [0], "explanation": "安全生产许可证颁发管理机关作出准予颁发申请人安全生产许可证决定的，应当自决定之日起10个工作日内向申请人颁发、送达安全生产许可证；对作出不予颁发决定的，应当在10个工作日内书面通知申请人并说明理由。"},
  {"id": 1287, "type": "judge", "question": "颁发管理机关应建立建筑施工企业安全生产许可动态监管激励制度。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1288, "type": "judge", "question": "企业对告知承诺书、申请表进行企业法定代表人电子签名和企业电子签章，网上提交申请并按照告知承诺书约定上传部分书面材料，系统核对受理。", "options": ["正确", "错误"], "answer": [0], "explanation": "企业对告知承诺书、申请表进行企业法定代表人电子签名和企业电子签章,网上提交申请并按照告知承诺书约定上传部分书面材料,系统核对受理。"},
  {"id": 1289, "type": "judge", "question": "随着国家政治地位、经济水平的不断发展提高，简政放权、放管结合、优化服务改革，施工企业安全生产许可证推行电子化，简化流程。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《安全生产许可证条例》 / 《建筑施工企业安全生产许可证管理规定》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1290, "type": "judge", "question": "根据《建筑施工企业安全生产许可证管理规定》，建筑施工企业破产、倒闭、撤销的，不需要将安全生产许可证交回原安全生产许可证颁发管理机关予以注销。", "options": ["正确", "错误"], "answer": [1], "explanation": "建筑施工企业破产、倒闭、撤销的,应当将安全生产许可证交回原安全生产许可证颁发管理机关予以注销。"},
  {"id": 1291, "type": "judge", "question": "上海市住房和城乡建设管理委员会下发的《关于本市建筑施工企业安全生产许可证实施告知承诺电子化审批的通知》中指出，市、区建设行政管理部门在作出行政审批决定后，在一个月内，对无在建工地的企业的人员配置及社保情况进行核实。", "options": ["正确", "错误"], "answer": [1], "explanation": "市、区建设行政管理部门在作出行政审批决定后，在二个月内，对无在建工地的企业的人员配置及社保情况进行核实；"},
  {"id": 1292, "type": "judge", "question": "根据《建筑施工企业安全生产许可证管理规定》，建筑施工企业取得安全生产许可证后，可以降低安全生产条件。", "options": ["正确", "错误"], "answer": [1], "explanation": "建筑施工企业取得安全生产许可证后,不得降低安全生产条件。"},
  {"id": 1293, "type": "judge", "question": "安全生产许可证是针对生产的“结果”（即产品）颁发的许可证书。", "options": ["正确", "错误"], "answer": [1], "explanation": "【依据】《安全生产许可证条例》 / 《建筑施工企业安全生产许可证管理规定》\n【解析】该说法错误。题干中的主体、程序、禁止性要求或控制数值与现行规定不一致。"},
  {"id": 1294, "type": "judge", "question": "根据《建筑施工企业安全生产许可证动态监管暂行办法》的规定，建设单位或其委托的工程招标代理机构在编制资格预审文件和招标文件时，不需要建筑施工企业提供安全生产许可证，以及企业主要负责人、拟担任该项目负责人和专职安全生产管理人员（以下简称“三类人员”）相应的安全生产考核合格证书。", "options": ["正确", "错误"], "answer": [1], "explanation": "第二条 建设单位或其委托的工程招标代理机构在编制资格预审文件和招标文件时，应当明确要求建筑施工企业提供安全生产许可证，以及企业主要负责人、拟担任该项目负责人和专职安全生产管理人员（以下简称“三类人员”）相应的安全生产考核合格证书。"},
  {"id": 1295, "type": "judge", "question": "施工许可证申请主体资格是建筑施工企业。", "options": ["正确", "错误"], "answer": [1], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法错误。题干把关键表述写成“施工许可证”，规范要求应为“吊装令”。"},
  {"id": 1296, "type": "judge", "question": "根据《上海市建筑施工企业安全生产许可批后监督管理办法》，建筑施工企业负责人牵头，每年不少于一次组织开展安全生产管理体系自查自纠及安全生产条件自评工作，并保留相关记录。", "options": ["正确", "错误"], "answer": [0], "explanation": "第八条 建筑施工企业负责人牵头，每年不少于一次组织开展安全生产管理体系自查自纠及安全生产条件自评工作，并保留相关记录。\n企业发生生产安全事故后，应及时开展企业安全生产管理体系自查自纠及安全生产条件自评，并保留相关记录。"},
  {"id": 1297, "type": "judge", "question": "根据《上海市住房和城乡建设管理委员会关于本市建筑施工企业安全生产许可证实施告知承诺电子化审批的通知》的规定，具有建筑业资质的施工企业进行网上申请后，按告知承诺书的约定，通过网络系统上传承诺内容的书面资料，市住房城乡建设管理委通过审批系统，即时作出行政许可决定，已获得行政许可的企业即可使用安全生产许可证电子证照。", "options": ["正确", "错误"], "answer": [0], "explanation": "二、告知承诺电子化审批\n(一)网上申请\n本市具有建筑业企业资质的建筑施工企业，按照《建筑施工企业安全生产许可证管理规定》(建设部128号令)的要求，企业自查符合安全生产条件的，使用上海市“法人一证通”数字证书，登录上海一网通办选择部门“市住房城乡建设管理委”，在行政许可事项中选择“对建筑施工企业安全生产的许可”事项，点击“立即办理”按钮，启动安全生产许可证申请流程。\n企业线上收到《上海市住房和城乡建设管理委员会行政审批告知承诺书》(见附件1，以下简称“告知承诺书”)，确认并作出承诺后，在网上进行安全生产许可证申请填报。\n企业对告知承诺书、申请表进行企业法定代表人电子签名和企业电子签章，如实填报企业基本信息，网上提交申请，系统核对受理。\n(二)审批决定\n市住房城乡建设管理委通过审批系统，即时作出行政许可决定，并制作安全生产许可证电子证照，供申请人网上自行下载使用。\n(三)证书领取\n已获得行政许可的企业可使用上海市“法人一证通”数字证书，登录“市住房城乡建设管理委网上办事大厅”，自行下载、打印、使用安全生产许可证电子证照。\n(四)上传承诺书面资料\n申请人应按告知承诺书的约定，通过网络系统上传承诺内容的书面资料。"},
  {"id": 1298, "type": "judge", "question": "根据住建部的规定，建筑企业若是没有取得安全生产许可证，就没有资格参加投标。", "options": ["正确", "错误"], "answer": [0], "explanation": "投标需要根据建设部规定,建筑企业若是没有取得安全生产许可证,就没有资格参加投标。"},
  {"id": 1299, "type": "judge", "question": "建筑施工企业应不断完善安全生产管理体系，只需要确保施工现场管理始终满足安全生产许可条件即可，企业其他的安全生产条件可适当降低。", "options": ["正确", "错误"], "answer": [1], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法错误。题干中的主体、程序、禁止性要求或控制数值与现行规定不一致。"},
  {"id": 1300, "type": "judge", "question": "来自政府及安全管理机构的安全生产检查，一般都会检查到是否具备在有效期内的安全生产许可证。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《安全生产许可证条例》 / 《建筑施工企业安全生产许可证管理规定》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1301, "type": "judge", "question": "安全生产管理机构是指企业安全生产委员会、企业专门安全管理机构和工程项目安全生产领导小组。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑施工企业安全生产管理机构设置及专职安全生产管理人员配备办法》 / 《建筑施工企业主要负责人、项目负责人和专职安全生产管理人员安全生产管理规定》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1302, "type": "judge", "question": "安全生产委员会是企业法人建立的安全生产领导机构。", "options": ["正确", "错误"], "answer": [1], "explanation": "安全生产委员会是企业法人必须依法建立的安全生产决专策机构，一般由企业法人或其委托代理人牵头负责，企业各分管领导、各职能部门负责人为成员，任务是研究、分析和解决企业重大安全生产属问题。安全管理机构负责落实日产工作，遇到重大问题，要及时向安全生产委员会报告，由安委会决策。"},
  {"id": 1303, "type": "judge", "question": "工程项目经理部应根据工程规模大小配备专职安全员。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1304, "type": "judge", "question": "《建筑法》规定：“建筑施工企业应当建立健全劳动安全教育培训制度，加强对企业安全生产的教育培训，未经安全生产教育培训的人员，不得上岗作业。”", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《中华人民共和国建筑法》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1305, "type": "judge", "question": "根据《建筑施工项目经理质量安全责任十项规定》的要求，建筑施工项目经理必须按规定取得相应执业资格和安全生产考核合格证书；合同约定的项目经理必须在岗履职，不得违反规定同时在两个及两个以上的工程项目担任项目经理。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑施工项目经理质量安全责任十项规定》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1306, "type": "judge", "question": "根据《上海市建筑施工企业主要负责人、项目负责人和专职安全生产管理人员安全生产考核发证管理办法》的规定，外省市建筑施工企业“三类人员”，不必经本市“三类人员”安全生产知识继续教育培训考试合格，直接可在沪持证上岗从业。", "options": ["正确", "错误"], "answer": [1], "explanation": "外省市建筑施工企业“三类人员”，应经本市“三类人员”安全生产知识继续教育培训考试合格，方可在沪持证上岗从业。"},
  {"id": 1307, "type": "judge", "question": "企业安管机构是指企业安全生产委员会、企业专门安全管理机构和工程项目安全生产领导小组。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑施工企业安全生产管理机构设置及专职安全生产管理人员配备办法》 / 《建筑施工企业主要负责人、项目负责人和专职安全生产管理人员安全生产管理规定》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1308, "type": "judge", "question": "企业安委会的任务是研究、分析和解决企业重大安全生产问题。", "options": ["正确", "错误"], "answer": [0], "explanation": "企业安全生产委员会一般由企业主要负责人、分管负责人和各职能部门负责人组成，主要职责是定期分析企业安全生产形势，统筹、指导、督促企业安全生产工作,研究、协调、解决安全生产重大问题。"},
  {"id": 1309, "type": "judge", "question": "工程项目经理部是施工企业二线管理机构。", "options": ["正确", "错误"], "answer": [1], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法错误。题干中的主体、程序、禁止性要求或控制数值与现行规定不一致。"},
  {"id": 1310, "type": "judge", "question": "工程项目安全生产领导小组应该建立安全生产领导小组成员轮流安全生产值日制度，解决和处理施工生产中的安全问题并进行巡回检查。", "options": ["正确", "错误"], "answer": [0], "explanation": "建立安全生产值班制度,安全生产领导小组成员轮流值日,解决和处理施工生产中的安全问题并进行巡回安全生产监督检查。"},
  {"id": 1311, "type": "judge", "question": "工程项目实行总承包的，总承包企业应当与分包企业签订安全生产协议，明确双方安全生产责任。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1312, "type": "judge", "question": "施工单位应当建立健全安全生产责任制度和安全生产教育培训制度，制定安全生产规章制度和操作规程，保证本单位安全生产条件所需资金的投入，对所承担的建设工程进行定期和专项安全检查，并做好安全检查记录。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建设工程安全生产管理条例》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1313, "type": "judge", "question": "根据住建部令（第17号）的规定，安全生产考核合格证书有效期为2年，证书在全国范围内有效。", "options": ["正确", "错误"], "answer": [1], "explanation": "第九条 安全生产考核合格证书有效期为3年，证书在全国范围内有效。\n证书式样由国务院住房城乡建设主管部门统一规定。"},
  {"id": 1314, "type": "judge", "question": "根据住建部令（第17号）的规定，“安管人员”应当在安全生产考核合格证书有效期届满前3个月内，由本人通过受聘企业向任意考核机关申请证书延续。", "options": ["正确", "错误"], "answer": [1], "explanation": "第十条 安全生产考核合格证书有效期届满需要延续的，“安管人员”应当在有效期届满前3个月内，由本人通过受聘企业向原考核机关申请证书延续。准予证书延续的，证书有效期延续3年。"},
  {"id": 1315, "type": "judge", "question": "根据住建部令（第17号）的规定，某建筑施工企业“安管人员”的安全生产考核合格证书遗失，应通过其受聘企业向原安全生产考核合格证书考核机关声明作废并申请补办。", "options": ["正确", "错误"], "answer": [1], "explanation": "第十二条 “安管人员”遗失安全生产考核合格证书的，应当在公共媒体上声明作废，通过其受聘企业向原考核机关申请补办。考核机关应当在受理申请之日起5个工作日内办理完毕。"},
  {"id": 1316, "type": "judge", "question": "根据《建筑施工企业安全生产管理机构设置及专职安全生产管理人员配备办法》的规定，建设工程项目的专职安全生产管理人员应当定期将项目安全生产管理情况报告企业安全生产管理机构。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑施工企业安全生产管理机构设置及专职安全生产管理人员配备办法》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1317, "type": "judge", "question": "根据《建筑施工企业负责人及项目负责人施工现场带班暂行办法》的规定，企业负责人带班检查是指由建筑施工企业负责人带队实施对工程项目质量安全生产状况及项目负责人带班生产情况的检查。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑施工企业负责人及项目负责人施工现场带班暂行办法》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1318, "type": "judge", "question": "根据《建筑施工企业负责人及项目负责人施工现场带班暂行办法》的规定，项目负责人每月带班生产时间不得少于本月工作日的80%。因其他事务需离开施工现场时，应向工程项目的建设单位请假，经批准后方可离开。离开期间应委托项目相关负责人负责其外出时的日常工作。", "options": ["正确", "错误"], "answer": [1], "explanation": "第十一条 项目负责人每月带班生产时间不得少于本月【施工】时间的80%。因其他事务需离开施工现场时，应向工程项目的建设单位请假，经批准后方可离开。离开期间应委托项目相关负责人负责其外出时的日常工作。"},
  {"id": 1319, "type": "judge", "question": "根据《上海市建筑施工企业施工现场项目管理机构关键岗位人员配备指南》的规定，建筑工程、装修工程中，建筑面积大于1万平方米，小于等于5万平方米时，施工现场项目管理机构关键岗位人员总人数不少于13人。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《上海市建筑施工企业施工现场项目管理机构关键岗位人员配备指南》\n【解析】该说法正确。题干中的主体、程序或控制数值与现行规定一致，属于直接记忆点。"},
  {"id": 1320, "type": "judge", "question": "根据《上海市建筑施工企业主要负责人、项目负责人和专职安全生产管理人员安全生产考核发证管理办法（试行）》的规定，本市建筑施工企业“三类人员”证书实行电子证书管理。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《上海市建筑施工企业主要负责人、项目负责人和专职安全生产管理人员安全生产考核发证管理办法（试行）》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1321, "type": "judge", "question": "根据《上海市建设工程项目经理质量安全管理履职规定》，项目经理变更后，施工单位应及时报建设行政主管部门进行网上变更。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《上海市建设工程项目经理质量安全管理履职规定》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1322, "type": "judge", "question": "根据《关于进一步贯彻落实建筑施工企业负责人及项目负责人施工现场带班制度的通知》的规定，企业负责人应当对施工企业项目经理的到岗情况进行复核，并对带班情况予以记录，并作为对施工单位安全生产标准达标的复核依据之一。", "options": ["正确", "错误"], "answer": [1], "explanation": "监理单位应当对施工企业项目经理的到岗情况进行复核，并对带班情况予以记录，并作为对施工单位安全生产标准达标的复核依据之一。建设单位应采取有效措施督促施工单位、监理单位带班生产的实施。"},
  {"id": 1323, "type": "judge", "question": "标准要由权威机构批准发布，在相关领域有技术权威，为社会所公认。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1324, "type": "judge", "question": "标准有两种存在形式，一种是文本标准，另一种是实物标准，也就是标准样品。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1325, "type": "judge", "question": "推荐性国家标准一经发布，必须强制执行。", "options": ["正确", "错误"], "answer": [1], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法错误。题干中的主体、程序、禁止性要求或控制数值与现行规定不一致。"},
  {"id": 1326, "type": "judge", "question": "安全生产标准化是指通过建立安全生产责任制，制定安全管理制度和操作规程，排查治理隐患和监控重大危险源，建立预防机制，规范生产行为，使各生产环节符合有关安全生产法律法规和标准规范的要求，人（人员）、机（机械）、料（材料）、法（工法）、环（环境）、测（测量）处于良好的生产状态，并持续改进。", "options": ["正确", "错误"], "answer": [0], "explanation": "安全生产标准化，是指通过建立安全生产责任制，制定安全管理制度和操作规程，排查治理隐患和监控重大危险源，建立预防机制，规范生产行为，使各生产环节符合有关安全生产法律法规和标准规范的要求，人（人员）、机（机械）、料（材料）、法（工法）、环（环境）、测（测量）处于良好的生产状态，并持续改进，不断加强企业安全生产规范化建设。"},
  {"id": 1327, "type": "judge", "question": "安全生产责任制只需要落实到企业负责人，不需要落实到每个从业人员。", "options": ["正确", "错误"], "answer": [1], "explanation": "【依据】《中华人民共和国安全生产法》\n【解析】该说法错误。题干中的主体、程序、禁止性要求或控制数值与现行规定不一致。"},
  {"id": 1328, "type": "judge", "question": "施工企业在推进安全生产标准化建设中，除要依据国家标准化法律、行政法规外，还要与时俱进地遵守和执行国家标准行政主管部门、安全生产行政主管部门、建设行政主管部门颁布的涉及建筑施工安全生产标准化建设有关的部门规章和政策。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《企业安全生产标准化基本规范》 / 《中华人民共和国标准化法》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1329, "type": "judge", "question": "根据《建筑施工安全生产标准化考评暂行办法》规定，项目完工办理竣工验收后，建筑施工企业应当向项目考评主体提交项目安全生产标准化自评材料。", "options": ["正确", "错误"], "answer": [1], "explanation": "【依据】《建筑施工安全生产标准化考评暂行办法》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1330, "type": "judge", "question": "《关于贯彻落实<上海市建筑施工安全生产标准化考评规范>若干事项的通知》中提出了强化管理目标，施工项目在安全生产标准化开工申报时，应明确相关管理目标，如实填报相关管理信息。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《关于贯彻落实<上海市建筑施工安全生产标准化考评规范>若干事项的通知》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1331, "type": "judge", "question": "《关于开展建筑施工安全生产标准化考评工作的指导意见》指出，开展建筑施工安全生产标准化考评工作的目的是规范建筑施工企业及施工项目安全生产管理，全面落实安全生产责任制，加大安全生产投入，改善安全生产条件，增强从业人员安全素质，提高事故预防能力，促进建筑安全生产形势持续稳定好转。", "options": ["正确", "错误"], "answer": [0], "explanation": "考评目的 规范建筑施工企业及施工项目安全生产管理，全面落实安全生产责任制，加大安全生产投入，改善安全生产条件，增强从业人员安全素质，提高事故预防能力，促进建筑安全生产形势持续稳定好转。"},
  {"id": 1332, "type": "judge", "question": "《关于开展建筑施工安全生产标准化考评工作的指导意见》指出，建筑施工企业在申请安全生产许可证延期时，应当提交近五年企业安全生产标准化年度自评报告", "options": ["正确", "错误"], "answer": [1], "explanation": "建筑施工企业在申请安全生产许可证延期时，应当提交近三年企业安全生产标准化年度自评报告。"},
  {"id": 1333, "type": "judge", "question": "。《建筑施工安全生产标准化考评暂行办法》明确，建筑施工安全生产标准化考评，建筑施工项目实行施工总承包的，施工总承包单位对分包的项目不用负责。", "options": ["正确", "错误"], "answer": [1], "explanation": "【依据】《建筑施工安全生产标准化考评暂行办法》\n【解析】该说法错误。题干中的主体、程序、禁止性要求或控制数值与现行规定不一致。"},
  {"id": 1334, "type": "judge", "question": "《建筑施工安全生产标准化考评暂行办法》明确，建筑施工安全生产标准化考评，项目考评结果告知书中应包括项目建设、监理、施工总承包、专业承包等单位及其项目主要负责人信息。", "options": ["正确", "错误"], "answer": [0], "explanation": "项目考评结果告知书中应包括项目建设、监理、施工总承包、专业承包等单位及其项目主要负责人信息。"},
  {"id": 1335, "type": "judge", "question": "《建筑施工安全生产标准化考评暂行办法》明确，建筑施工项目有发生劳动纠纷的，项目安全生产标准化评定为不合格。", "options": ["正确", "错误"], "answer": [1], "explanation": "【依据】《建筑施工安全生产标准化考评暂行办法》\n【解析】该说法错误。题干中的主体、程序、禁止性要求或控制数值与现行规定不一致。"},
  {"id": 1336, "type": "judge", "question": "《建筑施工安全生产标准化考评暂行办法》明确，建筑施工安全生产标准化考评，项目竣工验收时建筑施工企业未提交项目自评材料的，视同项目考评不合格。", "options": ["正确", "错误"], "answer": [0], "explanation": "第十九条 项目竣工验收时建筑施工企业未提交项目自评材料的，视同项目考评不合格。"},
  {"id": 1337, "type": "judge", "question": "《建筑施工安全生产标准化考评暂行办法》明确，企业近三年所承建的项目发生一般生产安全责任事故的，企业安全生产标准化评定为不合格。", "options": ["正确", "错误"], "answer": [1], "explanation": "【依据】《建筑施工安全生产标准化考评暂行办法》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1338, "type": "judge", "question": "《上海市建筑施工安全生产标准化考评规范》规定，总包的项目负责人负责每月组织各分包，对施工项目及日巡查情况进行全面检查，并督促责任单位落实整改，检查和整改情况及时进行网上填报。", "options": ["正确", "错误"], "answer": [1], "explanation": "总包的项目负责人负责每周组织各分包，对施工项目及日巡查情况进行全面检查，并督促责任单位落实整改，检查和整改情况及时进行网上填报（详见附表一）。"},
  {"id": 1339, "type": "judge", "question": "《上海市建筑施工安全生产标准化考评规范》规定，对分包的月度考评连续3个月及以上为“不合格，分包竣工确认等级为不合格。", "options": ["正确", "错误"], "answer": [1], "explanation": "有下列情形之一的，对分包的竣工确认及复核为“不合格”。\n1.对分包的月度考评1/3及以上不合格；\n2.对分包的月度考评连续2个月及以上为“不合格”；"},
  {"id": 1340, "type": "judge", "question": "《上海市建筑施工安全生产标准化考评规范》规定，季度确认总次数2/3及以上不合格的，施工项目安全生产标准化竣工确认等级为“不合格”。", "options": ["正确", "错误"], "answer": [1], "explanation": "（二）有下列情形之一的，施工项目安全生产标准化竣工确认为“不合格”：\n1.季度确认总次数 1/3 及以上不合格；\n2.季度确认3次及以上不合格；\n3.季度确认连续2次及以上不合格。"},
  {"id": 1341, "type": "judge", "question": "“关于贯彻落实《上海市建筑施工安全生产标准化考评规范》（2016版）若干事项的通知（沪建安质监(2017)57号）”指出，安全生产标准化工作应当围绕班组的标准化和文件资料的标准化等内容全面开展。", "options": ["正确", "错误"], "answer": [1], "explanation": "安全生产标准化工作应当围绕以建筑行业、企业、施工现场、班组各层面安全管理为主的“管理的标准化”、以建筑施工现场人员安全行为为主的“人的标准化”、以建筑施工现场实物状态安全为主的“物的标准化”等三个方面的内容全面开展。\n分析：安全生产标准化工作应当围绕管理的标准化、人的标准化和物的标准化三个方面全面开展，而班组标准化是管理标准化中的一个重要环节。"},
  {"id": 1342, "type": "judge", "question": "“关于贯彻落实《上海市建筑施工安全生产标准化考评规范》（2016版）若干事项的通知（沪建安质监(2017)57号）”规定，总包企业应如实对分包进行月度和竣工考评。总包对分包的“不合格”考评结论，影响总包的评级。", "options": ["正确", "错误"], "answer": [1], "explanation": "总包企业和施工项目应如实对分包进行月度和竣工考评。总包对分包的“不合格”考评结论,不影响管理到位的总包的评级。"},
  {"id": 1343, "type": "judge", "question": "开挖深度超过3m（含3m）的基坑（槽）的土方开挖、支护、降水工程，不属于危险性较大的分部分项工程。", "options": ["正确", "错误"], "answer": [1], "explanation": "危险性较大的分部分项工程清单 (一)基坑支护、降水工程 开挖深度超过 3m(含 3m)或虽未超过 3m 但地质条件和周边环境复杂的基坑 (槽)支护、降水工程。"},
  {"id": 1344, "type": "judge", "question": "根据《危险性较大的分部分项工程安全管理规定》（住建部令第37号），高度小于支撑水平投影宽度且相对独立无联系构件的混凝土模板支撑工程，属于危险性较大的分部分项工程。", "options": ["正确", "错误"], "answer": [1], "explanation": "高度大于支撑水平投影宽度且相对独立无联系构件的混凝土模板支撑工程。"},
  {"id": 1345, "type": "judge", "question": "起重量200KN及以上的起重吊装工程，高度150m及以上内爬起重设备的拆除工程专项施工方案，均应组织专家进行论证。", "options": ["正确", "错误"], "answer": [1], "explanation": "起重量300kN及以上的起重设备安装工程；高度200m及以上内爬起重设备的拆除工程。"},
  {"id": 1346, "type": "judge", "question": "凡是危险性较大的分部分项工程，施工单位应当在施工前组织工程技术人员编制专项施工方案。", "options": ["正确", "错误"], "answer": [0], "explanation": "《危险性较大的分部分项工程安全管理规定》\n第十条 施工单位应当在危大工程施工前组织工程技术人员编制专项施工方案。\n实行施工总承包的，专项施工方案应当由施工总承包单位组织编制。危大工程实行分包的，专项施工方案可以由相关专业分包单位组织编制。"},
  {"id": 1347, "type": "judge", "question": "危大工程实行分包的，专项施工方案不得由相关专业分包单位组织编制。", "options": ["正确", "错误"], "answer": [1], "explanation": "危大工程实行分包的,专项施工方案可以由相关专业分包单位组织编制。"},
  {"id": 1348, "type": "judge", "question": "超过一定规模的危险性较大的分部分项工程，施工单位应当组织召开专家论证会对专项施工方案进行论证。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建设工程安全生产管理条例》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1349, "type": "judge", "question": "对于超过一定规模的危险性较大的分部分项工程，专家论证前专项施工方案应当通过施工单位审核和总监理工程师审查。", "options": ["正确", "错误"], "answer": [0], "explanation": "第十二条 对于超过一定规模的危大工程，施工单位应当组织召开专家论证会对专项施工方案进行论证。实行施工总承包的，由施工总承包单位组织召开专家论证会。专家论证前专项施工方案应当通过施工单位审核和总监理工程师审查。"},
  {"id": 1350, "type": "judge", "question": "为了保证专家的专业和公正性，施工单位应当从企业专家库中选取5名以上符合专业要求且与评审项目无利益相关的专家进行论证。", "options": ["正确", "错误"], "answer": [1], "explanation": "专家应当从地方人民政府住房城乡建设主管部门建立的专家库中选取,符合专业要求且人数不得少于5名。与本工程有利害关系的人员不得以专家身份参加专家论证会。"},
  {"id": 1351, "type": "judge", "question": "对于危险性较大的分部分项工程现场安全管理，施工现场管理人员应当向作业人员进行安全技术交底，并由双方共同签字确认。", "options": ["正确", "错误"], "answer": [1], "explanation": "施工现场管理人员应当向作业人员进行安全技术交底，并由双方和项目专职安全生产管理人员共同签字确认。"},
  {"id": 1352, "type": "judge", "question": "施工单位一般应按照专项施工方案组织施工，可根据施工条件、工期进度等现场实际情况对专项施工方案进行调整修改后实施。", "options": ["正确", "错误"], "answer": [1], "explanation": "因规划调整、设计变更等原因确需调整的,修改后的专项施工方案必须重新执行审核和论证程序。"},
  {"id": 1353, "type": "judge", "question": "对于危险性较大的分部分项工程现场安全管理，项目负责人应当对专项施工方案实施情况进行现场监督。", "options": ["正确", "错误"], "answer": [1], "explanation": "第十七条 施工单位应当对危大工程施工作业人员进行登记，项目负责人应当在施工现场履职。\n项目专职安全生产管理人员应当对专项施工方案实施情况进行现场监督，对未按照专项施工方案施工的，应当要求立即整改，并及时报告项目负责人，项目负责人应当及时组织限期整改。"},
  {"id": 1354, "type": "judge", "question": "对于按照规定验收合格的危险性较大的分部分项工程，需经施工单位项目技术负责人及施工单位项目负责人签字确认后，方可进入下一道工序。", "options": ["正确", "错误"], "answer": [1], "explanation": "对于按照规定验收合格的危险性较大的分部分项工程，需经施工单位项目技术负责人及项目总监理工程师签字确认后，方可进入下一道工序。"},
  {"id": 1355, "type": "judge", "question": "根据《危险性较大的分部分项工程安全管理规定》，危险性较大的分部分项工程发生险情或者事故时，施工单位应当立即采取应急处置措施，并报告工程所在地住房城乡建设主管部门。建设、勘察、设计等单位应当配合监理、施工单位开展应急抢险工作。", "options": ["正确", "错误"], "answer": [1], "explanation": "第二十二条 危大工程发生险情或者事故时，施工单位应当立即采取应急处置措施，并报告工程所在地住房城乡建设主管部门。建设、勘察、设计、监理等单位应当配合施工单位开展应急抢险工作。"},
  {"id": 1356, "type": "judge", "question": "监理单位的专项施工方案审查、专项巡视检查等资料应纳入施工单位的危大工程安全管理档案。", "options": ["正确", "错误"], "answer": [1], "explanation": "监理单位危大工程安全管理档案\n监理单位应当将监理实施细则、专项施工方案审查、专项巡视检查、验收及整改等相关资料纳入档案管理。\n施工单位危大工程安全管理档案\n施工单位应当将专项施工方案及审核、专家论证、交底、现场检查、验收及整改等相关资料纳入档案管理。"},
  {"id": 1357, "type": "judge", "question": "根据《安全生产法》规定，生产经营单位应当建立重大危险源综合管控制度，按照安全风险分级采取相应的管控措施。", "options": ["正确", "错误"], "answer": [1], "explanation": "第四十一条 生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。"},
  {"id": 1358, "type": "judge", "question": "根据《危险性较大的分部分项工程安全管理规定》，危险性较大的分部分项工程及超过一定规模的危险性较大的分部分项工程范围由国务院住房城乡建设主管部门制定。", "options": ["正确", "错误"], "answer": [0], "explanation": "危大工程及超过一定规模的危大工程范围由国务院住房城乡建设主管部门制定。"},
  {"id": 1359, "type": "judge", "question": "施工单位应当按照《危险性较大的分部分项工程安全管理规定》，对危险性较大的分部分项工程进行施工监测，发现有危及人身安全的紧急情况，应当立即组织作业人员撤离施工现场。", "options": ["正确", "错误"], "answer": [1], "explanation": "施工单位应当按照规定对危大工程进行施工监测和安全巡视，发现危及人身安全的紧急情况，应当立即组织作业人员撤离危险区域。"},
  {"id": 1360, "type": "judge", "question": "根据《上海市建筑玻璃幕墙管理办法》，施工单位应当按照国家和本市相关技术标准以及经审查合格的施工图设计文件进行玻璃幕墙的施工。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《上海市建筑玻璃幕墙管理办法》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1361, "type": "judge", "question": "根据《装配整体式混凝土结构工程施工安全管理规定》，堆场加固、构件堆放架体、构件吊点、施工设施设备附墙等涉及工程结构安全的方案应由监理单位核定。", "options": ["正确", "错误"], "answer": [1], "explanation": "装配整体式混凝土结构工程施工实施深化施工设计、专项施工方案论证、吊装令、持证上岗等制度。\n(一）深化施工设计制度。堆场加固、构件堆放架体、构件吊点、施工设施设备附墙，附着设施等涉及工程结构安全的方案应由设计单位核定."},
  {"id": 1362, "type": "judge", "question": "根据《装配整体式混凝土结构工程施工安全管理规定》，专项施工方案中高处作业的安全防护，应包括：因临边安装构件、连接节点现浇混凝土及成品保护修补所采取的防护措施以及交叉作业安全防护等。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《装配整体式混凝土结构工程施工安全管理规定》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1363, "type": "judge", "question": "密闭空间作业是指与外界相对隔离，进出口受限，自然通风不良，人员进入后从事非常规、非连续作业的有限空间。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1364, "type": "judge", "question": "进入密闭空间作业，应严格执行作业审批制度和“先检测、再通风、后作业”的规定。", "options": ["正确", "错误"], "answer": [1], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1365, "type": "judge", "question": "密闭空间施工作业完成后，安全员与施工作业人员应一起检查，确认密闭空间内无人员、杂物、遗留火星后方可撤离。", "options": ["正确", "错误"], "answer": [1], "explanation": "密闭空间施工作业完成后,监护员与施工作业人员应一起检查,确认密闭空间内无人员、杂物、遗留火星后方可撤离。"},
  {"id": 1366, "type": "judge", "question": "根据《上海市基坑工程管理办法》，施工总承包单位应当对基坑工程的施工质量和安全负总责，分包单位应当接受总承包单位施工现场的质量和安全管理，按照分包合同的约定对建设单位负责。", "options": ["正确", "错误"], "answer": [1], "explanation": "第十七条 施工总承包单位应当对基坑工程的施工质量和安全负总责，分包单位应当接受总承包单位施工现场的质量和安全管理，按照分包合同的约定对总承包单位负责。"},
  {"id": 1367, "type": "judge", "question": "基坑工程开工前，施工单位应编制基坑工程施工方案，包括基坑围护、降水、支（换）撑、挖土、渣土外运、场地清理内容。", "options": ["正确", "错误"], "answer": [1], "explanation": "第十八条 基坑工程开工前，施工单位应编制基坑工程施工方案，包括基坑围护、降水、支（换）撑、挖土、支撑栈桥拆除、坑中坑砖胎（预制板）模砌筑，以及基础底板浇筑等内容。如果基坑开挖影响范围内有其他工程同期施工的情况，应当明确基坑开挖与建筑结构工程彼此施工顺序和进度要求，确保工程质量和安全。"},
  {"id": 1368, "type": "judge", "question": "对开挖深度7m以上的基坑工程，需要抽取地下承压水进行减压降水的，施工单位应当按照“按需降水、降水最小化”的原则控制降水。", "options": ["正确", "错误"], "answer": [0], "explanation": "第二十条 对开挖深度7m以上的基坑工程，需要抽取地下承压水进行减压降水的，施工单位应当按照“按需降水、降水最小化”的原则，适时调整减压降水井的抽水流量和抽取时间，并安装计量装置对抽取水量进行计量和控制。"},
  {"id": 1369, "type": "judge", "question": "根据《上海市基坑工程管理办法》，环境保护等级为一、二级，且开挖深度7m（含7m）以上的基坑工程，以及地质条件比较复杂的其他深基坑工程，其内支撑应不少于两道。", "options": ["正确", "错误"], "answer": [1], "explanation": "环境保护等级为一、二级，且开挖深度8m（含8m）以上的基坑工程，以及地质条件比较复杂的其他深基坑工程，其内支撑应不少于两道。"},
  {"id": 1370, "type": "judge", "question": "深基坑工程采用真空式管井降水时，管井必须同时配备真空泵和潜水泵。可以采用塑料管材的承压水降压井管。", "options": ["正确", "错误"], "answer": [1], "explanation": "【依据】《建筑基坑支护技术规程》JGJ 120-2012 / 《建筑基坑工程监测技术标准》GB 50497-2019\n【解析】该说法错误。题干中的主体、程序、禁止性要求或控制数值与现行规定不一致。"},
  {"id": 1371, "type": "judge", "question": "根据《上海市危险性较大的分部分项工程专家论证管理办法》，除设计方外，本工程参建各方人员不得以专家身份参与方案论证。", "options": ["正确", "错误"], "answer": [1], "explanation": "第十三条 （论证专家组成）论证专家应从论证专家库中抽取，不少于5名。论证专家的专业应与论证工程匹配，论证专家组应由不同职业、类别的论证专家组合而成；论证专家的选择宜与论证工程的风险程度相对应。\n本工程参建各方人员不得以专家身份参与方案论证。同一论证专家不得参与不同机构组织的对同一方案的论证。"},
  {"id": 1372, "type": "judge", "question": "根据《上海市危险性较大的分部分项工程专家论证管理办法》，危险性较大的分部分项工程专项施工方案论证报告应在论证后的7个工作日内反馈给施工企业。", "options": ["正确", "错误"], "answer": [1], "explanation": "论证报告应在论证后的5个工作日内反馈给施工企业。"},
  {"id": 1373, "type": "judge", "question": "根据《上海市危险性较大的分部分项工程专家论证管理办法》，对危险性较大的分部分项工程专项施工方案论证报告存在争议的，施工企业可申请市建设管理委科技委办公室进行论证技术复核。", "options": ["正确", "错误"], "answer": [1], "explanation": "第十九条 （争议仲裁）对论证报告存在争议的，建设单位、施工企业可申请市建设管理委科技委办公室进行论证仲裁。"},
  {"id": 1374, "type": "judge", "question": "根据《上海市建设工程危险性较大的分部分项工程安全管理实施细则》，当两个相邻工地存在施工影响时，应由建设单位组织总承包单位编制相关专项施工方案。", "options": ["正确", "错误"], "answer": [0], "explanation": "当两个相邻工地存在施工影响时，应由建设单位组织总承包单位编制相关专项施工方案。"},
  {"id": 1375, "type": "judge", "question": "施工机械主要用于施工现场，一般属于施工单位的非固定资产，可以自购也可向专业租赁公司租赁。", "options": ["正确", "错误"], "answer": [1], "explanation": "“施工机械主要用于施工现场，一般属于施工单位的非固定资产，可以自购也可向专业租赁公司租赁”这一说法在大多数情况下是正确的，但需要注意其资产属性的具体判断可能因施工单位的财务处理方式和设备价值等因素而有所不同。\n固定资产与非固定资产的界定\n固定资产通常指的是企业为生产商品、提供劳务、出租或经营管理而持有的、使用寿命超过一个会计年度的有形资产。施工机械如果满足这一条件，且被施工单位计入固定资产账目，则属于固定资产。反之，如果施工机械的使用寿命较短，或者施工单位选择不计入固定资产，而是作为低值易耗品或租赁资产处理，则不属于固定资产。"},
  {"id": 1376, "type": "judge", "question": "升降作业平台是一种多功能升降机械设备，可分为固定式和移动式、导轨式、曲臂式，剪叉式、链条式、装卸平台等，通常被用于救援和装修。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1377, "type": "judge", "question": "建筑施工企业采用新设备、新技术，或者转场到新的施工环境，还要进行持证上岗后的继续教育，使施工机械操作人员的知识和技能适应和满足不断发展安全生产、安全管理的需要。", "options": ["正确", "错误"], "answer": [0], "explanation": "第三十四条 采用新技术、新工艺、新设备施工和调换工作岗位时，要对操作人员进行新技术操作和新岗位的安全教育，未经教育不得上岗操作"},
  {"id": 1378, "type": "judge", "question": "施工机械安全管理中，对于新进场的机械设备，要建立进场登记制度，对设备的完好性、安全性、合格性、合法性进行登记。", "options": ["正确", "错误"], "answer": [1], "explanation": "对于新进场的机械设备，要建立进场检查制度，检查设备的完好性、安全性、合格性、合法性。即机械设备必须是合法的生产厂家生产，有出厂合格证，产品外观完好无缺、不变形，安全保护装置齐全。凡不符合这四项要求的，坚决拒绝进场。"},
  {"id": 1379, "type": "judge", "question": "施工机械安全管理中，安装好的机械设备要取得法定检测部门的检测合格证后方可使用。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1380, "type": "judge", "question": "根据《特种设备安全法》的规定，特种设备使用单位应当对其使用的特种设备进行季度维护保养和定期自行检查，并作出记录。", "options": ["正确", "错误"], "answer": [1], "explanation": "第三十九条 特种设备使用单位应当对其使用的特种设备进行【经常性】维护保养和定期自行检查，并作出记录。"},
  {"id": 1381, "type": "judge", "question": "根据《特种设备安全法》的规定，特种设备检验机构接到定期检验要求后，应当按照安全技术规范的要求及时进行运行性能检验。", "options": ["正确", "错误"], "answer": [1], "explanation": "特种设备检验机构接到定期检验要求后，应当按照安全技术规范的要求及时进行安全性能检验。特种设备使用单位应当将定期检验标志置于该特种设备的显著位置。"},
  {"id": 1382, "type": "judge", "question": "根据《特种设备安全法》的规定，特种设备作业人员在作业过程中发现事故隐患或者其他不安全因素，应当立即向特种设备安全管理人员和单位有关负责人报告。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《中华人民共和国特种设备安全法》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1383, "type": "judge", "question": "根据《特种设备安全法》的规定，报废条件以外的特种设备，达到设计使用年限可以继续使用的，应当按照安全技术规范的要求通过检验或者安全评估，并办理使用登记证书变更，方可继续使用。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《中华人民共和国特种设备安全法》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1384, "type": "judge", "question": "根据《建筑起重机械安全监督管理规定》，建筑起重机械在验收前应当经具有相应资质的检验检测机构监督检验合格。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑起重机械安全监督管理规定》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1385, "type": "judge", "question": "根据《建筑起重机械安全监督管理规定》，经使用单位内部论证通过后，方可在建筑起重机械上安装非原制造厂制造的标准节和附着装置。", "options": ["正确", "错误"], "answer": [1], "explanation": "禁止擅自在建筑起重机械上安装非原制造厂制造的标准节和附着装置。"},
  {"id": 1386, "type": "judge", "question": "根据《建筑起重机械安全监督管理规定》的，施工总承包单位应制定建筑起重机械安装、拆卸工程专项施工方案和生产安全事故应急救援预案。", "options": ["正确", "错误"], "answer": [1], "explanation": "审核安装单位制定的建筑起重机械安装、拆卸工程专项施工方案和生产安全事故应急救援预案；"},
  {"id": 1387, "type": "judge", "question": "根据《建筑起重机械备案登记办法》的规定，建筑起重机械相关资料非原始版本的建筑起重机械，设备备案机关不予备案，并通知产权单位。", "options": ["正确", "错误"], "answer": [1], "explanation": "第八条 有下列情形之一的建筑起重机械，设备备案机关不予备案，并通知产权单位：\n（一）属国家和地方明令淘汰或者禁止使用的；\n（二）超过制造厂家或者安全技术标准规定的使用年限的；\n（三）经检验达不到安全技术标准规定的。"},
  {"id": 1388, "type": "judge", "question": "根据《建筑施工特种作业人员管理规定》，建筑施工特种作业人员必须经国家应急管理部门考核合格，取得建筑施工特种作业人员操作资格证书，方可上岗从事相应作业。", "options": ["正确", "错误"], "answer": [1], "explanation": "建筑施工特种作业人员必须经建设主管部门考核合格，取得建筑施工特种作业人员操作资格证书（以下简称“资格证书”），方可上岗从事相应作业。"},
  {"id": 1389, "type": "judge", "question": "根据《建筑施工特种作业人员管理规定》，用人单位按规定组织特种作业人员参加年度安全教育培训或者继续教育，培训时间不少于32小时。", "options": ["正确", "错误"], "answer": [1], "explanation": "按规定组织特种作业人员参加年度安全教育培训或者继续教育，培训时间不少于24小时；"},
  {"id": 1390, "type": "judge", "question": "根据《建筑施工特种作业人员管理规定》，建筑施工特种作业人员变动工作单位，其资格证书由原单位收回。", "options": ["正确", "错误"], "answer": [1], "explanation": "第二十一条 建筑施工特种作业人员变动工作单位，任何单位和个人不得以任何理由非法扣押其资格证书。"},
  {"id": 1391, "type": "judge", "question": "根据《关于进一步加强建设工程起重机械监督管理的通知》的规定，从事起重机械施工作业，必须编制施工组织设计，可以以机械装拆方案替代专项施工方案。", "options": ["正确", "错误"], "answer": [1], "explanation": "从事起重机械施工作业，必须编制施工组织设计和针对性的专项施工方案，不得以机械装拆方案替代。"},
  {"id": 1392, "type": "judge", "question": "根据《关于进一步加强建设工程起重机械监督管理的通知》的规定，使用非常规起重设备、装拆设备和装拆方法作业的，其专项施工方案须经5名以上专家论证通过", "options": ["正确", "错误"], "answer": [1], "explanation": "八、使用非常规起重设备、装拆设备和装拆方法作业的，其专项施工方案须经3名以上专家论证通过。"},
  {"id": 1393, "type": "judge", "question": "。根据《关于进一步加强本市建筑起重机械监督管理的通知》的规定，建筑起重机械设备经安装单位安装完毕并自检合格后，由监理单位进行检测申报。", "options": ["正确", "错误"], "answer": [1], "explanation": "建筑起重机械设备经安装单位安装完毕并自检合格后，由施工总包单位进行检测申报。"},
  {"id": 1394, "type": "judge", "question": "根据《关于上海市建筑施工特种作业人员考核和持证上岗管理工作的实施意见》的规定，首次取得操作资格证书的特种作业人员，须经过6个月的实习操作后，方可正式独立上岗。", "options": ["正确", "错误"], "answer": [1], "explanation": "五、依据《通知》规定，经核准取得《建筑施工特种作业人员操作资格证书》和备案的特种作业人员，应当认真按照下列要求执行。\n（一）首次取得操作资格证书的特种作业人员，须经过3个月的实习操作后，方可正式独立上岗。\n（二）每年必须参加不少于24小时的继续教育培训。\n（三）有下列情况之一的，必须通过定点强化培训经考试后方可上岗：\n1、连续一年内有2次违章记录的；\n2、因违章操作，导致发生财产损失事故的；\n3、因违章操作，导致发生人员伤亡事故的；"},
  {"id": 1395, "type": "judge", "question": "根据《关于加强塔式起重机钢结构组合式基础平台安全管理要求的通知》的规定，钢平台的焊缝应按照钢平台的静载荷设计进行疲劳验算，明确焊缝质量等级。", "options": ["正确", "错误"], "answer": [1], "explanation": "（2）钢平台的焊缝应按照承受动载荷设计进行疲劳验算，明确焊缝质量等级；焊接连接构造设计，节点区应便于焊接操作和焊后检测。"},
  {"id": 1396, "type": "judge", "question": "根据《关于加强塔式起重机钢结构组合式基础平台安全管理要求的通知》的规定，钢平台承受交变载荷的主要受力构件、受力部位的焊接，强度应高于母材，焊缝应焊透。", "options": ["正确", "错误"], "answer": [1], "explanation": "格构柱、钢平台的制作宜在具有焊接工艺装备的室内进行，施工现场实施成品安装。\n钢平台承受交变载荷的主要受力构件、受力部位的焊接，应与母材【等强】，焊缝应焊透。"},
  {"id": 1397, "type": "judge", "question": "根据《关于加强塔式起重机钢结构组合式基础平台安全管理要求的通知》的规定，总承包施工企业和监理单位应加强对塔机钢结构组合式基础平台的验收、日常检查管理。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《关于加强塔式起重机钢结构组合式基础平台安全管理要求的通知》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1398, "type": "judge", "question": "根据《上海市建筑施工机械安全监督管理规定》，建筑施工机械推行租赁、安装、拆卸、维保专业化管理。", "options": ["正确", "错误"], "answer": [1], "explanation": "建筑施工机械推行租赁、安装、拆卸、维保一体化管理。"},
  {"id": 1399, "type": "judge", "question": "根据《上海市建筑施工机械安全监督管理规定》，总承包单位、监理单位需对起重机械的产权登记信息实施核查。", "options": ["正确", "错误"], "answer": [0], "explanation": "第十三条 （资料核查）\n建筑施工机械进场前，总承包单位、监理单位应对下列资 料进行核查：\n（一）产品购销合同、合格证、使用说明书，定期维护保 养记录、维修和技术改造记录等；\n（二）安装、拆卸单位的资质证书、安全生产许可证，项 目经理、安全管理人员、特种作业人员证书。\n起重机械需对产权登记信息实施核查"},
  {"id": 1400, "type": "judge", "question": "根据《上海市建筑施工机械安全监督管理规定》，专项施工方案应当由总承包单位技术负责人及相关职能部门审核签字、加盖单位公章，并由总监理工程师审查签字、加盖执业印章后方可实施。", "options": ["正确", "错误"], "answer": [0], "explanation": "专项施工方案应当由总承包单位技术负责人及相关职能部门审核签字、加盖单位公章，并由总监理工程师审查签字、加盖执业印章后方可实施。"},
  {"id": 1401, "type": "judge", "question": "根据《上海市建筑施工机械安全监督管理规定》，监理单位应当组织安装单位对建筑施工机械安装、拆卸作业条件进行检查验收，并对作业验收实行监督管理。", "options": ["正确", "错误"], "answer": [1], "explanation": "总承包单位应当组织安装单位对建筑施工机械安装、拆卸作业条件进行检查验收，监理单位对作业验收实行监督管理。"},
  {"id": 1402, "type": "judge", "question": "根据《上海市建筑施工机械安全监督管理规定》，建筑施工机械安装作业过程中，监理单位应对总承包单位和安装单位的到岗履职情况进行巡视抽查。", "options": ["正确", "错误"], "answer": [0], "explanation": "（三）监理单位应对总承包单位和安装单位的到岗履职情况进行巡视抽查。"},
  {"id": 1403, "type": "judge", "question": "根据《上海市建筑施工机械安全监督管理规定》，总承包单位收到建筑施工机械安装自检合格证明、起重机械检验检测报告后，应当组织安装单位、租赁单位进行验收。安质监站对验收程序及手续的合规性进行监督管理。", "options": ["正确", "错误"], "answer": [1], "explanation": "第二十八条（使用验收）\n总承包单位收到建筑施工机械安装自检合格证明、起重机械检验检测报告后，应当组织安装单位、租赁单位进行验收。监理单位对验收程序及手续的合规性进行监督管理。"},
  {"id": 1404, "type": "judge", "question": "根据《上海市建筑施工机械安全监督管理规定》，总承包单位应当在台风前后、工程停工复工前对建筑施工机械组织专项检查。", "options": ["正确", "错误"], "answer": [0], "explanation": "第三十二条（日常检查）\n总承包单位应当每月不少于一次组织对建筑施工机械的日常检查，台风前后、工程停工复工前还需组织专项检查。\n监理单位应对总承包单位检查的情况进行督查。"},
  {"id": 1405, "type": "judge", "question": "任何单位和个人都有参加有组织的灭火工作的义务。", "options": ["正确", "错误"], "answer": [1], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1406, "type": "judge", "question": "优化消防监管执法模式应建立公安机关与消防救援机构、住房城乡建设管理部门在消防监督检查、火灾隐患防范与处置、违法行为处罚、信息共享等方面的执法协作", "options": ["正确", "错误"], "answer": [0], "explanation": "《上海市消防条例》新条例建立了公安机关与消防救援机构、住房城乡建设管理部门在消防监督检查、违法行为处罚、信息共享等方面的协作机制。"},
  {"id": 1407, "type": "judge", "question": "建立现代化消防监管模式，单位应当采用电气火灾监控技术，提升对电器产品及其线路运行状态的监测、预警和处置能力。", "options": ["正确", "错误"], "answer": [1], "explanation": "【依据】《建设工程施工现场消防安全技术规范》GB 50720-2011 / 《中华人民共和国消防法》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1408, "type": "judge", "question": "动火作业前，应对作业现场可燃物进行清理，裸露的可燃材料上严禁直接进行动火作业。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建设工程施工现场消防安全技术规范》GB 50720-2011 / 《中华人民共和国消防法》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1409, "type": "judge", "question": "具有火灾、爆炸危险的场所必须严格限制明火作业范围与时间。", "options": ["正确", "错误"], "answer": [0], "explanation": "禁止在具有火灾、爆炸危险的场所使用明火,因特殊情况需要使用明火作业的,应当按照规定事先办理审批手续。"},
  {"id": 1410, "type": "judge", "question": "动火作业结束后，应对现场进行检查、清理，并应在确认无火灾危险后，动火操作人和监护人员方可离开。", "options": ["正确", "错误"], "answer": [0], "explanation": "动火作业结束后，应对现场进行检查、清理，并应在确认无火灾危险后，动火操作和监护人员方可离开;"},
  {"id": 1411, "type": "judge", "question": "进行焊接、切割、烘烤或加热等动火作业，除配备灭火器材外，必须落实消防水源。", "options": ["正确", "错误"], "answer": [0], "explanation": "《建设工程施工现场消防安全管理要点》\n4、做好灭火准备。进行焊接、切割、烘烤或加热等动火作业，除配备灭火器材外，必须落实消防水源。动火作业区域有室内、外消火栓的，作业前应认真检查并测试墙式消火栓、室外消火栓的水量、水压是否能满足正常使用需要，并确保在动火作业区域内不少于2支水枪的射流能同时保护到。动火区域内没有消火栓系统的，应利用移动容器储存一定量消防用水以备应急使用。"},
  {"id": 1412, "type": "judge", "question": "施工现场使用的电气线路应具有相应的绝缘强度和机械强度，每个用电设备应设置漏电保护器、短路、过载保护器。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《施工现场临时用电安全技术规范》JGJ 46-2005\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1413, "type": "judge", "question": "可燃材料及易燃易爆危险品应按实际使用数量进场。", "options": ["正确", "错误"], "answer": [1], "explanation": "可燃材料及易燃易爆危险品应按计划限量进场。"},
  {"id": 1414, "type": "judge", "question": "乙炔等气瓶搬运、存放、使用应倾斜放置，严禁横躺卧放，严禁碰撞、敲打、抛掷、滚动气瓶。", "options": ["正确", "错误"], "answer": [1], "explanation": "【依据】《建设工程施工现场消防安全技术规范》GB 50720-2011 / 《中华人民共和国消防法》\n【解析】该说法错误。题干中的主体、程序、禁止性要求或控制数值与现行规定不一致。"},
  {"id": 1415, "type": "judge", "question": "临时宿舍、办公用房可以与厨房操作间、锅炉房、变配电房等组合建造。", "options": ["正确", "错误"], "answer": [1], "explanation": "宿舍、办公用房不应与厨房操作间、锅炉房、变配电房等组合建造。"},
  {"id": 1416, "type": "judge", "question": "施工现场临时消防给水系统应按照《建设工程施工现场消防安全技术规范》的要求与在建工程的施工同步设置。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建设工程施工现场消防安全技术规范》GB 50720-2011\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1417, "type": "judge", "question": "根据《机关、团体、企业、事业单位消防安全管理规定》，明确建筑工程施工现场的消防安全由施工单位负责。实行施工总承包的，由总承包单位负责。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《机关、团体、企业、事业单位消防安全管理规定》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1418, "type": "judge", "question": "施工单位编制的施工现场防火技术方案，应根据现场使用的材料变化及时对其修改、完善。", "options": ["正确", "错误"], "answer": [0], "explanation": "根据《建设工程施工现场消防安全技术规范》GB50720-20116.1.5施工单位应编制施工现场防火技术方案，并应根据现场情况变化及时对其修改、完善。\n防火技术方案应包括下列主要内容：\n1）施工现场重大火灾危险源辨识。\n2）施工现场防火技术措施。\n3）临时消防设施、临时疏散设施配备。\n4）临时消防设施和消防警示标识布置图。"},
  {"id": 1419, "type": "judge", "question": "焊接、切割、烘烤或加热等动火作业，应配备灭火器材，并设动火监护人进行现场监护，每个动火作业点均应设置一个监护人。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建设工程施工现场消防安全技术规范》GB 50720-2011 / 《中华人民共和国消防法》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1420, "type": "judge", "question": "施工单位自行改装现场供用电设施后，应定期对电气设备和线路的运行及维护情况进行检查。", "options": ["正确", "错误"], "answer": [1], "explanation": "电气设备不应超负荷运行或带故障使用；禁止私自改装现场供用电设施；应定期对电气设备和线路的运行及维护情况进行检查。"},
  {"id": 1421, "type": "judge", "question": "施工现场发生火警或火灾，应立即报告专职性消防救援队伍，并组织力量扑救。", "options": ["正确", "错误"], "answer": [1], "explanation": "施工现场发生火警或火灾,应立即报告公安消防部门,并组织力量扑救。"},
  {"id": 1422, "type": "judge", "question": "施工现场必须设置临时消防车道。其宽度不得小于5m，并保证临时消防车道的畅通，禁止在临时消防车道上堆物、堆料或挤占临时消防车道。", "options": ["正确", "错误"], "answer": [1], "explanation": "第十二、施工现场必须设置临时消防车道。其宽度不得小于4m，并保证临时消防车道的畅通，禁止在临时消防车道上堆物、堆料或挤占临时消防车道。"},
  {"id": 1423, "type": "judge", "question": "建筑施工现场防火基本要求规定，在高压架空线下面搭设临时性建筑物或堆放可燃物品要保持一定的距离。", "options": ["正确", "错误"], "answer": [1], "explanation": "不准在高压架空线下面搭设临时性建筑物或堆放可燃物品。"},
  {"id": 1424, "type": "judge", "question": "根据《消防法》规定，对按照国家工程建设消防技术标准需要进行消防设计的建设工程，实行建设工程消防设计审查验收制度。", "options": ["正确", "错误"], "answer": [0], "explanation": "第十条 对按照国家工程建设消防技术标准需要进行消防设计的建设工程，实行建设工程消防设计审查验收制度。"},
  {"id": 1425, "type": "judge", "question": "根据《消防法》规定，消防产品，是指专门用于火灾预防、灭火救援和火灾防护、避难、逃生，包括应急照明、安全疏散等用品。", "options": ["正确", "错误"], "answer": [1], "explanation": "（一）消防设施，是指火灾自动报警系统、自动灭火系统、消火栓系统、防烟排烟系统以及应急广播和应急照明、安全疏散设施等。\n（二）消防产品，是指专门用于火灾预防、灭火救援和火灾防护、避难、逃生的产品。"},
  {"id": 1426, "type": "judge", "question": "根据《上海市消防条例》规定，依法确定的消防安全重点单位还应当履行每日防火巡查，并建立巡查记录的消防安全责任。", "options": ["正确", "错误"], "answer": [0], "explanation": "第十七条 依法确定的消防安全重点单位除应当履行本条例第十六条规定的责任外，还应当履行下列消防安全责任：\n（一） 确定消防安全管理人，组织实施本单位的消防安全管理工作；\n（二） 建立消防档案，确定消防安全重点部位，设置防火标志，实行严格管理；\n（三） 实行每日防火巡查，并建立巡查记录；\n（四） 对员工进行消防安全培训，管理本单位的专职消防队、志愿消防队；\n（五） 自行或者委托符合国家规定条件的消防技术服务机构定期开展消防安全评估，并自评估完成之日起五个工作日内将评估报告报所在地消防救援机构备案。"},
  {"id": 1427, "type": "judge", "question": "根据《上海市消防条例》规定，消防工程的设计、施工、监理、维修人员，消防产品的检验维修人员和自动消防设施的操作人员，应当接受消防安全培训。", "options": ["正确", "错误"], "answer": [0], "explanation": "第四十五条 下列人员应当接受消防安全培训：\n（一） 消防安全管理人员；\n（二） 消防工程的设计、施工、监理、维修人员，消防产品的检验维修人员和自动消防设施的操作人员；\n（三） 易燃易爆危险物品的作业人员；\n（四） 消防技术服务机构的执业人员。\n消防安全重点单位的消防安全管理人、自动消防设施的操作人员、易燃易爆危险物品仓库保管人员应当持有相应的上岗证书。"},
  {"id": 1428, "type": "judge", "question": "根据《上海市消防条例》规定，消防救援机构在消防监督检查中发现不及时消除可能严重威胁公共安全的情形，采取临时查封措施后，应等整改完成后再拆封启用。", "options": ["正确", "错误"], "answer": [1], "explanation": "第四十七条 公安机关消防机构在消防监督检查中发现以下情形，不及时消除可能严重威胁公共安全的，应当依照规定对危险部位或者场所采取临时查封措施：\n（一） 可燃物资仓库和生产、储存、装卸、使用易燃易爆危险物品的场所存在重大火灾隐患的；\n（二） 生产、储存、经营易燃易爆危险物品的场所与居住场所设置在同一建筑物内的；\n（三） 人员密集场所违反消防技术标准和管理规定，储存、经营、使用易燃易爆危险物品的；\n（四） 人员密集场所损坏或者擅自拆除、停用消防设施，堵塞疏散通道、安全出口的；\n（五） 其他不及时消除可能严重威胁公共安全的情形。\n未经采取临时查封措施的公安机关消防机构同意，不得拆封或者使用被查封的场所、部位。"},
  {"id": 1429, "type": "judge", "question": "根据《关于进一步加强建设工程施工现场消防安全工作的通知》规定，施工单位应当在施工组织设计中编制消防安全技术措施和专项施工方案，并由专职消防管理人员进行现场监督。", "options": ["正确", "错误"], "answer": [1], "explanation": "施工单位应当在施工组织设计中编制消防安全技术措施和专项施工方案,并由专职安全管理人员进行现场监督。"},
  {"id": 1430, "type": "judge", "question": "根据《关于进一步加强建设工程施工现场消防安全工作的通知》规定，施工单位应当建立施工现场消防组织，制定灭火和应急疏散预案，并至少每半年组织一次演练，提高施工人员及时报警、扑灭初期火灾和自救逃生能力。", "options": ["正确", "错误"], "answer": [0], "explanation": "五、加强初期火灾扑救和疏散演练\n施工单位应当根据国家有关消防法规和建设工程安全生产法规的规定，建立施工现场消防组织，制定灭火和应急疏散预案，并至少每半年组织一次演练，提高施工人员及时报警、扑灭初期火灾和自救逃生能力。"},
  {"id": 1431, "type": "judge", "question": "根据《上海市建筑工程施工现场消防安全管理规定》，施工现场发生火灾后，建设单位和施工单位应当立即清理火灾现场。", "options": ["正确", "错误"], "answer": [1], "explanation": "第十一条施工现场发生火灾时：\n（一）建设单位和施工单位应当立即向公安消防机构报警，并迅速组织疏散人员，扑救火灾。\n（二）建设单位和施工单位应当根据公安消防机构的要求，为抢救人员、扑救火灾提供便利条件。\n（三）火灾扑灭后，应当保护现场，接受事故调查，如实提供火灾的有关情况，并协助公安消防机构核定火灾损失，查明火灾原因和火灾事故责任。\n（四）未经公安消防机构同意，不得擅自清理火灾现场。"},
  {"id": 1432, "type": "judge", "question": "根据《上海市建筑工程施工现场消防安全管理规定》，临时油漆间、易燃易爆危险品仓库等每30平方米应配置两个灭火级别不小于2B的灭火器。", "options": ["正确", "错误"], "answer": [1], "explanation": "临时油漆间、易燃易爆危险品仓库等每 30 平方米应配置两具灭火级别不小于 4B 的灭火器。"},
  {"id": 1433, "type": "judge", "question": "根据《关于进一步加强本市建设工程施工现场消防安全管理工作的通知》的规定，相关单位要按照“安全第一，措施得当”的要求，进一步增强责任感和紧迫感，认真履行各自职责，切实做好建设工程施工现场消防安全管理工作。", "options": ["正确", "错误"], "answer": [1], "explanation": "各相关单位要按照“以人为本、安全为先、管理为重”的要求，进一步增强责任感和紧迫感，认真履行各自职责，切实做好施工现场消防安全管理工作。"},
  {"id": 1434, "type": "judge", "question": "施工安全事故是指施工企业在施工活动(包括与施工有关的活动)中突然发生的，伤害人身安全和健康，或者损坏设备设施，或者造成经济损失的，导致原施工活动(包括与施工有关的活动)暂时中止或永远终止的意外事件。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1435, "type": "judge", "question": "施工过程中，因不可抗力造成灾害，导致人员人身安全和健康收到损害的突发事件属于施工安全事故。", "options": ["正确", "错误"], "answer": [1], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法错误。题干中的主体、程序、禁止性要求或控制数值与现行规定不一致。"},
  {"id": 1436, "type": "judge", "question": "高空坠落是指施工人员在法定标准高度作业时坠落而造成的事故。", "options": ["正确", "错误"], "answer": [0], "explanation": "高处坠落事故是指人员由落差不低于2米高度坠落发生的人身伤害事故。"},
  {"id": 1437, "type": "judge", "question": "物料提升机应按有关规定由其产权单位编制安装拆卸施工方案，产权单位分管负责人审批签字，并负责安装和拆卸；使用前与施工单位共同进行验收，经验收合格签字后，方可作业。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建设工程安全生产管理条例》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1438, "type": "judge", "question": "施工外用电梯应按有关规定由其施工单位编制安装拆卸施工方案，施工单位分管负责人审批签字，并负责安装和拆卸。", "options": ["正确", "错误"], "answer": [1], "explanation": "施工外用电梯应按有关规定由其产权单位编制安装拆卸施工方案,产权单位分管负责人审批签字,并负责安装和拆卸;"},
  {"id": 1439, "type": "judge", "question": "各类作业平台、卸料平台应按相关规定编制施工方案，项目分管负责人审批签字并组织有关部门验收，经验收合格签字后，方可作业。", "options": ["正确", "错误"], "answer": [0], "explanation": "第十条 各类作业平台、卸料平台应按相关规定编制施工方案，项目分管负责人审批签字并组织有关部门验收，经验收合格签字后，方可作业。架体应保持稳固，不得与施工脚手架连接。作业平台上严禁超载。"},
  {"id": 1440, "type": "judge", "question": "作业层脚手板与建筑物之间的空隙小于15cm时应作全封闭，防止人员和物料坠落。作业人员上下应有专用通道，不得攀爬架体。", "options": ["正确", "错误"], "answer": [1], "explanation": "作业层脚手板与建筑物之间的空隙大于15cm时应作全封闭，防止人员和物料坠落。作业人员上下应有专用通道，不得攀爬架体。"},
  {"id": 1441, "type": "judge", "question": "附着式升降脚手架和其他外挂式脚手架每一作业层架体外侧必须设置上、下两道防护栏杆。", "options": ["正确", "错误"], "answer": [1], "explanation": "附着式升降脚手架和其他外挂式脚手架应设置安全可靠的防倾覆、防坠落装置，每一作业层架体外侧应设置符合要求的防护栏杆和挡脚板。"},
  {"id": 1442, "type": "judge", "question": "模板及其支撑体系的施工荷载应均匀堆置，并不得超过设计计算要求。", "options": ["正确", "错误"], "answer": [0], "explanation": "模板及其支撑体系的施工荷载应均匀堆置，并不得超过设计计算要求。"},
  {"id": 1443, "type": "judge", "question": "坍塌事故中，危害最大的是施工基坑（槽）坍塌、边坡坍塌、基础桩壁坍塌、模板支撑系统失稳坍塌及施工现场临时建筑（包括施工围墙）倒塌等。", "options": ["正确", "错误"], "answer": [0], "explanation": "施工基坑（槽）坍塌、边坡坍塌、基础桩壁坍塌、模板支撑系统失稳坍塌及施工现场临时建筑（包括施工围墙）倒塌等事故确实是施工安全事故中危害最大的一类，需要特别重视和采取有效的预防措施。"},
  {"id": 1444, "type": "judge", "question": "各类施工机械距基坑（槽）、边坡和基础桩孔边的距离，应根据设备重量、基坑（槽）、边坡和基础桩的支护、土质情况确定，并不得小于2m。", "options": ["正确", "错误"], "answer": [1], "explanation": "《事故灾难应急常识》第十条 基坑（槽）、边坡和基础桩孔边堆置各类建筑材料的，应按规定距离堆置。各类施工机械距基坑（槽）、边坡和基础桩孔边的距离，应根据设备重量、基坑（槽）、边坡和基础桩的支护、土质情况确定，并不得小于15m。"},
  {"id": 1445, "type": "judge", "question": "基坑（槽）作业时，施工单位应在施工方案中确定攀登设施及专用通道，作业人员不得攀爬模板、脚手架等临时设施。", "options": ["正确", "错误"], "answer": [0], "explanation": "基坑(槽)作业时,施工单位应在施工方案中确定攀登设施及专用通道,作业人员不得攀爬模板、脚手架等临时设施。"},
  {"id": 1446, "type": "judge", "question": "预防物体打击伤害，应严格遵守有关操作规程，防止上层物体坠落到下层。上下不同层次间，在前后左右方向必须有一段横向的安全距离，此距离应大于可能坠落半径。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1447, "type": "judge", "question": "根据《特种设备安全法》的规定，特种设备发生事故后，事故发生单位应当按照应急预案采取措施，组织抢救，防止事故扩大，减少人员伤亡和财产损失，并及时向事故发生地乡（镇）级以上人民政府负责特种设备安全监督管理的部门和有关部门报告。", "options": ["正确", "错误"], "answer": [1], "explanation": "第七十条 特种设备发生事故后，事故发生单位应当按照应急预案采取措施，组织抢救，防止事故扩大，减少人员伤亡和财产损失，保护事故现场和有关证据，并及时向事故发生地【县级】以上人民政府负责特种设备安全监督管理的部门和有关部门报告。"},
  {"id": 1448, "type": "judge", "question": "建筑施工单位应当制定具体应急预案，并对生产经营场所、有危险物品的建筑物、构筑物及周边环境开展隐患排查，及时采取措施消除隐患，防止发生突发事件。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《中华人民共和国安全生产法》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1449, "type": "judge", "question": "根据《建设工程安全生产管理条例》规定，施工单位应当制定本单位生产安全事故应急救援预案，建立应急救援组织或者配备应急救援人员，配备必要的应急救援器材、设备，并不定期组织演练。", "options": ["正确", "错误"], "answer": [1], "explanation": "施工单位应当制定本单位生产安全事故应急救援预案，建立应急救援组织或者配备应急救人员，配备必要的应急救授器材、设备，并定期组织演练。"},
  {"id": 1450, "type": "judge", "question": "根据《建设工程安全生产管理条例》规定，施工单位应当采取措施防止事故扩大，保护事故现场，严禁移动现场物品。", "options": ["正确", "错误"], "answer": [1], "explanation": "【依据】《建设工程安全生产管理条例》\n【解析】该说法错误。题干中的主体、程序、禁止性要求或控制数值与现行规定不一致。"},
  {"id": 1451, "type": "judge", "question": "根据《生产安全事故报告和调查处理条例》，事故发生后，事故现场有关人员应当立即向本单位负责人报告；单位负责人接到报告后，应当于12小时内向事故发生地县级以上人民政府安全生产监督管理部门和负有安全生产监督管理职责的有关部门报告。", "options": ["正确", "错误"], "answer": [1], "explanation": "【依据】《生产安全事故报告和调查处理条例》\n【解析】该说法错误。题干中的主体、程序、禁止性要求或控制数值与现行规定不一致。"},
  {"id": 1452, "type": "judge", "question": "根据《生产安全事故报告和调查处理条例》规定，因抢救人员、防止事故扩大以及疏通交通等原因，需要移动事故现场物件的，应当做出标志，绘制现场简图并向应急管理部门提出书面申请，妥善保存现场重要痕迹、物证。", "options": ["正确", "错误"], "answer": [1], "explanation": "因抢救人员、防止事故扩大以及疏通交通等原因，需要移动事故现场物件的，应当做出标志，绘制现场简图并做出书面记录，妥善保存现场重要痕迹、物证。"},
  {"id": 1453, "type": "judge", "question": "根据《生产安全事故报告和调查处理条例》，特别重大事故，负责事故调查的人民政府在收到事故调查组提交的事故调查报告后30日内做出批复，特殊情况下，批复时间可以适当延长，但延长的时间最长不超过15日。", "options": ["正确", "错误"], "answer": [1], "explanation": "第三十二条 重大事故、较大事故、一般事故，负责事故调查的人民政府应当自收到事故调查报告之日起15日内做出批复；特别重大事故，30日内做出批复，特殊情况下，批复时间可以适当延长，但延长的时间最长不超过30日。"},
  {"id": 1454, "type": "judge", "question": "根据《生产安全事故应急条例》规定，应急救援队伍使用单位应当按照国家有关规定对应急救援人员进行培训；应急救援人员经培训合格后，方可参加应急救援工作。", "options": ["正确", "错误"], "answer": [1], "explanation": "第十一条 应急救援队伍的应急救援人员应当具备必要的专业知识、技能、身体素质和心理素质。\n应急救援队伍建立单位或者兼职应急救援人员所在单位应当按照国家有关规定对应急救援人员进行培训；应急救援人员经培训合格后，方可参加应急救援工作。"},
  {"id": 1455, "type": "judge", "question": "根据《生产安全事故应急条例》规定，建筑施工单位应当根据本单位可能发生的生产安全事故的特点和危害，配备必要的灭火、排水、通风以及危险物品稀释、掩埋、收集等应急救援器材、设备和物资，并进行经常性维护、保养，保证正常运转。", "options": ["正确", "错误"], "answer": [0], "explanation": "易燃易爆物品、危险化学品等危险物品的生产、经营、储存、运输单位，矿山、金属冶炼、城市轨道交通运营、建筑施工单位，以及宾馆、商场、娱乐场所、旅游景区等人员密集场所经营单位，应当根据本单位可能发生的生产安全事故的特点和危害，配备必要的灭火、排水、通风以及危险物品稀释、掩埋、收集等应急救援器材、设备和物资，并进行经常性维护、保养，保证正常运转。"},
  {"id": 1456, "type": "judge", "question": "根据《生产安全事故信息报告和处置办法》规定，应当报告和处置的生产安全事故信息，是指已经发生的生产安全事故和较大涉险事故的信息。", "options": ["正确", "错误"], "answer": [0], "explanation": "第三条 本办法规定的应当报告和处置的生产安全事故信息（以下简称事故信息），是指已经发生的生产安全事故和较大涉险事故的信息。"},
  {"id": 1457, "type": "judge", "question": "根据《生产安全事故信息报告和处置办法》规定，事故信息报告后出现新情况的，负责事故报告的单位应当按规定及时续报。较大涉险事故、一般事故、较大事故每日至少续报2次。", "options": ["正确", "错误"], "answer": [1], "explanation": "【依据】《生产安全事故信息报告和处置办法》\n【解析】该说法错误。题干中的主体、程序、禁止性要求或控制数值与现行规定不一致。"},
  {"id": 1458, "type": "judge", "question": "根据上海市实施《生产安全事故报告和调查处理条例》的若干规定，经事故调查组认定不属于生产安全事故的，由事故发生单位提出，经负责事故调查的同级政府批准；需要相关部门调查的，事故调查组应当做好有关移交工作。", "options": ["正确", "错误"], "answer": [1], "explanation": "第二十二条（不属于生产安全事故的处理）\n经事故调查组认定不属于生产安全事故的，由事故调查组织部门提出，经负责事故调查的同级政府批准；需要相关部门调查的，事故调查组应当做好有关移交工作。"},
  {"id": 1459, "type": "judge", "question": "根据《上海市建设工程生产安全事故管理规定》关于全面整改的具体要求，在排除事故险情后，事故工地全面停工整改。事故企业按“四不放过”原则，对企业安全生产管理体系进行自查自纠，对企业安全生产条件开展自我评价。", "options": ["正确", "错误"], "answer": [0], "explanation": "全面整改。在排除事故险情后,事故工地全面停工整改。事故企业按“四不放过”原则，对企业安全生产管理体系进行自查自纠，对企业安全生产条件开展自我评价；"},
  {"id": 1460, "type": "judge", "question": "根据《上海市建设工程生产安全事故管理规定》，事故报告后情况发生变化，以及事故发生30日内伤亡人数发生变化的应当及时补报。", "options": ["正确", "错误"], "answer": [0], "explanation": "事故报告后情况发生变化，以及事故发生30日内伤亡人数发生变化的应当及时补报。"},
  {"id": 1461, "type": "judge", "question": "根据《上海市建设工程生产安全事故管理规定》，工地受监监督站在收到复工申请的五个工作日内，应组织对事故工地开展复工检查。工地取得《恢复施工通知书》，方可恢复施工。", "options": ["正确", "错误"], "answer": [1], "explanation": "工地受监监督站在收到复工申请的三个工作日内，应组织对事故工地开展复工检查。工地取得《恢复施工通知书》，方可恢复施工。"},
  {"id": 1462, "type": "judge", "question": "根据《上海市建设工程生产安全事故管理规定》，发生事故的建筑施工企业在《安全生产许可证》申请延期时，实行严格审批，全面核查企业安全生产条件。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《上海市建设工程生产安全事故管理规定》 / 《安全生产许可证》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1463, "type": "judge", "question": "根据《上海市建设工程生产安全事故管理规定》，对于关键岗位人员事故责任的处理，发生较大事故的，吊销注册建造师、总监理工程师执业资格证书，3年内不予注册。", "options": ["正确", "错误"], "answer": [1], "explanation": "5年内不予注册"},
  {"id": 1464, "type": "judge", "question": "根据《上海市建设工程生产安全事故行业调查办法》（试行），行业调查期间，对事故相关的设计单位、总承包单位、专业分包单位及监理单位暂停在沪承接业务。", "options": ["正确", "错误"], "answer": [1], "explanation": "行业调查期间，对事故相关的总承包单位、专业分包单位及监理单位暂停在沪承接业务。"},
  {"id": 1465, "type": "judge", "question": "根据《上海市建设工程生产安全事故行业调查办法》（试行），自事故发生之日起，取消事故项目当年度各类评优奖励资格，施工总承包及涉事分包企业记入事故企业名单。", "options": ["正确", "错误"], "answer": [0], "explanation": "自事故发生之日起，取消事故项目当年度各类评优奖励资格，施工总承包及涉事分包企业记入事故企业名单。 事故企业名单中的 施工企业1年内发生2起及以上事故的， 除取消事故项目评优资格外，同时取消企业当年度各类评优奖励资格。"},
  {"id": 1466, "type": "judge", "question": "《关于加强建设工程施工现场临建房屋安全管理的通知》规定，易燃易爆物品应专库储存，集中存放，保持通风，不准在临建房屋内调配油漆、稀料。", "options": ["正确", "错误"], "answer": [1], "explanation": "易燃易爆物品应专库储存,分类单独存放,保持通风,不准在临建房屋内调配油漆、稀料。"},
  {"id": 1467, "type": "judge", "question": "《关于加强建设工程施工现场临建房屋安全管理的通知》规定，办公、宿舍等临建房屋的围护结构须使用不燃材料。会议室等人员密集场所宜设置在二楼。", "options": ["正确", "错误"], "answer": [1], "explanation": "办公、宿舍等临建房屋的围护结构须使用不燃材料。会议室等人员密集场所须设置在首层。"},
  {"id": 1468, "type": "judge", "question": "《关于加强建设工程施工现场临建房屋安全管理的通知》规定，临建房屋周围消火栓处要设有明显标志，配备足够的消防水带、消防水枪，消防供水要保证足够的水源和水压。", "options": ["正确", "错误"], "answer": [0], "explanation": "上海市城乡建设和交通委员会\n关于加强建设工程施工现场临建房屋安全管理的通知\n沪建交〔2011〕795号\n三、临建房屋消防安全管理要求\n（二）临建房屋周围应合理布置消火栓。消火栓处要设有明显标志，配备足够的消防水带、消防水枪，消防供水要保证足够的水源和水压。消火栓周围3米内不准存放物品，地下消火栓的设置必须符合现行技术规范要求。临建房屋必须配备灭火器材，做到布局、选型合理，并经常检查、维护、保养，保证灭火器材灵敏有效。"},
  {"id": 1469, "type": "judge", "question": "《关于加强建设工程施工现场临建房屋安全管理的通知》规定，临建房屋配电线路布线应穿金属管或用非燃硬塑料管保护。", "options": ["正确", "错误"], "answer": [0], "explanation": "临建房屋配电线路布线应穿金属管或用非燃硬塑料管保护。"},
  {"id": 1470, "type": "judge", "question": "《建筑施工现场钢管扣件安全管理规定》规定，施工单位应在监理单位见证下对现场用于承重体系的钢管、扣件进行抽样，委托相关检测机构进行复试，每个工地钢管、扣件复试批次不得少于1次。", "options": ["正确", "错误"], "answer": [0], "explanation": "施工单位应在监理单位见证下对现场用于承重体系的钢管、扣件进行抽样,委托相关检测机构进行复试,每个工地钢管、扣件复试批次不得少于1次。"},
  {"id": 1471, "type": "judge", "question": "保险人是指与投保人订立保险合同，并承担赔偿或者给付保险金责任的保险公司。保险人必须是法人。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《中华人民共和国社会保险法》 / 保险学\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1472, "type": "judge", "question": "财产保险是以物质财富及其有关的利益为保险标的的险种。财产保险的标的是被保险的财产。", "options": ["正确", "错误"], "answer": [1], "explanation": "保险标的是作为保险对象的财产及其有关利益或人的生命和身体，它是保险利益的载体。"},
  {"id": 1473, "type": "judge", "question": "强制保险是政府以法令或政策形式强制被保险人与保险人的法律关系，不管当事人自愿与否，必须按规定办理保险。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《中华人民共和国社会保险法》 / 保险学\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1474, "type": "judge", "question": "责任保险以被保险人的民事损害赔偿责任为保险标的的险种，其构成须具备两个条件：一是被保险人对第三者依法负有赔偿责任；二是受害的第三者必须向被保险人请求赔偿。", "options": ["正确", "错误"], "answer": [1], "explanation": "在责任保险中，保险人的保险责任构成必须具备两个条件：一是被保险人对于第三者在法律上应承担的赔偿责任；二是受损害的第三者必须向保险人请求赔偿。"},
  {"id": 1475, "type": "judge", "question": "《上海市建设工程安全生产责任保险实施意见》规定，本市全面推行建设工程安责险，本市行政区域范围内的新开工建设工程需投保建设工程安责险，已开工项目无需投保建设工程安责险。", "options": ["正确", "错误"], "answer": [1], "explanation": "第三条 （适用范围）\n本市全面推行建设工程安责险，本市行政区域范围内的所有建设工程(包括新开工及已开工项目)均需投保建设工程安责险。"},
  {"id": 1476, "type": "judge", "question": "《上海市建设工程安全生产责任保险实施意见》规定，因投保单位自身原因造成的停工，可以申请退保。", "options": ["正确", "错误"], "answer": [1], "explanation": "因投保单位自身原因造成的停工，不得退保。"},
  {"id": 1477, "type": "judge", "question": "《上海市建设工程安全生产责任保险实施意见》规定，承担本市建设工程安责险的保险机构由市住房城乡建设管理委会同其他管理部门通过竞争性磋商方式确定，并负责日常管理考核。", "options": ["正确", "错误"], "answer": [1], "explanation": "承担本市建设工程安责险的保险机构由市住房城乡建设管理委会同其他管理部门通过公开招标方式确定，并负责日常管理考核。保险机构应当建立保险条款、责任限额、费率规则、事故预防、理赔流程“五统一”承保模式。"},
  {"id": 1478, "type": "judge", "question": "根据《上海市建设工程安全生产责任保险实施意见》规定，剩余工程造价低于总工程造价20%（含），或者剩余工期低于6个月的，企业可根据自身投保相关保险情况，自行确定是否投保建设工程安责险，不做强制要求", "options": ["正确", "错误"], "answer": [0], "explanation": "各设区市对已开工项目可按照以下两种情形处理（已投保保障范围与建设工程安责险相同类保险的在建项目除外）：\n（一）剩余工程造价低于总工程造价20%（含），或者剩余工期低于6个月的，企业可根据自身投保相关保险情况， 自行确定是否投保，不做强制要求。\n（二）剩余工程造价超过总工程造价的20%（不含），或者剩余工期超过6个月的， 企业应当按照剩余工程量投保；费率可适用短期费率系数：剩余工程天数/工程合同天数（以保险条款为准）。"},
  {"id": 1479, "type": "judge", "question": "。根据《上海市建设工程安全生产责任保险实施意见》规定，若建设工程安责险保险期限终止但工程尚未完工，投保人须事先获得保险人的书面同意保险期限的展延，", "options": ["正确", "错误"], "answer": [0], "explanation": "若保险期限终止但工程尚未完工，投保人须事先获得保险人的书面同意保险期限的展延，否则，从本保险合同明细表中列明的建筑期保险期间终止日之后发生的任何损失、费用和责任，保险人不负责赔偿。"},
  {"id": 1480, "type": "judge", "question": "《上海市建设工程安全生产责任保险实施意见》规定，保险责任限额应当至少包括投保单位从业人员和第三者的人身损害、第三者财产损失、事故抢险救援、医疗救护、事故鉴定、法律诉讼费用等部分，项目总保险责任限额应与该项目工程规模相匹配。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《上海市建设工程安全生产责任保险实施意见》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1481, "type": "judge", "question": "《上海市建设工程安全生产责任保险实施意见》规定，投保单位依法获得的建设工程安责险赔偿，不影响投保单位从业人员依法请求工伤保险赔偿的权利。", "options": ["正确", "错误"], "answer": [0], "explanation": "投保单位依法获得的建设工程安责险赔偿，不影响投保单位从业人员依法请求工伤保险赔偿的权利。"},
  {"id": 1482, "type": "judge", "question": "《上海市建设工程安全生产责任保险实施细则》规定，投保建设工程安全生产责任保险，投保企业仅需提供工程合同、工程中标通知书、投保人盖章的投保单、企业证照以上资料。", "options": ["正确", "错误"], "answer": [0], "explanation": "第十条（投保资料）投保企业应提供如下投保资料：\n1．工程合同或工程中标通知书；\n2．投保人盖章的投保单；\n3．企业信息证明（包括企业证照、安全生产负责人信息）。"},
  {"id": 1483, "type": "judge", "question": "《标准化法》规定，对满足基础通用、与强制性国家标准配套、对各有关行业起引领作用等需要的技术要求，可以制定为行业标准。", "options": ["正确", "错误"], "answer": [1], "explanation": "【依据】《标准化法》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1484, "type": "judge", "question": "《标准化法》规定，行业标准由国务院有关行政主管部门制定，报国务院标准化行政主管部门备案。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《标准化法》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1485, "type": "judge", "question": "团体标准由团体按照团体确立的标准制定程序自主制定发布，由社会自愿采用的标准。团体是指具有法人资格，且具备相应专业技术能力、标准化工作能力和组织管理能力的学会、协会、商会、联合会和产业技术联盟等社会团体。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《企业安全生产标准化基本规范》 / 《中华人民共和国标准化法》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1486, "type": "judge", "question": "《工程建设国家标准管理办法》规定，国家标准分为强制性标准和推荐性标准。", "options": ["正确", "错误"], "answer": [0], "explanation": "第三条 国家标准分为强制性标准和推荐性标准。\n下列标准属于强制性标准：\n（一）工程建设勘察、规划、设计、施工（包括安装）及验收等通用的综合标准和重要的通用的质量标准；\n（二）工程建设通用的有关安全、卫生和环境保护的标准；\n（三）工程建设重要的通用的术语、符号、代号、量与单位、建筑模数和制图方法标准；\n（四）工程建设重要的通用的试验、检验和评定方法等标准；\n（五）工程建设重要的通用的信息技术标准；\n（六）国家需要控制的其他工程建设通用的标准。\n强制性标准以外的标准是推荐性标准。"},
  {"id": 1487, "type": "judge", "question": "《工程建设行业标准管理办法》规定，行业标准在相应的国家标准实施后，应当及时修订或废止。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《工程建设行业标准管理办法》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1488, "type": "judge", "question": "根据《团体标准管理规定》规定，团体标准实施效果良好，且符合国家标准、行业标准或地方标准制定要求的，团体标准发布机构可以申请转化为国家标准、行业标准或地方标准。", "options": ["正确", "错误"], "answer": [0], "explanation": "第二十八条 团体标准实施效果良好,且符合国家标准、行业标准或地方标准制定要求的,团体标准发布机构可以申请转化为国家标准、行业标准或地方标准。"},
  {"id": 1489, "type": "judge", "question": "《档案法》将档案的定义表述为：“档案，是指过去和现在的国家机构、社会组织以及个人从事政治、经济、科学、技术、文化、宗教等活动直接形成的对国家和社会有保存价值的各种文字、图表、声像等不同形式的历史记录。”", "options": ["正确", "错误"], "answer": [0], "explanation": "第二条 本法所称的档案，是指过去和现在的国家机构、社会组织以及个人从事政治、军事、经济、科学、技术、文化、宗教等活动直接形成的对国家和社会有保存价值的各种文字、图表、声像等不同形式的历史记录。"},
  {"id": 1490, "type": "judge", "question": "企业信用信息主要包括企业的、财务报表、付款记录、企业发展史、经营状况等内容。", "options": ["正确", "错误"], "answer": [1], "explanation": "企业信用信息主要包括企业的注册信息、财务报表、付款记录、企业发展史、经营状况等内容"},
  {"id": 1491, "type": "judge", "question": "政府发行短期国库券，期限在一年之内，目的是解决财政先支后收的矛盾。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1492, "type": "judge", "question": "依据信用主体的不同，信用信息可分为政府信用信息、企业信用信息与个人信用信息。", "options": ["正确", "错误"], "answer": [1], "explanation": "依据信用主体的不同，信用信息可分为企业信用信息与个人信用信息。"},
  {"id": 1493, "type": "judge", "question": "根据《上海市建筑市场信用信息管理办法》的规定，良好信用信息，是指建筑市场从业单位和人员获得的与建设活动相关的国家和本市区级以上奖项等信息。", "options": ["正确", "错误"], "answer": [1], "explanation": "第八条（良好信用信息）\n本办法所称的良好信用信息，是指建筑市场从业单位和人员获得的与建设活动相关的国家和本市【市级】奖项等信息。记录内容包括奖项或者表彰名称、获奖项目、等级、评奖年度、取得时间和评奖或表彰部门。上述信息由本市建筑建材行业相关行业协会或者评奖单位记录。"},
  {"id": 1494, "type": "judge", "question": "《上海市建筑市场信用信息管理办法》规定，不良信用信息按照违法违规行为影响程度等，分为“A、B、C、D”四个级别。", "options": ["正确", "错误"], "answer": [1], "explanation": "不良信用信息按照违法违规行为影响程度等,分为“A、B、C”三个级别。"},
  {"id": 1495, "type": "judge", "question": "《上海市建筑市场信用信息管理办法》规定，从业单位和从业人员受到建设管理部门和专业建设管理部门行政处罚的违法行为，认定为C级不良信用信息。", "options": ["正确", "错误"], "answer": [0], "explanation": "第十二条（C 级不良信用信息） 从业单位和从业人员受到建设管理部门和专业建设管理部门行政处罚的违法行为，认定为 C 级不良信用信息。"},
  {"id": 1496, "type": "judge", "question": "《上海市建筑市场信用信息管理办法》规定，从业人员被开具《责令暂停担任项目经理资格通知书》的违法或违规行为，认定为B级不良信用信息。", "options": ["正确", "错误"], "answer": [0], "explanation": "《上海市建筑市场信用信息管理办法》规定，从业人员被开具《责令暂停担任项目经理资格通知书》的违法或违规行为，认定为B级不良信用信息。"},
  {"id": 1497, "type": "judge", "question": "《上海市建筑市场信用信息管理办法》规定，本市建立建筑市场从业单位和从业人员信用信息档案制度。从业单位和从业人员参与本市建筑活动过程中，应当通过市建管平台完成基本信息报送，建立信用信息档案。", "options": ["正确", "错误"], "answer": [1], "explanation": "第十三条(信用信息档案制度)本市建立建筑市场从业单位和从业人员信用信息档案制度。从业单位和从业人员参与本市建筑活动【前】,应当通过市建管平台完成基本信息报送,建立信用信息档案."},
  {"id": 1498, "type": "judge", "question": "所称的工程业绩信息，是指按规定应当办理项目信息报送的工程所签订的，并经合同信息报送且履约完成的施工总承包、专业承包和劳务分包等各类施工承发包合同业绩。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1499, "type": "judge", "question": "筑业企业的信用评价，按照已录入市建管信用信息库的信用信息的生效日期和追溯时长计算。", "options": ["正确", "错误"], "answer": [0], "explanation": "在沪建筑业企业的信用评价，按照已录入上海市建设市场管理信息平台信用信息数据库（以下简称市建管信用信息库）的信用信息的生效日期和追溯时长计算。"},
  {"id": 1500, "type": "judge", "question": "起重伤害指从事各种起重作业时发生的机械伤害事故，包括上下驾驶室时发生的坠落伤害。", "options": ["正确", "错误"], "answer": [1], "explanation": "起重伤害:指从事各种起重作业时发生的机械伤害事故,不包括上下驾驶室时发生的坠落伤害,起重设备引起的触电及检修时制动失灵造成的伤害。"},
  {"id": 1501, "type": "judge", "question": "我国在工伤事故统计中，按照《企业职工伤亡事故分类》（GB6441-1986）将企业工伤事故分为18类。", "options": ["正确", "错误"], "answer": [1], "explanation": "我国在工伤事故统计中，按照《企业职工伤亡事故分类》（GB6441-1986）将企业工伤事故分为20类"},
  {"id": 1502, "type": "judge", "question": "工伤保险不受用人单位效益好坏的影响，工伤保险基金发放的待遇能够保障工伤职工享有必须的医疗救治和基本生活。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《中华人民共和国社会保险法》 / 保险学\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1503, "type": "judge", "question": "鉴于工程建设中各工种调动频繁、用工流动性大，投保实行不记名和不计人数的这种方式属于工伤保险的投保。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《中华人民共和国社会保险法》 / 保险学\n【解析】该说法错误。题干中的主体、程序、禁止性要求或控制数值与现行规定不一致。"},
  {"id": 1504, "type": "judge", "question": "《上海市工伤保险实施办法》规定，工伤保险费根据以收定支、收支平衡的原则，确定费率。", "options": ["正确", "错误"], "answer": [1], "explanation": "第八条（缴费原则）\n用人单位应当按时缴纳工伤保险费。从业人员个人不缴纳工伤保险费。\n工伤保险费根据以【支定收】、收支平衡的原则，确定费率。"},
  {"id": 1505, "type": "judge", "question": "《上海市工伤保险实施办法》规定，从业人员因工外出期间，由于工作原因受到伤害或者发生事故下落不明的，应当认定为工伤。", "options": ["正确", "错误"], "answer": [0], "explanation": "《工伤保险条例》十四条：职工有下列情形之一的，应当认定为工伤：（一）在工作时间和工作场所内，因工作原因受到事故伤害的；（二）工作时间前后在工作场所内，从事与工作有关的预备性或者收尾性工作受到事故伤害的；（三）在工作时间和工作场所内，因履行工作职责受到暴力等意外伤害的；（四）患职业病的；（五）因工外出期间，由于工作原因受到伤害或者发生事故下落不明的；（六）在上下班途中，受到非本人主要责任的交通事故或者城市轨道交通、客运轮渡、火车事故伤害的；（七）法律、行政法规规定应当认定为工伤的其他情形。"},
  {"id": 1506, "type": "judge", "question": "《上海市工伤保险实施办法》规定，从业人员被诊断、鉴定为职业病，所在单位应当自事故伤害发生之日或者被诊断、鉴定为职业病之日起25日内，向用人单位所在地的区、县人力资源社会保障局提出工伤认定申请。", "options": ["正确", "错误"], "answer": [1], "explanation": "从业人员发生事故伤害或者按照职业病防治法规定被诊断、鉴定为职业病，所在单位应当自事故伤害发生之日或者被诊断、鉴定为职业病之日起 30 日内，向用人单位所在地的区、县人力资源社会保障局提出工伤认定申请。遇有特殊情况，经报区、县人力资源社会保障局同意，申请时限可以适当延长。"},
  {"id": 1507, "type": "judge", "question": "《关于进一步做好本市建筑业工伤保险工作若干意见的通知》规定，按项目参加本市工伤保险的，工伤保险费按建设工程施工合同载明的合同价的0.8‰确定，并根据以支定收、收支平衡的原则适时调整。", "options": ["正确", "错误"], "answer": [0], "explanation": "（一）按项目参保的工程建设项目，工伤保险费按照建设工程施工合同或项目标段合同（以下简称项目总承包合同）载明的合同价的0.8‰确定，并根据“以支定收、收支平衡”的原则适时调整。"},
  {"id": 1508, "type": "judge", "question": "《关于进一步做好本市建筑业工伤保险工作若干意见的通知》规定，未参加本市工伤保险的项目从业人员发生工伤事故，依法由工伤保险基金支付工伤保险待遇，施工总承包企业、建设单位各自承担相应责任。", "options": ["正确", "错误"], "answer": [1], "explanation": "五、未参加本市工伤保险的项目从业人员发生工伤事故，依法由所在的用人单位支付工伤保险待遇，施工总承包企业、建设单位承担连带责任；从业人员所在的用人单位、承担连带责任的施工总承包企业、建设单位不支付的，由工伤保险基金先行支付，从业人员所在的用人单位和承担连带责任的施工总承包企业、建设单位应当偿还；不偿还的，由社会保险经办机构依法追偿。"},
  {"id": 1509, "type": "judge", "question": "工伤预防项目在实施过程中，项目申报单位应及时跟踪项目实施的进展情况，确保项目按照服务合同有效开展。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1510, "type": "judge", "question": "建设工程应当优先选用有利于文明施工的施工技术、工艺和建筑材料，并按照本市相关规定，采用装配式建造方式。", "options": ["正确", "错误"], "answer": [0], "explanation": "建设工程应当优先选用有利于安全文明施工的施工技术、工艺和建筑材料,并按照省市相关规定,采用装配式建造方式。"},
  {"id": 1511, "type": "judge", "question": "本市规定，线性水利工程、非全封闭的城市道路工程和公路工程或者仅在夜间施工的管线工程的施工现场，可以使用敞开式围挡。", "options": ["正确", "错误"], "answer": [1], "explanation": "线性水利工程、非全封闭的城市道路工程和公路工程、施工工期小于7日或者仅在夜间施工的管线工程的施工现场，可以使用路拦式围挡。"},
  {"id": 1512, "type": "judge", "question": "施工单位进行建筑垃圾处理或者建筑物、构筑物拆除作业时，建筑垃圾必须在当日完成清运。", "options": ["正确", "错误"], "answer": [1], "explanation": "施工单位进行建筑垃圾处理或者建筑物、构筑物拆除作业时，应当遵守以下规定：\n（四）对建筑垃圾在当日不能完成清运的，采取遮盖、洒水等防尘措施。"},
  {"id": 1513, "type": "judge", "question": "施工单位应当对工地泥浆进行三级沉淀后予以排放，禁止直接将工地泥浆排入城市排水管网或者河道。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建设工程安全生产管理条例》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1514, "type": "judge", "question": "施工工地内住宿人员的管理，执行本市实有人口管理的有关规定。非本工地工作人员出示相关证明后可以在施工工地内的宿舍住宿。", "options": ["正确", "错误"], "answer": [1], "explanation": "第二十二条（工地住宿人员管理）\n施工工地内住宿人员的管理，执行本市实有人口管理的有关规定。非本工地工作人员不得在施工工地内的宿舍住宿。"},
  {"id": 1515, "type": "judge", "question": "《建筑工程安全防护、文明施工措施费用及使用管理规定》规定，建设单位与施工单位应当在施工合同中明确安全防护、文明施工措施项目总费用，以及费用预付、支付计划，使用要求、调整方式等条款。", "options": ["正确", "错误"], "answer": [0], "explanation": "第七条 建设单位与施工单位应当在施工合同中明确安全防护、文明施工措施项目总费用，以及费用预付计划、支付计划、使用要求、调整方式等条款。"},
  {"id": 1516, "type": "judge", "question": "《建筑工程安全防护、文明施工措施费用及使用管理规定》规定，施工单位安全生产管理机构和专职安全生产管理人员负责对建筑工程安全防护、文明施工措施的组织实施进行现场监督检查，并有权向建设主管部门反映情况。", "options": ["正确", "错误"], "answer": [0], "explanation": "第十一条 施工单位应当确保安全防护、文明施工措施费专款专用，在财务管理中单独列出安全防护、文明施工措施项目费用清单备查。施工单位安全生产管理机构和专职安全生产管理人员负责对建筑工程安全防护、文明施工措施的组织实施进行现场监督检查，并有权向建设主管部门反映情况。"},
  {"id": 1517, "type": "judge", "question": "《房屋建筑工程文明施工提升标准》规定的实施范围为申报创建市级文明工地的房屋建筑施工项目。", "options": ["正确", "错误"], "answer": [0], "explanation": "一、实施范围\n（一）外环线以内10000平方米及以上的房屋建筑施工项目；\n（二）申报创建市级文明工地的房屋建筑施工项目；\n（三）施工作业点距离住宅、医院、学校等敏感建筑物15米及以内的房屋建筑施工项目。"},
  {"id": 1518, "type": "judge", "question": "《房屋建筑工程文明施工提升标准》规定，施工现场应设置全封闭、轻质结构、可拆卸周转的围墙，材料宜选用金属材料，围墙基础色调为红色。", "options": ["正确", "错误"], "answer": [1], "explanation": "施工现场应设置全封闭、轻质结构、可拆卸周转的围墙，材料宜选用金属材料，围墙基础色调为白色，底部设置0.2米的踢脚线，基础色调为深蓝色，总高度不应低于2.0m。"},
  {"id": 1519, "type": "judge", "question": "《房屋建筑工程文明施工提升标准》规定，外挂式阻燃性密目安全网，续燃、阴燃时间均不应大于4s，网眼孔径不应大于12mm，颜色应采用灰色。", "options": ["正确", "错误"], "answer": [0], "explanation": "2.1外挂式阻燃性密目安全网，续燃、阴燃时间均不应大于4s，网眼孔径不应大于12mm，颜色应采用灰色。"},
  {"id": 1520, "type": "judge", "question": "《房屋建筑工程文明施工提升标准》规定，大开间楼层临边、楼梯扶手栏杆等位置，应使用固定化防护网片，固定安全可靠。", "options": ["正确", "错误"], "answer": [1], "explanation": "大开间楼层临边、基坑临边、超过4m的较大洞口临边、楼梯扶手栏杆、电梯井口防护门、施工升降机防护门等位置，应使用标准化定型化防护网片，固定安全可靠。深基坑应设置定型化上下作业梯笼。"},
  {"id": 1521, "type": "judge", "question": "《房屋建筑工程文明施工提升标准》规定，施工单位应在围墙上安装喷雾降尘装置，在空气重污染预警启动或易扬尘作业时自动开启。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《房屋建筑工程文明施工提升标准》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1522, "type": "judge", "question": "《建筑施工场界环境噪声排放标准》GB12523-2011规定，建筑施工过程中场界环境噪声不得超过规定的排放限值。夜间噪声最大声级超过限值的幅度不得高于15dB(A) 。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑施工场界环境噪声排放标准》\n【解析】该说法错误。题干中的主体、程序、禁止性要求或控制数值与现行规定不一致。"},
  {"id": 1523, "type": "judge", "question": "施工现场建设工程垃圾管理违反规定的施工工地，经整改通过后才可申报本市文明施工工地。", "options": ["正确", "错误"], "answer": [1], "explanation": "有下列情况之一的工程项目，不能申报市\"安全文明工地\":\n(一)没有向建设工程安全监督站提出创建市\"安全文明工地\"申请，并在市安监站备案的\n(二)发生四级及其以上重大安全事故或发生重大质量事故的\n(三)受到通报批评的、不良行为记录的、经济处罚的\n(四)发生重大火灾和治安事件以及发生10人以上食物中毒事件的\n(五)因严重扰民、野蛮施工受到举报、投诉被新闻媒体曝光并经查实的\n(六)在尚未竣工的建筑物内设置员工集体宿舍的。"},
  {"id": 1524, "type": "judge", "question": "本市实施建筑垃圾资源化利用产品的强制使用制度，明确产品使用的范围、比例和质量等方面的要求。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1525, "type": "judge", "question": "绿色施工基于可持续发展思想，以提高经济效益、减员增效和保护环境为典型特征，是对传统施工模式的创新。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《绿色施工导则》 / 《建筑工程绿色施工评价标准》GB/T 50640-2010\n【解析】该说法错误。题干中的主体、程序、禁止性要求或控制数值与现行规定不一致。"},
  {"id": 1526, "type": "judge", "question": "《绿色施工导则》要求，材料运输工具适宜，装卸方法得当，防止损坏和遗洒。根据现场平面布置情况就近卸载，避免和减少二次搬运。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《绿色施工导则》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1527, "type": "judge", "question": "根据《绿色施工导则》对临时用地保护的要求，应对深基坑施工方案进行优化，减少土方开挖和回填量，最大限度地减少对土地的扰动，保护周边自然生态环境。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《绿色施工导则》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1528, "type": "judge", "question": "《安全生产法》规定，国务院应急管理部门对全国安全生产工作实施综合监督管理；市级以上地方各级人民政府应急管理部门对本行政区域内安全生产工作实施综合监督管理。", "options": ["正确", "错误"], "answer": [1], "explanation": "【依据】《中华人民共和国安全生产法》\n【解析】该说法错误。题干中的主体、程序、禁止性要求或控制数值与现行规定不一致。"},
  {"id": 1529, "type": "judge", "question": "《上海市建设工程质量和安全管理条例》规定，建设行政管理部门在履行建设工程安全监督管理职责时，无权要求被检查单位提供有关建设工程质量和安全的资料。", "options": ["正确", "错误"], "answer": [1], "explanation": "《上海市建设工程质量和安全管理条例》规定，建设行政管理部门在履行建设工程安全监督管理职责时，有权要求被检查单位提供有关建设工程质量和安全的资料。"},
  {"id": 1530, "type": "judge", "question": "《上海市建设工程安全质量监督总站主要职责、内设机构和人员编制方案》规定，上海市建设工程安全质量监督总站负责本市建设工程安全质量、文明施工及相关工作的监督、管理和指导，负责本市建设工程现场监督管理信息的管理。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《上海市建设工程安全质量监督总站主要职责、内设机构和人员编制方案》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1531, "type": "judge", "question": "建设行政管理部门和其他有关部门在履行建设工程质量和安全监督管理职责时，有权要求被检查单位提供有关建设工程质量和安全的资料。", "options": ["正确", "错误"], "answer": [0], "explanation": "建设行政管理部门和其他有关部门在履行建设工程质量和安全监督管理职责时，有权采取下列措施：\n(一)要求被检查单位提供有关建设工程质量和安全的资料;"},
  {"id": 1532, "type": "judge", "question": "《上海市建设工程质量和安全管理条例》规定，建设行政管理部门和其他有关部门在履行建设工程质量和安全监督管理职责时，发现有影响建设工程质量的问题或者安全事故隐患时，有权责令改正或者立即排除；重大安全事故隐患排除前或者排除过程中无法保证安全的，责令从危险区域内撤出作业人员或者暂停施工。", "options": ["正确", "错误"], "answer": [0], "explanation": "第五十五条建设行政管理部门和其他有关部门在履行建设工程质量和安全监督管理职责时，有权采取下列措施：\n（一） 要求被检查单位提供有关建设工程质量和安全的资料；\n（二） 进入被检查单位的施工现场进行检查，并将检查的时间、地点、内容、发现的问题及其处理情况，作出书面记录；\n（三） 发现有影响建设工程质量的问题或者安全事故隐患时，责令改正或者立即排除；重大安全事故隐患排除前或者排除过程中无法保证安全的，责令从危险区域内撤出作业人员或者暂停施工；\n（四） 法律、法规规定采取的其他措施。"},
  {"id": 1533, "type": "judge", "question": "《上海市建设工程施工安全监督管理办法》规定，施工单位应当负责本单位承担的施工任务范围内全部的安全管理工作。", "options": ["正确", "错误"], "answer": [0], "explanation": "第七条 （施工单位的安全管理责任）\n施工单位应当负责本单位承担的施工任务范围内全部的安全管理工作。但施工承包合同中另有约定的，从其约定。"},
  {"id": 1534, "type": "judge", "question": "《上海市建设工程施工安全监督管理办法》规定，从事电工、金属焊接、起重机械设备操作等特殊工种作业的人员，应当按照国家有关规定组织专业培训，经考核后才能上岗。", "options": ["正确", "错误"], "answer": [1], "explanation": "从事电工、金属焊接、起重机械设备操作等特殊工种作业的人员，应当按照国家有关规定组织专业培训，经考核合格后持证上岗。"},
  {"id": 1535, "type": "judge", "question": "《上海市建设工程施工安全监督管理办法》规定，施工单位在施工现场的项目经理为全面负责施工安全管理的责任人。", "options": ["正确", "错误"], "answer": [1], "explanation": "第十条（施工安全管理责任人的确定）施工工地管理单位和施工单位应当在施工开始前，按照下列规定确定施工安全管理的责任人：\n（一）施工工地管理单位在施工工地的主管人员为全面负责施工安全管理的责任人；\n（二）施工单位在施工现场的项目经理为所在施工单位负责施工安全管理的责任人。"},
  {"id": 1536, "type": "judge", "question": "《上海市建设工程施工安全监督管理办法》规定，建设工程涉及公共安全的，施工单位应当按照有关规定，在施工现场周围设置专项的公共安全防护设施。", "options": ["正确", "错误"], "answer": [0], "explanation": "建设工程涉及公共安全的，施工单位应当按照有关规定，在施工现场周围设置专项的公共安全防护设施。公共安全防护设施的有关费用应当在施工承包合同中约定；施工承包合同中未作约定的，应当由建设单位负担。"},
  {"id": 1537, "type": "judge", "question": "《上海市建设工程施工安全监督管理办法》规定，施工人员对管理人员违反施工安全技术标准或者安全操作规程的作业指令，有权拒绝执行，并可以向施工安全管理责任人或者安全监督员报告。", "options": ["正确", "错误"], "answer": [0], "explanation": "施工人员对管理人员违反施工安全技术标准或者安全操作规程的作业指令，有权拒绝执行，并可以向施工安全管理责任人或者安全监督员报告。"},
  {"id": 1538, "type": "judge", "question": "《房屋建筑和市政基础设施工程施工安全监督规定》规定，工程项目因故中止施工的，监督机构对工程项目终止施工安全监督。", "options": ["正确", "错误"], "answer": [1], "explanation": "第十一条 工程项目因故中止施工的，监督机构对工程项目中止施工安全监督。\n工程项目经建设、监理、施工单位确认施工结束的，监督机构对工程项目终止施工安全监督。"},
  {"id": 1539, "type": "judge", "question": "《上海市建设工程质量安全监督管理规定》规定，在建设单位取得施工许可后，监督机构应制作监督告知书，明确相对固定的工程监督联系人，该人负责与受监工程的日常联系、工程监督资料的日常保管和监督档案归档。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《上海市建设工程质量安全监督管理规定》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1540, "type": "judge", "question": "《上海市建设工程质量安全监督管理规定》规定，监督机构对每个项目的质量安全监督抽查次数为每月不应少于一次。", "options": ["正确", "错误"], "answer": [1], "explanation": "监督机构对每个项目的质量安全监督抽查次数为每季度不应少于一次。"},
  {"id": 1541, "type": "judge", "question": "《上海市建设工程质量安全监督管理规定》规定，监督机构收到建设单位的工程质量竣工验收书面通知后，应派监督人员监督工程竣工验收，重点对验收的组织形式、程序等是否符合有关规定进行监督。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《上海市建设工程质量安全监督管理规定》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1542, "type": "judge", "question": "《上海市建设工程质量安全监督管理规定》规定，监督机构应当按照有关规定，将工程质量安全监督中发现的涉及主体基础部分和主要使用功能的工程质量问题及整改情况，及时向社会公布。", "options": ["正确", "错误"], "answer": [1], "explanation": "将工程质量监督中发现的涉及【主体结构安全】和主要使用功能的工程质量问题及整改情况，及时向社会公布。"},
  {"id": 1543, "type": "judge", "question": "《上海市建设工程质量安全巡查管理办法》规定，对开具《暂停施工指令书》的项目，应在责任单位整改完成，并经工程监管机构确认后，由市住建委或区建管部门开具复工通知书。", "options": ["正确", "错误"], "answer": [0], "explanation": "对开具《暂停施工指令书》的项目，应在责任单位整改完成，并经工程监管机构确认后，由市住建委或区建管部门开具复工通知书。"},
  {"id": 1544, "type": "judge", "question": "根据《上海市建设工程质量安全巡查管理办法》规定《巡查处置建议书》销项后，市住建委应对项目整改落实的真实情况进行“再升级”抽查。", "options": ["正确", "错误"], "answer": [1], "explanation": "《巡查处置建议书》销项后，市住建委应对项目整改落实的真实情况进行“回头看”抽查。"},
  {"id": 1545, "type": "judge", "question": "《关于进一步优化本市建筑工程质量安全监督和综合竣工验收管理工作的通知》规定，风险级别为高风险和超高风险的项目，由建设单位项目负责人组织施工单位技术负责人、设计单位项目负责人和项目总监理工程师实施风险识别。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《关于进一步优化本市建筑工程质量安全监督和综合竣工验收管理工作的通知》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1546, "type": "judge", "question": "我国《民法典》、《行政处罚法》和《刑法》分别规定了民事法律责任、行政法律责任和刑事法律责任的的性质，保证了国家法制的权威性。", "options": ["正确", "错误"], "answer": [1], "explanation": "我国《民法典》、《行政处罚法》和《刑法》分别规定了民事法律责任、行政法律责任和刑事法律责任的的种类，保证了国家法制的统一性。"},
  {"id": 1547, "type": "judge", "question": "停止侵权主要适用于所有侵犯他人合法权益（包括侵犯财产权和侵犯人身权）的行为。", "options": ["正确", "错误"], "answer": [1], "explanation": "停止侵害这种民事责任适用于所有正在进行中的侵犯他人合法权益的行为,侵犯财产权和侵犯人身权都应当承担此种责任。"},
  {"id": 1548, "type": "judge", "question": "民事责任主要是一种财产责任，在确定财产责任范围的大小时，一般是按照惩罚性的原则确定的，即按照不履行民事义务或侵权行为所造成的实际经济损失确定赔偿数额，是一种等价赔偿。", "options": ["正确", "错误"], "answer": [1], "explanation": "民事责任可以分为财产责任和非财产责任。其中当民事责任体现为一种财产责任时，在确定财产责任范围的大小时，一般是按照【补偿性原则】来确定的，即按照不履行民事义务【和】侵权行为所造成的实际经济损失确定赔偿数额，是一种等价赔偿，这一点与行政责任、刑事责任不同。行政、刑事责任给予法人的经济处罚，不具有等价赔偿性质，如对法人的违法收入，行政管理机关可以给予违法数额数倍以上的处罚，且处罚所取得的款项归国家所有。"},
  {"id": 1549, "type": "judge", "question": "我国《行政处罚法》的七种行政处罚：警告，罚款，没收违法所得、没收非法财物，责令停产停业，暂扣或者吊销许可证、暂扣或者吊销执照、行政拘留均由行政主体行使。", "options": ["正确", "错误"], "answer": [0], "explanation": "第九条 行政处罚的种类：\n（一）警告、通报批评；\n（二）罚款、没收违法所得、没收非法财物；\n（三）暂扣许可证件、降低资质等级、吊销许可证件；\n（四）限制开展生产经营活动、责令停产停业、责令关闭、限制从业；\n（五）行政拘留；\n（六）法律、行政法规规定的其他行政处罚。"},
  {"id": 1550, "type": "judge", "question": "附加刑只能附加适用，不可以独立适用。", "options": ["正确", "错误"], "answer": [1], "explanation": "附加刑不是只能附加适用不能独立使用,而是既可以附加适用也可以独立适用。"},
  {"id": 1551, "type": "judge", "question": "最高检《关于办理危害生产安全刑事责任案件适用法律若干问题的解释》明确规定，发生安全生产事故，造成死亡一人以上，或者重伤三人以上的、造成直接经济损失一百万元以上的、其他造成严重后果或者重大安全事故的情形之一的，应当认定为“造成重大安全事故”，对直接责任人员，处三年以下有期徒刑或者拘役，并处罚金。", "options": ["正确", "错误"], "answer": [1], "explanation": "第六条 实施刑法第一百三十二条、第一百三十四条第一款、第一百三十五条、第一百三十五条之一、第一百三十六条、第一百三十九条规定的行为，因而发生安全事故，具有下列情形之一的，应当认定为“造成严重后果”或者“发生重大伤亡事故或者造成其他严重后果”，对相关责任人员，处三年以下有期徒刑或者拘役：\n（一）造成死亡一人以上，或者重伤三人以上的；\n（二）造成直接经济损失一百万元以上的；\n（三）其他造成严重后果或者重大安全事故的情形。\n实施刑法第一百三十四条第二款规定的行为，因而发生安全事故，具有本条第一款规定情形的，应当认定为“发生重大伤亡事故或者造成其他严重后果”，对相关责任人员，处五年以下有期徒刑或者拘役。\n实施刑法第一百三十七条规定的行为，因而发生安全事故，具有本条第一款规定情形的，应当认定为“造成重大安全事故”，对直接责任人员，处五年以下有期徒刑或者拘役，并处罚金。\n实施刑法第一百三十八条规定的行为，因而发生安全事故，具有本条第一款第一项规定情形的，应当认定为“发生重大伤亡事故”，对直接责任人员，处三年以下有期徒刑或者拘役。"},
  {"id": 1552, "type": "judge", "question": "《安全生产法》规定，生产经营单位的主要负责人受刑事处罚或者撤职处分的，自刑罚执行完毕或者受处分之日起，3年内不得担任任何生产经营单位的主要负责人；对重大、特别重大生产安全事故负有责任的，3年内不得担任本行业生产经营单位的主要负责人。", "options": ["正确", "错误"], "answer": [1], "explanation": "【依据】《中华人民共和国安全生产法》\n【解析】该说法错误。题干中的主体、程序、禁止性要求或控制数值与现行规定不一致。"},
  {"id": 1553, "type": "judge", "question": "《安全生产法》规定，生产经营单位未按照规定对从业人员、被派遣劳动者、实习学生进行安全生产教育和培训，或者未按照规定如实告知有关的安全生产事项的，责令限期改正，处十万元以下的罚款。", "options": ["正确", "错误"], "answer": [0], "explanation": "第九十七条 生产经营单位有下列行为之一的，责令限期改正，处十万元以下的罚款；逾期未改正的，责令停产停业整顿，并处十万元以上二十万元以下的罚款， 对其直接负责的主管人员和其他直接责任人员处二万元以上五万元以下的罚款：\n（三）未按照规定对从业人员、被派遣劳动者、实习学生进行安全生产教育和培训，或者未按照规定如实告知有关的安全生产事项的；"},
  {"id": 1554, "type": "judge", "question": "《安全生产法》规定，生产经营单位未对安全设备进行经常性维护、保养和定期检测的，责令限期改正，处五万元以下的罚款；逾期未改正的，处五万元以上二十万元以下的罚款。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《中华人民共和国安全生产法》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1555, "type": "judge", "question": "《安全生产法》规定，高危行业、领域的生产经营单位未按照国家规定投保工程质量保险，责令限期改正，处五万元以上十万元以下的罚款；逾期未改正的，处十万元以上二十万元以下的罚款。", "options": ["正确", "错误"], "answer": [1], "explanation": "第一百零九条 高危行业、领域的生产经营单位未按照国家规定投保安全生产责任保险的，责令限期改正，处五万元以上十万元以下的罚款；逾期未改正的，处十万元以上二十万元以下的罚款。"},
  {"id": 1556, "type": "judge", "question": "《安全生产违法行为行政处罚办法》规定，生产经营单位不具备法律、行政法规和国家标准、行业标准规定的安全生产条件，经责令停产停业整顿仍不具备安全生产条件的，安全监管监察部门应当提请有管辖权的人民政府予以关闭；人民政府决定关闭的，安全监管监察部门应当依法暂扣其有关许可证。", "options": ["正确", "错误"], "answer": [1], "explanation": "第四十八条 生产经营单位不具备法律、行政法规和国家标准、行业标准规定的安全生产条件，经责令停产停业整顿仍不具备安全生产条件的，安全监管监察部门应当提请有管辖权的人民政府予以关闭；人民政府决定关闭的，安全监管监察部门应当依法吊销其有关许可证。"},
  {"id": 1557, "type": "judge", "question": "《安全生产违法行为行政处罚办法》规定，对同一生产经营单位及其有关人员的同一安全生产违法行为，可以给予两次以上罚款的行政处罚。", "options": ["正确", "错误"], "answer": [1], "explanation": "【依据】《安全生产违法行为行政处罚办法》\n【解析】该说法错误。题干中的主体、程序、禁止性要求或控制数值与现行规定不一致。"},
  {"id": 1558, "type": "judge", "question": "《安全生产违法行为行政处罚办法》规定，生产经营单位及其有关人员主动消除或者减轻安全生产违法行为危害后果的，应当从轻或者减轻行政处罚。", "options": ["正确", "错误"], "answer": [0], "explanation": "第五十六条 生产经营单位及其有关人员有下列情形之一的，应当依法从轻或者减轻行政处罚：\n（二）主动消除或者减轻安全生产违法行为危害后果的；"},
  {"id": 1559, "type": "judge", "question": "未取得相应资格、资质证书的有关人员从事安全评价、认证、检测、检验工作，责令停止违法行为，并对有关人员处5千元以上1万元以下的罚款。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干中的主体、程序或控制数值与现行规定一致，属于直接记忆点。"},
  {"id": 1560, "type": "judge", "question": "《关于加强建筑施工安全事故责任企业人员处罚的意见》规定，建筑施工企业承担安全生产主体责任，必须遵守安全生产法律、法规，建立、健全安全生产责任制和安全生产规章制度。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《关于加强建筑施工安全事故责任企业人员处罚的意见》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1561, "type": "judge", "question": "《安全生产法》第二十七条规定生产经营单位的特种作业人员必须按照国家有关规定经专门的安全作业培训，取得相应资格，方可上岗作业。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《中华人民共和国安全生产法》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1562, "type": "judge", "question": "根据《建筑起重机械安全监督管理规定》，建筑起重机械出现故障或者发生异常情况的，使用单位应当在当日完工后，进行隐患排查。", "options": ["正确", "错误"], "answer": [1], "explanation": "建筑起重机械出现故障或者发生异常情况的，立即停止使用，消除故障和事故隐患后，方可重新投入使用。"},
  {"id": 1563, "type": "judge", "question": "根据《建筑起重机械安全监督管理规定》，施工现场有多台塔式起重机作业时，施工总承包单位应当组织制定并实施防止塔式起重机相互碰撞的安全措施。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑起重机械安全监督管理规定》\n【解析】该说法错误。题干中的主体、程序、禁止性要求或控制数值与现行规定不一致。"},
  {"id": 1564, "type": "judge", "question": "根据《建筑施工企业安全生产许可证管理规定》，建筑施工企业依法参加工伤保险，依法为施工现场从事危险作业的人员办理意外伤害保险，由从业人员自行交纳保险费。", "options": ["正确", "错误"], "answer": [1], "explanation": "第四条 建筑施工企业取得安全生产许可证，应当具备下列安全生产条件：\n（七）依法参加工伤保险，依法为施工现场从事危险作业的人员办理意外伤害保险，为从业人员交纳保险费；"},
  {"id": 1565, "type": "judge", "question": "国际劳工组织是以国家为单位参加的国际组织，但在组织结构上实行独特的“三方性”原则。", "options": ["正确", "错误"], "answer": [0], "explanation": "国际劳工组织是以国家为单位参加的国际组织，但在组织结构上实行独特的“三方性”原则，即参加各种会议和活动的成员国代表团由政府、雇主组织和工人组织的代表组成，三方代表有平等独立的发言和表决权。"},
  {"id": 1566, "type": "judge", "question": "本市规定，为降低建设工地的噪声污染，制定了建设工地施工分贝控制值，晚上23时至次晨6时除连续振捣混凝土和采用钻孔灌柱桩工艺外控制在70分贝以内。", "options": ["正确", "错误"], "answer": [1], "explanation": "夜间（22:00至次日6:00）噪声限值55分贝；"},
  {"id": 1567, "type": "judge", "question": "《建筑业安全卫生公约》约定，凡若干雇主或独立劳动者同时在同一建筑工地从事活动时，他们有责任按照国家法律或条例的要求在执行规定的安全和卫生措施方面进行合作。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑业安全卫生公约》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1568, "type": "judge", "question": "《建筑业安全卫生公约》规定，构架和构件、模板、临时支架和支撑的架设只能在项目经理监督下进行。", "options": ["正确", "错误"], "answer": [1], "explanation": "【依据】《建筑业安全卫生公约》\n【解析】该说法错误。题干中的主体、程序、禁止性要求或控制数值与现行规定不一致。"},
  {"id": 1569, "type": "judge", "question": "建筑施工安全生产技术指的是发现建筑施工过程中未知或潜在危险因素及其危害的工艺和方法。", "options": ["正确", "错误"], "answer": [1], "explanation": "建筑施工安全技术是指消除或控制建筑施工过程中已知或潜在危险因素及减少其危害的工艺和方法。"},
  {"id": 1570, "type": "judge", "question": "建筑施工安全生产技术应包括建筑施工危险源识别、建筑施工安全风险评估和建筑施工安全生产技术方案分析。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1571, "type": "judge", "question": "开挖深度15m及以上的基坑（槽）的土方开挖、支护、降水工程属于Ⅲ类危险等级。", "options": ["正确", "错误"], "answer": [1], "explanation": "该说法错误。按基坑工程危险等级（风险）划分：开挖深度≥5m的基坑（槽）土方开挖、支护、降水工程属于一级（最高、红色）危险等级；Ⅲ类（三级、黄色）对应开挖深度未超过3m但地质条件、周围环境复杂的情形。开挖深度15m及以上属最高危险等级，并非Ⅲ类。"},
  {"id": 1572, "type": "judge", "question": "为了保证施工安全，对采用新工艺的建筑工程，在制定和实施施工方案时，必须有专项施工安全生产技术分析报告。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1573, "type": "judge", "question": "采用有可靠依据的方法分析确定安全生产技术的可靠性和有效性。", "options": ["正确", "错误"], "answer": [0], "explanation": "采用有可靠依据的方法分析确定安全技术方案的可靠性和有效性；"},
  {"id": 1574, "type": "judge", "question": "安全生产技术措施实施的过程控制应以数据分析、信息分析以及过程监测反馈为基础。", "options": ["正确", "错误"], "answer": [0], "explanation": "安全技术措施实施的过程控制应以数据分析、信息分析以及过程监测反馈为基础。"},
  {"id": 1575, "type": "judge", "question": "建筑施工安全生产技术措施应按危险等级分级控制，Ⅰ级应采取监测预警技术进行局部或分段过程监控。", "options": ["正确", "错误"], "answer": [1], "explanation": "建筑施工安全技术监测与预警应根据危险等级分级进行，并满足下列要求：\nⅠ级：采用监测预警技术进行全过程监测控制；\nⅡ级：采用监测预警技术进行局部或分段过程监测控制。"},
  {"id": 1576, "type": "judge", "question": "安全生产技术交底应有书面记录，交底双方应履行签字手续，书面记录应在交底者和被交底者双方留存备查。", "options": ["正确", "错误"], "answer": [1], "explanation": "安全技术交底应有书面记录,交底双方应履行签字手续,书面记录应由交底者、被交底者和安全管理者只方留存备查。"},
  {"id": 1577, "type": "judge", "question": "安全生产技术交底活动是在工程施工开工初期组织全体工程技术人员、现场管理人员和施工作业人员开展这项活动，让施工作业人员能够提前了解施工中需要控制的工艺、工序、质量和安全注意事项。", "options": ["正确", "错误"], "answer": [1], "explanation": "安全技术交底活动是施工管理中的重要组成部分。安全技术交底活动是施工安全管理中不可缺少的过程。是一种超前的管理手段。必须安排在工程施工【开工前】组织全体工程技术人员、现场管理人员和施工作业人员开展这项活动，让施工作业人员能够提前了解施工中需要控制的工艺、工序、质量和安全注意事项，提前对施工中需要关注的问题进行理解和消化，最大限度的避免质量和安全事故，实现安全、优质、高效的完成施工任务的目标。"},
  {"id": 1578, "type": "judge", "question": "施工单位应建立分级、分层次的安全生产技术交底制度。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建设工程安全生产管理条例》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1579, "type": "judge", "question": "施工现场安全生产技术措施实施验收应在实施责任主体单位自行检查评定合格的基础上进行，且安全生产技术措施实施验收应有明确的验收结果意见。", "options": ["正确", "错误"], "answer": [0], "explanation": "施工现场安全技术措施实施验收应在实施责任主体单位自行检查评定合格的基础上进行，安全技术措施实施验收应有明确的验收结果意见；"},
  {"id": 1580, "type": "judge", "question": "安全生产技术文件建档起止时限，应从工程施工准备阶段到工程竣工验收合格止。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1581, "type": "judge", "question": "归档文件应按《建设工程过程文件归档整理规范》GB/T50328附录的范围和内容收集齐全、分类整理、规范装订后归档。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建设工程过程文件归档整理规范》\n【解析】该说法正确。题干中的主体、程序或控制数值与现行规定一致，属于直接记忆点。"},
  {"id": 1582, "type": "judge", "question": "建筑施工安全生产技术监测是指在建筑施工过程中现场安全信息、数据进行收集、汇总、分析和反馈的技术活动。", "options": ["正确", "错误"], "answer": [0], "explanation": "建筑施工安全技术监测对建筑施工过程中现场安全信息、数据进行收集、汇总、分析和反馈的技术活动。"},
  {"id": 1583, "type": "judge", "question": "建筑施工安全生产技术监测与预警应根据危险等级分级进行，如果是Ⅰ级，应采用监测预警技术进行全过程监测控制。", "options": ["正确", "错误"], "answer": [0], "explanation": "建筑施工安全技术监测与预警应根据危险等级分级进行，并满足下列要求：\n1 Ⅰ级：采用监测预警技术进行全过程监测控制；\n2 Ⅱ级：采用监测预警技术进行局部或分段过程监测控制。"},
  {"id": 1584, "type": "judge", "question": "根据建筑施工生产安全事故应急救援预案，应对全体从业人员进行针对性的培训和交底，并组织专项应急救援演练。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《中华人民共和国安全生产法》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1585, "type": "judge", "question": "基坑是指为进行建（构）筑物地下部分的施工，由地面向下开挖出的空间。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑基坑支护技术规程》JGJ 120-2012 / 《建筑基坑工程监测技术标准》GB 50497-2019\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1586, "type": "judge", "question": "基础埋置不深，施工期较短，挖基坑时不影响邻近建筑物的安全属于无支护基坑的特点。", "options": ["正确", "错误"], "answer": [0], "explanation": "无支护基坑特点和主要形式特点：\n1、基础埋置不深，施工期较短，挖基坑时不影响邻近建筑物的安全。\n2、地下水位低于基底，或者渗透量小，不影响坑壁稳定性。\n主要形式：\n无支护基坑的坑壁形式分为垂直坑壁、斜坡和阶梯形坑壁以及变坡度坑壁。"},
  {"id": 1587, "type": "judge", "question": "基坑工程安全要点主要包括了基坑围（支）护、降排水、基坑开挖、坑边荷载及安全防护、基坑监测、支撑拆除等。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑基坑支护技术规程》JGJ 120-2012 / 《建筑基坑工程监测技术标准》GB 50497-2019\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1588, "type": "judge", "question": "基坑工程不同于其他工程，其功能是承上启下，其显著的特点是临时性、区域性、时空效应、环境效应和综合性等。", "options": ["正确", "错误"], "answer": [0], "explanation": "基坑工程不同于其他工程,它的功能是承上启下,既涉及岩土工程,也涉及结构工程,其显著的特点是临时性、区域性、时空效应、环境效应和综合性等等。"},
  {"id": 1589, "type": "judge", "question": "基坑工程施工安全专项方案中工程概况包括了基坑所处的位置、基坑规模、基坑安全等级及周边环境安全、支护结构形式及相应附图等。", "options": ["正确", "错误"], "answer": [1], "explanation": "工程概况，包含基坑所处位置、基坑规模、基坑安全等级及现场勘查及环境调查结果、支护结构形式及相应附图；\n题目中【周边环境安全】属于危险源分析。"},
  {"id": 1590, "type": "judge", "question": "基坑底部和墙体外面大量的泥沙随地下水涌入基坑，导致坑外地面塌陷，严重时使墙体产生过大位移，引起整个支护体系崩塌，是导致墙体破坏的主要原因。", "options": ["正确", "错误"], "answer": [0], "explanation": "坑底部和墙体外面大量的泥砂随地下水涌入基坑，导致坑外地面坍陷，严重时使墙体产生过大位移，引起整个支护体系崩塌。"},
  {"id": 1591, "type": "judge", "question": "支护结构整体失稳的原因是基坑底部和墙体外面大量的泥沙随地下水涌入基坑，导致坑外地面塌陷。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑基坑支护技术规程》JGJ 120-2012 / 《建筑基坑工程监测技术标准》GB 50497-2019\n【解析】该说法错误。题干中的主体、程序、禁止性要求或控制数值与现行规定不一致。"},
  {"id": 1592, "type": "judge", "question": "当挡土结构入土深度不足，则会使基坑内土体大量隆起，基坑外土体过量沉陷，支撑系统应力陡增，导致支护结构整体失稳破坏。", "options": ["正确", "错误"], "answer": [0], "explanation": "基坑隆起：在软弱的粘性土层中开挖基坑，当基坑内的主体不断开挖，挡土结构内外土面的高差等于结构外在基坑开挖水平面上作用一附加荷载。挖深增大，荷载亦增加。当挡土结构入土深度不足，则会使基坑内土体大量隆起，基坑外土体过量沉陷，支撑系统应力陡增，导致支护结构整体失稳破坏。"},
  {"id": 1593, "type": "judge", "question": "编制专项施工方案是为了更好地指导基坑支护开挖作业，确保基坑及作业人员的安全。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《危险性较大的分部分项工程安全管理规定》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1594, "type": "judge", "question": "排桩适用于可采用降水或截水帷幕的基坑。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑基坑支护技术规程》JGJ 120-2012 / 《建筑基坑工程监测技术标准》GB 50497-2019\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1595, "type": "judge", "question": "当基坑潜在滑动面内有建（构）筑物、重要地下管线时，不宜采用土钉墙。", "options": ["正确", "错误"], "answer": [0], "explanation": "当基坑潜在滑动面内有建筑物、重要地下管线时，不宜采用土钉墙。"},
  {"id": 1596, "type": "judge", "question": "当基坑不同部位的周边环境条件、土层性状、基坑深度等不同时，可在不同部位分别采用不同的支护形式。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑基坑支护技术规程》JGJ 120-2012 / 《建筑基坑工程监测技术标准》GB 50497-2019\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1597, "type": "judge", "question": "基坑支护结构可采用左、右部以不同结构类型组合的形式。", "options": ["正确", "错误"], "answer": [1], "explanation": "基坑支护结构的类型主要分为三大类:外支护结构、内支护结构以及内外混合支护结构。"},
  {"id": 1598, "type": "judge", "question": "锚杆不宜用在软土层和高水位的碎石土、砂土层中。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1599, "type": "judge", "question": "对灵敏度较高的粉土、粉质黏土及可能产生液化的土体，可采用振动法施工土钉。", "options": ["正确", "错误"], "answer": [1], "explanation": "对于灵敏度较高的粉土、粉质粘土及可能产生液化的土体,禁止采用振动法施工土钉。"},
  {"id": 1600, "type": "judge", "question": "地下连续墙成槽施工前应进行成槽试验，并通过试验确定施工工艺及施工参数。", "options": ["正确", "错误"], "answer": [0], "explanation": "《建筑基坑支护技术规程》JGJ120-2012第4.6.1条指出：地下连续墙的施工应根据地质条件的适宜性等因素选择成槽设备。成槽施工前应进行成槽试验，并应通过试验确定施工工艺及施工参数。"},
  {"id": 1601, "type": "judge", "question": "地下连续墙施工时，每个单元槽段挖槽分段不宜超过3个。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑基坑支护技术规程》JGJ 120-2012 / 《建筑基坑工程监测技术标准》GB 50497-2019\n【解析】该说法正确。题干中的主体、程序或控制数值与现行规定一致，属于直接记忆点。"},
  {"id": 1602, "type": "judge", "question": "地下连续墙护壁泥浆拌制后应贮放24h，待泥浆材料充分水化后方可使用。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑基坑支护技术规程》JGJ 120-2012 / 《建筑基坑工程监测技术标准》GB 50497-2019\n【解析】该说法正确。题干中的主体、程序或控制数值与现行规定一致，属于直接记忆点。"},
  {"id": 1603, "type": "judge", "question": "混凝土浇筑完毕后，应及时在桩孔位置回填土方或加盖盖板。", "options": ["正确", "错误"], "answer": [0], "explanation": "混凝土浇筑完毕后，应及时在桩孔位置回填土方或加盖盖板。"},
  {"id": 1604, "type": "judge", "question": "当打桩机带锤走行时，应将桩锤放至最低位。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1605, "type": "judge", "question": "排水沟和集水井宜布置于地下结构外侧，距坡脚不宜小于0.5m。单级放坡基坑的降水井宜设置在坡顶，多级放坡基坑的降水井宜设置于坡顶、放坡平台。", "options": ["正确", "错误"], "answer": [0], "explanation": "排水沟和集水井宜布置于地下结构外侧，距坡脚不宜小于0.5m.单级放坡基坑的降水井宜设置在坡顶，多级放坡基坑的降水井宜设置于坡顶、放坡平台。"},
  {"id": 1606, "type": "judge", "question": "排水系统最大排水能力不宜小于工程所需最大排量的1.5倍。", "options": ["正确", "错误"], "answer": [1], "explanation": "排水系统最大排水能力不应小于工程所需最大排量的1.2倍。"},
  {"id": 1607, "type": "judge", "question": "当降水管井采用钻、冲孔法施工时，钻机转动部分应有安全防护装置。", "options": ["正确", "错误"], "answer": [0], "explanation": "当降水管井采用钻、冲孔法施工时，应符合下列规定：\n1 应采取措施防止机具突然倾倒或钻具下落造成人员伤亡或设备损坏。\n2 施工前先查明井位附近地下构筑物及地下电缆、水、煤气管道的情况，并应采取相应防护措施。\n3 钻机转动部分应有安全防护装置。\n4 在架空输电线附近施工，应按安全操作规程的有关规定进行，钻架与高压线之间应有可靠的安全距离。\n5 夜间施工应有足够的照明设备，对钻机操作台、传动及转盘等危险部位和主要通道不应留有黑影。"},
  {"id": 1608, "type": "judge", "question": "喷射井点施工时，每套喷射井点的井点数不宜超过30根，总管直径不宜小于100mm，总长不宜超过60m。", "options": ["正确", "错误"], "answer": [1], "explanation": "每套喷射井点的井点数不宜超过 30 根,总管直径不宜小于为 150mm, 总长不宜超过 60.0m。如果多套井点呈环圈布置,各套进水总管之间宜用阀门隔 开,每套井点自成系统。"},
  {"id": 1609, "type": "judge", "question": "采用与排桩咬合的高压喷射注浆截水帷幕时，应先进行排桩施工，后进行高压喷射注浆施工。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑基坑支护技术规程》JGJ 120-2012 / 《建筑基坑工程监测技术标准》GB 50497-2019\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1610, "type": "judge", "question": "土方开挖工程的施工工艺一般有两种：放坡开挖(无支护开挖)和在支护体系保护下进行开挖施工。因为简单经济，上海大多采用放坡开挖。", "options": ["正确", "错误"], "answer": [1], "explanation": "在城市施工，往往不具备放坡开挖的条件，只能采取有支护开挖。"},
  {"id": 1611, "type": "judge", "question": "土石方开挖顺序、方法必须与设计工况和施工方案相一致，并遵循“槽支撑，先撑后挖，分层开挖，严禁超挖”的原则。", "options": ["正确", "错误"], "answer": [0], "explanation": "土方开挖的顺序、方法必须与设计要求相一致,并遵循“开槽支撑,先撑后挖,分层开挖,严禁超挖”的原则。"},
  {"id": 1612, "type": "judge", "question": "基坑开挖应按照分层、分段、分块、对称、平衡、限时的方法确定开挖顺序。开挖后，支护结构、基坑土体加固、降水应达到设计和施工要求。", "options": ["正确", "错误"], "answer": [1], "explanation": "基坑开挖应按照分层、分段、分块、对称、平衡、限时的方法确定开挖顺序。基坑开挖前,支护结构、基坑土体加固、降水应达到设计和施工要求。"},
  {"id": 1613, "type": "judge", "question": "安全等级为一级、二级的支护结构，在基坑开挖过程与支护结构使用期内，必须进行支护结构的水平位移监测和基坑开挖影响范围内建（构）筑物、地面的沉降监测", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑基坑支护技术规程》JGJ 120-2012 / 《建筑基坑工程监测技术标准》GB 50497-2019\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1614, "type": "judge", "question": "。围护墙竖直方向监测点应布置在压力极值处。", "options": ["正确", "错误"], "answer": [1], "explanation": "竖直方向监测点应布置在弯矩极值处，且宜布置支撑处和相邻两层支撑的中间部位，间距宜为2m~4m"},
  {"id": 1615, "type": "judge", "question": "当发现基坑周边建(构)筑、道路、地面开裂时，应立即停止施工作业，撤离相关人员，待险情排除后方可恢复施工。", "options": ["正确", "错误"], "answer": [0], "explanation": "基坑(槽)、边坡和基础桩施工及模板作业时,施工单位应指定专人指挥、监护,出现位移、开裂及渗漏时,应立即停止施工,将作业人员撤离作业现场,待险情排除后,方可作业"},
  {"id": 1616, "type": "judge", "question": "孔隙水压力监测的同时测量孔隙水压力计埋设位置附近的地下水位，以便在计算中消除水位变化影响，获得真实的超孔隙水压力值。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1617, "type": "judge", "question": "基坑工程工作状态一般分为正常、异常和危险三种情况。", "options": ["正确", "错误"], "answer": [0], "explanation": "基坑工程工作状态一般分为正常,异常 和危险三种情况"},
  {"id": 1618, "type": "judge", "question": "板桩拔出时应采用先拔后注浆等措施减少对环境的影响。", "options": ["正确", "错误"], "answer": [1], "explanation": "板桩围护墙施工时，应采用适当的工艺和方法减少沉桩时的挤土与振动影响；板桩拔出时应采用边拔边注浆等措施"},
  {"id": 1619, "type": "judge", "question": "模板工程，通常包括：模板采购、模板运输、模板支撑体系、紧固件四大部分。", "options": ["正确", "错误"], "answer": [1], "explanation": "模板系统包括:模板、支撑系统、紧固件三大部分"},
  {"id": 1620, "type": "judge", "question": "永久式模板是指模板在混凝土浇筑过程中及混凝土强度增长过程中起模板作用，在结构使用过程中与结构连成一个整体，不再拆除。", "options": ["正确", "错误"], "answer": [0], "explanation": "永久式模板是指模板在混凝土浇筑过程中及混凝土强度增长过程中起模板作用，在结构使用过程中与结构连成一个整体，不再拆除，成为结构组成的一部分。"},
  {"id": 1621, "type": "judge", "question": "脚手架或操作平台上临时堆放的模板不宜超过3层。", "options": ["正确", "错误"], "answer": [0], "explanation": "脚手架或操作平台上临时堆放的模板不宜超过 3 层, 脚手架或操作平台上的施工总荷载不得超过其设计值。"},
  {"id": 1622, "type": "judge", "question": "雨期施工时，高耸结构的模板作业要安装避雷设施。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑施工模板安全技术规范》JGJ 162-2008\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1623, "type": "judge", "question": "现浇钢筋混凝土梁、板，当跨度大于4m时，模板应起拱。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑施工模板安全技术规范》JGJ 162-2008\n【解析】该说法正确。题干中的主体、程序或控制数值与现行规定一致，属于直接记忆点。"},
  {"id": 1624, "type": "judge", "question": "支撑梁、板的支架立柱，当层高大于20m时，水平拉杆的布置方式为：扫地杆与顶部水平拉杆之间的间距，进行平均分配确定步距后，在每一步距处纵横向应各设一道水平拉杆。", "options": ["正确", "错误"], "answer": [1], "explanation": "当层高大于20m时，在最顶两步距水平拉杆中间应分别增加一道水平拉杆。所有水平拉杆的端部均应与四周建筑物顶紧顶牢。无处可顶时，应在水平拉杆端部和中部沿竖向设置连续式剪刀撑。"},
  {"id": 1625, "type": "judge", "question": "吊运大块或整体模板时，竖向吊运不应少于两个吊点。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑施工模板安全技术规范》JGJ 162-2008\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1626, "type": "judge", "question": "支承梁式或桁架式支架的建筑结构应具有足够强度，否则，应另设立柱支撑。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1627, "type": "judge", "question": "立柱接长严禁搭接，必须采用对接扣件连接。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑施工扣件式钢管脚手架安全技术规范》JGJ 130-2011\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1628, "type": "judge", "question": "多层悬挑结构模板的上下立柱应保持在同一条垂直线上。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑施工模板安全技术规范》JGJ 162-2008\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1629, "type": "judge", "question": "混凝土浇筑时，必须按照专项施工方案规定的顺序进行。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《危险性较大的分部分项工程安全管理规定》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1630, "type": "judge", "question": "后张预应力混凝土结构的侧模宜在施加预应力前拆除。", "options": ["正确", "错误"], "answer": [0], "explanation": "后张预应力混凝土结构的侧模宜在施加预应力前拆除,底模应在施加预应力后拆除。"},
  {"id": 1631, "type": "judge", "question": "操作层上临时拆下的模板堆放不能超过4层。", "options": ["正确", "错误"], "answer": [1], "explanation": "操作层上临时拆下的模板堆放不能超过3层。"},
  {"id": 1632, "type": "judge", "question": "当支架立柱的水平拉杆超出2层时，应首先拆除2层以上的拉杆。", "options": ["正确", "错误"], "answer": [0], "explanation": "当立柱的水平拉杆超出2层时，应首先拆除2层以上的拉杆。当拆除最后一道水平拉杆时，应和拆除立柱同时进行。"},
  {"id": 1633, "type": "judge", "question": "柱模拆除应分别采用分散拆和分片拆两种方法。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑拆除工程安全技术规范》JGJ 147-2016\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1634, "type": "judge", "question": "拆除墙模时，应先拆除全部支撑系统，然后拆卸大块墙模接缝处的连接型钢及零配件。", "options": ["正确", "错误"], "answer": [0], "explanation": "预组拼大块墙模拆除顺序应为：拆除全部支撑系统、拆卸大块墙模接缝处的连接型钢及零配件、拧去固定埋设件的螺栓及大部分对拉螺栓、挂上吊装绳扣并略拉紧吊绳后，拧下剩余对拉螺栓，用方木均匀敲击大块墙模立楞及钢模板，使其脱离墙体，用撬棍轻轻外撬大块墙模板使全部脱离，指挥起吊、运走、清理、刷防锈油或脱模剂备用。"},
  {"id": 1635, "type": "judge", "question": "扣件式钢管满堂支撑架的可调底座、可调托撑螺杆伸出长度不宜超过300mm，插入立杆内的长度不得小于200mm。", "options": ["正确", "错误"], "answer": [1], "explanation": "可调托撑螺杆伸出长度不宜超过300mm，插入立杆内的长度不得小于150mm。"},
  {"id": 1636, "type": "judge", "question": "可移动的满堂支架脚手架搭设，应在外侧立面、内部纵向和横向间隔不大于4m由底部至顶部连续设置一道竖向剪刀撑。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑施工扣件式钢管脚手架安全技术规范》JGJ 130-2011\n【解析】该说法正确。题干中的主体、程序或控制数值与现行规定一致，属于直接记忆点。"},
  {"id": 1637, "type": "judge", "question": "悬挑梁间距应按悬挑架架体立杆纵距设置，每二纵距设置一根。", "options": ["正确", "错误"], "answer": [1], "explanation": "悬挑梁间距应按悬挑架架体立杆纵距设置,每一纵距设置一根。"},
  {"id": 1638, "type": "judge", "question": "纵向扫地杆作用是连接立杆下端，距底座下皮200mm处的纵向水平杆，可约束立杆底端在纵向发生位移。", "options": ["正确", "错误"], "answer": [0], "explanation": "纵向水平扫地杆连接立杆下端,是距底座下方200mm处的纵向水平杆,可约束立杆底端在纵向发生位移的作用."},
  {"id": 1639, "type": "judge", "question": "脚手架纵向水平杆接长应采用对接扣件连接或搭接。", "options": ["正确", "错误"], "answer": [0], "explanation": "纵向水平杆接长宜采用对接扣件连接，也可采用搭接。"},
  {"id": 1640, "type": "judge", "question": "扣件式钢管脚手架，单排脚手架门洞处，应在平面桁架的每一节间设置一根斜腹杆。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑施工扣件式钢管脚手架安全技术规范》JGJ 130-2011\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1641, "type": "judge", "question": "斜道脚手板顺铺时，接头应采用搭接，上面的板头应压住下面的板头，板头的凸棱应采用三角木填顺。", "options": ["正确", "错误"], "answer": [1], "explanation": "脚手板顺铺时，接头应采用搭接，下面的板头应压住上面的板头，板头的凸棱处应采用三角木填顺。"},
  {"id": 1642, "type": "judge", "question": "扣件式钢管满堂支撑架搭设高度不宜超过30m。", "options": ["正确", "错误"], "answer": [0], "explanation": "满堂支撑架搭设高度不宜超过30m"},
  {"id": 1643, "type": "judge", "question": "扣件式钢管脚手架开始搭设立杆时，应每隔6跨设置一根抛撑。", "options": ["正确", "错误"], "answer": [0], "explanation": "搭设立杆时,要每隔6跨设置一根抛撑,直至连墙件安装稳定后,才可视情况拆除。"},
  {"id": 1644, "type": "judge", "question": "双排脚手架拆除作业必须由下而上逐层进行，严禁整体同时作业。", "options": ["正确", "错误"], "answer": [1], "explanation": "双排脚手架拆除作业必须由上而下逐层进行，严禁上下同时作业。"},
  {"id": 1645, "type": "judge", "question": "承插型盘扣式支架，当搭设高度超过8m的满堂模板支架时，竖向斜杆应满布设置，水平杆的步距不得大于2.5m。", "options": ["正确", "错误"], "answer": [1], "explanation": "【依据】《建筑施工承插型盘扣式钢管脚手架安全技术标准》JGJ/T 231-2021\n【解析】该说法正确。题干中的主体、程序或控制数值与现行规定一致，属于直接记忆点。"},
  {"id": 1646, "type": "judge", "question": "挂扣式钢梯宜设置在尺寸不小于1.2m×1.8m的脚手架框架内，钢梯宽度应为廊道宽度的1/2。", "options": ["正确", "错误"], "answer": [1], "explanation": "挂扣式钢梯宜设置在尺寸不小于0. 9m× 1. 8m 的脚手架框架内，钢梯宽度应为廊道宽度的1/2 ，钢梯可在一个框架高度内折线上升；钢架拐弯处应设置钢脚手板及扶手杆。"},
  {"id": 1647, "type": "judge", "question": "脚手架作业层与主体结构间的空隙应设置内侧防护网。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1648, "type": "judge", "question": "轮扣节点由焊接于立杆的轮扣盘、水平杆的端插头和插销组成。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑施工扣件式钢管脚手架安全技术规范》JGJ 130-2011\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1649, "type": "judge", "question": "对于承插型轮扣式模板支架，当高宽比大于3且四周不具备拉结条件时，应采取扩大架体下部尺寸或其他构造措施。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑施工模板安全技术规范》JGJ 162-2008\n【解析】该说法正确。题干中的主体、程序或控制数值与现行规定一致，属于直接记忆点。"},
  {"id": 1650, "type": "judge", "question": "承插型轮扣式模板支架，立杆基础不在同一高度时，必须将高处的扫地杆与低处水平杆拉通。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑施工扣件式钢管脚手架安全技术规范》JGJ 130-2011\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1651, "type": "judge", "question": "搭设门式脚手架，水平架、脚手板、钢梯与门架的挂扣连接应有防止脱落的构造。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑施工门式钢管脚手架安全技术标准》JGJ/T 128-2019\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1652, "type": "judge", "question": "门式支撑架应按步在门架的两侧满设交叉支撑。", "options": ["正确", "错误"], "answer": [0], "explanation": "交叉支撑应在每列门架两侧设置,并应采用锁销与门架立杆锁牢,施工期间不得随意拆除。"},
  {"id": 1653, "type": "judge", "question": "门式作业脚手架连墙件应从作业脚手架的首层首步开始设置。", "options": ["正确", "错误"], "answer": [0], "explanation": "连墙件应从作业脚手架的首层首步开始设置,连墙点之上架体的悬臂高度不应超过2步"},
  {"id": 1654, "type": "judge", "question": "在门式支撑架的底层门架立杆上应分别设置纵横向通长扫地杆，并应采用扣件与门架立杆扣紧。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑施工扣件式钢管脚手架安全技术规范》JGJ 130-2011\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1655, "type": "judge", "question": "门式支撑架应采用逐列、逐排和逐层的方法搭设。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1656, "type": "judge", "question": "碗扣式脚手架，当土层地基上的立杆底部采用垫板时，垫板宜采用厚度不小于50mm、宽度不小于200mm，长度不少于两跨的木垫板。", "options": ["正确", "错误"], "answer": [0], "explanation": "土层地基上的立杆底部应设置底座和混凝土垫层，垫层混凝土标号不应低于C15，厚度不应小于150mm；当采用垫板代替混凝土垫层时，垫板宜采用厚度不小于50mm、宽度不小于200mm、长度不少于两跨的木垫板；"},
  {"id": 1657, "type": "judge", "question": "当碗扣式双排脚手架斜撑杆临时拆除时，拆除前应在相邻立杆间设置相同数量的斜撑杆。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑施工扣件式钢管脚手架安全技术规范》JGJ 130-2011\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1658, "type": "judge", "question": "当碗扣式钢管双排脚手架内立杆与建筑物距离大于200mm时，应采用脚手板或安全平网封闭。", "options": ["正确", "错误"], "answer": [1], "explanation": "双排脚手架内立杆与建筑物距离不宜大于150mm;当双排脚手架内立杆与建筑物距离大于150mm时,应采用脚手板或安全平网封闭。"},
  {"id": 1659, "type": "judge", "question": "桥梁碗扣式钢管模板支撑架顶面四周应设置作业平台，作业层宽度不应小于800mm。", "options": ["正确", "错误"], "answer": [1], "explanation": "桥梁模板支撑架顶面四周应设置作业平台,作业层宽度不应小于900mm,并应符合本规范第6.1.5条的规定。"},
  {"id": 1660, "type": "judge", "question": "碗扣式钢管脚手架应按顺序搭设，双排脚手架搭设应按斜杆、连墙件、水平杆、立杆的顺序逐步搭设。", "options": ["正确", "错误"], "answer": [1], "explanation": "根据《建筑施工碗扣式钢管脚手架安全技术规范》规定，双排脚手架搭设应按立杆、水平杆、斜杆、连墙件的顺序配合施工进度逐层搭设。"},
  {"id": 1661, "type": "judge", "question": "碗扣式钢管双排脚手架的斜撑杆、剪刀撑等加固件应在架体拆除之前拆除。", "options": ["正确", "错误"], "answer": [1], "explanation": "双排脚手架的斜撑杆、剪刀撑等加固件应在架体拆除至该部位时, 才能拆除。"},
  {"id": 1662, "type": "judge", "question": "当附着式升降脚手架架体升降采用中心吊时，在悬臂梁行程范围内竖向主框架内侧水平杆去掉部分的断面，应采取可靠的加固措施。", "options": ["正确", "错误"], "answer": [0], "explanation": "当架体升降采用中心吊时,在悬臂梁行程范围内竖向主框架内侧水平杆去掉部分的断面,应采取可靠的加固措施。"},
  {"id": 1663, "type": "judge", "question": "附着式防护平台的导轨之间的接头设置应成为柔性接头。", "options": ["正确", "错误"], "answer": [1], "explanation": "有振动的场所和埋地管道应采用柔性接头，其他场所宜采用刚性接头，当采用刚性接头时，每隔4～5个刚性接头应设置一个挠性接头，埋地连接时螺栓和螺母应采用不锈钢件。"},
  {"id": 1664, "type": "judge", "question": "附着式防护平台防倾斜装置中应包括导轨和两个以上与导轨连接的可滑动的导向件。在使用工况下，最上和最下两个导向件之间的最小间距不得小于2.8m或平台高度的1/4。", "options": ["正确", "错误"], "answer": [0], "explanation": "二、 防倾覆装置应符合下列规定：\n1、防倾覆装置中必须包括导轨和两个以上与导轨连接的可滑动的导向件；\n2、在防倾覆导向件的范围内应设置防倾覆导轨，且应与竖向主框架可靠连接；\n3、在升降和使用两种工况下，最上和最下两个导向件之间的最小间距不得小于2.8 m或架体高度的1/4；\n4、应具有防止竖向主框架倾斜的功能；\n5、应用螺栓与附墙支座连接，其装置与导向杆之间的间隙不应大于5mm。"},
  {"id": 1665, "type": "judge", "question": "当附着式防护平台停用超过3个月时，应提前采取加固措施。", "options": ["正确", "错误"], "answer": [0], "explanation": "当附着式升降脚手架停用超过3个月时，应提前采取加固措施。"},
  {"id": 1666, "type": "judge", "question": "超高层钢结构工程安全要点中，作业人员个人防护用品须符合要求。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1667, "type": "judge", "question": "超高层钢结构工程安全要点中，作业人员个人情绪及心态须符合要求。", "options": ["正确", "错误"], "answer": [0], "explanation": "超高层钢结构工程安全要点中，作业人员当天个人精神及身体状态须符合要求。"},
  {"id": 1668, "type": "judge", "question": "超高层钢结构工程安全要点中，作业人员工作着装须符合要求。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1669, "type": "judge", "question": "超高层钢结构工程安全要点中，须对当天作业存在的危险源、危险点进行交代。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1670, "type": "judge", "question": "大跨度及厂房钢结构工程安全要点中，作业人员个人安全防护用品须符合要求。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1671, "type": "judge", "question": "大跨度及厂房钢结构工程安全要点中，对当天作业的技术措施和安全措施进行交代，包括防高空坠落措施、防火星坠落等。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建设工程施工现场消防安全技术规范》GB 50720-2011 / 《中华人民共和国消防法》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1672, "type": "judge", "question": "大跨度及厂房钢结构工程安全要点中，对当天作业的施工措施和安全措施进行交代，包括防高空坠落措施、防火星坠落等。", "options": ["正确", "错误"], "answer": [1], "explanation": "大跨度及厂房钢结构工程安全要点中，对当天作业的【技术】措施和安全措施进行交代，包括防高空坠落措施、防火星坠落等。"},
  {"id": 1673, "type": "judge", "question": "市政类钢结构工程安全要点中，对当天作业的施工方案和安全措施进行交代。", "options": ["正确", "错误"], "answer": [1], "explanation": "市政类钢结构工程安全要点中，对当天作业的技术措施和安全措施进行交代"},
  {"id": 1674, "type": "judge", "question": "施工人员觉得身体不适，但本人认为仍可以带病工作的情况下，可以准许他工作。", "options": ["正确", "错误"], "answer": [1], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法错误。题干中的主体、程序、禁止性要求或控制数值与现行规定不一致。"},
  {"id": 1675, "type": "judge", "question": "钢结构工程的安全生产目标是保证作业人员的财产安全，保证不发生火灾事故，以及涂装作业人员的人身安全。", "options": ["正确", "错误"], "answer": [1], "explanation": "钢结构工程的安全生产目标是保证作业人员的人身和财产安全，保证施工机械和设备能够安全运行。"},
  {"id": 1676, "type": "judge", "question": "钢柱吊装采取登高摘钩的方法时，尽量使用安全带，对登高作业人员进行保护。", "options": ["正确", "错误"], "answer": [1], "explanation": "钢柱吊装采取登高摘钩的方法时，尽量使用防坠器，对登高作业人员进行保护。"},
  {"id": 1677, "type": "judge", "question": "钢柱吊装采取登高挂钩的方法时，尽量使用安全带，对登高作业人员进行保护。", "options": ["正确", "错误"], "answer": [1], "explanation": "钢柱吊装采取登高摘钩的方法时，尽量使用防坠器，对登高作业人员进行保护。"},
  {"id": 1678, "type": "judge", "question": "钢结构安装工程中的安全爬梯的承载必须经过结构计算。", "options": ["正确", "错误"], "answer": [1], "explanation": "安全爬梯的承载必须经过安全计算。"},
  {"id": 1679, "type": "judge", "question": "钢结构施工的平面安全通道宽度不宜小于600mm，且两侧应设置安全护栏和安全标志。", "options": ["正确", "错误"], "answer": [1], "explanation": "钢结构施工的平面安全通道宽度不宜小于 600mm,且两侧应设置安全护栏或防护钢丝绳。"},
  {"id": 1680, "type": "judge", "question": "钢结构施工的平面安全通道宽度不宜小于600mm，且两侧应设置安全护栏或防护钢丝绳。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干中的主体、程序或控制数值与现行规定一致，属于直接记忆点。"},
  {"id": 1681, "type": "judge", "question": "钢结构安装施工中，边长或直径为45cm的洞口应采用刚性盖板固定防护。", "options": ["正确", "错误"], "answer": [1], "explanation": "边长或直径为20cm~40cm的洞口应采用刚性盖板固定防护。"},
  {"id": 1682, "type": "judge", "question": "钢结构安装施工中，边长或直径为150cm以上的洞口应张设密目安全网防护并加护栏。", "options": ["正确", "错误"], "answer": [0], "explanation": "钢结构安装施工中，边长或直径为150cm以上的洞口应张设密目安全网防护并加护栏。"},
  {"id": 1683, "type": "judge", "question": "钢结构安装施工中，直径100cm的洞口不用架设钢管脚手架、满铺脚手板等。", "options": ["正确", "错误"], "answer": [1], "explanation": "边长或直径为40cm~150cm的洞口应架设钢管脚手架、满铺脚手板等。"},
  {"id": 1684, "type": "judge", "question": "钢结构安装施工中，建（构）筑物楼层钢梁吊装完毕后，可等需要了再分区铺设安全网。", "options": ["正确", "错误"], "answer": [1], "explanation": "屋架吊装以前,应预先在下弦挂设安全网;吊装完毕后,即将安全网铺设固定"},
  {"id": 1685, "type": "judge", "question": "起重吊装机械应安装限位装置，并应定期检查。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑施工起重吊装工程安全技术规范》JGJ 276-2012\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1686, "type": "judge", "question": "起重机应有良好的接地装置。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《施工现场临时用电安全技术规范》JGJ 46-2005\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1687, "type": "judge", "question": "吊装区域应设置安全警戒线，非作业人员可临时入内。", "options": ["正确", "错误"], "answer": [1], "explanation": "吊装区域应设置安全警戒线,非作业人员严禁入内。"},
  {"id": 1688, "type": "judge", "question": "高空作业使用的小型手持工具和小型零部件应采取防止坠落措施。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1689, "type": "judge", "question": "高空作业使用的小型手持工具和小型零部件应采取防止安全措施。", "options": ["正确", "错误"], "answer": [1], "explanation": "高空作业使用的小型手持工具和小型零部件应采取防止坠落措施。"},
  {"id": 1690, "type": "judge", "question": "钢结构安装施工，施工现场应有专业人员负责安装、维护和管理用电设备。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1691, "type": "judge", "question": "钢结构安装施工，静音切割和高空焊接作业时，应清除作业区危险品易燃物，并应采取防火措施。", "options": ["正确", "错误"], "answer": [0], "explanation": "在进行钢结构安装施工中的静音切割和高空焊接作业时，确实应当：\n1. 清除作业区的危险品和易燃物：以防止火花引发火灾或爆炸。\n2. 采取防火措施：例如准备灭火器、铺设防火毯、设置隔离带、安排专人监护等，确保一旦出现火情能够及时处理。\n这是建筑施工安全管理中非常基本且重要的要求，符合《建筑施工安全检查标准》（JGJ59）和《建筑施工现场消防安全技术规范》（GB50720）等相关规范。"},
  {"id": 1692, "type": "judge", "question": "钢结构防腐蚀工程安全要求，涂料仓库及施工现场应有消防水源、灭火器和消防器具，并应定期检查。消防道路应畅通。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建设工程施工现场消防安全技术规范》GB 50720-2011 / 《中华人民共和国消防法》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1693, "type": "judge", "question": "钢结构防腐蚀工程安全要求，涂装作业场所空气中有害物质可以超过最高允许浓度。", "options": ["正确", "错误"], "answer": [1], "explanation": "不得超过"},
  {"id": 1694, "type": "judge", "question": "钢结构防腐蚀工程安全要求，密闭空间涂装作业成后油漆在空气中的挥发物消散前，严禁电焊修补作业。", "options": ["正确", "错误"], "answer": [0], "explanation": "6.5.6 密闭空间涂装作业应使用防爆灯具，安装防爆报警装置；作业完成后油漆在空气中的挥发物消散前，严禁电焊修补作业。"},
  {"id": 1695, "type": "judge", "question": "钢结构防腐蚀工程安全要求，所有电气设备绝缘良好，临时电线应选用护套线，工作结束后应切断电源。", "options": ["正确", "错误"], "answer": [0], "explanation": "所有电器设备应绝缘良好,临时电线应选用胶皮线,工作结束后应切断电源。"},
  {"id": 1696, "type": "judge", "question": "钢结构安装工程施工时，高空操作必须配戴安全带，穿绝缘软底鞋，并作好安全措施。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1697, "type": "judge", "question": "钢结构安装工程施工时，高空现场作业人员应穿防水皮鞋，并作好安全措施。", "options": ["正确", "错误"], "answer": [1], "explanation": "现场施工人员均应戴安全帽，高空作业人员应佩戴安全带，并要高挂低用，并系在安全可靠的地方，现场作业人员穿好防滑鞋。"},
  {"id": 1698, "type": "judge", "question": "钢结构安装工程施工时，在结构基础安装完毕檩条就位安装后，须加固梁上弦安全支架。", "options": ["正确", "错误"], "answer": [1], "explanation": "在结构基础完毕，檩条就位安装后，需拆除梁上弦安全支架，在拆除安装支架前，在整榀梁的檩条之上，从两边柱底固定一个直径15mm长度90m的棕绳作安全绳挂安全带，才允许拆除安全支架，并进行其上方剩余檩条的安装。"},
  {"id": 1699, "type": "judge", "question": "钢结构安装工程施工时，在可以安全行走之前，屋面板连接在檩条上，可以在部分连接或未连接的屋面板上行走。", "options": ["正确", "错误"], "answer": [1], "explanation": "在可以安全行走之前,屋面板必须安全连接在檩条上,使每侧均与其他屋面板连接,绝不能在部分连接或未连接旳屋面板上行走。"},
  {"id": 1700, "type": "judge", "question": "钢结构安装工程施工时，高空作业人员所携带各种工具、螺栓等应在口袋中放好，在高空传递物品时，应挂好安全绳，不得随便抛掷，以防伤人。", "options": ["正确", "错误"], "answer": [1], "explanation": "高空作业人员所携带各种工具、螺栓等应在【专用工具袋】中放好，在高空传递物品时，应挂好安全绳，不得随便抛掷，以防伤人。"},
  {"id": 1701, "type": "judge", "question": "钢结构安装工程施工起吊构件时，速度不能太快，不能在高空停留太久，严禁猛升、降，以防构件脱落。", "options": ["正确", "错误"], "answer": [0], "explanation": "起吊构件时,速度不能太快,不能在高空停留太久,严禁猛升、降,以防构件脱落。"},
  {"id": 1702, "type": "judge", "question": "钢结构安装工程施工构件安装后，应检查各构件的连接和稳定情况，当连接确实安全可靠，方可松钩、卸索。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1703, "type": "judge", "question": "钢结构安装工程施工，对于夹层吊装时的松钩、卸索，施工人员应站在稳固可靠的梯子之上。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑施工起重吊装工程安全技术规范》JGJ 276-2012\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1704, "type": "judge", "question": "钢结构安装工程施工时，起重设备允许在斜坡道上工作，允许起重机两边高低差太大。", "options": ["正确", "错误"], "answer": [1], "explanation": "起重设备不允许在斜坡道上工作,不允许起重机两边高低差相差太多。"},
  {"id": 1705, "type": "judge", "question": "钢结构安装工程施工时，现场用电要有专门人员负责安装、管理、维护，严禁非电工人员随意拆改。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1706, "type": "judge", "question": "钢结构安装工程施工时，作业人员不要站在潮湿的地方使用电动工具或设备。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1707, "type": "judge", "question": "钢结构安装工程施工时，现场防火防爆必须备好消防器材、工具，并有专门消防保卫人员。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建设工程施工现场消防安全技术规范》GB 50720-2011 / 《中华人民共和国消防法》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1708, "type": "judge", "question": "索膜吊装时注意膜面的应力分布均匀，必要时可在膜上焊接连续的“吊装搭扣”，用两片钢板夹紧搭扣来吊装。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑施工起重吊装工程安全技术规范》JGJ 276-2012\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1709, "type": "judge", "question": "大面积膜面的吊装应选择晴朗无风的天气进行，风力大于4级或气温低于5℃时不宜进行安装。", "options": ["正确", "错误"], "answer": [1], "explanation": "大面积膜面的吊装应选择晴朗无风的天气进行，风力大于三级或气温低于 4°C 时不宜进行安装。"},
  {"id": 1710, "type": "judge", "question": "幕墙又称为悬挂墙。", "options": ["正确", "错误"], "answer": [0], "explanation": "幕墙是建筑物的外墙护围，不承重，像幕布一样挂上去，故又称为悬挂墙。"},
  {"id": 1711, "type": "judge", "question": "幕墙是由面板与支承结构体系（支承装置与支承结构）组成的、可相对主体结构有一定位移能力或自身有一定变形能力、不承担主体结构所受作用的建筑外围护墙。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1712, "type": "judge", "question": "开放式建筑幕墙是指要求不具有阻止空气渗透和雨水渗透功能的建筑幕墙。", "options": ["正确", "错误"], "answer": [1], "explanation": "不完全正确。\n开放式建筑幕墙通常指的是设计上允许一定程度的空气和雨水渗透的幕墙系统，其设计目的是通过控制通风和湿度，改善室内环境的舒适性和空气质量。因此，开放式建筑幕墙并非要求完全不具有阻止空气和雨水渗透功能，而是在设计上允许一定程度的通风和湿度调节。\n正式的定义和分类可能因地区和具体规范而异，但通常开放式建筑幕墙不是要求完全无阻隔功能，而是具有一定的通风和透气性能。"},
  {"id": 1713, "type": "judge", "question": "现场在主体结构上安装立柱、横梁和各种面板的建筑幕墙称构件式幕墙。", "options": ["正确", "错误"], "answer": [0], "explanation": "构件式建筑幕墙:现场在主体结构上安装立柱、横梁和各种面板的建筑幕墙。\n构件式玻璃幕墙主要包括：明框玻璃幕墙、隐框玻璃幕墙、半隐框玻璃幕墙。"},
  {"id": 1714, "type": "judge", "question": "由玻璃面板和玻璃肋构成的建筑幕墙称全玻式幕墙。", "options": ["正确", "错误"], "answer": [0], "explanation": "全玻璃幕墙是指由玻璃肋和玻璃面板构成的玻璃幕墙。"},
  {"id": 1715, "type": "judge", "question": "幕墙工程施工按面板材料，可分为玻璃幕墙、石材幕墙、人造板材幕墙、组合面板幕墙。", "options": ["正确", "错误"], "answer": [0], "explanation": "（一）按建筑幕墙的面板材料分类\n可分为：\n1.玻璃幕墙\n（1）框支承玻璃幕墙玻璃面板周边由金属框架支承的玻璃幕墙，主要包括下列类型：\n1）明框玻璃幕墙金属框架的构件显露于面板外表面的框支承玻璃幕墙；\n2）隐框玻璃幕墙金属框架完全不显露于面板外表面的框支承玻璃幕墙；\n3）半隐框玻璃幕墙金属框架的竖向或横向构件显露于面板外表面的框支承玻璃幕墙。\n（2）全玻幕墙 由玻璃肋和玻璃面板构成的玻璃幕墙。\n（3）点支承玻璃幕墙 由玻璃面板、点支承装置和支承结构构成的玻璃幕墙。\n2.金属幕墙面板为金属板材的建筑幕墙，主要包括：单层铝板幕墙、铝塑复合板幕墙、蜂窝铝板幕墙、不锈钢板幕墙、搪瓷板幕墙等。\n3.石材幕墙面板为建筑石材板的建筑幕墙。\n4.人造板材幕墙面板由瓷板、陶板、微晶玻璃板等。\n5.组合幕墙面板由玻璃、金属、石材、人造板材等不同面板组成的建筑幕墙。"},
  {"id": 1716, "type": "judge", "question": "幕墙工程施工前，项目经理组织项目施工员，依据施工设计文件、施工合同和幕墙工程相关规范结合现场场地情况编制《施工组织设计》和相应的《专项施工方案》等。", "options": ["正确", "错误"], "answer": [1], "explanation": "施工组织设计及专项方案编制\n项目经理组织项目【技术人员】，依据施工设计文件、施工合同和幕墙工程相关规范结合现场场地情况编制《施工组织设计》和相应的《专项施工方案》等。超过一定规模风险较大的分部分项工程专项施工方案，应由施工单位组织专家论证、审查。"},
  {"id": 1717, "type": "judge", "question": "幕墙安装工程属于危险性较大的分部分项工程，应编制专项施工方案，对于超过一定规模的应由监理单位组织专家论证、审查。", "options": ["正确", "错误"], "answer": [1], "explanation": "【依据】《建设工程安全生产管理条例》\n【解析】该说法错误。题干中的主体、程序、禁止性要求或控制数值与现行规定不一致。"},
  {"id": 1718, "type": "judge", "question": "幕墙工程施工，在沿海地区应进行季节性安全教育和台风期安全教育。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1719, "type": "judge", "question": "幕墙工程施工，项目部落实安全生产检查制度，对施工形成的安全状况和业绩进行日常检查。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1720, "type": "judge", "question": "幕墙工程施工，项目部根据项目特点和现场环境编制施工现场安全急救方案，并组织演练，一旦发生事故按已审批的救援方案开展救援工作，防止事故扩大，减少人员伤亡。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1721, "type": "judge", "question": "幕墙安装工程项目竣工后，施工单位要为业主提供《幕墙质保书》。当业主需要时提供技术咨询服务，使业主能够较好地使用和维护幕墙。避免因业主方使用和维护不当导致幕墙玻璃或石材等坠落伤人。", "options": ["正确", "错误"], "answer": [1], "explanation": "幕墙安装工程项目竣工后，施工单位要为业主提供《幕墙使用维护说明书》。当业主需要时提供技术咨询服务，使业主能够较好地使用和维护幕墙。避免因业主方使用和维护不当导致幕墙玻璃或石材等坠落伤人。"},
  {"id": 1722, "type": "judge", "question": "玻璃幕墙工程施工工艺流为放样定位→安装立柱→安装横梁→安装玻璃→打胶→清理", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1723, "type": "judge", "question": "玻璃幕墙施工中立柱安装时，支座的角钢和铝合金立柱接触处用柔性垫片进行隔离。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1724, "type": "judge", "question": "玻璃幕墙施工中安装横梁时，相邻两根横梁水平标高偏差不应大于1mm。", "options": ["正确", "错误"], "answer": [0], "explanation": "相邻两根横梁水平标高偏差不应大于1mm。"},
  {"id": 1725, "type": "judge", "question": "幕墙玻璃采用镀膜玻璃时，镀膜的一面应向室内。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法错误。题干中的主体、程序、禁止性要求或控制数值与现行规定不一致。"},
  {"id": 1726, "type": "judge", "question": "玻璃幕墙施工同一层横梁在安装时应由上而下进行，当一层高度的横梁装好后，应进行检查、调整、校正后再进行固定。", "options": ["正确", "错误"], "answer": [1], "explanation": "同一层横梁在安装时应由【下而上】进行,相邻两根横梁的水平标高偏差不得大于1mm。对于同层横梁的标高偏差,当幕墙宽度不超过35m时,不得大于5mm;当幕墙宽度大于35m时,不得大于7mm。当一层高度的横梁装好后,应进行检查、调整、校正后再进行固定。"},
  {"id": 1727, "type": "judge", "question": "明框幕墙的玻璃是用压板和橡皮固定在横梁和立柱上，压板再用螺栓固定在横梁或立柱上。", "options": ["正确", "错误"], "answer": [0], "explanation": "明框幕墙的玻璃是用压板和橡皮为固定在横梁和立柱上,压板再用螺栓固定在横梁或立柱上。"},
  {"id": 1728, "type": "judge", "question": "半隐框幕墙在隐框方向上的玻璃边缘用结构硅酮胶固定，在明框方向上的玻璃边缘用压板和连接螺栓固定。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1729, "type": "judge", "question": "石材幕墙施工预埋件安装时如有预埋件位置超差而无法使用或漏放时，应根据实际情况提出选用膨胀螺栓的方案，并必须报监理单位审核批准，且应在现场做拉拔试验，做好记录。", "options": ["正确", "错误"], "answer": [1], "explanation": "如有预埋件位置超差而无法使用或漏放时，应根据实际情况提出选用膨胀螺栓的方案，并必须报设计单位审核批准，且应在现场做拉拔试验，做好记录。"},
  {"id": 1730, "type": "judge", "question": "石材幕墙施工测量放线应在风力不大于4级的情况下进行，并要采取避风措施。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干中的主体、程序或控制数值与现行规定一致，属于直接记忆点。"},
  {"id": 1731, "type": "judge", "question": "石材幕墙金属骨架安装上时，检查焊缝质量合格后，所有焊点、焊缝均需去焊渣及抛光处理。", "options": ["正确", "错误"], "answer": [1], "explanation": "检查焊缝质量合格后,所有的焊点、焊缝均需作去焊渣及【防锈】处理,如刷防锈漆等。"},
  {"id": 1732, "type": "judge", "question": "石材幕墙在防火、保温材料安装时，在每层楼板与石板幕墙之间不能有空隙，应用钢板和石棉形成防火带。", "options": ["正确", "错误"], "answer": [1], "explanation": "石材幕墙在防火、保温材料安装时，在每层楼板与石板幕墙之间不能有空隙，应用镀锌钢板和防火棉形成防火带。"},
  {"id": 1733, "type": "judge", "question": "石材幕墙的石材饰面板安装，先按幕墙面基准线仔细安装好底层第一皮石材板。", "options": ["正确", "错误"], "answer": [0], "explanation": "2.5安装石板\n（1）先按幕墙面基准线仔细安装好底层第一层石材。\n（2）板与板之间留缝10~15mm，以便调整安装误差。石板安装时，左右、上下的偏差不应大于1.5mm.注意安放每层金属挂件的标高，金属挂件应紧托上层饰面板，而与下层饰面板之间留有间隙。\n（3）安装时要在饰面板的销钉孔或切槽口内注入大理石胶，以保证饰面板与挂件的可靠连接。\n（4）安装时宜先完成窗洞口四周的石材，以免安装发生困难。\n（5）安装到每一楼层标高时，要注意调整垂直误差。"},
  {"id": 1734, "type": "judge", "question": "嵌胶封缝石材板间的胶缝是石板幕墙的第一道防水措施，同时也使石板幕墙形成一个整体。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1735, "type": "judge", "question": "石材幕墙嵌胶封缝时，选用的泡沫塑料圆条直径应大于缝宽。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法错误。题干中的主体、程序、禁止性要求或控制数值与现行规定不一致。"},
  {"id": 1736, "type": "judge", "question": "金属幕墙锚固件施工，锚栓要现场进行拉拔试验，满足强度要求后才能使用。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1737, "type": "judge", "question": "金属幕墙的面板安装固定方式，一般采用自攻钉直接固定到骨架上，或板折边加角铝后再用自攻钉固定角铝的方法。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1738, "type": "judge", "question": "金属幕墙安装打胶操作阴雨天不宜进行。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1739, "type": "judge", "question": "金属幕墙施工完毕清洗后要设专人保护，在明显位置设警示牌以防污染或破坏。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1740, "type": "judge", "question": "幕墙玻璃边缘应进行磨边和倒角处理。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1741, "type": "judge", "question": "对于玻璃幕墙专项要求，中空玻璃气体层厚度不应小于9mm，宜采双单道密封，其中明框玻璃幕墙、隐框和半隐框玻璃幕墙的中空玻璃都可以采用丁基密封胶。", "options": ["正确", "错误"], "answer": [1], "explanation": "3.4.3 玻璃幕墙采用中空玻璃时，除应符合现行国家标准《中空玻璃》GB/T 11944的有关规定外，尚应符合下列规定：\n1 中空玻璃气体层厚度不应小于9mm；\n2 中空玻璃应采用双道密封。一道密封应采用丁基热熔密封胶。隐框、半隐框及点支承玻璃幕墙用中空玻璃的二道密封应采用硅酮结构密封胶；明框玻璃幕墙用中空玻璃的二道密封宜采用聚硫类中空玻璃密封胶，也可采用硅酮密封胶。二道密封应采用专用打胶机进行混合、打胶；"},
  {"id": 1742, "type": "judge", "question": "金属板幕墙中面板与支承结构相连接时，应采取措施避免双金属接触腐蚀。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1743, "type": "judge", "question": "人造板材幕墙面板挂件与支承构件之间应采用不锈钢螺栓或不锈钢自钻自攻螺钉连接。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1744, "type": "judge", "question": "人造板材幕墙专项要求，陶板宜采用短挂件连接，也可采用通长挂件连接。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1745, "type": "judge", "question": "人造板材幕墙专项要求，瓷板通长挂件用不锈钢材料和铝合金型材的截面厚度均不宜小于1.5mm。", "options": ["正确", "错误"], "answer": [0], "explanation": "瓷板;通长挂件用不锈钢材料和铝合金型材的截面厚度均不宜小于1.5mm。"},
  {"id": 1746, "type": "judge", "question": "人造板材幕墙专项要求，微晶玻璃板短挂件用不锈钢材料的截面厚度不宜小于3.0mm，铝合金型材的截面厚度不宜小于4.0mm。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干中的主体、程序或控制数值与现行规定一致，属于直接记忆点。"},
  {"id": 1747, "type": "judge", "question": "人造板材幕墙专项要求，陶板短挂件用不锈钢材料的截面厚度不宜小于1.5mm，铝合金型材的截面厚度不宜小于2.0mm。", "options": ["正确", "错误"], "answer": [0], "explanation": "陶板短挂件用不锈钢材料的截面厚度不宜小于1.5mm，铝合金型材的截面厚度不宜小于2.0mm；"},
  {"id": 1748, "type": "judge", "question": "人造板材幕墙挂件与陶板挂槽前后之间的空隙宜填充聚氨酯密封胶或设置弹性垫片，采用橡胶垫片时，其厚度不宜小于1.0mm。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干中的主体、程序或控制数值与现行规定一致，属于直接记忆点。"},
  {"id": 1749, "type": "judge", "question": "拆除工程是指对已经建成或部分建成的建（构）筑物实施整体或单元拆除的施工项目。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑拆除工程安全技术规范》JGJ 147-2016\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1750, "type": "judge", "question": "对危险性较大的拆除工程专项施工方案，应按相关规定组织专家论证。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《危险性较大的分部分项工程安全管理规定》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1751, "type": "judge", "question": "拆除工程施工不得在同一单元内同时进行，但可以与其他施工作业同时进行。", "options": ["正确", "错误"], "answer": [1], "explanation": "拆除作业必须由上而下逐层进行,严禁上下同时作业"},
  {"id": 1752, "type": "judge", "question": "拆除工程施工中，对有限空间拆除施工，应先采取纯氧通风换气措施，经检测合格后再进行作业。", "options": ["正确", "错误"], "answer": [1], "explanation": "拆除工程施工中，对有限空间拆除施工，应先采取通风措施，经检测合格后再进行作业。"},
  {"id": 1753, "type": "judge", "question": "对拆除工程施工的区域，应设置围挡及安全警示标志，严禁无关人员进入施工区域。", "options": ["正确", "错误"], "answer": [1], "explanation": "对拆除工程施工的区域，应设置硬质封闭围挡及安全警示标志，严禁无关人员进入施工区域。"},
  {"id": 1754, "type": "judge", "question": "当框架结构采用人工拆除施工时，应按楼板、次梁、主梁、结构柱的顺序依次进行。", "options": ["正确", "错误"], "answer": [0], "explanation": "当框架结构采用人工拆除时,应按楼板、次梁、主梁、结构柱的顺序依次进行。"},
  {"id": 1755, "type": "judge", "question": "人工拆除作业时，建筑的承重梁柱，应在其所承载的全部构件拆除后，再进行拆除。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑拆除工程安全技术规范》JGJ 147-2016\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1756, "type": "judge", "question": "当采用机械拆除建筑时，应从上至下逐层拆除，并应分段进行：先拆除承重结构，再拆除非承重结构。", "options": ["正确", "错误"], "answer": [1], "explanation": "当采用机械拆除建筑时，应从上至下，逐层分段进行；应先拆除非承重结构，再拆除承重结构。"},
  {"id": 1757, "type": "judge", "question": "进行高处拆除作业时，较大尺寸的构件或沉重的材料必须采用起重机具及时吊下。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑拆除工程安全技术规范》JGJ 147-2016\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1758, "type": "judge", "question": "机械拆除施工作业中，在吊装时，两台起重机的吊钩滑轮组应保持垂直状态。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑施工起重吊装工程安全技术规范》JGJ 276-2012\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1759, "type": "judge", "question": "当拆除桥梁时，应先拆除主体结构，再拆除桥面及附属结构。", "options": ["正确", "错误"], "answer": [1], "explanation": "当拆除桥梁时，应先拆除桥面及附属结构，再拆除主体。"},
  {"id": 1760, "type": "judge", "question": "拆除作业时，清运渣土的车辆应敞开或半敞开，出入现场时应有指示标志。", "options": ["正确", "错误"], "answer": [1], "explanation": "清运渣土的车辆应封闭或覆盖,出入现场时应有专人指挥。"},
  {"id": 1761, "type": "judge", "question": "爆破拆除是指对废弃的旧建（构）筑物进行拆除的控制爆破技术。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑拆除工程安全技术规范》JGJ 147-2016\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1762, "type": "judge", "question": "爆破器材临时保管地点，必须经当地法定部门批准。", "options": ["正确", "错误"], "answer": [0], "explanation": "爆破器材临时保管地点,必须经当地法定部门批准。严禁同室保管与爆破器材无关的物品。"},
  {"id": 1763, "type": "judge", "question": "静力破碎是利用静力破碎剂固化膨胀力破碎混凝土、岩石的一种技术。", "options": ["正确", "错误"], "answer": [0], "explanation": "静力破碎是利用静力破碎剂固化膨胀力破碎混凝土、岩石等的一种技术。"},
  {"id": 1764, "type": "judge", "question": "建（构）筑物的整体拆除或承重构件拆除，均可以采用静力破碎的方法。", "options": ["正确", "错误"], "answer": [1], "explanation": "根据《建筑拆除工程安全技术规范》JGJ147-2016的内容，对建筑物、构筑物的整体拆除或承重构件拆除，均不得采用静力破碎拆除的方法拆除。"},
  {"id": 1765, "type": "judge", "question": "当采用静力破碎剂作业时，施工人员必须佩戴防护手套和防护眼镜。", "options": ["正确", "错误"], "answer": [0], "explanation": "根据《建筑拆除工程安全技术规范》（JGJ147-2016）规定，当采用静力破碎剂作业时，施工人员必须佩戴防护手套和防护眼镜。"},
  {"id": 1766, "type": "judge", "question": "孔内注入破碎剂后，作业人员应保持适当距离，可在注孔区域行走，但严禁停留。", "options": ["正确", "错误"], "answer": [1], "explanation": "静力破碎剂作业时,孔内注入破碎剂后,作业人员应保持安全距离,严禁在注孔区域行走或停留。"},
  {"id": 1767, "type": "judge", "question": "高处作业是指在坠落高度基准面2m或2m以上有可能坠落的高处进行的作业。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑施工高处作业安全技术规范》JGJ 80-2016\n【解析】该说法正确。题干中的主体、程序或控制数值与现行规定一致，属于直接记忆点。"},
  {"id": 1768, "type": "judge", "question": "坠落高度基准面是指通过可能坠落范围内最高处的水平面。", "options": ["正确", "错误"], "answer": [1], "explanation": "坠落高度基准面: 是指通过可能坠落范围内最低的水平面。"},
  {"id": 1769, "type": "judge", "question": "高处作业高度是指作业区各作业位置至相应坠落高度基准面的垂直距离中的最小值。", "options": ["正确", "错误"], "answer": [1], "explanation": "根据国家标准 GB/T 3608 - 2008《高处作业分级》规定，高处作业高度是指作业区各作业位置至相应坠落高度基准面的垂直距离中的最大值。"},
  {"id": 1770, "type": "judge", "question": "无客观危险因素的高处作业可分为四个级别。", "options": ["正确", "错误"], "answer": [0], "explanation": "高处作业高度分为2m至5m、5m以上至15m、15m以上至30m、30m以上4个区段。"},
  {"id": 1771, "type": "judge", "question": "建筑施工高处作业前，应对安全防护设施进行检查、验收，验收合格后方可进行作业。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑施工高处作业安全技术规范》JGJ 80-2016\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1772, "type": "judge", "question": "高处作业施工前，应检查高处作业的安全标志、安全设施、工具、仪表、防火设施、电气设施和设备，确认其完好，方可进行施工。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑施工高处作业安全技术规范》JGJ 80-2016\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1773, "type": "judge", "question": "高处作业时，对施工作业现场所有可能坠落的物料，应及时拆除或采取固定措施。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑施工高处作业安全技术规范》JGJ 80-2016\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1774, "type": "judge", "question": "高处作业时，施工现场应按规定设置消防器材，当进行焊接等动火作业时，应采取防火措施。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑施工高处作业安全技术规范》JGJ 80-2016\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1775, "type": "judge", "question": "高处作业时，当遇有5级以上强风、浓雾、沙尘暴等恶劣气候，不得进行露天攀登与悬空高处作业。", "options": ["正确", "错误"], "answer": [1], "explanation": "当遇到6级以上强风、浓雾、沙尘暴等恶劣气候，不得进行露天攀登与悬空高处作业"},
  {"id": 1776, "type": "judge", "question": "高处作业时，各类安全防护设施，并应建立定期检查和维修保养制度，发现隐患应及时采取整改措施。", "options": ["正确", "错误"], "answer": [1], "explanation": "各类安全防护设施,并应建立定期和不定期的检查和维修保养制度,发现隐患应及时采取整改措施。"},
  {"id": 1777, "type": "judge", "question": "在进入电梯安装施工工序之前，同时井道内应每隔12m，且不大于3层加设一道水平安全网。", "options": ["正确", "错误"], "answer": [1], "explanation": "在进入电梯安装施工工序之前，同时井道内应每隔 10m 且不大于 2 层加设一道水平安全网。电梯井内的施工层上部，应设置隔离防护设施。"},
  {"id": 1778, "type": "judge", "question": "当防护栏杆高度大于去1.2m时，应增设横杆，横杆间距不应大于600mm.", "options": ["正确", "错误"], "answer": [0], "explanation": "当防护栏杆高度大于1.2m时，应增设横杆，横杆间距不应大于600mm"},
  {"id": 1779, "type": "judge", "question": "应确保防护栏杆在上下横杆和立杆任何处，均能承受任何方向的最小3kN外力作用。", "options": ["正确", "错误"], "answer": [1], "explanation": "栏杆立杆和横杆的设置、固定及连接，应确保防护栏杆在上下横杆和立杆任何处,均能承受任何方向的最小1kN外力作用，当栏杆所处位置有发生人群拥挤、车辆冲击和物件碰撞等可能时，应加大横杆截面或加密立杆间距。"},
  {"id": 1780, "type": "judge", "question": "攀登作业是指在施工现场借助于登高用具或登高设施，在攀登条件下进行的高处作业。", "options": ["正确", "错误"], "answer": [0], "explanation": "根据《建筑施工高处作业安全技术规范》（JGJ80-2016）规定，攀登作业是指借助登高用具或登高设施进行的高处作业。"},
  {"id": 1781, "type": "judge", "question": "攀登作业中，最多可允许两人同时在梯子上作业。", "options": ["正确", "错误"], "answer": [1], "explanation": "攀登施工时，不得两人同时在梯子上作业。在通道处使用梯子作业时，应有专人监护或设置围栏。脚手架操作层上不得使用梯子进行作业。"},
  {"id": 1782, "type": "judge", "question": "当无电焊防风要求时，高处作业操作平台的防护栏杆高度不应小于1.2m。", "options": ["正确", "错误"], "answer": [0], "explanation": "当无电焊防风要求时,操作平台的防护栏杆高度不应小于1.2m;有电焊防风要求时,操作平台的防护栏杆高度不应小于1.8m。"},
  {"id": 1783, "type": "judge", "question": "当安装三角形屋架时时，应在屋脊处设置上下的扶梯。", "options": ["正确", "错误"], "answer": [0], "explanation": "当安装三角形屋架时,应在屋脊处设置扶梯;当安装梯形屋架时,应在两端设置扶梯,扶梯踏步间距不应大于400mm。"},
  {"id": 1784, "type": "judge", "question": "深基坑施工，应设置扶梯、入坑踏步及专用载人设备或斜道等。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑基坑支护技术规程》JGJ 120-2012 / 《建筑基坑工程监测技术标准》GB 50497-2019\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1785, "type": "judge", "question": "高处作业的操作平台是指现场施工中以站人、载料并可进行操作的平台。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑施工高处作业安全技术规范》JGJ 80-2016\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1786, "type": "judge", "question": "高处作业的落地式操作平台高度不应大于15m，高宽比不应大于2∶1。", "options": ["正确", "错误"], "answer": [1], "explanation": "落地式操作平台的搭设高度不应大于15m,高宽比不应大于3:1。"},
  {"id": 1787, "type": "judge", "question": "高处作业的落地式操作平台遇6级以上大风、雷雨、大雪等恶劣天气及停用超过3个月，恢复使用前，应进行清理。", "options": ["正确", "错误"], "answer": [1], "explanation": "高处作业的落地式操作平台遇6级以上大风、雷雨、大雪等恶劣天气及停用超过1个月，恢复使用前，应进行检查。"},
  {"id": 1788, "type": "judge", "question": "高处作业时，不得在悬挑式操作平台吊运、安装时上人。", "options": ["正确", "错误"], "answer": [0], "explanation": "确定了目标后，《实施意见》将安全生产领域改革发展的任务细分为六个重点。\n第一是 健全落实安全生产责任体系。《实施意见》指出，要严格落实党政同责、一岗双责、齐抓共管、失职追责安全生产责任体系。"},
  {"id": 1789, "type": "judge", "question": "施工现场人员进出的通道口，应搭设安全防护棚。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑施工高处作业安全技术规范》JGJ 80-2016\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1790, "type": "judge", "question": "当安全防护棚为机动车辆通行时，棚底至地面高度不应小于4m。", "options": ["正确", "错误"], "answer": [0], "explanation": "当安全防护棚为非机动车辆通行时,棚底至地面高度不应小于3m;当安全防护棚为机动车辆通行时,棚底至地面高度不应小于4m."},
  {"id": 1791, "type": "judge", "question": "采用平网防护时，严禁使用密目式安全立网代替平网使用。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1792, "type": "judge", "question": "装配式混凝土建筑施工无须执行企业的安全生产法规和规章制度。", "options": ["正确", "错误"], "answer": [1], "explanation": "严格执行国家行业和企业的安全生产法规和规章制度,认真落实各级各类人员的安全生产责任制。"},
  {"id": 1793, "type": "judge", "question": "装配整体式混凝土结构工程施工，堆场加固、构件堆放架体、构件吊点、施工设施设备附墙，附着设施等涉及工程结构安全的方案应由设计单位核定。", "options": ["正确", "错误"], "answer": [0], "explanation": "深化施工设计制度。堆场加固、构件堆放架体、构件吊点、施工设施设备附墙，附着设施等涉及工程结构安全的方案应由设计单位核定。"},
  {"id": 1794, "type": "judge", "question": "装配整体式混凝土结构工程施工，吊装机械选型及平面布置由建设单位编制专项施工方案。", "options": ["正确", "错误"], "answer": [1], "explanation": "第五条 施工单位应当在危险性较大的分部分项工程施工前编制专项方案；对于超过一定规模的危险性较大的分部分项工程，施工单位应当组织专家对专项方案进行论证。"},
  {"id": 1795, "type": "judge", "question": "装配整体式混凝土结构工程施工，预制构件安装起吊前，施工、监理单位应对吊装的安全生产措施、条件等进行全面检查，在取得《吊装令》后，方可实施安装。", "options": ["正确", "错误"], "answer": [0], "explanation": "吊装令制度。预制构件安装起吊前,施工、监理单位应对吊装的安全生产措施、条件等进行全面检查,在取得《吊装令》后,方可实施安装。\n修改解析\n查询试题修改"},
  {"id": 1796, "type": "judge", "question": "装配整体式混凝土结构工程施工，预制构件安装起吊前，施工、监理单位应对吊装的安全生产措施、条件等进行抽样检查，在取得施工许可证后，方可实施安装。", "options": ["正确", "错误"], "answer": [1], "explanation": "吊装令制度。预制构件安装起吊前,施工、监理单位应对吊装的安全生产措施、条件等进行全面检查,在取得《吊装令》后,方可实施安装。"},
  {"id": 1797, "type": "judge", "question": "装配式混凝土建筑应根据预制构件的类型选择合适的堆放方式，规定堆放层数，构件之间应设置可靠的支撑；若使用货架堆置，货架应进行结构计算。", "options": ["正确", "错误"], "answer": [1], "explanation": "装配式混凝土建筑应根据预制构件的类型选择合适的堆放方式，规定堆放层数，构件之间应设置可靠的【垫块】；若使用货架堆置，货架应进行力学计算。"},
  {"id": 1798, "type": "judge", "question": "装配式混凝土建筑预制构件进场后应抽查吊点的隐蔽工程验收记录。", "options": ["正确", "错误"], "answer": [1], "explanation": "预制构件进场时应复核预制构件质保书，查验吊点的隐蔽工程验收记录、混凝土强度等相关内容。查验吊点及构件外观。\n题目意思是【进场后】"},
  {"id": 1799, "type": "judge", "question": "装配式混凝土建筑预制构件起吊使用的钢丝绳、手拉葫芦等起重工具应根据使用频率，增加检查频次，根据检查结果定期更换。", "options": ["正确", "错误"], "answer": [0], "explanation": "（六）起吊使用的钢丝绳、手拉葫芦等起重工具应根据使用频率，增加检查频次，根据检查结果定期更换。严禁使用自编的钢丝绳接头；严禁使用无设计依据的自制吊索具。"},
  {"id": 1800, "type": "judge", "question": "装配式混凝土建筑预制构件安装施工前，应检查复核吊装设备及吊具处于安全操作状态。", "options": ["正确", "错误"], "answer": [0], "explanation": "安装施工前，应复核吊装设备的吊装能力。应桉现行行业标准《建筑机械使用安全技术规程》 ( JGJ33 ) 的有关规定，检查复核吊装设备及吊具处于安全操作状态，并核实现场环境、天气、道路状况等是否满足吊装施工要求；防护系统应按照施工方案进行搭设、验收。"},
  {"id": 1801, "type": "judge", "question": "装配式混凝土建筑预制构件安装前按设计要求检查预制构件、预埋件以及配件的型号、规格、数量等。", "options": ["正确", "错误"], "answer": [0], "explanation": "安装前按设计要求检查预制构件、预埋件以及配件的型号、规格、数量等；"},
  {"id": 1802, "type": "judge", "question": "装配式混凝土建筑预制板叠放按照规定不得超过3层。", "options": ["正确", "错误"], "answer": [1], "explanation": "装配式混凝土建筑预制构件堆放按规定堆放不超限，板叠放不大于6层，柱、梁叠放不大于2层。"},
  {"id": 1803, "type": "judge", "question": "装配式混凝土建筑预制构件吊装所用的吊索具和牵引绳须有允许使用的识别标志。", "options": ["正确", "错误"], "answer": [0], "explanation": "吊索具和牵引绳有允许使用的识别标志;"},
  {"id": 1804, "type": "judge", "question": "装配式混凝土建筑预制构件吊装作业，临时固定措施按设计方案设置，安全可靠。", "options": ["正确", "错误"], "answer": [1], "explanation": "临时固定措施按施工方案设置,安全可靠;"},
  {"id": 1805, "type": "judge", "question": "装配式混凝土建筑安装作业登高及平台须有验收挂牌。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《装配整体式混凝土结构工程施工安全管理规定》 / 《装配式混凝土结构技术规程》JGJ 1-2014\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1806, "type": "judge", "question": "装配式混凝土建筑施工，安全防护采用操作架时，操作架应与结构有可靠的连接体系，操作架受力应满足计算要求。", "options": ["正确", "错误"], "answer": [0], "explanation": "安全防护采用操作架时，操作架应与结构有可靠的连接体系, 操作架受力应满足计算要求。操作架要逐次安装与提升，不准交叉作业, 每一单元不得随意中断提升，严禁操作架在不安全状态下过夜。操作架 安装、吊升时，如有障碍，应及时查清，并在排除障碍后，方可继续。"},
  {"id": 1807, "type": "judge", "question": "装配式混凝土建筑预制外墙板就位后，应及时安装上一层围挡。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《房屋建筑工程文明施工提升标准》 / 《上海市建设工程文明施工标准》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1808, "type": "judge", "question": "装配整体式混凝土结构施工在绑扎柱、墙钢筋，应采用专用登高设施，当高于围挡时，必须佩戴双背带式保险带。", "options": ["正确", "错误"], "answer": [1], "explanation": "装配整体式混凝土结构施工在绑扎柱、墙钢筋,应采用专用登高设施,当高于围挡时必须佩戴穿芯自锁保险带。"},
  {"id": 1809, "type": "judge", "question": "大风天气不影响正常预制构件吊装。", "options": ["正确", "错误"], "answer": [1], "explanation": "五级风以上禁止吊装作业。"},
  {"id": 1810, "type": "judge", "question": "装配式混凝土建筑施工现场，注浆机等机具验收使用，须有验收挂牌或允许使用的识别标志，安全可靠。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《装配整体式混凝土结构工程施工安全管理规定》 / 《装配式混凝土结构技术规程》JGJ 1-2014\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1811, "type": "judge", "question": "对于塔机施工升降机，塔机型号、起重吨位是否满足本工程单块构件日常重量要求；塔机施工升降机附着设置按场地要求设置。", "options": ["正确", "错误"], "answer": [1], "explanation": "对于塔机施工升降机，塔机型号、起重吨位是否满足本工程单块构件最大重量要求；塔机施工升降机附着设置按方案设计要求设置。"},
  {"id": 1812, "type": "judge", "question": "在预制混凝土构件中预留孔道，在孔道中插入需搭接的钢筋，并灌注水泥基灌浆料而实现的钢筋搭接连接方式，称钢筋浆锚搭接连接。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《装配整体式混凝土结构工程施工安全管理规定》 / 《装配式混凝土结构技术规程》JGJ 1-2014\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1813, "type": "judge", "question": "混凝土粗糙面指预制构件结合面上的凹凸不平或骨料显露的表面。简称粗糙面。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《装配整体式混凝土结构工程施工安全管理规定》 / 《装配式混凝土结构技术规程》JGJ 1-2014\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1814, "type": "judge", "question": "装配式混凝土结构在建筑工程中，简称装配式建筑；其在结构工程中，简称装配式结构。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《装配整体式混凝土结构工程施工安全管理规定》 / 《装配式混凝土结构技术规程》JGJ 1-2014\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1815, "type": "judge", "question": "装配整体式混凝土框架结构是指全部或部分框架梁、柱采用预制构件建成的装配整体式混凝土结构。简称装配整体式框架结构。", "options": ["正确", "错误"], "answer": [0], "explanation": "2.1.4 装配整体式混凝土框架结构\n全部或部分框架梁、柱采用预制构件构建成的装配整体式混凝土结构。简称装配整体式框架结构。"},
  {"id": 1816, "type": "judge", "question": "建筑起重机械具体包括桥式起重机、塔式起重机、门式起重机、流动式起重机、升降机等。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑起重机械安全监督管理规定》 / 《塔式起重机安全规程》GB 5144-2006\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1817, "type": "judge", "question": "内爬升塔式起重机的特性代号是QTP。", "options": ["正确", "错误"], "answer": [0], "explanation": "QTP——内爬升式塔吊"},
  {"id": 1818, "type": "judge", "question": "塔式起重机最高附着点以上的最大可安装高度是指工作高度。", "options": ["正确", "错误"], "answer": [1], "explanation": "自由高度，指的是扶墙后，扶墙以上最高可安装（不进行下一道扶墙）高度。"},
  {"id": 1819, "type": "judge", "question": "塔机按回转部位分为上回转塔机和下回转塔机。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑起重机械安全监督管理规定》 / 《塔式起重机安全规程》GB 5144-2006\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1820, "type": "judge", "question": "起重量是指起重机吊起重物和物料（不包括吊具、索具）质量的总和。", "options": ["正确", "错误"], "answer": [1], "explanation": "起重量:起重机吊起重物和物料,包括吊具(或索具)质量的总和。"},
  {"id": 1821, "type": "judge", "question": "塔机启动时，应根据起吊重物和现场情况，选择适当的工作速度，操纵各控制器时应从零点开始，依次增加速度，可越挡操作。", "options": ["正确", "错误"], "answer": [1], "explanation": "应根据起吊重物和现场情况，选择适当的工作速度，操纵各控制器应从停止点（零点）开始，依次逐级增加速度，严禁越档操作。在变换运转方向，应将控制器手柄扳到零位待电动机停转后再转向另一方向，不得直接变换运转方向、突然变速或制动。"},
  {"id": 1822, "type": "judge", "question": "塔机在提升吊钩、起重小车到限位装置前，应减速缓行到停止位置，并与限位装置保持一定距离。可采用限位装置作为停止运行的控制开关。", "options": ["正确", "错误"], "answer": [1], "explanation": "在吊钩提升、起重小车运行到限位装置前,均应减速缓行到停止位置,并应与限位装置保持一定距离。严禁采用限位装置作为停止运行的控制开关。"},
  {"id": 1823, "type": "judge", "question": "塔机若回转部分不设集电器，应安装回转限位器，在作业时，不得顺一个方向连续回转2圈。", "options": ["正确", "错误"], "answer": [1], "explanation": "回转部分不设集电器的塔式起重机,应按照回转限位器,在作业时,不得顺 一个方向连续回转1.5圈。"},
  {"id": 1824, "type": "judge", "question": "采用涡流制动调速系统的塔机，不得使用低速挡作业。", "options": ["正确", "错误"], "answer": [1], "explanation": "采用涡流制动调速系统的塔式起重机,不得长时间使用低速挡或慢就位速度作业。"},
  {"id": 1825, "type": "judge", "question": "塔机司机与要现场指挥人员配合好；同时，司机对任何人发出的信号，均应服从。", "options": ["正确", "错误"], "answer": [1], "explanation": "塔机司机要与现场指挥人员配合好,同时,司机对任何人发出的紧急停止信号,均应服从。"},
  {"id": 1826, "type": "judge", "question": "塔机在电磁波发射天线附近施工时，与吊钩接触的作业人员，应戴绝缘手套和穿绝缘鞋，并应在吊钩上挂接临时放电装置。", "options": ["正确", "错误"], "answer": [0], "explanation": "塔式起重机在无线电台、电视台或其他电磁波发射天线附近施工时,与吊钩接触的作业人员,应戴绝缘手套和穿绝缘鞋,并应在吊钩上挂接临时放电装置。"},
  {"id": 1827, "type": "judge", "question": "动臂式和未附着塔式起重机及附着以上塔式起重机桁架上不得悬挂标语牌。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑起重机械安全监督管理规定》 / 《塔式起重机安全规程》GB 5144-2006\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1828, "type": "judge", "question": "动臂式和未附着塔式起重机及附着以上塔式起重机桁架上须酌情悬挂标语牌。", "options": ["正确", "错误"], "answer": [1], "explanation": "动臂式和未附着塔式起重机及附着以上塔式起重机桁架上不得悬挂标语牌。"},
  {"id": 1829, "type": "judge", "question": "塔式起重机和220kV输电线路之间的安全距离，水平方向需达到至少5m。", "options": ["正确", "错误"], "answer": [1], "explanation": "当电压为220kV时，塔式起重机和输电线路之间的安全距离沿水平方向为6m。"},
  {"id": 1830, "type": "judge", "question": "装拆作业前必须进行安全技术交底，装拆作业中各工序应定人定岗，定专人统一指挥。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑施工安全技术统一规范》GB 50870-2013\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1831, "type": "judge", "question": "塔机装拆作业应设置警戒线，并设专人监护，无关人员不得入内。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑起重机械安全监督管理规定》 / 《塔式起重机安全规程》GB 5144-2006\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1832, "type": "judge", "question": "装拆塔式起重机时安装拆卸人员可参照装拆方案操作。", "options": ["正确", "错误"], "answer": [1], "explanation": "塔式起重机的安装、拆卸必须认真执行专项安全施工组织设计(施工方案)和安全技术措施交底，并应统一指挥、专人监护。塔身上不得悬挂任何标语牌。"},
  {"id": 1833, "type": "judge", "question": "塔式起重机拆装作业的关键问题是安全，拆装方案中，应体现对安全作业的充分保证。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑起重机械安全监督管理规定》 / 《塔式起重机安全规程》GB 5144-2006\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1834, "type": "judge", "question": "塔式起重机的拆卸程序是安装的逆过程。", "options": ["正确", "错误"], "answer": [0], "explanation": "塔式起重机的拆卸顺序是安装的逆过程,即后装的先拆。"},
  {"id": 1835, "type": "judge", "question": "塔机的拆装人员应熟悉拆卸工艺，遵守操作规程，当发现异常情况或疑难问题时，应努力自行处理问题。", "options": ["正确", "错误"], "answer": [1], "explanation": "熟悉并认真执行拆卸工艺和操作规程 ,当发现异常情况或疑难问题时 ,应及时向技术负责人反映 ,不得自行其是 ,应防止处理不当而造成事故。"},
  {"id": 1836, "type": "judge", "question": "在拆装作业过程中，当遇天气剧变、突然停电、机械故障等意外情况时，应将已装拆的部件固定牢靠，并经检查确认无隐患后继续作业。", "options": ["正确", "错误"], "answer": [1], "explanation": "在拆装作业过程中，当遇天气剧变、突然停电、机械故障等意外情况，应将已拆装的部位固定牢靠，并经检查确认无隐患后停止作业。"},
  {"id": 1837, "type": "judge", "question": "塔机基础的钢筋绑扎后，应做隐蔽工程检查，检查后方可浇筑混凝土。", "options": ["正确", "错误"], "answer": [1], "explanation": "基础的钢筋绑扎后,作隐蔽工程验收。隐蔽工程包括塔机基础节的预埋件或预埋节等。验收合格后方浇筑混凝土。"},
  {"id": 1838, "type": "judge", "question": "塔机基础结构的外观质量不应有一般缺陷。", "options": ["正确", "错误"], "answer": [1], "explanation": "基础结构的外观质量不应有严重缺陷。不宜有一般缺陷。"},
  {"id": 1839, "type": "judge", "question": "塔机型钢平台和钢立柱的焊接作业，焊工应持证上岗。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑起重机械安全监督管理规定》 / 《塔式起重机安全规程》GB 5144-2006\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1840, "type": "judge", "question": "升降机分为人用升降机和货用升降机。", "options": ["正确", "错误"], "answer": [1], "explanation": "升降机分为人货两用升降机和货用升降机。"},
  {"id": 1841, "type": "judge", "question": "人货两用升降机有半封围的吊笼，可运送货物和人员。", "options": ["正确", "错误"], "answer": [1], "explanation": "人货两用升降机有完全封围的吊笼.可运送货物和人员。"},
  {"id": 1842, "type": "judge", "question": "货用升降机的运载装置可只配有侧围壁而不必完全封围，正常运行时只能载货而不能载人。", "options": ["正确", "错误"], "answer": [0], "explanation": "货用升降机的运载装置可只配有侧围壁而不必完全封围,正常运行时只能载货而不能载人。"},
  {"id": 1843, "type": "judge", "question": "运载装置不可进人的倾斜式货用升降机，紧急情况下人员可以进入运载装置。", "options": ["正确", "错误"], "answer": [1], "explanation": "运载装置不可进人的倾斜式升降机"},
  {"id": 1844, "type": "judge", "question": "施工升降机的吊笼净重尺寸是指吊笼内空间大小(长×宽×高)m。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑施工升降机安装、使用、拆卸安全技术规程》JGJ 215-2010\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1845, "type": "judge", "question": "防坠安全器在施工升降机的接高和拆卸过程中暂时不起作用。", "options": ["正确", "错误"], "answer": [1], "explanation": "防坠安全器在施工升降机的接高和拆卸过程中应仍起作用。"},
  {"id": 1846, "type": "judge", "question": "在非坠落试验的情况下，防坠安全器动作后，吊笼应能正常运行。", "options": ["正确", "错误"], "answer": [1], "explanation": "在非坠落试验的情况下,安全器动作后,吊笼应不能运行。"},
  {"id": 1847, "type": "judge", "question": "防坠安全器试验时，吊笼应载有专业操作人员。", "options": ["正确", "错误"], "answer": [1], "explanation": "在进行防坠落试验时,吊笼内不允许有人"},
  {"id": 1848, "type": "judge", "question": "齿轮齿条式施工升降机应采用瞬时式安全器。", "options": ["正确", "错误"], "answer": [1], "explanation": "齿轮齿条式施工升降机应采用渐进式防坠安全器"},
  {"id": 1849, "type": "judge", "question": "对于额定提升速度不超过0.63m/s的施工升降机，可采用瞬时式安全器。", "options": ["正确", "错误"], "answer": [0], "explanation": "对于额定提升速度不超过0.63m/s的施工升降机,可采用瞬时式安全器,否则应采用渐进式安全器;"},
  {"id": 1850, "type": "judge", "question": "齿轮齿条式施工升降机和钢丝绳式人货两用施工升降机的极限开关为非自动复位型的，其动作后必须手动复位才能使吊笼可重新启动。", "options": ["正确", "错误"], "answer": [0], "explanation": "齿轮齿条式施工升降机和钢丝绳式人货两用施工升降机必须设置极限开关，吊笼越程超出限位开关后，极限开关须切断总电源使吊笼停车。极限开关为非自动复位型的，其动作后必须手动复位才能使吊笼可重新启动。"},
  {"id": 1851, "type": "judge", "question": "施工升降机应装有超载保护装置，该装置应对吊笼内载荷、吊笼顶部载荷均有效。", "options": ["正确", "错误"], "answer": [0], "explanation": "施工升降机应装有超载保护装置，该装置应对吊笼内载荷、吊笼顶部载荷均有效。装载额定载荷的90%时应报警，达到110%时应不能启动。"},
  {"id": 1852, "type": "judge", "question": "施工升降机应装有超载保护装置，该装置应只对吊笼内载荷有效，对吊笼顶部载荷无效。", "options": ["正确", "错误"], "answer": [1], "explanation": "施工升降机应装有超载保护装置，该装置应对吊笼内载荷、吊笼顶部载荷均有效。装载额定载荷的90%时应报警，达到110%时应不能启动。"},
  {"id": 1853, "type": "judge", "question": "施工升降机司机应持有建筑施工特种作业操作资格证书，不得无证操作。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建筑施工升降机安装、使用、拆卸安全技术规程》JGJ 215-2010\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1854, "type": "judge", "question": "当建筑物超过5层时，施工升降机地面通道上方应搭设防护棚。", "options": ["正确", "错误"], "answer": [1], "explanation": "当建筑物超过2层时，施工升降机地面通道上方应搭设防护棚。当建筑物高度超过24m时，应设置双层防护棚。"},
  {"id": 1855, "type": "judge", "question": "施工升降机使用过程中，吊笼的界限不应超过运载物料的尺寸。", "options": ["正确", "错误"], "answer": [1], "explanation": "施工升降机使用过程中,运载物料的尺寸不应超过吊笼的界限。"},
  {"id": 1856, "type": "judge", "question": "作业结束后应将施工升降机返回最顶层停放。", "options": ["正确", "错误"], "answer": [1], "explanation": "作业结束后应将施工升降机返回最底层停放,将各控制开半拨到零位,切断电源,锁好开关箱,锁好开关箱、吊笼门和地面防护围栏门"},
  {"id": 1857, "type": "judge", "question": "钢丝绳受力后，在破断前一般有断丝、断股等现象，容易检查、便于预防事故。", "options": ["正确", "错误"], "answer": [0], "explanation": "钢丝绳在破断前一般有断丝、断股预兆,容易检查、便于预防事故。"},
  {"id": 1858, "type": "judge", "question": "6x37钢丝绳其断丝数在一个节距内超过18丝应报废。", "options": ["正确", "错误"], "answer": [1], "explanation": "22丝"},
  {"id": 1859, "type": "judge", "question": "钢丝绳直径的磨损和腐蚀大于钢丝绳的直径7%应报废。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干中的主体、程序或控制数值与现行规定一致，属于直接记忆点。"},
  {"id": 1860, "type": "judge", "question": "绳夹要一顺排列，绳卡滑鞍（夹板）应在钢丝绳承载时受力的一侧，U形螺栓应在钢丝绳的尾端，不得正反交错。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1861, "type": "judge", "question": "单斗挖掘机的工作装置是可更换的，可进行破碎、打桩、夯土、起重等多种作业。", "options": ["正确", "错误"], "answer": [0], "explanation": "单斗挖掘机主要是一种土方机械。在建筑工程中，单斗挖掘机可挖掘基坑、沟槽，清理和平整场地。是建筑工程土方施工中很重要的机械设备。在更换工作装置后还可以进行破碎、装卸、起重、打桩等作业任务。\n在水利工程中开挖沟渠、河道，在露天采矿工程中用来进行剥离表土和矿物的挖装作业；更换工作装置后还可进行浇筑、起重、安装、打桩、夯土和拔桩等工作 。"},
  {"id": 1862, "type": "judge", "question": "平整场地时，不得用铲斗进行横扫或用铲斗对地面进行夯实。", "options": ["正确", "错误"], "answer": [0], "explanation": "平整作业场地时,不得用铲斗进行横扫或用铲斗对地面进行夯实。"},
  {"id": 1863, "type": "judge", "question": "平整场地时，可视情况用铲斗进行横扫或对地面进行夯实。", "options": ["正确", "错误"], "answer": [1], "explanation": "平整作业场地时,不得用铲斗进行横扫或用铲斗对地面进行夯实。"},
  {"id": 1864, "type": "judge", "question": "作业中，履带式挖掘机短距离行走时，主动轮应在前面，斗臂应在正前方与履带平行，并应制动回转机构。", "options": ["正确", "错误"], "answer": [1], "explanation": "作业中,履带式挖掘机短距离行走时,主动轮应在后面,斗臂应在正前方与履带平行,并应制动回转机构"},
  {"id": 1865, "type": "judge", "question": "高空作业车的专用车用途特征代号是HK。", "options": ["正确", "错误"], "answer": [1], "explanation": "用途特征代号。GK表示高空。"},
  {"id": 1866, "type": "judge", "question": "建筑有限空间是指封闭或部分封闭，进出口较为狭窄有限，未被设计为固定工作场所，自然通风不良，易造成有毒有害、易燃易爆物质积聚或氧含量不足的空间。", "options": ["正确", "错误"], "answer": [0], "explanation": "有限空间是指封闭或部分封闭，进出口较为狭窄有限，未被设计为固定工作场所，自然通风不良，易造成有毒有害、易燃易爆物质积聚或氧含量不足的空间。本项目施工区域内从事有限空间作业和具有有限空间作业行为的生产经营单位、班组均适用本方案。"},
  {"id": 1867, "type": "judge", "question": "建筑有限空间作业是指在封闭或部分封闭，进出口较为狭窄有限，未被设计为固定工作场所，自然通风不良，易造成有毒有害、易燃易爆物质积聚或氧含量不足的空间进行常规作业。", "options": ["正确", "错误"], "answer": [0], "explanation": "有限空间是指封闭或部分封闭，进出口较为狭窄有限，未被设计为固定工作场所，自然通风不良，易造成有毒有害、易燃易爆物质积聚或氧含量不足的空间。"},
  {"id": 1868, "type": "judge", "question": "有限空间主要分为密闭设备、地上有限空间、地下有限空间三类。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1869, "type": "judge", "question": "实施有限空间作业前，作业单位应对作业环境及作业过程进行风险评估，分析可能存在的危险有害因素，提出消除、控制危害的措施，制订作业方案，并经本单位施工管理人员审核，负责人批准。", "options": ["正确", "错误"], "answer": [1], "explanation": "实施有限空间作业前，作业单位应对作业环境及作业过程进行风险评估，分析可能存在的危险有害因素，提出消除、控制危害的措施，制定作业方案，并经本单位安全生产管理人员审核，负责人批准。"},
  {"id": 1870, "type": "judge", "question": "有限空间作业单位应按照有限空间作业方案，明确作业负责人、监护者、作业者及其安全职责。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1871, "type": "judge", "question": "监护者在履行监测和保护职责时，必须坚守岗位，履行职责；对未经许可欲进入者予以警告并劝离。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1872, "type": "judge", "question": "有限空间作业时，应进行作业审批，有限空间作业审批表应经单位审批责任人确认。", "options": ["正确", "错误"], "answer": [1], "explanation": "有限空间作业前,应进行作业审批。有限空间作业审批表应经单位审批责任人签字确认,并存档保存至少1年。"},
  {"id": 1873, "type": "judge", "question": "在有限空间作业时，作业负责人应对实施作业的部分人员进行安全交底，告知作业内容、作业方案等，并经其确认。", "options": ["正确", "错误"], "answer": [1], "explanation": "安全交底。作业现场负责人应对实施作业的全体人员进行安全交底，告知作业内容、作业现场可能存在的安全风险、作业安全要求及应急处置措施等，并履行签字确认手续。"},
  {"id": 1874, "type": "judge", "question": "可燃性气体、蒸气预警值应为爆炸下限（LEL）的5%，报警值应为爆炸下限（LEL）的10%。", "options": ["正确", "错误"], "answer": [0], "explanation": "4.3.3 可燃气预警值应为爆炸下限的5%，报警值应为爆炸下限的10%。"},
  {"id": 1875, "type": "judge", "question": "可燃性气体、有毒有害气体和蒸气应设定预警值和报警值两级检测报警值。", "options": ["正确", "错误"], "answer": [0], "explanation": "4.3.2 可燃气体和有毒有害气体应设定预警值和报警值两级检测报警值。部分有毒有害气体的预警值\n和报警值参见附录A。"},
  {"id": 1876, "type": "judge", "question": "有限空间内宜设置移动式气体检测报警仪，并在作业过程中全程运行。", "options": ["正确", "错误"], "answer": [1], "explanation": "4.1.2 地下有限空间设置固定式气体检测报警系统的，作业过程中应全程运行。"},
  {"id": 1877, "type": "judge", "question": "有限空间应急救援预案每3年至少进行1次应急培训与演练。", "options": ["正确", "错误"], "answer": [1], "explanation": "有限空间作业事故专项应急预案应每年至少组织1次演练,现场处置方案应至少每半年组织1次演练。"},
  {"id": 1878, "type": "judge", "question": "有限空间作业安全培训，发包单位应做好培训记录，由参加培训的人员签字确认，并将培训签到记录、讲义和试卷等相关材料归档保存。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1879, "type": "judge", "question": "从事地下有限空间作业的，监护者应按照有关规定，经培训考核合格，持证上岗作业。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1880, "type": "judge", "question": "进入密闭空间施工作业前，应拟定和掌握紧急情况时的撤离线路和方法。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1881, "type": "judge", "question": "密闭空间施工作业完成后，只需要监护员检查，确认密闭空间内无人员、杂物、遗留火星后即可撤离。", "options": ["正确", "错误"], "answer": [1], "explanation": "密闭空间施工作业完成后,监护员与施工作业人员应一起检查,确认密闭空间内无人员、杂物、遗留火星后方可撤离。"},
  {"id": 1882, "type": "judge", "question": "在积水、结露等潮湿环境的有限空间和金属容器中作业，照明灯具电压应不大于24V。", "options": ["正确", "错误"], "answer": [1], "explanation": "在积水、结露等潮湿环境的有限空间和金属容器中作业,照明灯具电压应不大于12V。"},
  {"id": 1883, "type": "judge", "question": "有限空间作业时，当需要使用电动工具或照明电压大于24V时，应按规定安装漏电保护器，其接线箱（板）必须放置在外部。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《施工现场临时用电安全技术规范》JGJ 46-2005\n【解析】该说法正确。题干中的主体、程序或控制数值与现行规定一致，属于直接记忆点。"},
  {"id": 1884, "type": "judge", "question": "在有限空间使用超过安全电压的手持电动工具作业或进行电焊作业时，应配备熔断器。", "options": ["正确", "错误"], "answer": [1], "explanation": "使用超过安全电压的手持电动工具作业或进行电焊作业时,应配备漏电保护器。在潮湿容器中,作业人员应站在绝缘板上,同时保证金属容器接地可靠。"},
  {"id": 1885, "type": "judge", "question": "有限空间施工现场动火作业，必须办理消防审批手续。", "options": ["正确", "错误"], "answer": [1], "explanation": "有限空间施工现场动火作业，必须办理动火审批手续。"},
  {"id": 1886, "type": "judge", "question": "施工单位应编制发布密闭空间施工作业应急救援预案，经常开展密闭空间施工作业的单位须配备应急救援绳索和空气呼吸器等器材，并开展针对性的应急演练，切实提高作业人员应急意识和自防自救能力。", "options": ["正确", "错误"], "answer": [0], "explanation": "1、施工单位应编制发布密闭空间施工作业应急救援预案，经常开展密闭空间施工作业的单位须配备应急救援绳索和空气呼吸器等器材，并开展针对性的应急演练，切实提高作业人员应急意识和自防自救能力。"},
  {"id": 1887, "type": "judge", "question": "密闭空间施工作业条件发生变化有可能危及作业人员安全的，作业人员和监护员均应立即撤离密闭空间。", "options": ["正确", "错误"], "answer": [0], "explanation": "2、密闭空间施工作业条件发生变化，有可能危及作业人员安全的，作业人员和监护员均应立即撤离密闭空间。"},
  {"id": 1888, "type": "judge", "question": "密闭空间施工作业条件发生变化有可能危及作业人员安全的，作业人员和监护员均应立即组织安全检查。", "options": ["正确", "错误"], "answer": [1], "explanation": "2、密闭空间施工作业条件发生变化，有可能危及作业人员安全的，作业人员和监护员均应立即撤离密闭空间。"},
  {"id": 1889, "type": "judge", "question": "密闭空间内发生险情后应立即报警，救援人员应立即实施救援。", "options": ["正确", "错误"], "answer": [1], "explanation": "3、密闭空间内发生险情后应立即报警，救援人员应在做好自身防护后实施救援，禁止在不具备条件的情况下盲目施救。"},
  {"id": 1890, "type": "judge", "question": "进行有限空间作业时，作业单位应在有限空间外醒目位置，设置警戒区、警戒线、警戒标志，未经许可，不得入内。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1891, "type": "judge", "question": "有限空间作业时，应对气体温度进行测量，作业时30分钟内，进行气体分析，分析完成后方可入内。", "options": ["正确", "错误"], "answer": [1], "explanation": "受限空间作业【前】（30）分钟内，应对受限空间进行气体采样分析，分析合格后方可进入。"},
  {"id": 1892, "type": "judge", "question": "进入自然通风换气效果不良的有限空间，应采用机械通风，通风换气次数每小时不能少于3次。", "options": ["正确", "错误"], "answer": [0], "explanation": "进入自然通风换气效果不良的有限空间，应采用机械通风，通风换气次数每小时不能少于3次.对不能采用通风换气措施或受作业环境限制不易充分通风换气的场所，作业人员必须配备并使用空气呼吸器或软管面具等隔离式呼吸保护器具。严禁使用过滤式面具。"},
  {"id": 1893, "type": "judge", "question": "有限空间作业人员应具备对工作认真负责的态度，身体无妨碍从事相应工种作业的疾病和生理缺陷，并符合相应工种作业需要的资格。", "options": ["正确", "错误"], "answer": [0], "explanation": "(五)有限空间作业人员应具备对工作认真负责的态度,身体无妨碍从事相应工种作业的疾病和生理缺陷,并符合相应工种作业需要的资格。"},
  {"id": 1894, "type": "judge", "question": "对不能采用通风换气措施或受作业环境限制不易充分通风换气的场所，作业人员必须配备并使用隔离式呼吸保护器具。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1895, "type": "judge", "question": "有限空间作业现场应明确监护人员和作业人员，监护人员可以进入有限空间。", "options": ["正确", "错误"], "answer": [1], "explanation": "第十五条监护人员应当全程进行监护,与作业人员保持实时联络,不得离开作业现场或者进入有限空间参与作业。"},
  {"id": 1896, "type": "judge", "question": "有限空间作业人员意识到身体出现危险异常症状时，应及时向监护者报告或自行撤离有限空间。", "options": ["正确", "错误"], "answer": [0], "explanation": "(四)作业人员意识到身体出现危险异常症状时,应及时向作业防护人报告或自行撤离有限空间并及时告知其他作业人员。"},
  {"id": 1897, "type": "judge", "question": "有限空间作业人员应遵守有限空间作业安全操作规程，正确使用有限空间作业安全设施与个体防护用具；应与监护人员进行有效的安全、报警、撤离等双向信息交流", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1898, "type": "judge", "question": "。有限空间作业人员应遵守有限空间作业安全操作规程，使用有限空间作业安全设施与个体防护用具；应向监护人员进行有效的安全、报警、撤离等单向信息汇报。", "options": ["正确", "错误"], "answer": [1], "explanation": "（八）有限空间作业人员应遵守有限空间作业安全操作规程，正确使用有限空间作业安全设施与个体防护用具；应与监护人员进行有效的安全、报警、撤离等双向信息交流；作业人员意识到身体出现危险异常症状时，应及时向监护者报告或自行撤离有限空间。"},
  {"id": 1899, "type": "judge", "question": "施工现场用电设备在5台及以上或设备总容量在50kW及以上者，应编制临时用电方案。", "options": ["正确", "错误"], "answer": [1], "explanation": "施工现场临时用电设备在5台及以上或设备总容量在50KW及以上者,应编制用电组织设计。"},
  {"id": 1900, "type": "judge", "question": "临时用电工程必须经编制、审核、批准部门和使用单位共同验收后方可投入使用。", "options": ["正确", "错误"], "answer": [1], "explanation": "临时用电工程必须经编制、审核、批准部门和使用单位共同验收合格后方可投入使用。"},
  {"id": 1901, "type": "judge", "question": "编制用电组织设计的目的是用以指导建造一个安全可靠、经济合理、方便适用、适应施工现场特点和用电特性的用电工程，并且用以指导所建用电工程的正确使用。", "options": ["正确", "错误"], "answer": [0], "explanation": "编制用电组织设计的目的是用以指导建造一个安全可靠、经济合理、方便适用,适应施工现场特点和用电特性的用电工程,并且用以指导所建用电工程的正确使用。"},
  {"id": 1902, "type": "judge", "question": "临时用电负荷是电力负荷的简称，是指电气设备(例如电力变压器)中的功率。", "options": ["正确", "错误"], "answer": [0], "explanation": "在电力系统中，功率是指单位时间内的能量消耗或转化率。对于电气设备来说，功率表示该设备在运行时所需的能量速率。临时用电负荷实际指的就是电气设备的功率需求。"},
  {"id": 1903, "type": "judge", "question": "按照《施工现场临时用电安全技术规范》JGJ46—2005的规定，所有防雷冲击接地电阻值均不得大于50Ω。", "options": ["正确", "错误"], "answer": [1], "explanation": "按照《施工现场临时用电安全技术规范》JGJ46一2005的规定,所有防雷冲击接地电阻值均不得大于30Ω。"},
  {"id": 1904, "type": "judge", "question": "安全用电措施和电气防火措施是指为了正确使用现场用电工程，并保证其安全运行，防止各种触电事故和电气火灾事故而制定的技术性和管理性规定。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建设工程施工现场消防安全技术规范》GB 50720-2011 / 《中华人民共和国消防法》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1905, "type": "judge", "question": "施工现场用电安全技术档案包括施工施工现场用电组织设计的全部资料、用电技术交底记录等。", "options": ["正确", "错误"], "answer": [0], "explanation": "按照《规范》的规定，施工现场用电安全技术档案应包括以下八个方面的内容：\n① 施工现场用电组织设计的全部资料；\n② 修改施工现场用电组织设计资料；\n③ 用电技术交底资料；\n④ 施工现场用电工程检查验收表；\n⑤ 电气设备试、检验凭单和调试记录；\n⑥ 接地电阻、绝缘电阻、漏电保护器漏电动作参数测定记录表；\n⑦ 定期检(复)查表；\n⑧ 电工安装、巡检、维修、拆除工作记录。"},
  {"id": 1906, "type": "judge", "question": "电工作业必须经专业安全技术培训，考试合格，非电工在必要情况下也可进行电气作业。", "options": ["正确", "错误"], "answer": [1], "explanation": "电工作业必须经专业安全技术培训，考试合格，非电工严禁进行电气作业。"},
  {"id": 1907, "type": "judge", "question": "保护零线PE必须采用蓝黑双色线，严格与相线、工作零线相区别，不得混用。", "options": ["正确", "错误"], "answer": [1], "explanation": "保护线PE必须采用绿/黄双色线,严格与相线、工作零线相区别,不得混用。"},
  {"id": 1908, "type": "judge", "question": "配电间门要朝内开。", "options": ["正确", "错误"], "answer": [1], "explanation": "应向外开。"},
  {"id": 1909, "type": "judge", "question": "合理配置施工现场的临时 （　　） ，包括变压器、总配电箱（配电柜）、分配电箱、开关箱、无功补偿等，确保配电系统安全可靠。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《施工现场临时用电安全技术规范》JGJ 46-2005\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1910, "type": "judge", "question": "施工现场用电工程的基本供配电系统应当按三级设置，即采用三级配电。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1911, "type": "judge", "question": "三级配电是指施工现场从电源进线开始至用电设备之间，应经过三级配电装置配送电力。", "options": ["正确", "错误"], "answer": [0], "explanation": "教材P220页：\n三级配电是指施工现场从电源进线开始至用电设备之间，应经过三级配电装置配送电力。"},
  {"id": 1912, "type": "judge", "question": "按照分级分路规则的要求，在三级配电系统中，任何用电设备均不得越级配电，即其电源线不得直接连接于分配电箱或总配电箱。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《施工现场临时用电安全技术规范》JGJ 46-2005\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1913, "type": "judge", "question": "按照分级分路规则的要求，在三级配电系统中，用电设备的电源线可连接于分配电箱或总配电箱。", "options": ["正确", "错误"], "answer": [1], "explanation": "在三级配电系统中，任何用电设备均不得越级配电，即其电源线不得直接连接于分配电箱或总配电箱。"},
  {"id": 1914, "type": "judge", "question": "压缩配电间距规则是指除总配电箱，配电室(配电柜)外，分配电箱与开关箱之间，开关箱与用电设备之间的空间间距应尽量伸长。", "options": ["正确", "错误"], "answer": [1], "explanation": "压缩配电间距规则 压缩配电间距规则是指除总配电箱、配电室（配电柜）外，分配电箱与开关箱之间和开关箱与用电设备之间的空间间距应尽量缩短。"},
  {"id": 1915, "type": "judge", "question": "压缩配电间距规则中规定分配电箱与开关箱的距离不得超过3m。", "options": ["正确", "错误"], "answer": [1], "explanation": "分配电箱与开关箱的距离不得超过30m。"},
  {"id": 1916, "type": "judge", "question": "根据现行行业标准《建筑施工安全检查标准》JGJ59规定，配电室建筑耐火等级应不低于2级并配备合格的消防器材。", "options": ["正确", "错误"], "answer": [1], "explanation": "配电室建筑耐火等级不低于3级并配备合格的消防器材;"},
  {"id": 1917, "type": "judge", "question": "配电室的位置周围环境无灰层、无潮气、无振动、无腐蚀介质、无易燃易爆物、无积水。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建设工程施工现场消防安全技术规范》GB 50720-2011 / 《中华人民共和国消防法》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1918, "type": "judge", "question": "配电柜正面的操作通道宽度，单列布置或双列背对背布置时不应小于2m，双列面对面布置时不应小于2.5m。", "options": ["正确", "错误"], "answer": [1], "explanation": "配电柜正面的操作通道宽度,单列布置或双列背对背布置不小于1.5m,双列面对面布置不小于2m。"},
  {"id": 1919, "type": "judge", "question": "配电柜正面的操作通道宽度，双列面对面布置时不应小于2.5m。", "options": ["正确", "错误"], "answer": [1], "explanation": "配电柜正面的操作通道宽度,单列布置或双列背对背布置不小于1.5m,双列面对面布置不小于2m。"},
  {"id": 1920, "type": "judge", "question": "配电室的照明包括二两个彼此独立的照明系统：一是正常照明，二是事故照明，事故照明受配电室总配电箱控制。", "options": ["正确", "错误"], "answer": [1], "explanation": "配电室的照明应包括两个彼此独立的照明系统。一是正常照明，二是事故照明，事故照明应不受配电室总配电箱控制。"},
  {"id": 1921, "type": "judge", "question": "施工现场设置的自备电源，即是指自备的230／400V发电机组。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《施工现场临时用电安全技术规范》JGJ 46-2005\n【解析】该说法正确。题干中的主体、程序或控制数值与现行规定一致，属于直接记忆点。"},
  {"id": 1922, "type": "judge", "question": "配电箱、开关箱的箱体应采用木板制作。", "options": ["正确", "错误"], "answer": [1], "explanation": "配电箱、开关箱的箱体一般应采用铁板制作、亦可采用优质绝缘板制作,但不得采用木板制作。"},
  {"id": 1923, "type": "judge", "question": "配电箱、开关箱内应配置电器安装板，用以安装所配置的电器和接线端子板等，钢质安装板与钢板箱体之间应做金属性（电气）连接。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《施工现场临时用电安全技术规范》JGJ 46-2005\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1924, "type": "judge", "question": "电源隔离功能是指所选配的电器分断时具有可见分断点，并能同时断开电源所有极，因此这类电器称为隔离开关。", "options": ["正确", "错误"], "answer": [0], "explanation": "(1)电源隔离功能：所谓电源隔离功能是指所选配的电器分断时具有可见分断点，并能同时断开电源所有极，因之这类电器称为隔离开关。用作隔离开关的电器有刀型开关、刀熔开关和分断时具有可见分断点的断路器。隔离开关可用于空载接通与分断电路。"},
  {"id": 1925, "type": "judge", "question": "具有正常接通与分断电路功能的电器有各种断路器。", "options": ["正确", "错误"], "answer": [0], "explanation": "(2)正常接通与分断电路功能：所谓正常接通与分断电路功能是指所选配的电器能够在配电系统空载或正常负载情况下可靠、有效地接通与分断电路(非频繁操作)。具有这种功能的电器有各种断路器。"},
  {"id": 1926, "type": "judge", "question": "具有过载、短路、漏电保护功能的电器就是各种断路器和漏电保护器的组合、漏电断路器或刀熔开关和漏电保护器的组合。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《施工现场临时用电安全技术规范》JGJ 46-2005\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1927, "type": "judge", "question": "当所设总漏电保护器是同时具备短路、过载、漏电保护功能的漏电断路器时，可不设分路熔断器。", "options": ["正确", "错误"], "answer": [1], "explanation": "当所设总漏电保护器是同时具备短路、过载、漏电保护功能的漏电断路器时,可不设总断路器或总熔断器。"},
  {"id": 1928, "type": "judge", "question": "总配电箱电器的电气接线图为单线图。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《施工现场临时用电安全技术规范》JGJ 46-2005\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1929, "type": "judge", "question": "临时用电的配电采用一总路、二分路形式。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《施工现场临时用电安全技术规范》JGJ 46-2005\n【解析】该说法错误。题干中的主体、程序、禁止性要求或控制数值与现行规定不一致。"},
  {"id": 1930, "type": "judge", "question": "在采用二级漏电保护的配电系统中，分配电箱中不要求设置电源隔离开关、过载与短路保护电器，但漏电保护器必须设置。", "options": ["正确", "错误"], "answer": [1], "explanation": "在采用二级漏电保护的配电系统中，分配电箱中不要求设置漏电保护器，但电源隔离开关、过载与短路保护电器必须设置。"},
  {"id": 1931, "type": "judge", "question": "配电装置设置场所应保持干燥、通风、常温；应及时清除易燃易爆物、腐蚀介质、积水和杂物，并留有足够一人工作的空间和通道。", "options": ["正确", "错误"], "answer": [1], "explanation": "配电装置设置场所应保持干燥、通风、常温。应及时清除易燃易爆物品、腐蚀介质和积水杂物等,并留出足够二人同时工作的空间和通道。"},
  {"id": 1932, "type": "judge", "question": "送电操作顺序为开关箱一分配电箱一总配电箱(配电柜)。", "options": ["正确", "错误"], "answer": [1], "explanation": "送电操作顺序为:配电柜一总配电箱一分配电箱一开关箱。\n停电操作顺序为:开关箱一分配电箱一总配电箱一配电柜(紧急情况下除外)。"},
  {"id": 1933, "type": "judge", "question": "配电装置的漏电保护器应于每周试验按钮试跳1次，只有试跳正常才可继续使用。", "options": ["正确", "错误"], "answer": [1], "explanation": "配电装置的漏电保护器应于每次使用时首先用试验按钮试跳1次，只有试跳正常才可继续使用。"},
  {"id": 1934, "type": "judge", "question": "配电线的选择，实际上就是架空线路导线、电缆线路电缆、室外线路导线、电缆以及配电母线的选择。", "options": ["正确", "错误"], "answer": [1], "explanation": "配电线的选择,实际上就是架空线路导线、电缆线路电缆、室【内】线路导线、电缆,以及配电母线的选择。"},
  {"id": 1935, "type": "judge", "question": "施工现场内的低压架空线路不得直接捆绑在电杆、树木、脚手架上，不得拖在地面上。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1936, "type": "judge", "question": "架空线的选择主要是选择配电线的种类和导线的截面，其选择依据主要是线路敷设的要求和线路负荷计算的计算电流值。", "options": ["正确", "错误"], "answer": [0], "explanation": "配电线的选择,实际上就是架空线路导线、电缆线路电缆、室内线路导线、电缆,以及配电母线的选择。架空线的选择主要是选择架空线路导线的种类和导线的截面，其选择依据主要是线路敷设的要求和线路负荷计算的电流。"},
  {"id": 1937, "type": "judge", "question": "跨越铁路、公路、河流电力线路挡距内的铝线不得有接头。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1938, "type": "judge", "question": "根据基本供配电系统的要求，电缆中必须包含线路工作制所需要的全部工作芯线和PE线。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1939, "type": "judge", "question": "由于施工现场配电母线常常采用裸扁铜板或裸扁铝板制作成所谓裸母线，因此安装时，必须用绝缘子支撑固定在配电柜上，以保持对地绝缘和电磁稳定性。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1940, "type": "judge", "question": "根据架空线的敷设要求，动力、照明线在同一横担上架设时，导线相序排列顺序是：面向负荷从左侧起依次为:L1、L2、L3、N、PE。", "options": ["正确", "错误"], "answer": [1], "explanation": "动力、照明线在同一横担上架设时，导线相序排列是：面向负荷从左侧起依次为 L1、N、L2、L3、PE。"},
  {"id": 1941, "type": "judge", "question": "根据架空线的敷设要求，动力、照明线在二层横担上分别架设时，导线相序排列顺序是：上层横担面向负荷从左侧起依次为L（L1或L2或L3）、N、PE，下层横担面向负荷从左侧起依次为L1、L2、L3。", "options": ["正确", "错误"], "answer": [1], "explanation": "动力、照明线在二层横担上分别架设时，导线相序排列是：上层横担面向负荷从左侧起依次为L1、L2、L3;下层横担面向负荷从左侧起依次为L1(L2、L3)、N、PE。"},
  {"id": 1942, "type": "judge", "question": "电缆敷设应采用埋地或地面明设两种方式。", "options": ["正确", "错误"], "answer": [1], "explanation": "施工现场电缆敷设应采用埋地或架空两种方式，严禁沿地面明设，以防机械损伤和介质腐蚀。"},
  {"id": 1943, "type": "judge", "question": "电缆应沿地面铺设，为避免机械损伤和介质腐蚀，应做好防护措施。", "options": ["正确", "错误"], "answer": [1], "explanation": "电缆干线应采用埋地或架空敷设,严禁沿地面明设,并应避免机械损伤和介质腐蚀。"},
  {"id": 1944, "type": "judge", "question": "埋地电缆的接头应设在地面以上的接线盒内，电缆接线盒应能防水、防尘、防机械损伤，并远离易燃、易爆、易腐蚀场所。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1945, "type": "judge", "question": "根据室内配线安全要求，钢索配线的架吊间距不宜大于12m。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干中的主体、程序或控制数值与现行规定一致，属于直接记忆点。"},
  {"id": 1946, "type": "judge", "question": "根据架空线的敷设要求，线路中应尽量减少接头，以减少故障点。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1947, "type": "judge", "question": "潮湿场所或埋地非电缆（绝缘导线）配线必须穿管敷设，管口和管接头应密封。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1948, "type": "judge", "question": "施工现场的用电系统，不论其供电方式如何，都属于电源中性点直接接地的220／380V三相四线制低压电力系统。", "options": ["正确", "错误"], "answer": [1], "explanation": "施工现场的用电系统，不论其供电方式如何，都属于电源中性点直接接地的220V/380V三相五线制低压电力系统。"},
  {"id": 1949, "type": "judge", "question": "电气设备正常情况带电的金属外壳和机械设备的金属构架与保护零线连接，称为保护接零或接零保护。", "options": ["正确", "错误"], "answer": [1], "explanation": "因漏电保护需要,将电气设备正常情况下不带电的金属外壳和机械设备的金属构架接地,称为保护接地。阻值也应小于4Ω。"},
  {"id": 1950, "type": "judge", "question": "在施工现场用电工程专用的电源中性点直接接地的220/380V三相四线制低压电力系统中，必须采用TN-C接零保护系统，严禁采用TN-S接零保护系统。", "options": ["正确", "错误"], "answer": [1], "explanation": "在施工现场用电工程专用的电源中性点直接接地的220/380V三相四线制低压电力系统中，必须采线TN-S（三相五线）接零保护系统，严禁采用TN-C（三相四线）接零保护系统或TT接地保护系统。"},
  {"id": 1951, "type": "judge", "question": "当施工现场与外电线路共用同一供电系统时，电气设备的接地形式应一部分设备作保护系统，另一部分设备作保护接地。", "options": ["正确", "错误"], "answer": [1], "explanation": "当施工现场与外电线路共用同一供电系统时,电气设备的接地形式应与原系统保持一致。不得一部分设备作保护接零,另一部分设备作保护接地。"},
  {"id": 1952, "type": "judge", "question": "PE线与N线的连接关系：经过总漏电保护器(RCD)后PE线和N线即分开，不得再作电气连接。", "options": ["正确", "错误"], "answer": [0], "explanation": "PE线与N线的连接关系:经过总漏电保护器,PE线与N线即分开,不得再作电气连接。"},
  {"id": 1953, "type": "judge", "question": "重复接地必须与保护零线线相连接，严禁与工作零线线相连接。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《施工现场临时用电安全技术规范》JGJ 46-2005\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1954, "type": "judge", "question": "用作过载、短路保护的电器主要有各种类型的断路器和熔断器。断路器以塑壳式断路器为宜，熔断器应选用普通熔丝。", "options": ["正确", "错误"], "answer": [1], "explanation": "用作过载、短路保护的电器主要有各种类型的断路器和熔断器.其中,断路器以塑壳式断路器为宜;熔断器则应选用具有可靠灭弧分断功能的产品，不得以普通熔丝替代。"},
  {"id": 1955, "type": "judge", "question": "N线和相线采用绿／黄双色绝缘线。", "options": ["正确", "错误"], "answer": [1], "explanation": "根据电气工程相关标准（如中国国家标准 GB/T 5023 或国际电工委员会标准 IEC 60446），绿/黄双色绝缘线通常用于保护接地线（PE线），而不是用于N线（中性线）或相线（L线）。\nN线（中性线）：通常采用蓝色绝缘线。\n相线（L线）：通常采用红、黄、绿（单色）等颜色，具体根据相序区分。\n绿/黄双色线：专门用于保护接地线，以确保电气设备的安全接地。\n因此，N线和相线不应使用绿/黄双色绝缘线。"},
  {"id": 1956, "type": "judge", "question": "为了保证PE线电气连接的可靠性，PE线必须采用绝缘铜线。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】建筑施工企业安全生产管理人员考核教材 / 现行建设工程安全法规汇编\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1957, "type": "judge", "question": "二级漏电保护系统中漏电保护器的设置位置必须在基本供配电系统的总配电箱(配电柜)和开关箱首、末二级配电装置中。", "options": ["正确", "错误"], "answer": [0], "explanation": "漏电保护器的设置位置:二级漏电保护系统中漏电保护器的设置位置必须在基本供配电系统的总配电箱(配电柜)和开关箱首、末二级配电装置。"},
  {"id": 1958, "type": "judge", "question": "文明施工涵盖的内容比较广泛，不仅要着重做好现场的场容管理工作，而且还要相应做好现场材料、设备、安全、技术、保卫、消防和生活卫生等方面的管理工作。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建设工程施工现场消防安全技术规范》GB 50720-2011 / 《中华人民共和国消防法》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1959, "type": "judge", "question": "现场办公与住宿属于文明施工中的一般项目。", "options": ["正确", "错误"], "answer": [1], "explanation": "保证项目应包括:现场围挡、封闭管理、施工场地、材料管理、现场办公与住宿、现场防火。一般项目应包括:综合治理、公示标牌、生活设施、社区服务。"},
  {"id": 1960, "type": "judge", "question": "综合治理属于文明施工中的一般项目。", "options": ["正确", "错误"], "answer": [0], "explanation": "保证项目应包括:现场围挡、封闭管理、施工场地、材料管理、现场办公与住宿、现场防火。一般项目应包括:综合治理、公示标牌、生活设施、社区服务。"},
  {"id": 1961, "type": "judge", "question": "施工单位应当不定期对施工现场的围挡进行养护、维修、保持完好、整洁和美观。", "options": ["正确", "错误"], "answer": [1], "explanation": "施工单位要【定期】对围挡进行维护，保持围挡表面整洁、无污渍；及时修复或更换破损、变形的围挡部件，确保广告内容清晰、完整，无褪色、破损等情况，保证围挡的牢固性和稳定性；对围挡周边的垃圾、杂物等进行清理，保持周边环境整洁。"},
  {"id": 1962, "type": "judge", "question": "上海市重点区域内施工工地的文明施工要求，隧道工程工作井施工，要采用覆罩法作业方式，但施工现场安全或者空间条件无法达到要求的除外。", "options": ["正确", "错误"], "answer": [0], "explanation": "本市重点区域内施工工地的文明施工要求，还应当符合下列规定：\n（八）轨道交通站点、隧道工程工作井施工，采用覆罩法作业方式，但施工现场安全或者空间条件无法达到要求的除外。"},
  {"id": 1963, "type": "judge", "question": "上海市重点区域内施工工地的文明施工要求，因特殊工序要求确需夜间施工的，应当向城管部门或者区生态环境部门办理夜间施工有关手续并提前在周边区域予以公告。", "options": ["正确", "错误"], "answer": [1], "explanation": "（六）禁止夜间施工，但抢险、抢修工程及有特殊工序要求的工程除外；因特殊工序要求确需夜间施工的，应当向【交通行政管理部门】或者区生态环境部门办理夜间施工有关手续，并提前在周边区域予以公告。"},
  {"id": 1964, "type": "judge", "question": "施工单位应对围挡进行养护、维修，可将围挡用作挡土墙或其他设施设备的支持。", "options": ["正确", "错误"], "answer": [1], "explanation": "禁止将围挡用作挡土墙或其他设施设备的支撑。"},
  {"id": 1965, "type": "judge", "question": "采用砖墙作围挡的，应使用黏土砖砌筑，其墙柱和基础砌筑应符合相关技术规范和标准的规定。", "options": ["正确", "错误"], "answer": [1], "explanation": "采用砖墙作围挡的,墙体厚度不应小于0.24m,严禁使用粘土砖砌筑(陈旧粘土砖利用除外),其墙柱和基础砌筑应符合相关技术规范和标准的规定。"},
  {"id": 1966, "type": "judge", "question": "施工中确需扩大施工边界的，应经批准后，先撤除原围挡封闭，再在扩大施工的边界搭设围挡封闭。", "options": ["正确", "错误"], "answer": [1], "explanation": "施工中确需扩大施工边界的,应经批准后,在扩大施工的边界事先搭设围挡封闭,再撤除原围挡封闭工程未完工前严禁撤除围挡封闭。"},
  {"id": 1967, "type": "judge", "question": "线形水利工程、非全封闭的城市道路工程和公路工程，施工工期小于7天，可使用路栏式围挡。", "options": ["正确", "错误"], "answer": [0], "explanation": "线形水利工程、非全封闭的城市道路工程和公路工程，施工工期小于7天，可使用路栏式围挡。\n这一规定旨在兼顾施工便捷性与交通安全，适用于短期、临时性的施工场景。"},
  {"id": 1968, "type": "judge", "question": "根据上海市重点区域内施工工地的文明施工要求，重点区域内的施工现场安全网采用不透尘、符合安全要求的材料。", "options": ["正确", "错误"], "answer": [0], "explanation": "第二十四条 （重点区域管理要求）\n本市重点区域内施工工地的文明施工要求，还应当符合下列规定：\n（二）安全网采用不透尘、符合安全要求的材料。"},
  {"id": 1969, "type": "judge", "question": "根据上海市重点区域内施工工地的文明施工要求，重点区域内的施工现场禁止采用钢筋、模板成形加工作业。", "options": ["正确", "错误"], "answer": [0], "explanation": "第二十四条 （重点区域管理要求）\n本市重点区域内施工工地的文明施工要求，还应当符合下列规定：\n（七）禁止采用钢筋、模板成型加工作业。"},
  {"id": 1970, "type": "judge", "question": "单体建（构）筑物拆除时的，应在其单体建（构）筑物的外围设置封闭围挡。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《房屋建筑工程文明施工提升标准》 / 《上海市建设工程文明施工标准》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1971, "type": "judge", "question": "围挡应采用彩钢夹心板、砌体或其他能满足强度要求的硬质材料。", "options": ["正确", "错误"], "answer": [0], "explanation": "根据《建设工程施工现场环境与卫生标准》（JGJ 146）及各地文明施工管理规定（如《上海市建设工程文明施工管理规定》），施工现场围挡应采用彩钢夹心板、砌体、金属板材或其他能满足强度要求的硬质材料，禁止使用竹笆、彩条布、石棉瓦等易变形、破损的软质材料。"},
  {"id": 1972, "type": "judge", "question": "拆除工程围挡宜采用彩钢夹心板等轻质硬质材料。", "options": ["正确", "错误"], "answer": [1], "explanation": "拆除工程围挡宜采用轻型硬质的彩钢板等材料做围挡。"},
  {"id": 1973, "type": "judge", "question": "施工现场出入口应设置出入门，出入门应采用敞口式或栏栅式。", "options": ["正确", "错误"], "answer": [1], "explanation": "出入门应采用金属板材和金属型材作实体式制作,并符合强度要求。出入门制作不得采用敞口式或栏栅式。"},
  {"id": 1974, "type": "judge", "question": "施工现场出入们应保持清洁、无锈痕、无破损和开启障碍，其内测应书写施工单位名称，并可同时绘制企业标识或标志。", "options": ["正确", "错误"], "answer": [1], "explanation": "5.出入门应保持清洁、无锈痕、无破损和开启障碍,其【外侧】应书写施工单位名称,并可同时绘制企业标识或标志。"},
  {"id": 1975, "type": "judge", "question": "施工现场、加工区、生活区的道路及场地地面应进行硬化处理。", "options": ["正确", "错误"], "answer": [0], "explanation": "2.施工现场、加工区和生活区的道路及场地应作硬化处理,并应符合下列要求:\n2.1 施工现场、加工区和生活区的道路及场地,应事先进行现场平面布置的总体设计,确定各区域的边界和相对平面标高及排水设施,并在实地进行放样和组织实施。\n2.2 施工人员通道应用0.05-0.1m 厚的C20及以上混凝土硬化,生产加工场地用0.15m 厚的C20及以上混凝土硬化,办公生活区场地用0.1m-0.12m 厚的C20及以上混凝土硬化。\n2.3 车辆通行道路以外的其它场地和一般区域的建筑施工、办公场地,可采用混凝土或铺砖等其他硬化方式处理,宜优先使用能回收重复利用的预制砖、板等材料。生产加工场地、堆场场地应用0.1-0.15m 厚的C20及以上混凝土。\n2.4 用作车辆通行的道路应采用混凝土铺设,并满足车辆行驶和抗压要求。工地出入门门口及连接社会道路与施工现场的通道的混凝土厚度不应小于0.2m、标号不应小于C20,宽度不应小于门墩与门墩外径距离。\n2.5 场内硬地坪应保持基本平整。凡各类场地未按规定实施硬化处理的,不得施工。"},
  {"id": 1976, "type": "judge", "question": "高层作业区以及道路管线工程施工现场应选用封盖型便桶式厕所或标准型移动厕所作临时厕所。设置移动式临时厕所应搭设相应棚式。", "options": ["正确", "错误"], "answer": [1], "explanation": "5.4 高层作业区以及道路管线工程施工现场应选用封盖型便桶式厕所或标准型移动厕所作临时厕所。设置封盖型便桶式临时厕所,应搭设相应棚室。临时厕所内外应做好保洁工作。"},
  {"id": 1977, "type": "judge", "question": "非本工地工作人员在施工工地内住宿的，要先做好登记工作。", "options": ["正确", "错误"], "answer": [1], "explanation": "3.3 严禁在建筑物内地下室安排人员住宿,严禁非本工地工作人员在施工工地内的宿舍住宿,严禁在未竣工的建筑物内设置员工宿舍。住宿人员在宿舍内严禁私拉电线、私接插座,使用大功率取暖电器、电饭煲、电炒锅。严禁宿舍内设置通铺。"},
  {"id": 1978, "type": "judge", "question": "施工现场的明火作业应履行动火审批手续，配备动火监护人员。", "options": ["正确", "错误"], "answer": [0], "explanation": "（5）明火作业应履行动火审批手续，配备动火监护人员。"},
  {"id": 1979, "type": "judge", "question": "施工现场应建立治安保卫制度、制定治安防范措施。", "options": ["正确", "错误"], "answer": [0], "explanation": "5.11.2施工现场应建立治安保卫制度、责任分解落实到人；\n5.11.3施工现场应制定治安防范措施。"},
  {"id": 1980, "type": "judge", "question": "施工现场生活区内应设置供作业人员学习和娱乐的场所。", "options": ["正确", "错误"], "answer": [0], "explanation": "5.11.1生活区内应设置供作业人员学习和娱乐的场所；"},
  {"id": 1981, "type": "judge", "question": "获准夜间施工的，施工单位应在铭牌中的告示栏内张贴告示，并书面告知施工所在地居委会。", "options": ["正确", "错误"], "answer": [0], "explanation": "五、获准夜间施工时,施工单位会在告示栏内张贴告示,并书面告知施工所在地居委会。夜间施工严禁进行捶打、敲击和锯割等易产生高噪声的作业,对确需使用易产生噪声的机具采取有效降噪措施。装卸材料轻卸轻放。"},
  {"id": 1982, "type": "judge", "question": "安全管理资料是一种以文字、图像等手段记录安全生产管理过程所形成的一系列文件的组合。", "options": ["正确", "错误"], "answer": [0], "explanation": "安全管理资料是一种以文字、图像等手段记录安全生产管理过程所形成的一系列文件的组合;"},
  {"id": 1983, "type": "judge", "question": "真实、完善的安全管理资料，能最大限度地规避或降低企业和相关人员因生产事故带来法律后果的风险，是区分和追究安全生产事故法律责任最直接的证据之一。", "options": ["正确", "错误"], "answer": [0], "explanation": "5、真实、完善的安全管理资料，能最大限度地规避或降低企业和相关人员因生产事故带来法律后果的风险，是区分和追究安全生产事故法律责任最直接的证据之一。"},
  {"id": 1984, "type": "judge", "question": "安全生产管理资料和记录分为基本条件类(A类）、核心要求类（B类）、基本要求类（C类）。", "options": ["正确", "错误"], "answer": [0], "explanation": "安全资料分为A、B、C三类：A类为基本条件类，B类为核心要求类，这两类属于相对静态，以开工前和开工初期为主；C类为基本要求类，属于相对动态，以开工后为主。"},
  {"id": 1985, "type": "judge", "question": "项目部应及时、真实地形成现代施工安全生产管理活动的资料和记录，并有效保存至工程完工之日起之后1年。", "options": ["正确", "错误"], "answer": [1], "explanation": "7.0.1 项目部应及时、真实的形成现场施工安全生产管理活动的资料和记录,并有效保存至工程【竣工】之日起以后1年。"},
  {"id": 1986, "type": "judge", "question": "一级动火作业应由所在工地负责人填写动火申请表。", "options": ["正确", "错误"], "answer": [1], "explanation": "一级动火作业由项目负责人组织编制防火安全技术方案，填写动火申请表，报企业安全管理部门审查批准后，方可动火。"},
  {"id": 1987, "type": "judge", "question": "专项施工方案中起重设备安装拆卸方案是开工前要求技术员编制完成的内容。", "options": ["正确", "错误"], "answer": [1], "explanation": "起重设备安装拆卸专项施工方案需在开工前由施工单位专业技术人员编制完成，经施工单位技术负责人审核、总监理工程师审批（如需专家论证则通过论证）后，方可实施。"},
  {"id": 1988, "type": "judge", "question": "施工现场发生火灾，应立即报告公安消防部门，并组织力量扑救。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建设工程施工现场消防安全技术规范》GB 50720-2011 / 《中华人民共和国消防法》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1989, "type": "judge", "question": "在编制施工方案时，施工总平面图、施工方法和施工技术均应符合消防安全要求。", "options": ["正确", "错误"], "answer": [0], "explanation": "《上海市建筑施工现场安全生产管理规范》（DGJ 08-2066-2016）第6.1节进一步强调，施工方案的编制应包含消防安全内容，施工总平面图、施工方法和施工技术均需符合消防安全标准，确保施工现场的消防安全管理。"},
  {"id": 1990, "type": "judge", "question": "禁止在临时消防车道上堆物、堆料或挤占临时消防车道。", "options": ["正确", "错误"], "answer": [0], "explanation": "临建房屋周边应设置临时消防车道,其宽度不得小于3.5m,并保证临时消防车道的畅通,禁止在临时消防车道上堆物、堆料或挤占临时消防车道。"},
  {"id": 1991, "type": "judge", "question": "根据施工现场消防安全管理要求，严禁工程中明火施工及宿舍内明火取暖。", "options": ["正确", "错误"], "answer": [0], "explanation": "施工现场和生活区,未经保卫部门批准不得使用电热器具,严禁工程中明火保温施工及宿舍明火取暖。"},
  {"id": 1992, "type": "judge", "question": "根据施工现场消防安全管理要求，生活区的用电、用火要经政府部门审批。", "options": ["正确", "错误"], "answer": [1], "explanation": "生活区的用电要符合防火规定，用火要经保卫部门审批。"},
  {"id": 1993, "type": "judge", "question": "施工作业前，施工现场的施工作业人员应向管理人员进行消防安全生产技术交底，包括施工过程中可能发生火灾的部位或环节、逃生方法及路线等主要内容。", "options": ["正确", "错误"], "answer": [1], "explanation": "6.1.8 施工作业前，施工现场的施工管理人员应向作业人员进行消防安全技术交底。消防安全技术交底应包括下列主要内容：\n1 施工过程中可能发生火灾的部位或环节。\n2 施工过程应采取的防火措施及应配备的临时消防设施。\n3 初起火灾的扑救方法及注意事项。\n4 逃生方法及路线。"},
  {"id": 1994, "type": "judge", "question": "二级动火作业应由所在工地负责人填写动火申请表。", "options": ["正确", "错误"], "answer": [1], "explanation": "二级动火作业由项目责任工程师组织拟定防火安全技术措施，填写动火申请表，报项目安全管理部门和项目负责人审查批准后，方可动火。"},
  {"id": 1995, "type": "judge", "question": "重要文物单位动火作业属于二级动火作业。", "options": ["正确", "错误"], "answer": [1], "explanation": "一级动火作业"},
  {"id": 1996, "type": "judge", "question": "操作间冬季宜用暖气供暖。如用火炉取暖，可用燃烧劈柴取暖。", "options": ["正确", "错误"], "answer": [1], "explanation": "操作间冬季宜采用暖气(水暖)供暖,如用火炉取暖时,必须在四周采取挡火措施;不应用燃烧劈柴、刨花代煤取暖。每个火炉都要有专人负责,下班时要将余火彻底熄灭。"},
  {"id": 1997, "type": "judge", "question": "消防给水管道可以与施工用水管道合用。", "options": ["正确", "错误"], "answer": [1], "explanation": "【依据】《建设工程施工现场消防安全技术规范》GB 50720-2011 / 《中华人民共和国消防法》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 1998, "type": "judge", "question": "地下工程的施工作业场所宜配备防毒面具。", "options": ["正确", "错误"], "answer": [0], "explanation": "临时消防设施：\n（1）施工现场应设置灭火器、临时消防给水系统和临时消防应急照明等临时消防设施。\n（2）临时消防设施的设置应与在建工程的施工保持同步。对于房屋建筑工程，临时消防设施的设置与在建工程主体结构施工进度的差距不应超过3层。\n（3）在建工程可利用已具备使用条件的永久性消防设施作为临时消防设施。当永久性消防设施无法满足使用要求时，应增设临时消防设施。\n（4）施工现场的消火栓泵应采用专用消防配电线路。专用配电线路应自施工现场总配电箱的总断路器上端接入，并应保持连续不间断供电。\n（5）【地下工程的施工作业场所宜配备防毒面具。】\n（6）临时消防给水系统的贮水池、消火栓泵、室内消防竖管及水泵接合器等应设置醒目标识。"},
  {"id": 1999, "type": "judge", "question": "地下工程施工的防火要求规定，应备有通信报警装置，便于及时报告险情。", "options": ["正确", "错误"], "answer": [0], "explanation": "【依据】《建设工程施工现场消防安全技术规范》GB 50720-2011 / 《中华人民共和国消防法》\n【解析】该说法正确。题干表述与现行规定或教材标准表述一致。"},
  {"id": 2000, "type": "judge", "question": "根据建设部的规定，建筑企业若是没有取得安全生产许可证，就没有资格参加投标。", "options": ["正确", "错误"], "answer": [0], "explanation": "一、投标需要\n根据建设部的规定，建筑企业若是没有取得安全生产许可证，就没有资格参加投标。"}
];
